/// Target architecture for compilation. Subset of the full `TargetSpec`
/// from `hew-cli/src/target.rs`, exposed at the HIR boundary so target gates
/// can reject unsupported constructs before codegen. Kept minimal to avoid
/// introducing a `hew-hir → hew-cli` dependency.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TargetArch {
    Aarch64,
    X86_64,
    Wasm32,
    /// Any other target (e.g. riscv64, powerpc64). Used for target gates
    /// that reject coroutine-dependent constructs on non-x86_64/aarch64.
    Other,
}

/// Flatten a (potentially nested) `Pattern::Or` tree into its leaf patterns,
/// preserving source spans. A pattern that is not an `Or` returns a
/// single-element list containing itself.
///
/// Example: `1 | 2 | 3` parses as `Or(1, Or(2, 3))` and flattens to
/// `[1, 2, 3]`.
fn flatten_or_pattern(pattern: &Spanned<Pattern>) -> Vec<Spanned<Pattern>> {
    match &pattern.0 {
        Pattern::Or(left, right) => {
            let mut leaves = flatten_or_pattern(left);
            leaves.extend(flatten_or_pattern(right));
            leaves
        }
        _ => vec![pattern.clone()],
    }
}

fn collect_match_payload_predicates(ctx: &LowerCtx, pattern: &Pattern) -> Vec<HirPayloadPredicate> {
    match pattern {
        Pattern::Constructor { name, patterns } => {
            let field_tys = ctx
                .lookup_variant_ctor(name)
                .map(|(_, _, kind)| match kind {
                    HirVariantKind::Tuple(field_tys) => field_tys.clone(),
                    HirVariantKind::Unit | HirVariantKind::Struct(_) => Vec::new(),
                })
                .unwrap_or_default();
            patterns
                .iter()
                .enumerate()
                .filter_map(|(field_idx, (sub_pat, _))| {
                    let Pattern::Literal(lit) = sub_pat else {
                        return None;
                    };
                    let Ok(field_idx) = u32::try_from(field_idx) else {
                        return None;
                    };
                    let (literal, literal_ty) = literal_to_hir(lit);
                    let ty = field_tys
                        .get(field_idx as usize)
                        .cloned()
                        .unwrap_or(literal_ty);
                    Some(HirPayloadPredicate {
                        field_idx,
                        literal,
                        ty,
                    })
                })
                .collect()
        }
        Pattern::Struct { name, fields } => {
            let field_decls = ctx
                .lookup_variant_ctor(name)
                .map(|(_, _, kind)| match kind {
                    HirVariantKind::Struct(field_decls) => field_decls.clone(),
                    HirVariantKind::Unit | HirVariantKind::Tuple(_) => Vec::new(),
                })
                .unwrap_or_default();
            fields
                .iter()
                .filter_map(|field| {
                    let (sub_pat, _) = field.pattern.as_ref()?;
                    let Pattern::Literal(lit) = sub_pat else {
                        return None;
                    };
                    let (field_idx, (_, ty)) = field_decls
                        .iter()
                        .enumerate()
                        .find(|(_, (name, _))| name == &field.name)?;
                    let Ok(field_idx) = u32::try_from(field_idx) else {
                        return None;
                    };
                    let (literal, _) = literal_to_hir(lit);
                    Some(HirPayloadPredicate {
                        field_idx,
                        literal,
                        ty: ty.clone(),
                    })
                })
                .collect()
        }
        Pattern::Wildcard
        | Pattern::Identifier(_)
        | Pattern::Literal(_)
        | Pattern::Tuple(_)
        | Pattern::Or(_, _)
        | Pattern::Regex { .. } => Vec::new(),
    }
}

fn literal_to_hir(lit: &Literal) -> (HirLiteral, ResolvedTy) {
    match lit {
        Literal::Integer { value, .. } => (HirLiteral::Integer(*value), ResolvedTy::I64),
        Literal::Float(value) => (HirLiteral::Float(*value), ResolvedTy::F64),
        Literal::String(value) => (HirLiteral::String(value.clone()), ResolvedTy::String),
        Literal::Bool(value) => (HirLiteral::Bool(*value), ResolvedTy::Bool),
        Literal::Char(value) => (HirLiteral::Char(*value), ResolvedTy::Char),
        Literal::Duration(value) => (HirLiteral::Duration(*value), ResolvedTy::Duration),
    }
}

#[derive(Debug, Clone)]
enum ForIterNextCall {
    BuiltinVecIter,
    VarSelf(HirVarSelfMethodTarget),
    /// `for x in <generator>` — each iteration consumes one value via the
    /// generator `.next()` consumption seam (`HirExprKind::GeneratorNext`).
    /// The generator handle is the loop's `__hew_for_iter_*` binding; it is
    /// borrowed by each `.next()` and freed by its scope-exit drop on loop exit.
    Generator,
}

fn literal_match_supported(lit: &HirLiteral, ty: &ResolvedTy) -> bool {
    match (lit, ty) {
        (HirLiteral::Integer(_), ty) => literal_match_integer_ty(ty),
        (HirLiteral::Bool(_), ResolvedTy::Bool)
        | (HirLiteral::Char(_), ResolvedTy::Char)
        | (HirLiteral::String(_), ResolvedTy::String) => true,
        _ => false,
    }
}

fn literal_match_integer_ty(ty: &ResolvedTy) -> bool {
    ty.is_integer() && !matches!(ty, ResolvedTy::Isize | ResolvedTy::Usize)
}

impl TargetArch {
    /// Returns the target architecture of the host running the compiler.
    /// Used for tests that don't need to test cross-compilation behavior.
    #[must_use]
    pub fn host() -> Self {
        #[cfg(target_arch = "x86_64")]
        return TargetArch::X86_64;
        #[cfg(target_arch = "aarch64")]
        return TargetArch::Aarch64;
        #[cfg(target_arch = "wasm32")]
        return TargetArch::Wasm32;
        #[cfg(not(any(
            target_arch = "x86_64",
            target_arch = "aarch64",
            target_arch = "wasm32"
        )))]
        return TargetArch::Other;
    }
}

type ScopeBinding = (BindingId, ResolvedTy, std::ops::Range<usize>);
type ScopeMap = HashMap<String, ScopeBinding>;
type OuterClosureBinding = (String, ResolvedTy, std::ops::Range<usize>);
type ClosureCaptureCandidate = (BindingId, String, std::ops::Range<usize>);
const SYNTHETIC_OPTION_ITEM: ItemId = ItemId(u32::MAX - 1);
const SYNTHETIC_RESULT_ITEM: ItemId = ItemId(u32::MAX - 2);
/// `LookupError` is declared in `std/builtins.hew`, but builtins.hew is
/// loaded out-of-band (not via `module_graph`), so the user-enum walk in
/// `lower_program` never sees it. Surface it through the same builtin-enum
/// path as `Option` / `Result` so `Err(LookupError::NotFound)` match arms
/// resolve via `machine_ctor_registry`.
const SYNTHETIC_LOOKUP_ERROR_ITEM: ItemId = ItemId(u32::MAX - 1000);
/// `SendError` is also declared in `std/builtins.hew` and likewise invisible
/// to the user-enum walk. Surface it so `match e { SendError::NodeRoutingNotWired
/// => ... }` arms inside `Result<(), SendError>` matches resolve via
/// `machine_ctor_registry`. Variant order matches `hew-codegen-rs/src/llvm.rs`:
/// Full=0, Closed=1, NodeRoutingNotWired=2.
const SYNTHETIC_SEND_ERROR_ITEM: ItemId = ItemId(u32::MAX - 1001);
const SYNTHETIC_VEC_ITER_ITEM: ItemId = ItemId(u32::MAX - 1002);
const BUILTINS_HEW_SOURCE: &str = include_str!("../../std/builtins.hew");

/// Synthetic-builtin sentinel `ItemId`s for the actor `link(target)` /
/// `monitor(target)` builtins. These have no AST `fn` item, so
/// `seed_stdlib_fn_registry` mints them in the `u32::MAX / 2` band — the same
/// band as `supervisor_stop` (`u32::MAX / 2`) and the `hew_duplex_*` family
/// (`u32::MAX / 2 - 1 - offset`, offsets 0..=7). `link`/`monitor` sit just
/// below the duplex slots. The MIR user-name → C-symbol bridge
/// (`runtime_symbol_for_call_expr`) exempts this band from the
/// `ResolvedRef::Item(_)` guard via [`is_synthetic_builtin_item`].
const SYNTHETIC_LINK_ITEM: ItemId = ItemId(u32::MAX / 2 - 9);
const SYNTHETIC_MONITOR_ITEM: ItemId = ItemId(u32::MAX / 2 - 10);

/// Synthetic-builtin sentinel `ItemId` for the user-facing `duplex_pair`
/// constructor. The checker (`Checker::register_builtins`) registers it as a
/// builtin function with no AST `fn` item, so — like `link`/`monitor`/
/// `supervisor_stop` — it needs a synthetic `Item(id)` in `fn_registry` for
/// `lower_identifier` to resolve and for `verify_hir` to accept (it rejects
/// `Unresolved` callee refs). It sits just below `monitor` in the same
/// `u32::MAX / 2` band, inside the [`SYNTHETIC_BUILTIN_ITEM_FLOOR`] band, so
/// the MIR user-name → C-symbol bridge (`runtime_symbol_for_call_expr`)
/// exempts it from its `ResolvedRef::Item(_)` guard via
/// [`is_synthetic_builtin_item`] and routes it to `hew_duplex_pair`.
///
/// The sibling checker builtin `duplex` (detached) is deliberately NOT seeded
/// here: `duplex` has no runtime constructor (`hew_duplex_new` was removed in
/// the M2 runtime refactor). Registering it would pass `verify_hir` but fail
/// closed at the MIR boundary — pretend-support rather than a real lowering
/// path. The runnable Stream/Sink constructor surface is `std::stream`'s
/// `pipe`/`bytes_pipe` (real `fn` items).
const SYNTHETIC_DUPLEX_PAIR_ITEM: ItemId = ItemId(u32::MAX / 2 - 11);

/// Synthetic-builtin sentinel `ItemId`s for the four channel recv out-param-ABI
/// symbols (`hew_channel_recv`, `hew_channel_recv_int`, `hew_channel_try_recv`,
/// `hew_channel_try_recv_int`).
///
/// These symbols are registered by the checker (`registration.rs:5364`) but
/// are NOT extern-declared in `std/channel/channel.hew` (they use an
/// out-parameter ABI for `Option<T>` that cannot be expressed as a plain
/// `extern "C"` declaration). Without a synthetic `fn_registry` entry the HIR
/// import filter (`collect_all_bare_call_names`) would see these bare names as
/// unresolvable and skip the `recv`/`try_recv` impl methods entirely, leaving
/// the user with a "no method recv" error.
///
/// By seeding them here:
///   1. The import filter admits `recv`/`try_recv` (the body calls are now
///      resolvable via `fn_registry`).
///   2. `lower_identifier` resolves them to `ResolvedRef::Item(_)` rather than
///      `Unresolved`, so the HIR callable-set gate fires `CallableUnsupportedInMir`
///      (which `build_callable_set` then silences) rather than the premature
///      `IndirectCallUnsupported`.
///   3. `is_synthetic_builtin_item` admits the IDs, so MIR's
///      `runtime_symbol_for_call_expr` does NOT short-circuit on the
///      `ResolvedRef::Item` guard and reaches the `user_name_to_c_symbol`
///      table; since these names have no entry there, the function returns
///      `None`, and MIR falls through to `module_fn_names` (which this lane
///      also populates) → `lower_direct_call` → `Terminator::Call`.
///   4. Codegen intercepts the `Terminator::Call` by callee name and emits the
///      custom null-ptr → `Option<T>` materialisation sequence.
const SYNTHETIC_CHANNEL_RECV_STR_ITEM: ItemId = ItemId(u32::MAX / 2 - 12);
const SYNTHETIC_CHANNEL_RECV_INT_ITEM: ItemId = ItemId(u32::MAX / 2 - 13);
const SYNTHETIC_CHANNEL_TRY_RECV_STR_ITEM: ItemId = ItemId(u32::MAX / 2 - 14);
const SYNTHETIC_CHANNEL_TRY_RECV_INT_ITEM: ItemId = ItemId(u32::MAX / 2 - 15);

/// Inclusive floor of the synthetic-builtin sentinel `ItemId` band.
///
/// `seed_stdlib_fn_registry` mints checker-registered runtime builtins that
/// have no AST `fn` item into the high `u32` range: the stdlib catalog at
/// `u32::MAX - index`, and the C-symbol-bridge builtins (`supervisor_stop`,
/// `link`, `monitor`, the `hew_duplex_*` family) in the `u32::MAX / 2` band.
/// Source items count up from 0, so this floor (chosen well below the lowest
/// sentinel and far above any realistic source-item count) cleanly separates
/// synthetic sentinels from user items.
pub const SYNTHETIC_BUILTIN_ITEM_FLOOR: u32 = u32::MAX / 2 - 4096;

/// True when `id` is a synthetic-builtin sentinel `ItemId` (see
/// [`SYNTHETIC_BUILTIN_ITEM_FLOOR`]).
///
/// The MIR producer uses this to exempt synthetic builtins from the
/// `ResolvedRef::Item(_)` short-circuit in `runtime_symbol_for_call_expr`,
/// so that `link`/`monitor`/`supervisor_stop` reach the user-name → C-symbol
/// bridge while a *real* user function item that happens to share a builtin
/// name (low `ItemId`) stays blocked. The bridge's own narrow allowlist
/// (`user_name_to_c_symbol`) is the second gate, so exempting the whole
/// sentinel band cannot mis-route any name outside that allowlist.
#[must_use]
pub fn is_synthetic_builtin_item(id: ItemId) -> bool {
    id.0 >= SYNTHETIC_BUILTIN_ITEM_FLOOR
}

/// Bare-name variants of built-in tagged unions. Counted into the pre-pass's
/// `bare_counts` so a user enum that redeclares one of them correctly marks
/// the bare form as ambiguous. Must include every variant of every spec in
/// `builtin_enum_specs()` — omissions cause silent overwrites of user
/// machine-state ctor entries in `machine_ctor_registry` (the `Full` /
/// `Closed` / `NodeRoutingNotWired` `SendError` variants and `NotFound`
/// `LookupError` variant were the original regression that motivated this
/// completeness rule).
const BUILTIN_ENUM_VARIANT_BARE_NAMES: &[&str] = &[
    "Some",
    "None",
    "NoError",
    "Ok",
    "Err",
    "NotFound",
    "Full",
    "Closed",
    "NodeRoutingNotWired",
    "NodeNotRunning",
    "RoutingFailed",
    "EncodeFailed",
    "SendFailed",
    "Timeout",
    "ConnectionDropped",
    "PayloadSizeMismatch",
    "WorkerAtCapacity",
    "ActorStopped",
    "MailboxFull",
    "OrphanedAsk",
    "NoRunnableWork",
];

/// Description of a built-in tagged union for the HIR pre-pass that seeds
/// the same registries user enums populate (`machine_ctor_registry`,
/// `enum_variants_by_name`, `enum_type_params`, `enum_item_ids`). Variant
/// payload type-parameter names index into `type_params`.
struct BuiltinEnumSpec {
    type_name: &'static str,
    item_id: ItemId,
    type_params: &'static [&'static str],
    variant_names: &'static [&'static str],
    /// Per-variant payload, listed as the type-parameter names that appear
    /// in the variant. Empty inner slice means a unit variant.
    variant_payloads: &'static [&'static [&'static str]],
}

fn builtin_enum_specs() -> &'static [BuiltinEnumSpec] {
    &[
        BuiltinEnumSpec {
            type_name: "Option",
            item_id: SYNTHETIC_OPTION_ITEM,
            type_params: &["T"],
            variant_names: &["Some", "None"],
            variant_payloads: &[&["T"], &[]],
        },
        BuiltinEnumSpec {
            type_name: "Result",
            item_id: SYNTHETIC_RESULT_ITEM,
            type_params: &["T", "E"],
            variant_names: &["Ok", "Err"],
            variant_payloads: &[&["T"], &["E"]],
        },
        BuiltinEnumSpec {
            type_name: "LookupError",
            item_id: SYNTHETIC_LOOKUP_ERROR_ITEM,
            type_params: &[],
            variant_names: &["NotFound"],
            variant_payloads: &[&[]],
        },
        BuiltinEnumSpec {
            type_name: "SendError",
            item_id: SYNTHETIC_SEND_ERROR_ITEM,
            type_params: &[],
            variant_names: &["Full", "Closed", "NodeRoutingNotWired"],
            variant_payloads: &[&[], &[], &[]],
        },
        BuiltinEnumSpec {
            type_name: "AskError",
            item_id: ItemId(u32::MAX - 1003),
            type_params: &[],
            variant_names: &[
                "NoError",
                "NodeNotRunning",
                "RoutingFailed",
                "EncodeFailed",
                "SendFailed",
                "Timeout",
                "ConnectionDropped",
                "PayloadSizeMismatch",
                "WorkerAtCapacity",
                "ActorStopped",
                "MailboxFull",
                "OrphanedAsk",
                "NoRunnableWork",
            ],
            variant_payloads: &[
                &[],
                &[],
                &[],
                &[],
                &[],
                &[],
                &[],
                &[],
                &[],
                &[],
                &[],
                &[],
                &[],
            ],
        },
    ]
}

#[derive(Debug, Clone, Default)]
pub struct ResolutionCtx;

/// Output of [`lower_program`].
///
/// The `diagnostics` field is checked by all production pipelines before the
/// `module` is passed downstream.  The [`LowerOutput::into_result`] method
/// provides a fail-closed boundary: it returns `Err(diagnostics)` when any
/// `CheckerBoundaryViolation` is present, making it impossible to silently
/// continue past checker-boundary failures.
#[derive(Debug, Clone, PartialEq)]
pub struct LowerOutput {
    pub module: HirModule,
    pub diagnostics: Vec<HirDiagnostic>,
}

impl LowerOutput {
    /// Converts `self` into `Ok(module)` when no fatal diagnostics are
    /// present, or `Err(diagnostics)` when at least one fatal diagnostic
    /// exists.
    ///
    /// **Fatal diagnostic kinds** (fail-closed set):
    /// - [`HirDiagnosticKind::CheckerBoundaryViolation`] — a checker-authority
    ///   invariant was violated (e.g. a leaked inference variable).
    /// - [`HirDiagnosticKind::RecordLayoutMissing`] — a generic record init
    ///   site was accepted by the checker but its type-arg entry was absent,
    ///   meaning the downstream `Named { args: [] }` shape would be wrong.
    ///
    /// - [`HirDiagnosticKind::TargetCoroutineUnsupported`] — the program uses
    ///   actors/tasks/coroutines on a target that does not support them.
    /// - [`HirDiagnosticKind::BlockingChannelRecvUnsupportedOnWasm`] — the
    ///   program calls blocking channel recv on wasm32.
    /// - [`HirDiagnosticKind::SupervisorPoolChildAccessorUnsupported`] — the
    ///   program performs `sup.pool_child` field access on a pool slot
    ///   (v0.6 `hew_supervisor_pool_route` ABI not yet implemented).
    /// - [`HirDiagnosticKind::NestedSupervisorAccessorUnsupported`] — the
    ///   program performs `sup.nested` field access where the named child
    ///   is itself a supervisor (v0.6 `hew_supervisor_nested_get` ABI not
    ///   yet implemented).
    /// - [`HirDiagnosticKind::ActorSendRequiresUnitHandler`] — the program
    ///   calls bare `.send(msg)` on an actor handle whose receive handler
    ///   returns a non-unit type (must use `.ask()` + `await` instead).
    /// - [`HirDiagnosticKind::BinaryOperatorUnsupportedInMir`] — value-position
    ///   range operator (FC-P1-D).
    /// - [`HirDiagnosticKind::PlatformSizedDivRemUnsupported`] — div/mod on
    ///   `isize` (FC-P1-D).
    /// - [`HirDiagnosticKind::PlatformSizedShiftUnsupported`] — shift on
    ///   `isize`/`usize` (FC-P1-D).
    /// - [`HirDiagnosticKind::CallableUnsupportedInMir`] — a call expression
    ///   resolves to an item with no MIR body or runtime-ABI lowering.
    /// - [`HirDiagnosticKind::IndirectCallUnsupported`] — a call expression
    ///   has an unresolved callee with callable static type that the MIR
    ///   producer cannot dispatch.
    /// - [`HirDiagnosticKind::SupervisorSpawnArgsUnsupported`] — the program
    ///   calls `spawn AppSupervisor(...)` with init args.
    /// - [`HirDiagnosticKind::VecIndexElementTypeUnsupported`] — `xs[i]` on
    ///   a `Vec<T>` whose element type `T` has no `hew_vec_get_T` getter.
    /// - [`HirDiagnosticKind::VecSliceElementTypeUnsupported`] — `xs[a..b]`
    ///   on a `Vec<T>` whose element type `T` has no
    ///   `hew_vec_slice_range_T` runtime symbol.
    /// - [`HirDiagnosticKind::MonomorphisationCallTypeArgsViolation`] — a
    ///   generic-function call's `call_type_args` entry failed the
    ///   `ResolvedTy::from_ty` boundary conversion (e.g. contained `Ty::Error`
    ///   or an unresolved inference variable); passing a corrupt monomorphisation
    ///   entry downstream produces an invalid MIR.
    /// - [`HirDiagnosticKind::RecordLayoutTypeArgsViolation`] — same as above
    ///   for the record-layout side-table.
    ///
    /// Callers that want to continue despite non-fatal diagnostics should
    /// check `.diagnostics` directly.  This method is the recommended
    /// entry-point for production pipelines because it makes the fail-closed
    /// contract impossible to accidentally bypass.
    ///
    /// # Errors
    ///
    /// Returns `Err(diagnostics)` when the output contains at least one fatal
    /// diagnostic (see above).
    ///
    /// TODO: if more fail-closed diagnostic kinds are added, consider a
    /// `severity()` method on `HirDiagnosticKind` returning `Fatal | NonFatal`
    /// so this match does not need updating each time (approach (b)).
    pub fn into_result(self) -> Result<HirModule, Vec<HirDiagnostic>> {
        let has_fatal = self.diagnostics.iter().any(|d| {
            matches!(
                d.kind,
                crate::HirDiagnosticKind::CheckerBoundaryViolation { .. }
                    | crate::HirDiagnosticKind::RecordLayoutMissing { .. }
                    | crate::HirDiagnosticKind::ImportedBodyMissingPrivateHelper { .. }
                    | crate::HirDiagnosticKind::ImportedFreeFnBodyUnresolvedBareCall { .. }
                    | crate::HirDiagnosticKind::TargetCoroutineUnsupported { .. }
                    | crate::HirDiagnosticKind::BlockingChannelRecvUnsupportedOnWasm { .. }
                    | crate::HirDiagnosticKind::TaskSpawnSignatureUnsupported { .. }
                    | crate::HirDiagnosticKind::TaskSpawnCalleeUnsupported { .. }
                    | crate::HirDiagnosticKind::SpawnedClosureSignatureUnsupported { .. }
                    | crate::HirDiagnosticKind::SpawnedClosureNonSendCapture { .. }
                    | crate::HirDiagnosticKind::ForkBlockBodyUnsupported { .. }
                    | crate::HirDiagnosticKind::DeadlineBodyUnsupported { .. }
                    | crate::HirDiagnosticKind::AwaitTaskResultUnsupported { .. }
                    | crate::HirDiagnosticKind::SupervisorPoolChildAccessorUnsupported { .. }
                    | crate::HirDiagnosticKind::NestedSupervisorAccessorUnsupported { .. }
                    | crate::HirDiagnosticKind::ActorSendRequiresUnitHandler { .. }
                    | crate::HirDiagnosticKind::BinaryOperatorUnsupportedInMir { .. }
                    | crate::HirDiagnosticKind::PlatformSizedDivRemUnsupported { .. }
                    | crate::HirDiagnosticKind::PlatformSizedShiftUnsupported { .. }
                    | crate::HirDiagnosticKind::CallableUnsupportedInMir { .. }
                    | crate::HirDiagnosticKind::IndirectCallUnsupported { .. }
                    | crate::HirDiagnosticKind::SupervisorSpawnArgsUnsupported { .. }
                    | crate::HirDiagnosticKind::VecIndexElementTypeUnsupported { .. }
                    | crate::HirDiagnosticKind::VecSliceElementTypeUnsupported { .. }
                    | crate::HirDiagnosticKind::CloneNotYetSupported { .. }
                    | crate::HirDiagnosticKind::MonomorphisationCallTypeArgsViolation { .. }
                    | crate::HirDiagnosticKind::RecordLayoutTypeArgsViolation { .. }
            )
        });
        if has_fatal {
            Err(self.diagnostics)
        } else {
            Ok(self.module)
        }
    }
}

/// Pre-collected signature of a top-level function item.
#[derive(Debug, Clone)]
struct FnEntry {
    id: ItemId,
    return_ty: ResolvedTy,
    param_tys: Vec<ResolvedTy>,
    linkage: Option<BuiltinLinkage>,
    /// Source-declared generic type parameter names, in order. Empty for
    /// non-generic functions. Consulted at `Expr::Call` lowering sites to
    /// decide whether the callee is a generic top-level user fn that
    /// requires a monomorphisation-registry entry.
    type_params: Vec<String>,
}

/// Pre-collected shape of a top-level `const NAME: T = ...;` declaration.
///
/// Populated in the first pass (`register_const_entry`) so that const
/// references resolve to a stable `ItemId` regardless of source order. The
/// folded value is NOT stored here — it is produced once, canonically, in the
/// emit pass (`lower_const`) on the `HirItem::Const`. A const reference only
/// needs the id (for `ResolvedRef::Const`) and the declared type.
#[derive(Debug, Clone)]
struct ConstEntry {
    id: ItemId,
    ty: ResolvedTy,
}
///
/// Populated in the type-decl / record pre-pass and consulted at
/// `Expr::StructInit` lowering to (a) decide whether a record-init site
/// needs a per-instantiation `RecordLayout` and (b) substitute the
/// type-params with the concrete args from `record_init_type_args` to
/// produce the layout's field shape.
///
/// Tuple-form records are admitted with `fields = vec![]` — their
/// constructor is reached via `Expr::Call`, not `StructInit`, so they
/// never hit the record-layout registry. The entry is kept for shape
/// uniformity with the named-form path.
#[derive(Debug)]
struct RecordEntry {
    id: ItemId,
    /// Source-declared generic type-parameter names, in order. Empty for
    /// monomorphic record/type declarations.
    type_params: Vec<String>,
    /// Field shape as written in source — types still mention the
    /// declaration's type params verbatim (no substitution yet). The
    /// record-layout registry walks these and substitutes per
    /// instantiation.
    fields: Vec<(String, ResolvedTy)>,
}

/// Pre-collected inherent-impl `close` method signature for a `#[resource]`
/// type. Populated before the type-decl pre-pass by walking `program.items`
/// for inherent `impl T { fn close(...) {...} }` blocks (no trait bound,
/// nominal target). Consulted by `lower_type_decl` to:
///
///   1. Broaden the `ResourceMissingClose` presence check beyond inline
///      `TypeBodyItem::Method` (W3.030 Q-α-B): a `#[resource]` may declare
///      `close` in a sibling inherent-impl block rather than in the type
///      body itself.
///   2. Enforce the `close`-must-return-unit discipline at the HIR
///      boundary (W3.030 Q-β-C): fallible cleanup composes through
///      `defer`, not through a non-unit `close` return.
#[derive(Debug)]
struct ImplCloseSignature {
    /// Span of the declaration site (the impl-block method's `decl_span`
    /// when available, else its `fn_span`). Used as the diagnostic anchor
    /// for `ResourceCloseMustReturnUnit`.
    decl_span: Span,
    /// `true` when the declared return type is unit — either no `->`
    /// clause or an explicit `()` tuple-of-zero.
    return_ty_unit: bool,
    /// User-facing rendering of the offending non-unit return type. Only
    /// meaningful when `!return_ty_unit`.
    return_ty_display: String,
}

/// Per-impl-block context threaded into `lower_impl_block` for imported
/// modules. Carries the same-module fn-name rewrite map (bare helper name →
/// mangled qualified symbol, identical to the free-function imported path) and
/// the set of method names to skip because their bodies call a private helper
/// the importer cannot reach.
struct ImportedImplLowering<'a> {
    rewrites: &'a HashMap<String, String>,
    skip_methods: &'a HashSet<String>,
}

/// Walk the root program's items collecting inherent-impl `close` method
/// signatures, keyed by the self-type name. Trait impls (`impl T for U`)
/// are deliberately skipped — the `close` ritual under the W3.030 contract
/// is dispatched through `<T>::close` as an inherent method symbol; trait
/// methods would land at `<T as Trait>::close` and are not the surface
/// W3.030 owns. Multiple inherent impls declaring `close` on the same
/// nominal would be a duplicate-symbol error caught downstream; this
/// collector keeps the first occurrence and ignores any later ones.
fn collect_inherent_impl_close_methods(
    items: &[(Item, Span)],
) -> HashMap<String, ImplCloseSignature> {
    let mut out: HashMap<String, ImplCloseSignature> = HashMap::new();
    for (item, _item_span) in items {
        let Item::Impl(impl_decl) = item else {
            continue;
        };
        if impl_decl.trait_bound.is_some() {
            continue;
        }
        let TypeExpr::Named {
            name: self_type_name,
            ..
        } = &impl_decl.target_type.0
        else {
            continue;
        };
        for method in &impl_decl.methods {
            if method.name != "close" {
                continue;
            }
            let (return_ty_unit, return_ty_display) = match &method.return_type {
                None => (true, String::new()),
                Some((TypeExpr::Tuple(items), _)) if items.is_empty() => (true, String::new()),
                Some((ty_expr, _)) => (false, render_type_expr(ty_expr)),
            };
            let decl_span = if method.decl_span.start == method.decl_span.end {
                method.fn_span.clone()
            } else {
                method.decl_span.clone()
            };
            out.entry(self_type_name.clone())
                .or_insert(ImplCloseSignature {
                    decl_span,
                    return_ty_unit,
                    return_ty_display,
                });
            // Once we found a `close` on this impl, stop scanning its
            // methods — a single impl-block cannot declare two methods
            // with the same name.
            break;
        }
    }
    out
}

/// Collect trait default method bodies from all `Item::Trait` declarations
/// in the root program. Keyed by trait name; values are the `TraitMethod`
/// entries that carry a non-`None` body. Used by `lower_impl_block` to lower
/// default methods for concrete impls that do not override them.
fn collect_trait_default_methods(items: &[(Item, Span)]) -> HashMap<String, Vec<TraitMethod>> {
    let mut out: HashMap<String, Vec<TraitMethod>> = HashMap::new();
    for (item, _) in items {
        let Item::Trait(trait_decl) = item else {
            continue;
        };
        let defaults: Vec<TraitMethod> = trait_decl
            .items
            .iter()
            .filter_map(|ti| match ti {
                TraitItem::Method(m) if m.body.is_some() => Some(m.clone()),
                _ => None,
            })
            .collect();
        if !defaults.is_empty() {
            out.insert(trait_decl.name.clone(), defaults);
        }
    }
    out
}

/// Harvest opaque-type identity from the whole program (root items + every
/// imported module) for the `ResolvedTy::Named.is_opaque` discriminator
/// stamped by [`LowerCtx::lower_type`]:
///
/// * `opaque` — opaque type names in BOTH forms: the bare short name
///   (`"Value"` for a `#[opaque] type Value` in `std::encoding::json`) AND
///   the module-qualified form (`"json.Value"`). A bare reference matches the
///   short form; a qualified reference (`json.Value`) matches the qualified
///   form EXACTLY, so it cannot be confused with a same-short-name user type
///   in a different module (`m.Value`).
/// * `non_opaque` — short names of every non-opaque user type declaration
///   (`type`/`record`/`enum`/`actor`/`machine`). Used to resolve a BARE
///   reference whose short name is opaque-in-one-module: if a local user type
///   shadows the short name, the bare reference is the user type, not the
///   opaque handle.
///
/// Keeping qualified opaque keys is what makes the discriminator a precise
/// identity fact rather than a short-name heuristic: `m.Value` (user record
/// from module `m`) and `json.Value` (opaque handle) both have short name
/// `"Value"`, but only `json.Value` is in `opaque` under its qualified key.
fn collect_opaque_type_short_names(
    program: &Program,
    opaque: &mut HashSet<String>,
    non_opaque: &mut HashSet<String>,
) {
    fn visit_items(
        items: &[(Item, Span)],
        module_short: Option<&str>,
        opaque: &mut HashSet<String>,
        non_opaque: &mut HashSet<String>,
    ) {
        for (item, _) in items {
            match item {
                Item::TypeDecl(decl) => {
                    if decl.is_opaque {
                        opaque.insert(decl.name.clone());
                        if let Some(m) = module_short {
                            opaque.insert(format!("{m}.{}", decl.name));
                        }
                    } else {
                        non_opaque.insert(decl.name.clone());
                    }
                }
                // `record`/`enum`/`actor`/`machine` are never `#[opaque]`
                // (opacity is only expressible on `type` decls), so they only
                // ever contribute to the non-opaque complement.
                Item::Record(decl) => {
                    non_opaque.insert(decl.name.clone());
                }
                Item::Actor(decl) => {
                    non_opaque.insert(decl.name.clone());
                }
                Item::Machine(decl) => {
                    non_opaque.insert(decl.name.clone());
                }
                _ => {}
            }
        }
    }

    visit_items(&program.items, None, opaque, non_opaque);
    if let Some(ref mg) = program.module_graph {
        for mod_id in &mg.topo_order {
            if *mod_id == mg.root {
                continue;
            }
            if let Some(module) = mg.modules.get(mod_id) {
                let module_short = mod_id.path.last().map(String::as_str);
                visit_items(&module.items, module_short, opaque, non_opaque);
            }
        }
    }
}

/// Synthesize a `FnDecl` from a `TraitMethod` for HIR lowering purposes.
/// The resulting `FnDecl` carries the default body and the same signature
/// as the trait declaration. `current_impl_self_ty` in the lowering context
/// handles substituting `Self` for the concrete type.
fn trait_method_to_fn_decl(method: &TraitMethod) -> FnDecl {
    FnDecl {
        attributes: vec![],
        is_async: false,
        is_generator: false,
        visibility: hew_parser::ast::Visibility::Private,
        name: method.name.clone(),
        type_params: method.type_params.clone(),
        params: method.params.clone(),
        return_type: method.return_type.clone(),
        where_clause: method.where_clause.clone(),
        // Only called for methods where `body.is_some()`; the unwrap is safe.
        body: method
            .body
            .clone()
            .expect("trait_method_to_fn_decl called on method without body"),
        doc_comment: None,
        decl_span: 0..0,
        fn_span: 0..0,
        intrinsic: None,
    }
}

/// Compact, user-facing rendering of a parser-side `TypeExpr` used by the
/// `ResourceCloseMustReturnUnit` diagnostic. Best-effort; complex / deeply
/// nested shapes degrade to a short description rather than a full pretty
/// print — the diagnostic's purpose is to name what the user wrote enough
/// to direct them to the fix, not to round-trip the AST.
fn render_type_expr(ty: &TypeExpr) -> String {
    match ty {
        TypeExpr::Named { name, type_args } => match type_args {
            Some(args) if !args.is_empty() => {
                let inner: Vec<String> = args.iter().map(|a| render_type_expr(&a.0)).collect();
                format!("{name}<{}>", inner.join(", "))
            }
            _ => name.clone(),
        },
        TypeExpr::Result { ok, err } => {
            format!(
                "Result<{}, {}>",
                render_type_expr(&ok.0),
                render_type_expr(&err.0)
            )
        }
        TypeExpr::Option(inner) => format!("Option<{}>", render_type_expr(&inner.0)),
        TypeExpr::Tuple(items) => {
            if items.is_empty() {
                "()".to_string()
            } else {
                let inner: Vec<String> = items.iter().map(|t| render_type_expr(&t.0)).collect();
                format!("({})", inner.join(", "))
            }
        }
        TypeExpr::Array { element, size } => {
            format!("[{}; {size}]", render_type_expr(&element.0))
        }
        TypeExpr::Slice(inner) => format!("[{}]", render_type_expr(&inner.0)),
        TypeExpr::Function {
            params,
            return_type,
        } => {
            let ps: Vec<String> = params.iter().map(|p| render_type_expr(&p.0)).collect();
            format!(
                "fn({}) -> {}",
                ps.join(", "),
                render_type_expr(&return_type.0)
            )
        }
        TypeExpr::Pointer {
            is_mutable,
            pointee,
        } => {
            let m = if *is_mutable { "mut " } else { "" };
            format!("*{m}{}", render_type_expr(&pointee.0))
        }
        TypeExpr::TraitObject(_) => "dyn Trait".to_string(),
        TypeExpr::Borrow(inner) => format!("&{}", render_type_expr(&inner.0)),
        TypeExpr::Infer => "_".to_string(),
    }
}

fn builtin_receiver_impl_program() -> Option<Program> {
    let parsed = hew_parser::parse(BUILTINS_HEW_SOURCE);
    debug_assert!(
        parsed.errors.is_empty(),
        "std/builtins.hew failed to parse: {:?}",
        parsed.errors
    );
    if !parsed.errors.is_empty() {
        return None;
    }
    let items = parsed
        .program
        .items
        .into_iter()
        .filter(|(item, _)| {
            matches!(
                item,
                Item::Trait(tr) if tr.name == "Iterator" || tr.name == "IntoIterator"
            ) || matches!(item, Item::TypeDecl(td) if td.name == "VecIter")
                || is_builtin_receiver_impl(item)
        })
        .collect();
    Some(Program {
        items,
        module_doc: None,
        module_graph: None,
    })
}

fn is_builtin_vec_iterator_impl(item: &Item) -> bool {
    let Item::Impl(impl_decl) = item else {
        return false;
    };
    let Some(trait_name) = impl_decl
        .trait_bound
        .as_ref()
        .map(|bound| bound.name.as_str())
    else {
        return false;
    };
    let TypeExpr::Named { name, .. } = &impl_decl.target_type.0 else {
        return false;
    };
    matches!(
        (trait_name, name.as_str()),
        ("Iterator", "VecIter") | ("IntoIterator", "Vec")
    )
}

fn is_builtin_display_impl(item: &Item) -> bool {
    let Item::Impl(impl_decl) = item else {
        return false;
    };
    let Some(trait_name) = impl_decl
        .trait_bound
        .as_ref()
        .map(|bound| bound.name.as_str())
    else {
        return false;
    };
    let TypeExpr::Named { name, .. } = &impl_decl.target_type.0 else {
        return false;
    };
    trait_name == "Display"
        && matches!(
            name.as_str(),
            "i32" | "i64" | "u32" | "u64" | "bool" | "char" | "f64" | "string"
        )
}

fn is_builtin_receiver_impl(item: &Item) -> bool {
    is_builtin_vec_iterator_impl(item) || is_builtin_display_impl(item)
}

fn impl_type_param_names(decl: &hew_parser::ast::ImplDecl) -> Vec<String> {
    decl.type_params
        .as_ref()
        .map(|params| params.iter().map(|param| param.name.clone()).collect())
        .unwrap_or_default()
}

fn check_builtin_receiver_impl_program(program: &Program) -> TypeCheckOutput {
    let mut checker =
        hew_types::Checker::new(hew_types::module_registry::ModuleRegistry::new(Vec::new()));
    let output = checker.check_program(program);
    debug_assert!(
        output.errors.is_empty(),
        "std/builtins.hew receiver impls failed to type-check: {:?}",
        output.errors
    );
    output
}

#[must_use]
pub fn lower_program(
    program: &Program,
    type_check_output: &TypeCheckOutput,
    ctx: &ResolutionCtx,
    target_arch: TargetArch,
) -> LowerOutput {
    lower_program_with_mono_cap(
        program,
        type_check_output,
        ctx,
        MONOMORPHISATION_REGISTRY_CAP,
        target_arch,
    )
}

/// Convenience helper that defaults to the host's target architecture.
/// Used primarily in tests that don't care about cross-compilation.
#[must_use]
pub fn lower_program_host_target(
    program: &Program,
    type_check_output: &TypeCheckOutput,
    ctx: &ResolutionCtx,
) -> LowerOutput {
    lower_program(program, type_check_output, ctx, TargetArch::host())
}

/// Variant of [`lower_program`] with an explicit monomorphisation-registry
/// cap. Intended for tests that exercise the
/// `MonomorphisationCapExceeded` diagnostic with a small fixture; the
/// production entry point [`lower_program`] always uses
/// `MONOMORPHISATION_REGISTRY_CAP`.
#[must_use]
#[allow(
    clippy::too_many_lines,
    reason = "three structured passes (fn pre-pass, record/type-decl pre-pass, \
              source-order emit) read more clearly here than across helpers"
)]
pub fn lower_program_with_mono_cap(
    program: &Program,
    type_check_output: &TypeCheckOutput,
    _ctx: &ResolutionCtx,
    mono_cap: usize,
    target_arch: TargetArch,
) -> LowerOutput {
    let mut ctx = LowerCtx::new(type_check_output, mono_cap, target_arch);
    ctx.seed_stdlib_fn_registry();
    let builtin_receiver_impl_program = builtin_receiver_impl_program();
    let builtin_receiver_impl_output = builtin_receiver_impl_program
        .as_ref()
        .map(check_builtin_receiver_impl_program);

    // Pre-pre-pass: harvest inherent-impl `close` method signatures from
    // the root program so the type-decl pre-pass below can broaden the
    // `ResourceMissingClose` presence check to consider inherent-impl
    // surface and enforce the close-must-return-unit discipline. See
    // [`collect_inherent_impl_close_methods`] for the precise contract
    // (W3.030 Q-α-B + Q-β-C ratifications).
    ctx.impl_close_methods = collect_inherent_impl_close_methods(&program.items);

    // Pre-pre-pass: harvest trait default method bodies so that impl-block
    // lowering can emit them for impls that do not override them.
    ctx.trait_default_methods = collect_trait_default_methods(&program.items);

    // Pre-pre-pass: harvest `#[opaque]` type-decl short names (and the
    // complement of non-opaque user type short names) from the whole program
    // — root items and every imported module. `lower_type` reads these to
    // stamp the `ResolvedTy::Named.is_opaque` discriminator BEFORE any actor
    // state-field type is resolved, so the actor-state clone/drop classifier
    // can tell a real opaque handle apart from a colliding user type by
    // identity rather than by name. See the field docs on `LowerCtx`.
    collect_opaque_type_short_names(
        program,
        &mut ctx.opaque_type_short_names,
        &mut ctx.non_opaque_type_short_names,
    );

    let mut builtin_receiver_impl_method_symbols: HashSet<String> = HashSet::new();

    // First pass: collect all function signatures so that forward and mutual
    // references in call expressions resolve to the correct return type.
    // Diagnostics from this pass are discarded — the same types are re-lowered
    // in the second pass, which is where canonical diagnostics are emitted.
    for (item, _) in &program.items {
        match item {
            Item::Function(func) => {
                ctx.register_fn_entry(&func.name, func);
            }
            Item::ExternBlock(block) => {
                // Register extern fn signatures so call sites resolve them
                // to a `BindingRef::Item` like any other top-level function.
                // Codegen pre-declares the LLVM symbol with external linkage
                // (see `predeclare_extern_decls` in hew-codegen-rs).
                for extern_fn in &block.functions {
                    ctx.register_extern_fn_entry(extern_fn);
                }
            }
            Item::Impl(impl_decl) => {
                // Register methods of any V0b-acceptable impl block under the
                // qualified `<SelfType>::<method>` name so call sites can
                // resolve them in the second pass. The Index special-case is
                // a subset of this — its methods landed in `fn_registry`
                // historically via the same key shape.
                if let TypeExpr::Named { name, .. } = &impl_decl.target_type.0 {
                    if impl_decl.where_clause.is_none()
                        || classify_unsupported_where_clause(impl_decl).is_none()
                    {
                        let impl_type_params = impl_type_param_names(impl_decl);
                        for method in &impl_decl.methods {
                            ctx.register_impl_method_fn_entry(name, method, &impl_type_params);
                        }
                        // Also register trait default methods that are NOT
                        // overridden in this impl block — they need fn_registry
                        // entries so call sites resolve `Type::method` even
                        // when the body lives on the trait declaration.
                        if let Some(tb) = &impl_decl.trait_bound {
                            let overridden: HashSet<&str> =
                                impl_decl.methods.iter().map(|m| m.name.as_str()).collect();
                            if let Some(defaults) = ctx.trait_default_methods.get(&tb.name).cloned()
                            {
                                for default_method in &defaults {
                                    if !overridden.contains(default_method.name.as_str()) {
                                        let fn_decl = trait_method_to_fn_decl(default_method);
                                        ctx.register_impl_method_fn_entry(
                                            name,
                                            &fn_decl,
                                            &impl_type_params,
                                        );
                                    }
                                }
                            }
                        }
                    }
                }
            }
            Item::Const(const_decl) => {
                ctx.register_const_entry(const_decl);
            }
            // No fn signatures to register for the variants below in this
            // pass. If a new Item variant is added, the compiler will force a
            // conscious decision here.
            Item::Import(_)
            | Item::TypeDecl(_)
            | Item::TypeAlias(_)
            | Item::Trait(_)
            | Item::Wire(_)
            | Item::Machine(_)
            | Item::Record(_)
            | Item::Actor(_)
            | Item::Supervisor(_) => {}
        }
    }
    // Pre-pass: register user-module pub fn signatures under their qualified,
    // native-symbol-safe key (e.g. `greeting$hello`) so that HIR's
    // `RewriteModuleQualifiedToFunction` arm can resolve the callee `ItemId`
    // at the call site.  Only `pub` functions are callable across module
    // boundaries; private functions are invisible to importers.
    //
    // This walk runs AFTER the root-item pre-pass above so that any name
    // clash between a qualified key and a root-level function is caught by
    // the duplicate-short-module diagnostic in the frontend before HIR ingest.
    if let Some(ref mg) = program.module_graph {
        for mod_id in &mg.topo_order {
            if *mod_id == mg.root {
                continue;
            }
            let module_short = mod_id.path.last().map_or("", String::as_str);
            if let Some(module) = mg.modules.get(mod_id) {
                for (item, _) in &module.items {
                    match item {
                        Item::Function(func) if func.visibility.is_pub() => {
                            let qualified =
                                crate::mangle_dotted_name(&format!("{module_short}.{}", func.name));
                            ctx.register_fn_entry(&qualified, func);
                        }
                        // Register public type declarations plus private
                        // struct records from imported modules into
                        // `record_registry` so `Expr::StructInit` and
                        // `Expr::FieldAccess` lowering can resolve their field
                        // layouts. Without this, field access on imported
                        // non-generic private FFI-result records fails with
                        // `NotYetImplemented` because the layout is missing
                        // from `record_field_orders` at MIR time.
                        //
                        // All matching TypeDecls from non-root modules are
                        // registered, not just monomorphic ones; the generic
                        // case is filtered at MIR layout-emission time (same
                        // rule as root items). Private imported generic
                        // handles stay on their existing intrinsic paths, and
                        // private imported enums stay on the existing enum-only
                        // machinery.
                        Item::TypeDecl(decl)
                            if decl.visibility.is_pub()
                                || (decl.kind == TypeDeclKind::Struct
                                    && decl.type_params.is_none()) =>
                        {
                            let id = ctx.ids.item();
                            let type_params: Vec<String> = decl
                                .type_params
                                .as_ref()
                                .map_or(vec![], |ps| ps.iter().map(|p| p.name.clone()).collect());
                            let mut fields: Vec<(String, ResolvedTy)> = Vec::new();
                            for body_item in &decl.body {
                                if let TypeBodyItem::Field { name, ty, .. } = body_item {
                                    fields.push((name.clone(), ctx.lower_type(ty)));
                                }
                            }
                            ctx.record_registry.insert(
                                decl.name.clone(),
                                RecordEntry {
                                    id,
                                    type_params,
                                    fields,
                                },
                            );
                        }
                        Item::Record(decl) if decl.visibility.is_pub() => {
                            let id = ctx.ids.item();
                            let type_params: Vec<String> = decl
                                .type_params
                                .as_ref()
                                .map_or(vec![], |ps| ps.iter().map(|p| p.name.clone()).collect());
                            let fields: Vec<(String, ResolvedTy)> = match &decl.kind {
                                RecordKind::Named(rfs) => rfs
                                    .iter()
                                    .map(|rf| (rf.name.clone(), ctx.lower_type(&rf.ty)))
                                    .collect(),
                                RecordKind::Tuple(_) => Vec::new(),
                            };
                            ctx.record_registry.insert(
                                decl.name.clone(),
                                RecordEntry {
                                    id,
                                    type_params,
                                    fields,
                                },
                            );
                            ctx.type_classes
                                .insert(decl.name.clone(), (ResourceMarker::None, None));
                        }
                        // Register extern fn signatures declared by imported
                        // modules so call sites in user code resolve them
                        // through `BindingRef::Item` like any other top-level
                        // function. Without this, `import std::io; io.write(s)`
                        // fails with `UnresolvedSymbol("hew_io_write")` because
                        // the std/io.hew `extern "C" { fn hew_io_write(...); }`
                        // block never reaches `fn_registry`.
                        Item::ExternBlock(block) => {
                            for extern_fn in &block.functions {
                                ctx.register_extern_fn_entry(extern_fn);
                            }
                        }
                        // Register imported impl block methods in `fn_registry`
                        // under the same unqualified `<SelfType>::<method>` key
                        // used for root impl blocks. The key must be unqualified
                        // because the checker's `fn_sigs` table also uses
                        // unqualified keys for impl methods (see
                        // `scoped_module_item_name` / `register_impl_method` in
                        // checker).
                        //
                        // No per-method `pub` gate: impl methods in Hew have no
                        // independent visibility — access is governed by the
                        // trait/type, and impl bodies never carry `pub fn`. The
                        // checker registers EVERY imported impl method into
                        // `fn_sigs` without a `pub` filter and emits
                        // `RewriteToFunction { c_symbol: "<Type>::<method>" }`
                        // for any non-trivial builder method (one whose body is
                        // not a single C pass-through, so it is not captured by
                        // the runtime handle-method path). Gating this pre-pass
                        // on `pub` left those `<Type>::<method>` symbols absent
                        // from `fn_registry`, so the call lowered to a
                        // `ResolvedRef::Unresolved` callee and tripped
                        // `IndirectCallUnsupported` at the import boundary
                        // (e.g. `import std::encoding::json` then a `with_*`
                        // builder chain). Matching the root pre-pass (which has
                        // no `pub` filter) keeps HIR aligned with the
                        // checker-authoritative `fn_sigs`.
                        Item::Impl(impl_decl) => {
                            if let TypeExpr::Named { name, .. } = &impl_decl.target_type.0 {
                                if impl_decl.where_clause.is_none()
                                    || classify_unsupported_where_clause(impl_decl).is_none()
                                {
                                    let impl_type_params = impl_type_param_names(impl_decl);
                                    for method in &impl_decl.methods {
                                        ctx.register_impl_method_fn_entry(
                                            name,
                                            method,
                                            &impl_type_params,
                                        );
                                    }
                                }
                            }
                        }
                        // Register all consts from imported modules under their
                        // qualified key `"module_short.CONST_NAME"`.  Pub
                        // consts are needed for cross-module `module.CONST`
                        // field-access resolution; private consts must also be
                        // registered here so that imported function bodies that
                        // reference the module's own private consts by bare
                        // name get a stable `ItemId` that matches the
                        // `HirItem::Const` emitted in the later pass.
                        Item::Const(const_decl) => {
                            let id = ctx.ids.item();
                            let ty = ctx.lower_type(&const_decl.ty);
                            let qualified = format!("{module_short}.{}", const_decl.name);
                            ctx.const_registry.insert(qualified, ConstEntry { id, ty });
                        }
                        // Non-pub Function/TypeDecl/Record fall here (not exported to importers).
                        Item::Import(_)
                        | Item::Function(_)
                        | Item::TypeDecl(_)
                        | Item::TypeAlias(_)
                        | Item::Trait(_)
                        | Item::Wire(_)
                        | Item::Machine(_)
                        | Item::Record(_)
                        | Item::Actor(_)
                        | Item::Supervisor(_) => {}
                    }
                }
            }
        }
    }

    // Pre-pass: collect record/type-decl shapes so `Expr::StructInit`
    // lowering in the source-order pass can answer "is this a generic
    // user record?" regardless of declaration order relative to the
    // function that uses it. This mirrors the fn pre-pass above and is
    // the producer half of the record-layout registry.
    for (item, _) in &program.items {
        match item {
            Item::TypeDecl(decl) => {
                let id = ctx.ids.item();
                let type_params: Vec<String> = decl
                    .type_params
                    .as_ref()
                    .map_or(vec![], |ps| ps.iter().map(|p| p.name.clone()).collect());
                let mut fields: Vec<(String, ResolvedTy)> = Vec::new();
                for body_item in &decl.body {
                    if let TypeBodyItem::Field { name, ty, .. } = body_item {
                        fields.push((name.clone(), ctx.lower_type(ty)));
                    }
                }
                ctx.record_registry.insert(
                    decl.name.clone(),
                    RecordEntry {
                        id,
                        type_params,
                        fields,
                    },
                );
                ctx.type_classes
                    .insert(decl.name.clone(), (ResourceMarker::None, None));
            }
            Item::Record(decl) => {
                let id = ctx.ids.item();
                let type_params: Vec<String> = decl
                    .type_params
                    .as_ref()
                    .map_or(vec![], |ps| ps.iter().map(|p| p.name.clone()).collect());
                let fields: Vec<(String, ResolvedTy)> = match &decl.kind {
                    RecordKind::Named(rfs) => rfs
                        .iter()
                        .map(|rf| (rf.name.clone(), ctx.lower_type(&rf.ty)))
                        .collect(),
                    // Tuple-form records are reached via Expr::Call, not
                    // Expr::StructInit, so their record-layout registry
                    // entry would never be exercised. Record an empty
                    // field list for shape uniformity.
                    RecordKind::Tuple(_) => Vec::new(),
                };
                ctx.record_registry.insert(
                    decl.name.clone(),
                    RecordEntry {
                        id,
                        type_params,
                        fields,
                    },
                );
            }
            // No record shape to register for the variants below. If a new
            // Item variant with field layout is added, the compiler will force
            // a conscious decision here.
            Item::Import(_)
            | Item::Const(_)
            | Item::TypeAlias(_)
            | Item::Trait(_)
            | Item::Impl(_)
            | Item::Wire(_)
            | Item::Function(_)
            | Item::ExternBlock(_)
            | Item::Machine(_)
            | Item::Actor(_)
            | Item::Supervisor(_) => {}
        }
    }
    // Pre-pass: target architecture gates (P0.1-P0.4 fail-closed runtime-panic
    // prevention). Check if the program uses coroutine-dependent constructs
    // (actors/tasks) or wasm32-unsupported constructs (blocking channel recv)
    // on incompatible targets. Emit fatal diagnostics before lowering begins.
    //
    // This pass runs early so rejection happens before any HIR nodes are
    // materialized, keeping the fail-closed contract clear: if a program uses
    // unsupported runtime features, the compile stops here.
    check_target_gates(&mut ctx, program);

    // Pre-pass: register module-scope tagged-union constructors so
    // `lower_identifier` can lower variant references to `MachineVariantCtor`
    // regardless of declaration order relative to the function that uses them.
    //
    // Three surface forms share one tagged-union substrate:
    //   1. Machine states: `TrafficLight::Red`, bare `Red`.
    //   2. Machine event companions: `TrafficLightEvent::Tick`, bare `Tick`.
    //   3. User-defined enum unit variants: `Colour::Red`, bare `Red`.
    //
    // Bare names are registered only when unambiguous across ALL three forms
    // (machines + events + user enums). The qualified form (always prefixed
    // with the tagged-union typename) is always registered. See the doc on
    // `LowerCtx::machine_ctor_registry` for the consumer contract.
    {
        // First scan: count bare-name occurrences across machines' states,
        // machine events, and user enum unit variants. A bare name with
        // count > 1 is ambiguous and only the qualified form is registered.
        //
        // Built-in tagged unions (`Option<T>`, `Result<T, E>`) participate
        // in the same registry so `Ok(42)`, `None`, etc. lower through the
        // same `MachineVariantCtor` / match-arm path as user enums. Each
        // builtin variant contributes one count, so a user enum that
        // redeclares `Some` or `Ok` will correctly mark the bare name as
        // ambiguous (qualified forms still resolve via `Option::Some`,
        // `Result::Ok`).
        let mut bare_counts: HashMap<String, usize> = HashMap::new();
        for name in BUILTIN_ENUM_VARIANT_BARE_NAMES {
            *bare_counts.entry((*name).to_string()).or_insert(0) += 1;
        }
        for (item, _) in &program.items {
            match item {
                Item::Machine(md) => {
                    for state in &md.states {
                        *bare_counts.entry(state.name.clone()).or_insert(0) += 1;
                    }
                    for event in &md.events {
                        *bare_counts.entry(event.name.clone()).or_insert(0) += 1;
                    }
                }
                Item::TypeDecl(td) if td.kind == TypeDeclKind::Enum => {
                    // Count every variant — unit, tuple, struct — so the
                    // ambiguity guard fires across all surface forms (e.g. a
                    // bare `Line` is ambiguous with a `Line(i64)` variant on
                    // another enum just as it is with a unit variant).
                    for body_item in &td.body {
                        if let TypeBodyItem::Variant(v) = body_item {
                            *bare_counts.entry(v.name.clone()).or_insert(0) += 1;
                        }
                    }
                }
                // No variant bare-names to count for these items. If a new
                // Item variant with enumerable named variants is added, the
                // compiler will force a conscious decision here.
                Item::Import(_)
                | Item::Const(_)
                | Item::TypeDecl(_)
                | Item::TypeAlias(_)
                | Item::Trait(_)
                | Item::Impl(_)
                | Item::Wire(_)
                | Item::Function(_)
                | Item::ExternBlock(_)
                | Item::Actor(_)
                | Item::Supervisor(_)
                | Item::Record(_) => {}
            }
        }
        // Mirror the bare-count scan over `program.module_graph` non-root
        // modules so cross-module machine states/events and enum variants
        // participate in the same bare-ambiguity decision as root items.
        // Without this, a bare `On` used by a root function that imports
        // `std::machines::toggle` would not be marked ambiguous against any
        // other `On` in scope, and — more importantly — the qualified form
        // `Toggle::On` would not be registered in `machine_ctor_registry`
        // (next module-graph loop below) since the registration loop is the
        // producer side of the same walk.
        //
        // Gated on `is_pub()` for cross-module emission: a private machine
        // or enum in an imported module is invisible to consumers.
        if let Some(ref mg) = program.module_graph {
            for mod_id in &mg.topo_order {
                if *mod_id == mg.root {
                    continue;
                }
                if let Some(module) = mg.modules.get(mod_id) {
                    for (item, _) in &module.items {
                        match item {
                            Item::Machine(md) if md.visibility.is_pub() => {
                                for state in &md.states {
                                    *bare_counts.entry(state.name.clone()).or_insert(0) += 1;
                                }
                                for event in &md.events {
                                    *bare_counts.entry(event.name.clone()).or_insert(0) += 1;
                                }
                            }
                            Item::TypeDecl(td)
                                if td.visibility.is_pub() && td.kind == TypeDeclKind::Enum =>
                            {
                                for body_item in &td.body {
                                    if let TypeBodyItem::Variant(v) = body_item {
                                        *bare_counts.entry(v.name.clone()).or_insert(0) += 1;
                                    }
                                }
                            }
                            // No pub variant bare-names in imported modules for
                            // these items. Compiler enforces exhaustivity if a
                            // new Item variant is added.
                            Item::Import(_)
                            | Item::Const(_)
                            | Item::TypeDecl(_)
                            | Item::TypeAlias(_)
                            | Item::Trait(_)
                            | Item::Impl(_)
                            | Item::Wire(_)
                            | Item::Function(_)
                            | Item::ExternBlock(_)
                            | Item::Machine(_)
                            | Item::Actor(_)
                            | Item::Supervisor(_)
                            | Item::Record(_) => {}
                        }
                    }
                }
            }
        }
        for (item, _) in &program.items {
            match item {
                Item::Machine(md) => {
                    let event_type_name = format!("{}Event", md.name);
                    for (idx, state) in md.states.iter().enumerate() {
                        let qualified = format!("{}::{}", md.name, state.name);
                        ctx.machine_ctor_registry
                            .insert(qualified, (md.name.clone(), idx));
                        if bare_counts.get(&state.name).copied().unwrap_or(0) == 1 {
                            ctx.machine_ctor_registry
                                .insert(state.name.clone(), (md.name.clone(), idx));
                        }
                    }
                    for (idx, event) in md.events.iter().enumerate() {
                        let qualified = format!("{}::{}", event_type_name, event.name);
                        ctx.machine_ctor_registry
                            .insert(qualified, (event_type_name.clone(), idx));
                        if bare_counts.get(&event.name).copied().unwrap_or(0) == 1 {
                            ctx.machine_ctor_registry
                                .insert(event.name.clone(), (event_type_name.clone(), idx));
                        }
                    }
                }
                Item::TypeDecl(td) if td.kind == TypeDeclKind::Enum => {
                    // Register every variant — unit, tuple, struct — under
                    // the qualified `Type::Variant` key. The variant index is
                    // the ordinal in declaration order across all shapes; it
                    // matches the order `EnumLayout.variants` uses in
                    // MIR/codegen (see lane-plan D2 — variant-index ordering
                    // is HIR-pre-pass authoritative). Tuple variants are
                    // resolved by `Expr::Call` lowering; struct variants by
                    // `Expr::StructInit` lowering; unit variants by
                    // identifier-resolution. All three paths consult this
                    // registry and dispatch on the variant's `HirVariantKind`.
                    let mut variant_idx: usize = 0;
                    for body_item in &td.body {
                        if let TypeBodyItem::Variant(v) = body_item {
                            let qualified = format!("{}::{}", td.name, v.name);
                            ctx.machine_ctor_registry
                                .insert(qualified, (td.name.clone(), variant_idx));
                            if bare_counts.get(&v.name).copied().unwrap_or(0) == 1 {
                                ctx.machine_ctor_registry
                                    .insert(v.name.clone(), (td.name.clone(), variant_idx));
                            }
                            variant_idx += 1;
                        }
                    }
                }
                // No ctor entries to register for these items. If a new Item
                // variant with enumerable ctors is added, the compiler will
                // force a conscious decision here.
                Item::Import(_)
                | Item::Const(_)
                | Item::TypeDecl(_)
                | Item::TypeAlias(_)
                | Item::Trait(_)
                | Item::Impl(_)
                | Item::Wire(_)
                | Item::Function(_)
                | Item::ExternBlock(_)
                | Item::Actor(_)
                | Item::Supervisor(_)
                | Item::Record(_) => {}
            }
        }
        // Mirror the machine_ctor_registry fill over `program.module_graph`
        // non-root modules. The checker's `register_machine_decl` walk in
        // `hew-types/src/check/registration.rs` already populates `type_defs`
        // for imported pub machines and enums; this loop is the HIR-side
        // symmetric producer so `resolve_identifier_variant` hits in
        // `lower_identifier` (machine_ctor_registry lookup) for cross-module
        // ctors. Without this, a root `fn main() { var t: Toggle = Toggle::Off; }`
        // that imports `std::machines::toggle` would emit `UnresolvedSymbol`
        // at HIR even though the checker accepted the reference.
        //
        // Same Pub gating as the bare-count walk above so private machines /
        // enums in imported modules are invisible to consumers.
        if let Some(ref mg) = program.module_graph {
            for mod_id in &mg.topo_order {
                if *mod_id == mg.root {
                    continue;
                }
                let module_short = mod_id.path.last().map_or("", String::as_str);
                if let Some(module) = mg.modules.get(mod_id) {
                    for (item, _) in &module.items {
                        match item {
                            Item::Machine(md) if md.visibility.is_pub() => {
                                let event_type_name = format!("{}Event", md.name);
                                for (idx, state) in md.states.iter().enumerate() {
                                    let qualified = format!("{}::{}", md.name, state.name);
                                    ctx.machine_ctor_registry
                                        .insert(qualified, (md.name.clone(), idx));
                                    let module_qualified =
                                        format!("{module_short}.{}::{}", md.name, state.name);
                                    ctx.machine_ctor_registry
                                        .insert(module_qualified, (md.name.clone(), idx));
                                    if bare_counts.get(&state.name).copied().unwrap_or(0) == 1 {
                                        ctx.machine_ctor_registry
                                            .insert(state.name.clone(), (md.name.clone(), idx));
                                    }
                                }
                                for (idx, event) in md.events.iter().enumerate() {
                                    let qualified = format!("{}::{}", event_type_name, event.name);
                                    ctx.machine_ctor_registry
                                        .insert(qualified, (event_type_name.clone(), idx));
                                    let module_qualified =
                                        format!("{module_short}.{event_type_name}::{}", event.name);
                                    ctx.machine_ctor_registry
                                        .insert(module_qualified, (event_type_name.clone(), idx));
                                    if bare_counts.get(&event.name).copied().unwrap_or(0) == 1 {
                                        ctx.machine_ctor_registry.insert(
                                            event.name.clone(),
                                            (event_type_name.clone(), idx),
                                        );
                                    }
                                }
                            }
                            Item::TypeDecl(td)
                                if td.visibility.is_pub() && td.kind == TypeDeclKind::Enum =>
                            {
                                let mut variant_idx: usize = 0;
                                for body_item in &td.body {
                                    if let TypeBodyItem::Variant(v) = body_item {
                                        let qualified = format!("{}::{}", td.name, v.name);
                                        ctx.machine_ctor_registry
                                            .insert(qualified, (td.name.clone(), variant_idx));
                                        let module_qualified =
                                            format!("{module_short}.{}::{}", td.name, v.name);
                                        ctx.machine_ctor_registry.insert(
                                            module_qualified,
                                            (td.name.clone(), variant_idx),
                                        );
                                        if bare_counts.get(&v.name).copied().unwrap_or(0) == 1 {
                                            ctx.machine_ctor_registry.insert(
                                                v.name.clone(),
                                                (td.name.clone(), variant_idx),
                                            );
                                        }
                                        variant_idx += 1;
                                    }
                                }
                            }
                            // No pub ctor entries to register from imported
                            // modules for these items. Compiler enforces
                            // exhaustivity if a new Item variant is added.
                            Item::Import(_)
                            | Item::Const(_)
                            | Item::TypeDecl(_)
                            | Item::TypeAlias(_)
                            | Item::Trait(_)
                            | Item::Impl(_)
                            | Item::Wire(_)
                            | Item::Function(_)
                            | Item::ExternBlock(_)
                            | Item::Machine(_)
                            | Item::Actor(_)
                            | Item::Supervisor(_)
                            | Item::Record(_) => {}
                        }
                    }
                }
            }
        }
        // Register built-in tagged unions (`Option<T>`, `Result<T, E>`).
        // These have no `Item::TypeDecl` in user source — the checker treats
        // them as primitive — but the HIR lowering pipeline routes their
        // constructors (`Some/None/Ok/Err`) and match arms through the same
        // `machine_ctor_registry` / `enum_variants_by_name` registries as
        // user enums. Without these entries, `Ok(42)` would lower as an
        // unresolved identifier and `match r { Ok(n) => ... }` would emit
        // `match arm variant not registered in machine/enum ctor registry`.
        for spec in builtin_enum_specs() {
            for (variant_idx, variant_name) in spec.variant_names.iter().enumerate() {
                let qualified = format!("{}::{}", spec.type_name, variant_name);
                ctx.machine_ctor_registry
                    .insert(qualified, (spec.type_name.to_string(), variant_idx));
                if bare_counts.get(*variant_name).copied().unwrap_or(0) == 1 {
                    ctx.machine_ctor_registry.insert(
                        (*variant_name).to_string(),
                        (spec.type_name.to_string(), variant_idx),
                    );
                }
            }
        }
    }

    // Seed `enum_variants_by_name`, `enum_type_params`, and `enum_item_ids`
    // for the built-in tagged unions. These mirror what the type-decl second
    // pass below populates for user enums; the variant payload types reference
    // the generic type-parameter names (e.g. `Named { name: "T", args: [] }`)
    // so `substitute_type_params` in `try_register_enum_instantiation`
    // produces correctly substituted per-instantiation layouts that flow into
    // MIR via `module.enum_layouts`.
    for spec in builtin_enum_specs() {
        let variants: Vec<HirVariant> = spec
            .variant_names
            .iter()
            .zip(spec.variant_payloads.iter())
            .map(|(name, payload_params)| {
                let kind = if payload_params.is_empty() {
                    HirVariantKind::Unit
                } else {
                    HirVariantKind::Tuple(
                        payload_params
                            .iter()
                            .map(|p| ResolvedTy::Named {
                                name: (*p).to_string(),
                                args: Vec::new(),
                                builtin: None,
                                is_opaque: false,
                            })
                            .collect(),
                    )
                };
                HirVariant {
                    name: (*name).to_string(),
                    kind,
                }
            })
            .collect();
        ctx.enum_variants_by_name
            .insert(spec.type_name.to_string(), variants);
        ctx.enum_type_params.insert(
            spec.type_name.to_string(),
            spec.type_params.iter().map(|s| (*s).to_string()).collect(),
        );
        ctx.enum_item_ids
            .insert(spec.type_name.to_string(), spec.item_id);
        // Tag-only / monomorphic builtin enums (e.g. `LookupError`) need a
        // `type_classes` registration so MIR `push_unknown_type_diagnostics`
        // does not flag them, and so `ValueClass::of_ty` resolves them as
        // `BitCopy` (no payload → no drop work). Generic builtin enums
        // (`Option`, `Result`) are skipped here: their per-instantiation
        // origin name is added to `machine_layout_names` via the
        // `enum_layouts.iter().map(origin_name)` chain in `hew-mir/src/lower.rs`,
        // and their `ValueClass` is computed on the substituted variants.
        if spec.type_params.is_empty() {
            ctx.type_classes
                .insert(spec.type_name.to_string(), (ResourceMarker::BitCopy, None));
        }
    }

    // Discard pre-pass diagnostics from `lower_type`; the third pass re-emits
    // any real ones when it produces the canonical HirTypeDecl/HirRecordDecl.
    ctx.diagnostics.clear();

    // P0.3 + P0.4: wasm32 blocking channel recv gate. Dispatched HERE (after
    // the diagnostics.clear above) so the gate's BlockingChannelRecvUnsupportedOnWasm
    // diagnostics survive into the final LowerOutput. See check_target_gates
    // for why the coroutine gate is dispatched separately via inline arms.
    if ctx.target_arch == TargetArch::Wasm32 {
        check_wasm_blocking_recv_gate(&mut ctx, program);
    }

    // FC-P1-A1: Task/fork/deadline HIR pre-pass gates. Dispatched HERE (after
    // ctx.diagnostics.clear()) so these fail-closed diagnostics survive into
    // LowerOutput per the FC-P0 diagnostic survival ordering lesson.
    check_task_gates(&mut ctx, program);

    // P1-C: Supervisor child accessor gates. Dispatched HERE (after
    // diagnostics.clear above) so the gate's diagnostics survive into the
    // final LowerOutput. Reads checker side-table `supervisor_child_slots`
    // and emits fail-closed diagnostics for pool-child and nested-supervisor
    // accessors — both currently land in `unreachable`/`NotYetImplemented`
    // arms at MIR lowering (hew-mir/src/lower.rs:4413, :4443) because their
    // backing ABI calls (`hew_supervisor_pool_route`, `hew_supervisor_nested_get`)
    // are scheduled for v0.6. Gate runs unconditionally on every target
    // because the underlying ABI gap is target-independent.
    check_supervisor_child_accessor_gates(&mut ctx, program, type_check_output);

    // FC-P1-A2: Actor `.send(msg)` unit-handler gate. Dispatched AFTER the
    // diagnostics.clear above so ActorSendRequiresUnitHandler survives into
    // LowerOutput. Mirrors the FC-P0 survival-ordering invariant.
    check_actor_send_gates(&mut ctx, program);

    // FC-P1-D: HIR pre-pass binary-operator gates. Dispatched HERE (after
    // diagnostics.clear above) so the gate's diagnostics survive into the
    // final LowerOutput. Unconditional across all targets — these gates
    // close MIR sites that are unsupported regardless of target until MIR
    // gains TargetSpec threading (see audit `:5336`, `:5564`, `:5696`).
    check_binary_operator_gates(&mut ctx, program);

    // FC-P1-A3: Supervisor spawn args gate. Same survival-ordering rationale
    // as the wasm gate above — dispatched AFTER `ctx.diagnostics.clear()` so
    // the SupervisorSpawnArgsUnsupported diagnostics survive into the final
    // LowerOutput. The checker already rejects supervisor declarations with
    // init params; this HIR gate is defense-in-depth that catches any future
    // surface which reaches MIR (`hew-mir/src/lower.rs:8852`) before the
    // checker guard does. Per slepp A222: compile-time fail-closed instead of
    // a `NotYetImplemented` runtime-style diagnostic at MIR-lowering time.
    check_supervisor_spawn_gate(&mut ctx, program);

    // FC-P1-E: Vec<T> index/slice element-type gates. Dispatched HERE (after
    // the diagnostics.clear above) so the gate's VecIndex/Slice element-type
    // diagnostics survive into the final LowerOutput. Target-independent: the
    // runtime ABI lacks `hew_vec_get_T` / `hew_vec_slice_range_T` for the
    // rejected element types on every target.
    check_vec_index_element_type_gates(&mut ctx, program);

    // Second pass: lower type declarations and populate the per-module
    // type-class registry. Stored here so the source-order pass can emit them
    // in program order without a second lowering call. Function bodies depend
    // on type markers (so `ValueClass::of_ty` resolves `Named` types
    // correctly), but type-decl bodies do not depend on function signatures,
    // so this pre-pass can safely run before the combined item pass below.
    let mut type_decl_cache: HashMap<*const hew_parser::ast::TypeDecl, HirTypeDecl> =
        HashMap::new();
    let mut diagnostic_source_modules: HashMap<ItemId, String> = HashMap::new();
    for (item, span) in &program.items {
        if let Item::TypeDecl(decl) = item {
            let hir_decl = ctx.lower_type_decl(decl, span.clone());
            let builtin_registration =
                crate::builtin_type_classes::builtin_type_registration(&hir_decl.name);
            let marker = hir_decl.marker;
            let close_method = if marker == ResourceMarker::Resource {
                builtin_registration
                    .and_then(|registration| registration.close_method.map(str::to_string))
                    .or_else(|| {
                        hir_decl
                            .consuming_methods
                            .iter()
                            .find(|m| m.as_str() == "close")
                            .cloned()
                    })
                    // W3.030 Q-α-B: a `#[resource]` whose `close` lives in a
                    // sibling inherent-impl block must still register the
                    // close-method symbol so the MIR elaborator's
                    // `resource_drop_fn` emits `Some("<T>::close")` rather
                    // than `None`. Without this fallback the type-class
                    // table would record `(Resource, None)` for the broadened
                    // surface and drop-elaboration would silently elide the
                    // close call.
                    .or_else(|| {
                        ctx.impl_close_methods
                            .get(&hir_decl.name)
                            .map(|_| "close".to_string())
                    })
            } else {
                None
            };
            ctx.type_classes
                .insert(hir_decl.name.clone(), (marker, close_method));
            // Snapshot the enum's variant descriptors so call/struct-init
            // lowering can resolve payload ctors to `MachineVariantCtor`
            // without re-walking the parser AST.
            if !hir_decl.variants.is_empty() {
                ctx.enum_variants_by_name
                    .insert(hir_decl.name.clone(), hir_decl.variants.clone());
            }
            // Snapshot type-params and ItemId for the enum-layout discovery
            // pass (slice 2). Needed to substitute variant payload types and
            // to build EnumMonoKey.origin. Stored even for non-generic enums
            // (empty type_params) so discovery can safely skip them.
            ctx.enum_type_params
                .insert(hir_decl.name.clone(), hir_decl.type_params.clone());
            ctx.enum_item_ids.insert(hir_decl.name.clone(), hir_decl.id);
            type_decl_cache.insert(decl as *const _, hir_decl);
        }
    }
    for (item, _) in &program.items {
        if let Item::Machine(machine) = item {
            ctx.register_machine_ctor_variant_metadata(None, machine);
        }
    }
    if let Some(ref mg) = program.module_graph {
        for mod_id in &mg.topo_order {
            if *mod_id == mg.root {
                continue;
            }
            let module_short = mod_id.path.last().map_or("", String::as_str);
            if let Some(module) = mg.modules.get(mod_id) {
                let source_module = mod_id.path.join(".");
                let diag_start = ctx.diagnostics.len();
                for (item, span) in &module.items {
                    match item {
                        Item::TypeDecl(decl)
                            if decl.visibility.is_pub() && decl.kind == TypeDeclKind::Enum =>
                        {
                            let hir_decl = ctx.lower_type_decl(decl, span.clone());
                            if !hir_decl.variants.is_empty() {
                                ctx.enum_variants_by_name
                                    .insert(hir_decl.name.clone(), hir_decl.variants.clone());
                                ctx.enum_variants_by_name.insert(
                                    format!("{module_short}.{}", hir_decl.name),
                                    hir_decl.variants.clone(),
                                );
                            }
                            ctx.enum_type_params
                                .insert(hir_decl.name.clone(), hir_decl.type_params.clone());
                            ctx.enum_type_params.insert(
                                format!("{module_short}.{}", hir_decl.name),
                                hir_decl.type_params.clone(),
                            );
                            ctx.enum_item_ids.insert(hir_decl.name.clone(), hir_decl.id);
                            ctx.enum_item_ids
                                .insert(format!("{module_short}.{}", hir_decl.name), hir_decl.id);
                        }
                        Item::Machine(machine) if machine.visibility.is_pub() => {
                            ctx.register_machine_ctor_variant_metadata(Some(module_short), machine);
                        }
                        // No enum-variant metadata for these items in imported
                        // modules. Compiler enforces exhaustivity if a new
                        // Item variant is added.
                        Item::Import(_)
                        | Item::Const(_)
                        | Item::TypeDecl(_)
                        | Item::TypeAlias(_)
                        | Item::Trait(_)
                        | Item::Impl(_)
                        | Item::Wire(_)
                        | Item::Function(_)
                        | Item::ExternBlock(_)
                        | Item::Machine(_)
                        | Item::Actor(_)
                        | Item::Supervisor(_)
                        | Item::Record(_) => {}
                    }
                }
                ctx.tag_diagnostics_since(diag_start, &source_module);
            }
        }
    }

    // §4b — Imported-module type-decl + machine pre-pass.
    //
    // Mirror the root second pass above for `program.module_graph` non-root
    // modules so cross-module enum and machine variant descriptors are
    // available before any function body in either the root or an imported
    // module is lowered. Without this, `lookup_variant_ctor` (which consults
    // `enum_variants_by_name`) misses for imported enum tuple/struct variants
    // and for imported machine struct-states, and struct-init lowering falls
    // through to the regular-record path which then fails at MIR.
    //
    // For imported enum TypeDecls: lower once via `lower_type_decl`, cache
    // the result so the fourth-pass HirItem-emit walk reuses it (avoiding
    // double lowering and the resulting `ItemId` mismatch between the id
    // seeded into `enum_item_ids` and the id stamped on the emitted
    // `HirItem::TypeDecl`).
    //
    // For imported machines: synthesise `HirVariant` descriptors directly
    // from the AST state + event lists (machines have no `HirTypeDecl`),
    // seeding `enum_variants_by_name` under both the machine name (states)
    // and the synthesised `{Name}Event` companion (events). The checker's
    // `register_machine_decl` produces the same two `TypeDef` entries; this
    // is the HIR-side symmetric producer.
    if let Some(ref mg) = program.module_graph {
        for mod_id in &mg.topo_order {
            if *mod_id == mg.root {
                continue;
            }
            if let Some(module) = mg.modules.get(mod_id) {
                let source_module = mod_id.path.join(".");
                let module_short = mod_id
                    .path
                    .last()
                    .map_or_else(|| source_module.as_str(), String::as_str);
                let diag_start = ctx.diagnostics.len();
                for (item, span) in &module.items {
                    match item {
                        Item::TypeDecl(decl)
                            if decl.visibility.is_pub()
                                || (decl.kind == TypeDeclKind::Struct
                                    && decl.type_params.is_none()) =>
                        {
                            let hir_decl = ctx.lower_type_decl(decl, span.clone());
                            ctx.type_classes
                                .entry(hir_decl.name.clone())
                                .or_insert((hir_decl.marker, None));
                            ctx.type_classes
                                .entry(format!("{module_short}.{}", hir_decl.name))
                                .or_insert((hir_decl.marker, None));
                            if !hir_decl.variants.is_empty() {
                                ctx.enum_variants_by_name
                                    .insert(hir_decl.name.clone(), hir_decl.variants.clone());
                                ctx.enum_variants_by_name.insert(
                                    format!("{module_short}.{}", hir_decl.name),
                                    hir_decl.variants.clone(),
                                );
                            }
                            ctx.enum_type_params
                                .insert(hir_decl.name.clone(), hir_decl.type_params.clone());
                            ctx.enum_type_params.insert(
                                format!("{module_short}.{}", hir_decl.name),
                                hir_decl.type_params.clone(),
                            );
                            ctx.enum_item_ids.insert(hir_decl.name.clone(), hir_decl.id);
                            ctx.enum_item_ids
                                .insert(format!("{module_short}.{}", hir_decl.name), hir_decl.id);
                            type_decl_cache.insert(decl as *const _, hir_decl);
                        }
                        Item::Machine(md) if md.visibility.is_pub() => {
                            // Synthesise state variants. Unit when stateless,
                            // Struct otherwise — mirrors how `lookup_variant_ctor`
                            // dispatches on `HirVariantKind` at struct-init /
                            // identifier resolution sites.
                            let state_variants: Vec<HirVariant> = md
                                .states
                                .iter()
                                .map(|state| {
                                    let kind = if state.fields.is_empty() {
                                        HirVariantKind::Unit
                                    } else {
                                        HirVariantKind::Struct(
                                            state
                                                .fields
                                                .iter()
                                                .map(|(name, ty)| {
                                                    (name.clone(), ctx.lower_type(ty))
                                                })
                                                .collect(),
                                        )
                                    };
                                    HirVariant {
                                        name: state.name.clone(),
                                        kind,
                                    }
                                })
                                .collect();
                            ctx.enum_variants_by_name
                                .insert(md.name.clone(), state_variants);

                            // Synthesise event companion variants under the
                            // `{Name}Event` key, matching the checker's
                            // generated event-type TypeDef.
                            let event_type_name = format!("{}Event", md.name);
                            let event_variants: Vec<HirVariant> = md
                                .events
                                .iter()
                                .map(|event| {
                                    let kind = if event.fields.is_empty() {
                                        HirVariantKind::Unit
                                    } else {
                                        HirVariantKind::Struct(
                                            event
                                                .fields
                                                .iter()
                                                .map(|(name, ty)| {
                                                    (name.clone(), ctx.lower_type(ty))
                                                })
                                                .collect(),
                                        )
                                    };
                                    HirVariant {
                                        name: event.name.clone(),
                                        kind,
                                    }
                                })
                                .collect();
                            ctx.enum_variants_by_name
                                .insert(event_type_name, event_variants);
                        }
                        // No enum-variant/machine descriptors to cache for
                        // these items in imported modules (§4b pre-pass). If
                        // a new Item variant is added, the compiler will force
                        // a conscious decision here.
                        Item::Import(_)
                        | Item::Const(_)
                        | Item::TypeDecl(_)
                        | Item::TypeAlias(_)
                        | Item::Trait(_)
                        | Item::Impl(_)
                        | Item::Wire(_)
                        | Item::Function(_)
                        | Item::ExternBlock(_)
                        | Item::Machine(_)
                        | Item::Actor(_)
                        | Item::Supervisor(_)
                        | Item::Record(_) => {}
                    }
                }
                ctx.tag_diagnostics_since(diag_start, &source_module);
            }
        }
    }

    // Structural BitCopy inference: a user-defined struct whose every field
    // is BitCopy is itself BitCopy. Run as a fixed-point so that records
    // composed of other inferred-BitCopy records are also promoted. Generic
    // type-params remain unknown (we don't infer through them), and any
    // type that already carries an explicit ownership marker keeps it.
    // Enums are left alone here — their layout decisions go through the
    // EnumLayout pass, not the value-class table.
    {
        let mut changed = true;
        while changed {
            changed = false;
            let candidates: Vec<(String, Vec<ResolvedTy>)> = type_decl_cache
                .values()
                .filter(|d| {
                    d.marker == ResourceMarker::None
                        && d.variants.is_empty()
                        && d.type_params.is_empty()
                        && !d.fields.is_empty()
                })
                .filter(|d| {
                    ctx.type_classes
                        .get(&d.name)
                        .is_some_and(|(m, _)| *m == ResourceMarker::None)
                })
                .map(|d| {
                    (
                        d.name.clone(),
                        d.fields.iter().map(|f| f.ty.clone()).collect(),
                    )
                })
                .collect();
            for (name, field_tys) in candidates {
                let all_bitcopy = field_tys.iter().all(|ty| {
                    matches!(
                        crate::value_class::ValueClass::of_ty(ty, &ctx.type_classes),
                        crate::value_class::ValueClass::BitCopy
                    )
                });
                if all_bitcopy {
                    if let Some(entry) = ctx.type_classes.get_mut(&name) {
                        entry.0 = ResourceMarker::BitCopy;
                        changed = true;
                    }
                }
            }
        }
    }

    // Register std builtins.hew receiver impl methods only after all user item
    // IDs have been preallocated. This makes the builtin impls visible to
    // source-body lowering without perturbing stable user `ItemId`s.
    if let Some(program) = &builtin_receiver_impl_program {
        for (item, _) in &program.items {
            if let Item::Impl(impl_decl) = item {
                if !is_builtin_receiver_impl(item) {
                    continue;
                }
                if let TypeExpr::Named { name, .. } = &impl_decl.target_type.0 {
                    let method_symbols: Vec<String> = impl_decl
                        .methods
                        .iter()
                        .map(|method| crate::node::HirImplBlock::method_symbol(name, &method.name))
                        .collect();
                    if method_symbols
                        .iter()
                        .any(|symbol| ctx.fn_registry.contains_key(symbol))
                    {
                        continue;
                    }
                    let impl_type_params = impl_type_param_names(impl_decl);
                    for method in &impl_decl.methods {
                        ctx.register_impl_method_fn_entry(name, method, &impl_type_params);
                    }
                    builtin_receiver_impl_method_symbols.extend(method_symbols);
                }
            }
        }
    }

    // Third pass: emit all items in source order now that both fn signatures
    // and type markers are fully resolved.
    let mut items: Vec<HirItem> = Vec::new();
    for (item, span) in &program.items {
        match item {
            Item::TypeDecl(decl) => {
                // Retrieve the already-lowered decl so diagnostics are not
                // emitted a second time.
                if let Some(hir_decl) = type_decl_cache.remove(&(decl as *const _)) {
                    items.push(HirItem::TypeDecl(hir_decl));
                }
            }
            Item::Function(func) => {
                // If this function carries `#[intrinsic("key")]`, the checker
                // recorded it in `intrinsic_declarations`. Validate the key
                // against the stdlib catalog and skip body lowering — the
                // catalog entry already supplies the semantics. Fail-closed:
                // an unknown key produces `UnknownIntrinsic` instead of a
                // silently-incorrect lowering.
                if let Some(intrinsic_key) = ctx.intrinsic_declarations.get(&func.name).cloned() {
                    let known = crate::stdlib_catalog::entries()
                        .iter()
                        .any(|e| e.name == intrinsic_key);
                    if !known {
                        ctx.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::UnknownIntrinsic {
                                fn_name: func.name.clone(),
                                intrinsic_key,
                            },
                            span.clone(),
                            "intrinsic key not found in stdlib catalog; \
                             check the #[intrinsic(\"..\")] argument matches a catalog entry name",
                        ));
                    }
                    // Either way, do not lower a body — the declaration is a
                    // typed substrate stub that must match an existing catalog entry.
                } else {
                    items.push(HirItem::Function(ctx.lower_fn(func, span.clone())));
                }
            }
            Item::Impl(impl_decl) => {
                ctx.lower_impl_block(impl_decl, span.clone(), &mut items, false, None);
            }
            Item::Machine(machine) => {
                if let Some(hir_machine) = ctx.lower_machine(machine, span.clone()) {
                    items.push(HirItem::Machine(hir_machine));
                }
            }
            Item::Actor(actor) => {
                // P0.1: Fail-closed gate: actors require the actor runtime ABI
                if !matches!(ctx.target_arch, TargetArch::X86_64 | TargetArch::Aarch64) {
                    ctx.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::TargetCoroutineUnsupported {
                            target_arch: format!("{:?}", ctx.target_arch),
                            construct: "actor decl".to_string(),
                        },
                        span.clone(),
                        format!(
                            "actor '{}' requires the actor runtime ABI (x86_64/aarch64 only)",
                            actor.name
                        ),
                    ));
                }
                items.push(HirItem::Actor(ctx.lower_actor(actor, span.clone())));
            }
            Item::Record(decl) => {
                items.push(HirItem::Record(ctx.lower_record_decl(decl, span.clone())));
            }
            Item::Supervisor(decl) => {
                // P0.2: Fail-closed gate: supervisors require the actor runtime ABI
                if !matches!(ctx.target_arch, TargetArch::X86_64 | TargetArch::Aarch64) {
                    ctx.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::TargetCoroutineUnsupported {
                            target_arch: format!("{:?}", ctx.target_arch),
                            construct: "supervisor decl".to_string(),
                        },
                        span.clone(),
                        format!(
                            "supervisor '{}' requires the actor runtime ABI (x86_64/aarch64 only)",
                            decl.name
                        ),
                    ));
                }
                items.push(HirItem::Supervisor(
                    ctx.lower_supervisor(decl, span.clone()),
                ));
            }
            Item::Import(_) | Item::Trait(_) => {
                // Imports are frontend-resolved: module-path imports
                // (`import greeting;`) are lowered from `program.module_graph`
                // below under their qualified mangled name (e.g. `greeting$hello`).
                // File-path imports (`import "util.hew";`) are still flattened
                // into `program.items` by `flatten_import_items` and lowered in
                // the loop above.  The residual `Item::Import` stub is kept in
                // `program.items` for diagnostic source-map attribution (removing
                // it would require auditing every span consumer — out of scope).
                //
                // User-defined `trait` declarations likewise have no runtime
                // artefact — the type checker harvests their `trait_defs`
                // entry (and any `#[lang_item("...")]` registry mapping)
                // during its registration sweep, and impl-side method bodies
                // become flattened `HirItem::Function` entries via
                // `lower_impl_block`. We accept the trait declaration silently
                // here rather than fail-closing.
            }
            Item::Const(const_decl) => {
                items.push(HirItem::Const(ctx.lower_const(const_decl, span.clone())));
            }
            Item::TypeAlias(_) | Item::Wire(_) => {
                ctx.unsupported(span.clone(), "top-level-item", "slice-2");
            }
            Item::ExternBlock(block) => {
                for func in &block.functions {
                    let param_tys = func
                        .params
                        .iter()
                        .map(|p| ctx.lower_type(&p.ty))
                        .collect::<Vec<_>>();
                    let return_ty = func
                        .return_type
                        .as_ref()
                        .map_or(ResolvedTy::Unit, |ret| ctx.lower_type(ret));
                    items.push(HirItem::ExternFn(crate::node::HirExternFn {
                        id: ctx.ids.item(),
                        node: ctx.ids.node(),
                        name: func.name.clone(),
                        abi: block.abi.clone(),
                        param_tys,
                        return_ty,
                        span: func.span.clone(),
                    }));
                }
            }
        }
    }

    // Fourth pass: lower pub fn bodies from non-root modules under their
    // qualified, native-symbol-safe names (e.g. `greeting$hello`).
    //
    // Module-path imports (`import greeting;`) are NOT flattened into
    // `program.items` (see `flatten_import_items` restriction in
    // `hew-compile`), so the bodies would otherwise be absent from the
    // emitted `HirModule`.  Walking `module_graph` here ensures each
    // imported user module contributes exactly one `HirFn` per pub fn,
    // keyed by the same mangled name registered in the pre-pass above.
    //
    // Pub TypeDecls are emitted here for the same reason: imported stdlib
    // record types must appear as `HirItem::TypeDecl` so that `hew-mir`'s layout
    // pass (which walks `module.items`) can populate `record_field_orders` and
    // emit a `RecordLayout`. Without this, field accesses like `info.code` in
    // `#[on(crash)]` bodies fail at MIR time because the payload record layout
    // is absent from `record_field_orders`.
    if let Some(ref mg) = program.module_graph {
        for mod_id in &mg.topo_order {
            if *mod_id == mg.root {
                continue;
            }
            if let Some(module) = mg.modules.get(mod_id) {
                let source_module = mod_id.path.join(".");
                let diag_start = ctx.diagnostics.len();
                let item_start = items.len();
                let module_short = mod_id.path.last().map_or("", String::as_str);
                // Per-module helper sets used by the imported-body scan in
                // both the free-fn (Item::Function) and impl-method
                // (Item::Impl) arms. Computed once per module so the two
                // arms agree on which same-module callees count as
                // private vs. pub and so iteration cost is linear in the
                // module's item count rather than quadratic across arms.
                let same_module_private_fns: HashSet<String> = module
                    .items
                    .iter()
                    .filter_map(|(it, _)| {
                        if let Item::Function(f) = it {
                            if !f.visibility.is_pub() {
                                return Some(f.name.clone());
                            }
                        }
                        None
                    })
                    .collect();
                let same_module_private_fn_decls: HashMap<String, &FnDecl> = module
                    .items
                    .iter()
                    .filter_map(|(it, _)| {
                        if let Item::Function(f) = it {
                            if !f.visibility.is_pub() {
                                return Some((f.name.clone(), f));
                            }
                        }
                        None
                    })
                    .collect();
                let same_module_pub_fns: HashSet<String> = module
                    .items
                    .iter()
                    .filter_map(|(it, _)| {
                        if let Item::Function(f) = it {
                            if f.visibility.is_pub() {
                                return Some(f.name.clone());
                            }
                        }
                        None
                    })
                    .collect();
                let imported_private_closure =
                    collect_imported_private_fn_closure(module, &same_module_private_fns);
                for helper_name in &imported_private_closure {
                    if let Some(helper) = same_module_private_fn_decls.get(helper_name) {
                        let qualified =
                            crate::mangle_dotted_name(&format!("{module_short}.{}", helper.name));
                        ctx.register_fn_entry(&qualified, helper);
                    }
                }
                let same_module_fn_rewrites: HashMap<String, String> = same_module_pub_fns
                    .iter()
                    .chain(imported_private_closure.iter())
                    .map(|name| {
                        (
                            name.clone(),
                            crate::mangle_dotted_name(&format!("{module_short}.{name}")),
                        )
                    })
                    .collect();
                // Populate bare-name const scope for this module's own consts.
                // Functions inside the module reference module-level consts by
                // bare name (e.g. `STATUS_OK`), but the global `const_registry`
                // holds them under qualified keys `"module_short.STATUS_OK"`.
                // Both pub AND private consts are registered in the pre-pass
                // under their qualified keys; this map shadows them by bare
                // name so identifier resolution inside imported bodies finds
                // them without requiring the caller to qualify the access.
                let module_consts_scope: HashMap<String, ConstEntry> = module
                    .items
                    .iter()
                    .filter_map(|(it, _)| {
                        if let Item::Const(cd) = it {
                            let qualified = format!("{module_short}.{}", cd.name);
                            ctx.const_registry
                                .get(&qualified)
                                .map(|entry| (cd.name.clone(), entry.clone()))
                        } else {
                            None
                        }
                    })
                    .collect();
                let prev_module_consts = ctx.imported_module_consts.replace(module_consts_scope);

                for (item, span) in &module.items {
                    match item {
                        Item::Function(func) if func.visibility.is_pub() => {
                            let qualified =
                                crate::mangle_dotted_name(&format!("{module_short}.{}", func.name));
                            if let Some(lowered) = ctx.lower_imported_fn_floor_aware(
                                func,
                                &qualified,
                                &source_module,
                                span.clone(),
                                &same_module_fn_rewrites,
                            ) {
                                items.push(HirItem::Function(lowered));
                            }
                        }
                        Item::Function(func)
                            if imported_private_closure.contains(func.name.as_str()) =>
                        {
                            let qualified =
                                crate::mangle_dotted_name(&format!("{module_short}.{}", func.name));
                            if let Some(lowered) = ctx.lower_imported_fn_floor_aware(
                                func,
                                &qualified,
                                &source_module,
                                span.clone(),
                                &same_module_fn_rewrites,
                            ) {
                                items.push(HirItem::Function(lowered));
                            }
                        }
                        Item::TypeDecl(decl)
                            if decl.visibility.is_pub()
                                || (decl.kind == TypeDeclKind::Struct
                                    && decl.type_params.is_none()) =>
                        {
                            // Consume the cached `HirTypeDecl` produced by the
                            // §4b imported-module pre-pass so the emitted item
                            // shares the same `ItemId` already seeded into
                            // `enum_item_ids`. Re-lowering here would mint a
                            // fresh id and silently drift the registry's view
                            // of the enum from the emitted decl. Non-enum
                            // TypeDecls (records) were not cached above — fall
                            // back to lowering them inline.
                            if let Some(hir_decl) = type_decl_cache.remove(&(decl as *const _)) {
                                items.push(HirItem::TypeDecl(hir_decl));
                            } else {
                                items.push(HirItem::TypeDecl(
                                    ctx.lower_type_decl(decl, span.clone()),
                                ));
                            }
                        }
                        // Emit `HirItem::Machine` entries for imported pub
                        // machines so MIR's `machine_layout_names` set (built
                        // from `module.items`) includes their names. Without
                        // this, the MIR `Builder::is_known_actor_runtime_ty`
                        // classifies `Named { name: "Toggle" }` as
                        // `ValueClass::Unknown` → `Strategy::UnknownBlocked` →
                        // `DecisionMapTotal` + `UnknownType` diagnostics, even
                        // though HIR's `machine_ctor_registry` already resolved
                        // the qualified ctor reference. The visibility gate
                        // mirrors the TypeDecl arm above.
                        Item::Machine(machine) if machine.visibility.is_pub() => {
                            if let Some(hir_machine) = ctx.lower_machine(machine, span.clone()) {
                                items.push(HirItem::Machine(hir_machine));
                            }
                        }
                        // Emit HirItem::ExternFn entries for extern declarations
                        // in imported modules so MIR/codegen sees them in the
                        // lowered item list. Mirrors the root-item arm at the
                        // third pass.
                        Item::ExternBlock(block) => {
                            for func in &block.functions {
                                let param_tys = func
                                    .params
                                    .iter()
                                    .map(|p| ctx.lower_type(&p.ty))
                                    .collect::<Vec<_>>();
                                let return_ty = func
                                    .return_type
                                    .as_ref()
                                    .map_or(ResolvedTy::Unit, |ret| ctx.lower_type(ret));
                                items.push(HirItem::ExternFn(crate::node::HirExternFn {
                                    id: ctx.ids.item(),
                                    node: ctx.ids.node(),
                                    name: func.name.clone(),
                                    abi: block.abi.clone(),
                                    param_tys,
                                    return_ty,
                                    span: func.span.clone(),
                                }));
                            }
                        }
                        // Emit `HirItem::Function` entries for the methods of an
                        // imported impl block so that MIR/codegen can process
                        // cross-module method calls on named types.
                        //
                        // No per-method `pub` gate: impl methods in Hew have no
                        // independent visibility (impl bodies never carry
                        // `pub fn`; access is governed by the trait/type), so a
                        // `pub` filter excluded ALL imported impl methods. That
                        // left non-trivial builder methods (e.g. JSON `with_*` /
                        // `push_*`, whose bodies are a void C call followed by
                        // `return self`, so they are NOT captured by the runtime
                        // handle-method pass-through path) without a MIR body,
                        // surfacing as `CallableUnsupportedInMir` /
                        // `IndirectCallUnsupported` at the import boundary. The
                        // root impl-block path emits every method
                        // (`pub_only = false`); the imported path now matches.
                        //
                        // A method whose body calls a private (non-pub) free
                        // function in the same module that is NOT in the imported
                        // private-fn closure cannot be lowered (the helper is not
                        // in the emitted item list and has no qualified rewrite).
                        // Such methods are skipped — matching the prior behaviour
                        // where every imported impl method was dropped — so the
                        // module still imports cleanly. If an importer actually
                        // CALLS a skipped method it fails closed downstream with
                        // `CallableUnsupportedInMir`, exactly as before this
                        // change. (Lowering those bodies requires registering the
                        // private-helper closure reachable from impl methods, a
                        // follow-up to the free-fn closure already wired here.)
                        Item::Impl(impl_decl) => {
                            if let TypeExpr::Named {
                                name: self_type_name,
                                ..
                            } = &impl_decl.target_type.0
                            {
                                // Conservatively lower only the imported impl
                                // methods that are provably safe cross-module;
                                // skip the rest so they stay dropped exactly as
                                // before this change (the module still imports
                                // cleanly, and an actual call to a skipped method
                                // fails closed downstream just as it did on the
                                // prior, drop-everything path).
                                //
                                // A method is skipped when EITHER:
                                //  - its body calls a bare name that resolves in
                                //    neither the same-module rewrite map nor
                                //    `fn_registry` (which by now holds every
                                //    seeded stdlib/runtime symbol and every
                                //    same-module extern fn) — catches
                                //    codegen-intercepted builtins that are not
                                //    extern-declared, e.g. `std::channel`'s
                                //    `recv` → `hew_channel_recv`; OR
                                //  - its signature names a user type that would
                                //    not resolve at the MIR boundary — a
                                //    cross-module dotted type (`fs.IoError`) or a
                                //    user trait/type used as a generic argument
                                //    (`LocalPid<WebSocketHandler>`). Only
                                //    primitives/builtins and the impl's own self
                                //    type are admitted.
                                //
                                // This is intentionally tight: it captures the
                                // fluent-builder shape (e.g. JSON `with_*` /
                                // `push_*`, params `string`/`i64`/`f64`/`bool`,
                                // returning the opaque self handle) without
                                // eagerly lowering methods that would unmask
                                // pre-existing per-module cross-module-resolution
                                // gaps. Lifting the signature restriction needs
                                // imported user-type/trait registration at the
                                // MIR boundary — a separate lane.
                                let mut skip_methods: HashSet<String> = HashSet::new();
                                for method in &impl_decl.methods {
                                    let body_unresolvable = collect_all_bare_call_names(
                                        &method.body,
                                    )
                                    .into_iter()
                                    .any(|callee| {
                                        // Built-in tagged-union variant
                                        // constructors (`Ok`, `Err`,
                                        // `Some`, `None`, …) parse as bare
                                        // `Expr::Call { Identifier }` but
                                        // resolve through
                                        // `machine_ctor_registry`, not
                                        // `fn_registry`. They are always
                                        // resolvable cross-module, so a
                                        // body that constructs an
                                        // `Ok(n)` / `Err(e)` result is not
                                        // "unresolvable" on their account.
                                        !BUILTIN_ENUM_VARIANT_BARE_NAMES.contains(&callee.as_str())
                                            && !same_module_fn_rewrites.contains_key(&callee)
                                            && !ctx.fn_registry.contains_key(&callee)
                                    });
                                    // A user type in a signature is safe iff its
                                    // backing declaration was registered at the
                                    // MIR boundary by the imported-module
                                    // pre-pass (above): pub enums land in
                                    // `enum_variants_by_name` / `type_classes`,
                                    // pub records in `record_registry`. Dotted
                                    // cross-module names and bare same-module
                                    // names both consult those registries.
                                    let is_known_registered_type = |name: &str| {
                                        ctx.enum_variants_by_name.contains_key(name)
                                            || ctx.type_classes.contains_key(name)
                                            || ctx.record_registry.contains_key(name)
                                    };
                                    let sig_unresolvable =
                                        method_signature_type_exprs(method).any(|ty| {
                                            !imported_impl_signature_type_is_safe(
                                                ty,
                                                self_type_name,
                                                &is_known_registered_type,
                                            )
                                        });
                                    if body_unresolvable || sig_unresolvable {
                                        skip_methods.insert(method.name.clone());
                                    }
                                }
                                ctx.lower_impl_block(
                                    impl_decl,
                                    span.clone(),
                                    &mut items,
                                    false,
                                    Some(&ImportedImplLowering {
                                        rewrites: &same_module_fn_rewrites,
                                        skip_methods: &skip_methods,
                                    }),
                                );
                            }
                        }
                        // Emit HirItem::Const for ALL consts from imported modules
                        // (both pub and private).  Pub consts are externally
                        // accessible via `module.CONST`; private consts are
                        // visible only inside the module's own function bodies.
                        // Both shapes produce `BindingRef::Const(id)` references
                        // and both require a `HirItem::Const` descriptor so that
                        // MIR's `build_const_descriptors` emits the global and
                        // `Instr::ConstGlobalLoad` resolves correctly at codegen.
                        //
                        // The pre-pass registered every const under its qualified key
                        // `"module_short.CONST_NAME"`.  `lower_const` looks up
                        // `const_registry[decl.name]` for the pre-allocated ItemId,
                        // so we temporarily alias the qualified entry under the bare
                        // name, lower, then remove the alias to avoid polluting the
                        // global registry.
                        Item::Const(const_decl) => {
                            let qualified = format!("{module_short}.{}", const_decl.name);
                            if let Some(entry) = ctx.const_registry.get(&qualified).cloned() {
                                ctx.const_registry.insert(const_decl.name.clone(), entry);
                                let lowered = ctx.lower_const(const_decl, span.clone());
                                ctx.const_registry.remove(&const_decl.name);
                                items.push(HirItem::Const(lowered));
                            }
                        }
                        // Item::Record, Item::Actor, Item::Supervisor from
                        // imported modules are intentionally not emitted in
                        // this slice; their cross-module lowering semantics
                        // are tracked as separate follow-ups.
                        //
                        // Non-pub Function/TypeDecl/Machine fall here (not
                        // visible to importers). If a new Item variant is
                        // added, the compiler will force a conscious decision.
                        Item::Import(_)
                        | Item::Function(_)
                        | Item::TypeDecl(_)
                        | Item::TypeAlias(_)
                        | Item::Trait(_)
                        | Item::Wire(_)
                        | Item::Machine(_)
                        | Item::Record(_)
                        | Item::Actor(_)
                        | Item::Supervisor(_) => {}
                    }
                }
                // Restore the const scope after lowering this module's bodies.
                ctx.imported_module_consts = prev_module_consts;
                ctx.tag_diagnostics_since(diag_start, &source_module);
                record_source_modules_for_items(
                    &items[item_start..],
                    &source_module,
                    &mut diagnostic_source_modules,
                );
            }
        }
    }

    // Inject the std builtins.hew receiver impls through the same lowering path
    // as user impls so direct method rewrites and the static-dispatch index see
    // them. Keep them after source items to avoid changing user-item ordering
    // guarantees.
    if let (Some(program), Some(output)) = (
        &builtin_receiver_impl_program,
        &builtin_receiver_impl_output,
    ) {
        let item_start = items.len();
        ctx.with_typecheck_facts(output, |ctx| {
            let saved_some = ctx
                .machine_ctor_registry
                .insert("Some".to_string(), ("Option".to_string(), 0));
            let saved_none = ctx
                .machine_ctor_registry
                .insert("None".to_string(), ("Option".to_string(), 1));
            for (item, span) in &program.items {
                if let Item::Impl(impl_decl) = item {
                    if is_builtin_receiver_impl(item) {
                        let TypeExpr::Named { name, .. } = &impl_decl.target_type.0 else {
                            continue;
                        };
                        let registered = impl_decl.methods.iter().all(|method| {
                            builtin_receiver_impl_method_symbols.contains(
                                &crate::node::HirImplBlock::method_symbol(name, &method.name),
                            )
                        });
                        if !registered {
                            continue;
                        }
                        ctx.lower_impl_block(impl_decl, span.clone(), &mut items, false, None);
                    }
                }
            }
            if let Some(previous) = saved_some {
                ctx.machine_ctor_registry
                    .insert("Some".to_string(), previous);
            } else {
                ctx.machine_ctor_registry.remove("Some");
            }
            if let Some(previous) = saved_none {
                ctx.machine_ctor_registry
                    .insert("None".to_string(), previous);
            } else {
                ctx.machine_ctor_registry.remove("None");
            }
        });
        record_source_modules_for_items(
            &items[item_start..],
            "std.builtins",
            &mut diagnostic_source_modules,
        );
    }

    // Monomorphic builtin enums (e.g. `LookupError`) intentionally do NOT
    // appear in `items` here. Their declarations live in
    // `std/builtins.hew` and their tagged-union layout is registered
    // out-of-band into MIR via
    // `hew-mir::register_builtin_monomorphic_enum_layouts`, which reads
    // the catalog in `hew_types::builtin_enums::monomorphic_builtin_enums`.
    // Aside from the explicit Vec iterator impl harness entries above, this
    // keeps `HirProgram::items` a faithful mirror of user source — an earlier
    // prototype injected a synthetic `HirItem::TypeDecl` here for every
    // monomorphic builtin enum and leaked the type into the downstream
    // sandbox-VM bytecode descriptor table of every program, including ones
    // that never referenced `Node::lookup`. Generic builtin enums (`Option`,
    // `Result`) continue to flow through `EnumLayoutRegistry` per-instantiation
    // (see below).

    let mut monomorphisations = ctx.mono_registry.into_vec();
    let call_site_type_args = ctx.call_site_type_args;
    let mut record_layouts = ctx.record_layout_registry.into_vec();
    let mut enum_layouts = ctx.enum_layout_registry.into_vec();
    let supervisor_child_slots = ctx.supervisor_child_slots;

    // Closure under substitution: walk every monomorphisation's origin
    // body, find inner generic-fn call sites, substitute their recorded
    // type args via the monomorphisation's substitution map, and add
    // any newly discovered concrete instantiations to the registry.
    // Repeat to a fixed point (bounded by the configured cap).
    closure_under_substitution(
        &items,
        &call_site_type_args,
        &mut monomorphisations,
        mono_cap,
        &mut ctx.diagnostics,
    );

    // Post-function-mono record/enum layout discovery. MUST run AFTER
    // `closure_under_substitution` has closed the function-mono registry —
    // a generic record/enum constructed only inside a generic fn body (e.g.
    // `fn make<T>() -> Box<T> { Box { value: x } }`) is observable as a
    // concrete `Box<i64>` layout only after `make` is substituted as
    // `make$$i64`. Mirrors the `run_machine_mono_pass` ordering invariant.
    // The pass is purely additive: the origin-site path already registered
    // every concrete-site instantiation, and the dedup set is seeded from
    // those so nothing is double-counted. New entries are merged BEFORE
    // `finalize_user_record_value_classes` so each new mangled layout gets a
    // value-class assigned.
    let (extra_record_layouts, extra_enum_layouts, layout_mono_diagnostics) =
        crate::layout_mono::run_layout_mono_pass(
            &items,
            &monomorphisations,
            &record_layouts,
            &enum_layouts,
            mono_cap,
        );
    record_layouts.extend(extra_record_layouts);
    enum_layouts.extend(extra_enum_layouts);
    ctx.diagnostics.extend(layout_mono_diagnostics);

    finalize_user_record_value_classes(
        &ctx.record_registry,
        &record_layouts,
        &mut ctx.type_classes,
    );

    // FC-P1-B: HIR pre-pass for call-shape gates. Lifts MIR's call-shape
    // fail-closed diagnostics (`hew-mir/src/lower.rs:4194` / `:4236`) to the
    // HIR boundary so unresolved-Item callees and indirect-callable
    // unresolved callees surface during HIR lowering instead of after the
    // MIR producer has begun emitting instructions for the surrounding
    // function. Runs AFTER `ctx.diagnostics.clear()` at line ~921 and after
    // `closure_under_substitution` so the callable set includes the final
    // monomorphisation list. See `check_call_shape_gates` for the predicate.
    check_call_shape_gates(&items, &monomorphisations, &mut ctx.diagnostics);

    // W3.033c Stage 2 (R244=B): dedicated post-function-mono machine
    // instantiation discovery pass. MUST run AFTER
    // `closure_under_substitution` has finished closing the function-mono
    // registry — generic-function-mediated machine instantiations (e.g.
    // `fn make<T>() -> Lifecycle<T>` instantiated as `make::<File>()`) are
    // only observable once function-mono has substituted `T` into the
    // return-type slot — and BEFORE the `HirModule` is handed to MIR for
    // `machine_layouts` build (Stage 3, out of scope for this change).
    //
    // Pass-ordering invariant — see `machine_mono.rs` module docs and
    // the `machine_mono_pass_records_*` integration tests. Any future
    // refactor that moves this call before `closure_under_substitution`
    // (or parallelises the two passes) silently drops generic-mediated
    // machine instantiations.
    let (machine_instantiations, machine_mono_diagnostics) =
        crate::machine_mono::run_machine_mono_pass(&items, &monomorphisations, mono_cap);
    ctx.diagnostics.extend(machine_mono_diagnostics);

    LowerOutput {
        module: HirModule {
            items,
            diagnostic_source_modules,
            type_classes: ctx.type_classes,
            monomorphisations,
            call_site_type_args,
            record_layouts,
            enum_layouts,
            machine_instantiations,
            supervisor_child_slots,
            regex_literals: ctx.regex_literals,
        },
        diagnostics: ctx.diagnostics,
    }
}

fn finalize_user_record_value_classes(
    record_registry: &HashMap<String, RecordEntry>,
    record_layouts: &[RecordLayout],
    type_classes: &mut crate::value_class::TypeClassTable,
) {
    for name in record_registry.keys() {
        type_classes
            .entry(name.clone())
            .or_insert((ResourceMarker::None, None));
    }

    let mut changed = true;
    while changed {
        changed = false;

        for (name, entry) in record_registry {
            let Some((marker, _)) = type_classes.get(name) else {
                continue;
            };
            if *marker != ResourceMarker::None
                || !entry.type_params.is_empty()
                || entry.fields.is_empty()
            {
                continue;
            }
            if entry.fields.iter().all(|(_, ty)| {
                crate::value_class::ValueClass::of_ty(ty, type_classes)
                    == crate::value_class::ValueClass::BitCopy
            }) {
                if let Some((marker, _)) = type_classes.get_mut(name) {
                    *marker = ResourceMarker::BitCopy;
                    changed = true;
                }
            }
        }

        for layout in record_layouts {
            if layout.fields.is_empty() {
                continue;
            }
            if type_classes
                .get(&layout.mangled_name)
                .is_some_and(|(marker, _)| *marker != ResourceMarker::None)
            {
                continue;
            }
            if layout.fields.iter().all(|(_, ty)| {
                crate::value_class::ValueClass::of_ty(ty, type_classes)
                    == crate::value_class::ValueClass::BitCopy
            }) {
                type_classes.insert(layout.mangled_name.clone(), (ResourceMarker::BitCopy, None));
                changed = true;
            } else {
                type_classes
                    .entry(layout.mangled_name.clone())
                    .or_insert((ResourceMarker::None, None));
            }
        }
    }
}

/// Walk each monomorphisation's origin fn body, substitute the
/// per-monomorphisation type-arg map into every inner Call site's
/// recorded type arguments, and add any newly-discovered concrete
/// `(origin_fn, Vec<ResolvedTy>)` pairs to the registry. Iterates to a
/// fixed point.
///
/// Emits `MonomorphisationCapExceeded` (at most once) when the cap is
/// hit. Skips inner calls whose substituted args still contain any
/// abstract type-parameter symbol (no monomorphisation is possible
/// without a concrete instantiation).
/// A `CallTraitMethodStatic` site discovered inside a function body.
/// Carries enough info to derive the impl-method monomorphisation once the
/// surrounding function's type params have been substituted.
struct TraitMethodStaticSite {
    /// Type-parameter name of the receiver (e.g. "T" in `fn display<T: Show>`).
    receiver_type_param: String,
    /// Trait that directly declares the method (e.g. "Show") — used as the
    /// structured registry key so we don't reverse-parse the impl symbol.
    declaring_trait: String,
    /// Method name on the declaring trait (e.g. "show").
    method_name: String,
}

#[allow(
    clippy::too_many_lines,
    reason = "two-phase worklist: direct calls + trait method sites"
)]
fn closure_under_substitution(
    items: &[HirItem],
    call_site_type_args: &HashMap<SiteId, Vec<ResolvedTy>>,
    monomorphisations: &mut Vec<crate::monomorph::MonomorphizedFn>,
    cap: usize,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    use crate::monomorph::{mangle, MonomorphizedFn};

    // Build origin_id → &HirFn map for body lookup.
    let mut origin_fns: HashMap<ItemId, &HirFn> = HashMap::new();
    // Map of fn name → (origin id, type_params) for inner-call resolution.
    let mut fn_info: HashMap<String, (ItemId, Vec<String>)> = HashMap::new();
    for item in items {
        if let HirItem::Function(f) = item {
            origin_fns.insert(f.id, f);
            fn_info.insert(f.name.clone(), (f.id, f.type_params.clone()));
        }
    }
    // Structured `(declaring_trait, self_type_name, method_name)` index
    // built from `HirItem::Impl` metadata. Static-dispatch monomorphisation
    // resolves trait method calls through this rather than reconstructing
    // the impl symbol from a receiver display name.
    let impl_index = crate::dispatch::build_trait_impl_method_index(items);

    let mut seen: HashSet<MonoKey> = monomorphisations.iter().map(|m| m.key.clone()).collect();
    let mut worklist: Vec<MonoKey> = monomorphisations.iter().map(|m| m.key.clone()).collect();
    let mut cap_diag_emitted = false;

    while let Some(key) = worklist.pop() {
        let Some(origin) = origin_fns.get(&key.origin).copied() else {
            continue;
        };
        // Build substitution map: type_param name → concrete arg.
        let subst: HashMap<String, ResolvedTy> = origin
            .type_params
            .iter()
            .cloned()
            .zip(key.type_args.iter().cloned())
            .collect();
        // Walk the body to discover Call sites.
        let mut inner_sites: Vec<(String, SiteId)> = Vec::new();
        let mut trait_method_sites: Vec<TraitMethodStaticSite> = Vec::new();
        collect_call_sites_in_block(&origin.body, &mut inner_sites, &mut trait_method_sites);

        // ── Direct Call sites (existing logic) ───────────────────────────
        for (callee_name, site) in inner_sites {
            let Some((origin_id, type_params)) = fn_info.get(&callee_name).cloned() else {
                continue;
            };
            if type_params.is_empty() {
                continue;
            }
            let Some(args) = call_site_type_args.get(&site) else {
                continue;
            };
            // Substitute the recorded args.
            let substituted: Vec<ResolvedTy> =
                args.iter().map(|t| substitute_ty(t, &subst)).collect();
            // Skip if still abstract — the surrounding mono is generic
            // in some symbol that we don't have a concrete value for.
            if substituted
                .iter()
                .any(|t| contains_abstract_symbol(t, &fn_info))
            {
                continue;
            }
            let new_key = MonoKey {
                origin: origin_id,
                origin_name: callee_name.clone(),
                type_args: substituted.clone(),
            };
            if !seen.insert(new_key.clone()) {
                continue;
            }
            if monomorphisations.len() >= cap {
                if !cap_diag_emitted {
                    cap_diag_emitted = true;
                    diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::MonomorphisationCapExceeded { cap },
                        0..0,
                        "too many distinct generic-function instantiations discovered \
                         during inner-call closure; the compiler refuses to \
                         monomorphise beyond the configured cap",
                    ));
                }
                continue;
            }
            let mangled = mangle(&callee_name, &substituted);
            monomorphisations.push(MonomorphizedFn {
                key: new_key.clone(),
                mangled_name: mangled,
            });
            worklist.push(new_key);
        }

        // ── CallTraitMethodStatic sites (impl-method monomorphisation) ───
        // When a generic function body contains `item.show()` via a trait
        // bound, and this mono's substitution resolves the receiver type
        // param to a concrete type, look up the matching impl method via
        // the structured registry — `(declaring_trait, self_type_name,
        // method_name)` — and register the impl method's monomorphisation.
        for tms in trait_method_sites {
            let Some(concrete_ty) = subst.get(&tms.receiver_type_param) else {
                continue;
            };
            // Canonical (self_type_name, type_args) for impl lookup.
            let Some((self_type_name, type_args)) =
                crate::dispatch::receiver_self_type_for_impl_lookup(concrete_ty)
            else {
                continue;
            };
            // Structured registry lookup. The key is built from HIR-side
            // structured fields only — no symbol-name parsing.
            let key = (
                tms.declaring_trait.clone(),
                self_type_name.clone(),
                tms.method_name.clone(),
            );
            let Some(entry) = impl_index.get(&key) else {
                continue;
            };
            // Non-generic impl methods need no per-instantiation
            // registration; their bare symbol is already a module fn.
            if entry.impl_type_params.is_empty() {
                continue;
            }
            // Find the origin fn that owns this impl method symbol so
            // we can build a `MonoKey` whose `origin` points at the
            // pre-substitution body.
            let Some((origin_id, origin_type_params)) = fn_info.get(&entry.method_symbol).cloned()
            else {
                continue;
            };
            if origin_type_params.is_empty() {
                // Impl-block carried type params but the per-method
                // origin did not — invariant violation upstream;
                // skip to avoid wrong monomorphisation.
                continue;
            }
            // Skip if type_args still contain abstract symbols.
            if type_args
                .iter()
                .any(|t| contains_abstract_symbol(t, &fn_info))
            {
                continue;
            }
            let new_key = MonoKey {
                origin: origin_id,
                origin_name: entry.method_symbol.clone(),
                type_args: type_args.clone(),
            };
            if !seen.insert(new_key.clone()) {
                continue;
            }
            if monomorphisations.len() >= cap {
                if !cap_diag_emitted {
                    cap_diag_emitted = true;
                    diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::MonomorphisationCapExceeded { cap },
                        0..0,
                        "too many distinct generic-function instantiations discovered \
                         during inner-call closure; the compiler refuses to \
                         monomorphise beyond the configured cap",
                    ));
                }
                continue;
            }
            let mangled = mangle(&entry.method_symbol, &type_args);
            monomorphisations.push(MonomorphizedFn {
                key: new_key.clone(),
                mangled_name: mangled,
            });
            worklist.push(new_key);
        }
    }
}

fn collect_call_sites_in_block(
    block: &HirBlock,
    out: &mut Vec<(String, SiteId)>,
    trait_out: &mut Vec<TraitMethodStaticSite>,
) {
    for stmt in &block.statements {
        collect_call_sites_in_stmt(stmt, out, trait_out);
    }
    if let Some(tail) = &block.tail {
        collect_call_sites_in_expr(tail, out, trait_out);
    }
}

fn record_source_modules_for_items(
    items: &[HirItem],
    source_module: &str,
    diagnostic_source_modules: &mut HashMap<ItemId, String>,
) {
    for item in items {
        let id = match item {
            HirItem::Function(item) => item.id,
            HirItem::TypeDecl(item) => item.id,
            HirItem::Machine(item) => item.id,
            HirItem::Record(item) => item.id,
            HirItem::Actor(item) => item.id,
            HirItem::Supervisor(item) => item.id,
            HirItem::Impl(item) => item.id,
            HirItem::ExternFn(item) => item.id,
            HirItem::Const(item) => item.id,
        };
        diagnostic_source_modules.insert(id, source_module.to_string());
    }
}

fn collect_call_sites_in_stmt(
    stmt: &HirStmt,
    out: &mut Vec<(String, SiteId)>,
    trait_out: &mut Vec<TraitMethodStaticSite>,
) {
    match &stmt.kind {
        HirStmtKind::Let(_, Some(e)) | HirStmtKind::Expr(e) | HirStmtKind::Return(Some(e)) => {
            collect_call_sites_in_expr(e, out, trait_out);
        }
        HirStmtKind::Assign { target, value } => {
            collect_call_sites_in_expr(target, out, trait_out);
            collect_call_sites_in_expr(value, out, trait_out);
        }
        // Let-without-value and bare return have no sub-expression to collect.
        HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
        HirStmtKind::Defer { body, .. } => {
            collect_call_sites_in_expr(body, out, trait_out);
        }
    }
}

#[allow(
    clippy::too_many_lines,
    reason = "single recursive walker spanning all HirExprKind variants"
)]
fn collect_call_sites_in_expr(
    expr: &HirExpr,
    out: &mut Vec<(String, SiteId)>,
    trait_out: &mut Vec<TraitMethodStaticSite>,
) {
    match &expr.kind {
        HirExprKind::Call { callee, args } | HirExprKind::SpawnedCall { callee, args, .. } => {
            // Record the site if callee is a direct BindingRef name.
            if let HirExprKind::BindingRef { name, .. } = &callee.kind {
                out.push((name.clone(), expr.site));
            }
            collect_call_sites_in_expr(callee, out, trait_out);
            for a in args {
                collect_call_sites_in_expr(a, out, trait_out);
            }
        }
        HirExprKind::Spawn { args, .. } => {
            for (_, arg) in args {
                collect_call_sites_in_expr(arg, out, trait_out);
            }
        }
        HirExprKind::ActorSend { receiver, args, .. }
        | HirExprKind::ActorAsk { receiver, args, .. }
        | HirExprKind::ResolvedImplCall { receiver, args, .. }
        | HirExprKind::CallDynMethod { receiver, args, .. } => {
            collect_call_sites_in_expr(receiver, out, trait_out);
            for arg in args {
                collect_call_sites_in_expr(arg, out, trait_out);
            }
        }
        HirExprKind::ConnAwaitRead { conn, .. } => {
            collect_call_sites_in_expr(conn, out, trait_out);
        }
        HirExprKind::ListenerAwaitAccept { listener } => {
            collect_call_sites_in_expr(listener, out, trait_out);
        }
        HirExprKind::RemoteActorAsk {
            receiver,
            msg,
            timeout_ms,
            ..
        } => {
            collect_call_sites_in_expr(receiver, out, trait_out);
            collect_call_sites_in_expr(msg, out, trait_out);
            collect_call_sites_in_expr(timeout_ms, out, trait_out);
        }
        HirExprKind::CallTraitMethodStatic {
            receiver,
            receiver_type_param,
            declaring_trait,
            method_name,
            args,
            ..
        } => {
            // Record this as a trait-method static dispatch site for the
            // monomorphisation closure to resolve once the enclosing
            // function's type params are substituted.
            trait_out.push(TraitMethodStaticSite {
                receiver_type_param: receiver_type_param.clone(),
                declaring_trait: declaring_trait.clone(),
                method_name: method_name.clone(),
            });
            collect_call_sites_in_expr(receiver, out, trait_out);
            for arg in args {
                collect_call_sites_in_expr(arg, out, trait_out);
            }
        }
        HirExprKind::VarSelfMethodCall {
            receiver,
            target,
            args,
            ..
        } => {
            match target {
                HirVarSelfMethodTarget::Direct { callee } => out.push((callee.clone(), expr.site)),
                HirVarSelfMethodTarget::StaticTrait {
                    receiver_type_param,
                    declaring_trait,
                    method_name,
                    ..
                } => trait_out.push(TraitMethodStaticSite {
                    receiver_type_param: receiver_type_param.clone(),
                    declaring_trait: declaring_trait.clone(),
                    method_name: method_name.clone(),
                }),
            }
            collect_call_sites_in_expr(receiver, out, trait_out);
            for arg in args {
                collect_call_sites_in_expr(arg, out, trait_out);
            }
        }
        HirExprKind::Binary { left, right, .. } | HirExprKind::IdentityCompare { left, right } => {
            collect_call_sites_in_expr(left, out, trait_out);
            collect_call_sites_in_expr(right, out, trait_out);
        }
        HirExprKind::Unary { operand, .. } => collect_call_sites_in_expr(operand, out, trait_out),
        HirExprKind::NumericCast { value, .. } | HirExprKind::CoerceToDynTrait { value, .. } => {
            collect_call_sites_in_expr(value, out, trait_out);
        }
        HirExprKind::TupleLiteral { elements } => {
            for elem in elements {
                collect_call_sites_in_expr(elem, out, trait_out);
            }
        }
        HirExprKind::Block(b) => collect_call_sites_in_block(b, out, trait_out),
        HirExprKind::GenBlock { body, .. } => collect_call_sites_in_block(body, out, trait_out),
        HirExprKind::Yield {
            value: Some(value), ..
        } => collect_call_sites_in_expr(value, out, trait_out),
        HirExprKind::If {
            condition,
            then_expr,
            else_expr,
        } => {
            collect_call_sites_in_expr(condition, out, trait_out);
            collect_call_sites_in_expr(then_expr, out, trait_out);
            if let Some(e) = else_expr {
                collect_call_sites_in_expr(e, out, trait_out);
            }
        }
        HirExprKind::StructInit { fields, base, .. } => {
            for (_, e) in fields {
                collect_call_sites_in_expr(e, out, trait_out);
            }
            if let Some(b) = base {
                collect_call_sites_in_expr(b, out, trait_out);
            }
        }
        HirExprKind::FieldAccess { object, .. } => {
            collect_call_sites_in_expr(object, out, trait_out);
        }
        HirExprKind::Scope { body }
        | HirExprKind::ForkBlock { body, .. }
        | HirExprKind::Loop { body } => {
            collect_call_sites_in_block(body, out, trait_out);
        }
        HirExprKind::ScopeDeadline { duration, body } => {
            collect_call_sites_in_expr(duration, out, trait_out);
            collect_call_sites_in_block(body, out, trait_out);
        }
        HirExprKind::TupleIndex { tuple, .. } => collect_call_sites_in_expr(tuple, out, trait_out),
        HirExprKind::Index { container, index } => {
            collect_call_sites_in_expr(container, out, trait_out);
            collect_call_sites_in_expr(index, out, trait_out);
        }
        HirExprKind::Slice {
            container,
            start,
            end,
            ..
        } => {
            collect_call_sites_in_expr(container, out, trait_out);
            if let Some(s) = start {
                collect_call_sites_in_expr(s, out, trait_out);
            }
            if let Some(e) = end {
                collect_call_sites_in_expr(e, out, trait_out);
            }
        }
        HirExprKind::SpawnLambdaActor { body, .. } | HirExprKind::Closure { body, .. } => {
            collect_call_sites_in_expr(body, out, trait_out);
        }
        HirExprKind::While { condition, body } => {
            collect_call_sites_in_expr(condition, out, trait_out);
            collect_call_sites_in_block(body, out, trait_out);
        }
        HirExprKind::ForRange {
            start, end, body, ..
        } => {
            collect_call_sites_in_expr(start, out, trait_out);
            collect_call_sites_in_expr(end, out, trait_out);
            collect_call_sites_in_block(body, out, trait_out);
        }
        HirExprKind::Match { scrutinee, arms } => {
            collect_call_sites_in_expr(scrutinee, out, trait_out);
            for arm in arms {
                if let Some(guard) = &arm.guard {
                    collect_call_sites_in_expr(guard, out, trait_out);
                }
                collect_call_sites_in_expr(&arm.body, out, trait_out);
            }
        }
        HirExprKind::WhileLet {
            scrutinee, body, ..
        } => {
            collect_call_sites_in_expr(scrutinee, out, trait_out);
            collect_call_sites_in_block(body, out, trait_out);
        }
        HirExprKind::IfLet {
            scrutinee,
            body,
            else_body,
            ..
        } => {
            collect_call_sites_in_expr(scrutinee, out, trait_out);
            collect_call_sites_in_block(body, out, trait_out);
            if let Some(eb) = else_body {
                collect_call_sites_in_block(eb, out, trait_out);
            }
        }
        HirExprKind::Break { value, .. } => {
            if let Some(value) = value {
                collect_call_sites_in_expr(value, out, trait_out);
            }
        }
        HirExprKind::NumericMethod { receiver, arg, .. } => {
            collect_call_sites_in_expr(receiver, out, trait_out);
            collect_call_sites_in_expr(arg, out, trait_out);
        }
        HirExprKind::MachineEmit { fields, .. } => {
            for (_, e) in fields {
                collect_call_sites_in_expr(e, out, trait_out);
            }
        }
        HirExprKind::MachineStep {
            receiver, event, ..
        } => {
            collect_call_sites_in_expr(receiver, out, trait_out);
            collect_call_sites_in_expr(event, out, trait_out);
        }
        HirExprKind::CancellationTokenIsCancelled { receiver }
        | HirExprKind::GeneratorNext { receiver, .. }
        | HirExprKind::MachineStateName { receiver, .. } => {
            collect_call_sites_in_expr(receiver, out, trait_out);
        }
        HirExprKind::MachineVariantCtor { payload, .. } => {
            if let Some(fields) = payload {
                for (_, e) in fields {
                    collect_call_sites_in_expr(e, out, trait_out);
                }
            }
        }
        HirExprKind::Select(sel) => {
            for arm in &sel.arms {
                match &arm.kind {
                    HirSelectArmKind::StreamNext { stream } => {
                        collect_call_sites_in_expr(stream, out, trait_out);
                    }
                    HirSelectArmKind::ActorAsk { actor, args, .. } => {
                        collect_call_sites_in_expr(actor, out, trait_out);
                        for a in args {
                            collect_call_sites_in_expr(a, out, trait_out);
                        }
                    }
                    HirSelectArmKind::TaskAwait { task } => {
                        collect_call_sites_in_expr(task, out, trait_out);
                    }
                    HirSelectArmKind::ChannelRecv { receiver, .. } => {
                        collect_call_sites_in_expr(receiver, out, trait_out);
                    }
                    HirSelectArmKind::AfterTimer { duration } => {
                        collect_call_sites_in_expr(duration, out, trait_out);
                    }
                }
                collect_call_sites_in_expr(&arm.body, out, trait_out);
            }
        }
        // Leaf variants: no sub-expressions, so no call sites to collect.
        HirExprKind::Literal(_)
        | HirExprKind::RegexLiteralRef { .. }
        | HirExprKind::BindingRef { .. }
        | HirExprKind::ContextReader { .. }
        | HirExprKind::AwaitTask { .. }
        | HirExprKind::MachineFieldAccess { .. }
        | HirExprKind::MachineEventFieldAccess { .. }
        | HirExprKind::Yield { value: None, .. }
        | HirExprKind::Continue { .. }
        | HirExprKind::Unsupported(_) => {}
    }
}

/// Substitute `ResolvedTy::Named { name, args: [] }` whose `name`
/// appears in `subst` with the mapped concrete type. Recurses into
/// composite type constructors. Used by the closure-under-substitution
/// pass and by MIR-side monomorphisation lowering.
#[must_use]
#[allow(
    clippy::match_same_arms,
    reason = "DI-019: the abstract-parameter `TypeParam` case is listed \
              explicitly (totality over the new variant) even though an \
              un-substituted parameter clones identically to the leaf \
              fall-through"
)]
pub fn substitute_ty<S: std::hash::BuildHasher>(
    ty: &ResolvedTy,
    subst: &HashMap<String, ResolvedTy, S>,
) -> ResolvedTy {
    match ty {
        ResolvedTy::Named { name, args, .. } if args.is_empty() && subst.contains_key(name) => {
            subst[name].clone()
        }
        ResolvedTy::Named {
            name,
            args,
            builtin,
            is_opaque,
        } => ResolvedTy::Named {
            name: name.clone(),
            args: args.iter().map(|a| substitute_ty(a, subst)).collect(),
            builtin: *builtin,
            is_opaque: *is_opaque,
        },
        ResolvedTy::Tuple(items) => {
            ResolvedTy::Tuple(items.iter().map(|t| substitute_ty(t, subst)).collect())
        }
        ResolvedTy::Array(elem, n) => ResolvedTy::Array(Box::new(substitute_ty(elem, subst)), *n),
        ResolvedTy::Slice(elem) => ResolvedTy::Slice(Box::new(substitute_ty(elem, subst))),
        ResolvedTy::Function { params, ret } => ResolvedTy::Function {
            params: params.iter().map(|p| substitute_ty(p, subst)).collect(),
            ret: Box::new(substitute_ty(ret, subst)),
        },
        ResolvedTy::Closure {
            params,
            ret,
            captures,
        } => ResolvedTy::Closure {
            params: params.iter().map(|p| substitute_ty(p, subst)).collect(),
            ret: Box::new(substitute_ty(ret, subst)),
            captures: captures.iter().map(|c| substitute_ty(c, subst)).collect(),
        },
        ResolvedTy::Pointer {
            is_mutable,
            pointee,
        } => ResolvedTy::Pointer {
            is_mutable: *is_mutable,
            pointee: Box::new(substitute_ty(pointee, subst)),
        },
        ResolvedTy::Task(inner) => ResolvedTy::Task(Box::new(substitute_ty(inner, subst))),
        // Borrow and trait-object are composite type constructors: their
        // payloads must be descended so a nested `TypeParam` is substituted
        // (DI-019 — no wildcard absorbs a composite). Mirrors the scope-aware
        // converter in `hew_types::ResolvedTy::from_ty_scoped`.
        ResolvedTy::Borrow { pointee } => ResolvedTy::Borrow {
            pointee: Box::new(substitute_ty(pointee, subst)),
        },
        ResolvedTy::TraitObject { traits } => ResolvedTy::TraitObject {
            traits: traits
                .iter()
                .map(|bound| hew_types::ResolvedTraitBound {
                    trait_name: bound.trait_name.clone(),
                    args: bound.args.iter().map(|a| substitute_ty(a, subst)).collect(),
                    assoc_bindings: bound
                        .assoc_bindings
                        .iter()
                        .map(|(name, t)| (name.clone(), substitute_ty(t, subst)))
                        .collect(),
                })
                .collect(),
        },
        // A structural abstract parameter (A622). Substitute it when the map
        // carries its name; otherwise keep it abstract.
        ResolvedTy::TypeParam { name } if subst.contains_key(name) => subst[name].clone(),
        ResolvedTy::TypeParam { .. } => ty.clone(),
        _ => ty.clone(),
    }
}

fn contains_abstract_symbol(
    ty: &ResolvedTy,
    fn_info: &HashMap<String, (ItemId, Vec<String>)>,
) -> bool {
    // A type contains an abstract symbol if any `Named { args: [] }`
    // matches a type-parameter name declared on any top-level fn.
    let is_type_param = |name: &str| {
        fn_info
            .values()
            .any(|(_, params)| params.iter().any(|p| p == name))
    };
    match ty {
        ResolvedTy::Named { name, args, .. } => {
            if args.is_empty() && is_type_param(name) {
                return true;
            }
            args.iter().any(|a| contains_abstract_symbol(a, fn_info))
        }
        ResolvedTy::Tuple(items) => items.iter().any(|t| contains_abstract_symbol(t, fn_info)),
        ResolvedTy::Array(elem, _) | ResolvedTy::Slice(elem) => {
            contains_abstract_symbol(elem, fn_info)
        }
        ResolvedTy::Function { params, ret } => {
            params.iter().any(|p| contains_abstract_symbol(p, fn_info))
                || contains_abstract_symbol(ret, fn_info)
        }
        ResolvedTy::Closure {
            params,
            ret,
            captures,
        } => {
            params.iter().any(|p| contains_abstract_symbol(p, fn_info))
                || contains_abstract_symbol(ret, fn_info)
                || captures
                    .iter()
                    .any(|c| contains_abstract_symbol(c, fn_info))
        }
        ResolvedTy::Pointer { pointee, .. } | ResolvedTy::Borrow { pointee } => {
            contains_abstract_symbol(pointee, fn_info)
        }
        ResolvedTy::TraitObject { traits } => traits.iter().any(|bound| {
            bound
                .args
                .iter()
                .any(|a| contains_abstract_symbol(a, fn_info))
                || bound
                    .assoc_bindings
                    .iter()
                    .any(|(_, t)| contains_abstract_symbol(t, fn_info))
        }),
        ResolvedTy::Task(inner) => contains_abstract_symbol(inner, fn_info),
        // A structural type parameter is abstract by construction.
        ResolvedTy::TypeParam { .. } => true,
        _ => false,
    }
}

#[derive(Debug)]
struct LowerCtx {
    ids: IdGen,
    scopes: Vec<ScopeMap>,
    /// Maps function name → pre-allocated `ItemId` + return type + param types.
    fn_registry: HashMap<String, FnEntry>,
    /// Same-module bare-call rewrites active while lowering an imported module
    /// free-function body. Keys are source-visible bare identifiers; values are
    /// the qualified, native-symbol-safe `fn_registry` keys emitted for that
    /// imported module.
    imported_fn_rewrites: Option<HashMap<String, String>>,
    /// Bare-name → `ConstEntry` map active while lowering an imported module's
    /// function bodies.  A module may reference its own module-level consts
    /// by bare name (e.g. `STATUS_OK` inside `tls.hew`), but only the
    /// qualified key `"tls.STATUS_OK"` is in the global `const_registry`.
    /// This scoped map bridges the gap: it is populated before lowering each
    /// module's bodies and cleared after, mirroring `imported_fn_rewrites`.
    imported_module_consts: Option<HashMap<String, ConstEntry>>,
    /// Per-named-type marker + close-method registry. Pre-populated from
    /// every `Item::TypeDecl` before function bodies lower so that
    /// `ValueClass::of_ty` can resolve `Named` types as the body is walked.
    /// Also seeded with M2 substrate types (Duplex, Sink, Stream, etc.) via
    /// `builtin_type_classes::seed_builtin_type_classes` before the `TypeDecl` loop.
    type_classes: crate::value_class::TypeClassTable,
    /// Pre-collected inherent-impl `close` method signatures, keyed by the
    /// self-type name. Populated in `lower_program` before the type-decl
    /// pre-pass so `lower_type_decl` can:
    ///
    ///   * broaden the `ResourceMissingClose` presence check to consider
    ///     inherent-impl `<T>::close` declarations (W3.030 Q-α-B); and
    ///   * enforce the close-must-return-unit discipline at the HIR
    ///     boundary (W3.030 Q-β-C).
    ///
    /// Empty when called from non-`lower_program` entry points (the cross-
    /// module `lower_type_decl` calls under `program.module_graph` reach
    /// this with the root map already populated; imported enum `TypeDecls`
    /// carry no `#[resource]` marker so the absence of their inherent
    /// impls in this map is harmless).
    impl_close_methods: HashMap<String, ImplCloseSignature>,
    diagnostics: Vec<HirDiagnostic>,
    /// Checker-owned function and method signatures keyed by canonical function
    /// symbol. Var-self write-back lowering reads `requires_mutable_receiver`
    /// from this table instead of re-deriving it from syntax at call sites.
    fn_sigs: HashMap<String, hew_types::FnSig>,
    /// Checker-owned method-call lowering decisions. Keyed by the method-call
    /// expression span. `Expr::MethodCall` lowering looks up each call site
    /// here and rewrites to `HirExprKind::Call` with the runtime symbol.
    /// A missing entry is a fail-closed diagnostic (`MethodCallNoRewrite`).
    method_call_rewrites: HashMap<SpanKey, MethodCallRewrite>,
    /// Checker-owned integer opt-out method lowering decisions keyed by the
    /// method-call expression span. HIR checks this before generic method-call
    /// rewrites so numeric methods lower to a dedicated node without any
    /// downstream method-name matching.
    numeric_method_lowerings: HashMap<SpanKey, NumericMethodLowering>,
    /// Checker-owned actor receive dispatch decisions keyed by method-call span.
    /// HIR consumes these to choose `ActorSend` / `ActorAsk` without reclassifying
    /// receiver types.
    actor_method_dispatch: HashMap<SpanKey, ActorMethodKind>,
    /// Checker-owned machine method dispatch decisions keyed by method-call span.
    /// HIR checks this before `method_call_rewrites` to produce `MachineStep` /
    /// `MachineStateName` nodes rather than falling through to `MethodCallNoRewrite`.
    machine_method_dispatch: HashMap<SpanKey, hew_types::MachineMethodKind>,
    /// Checker-owned `await conn.read()` suspending-read sites keyed by the inner
    /// method-call span (NEW-1). `true` = `read_string` (string-wrapped), `false`
    /// = raw `read`. HIR's `Expr::Await` arm consumes this to emit `ConnAwaitRead`.
    conn_await_reads: HashMap<SpanKey, bool>,
    /// Checker-owned `await listener.accept()` suspending-accept sites keyed by
    /// the inner method-call span (NEW-2). HIR's `Expr::Await` arm consumes this
    /// to emit `ListenerAwaitAccept` — the sibling of `conn_await_reads`.
    listener_await_accepts: std::collections::HashSet<SpanKey>,
    /// Checker-owned method-call receiver classifications. Used only to fail
    /// closed when the checker classified a receiver as actor-dispatchable but
    /// omitted the corresponding `actor_method_dispatch` discriminator.
    method_call_receiver_kinds: HashMap<SpanKey, MethodCallReceiverKind>,
    /// Per-call-site `T → dyn Trait` coercion side-table. Keyed by the
    /// argument expression span. `lower_expr` consults this at every
    /// expression's exit; if the just-lowered expression's span has an
    /// entry, the result is wrapped in `HirExprKind::CoerceToDynTrait`.
    /// Carries the checker's authoritative method-table resolution.
    dyn_trait_coercions: HashMap<SpanKey, hew_types::DynCoercion>,
    /// Per-call-site `dyn Trait` method-dispatch side-table. Keyed by the
    /// method-call expression span. `lower_method_call` consults this
    /// before the `method_call_rewrites` branch so that
    /// `obj.method()` on a `dyn`-typed receiver lowers to
    /// `HirExprKind::CallDynMethod` (vtable slot index attached) rather
    /// than failing closed on the missing rewrite entry.
    dyn_trait_method_calls: HashMap<SpanKey, hew_types::DynMethodCall>,
    /// Checker-resolved `(ImplId, MethodTarget)` verdict per method-call
    /// site, keyed by the method-call expression span. Populated by the
    /// checker's `populate_collection_dispatch` for builtin-generic
    /// (HashMap/HashSet today; Vec/Option/Result on the migration roadmap)
    /// method calls.
    ///
    /// `lower_method_call` consults this **after** the existing checker
    /// side-tables (numeric / actor / machine / dyn-trait) and **before**
    /// the legacy `method_call_rewrites` branch. The lookup runs
    /// unconditionally so any boundary-type conversion failure surfaces
    /// as a real diagnostic; when the verdict survives boundary conversion,
    /// `lower_method_call` emits `HirExprKind::ResolvedImplCall` carrying
    /// `MethodTarget.symbol_name` verbatim. MIR consumes that symbol via
    /// `Terminator::Call`. This is the production path for builtin
    /// HashMap/HashSet dispatch today; Vec/Option/Result migrate later.
    resolved_calls: HashMap<SpanKey, hew_types::ResolvedCall>,
    /// Checker-inferred types for every expression, keyed by expression span.
    /// Consulted at `Expr::Call` sites to determine the call-result type from
    /// checker authority rather than re-deriving from the callee's HIR type.
    /// This is the canonical source of truth for builtin callee result types
    /// (e.g. `duplex_pair`) that have no AST `fn` entry and therefore no
    /// `fn_registry` hit.
    expr_types: HashMap<SpanKey, Ty>,
    /// W4.047 P1.2 — the **typed** checker→HIR handoff map (the shadow of
    /// `expr_types`). Carries `ResolvedTy` (never `Ty::Var`/`Ty::Error`/literal)
    /// for every concrete accepted span; cloned verbatim from
    /// `TypeCheckOutput::resolved_expr_types`.
    ///
    /// In Phase 1 this is a *shadow*: lowering still derives every node type
    /// from `expr_types`, and the typed map is only consulted by the
    /// `assert_resolved_ty_totality` net to prove — across the whole real
    /// corpus — that it agrees with the live `expr_types`→`from_ty` path at
    /// every fail-open / boundary-violation site. Zero behaviour change in
    /// Phase 1; Phase 2 promotes this to the primary read path.
    resolved_expr_types: HashMap<SpanKey, ResolvedTy>,
    /// Checker-authoritative RHS spans for accepted `lhs is TypeName`
    /// patterns. When present, the RHS identifier is a type pattern, not a
    /// value expression to lower through lexical bindings.
    is_type_patterns: HashMap<SpanKey, Ty>,
    /// Checker-authoritative general-closure capture facts keyed by closure
    /// literal span. HIR consumes this ledger fail-closed when materialising
    /// `HirExprKind::Closure`; it does not infer capture legality from syntax.
    closure_capture_facts: HashMap<SpanKey, Vec<ClosureCaptureFact>>,
    /// Checker-authoritative escape classification keyed by closure literal
    /// span (the checker's `closure_escape_facts`). HIR threads this fact into
    /// `HirExprKind::Closure::escape_kind` so MIR's
    /// `ClosureEnvLayout::allocation_strategy` can dispatch between
    /// `Local`/`Forked`/`Escapes` storage without re-deriving classification.
    closure_escape_facts: HashMap<SpanKey, ClosureEscapeFact>,
    /// Stack of checker-inferred generator Yield parameters while lowering
    /// nested `gen {}` bodies. `Expr::Yield` consumes the innermost entry.
    generator_yield_tys: Vec<ResolvedTy>,
    /// Depth counter for nested `scope{}` bodies. When > 0, statement-expression
    /// calls are inferred as child-task spawns (TI-1); outside any scope body
    /// all calls are synchronous (TI-3). Using a depth counter rather than a
    /// bool supports nested `scope{}` blocks correctly.
    scope_depth: u32,
    /// The `ScopeId` of the innermost lexical block currently being lowered.
    /// Updated by `lower_block` immediately after `self.ids.scope()` allocates
    /// the block's identity. Read by `Stmt::Defer` lowering to tag the deferred
    /// body with the owning scope so MIR can materialise it at scope exits.
    current_scope_id: ScopeId,
    /// Return type of the innermost function-like body currently being lowered.
    /// Used by `Expr::PostfixTry` to synthesize `return Err(e)` / `return None`
    /// with the enclosing body's return type rather than the scrutinee type.
    current_return_type: Option<ResolvedTy>,
    /// Set to `true` immediately before lowering the expression of a
    /// `Stmt::Expression` statement. `lower_expr` consumes it via
    /// `mem::replace(…, false)` at entry, so all recursive calls see `false`.
    /// This lets `Expr::Await` check whether it is the direct statement, not
    /// a sub-expression of a return value, argument, binary operand, etc.
    /// (TI-4 position rule.)
    statement_position: bool,
    /// `Some((let_id, let_name))` while lowering the body of an actor-lambda
    /// that is the value of `let <let_name> = actor |..| { .. }`. The
    /// capture-strength classifier inside the body walk compares each
    /// resolved capture's `BindingId` to `let_id` to discriminate the
    /// self-reference (Weak, §5.9 ratification 2) from every other captured
    /// binding (Strong). Nested actor-lambdas restore the prior value via
    /// `mem::replace` so the outer self-binding doesn't leak into an inner
    /// lambda's classification.
    current_actor_self: Option<(BindingId, String)>,
    /// Checker-resolved type arguments for generic function calls that
    /// lack explicit type annotations. Keyed by the call expression span.
    ///
    /// Consumed at `Expr::Call` lowering (G-1.a, producer-bridge wakeup):
    /// every callsite whose callee is a generic top-level user fn
    /// (non-empty `FnEntry.type_params`) is paired with the entry here
    /// and inserted into `mono_registry`. A poisoned entry (failing the
    /// `ResolvedTy::from_ty` boundary conversion) emits
    /// `MonomorphisationCallTypeArgsViolation`; a generic callsite with
    /// no entry at all is treated as the trivially-monomorphic case
    /// (e.g. a builtin or runtime-symbol call) and skipped.
    /// (LESSONS: checker-authority P0, producer-bridge-before-codegen P1)
    call_type_args: HashMap<SpanKey, Vec<Ty>>,
    /// Checker-authoritative ABI-selector facts for erased runtime types.
    /// Currently covers `HashSet` element-type dispatch (`i64`/`u64`/`str`
    /// → `Int64` or `String` ABI variant).
    ///
    /// Passive pass-through: `HashSet` ABI selection lives in MIR/codegen, not
    /// in HIR lowering.  Future consumer: E4 codegen and slice 4.7 spine
    /// widening when `HashSet` operations enter the Rust pipeline.
    /// (LESSONS: checker-authority P0, producer-bridge-before-codegen P1)
    #[expect(
        dead_code,
        reason = "passive pass-through; future consumer is HashSet ABI selection in E4 codegen"
    )]
    lowering_facts: HashMap<SpanKey, LoweringFact>,
    /// Checker-resolved assignment target classification keyed by the target
    /// expression span.
    ///
    /// Passive pass-through: HIR does not yet lower `Stmt::Assign` (it falls
    /// through to `unsupported`).  Future consumer: MIR/codegen compound-
    /// assignment lowering and Machine Lane B actor-field writes.
    /// (LESSONS: checker-authority P0, producer-bridge-before-codegen P1)
    #[expect(
        dead_code,
        reason = "passive pass-through; future consumer is Stmt::Assign lowering in MIR/codegen"
    )]
    assign_target_kinds: HashMap<SpanKey, AssignTargetKind>,
    /// Checker-resolved assignment target type-shape metadata (signedness flag)
    /// keyed by the target expression span.  Populated alongside
    /// `assign_target_kinds` for every accepted assignment.
    ///
    /// Passive pass-through: same consumer timeline as `assign_target_kinds`.
    /// (LESSONS: checker-authority P0, producer-bridge-before-codegen P1)
    #[expect(
        dead_code,
        reason = "passive pass-through; future consumer is compound-assignment signedness in codegen"
    )]
    assign_target_shapes: HashMap<SpanKey, AssignTargetShape>,
    /// Checker-owned actor receive-handler guard policy keyed by receive span.
    actor_handler_state_guards: HashMap<SpanKey, ActorStateGuard>,
    /// Actor type names that participate in reference cycles, computed by the
    /// checker's cycle-detection pass. Consumed by `lower_actor` to populate
    /// `HirActorDecl.cycle_capable`. Future runtime consumer: actor codegen
    /// (refcount-cycle-breaking strategy selection).
    /// (LESSONS: producer-bridge-before-codegen P1)
    cycle_capable_actors: HashSet<String>,
    /// Per-actor protocol descriptors lifted from the checker
    /// (`TypeCheckOutput.actor_protocol_descriptors`). Consumed by
    /// `lower_actor` to populate `HirActorDecl.protocol_descriptor`. An
    /// actor missing from this map either declares no receive handlers or
    /// the checker emitted an `ActorProtocolCollision` for it; either way
    /// the lowered HIR carries `protocol_descriptor: None` and downstream
    /// MIR fails closed when it tries to derive a `msg_id`.
    actor_protocol_descriptors: HashMap<String, hew_types::ActorProtocolDescriptor>,
    /// Distinct concrete instantiations of generic top-level user fns,
    /// accumulated as `Expr::Call` lowering walks the program. Drained
    /// into `HirModule.monomorphisations` at the end of `lower_program`.
    /// Cap is configurable via `lower_program_with_mono_cap` for
    /// fail-closed-diagnostic tests.
    mono_registry: MonoRegistry,
    /// Tracks whether the `MonomorphisationCapExceeded` diagnostic has
    /// already been emitted for this lowering invocation, to avoid
    /// spamming one diagnostic per overflowing callsite.
    mono_cap_diag_emitted: bool,
    /// Per-call-site recorded concrete type arguments. Populated by
    /// `record_call_site_type_args` whenever a `HirExprKind::Call` is
    /// produced for a generic top-level user-fn callee. Drained into
    /// `HirModule.call_site_type_args` at end of `lower_program`.
    ///
    /// Includes "still-abstract" entries (where the callee is generic
    /// and the call is itself inside a generic body, so the recorded
    /// args contain the enclosing fn's type-parameter symbols). MIR
    /// lowering substitutes those symbols via the per-monomorphisation
    /// substitution map; the registry's closure-under-substitution pass
    /// uses the same data to discover inner monomorphisations.
    call_site_type_args: HashMap<SiteId, Vec<ResolvedTy>>,
    /// Pre-collected record/type-decl shape registry. Populated in the
    /// type-decl pre-pass before function bodies lower, so that
    /// `Expr::StructInit` lowering can answer "is this a generic user
    /// record?" and look up its source field shape. Tuple-form records
    /// land here with `fields = []`; they never trigger record-layout
    /// emission (their constructor goes through `Expr::Call`).
    record_registry: HashMap<String, RecordEntry>,
    /// Checker-resolved type arguments for generic record-init sites
    /// (`R { ... }` against a `pub type R<T>` or `record R<T>`),
    /// keyed by the struct-init expression span.
    ///
    /// Consumed at `Expr::StructInit` lowering: every init site whose
    /// record has non-empty `type_params` is paired with the entry here
    /// and inserted into `record_layout_registry`. A poisoned entry
    /// (failing the `ResolvedTy::from_ty` boundary conversion) emits
    /// `RecordLayoutTypeArgsViolation`; a generic init site with no
    /// entry at all is skipped (the checker only records sites whose
    /// args resolved fully concretely).
    /// (LESSONS: `checker-authority` P0, `producer-bridge-before-codegen` P1)
    record_init_type_args: HashMap<SpanKey, Vec<Ty>>,
    /// Distinct user-record instantiations observed at `StructInit`
    /// sites, accumulated as expression lowering walks the program.
    /// Drained into `HirModule.record_layouts` at the end of
    /// `lower_program`. Cap is configurable via
    /// `lower_program_with_mono_cap` (shared with the fn registry).
    record_layout_registry: RecordLayoutRegistry,
    /// Tracks whether the `RecordLayoutCapExceeded` diagnostic has
    /// already been emitted for this lowering invocation.
    record_layout_cap_diag_emitted: bool,
    /// Per-enum type-parameter names, keyed by enum type name. Populated
    /// during the type-decl second pass alongside `enum_variants_by_name`.
    /// Consumed by the enum-layout discovery pass to know which names in a
    /// variant's field types are type-parameter symbols vs. concrete named
    /// types, so `substitute_type_params` can substitute correctly.
    enum_type_params: HashMap<String, Vec<String>>,
    /// Per-enum `ItemId`, keyed by enum type name. Populated alongside
    /// `enum_type_params` so the `EnumMonoKey.origin` field can be set to
    /// the HIR-allocated `ItemId` of the originating enum declaration rather
    /// than a synthetic value.
    enum_item_ids: HashMap<String, ItemId>,
    /// Distinct user-enum instantiations observed at enum-ctor sites and
    /// match scrutinees, accumulated during HIR lowering. Drained into
    /// `HirModule.enum_layouts` at the end of `lower_program`. Cap is
    /// shared with the fn and record registries.
    enum_layout_registry: EnumLayoutRegistry,
    /// Checker-authoritative mapping from qualified function name to the
    /// intrinsic catalog key declared via `#[intrinsic("key")]`. Functions
    /// present here must be validated against `stdlib_catalog` and must have
    /// their bodies skipped during lowering (the body is a placeholder).
    /// Fail-closed: an unknown key emits `UnknownIntrinsic`.
    intrinsic_declarations: HashMap<String, String>,
    /// Checker-side supervisor child-slot table, keyed by the `SpanKey` of
    /// each `FieldAccess` expression that the checker resolved as a supervisor
    /// child accessor. Cloned from `tc_output.supervisor_child_slots` at
    /// construction. Read-only during lowering; lookups translate the span key
    /// to the pre-allocated `SiteId` and accumulate into `supervisor_child_slots`.
    supervisor_child_slots_checker: HashMap<SpanKey, ChildSlot>,
    /// Per-field-access `SiteId` → `ChildSlot` accumulator. Populated during
    /// `HirExprKind::FieldAccess` lowering whenever
    /// `supervisor_child_slots_checker` contains an entry for the expression
    /// span. Drained into `HirModule.supervisor_child_slots` at the end of
    /// `lower_program` (mirrors the `call_site_type_args` pattern).
    supervisor_child_slots: HashMap<SiteId, ChildSlot>,
    /// Module-level regex literal table. Accumulates distinct compiled
    /// patterns observed in match arms (and standalone `re"..."` expressions).
    /// Deduplicated by raw pattern string equality (no flags in v0.5).
    /// Each entry's `literal_id` matches its 0-based index in this `Vec`.
    ///
    /// Drained into `HirModule.regex_literals` at the end of `lower_program`.
    regex_literals: Vec<HirRegexLiteral>,
    /// Deduplication index for `regex_literals`: maps pattern string to its
    /// allocated `literal_id`. Lookups via `alloc_regex_literal` avoid
    /// scanning the `Vec` linearly.
    regex_literal_index: HashMap<String, u32>,
    /// Event names of the machine currently being lowered, set only while
    /// lowering a machine body (transition bodies, entry/exit blocks). The
    /// index position corresponds to `HirMachineDecl::events` ordering so
    /// `Expr::MachineEmit` can resolve `event_idx` by name lookup.
    ///
    /// `None` outside of any machine body; `Some(names)` inside. Restored
    /// via `mem::replace` at the end of each machine-body lowering.
    current_machine_events: Option<Vec<String>>,
    /// Name of the machine currently being lowered, set at the same boundaries
    /// as `current_machine_events`. Used by `MachineVariantCtor` and
    /// `MachineFieldAccess` resolution to carry the machine type name.
    current_machine_name: Option<String>,
    /// Ordered state descriptors for the machine currently being lowered.
    /// Each entry is `(state_name, fields)` in declaration order, matching
    /// `HirMachineDecl.states` indices. Used by bare state-name resolution
    /// (`MachineVariantCtor`) and `self.field` resolution (`MachineFieldAccess`).
    ///
    /// `None` outside a machine body. Set alongside `current_machine_events`.
    current_machine_states: Option<Vec<(String, Vec<HirField>)>>,
    current_machine_transition_event: Option<(usize, Vec<HirField>)>,
    /// Source-state index for the transition currently being lowered.
    /// `Some(idx)` inside a transition body; `None` inside entry/exit blocks
    /// (where `self.field` reads are not valid surface syntax today).
    ///
    /// Used by `MachineFieldAccess` to identify which variant's payload fields
    /// are in scope. Set per-transition inside `lower_machine`; restored after
    /// each `lower_machine_expr_filtered` call.
    current_machine_source_state: Option<usize>,
    /// Module-scope registry of tagged-union unit constructors, keyed by the
    /// surface identifier the user writes at the construction site. Covers
    /// three surface forms that share one tagged-union substrate:
    ///   1. Machine states (`TrafficLight::Red`, bare `Red`).
    ///   2. Machine event companions (`TrafficLightEvent::Tick`, bare `Tick`).
    ///   3. User-defined enum unit variants (`Colour::Red`, bare `Red`).
    ///
    /// Built by a pre-pass over `program.items` before any function body is
    /// lowered so declaration order does not constrain resolution.
    ///
    /// Two key shapes are stored for every unit constructor:
    ///   - **Qualified**: `"<TaggedUnionType>::<Variant>"` (always registered).
    ///   - **Bare**: `"<Variant>"`, registered only when the variant name is
    ///     **unambiguous** across all three surface forms in the module.
    ///     Ambiguous bare names are omitted so the lexical/`fn_registry`
    ///     fall-through preserves user-binding precedence.
    ///
    /// Each value is `(tagged_union_typename, variant_idx)`. `variant_idx` is
    /// the declaration-order index among all variants of that type (including
    /// payload-bearing ones, which are not registered here but occupy slots).
    ///
    /// Consumed by `lower_identifier` to produce `HirExprKind::MachineVariantCtor`
    /// instead of an unresolved `BindingRef` when the user names a unit
    /// constructor at module scope (`var light = Red;`, `light.step(Tick);`,
    /// `let next = TrafficLight::Green;`, `let c = Colour::Red;`).
    machine_ctor_registry: HashMap<String, (String, usize)>,
    /// Maps module-level `const` name → pre-allocated `ItemId` + declared type.
    /// Populated in the first pass so const references resolve to a stable id
    /// regardless of source order. See [`ConstEntry`].
    const_registry: HashMap<String, ConstEntry>,
    /// Per-enum variant descriptors keyed by the enum's type name. Populated
    /// between the type-decl second pass and the source-order third pass so
    /// `Expr::Call` (tuple variant ctors like `Shape::Line(5)`) and
    /// `Expr::StructInit` (struct variant ctors like `Shape::Box { w, h }`)
    /// lowering can dispatch on the variant's `HirVariantKind` without
    /// re-walking the parser AST. The vec is in declaration order, so
    /// `machine_ctor_registry`'s `(type_name, variant_idx)` indexes directly
    /// into it.
    enum_variants_by_name: HashMap<String, Vec<HirVariant>>,
    /// Checker-resolved per-arm pattern classifications. Cloned from
    /// `tc_output.pattern_resolutions` at construction. Keyed by the
    /// `SpanKey` of each match arm's pattern span. Consumed by
    /// `Expr::Match` lowering to map arms to their resolved enum variant
    /// (or wildcard) without re-resolving names against the type registry.
    pattern_resolutions: HashMap<SpanKey, hew_types::ArmResolution>,
    /// Compiler-recognised lang-item registry surfaced by the checker.
    ///
    /// HIR f-string lowering looks up the `Display` trait method here
    /// (`LANG_ITEM_DISPLAY_FMT` → method name) instead of hard-coding
    /// `"fmt"`. Without an entry the lowering pass refuses to fabricate
    /// the dispatch — surfacing a fail-closed diagnostic.
    lang_items: hew_types::LangItemRegistry,
    /// Target architecture for compilation. Used by target gates to reject
    /// constructs that would panic at runtime on unsupported targets
    /// (P0.1-P0.4 fail-closed gates per slepp A222).
    target_arch: TargetArch,
    /// W3.042 Stage 2 — when lowering bodies of methods that live inside an
    /// `impl ... for <SelfType> { ... }` (or inherent `impl <SelfType>`) block,
    /// `Self` in any annotated `TypeExpr` position must resolve to the
    /// concrete self type rather than escaping to MIR as a literal
    /// `ResolvedTy::named_user("Self", _)` (which has no entry in the
    /// record-field-order table and fail-closes at MIR boundary).
    ///
    /// Set by `lower_impl_block` before lowering each method, cleared after.
    /// `None` outside an impl-method context — top-level free functions, trait
    /// declarations, and actor/machine method lowerings do not touch this.
    current_impl_self_ty: Option<ResolvedTy>,
    /// Default method bodies harvested from every `Item::Trait` in the root
    /// program. Keyed by trait name; values are the `TraitMethod` entries
    /// that carry a `body`. Populated once before the first lowering pass
    /// so that `lower_impl_block` can lower default methods that are not
    /// overridden in the concrete impl.
    trait_default_methods: HashMap<String, Vec<TraitMethod>>,
    /// Short names of every `#[opaque]` type declaration in the program
    /// (root + imported modules), e.g. `"Value"` for `json.Value`.
    ///
    /// Consulted by [`LowerCtx::lower_type`] to stamp the
    /// `ResolvedTy::Named.is_opaque` discriminator so the actor-state
    /// clone/drop classifier (`hew-mir::state_clone`) can distinguish a real
    /// opaque handle from a user record/enum that merely shares its short
    /// name. Populated by the type-decl pre-passes (root + imported) before
    /// any actor body lowers, so the discriminator is available when actor
    /// state-field types are resolved.
    ///
    /// `non_opaque_type_short_names` carries the complement: short names that
    /// are user records/enums/actors. A bare (unqualified) annotation whose
    /// short name is in BOTH sets refers to the user type (the local
    /// declaration shadows the imported opaque handle); only a qualified
    /// reference (`json.Value`) or a bare name that is exclusively opaque
    /// resolves to the opaque handle. This keeps the discriminator a type
    /// identity fact rather than a short-name heuristic.
    opaque_type_short_names: HashSet<String>,
    non_opaque_type_short_names: HashSet<String>,
}

impl LowerCtx {
    fn new(tc_output: &TypeCheckOutput, mono_cap: usize, target_arch: TargetArch) -> Self {
        let mut type_classes = crate::value_class::TypeClassTable::default();
        // Seed compiler-known M2 substrate types before source-order TypeDecls.
        // This ensures `ValueClass::of_ty` resolves Duplex/Sink/Stream as
        // AffineResource even though they are not user-declared TypeDecl items.
        seed_builtin_type_classes(&mut type_classes);
        Self {
            ids: IdGen::default(),
            scopes: Vec::new(),
            fn_registry: HashMap::new(),
            imported_fn_rewrites: None,
            imported_module_consts: None,
            type_classes,
            impl_close_methods: HashMap::new(),
            diagnostics: Vec::new(),
            fn_sigs: tc_output.fn_sigs.clone(),
            method_call_rewrites: tc_output.method_call_rewrites.clone(),
            numeric_method_lowerings: tc_output.numeric_method_lowerings.clone(),
            actor_method_dispatch: tc_output.actor_method_dispatch.clone(),
            machine_method_dispatch: tc_output.machine_method_dispatch.clone(),
            conn_await_reads: tc_output.conn_await_reads.clone(),
            listener_await_accepts: tc_output.listener_await_accepts.clone(),
            method_call_receiver_kinds: tc_output.method_call_receiver_kinds.clone(),
            dyn_trait_coercions: tc_output.dyn_trait_coercions.clone(),
            dyn_trait_method_calls: tc_output.dyn_trait_method_calls.clone(),
            resolved_calls: tc_output.resolved_calls.clone(),
            expr_types: tc_output.expr_types.clone(),
            resolved_expr_types: tc_output.resolved_expr_types.clone(),
            is_type_patterns: tc_output.is_type_patterns.clone(),
            closure_capture_facts: tc_output.closure_capture_facts.clone(),
            closure_escape_facts: tc_output.closure_escape_facts.clone(),
            generator_yield_tys: Vec::new(),
            scope_depth: 0,
            current_scope_id: ScopeId(0),
            current_return_type: None,
            statement_position: false,
            current_actor_self: None,
            call_type_args: tc_output.call_type_args.clone(),
            lowering_facts: tc_output.lowering_facts.clone(),
            assign_target_kinds: tc_output.assign_target_kinds.clone(),
            assign_target_shapes: tc_output.assign_target_shapes.clone(),
            actor_handler_state_guards: tc_output.actor_handler_state_guards.clone(),
            cycle_capable_actors: tc_output.cycle_capable_actors.clone(),
            actor_protocol_descriptors: tc_output.actor_protocol_descriptors.clone(),
            mono_registry: MonoRegistry::with_cap(mono_cap),
            mono_cap_diag_emitted: false,
            call_site_type_args: HashMap::new(),
            record_registry: HashMap::new(),
            record_init_type_args: tc_output.record_init_type_args.clone(),
            record_layout_registry: RecordLayoutRegistry::with_cap(mono_cap),
            record_layout_cap_diag_emitted: false,
            enum_type_params: HashMap::new(),
            enum_item_ids: HashMap::new(),
            enum_layout_registry: EnumLayoutRegistry::with_cap(mono_cap),
            intrinsic_declarations: tc_output.intrinsic_declarations.clone(),
            supervisor_child_slots_checker: tc_output.supervisor_child_slots.clone(),
            supervisor_child_slots: HashMap::new(),
            regex_literals: Vec::new(),
            regex_literal_index: HashMap::new(),
            current_machine_events: None,
            current_machine_name: None,
            current_machine_states: None,
            current_machine_transition_event: None,
            current_machine_source_state: None,
            machine_ctor_registry: HashMap::new(),
            const_registry: HashMap::new(),
            enum_variants_by_name: HashMap::new(),
            pattern_resolutions: tc_output.pattern_resolutions.clone(),
            lang_items: tc_output.lang_items.clone(),
            target_arch,
            current_impl_self_ty: None,
            trait_default_methods: HashMap::new(),
            opaque_type_short_names: HashSet::new(),
            non_opaque_type_short_names: HashSet::new(),
        }
    }

    fn with_typecheck_facts<T>(
        &mut self,
        tc_output: &TypeCheckOutput,
        f: impl FnOnce(&mut Self) -> T,
    ) -> T {
        let saved = (
            std::mem::replace(
                &mut self.method_call_rewrites,
                tc_output.method_call_rewrites.clone(),
            ),
            std::mem::replace(
                &mut self.numeric_method_lowerings,
                tc_output.numeric_method_lowerings.clone(),
            ),
            std::mem::take(&mut self.actor_method_dispatch),
            std::mem::take(&mut self.machine_method_dispatch),
            std::mem::take(&mut self.method_call_receiver_kinds),
            std::mem::take(&mut self.dyn_trait_coercions),
            std::mem::take(&mut self.dyn_trait_method_calls),
            std::mem::replace(&mut self.resolved_calls, tc_output.resolved_calls.clone()),
            std::mem::replace(&mut self.expr_types, tc_output.expr_types.clone()),
            std::mem::replace(
                &mut self.resolved_expr_types,
                tc_output.resolved_expr_types.clone(),
            ),
        );

        let result = f(self);

        (
            self.method_call_rewrites,
            self.numeric_method_lowerings,
            self.actor_method_dispatch,
            self.machine_method_dispatch,
            self.method_call_receiver_kinds,
            self.dyn_trait_coercions,
            self.dyn_trait_method_calls,
            self.resolved_calls,
            self.expr_types,
            self.resolved_expr_types,
        ) = saved;

        result
    }

    fn with_current_return_type<T>(
        &mut self,
        return_ty: ResolvedTy,
        f: impl FnOnce(&mut Self) -> T,
    ) -> T {
        let previous = self.current_return_type.replace(return_ty);
        let result = f(self);
        self.current_return_type = previous;
        result
    }

    /// W4.047 P1.2 — read the typed checker→HIR handoff map.
    ///
    /// Returns the `ResolvedTy` the checker recorded for `span`, or `None` if
    /// the span is absent (a synthesised/no-span node, or a pre-monomorphi-
    /// zation generic body whose type is a covered inference var and so is
    /// legitimately not in the typed map).
    ///
    /// Phase 1 only consults this through `assert_resolved_ty_totality`; Phase
    /// 2 promotes it to the primary node-type read path. Annotated `dead_code`
    /// because in release builds the only caller (the debug-only totality net)
    /// compiles away.
    #[cfg_attr(not(debug_assertions), allow(dead_code))]
    fn checked_ty(&self, span: &Span) -> Option<&ResolvedTy> {
        self.resolved_expr_types.get(&SpanKey::from(span))
    }

    /// W4.047 P1.2 — the totality assert net (zero behaviour change).
    ///
    /// At a fail-open / boundary-violation lowering site, prove that the typed
    /// `resolved_expr_types` map agrees *exactly* with the live
    /// `expr_types`→`ResolvedTy::from_ty` path the production code still drives
    /// off. The two must be observationally identical at every concrete
    /// accepted span:
    ///
    /// - span present + `from_ty` succeeds → typed map has the identical value,
    /// - span present + `from_ty` fails (covered generic var) → typed map omits
    ///   it and the live `.ok()` is `None`, so both agree on absence,
    /// - span absent → both miss.
    ///
    /// A trip means the typed handoff is missing an entry for an accepted
    /// concrete expr (a real fail-open gap the `.unwrap_or(Unit)` was masking)
    /// or that P1.1's population diverged from the live conversion. Compiled
    /// out of release: the live path is unchanged, so lowering output is
    /// byte-identical.
    #[inline]
    fn assert_resolved_ty_totality(&self, span: &Span) {
        #[cfg(debug_assertions)]
        {
            let key = SpanKey::from(span);
            let live = self
                .expr_types
                .get(&key)
                .and_then(|ty| ResolvedTy::from_ty(ty).ok());
            debug_assert_eq!(
                self.checked_ty(span),
                live.as_ref(),
                "W4.047 totality: typed resolved_expr_types disagrees with the \
                 live expr_types->from_ty path at span {key:?} — the typed \
                 checker->HIR handoff is not total over this accepted span"
            );
        }
        #[cfg(not(debug_assertions))]
        let _ = span;
    }

    fn tag_diagnostics_since(&mut self, start: usize, source_module: &str) {
        debug_assert!(start <= self.diagnostics.len());
        for diagnostic in self.diagnostics.iter_mut().skip(start) {
            if diagnostic.source_module.is_none() {
                diagnostic.source_module = Some(source_module.to_string());
            }
        }
    }

    /// Allocate (or look up an existing) regex literal in the module table.
    ///
    /// Deduplicates by raw pattern string equality. Returns the stable
    /// `literal_id` (0-based index into `HirModule::regex_literals`) for
    /// use in `HirMatchArmPredicate::Regex` and `HirExprKind::RegexLiteralRef`.
    fn alloc_regex_literal(&mut self, pattern: &str, captures: &[(String, u32)]) -> u32 {
        if let Some(&id) = self.regex_literal_index.get(pattern) {
            return id;
        }
        let id = u32::try_from(self.regex_literals.len())
            .expect("regex literal count exceeds u32::MAX — impossible in practice");
        self.regex_literal_index.insert(pattern.to_string(), id);
        self.regex_literals.push(HirRegexLiteral {
            literal_id: id,
            pattern: pattern.to_string(),
            captures: captures.to_vec(),
        });
        id
    }

    /// Try to record a generic-fn callsite in the monomorphisation
    /// registry. Returns silently for non-generic callees, callees not
    /// in `fn_registry` (builtins/runtime symbols/lambda bindings), and
    /// callsites with no `call_type_args` entry — the latter being the
    /// trivially-monomorphic case from the checker's perspective (an
    /// explicit `<T>` instantiation that already resolved to concrete
    /// types and was not recorded per `calls.rs:183` `record_call_type_args`).
    ///
    /// Emits `MonomorphisationCallTypeArgsViolation` when a recorded
    /// entry fails the `ResolvedTy::from_ty` boundary conversion, and
    /// `MonomorphisationCapExceeded` (at most once per invocation) when
    /// the registry cap is hit.
    /// Recursive check: does this `ResolvedTy` contain a `Named` whose
    /// name matches any type parameter declared on any top-level fn in
    /// this module? If so, the value is "still abstract" — the call
    /// site we're looking at is inside a generic body and the type-arg
    /// has not yet been substituted. Such entries must not enter the
    /// monomorphisation registry; G-1.b's body substitution pass will
    /// re-walk these callsites with substituted args and produce real
    /// entries.
    ///
    /// The check is a conservative over-approximation: a user-declared
    /// type with the same name as a type param (e.g. `pub type T { ... }`)
    /// would also be skipped. This is fine — that's not idiomatic Hew,
    /// and the checker uses `Named` for both cases; the only correct
    /// resolution requires bound-symbol metadata the checker side-table
    /// does not currently expose. Skipping is safe at G-1.a (no false
    /// emissions); a real `T`-named user type still produces the entry
    /// at the outer non-generic callsite where `type_args` is `[]`.
    fn contains_abstract_type_param(&self, ty: &ResolvedTy) -> bool {
        match ty {
            ResolvedTy::Named { name, args, .. } => {
                if self.is_type_param_symbol(name) {
                    return true;
                }
                args.iter().any(|a| self.contains_abstract_type_param(a))
            }
            ResolvedTy::Tuple(items) => items.iter().any(|t| self.contains_abstract_type_param(t)),
            ResolvedTy::Array(elem, _) | ResolvedTy::Slice(elem) => {
                self.contains_abstract_type_param(elem)
            }
            ResolvedTy::Function { params, ret } => {
                params.iter().any(|p| self.contains_abstract_type_param(p))
                    || self.contains_abstract_type_param(ret)
            }
            ResolvedTy::Closure {
                params,
                ret,
                captures,
            } => {
                params.iter().any(|p| self.contains_abstract_type_param(p))
                    || self.contains_abstract_type_param(ret)
                    || captures
                        .iter()
                        .any(|c| self.contains_abstract_type_param(c))
            }
            ResolvedTy::Pointer { pointee, .. } | ResolvedTy::Borrow { pointee } => {
                self.contains_abstract_type_param(pointee)
            }
            ResolvedTy::TraitObject { traits } => traits.iter().any(|tb| {
                tb.args.iter().any(|a| self.contains_abstract_type_param(a))
                    || tb
                        .assoc_bindings
                        .iter()
                        .any(|(_, t)| self.contains_abstract_type_param(t))
            }),
            ResolvedTy::Task(inner) => self.contains_abstract_type_param(inner),
            // A structural type parameter is abstract by construction.
            ResolvedTy::TypeParam { .. } => true,
            _ => false,
        }
    }

    /// Does `name` match any type-parameter declared on any top-level
    /// fn in `fn_registry`? Used to filter "still-abstract" type args
    /// from the monomorphisation registry. See
    /// `contains_abstract_type_param` for the rationale.
    fn is_type_param_symbol(&self, name: &str) -> bool {
        self.fn_registry
            .values()
            .any(|entry| entry.type_params.iter().any(|p| p == name))
    }

    fn imported_rewrite_symbol(&self, name: &str) -> Option<&str> {
        self.imported_fn_rewrites
            .as_ref()
            .and_then(|rewrites| rewrites.get(name).map(String::as_str))
    }

    fn record_var_self_direct_monomorphisation(
        &mut self,
        callee: &str,
        receiver_ty: &ResolvedTy,
        call_span: &std::ops::Range<usize>,
        call_site: SiteId,
    ) {
        let Some((origin, type_param_count, linkage)) = self
            .fn_registry
            .get(callee)
            .map(|entry| (entry.id, entry.type_params.len(), entry.linkage))
        else {
            return;
        };
        if linkage.is_some() || type_param_count == 0 {
            return;
        }
        let ResolvedTy::Named {
            args: receiver_args,
            ..
        } = receiver_ty
        else {
            return;
        };
        let mut type_args = receiver_args.clone();
        let key = SpanKey::from(call_span);
        if let Some(raw_call_args) = self.call_type_args.get(&key).cloned() {
            let mut call_args = Vec::with_capacity(raw_call_args.len());
            for ty in &raw_call_args {
                match ResolvedTy::from_ty(ty) {
                    Ok(resolved) => call_args.push(resolved),
                    Err(err) => {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::MonomorphisationCallTypeArgsViolation {
                                callee: callee.to_string(),
                                reason: err.to_string(),
                            },
                            call_span.clone(),
                            "checker-authoritative method call_type_args entry failed boundary conversion",
                        ));
                        return;
                    }
                }
            }
            if call_args.len() == type_param_count {
                type_args = call_args;
            } else {
                type_args.extend(call_args);
            }
        }
        if type_args.len() != type_param_count {
            return;
        }
        self.call_site_type_args
            .entry(call_site)
            .or_insert_with(|| type_args.clone());
        if type_args
            .iter()
            .any(|t| self.contains_abstract_type_param(t))
        {
            return;
        }
        let mono_key = MonoKey {
            origin,
            origin_name: callee.to_string(),
            type_args,
        };
        match self.mono_registry.insert(mono_key) {
            Ok(_) => {}
            Err(()) => {
                if !self.mono_cap_diag_emitted {
                    self.mono_cap_diag_emitted = true;
                    let cap = self.mono_registry.cap();
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::MonomorphisationCapExceeded { cap },
                        call_span.clone(),
                        "too many distinct generic-function instantiations; the \
                         compiler refuses to monomorphise beyond the configured \
                         cap (suspect polymorphic recursion or runaway inference)",
                    ));
                }
            }
        }
    }

    fn record_monomorphisation(
        &mut self,
        callee_expr: &hew_parser::ast::Expr,
        call_span: &std::ops::Range<usize>,
        call_site: SiteId,
    ) {
        let Expr::Identifier(name) = callee_expr else {
            // Only direct-name callees are candidates for top-level-fn
            // monomorphisation. Method calls, indirect calls through
            // bindings, and complex callee expressions are out of scope
            // for G-1.a.
            return;
        };
        let registry_name = if self.lookup(name).is_none() {
            self.imported_rewrite_symbol(name).unwrap_or(name)
        } else {
            name
        };
        let Some(entry) = self.fn_registry.get(registry_name) else {
            // Callee is not a top-level user fn — skip (builtin,
            // runtime-symbol, or unresolved). Filtering on `fn_registry`
            // membership inherently excludes runtime-symbol callees
            // since they have no AST `fn` item and therefore no
            // `fn_registry` insertion (`lower_program` first pass at
            // line 79).
            return;
        };
        if entry.linkage.is_some() {
            // Catalog-seeded stdlib functions are already monomorphic HIR
            // targets. They never produce user-function specialisations.
            return;
        }
        if entry.type_params.is_empty() {
            // Non-generic callee — nothing to monomorphise.
            return;
        }
        let origin = entry.id;
        let origin_name = registry_name.to_string();
        let key = SpanKey::from(call_span);
        let Some(type_args_raw) = self.call_type_args.get(&key).cloned() else {
            // Generic callee with no recorded type args at this site.
            // The checker records every callsite whose freshened type
            // args were resolved to fully concrete `Ty`s
            // (`calls.rs:78`); the only ways to miss a site are
            // (a) an explicit `<T>` syntax that doesn't re-record
            //     (`calls.rs:183`'s `record_call_type_args` guard), or
            // (b) the call failed to type-check.
            // In (a) the call is trivially monomorphic at the source
            // surface but downstream stages still need a registry
            // entry — that wiring lands in G-1.b once the explicit
            // type-args path is examined end-to-end.
            // (Per plan G-1.a: do not re-infer; treat as out of scope.)
            return;
        };
        let mut type_args: Vec<ResolvedTy> = Vec::with_capacity(type_args_raw.len());
        for ty in &type_args_raw {
            match ResolvedTy::from_ty(ty) {
                Ok(resolved) => type_args.push(resolved),
                Err(err) => {
                    // Fail-closed: poisoned side-table for this call.
                    // Emit a diagnostic; skip the registry entry so the
                    // downstream MIR/LLVM emit doesn't reach an
                    // unresolved type. (LESSONS: checker-output-boundary P0)
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::MonomorphisationCallTypeArgsViolation {
                            callee: origin_name.clone(),
                            reason: err.to_string(),
                        },
                        call_span.clone(),
                        "checker-authoritative call_type_args entry failed boundary conversion",
                    ));
                    return;
                }
            }
        }
        // Record the per-call-site type arguments unconditionally —
        // including "still-abstract" entries where the args reference
        // the enclosing fn's type-parameter symbols. MIR lowering of a
        // specialised body substitutes those symbols via its
        // per-monomorphisation substitution map; the registry's
        // closure-under-substitution pass uses the same data to
        // discover inner monomorphisations.
        self.call_site_type_args
            .insert(call_site, type_args.clone());
        // Skip "still-abstract" entries from the registry — call sites
        // inside a generic body where the type arg is `T` (the
        // surrounding fn's own type-param symbol) rather than a
        // concrete substitution. These appear with
        // `ResolvedTy::Named { name: "T", args: [] }` because the
        // checker treats unbound type params as opaque named types for
        // body-checking purposes. MIR's monomorphisation pass re-walks
        // these sites with concrete args via substitution.
        if type_args
            .iter()
            .any(|t| self.contains_abstract_type_param(t))
        {
            return;
        }
        let mono_key = MonoKey {
            origin,
            origin_name: origin_name.clone(),
            type_args,
        };
        match self.mono_registry.insert(mono_key) {
            Ok(_) => {}
            Err(()) => {
                if !self.mono_cap_diag_emitted {
                    self.mono_cap_diag_emitted = true;
                    let cap = self.mono_registry.cap();
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::MonomorphisationCapExceeded { cap },
                        call_span.clone(),
                        "too many distinct generic-function instantiations; the \
                         compiler refuses to monomorphise beyond the configured \
                         cap (suspect polymorphic recursion or runaway inference)",
                    ));
                }
            }
        }
    }

    /// Try to record a generic record-init site in the record-layout
    /// registry. Mirrors `record_monomorphisation` for the
    /// record-type surface.
    ///
    /// Skips silently when:
    /// - the record is not in `record_registry` (builtin Vec/Option/
    ///   Result/HashMap/Range/channel-handle types are never registered
    ///   because they have no `Item::TypeDecl`/`Item::Record` AST node),
    /// - the record has empty `type_params` (monomorphic record — no
    ///   per-instantiation layout needed; the bare-name layout in MIR
    ///   suffices),
    /// - no `record_init_type_args` entry exists for the site (the
    ///   checker filters out sites whose args still contain inference
    ///   vars; a missing entry means the init is trivially monomorphic
    ///   at the checker's seam).
    ///
    /// Emits `RecordLayoutTypeArgsViolation` when a recorded entry
    /// fails the `ResolvedTy::from_ty` boundary conversion;
    /// `RecursiveGenericTypeUnsupported` when substituted fields name
    /// the same origin record with different concrete args;
    /// `RecordLayoutCapExceeded` (at most once per invocation) when the
    /// registry cap is hit.
    #[allow(
        clippy::too_many_lines,
        reason = "single fail-closed validation pipeline (side-table read + boundary conversion + arity + abstract-skip + recursive-self + cap) kept in one place for ordering clarity"
    )]
    fn record_record_layout(
        &mut self,
        record_name: &str,
        init_span: &std::ops::Range<usize>,
    ) -> Option<Vec<ResolvedTy>> {
        let Some(entry) = self.record_registry.get(record_name) else {
            // Builtin or unresolved record — not a user-declared
            // generic type, so it has no record-layout registry entry.
            return None;
        };
        if entry.type_params.is_empty() {
            // Monomorphic record — bare-name layout (handled by MIR's
            // existing record-decl emission) is sufficient.
            return None;
        }
        let origin = entry.id;
        let origin_name = record_name.to_string();
        let type_params = entry.type_params.clone();
        let source_fields = entry.fields.clone();

        let key = SpanKey::from(init_span);
        let Some(type_args_raw) = self.record_init_type_args.get(&key).cloned() else {
            // No recorded type args at this init site.  Two legitimate
            // causes: (1) the site failed type-checking and was pruned
            // by `validate_record_init_type_args_output_contract` —
            // `expr_types` will also be missing the span, so a checker
            // error already owns the failure; (2) an explicit type-arg
            // path in the checker did not call
            // `record_concrete_record_init_type_args` — a missed
            // re-record that would silently produce `Named{args:[]}`.
            //
            // Fail-closed: if `expr_types` still carries this span the
            // checker accepted the expression but never wrote the type
            // args.  Surface `RecordLayoutMissing` so the downstream
            // shape is not silently wrong.
            if self.expr_types.contains_key(&key) {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::RecordLayoutMissing {
                        record: origin_name.clone(),
                    },
                    init_span.clone(),
                    "generic record init accepted by the checker but \
                     `record_init_type_args` has no entry for this site; \
                     downstream MIR would see an under-instantiated \
                     Named{args:[]}",
                ));
            }
            return None;
        };

        // Boundary conversion: any leaked inference var, error, or
        // unmaterialised literal is fail-closed per checker-authority.
        let mut type_args: Vec<ResolvedTy> = Vec::with_capacity(type_args_raw.len());
        for ty in &type_args_raw {
            match ResolvedTy::from_ty(ty) {
                Ok(resolved) => type_args.push(resolved),
                Err(err) => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::RecordLayoutTypeArgsViolation {
                            record: origin_name.clone(),
                            reason: err.to_string(),
                        },
                        init_span.clone(),
                        "checker-authoritative record_init_type_args entry failed boundary conversion",
                    ));
                    return None;
                }
            }
        }

        // Arity guard: the checker enforces matching arity, but be
        // defensive — substitution panics on a mismatch.
        if type_args.len() != type_params.len() {
            return None;
        }

        // Fail-closed: do NOT *register* an abstract origin-site layout, but DO
        // return the (abstract) type-args so the `StructInit` node's `expr.ty`
        // keeps `Box<T>`. Inside a generic fn body (`Box { value: x }` in
        // `make<T>`) the side-table carries the enclosing fn's `T`, not a
        // concrete arg; registering it would mangle `Box$$T` with a `T`-typed
        // field that leaks to the MIR boundary. The concrete `Box$$i64` layout
        // is discovered post-function-mono by `layout_mono` on the substituted
        // body. The abstract args must still ride on `expr.ty` so MIR's
        // monomorph lowering (`subst_ty` + `mangle`, hew-mir/src/lower.rs:6634)
        // recovers `Box<i64>` → `Box$$i64`. Never fires at a concrete site.
        if type_args
            .iter()
            .any(|t| self.contains_abstract_type_param(t))
        {
            return Some(type_args);
        }

        // Substitute the type-params with the concrete args to produce
        // this layout's field shape.
        let substituted_fields: Vec<(String, ResolvedTy)> = source_fields
            .iter()
            .map(|(fname, fty)| {
                (
                    fname.clone(),
                    substitute_type_params(fty, &type_params, &type_args),
                )
            })
            .collect();

        // Recursive polymorphic-self detection: a substituted field
        // type that names `origin_name` with *different* concrete args
        // than `type_args` is unbounded (each layer demands another
        // distinct layout). Same-arg self-reference is fine — that's
        // an ordinary recursive shape and converges to one layout.
        for (_, fty) in &substituted_fields {
            if contains_recursive_polymorphic_self(fty, &origin_name, &type_args) {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::RecursiveGenericTypeUnsupported {
                        name: origin_name.clone(),
                    },
                    init_span.clone(),
                    "recursive generic type definition: a field substitutes to \
                     a reference to the same record with different concrete \
                     type arguments, which would force unbounded layout \
                     expansion (deferred to v0.6)",
                ));
                return None;
            }
        }

        let returned_type_args = type_args.clone();
        let key = RecordMonoKey {
            origin,
            origin_name,
            type_args,
        };
        if self
            .record_layout_registry
            .insert(key, substituted_fields, init_span.clone())
            .is_err()
        {
            if !self.record_layout_cap_diag_emitted {
                self.record_layout_cap_diag_emitted = true;
                let cap = self.record_layout_registry.cap();
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::RecordLayoutCapExceeded { cap },
                    init_span.clone(),
                    "too many distinct generic-record instantiations; the \
                     compiler refuses to monomorphise beyond the configured \
                     cap (suspect polymorphic recursion or runaway inference)",
                ));
            }
            return None;
        }
        Some(returned_type_args)
    }
}

/// Collect the names of private helper functions that are referenced by direct
/// `Expr::Call { function: Expr::Identifier(name) }` within `body` and whose
/// names appear in `candidate_fns`. Method-call syntax (`foo.bar()`) is not
/// tracked — only bare identifier callees are considered. Returns a sorted,
/// deduplicated list of matching names.
fn collect_bare_fn_call_refs(body: &Block, candidate_fns: &HashSet<String>) -> Vec<String> {
    let mut found = Vec::new();
    scan_block_for_private_refs(body, Some(candidate_fns), &mut found);
    found.sort_unstable();
    found.dedup();
    found
}

/// Collect every bare-identifier call target (`foo(...)` where `foo` is an
/// identifier) reachable in `body`, regardless of any candidate filter.
///
/// Used to decide whether an imported impl-method body is safe to lower: a body
/// that calls a bare name resolvable in neither `fn_registry`, the same-module
/// rewrite map, nor the runtime/stdlib catalog cannot be lowered cross-module
/// (e.g. `std::channel`'s `recv` calls the codegen-intercepted `hew_channel_recv`,
/// which is not extern-declared in the module and never reaches the imported
/// `fn_registry`). Such methods are skipped, matching the prior behaviour where
/// every imported impl method was dropped.
fn collect_all_bare_call_names(body: &Block) -> Vec<String> {
    let mut found = Vec::new();
    scan_block_for_private_refs(body, None, &mut found);
    found.sort_unstable();
    found.dedup();
    found
}

/// Iterate the parameter and return `TypeExpr`s of an impl-block method.
fn method_signature_type_exprs(method: &FnDecl) -> impl Iterator<Item = &TypeExpr> {
    method
        .params
        .iter()
        .map(|param| &param.ty.0)
        .chain(method.return_type.as_ref().map(|rt| &rt.0))
}

/// Whether a `TypeExpr` appearing in an imported impl-method signature is safe
/// to lower cross-module: it must reference only primitives/builtins, the impl's
/// own self type, or an imported public type whose backing declaration the
/// imported-module pre-pass already registered at the MIR boundary. A user type
/// or a user trait used as a generic argument is rejected, because lowering a
/// method that names one trips `unknown type` / D10 at MIR time.
///
/// `is_known_registered_type` answers whether a type name resolves to a
/// declaration the lowering context has registered (e.g. dotted `fs.IoError` or
/// bare same-module records returned by stdlib receiver methods). This is the
/// checker/lowering authority — the gate consults it rather than re-inferring
/// safety from syntax alone.
///
/// Conservative by design: it admits the fluent-builder shape (scalar params +
/// opaque self return) and ADT-returning methods (`Result<_, fs.IoError>`)
/// while excluding signatures naming a type the importer cannot resolve.
/// Composite forms recurse into their components.
fn imported_impl_signature_type_is_safe(
    ty: &TypeExpr,
    self_type_name: &str,
    is_known_registered_type: &impl Fn(&str) -> bool,
) -> bool {
    match ty {
        TypeExpr::Named { name, type_args } => {
            // A user-type reference is resolvable only when its backing
            // declaration was registered at the MIR boundary by the
            // imported-module pre-pass. Otherwise it is rejected.
            let known_registered_type = is_known_registered_type(name);
            if name.contains('.') || known_registered_type {
                if !known_registered_type {
                    return false;
                }
                return type_args.as_ref().is_none_or(|args| {
                    args.iter().all(|arg| {
                        imported_impl_signature_type_is_safe(
                            &arg.0,
                            self_type_name,
                            is_known_registered_type,
                        )
                    })
                });
            }
            // The impl's own self type is the opaque handle (already resolvable);
            // scalar primitives (`string`, `i64`, `bool`, …) and compound
            // builtins (`Vec`, `Option`, `LocalPid`, …) are resolvable by name.
            let is_primitive = hew_types::ty::PRIMITIVE_ALIASES
                .iter()
                .any(|(canonical, aliases)| *canonical == name || aliases.contains(&name.as_str()));
            let head_ok = name == self_type_name
                || is_primitive
                || hew_types::lookup_builtin_type(name).is_some();
            if !head_ok {
                return false;
            }
            type_args.as_ref().is_none_or(|args| {
                args.iter().all(|arg| {
                    imported_impl_signature_type_is_safe(
                        &arg.0,
                        self_type_name,
                        is_known_registered_type,
                    )
                })
            })
        }
        TypeExpr::Option(inner) | TypeExpr::Slice(inner) | TypeExpr::Borrow(inner) => {
            imported_impl_signature_type_is_safe(&inner.0, self_type_name, is_known_registered_type)
        }
        TypeExpr::Array { element, .. } => imported_impl_signature_type_is_safe(
            &element.0,
            self_type_name,
            is_known_registered_type,
        ),
        TypeExpr::Pointer { pointee, .. } => imported_impl_signature_type_is_safe(
            &pointee.0,
            self_type_name,
            is_known_registered_type,
        ),
        TypeExpr::Result { ok, err } => {
            imported_impl_signature_type_is_safe(&ok.0, self_type_name, is_known_registered_type)
                && imported_impl_signature_type_is_safe(
                    &err.0,
                    self_type_name,
                    is_known_registered_type,
                )
        }
        TypeExpr::Tuple(elems) => elems.iter().all(|elem| {
            imported_impl_signature_type_is_safe(&elem.0, self_type_name, is_known_registered_type)
        }),
        // Function-typed params, trait objects, and any other composite carry
        // user-type identity that the importer cannot resolve — reject.
        _ => false,
    }
}

fn collect_imported_private_fn_closure(
    module: &hew_parser::module::Module,
    private_fns: &HashSet<String>,
) -> HashSet<String> {
    let private_fn_bodies: HashMap<String, &Block> = module
        .items
        .iter()
        .filter_map(|(item, _)| {
            if let Item::Function(func) = item {
                if !func.visibility.is_pub() {
                    return Some((func.name.clone(), &func.body));
                }
            }
            None
        })
        .collect();
    let mut reachable = HashSet::new();
    let mut worklist = Vec::new();
    let seed_from = |body: &Block, reachable: &mut HashSet<String>, worklist: &mut Vec<String>| {
        for helper in collect_bare_fn_call_refs(body, private_fns) {
            if reachable.insert(helper.clone()) {
                worklist.push(helper);
            }
        }
    };
    for (item, _) in &module.items {
        match item {
            // Pub free fns are importer-callable entry points.
            Item::Function(func) if func.visibility.is_pub() => {
                seed_from(&func.body, &mut reachable, &mut worklist);
            }
            // Impl-block methods are importer-callable entry points too (they
            // are lowered cross-module by `lower_impl_block`). A private helper
            // reachable only through a method body — e.g. `net.set_read_timeout`
            // calling `net_result_from_status` — must still be pulled into the
            // closure so the method's body resolves it. Without this seed the
            // method is skipped as body-unresolvable even though the helper
            // exists in the same module.
            Item::Impl(impl_decl) => {
                for method in &impl_decl.methods {
                    seed_from(&method.body, &mut reachable, &mut worklist);
                }
            }
            _ => {}
        }
    }
    while let Some(helper) = worklist.pop() {
        if let Some(body) = private_fn_bodies.get(&helper) {
            for next in collect_bare_fn_call_refs(body, private_fns) {
                if reachable.insert(next.clone()) {
                    worklist.push(next);
                }
            }
        }
    }
    reachable
}

fn scan_block_for_private_refs(block: &Block, pf: Option<&HashSet<String>>, out: &mut Vec<String>) {
    for (stmt, _) in &block.stmts {
        scan_stmt_for_private_refs(stmt, pf, out);
    }
    if let Some(e) = &block.trailing_expr {
        scan_expr_for_private_refs(&e.0, pf, out);
    }
}

fn scan_stmt_for_private_refs(stmt: &Stmt, pf: Option<&HashSet<String>>, out: &mut Vec<String>) {
    match stmt {
        Stmt::Let { value: Some(v), .. } | Stmt::Var { value: Some(v), .. } => {
            scan_expr_for_private_refs(&v.0, pf, out);
        }
        Stmt::Assign { target, value, .. } => {
            scan_expr_for_private_refs(&target.0, pf, out);
            scan_expr_for_private_refs(&value.0, pf, out);
        }
        Stmt::If {
            condition,
            then_block,
            else_block,
            ..
        } => {
            scan_expr_for_private_refs(&condition.0, pf, out);
            scan_block_for_private_refs(then_block, pf, out);
            if let Some(eb) = else_block {
                if let Some(b) = &eb.block {
                    scan_block_for_private_refs(b, pf, out);
                }
                if let Some(s) = &eb.if_stmt {
                    scan_stmt_for_private_refs(&s.0, pf, out);
                }
            }
        }
        Stmt::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_private_refs(&expr.0, pf, out);
            scan_block_for_private_refs(body, pf, out);
            if let Some(b) = else_body {
                scan_block_for_private_refs(b, pf, out);
            }
        }
        Stmt::Match { scrutinee, arms } => {
            scan_expr_for_private_refs(&scrutinee.0, pf, out);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_private_refs(&g.0, pf, out);
                }
                scan_expr_for_private_refs(&arm.body.0, pf, out);
            }
        }
        Stmt::Loop { body, .. } => scan_block_for_private_refs(body, pf, out),
        Stmt::For { iterable, body, .. } => {
            scan_expr_for_private_refs(&iterable.0, pf, out);
            scan_block_for_private_refs(body, pf, out);
        }
        Stmt::While {
            condition, body, ..
        } => {
            scan_expr_for_private_refs(&condition.0, pf, out);
            scan_block_for_private_refs(body, pf, out);
        }
        Stmt::WhileLet { expr, body, .. } => {
            scan_expr_for_private_refs(&expr.0, pf, out);
            scan_block_for_private_refs(body, pf, out);
        }
        Stmt::Break { value: Some(v), .. } => scan_expr_for_private_refs(&v.0, pf, out),
        Stmt::Return(Some(e)) | Stmt::Expression(e) => {
            scan_expr_for_private_refs(&e.0, pf, out);
        }
        Stmt::Defer(e) => scan_expr_for_private_refs(&e.0, pf, out),
        _ => {}
    }
}

#[allow(
    clippy::too_many_lines,
    reason = "exhaustive single-pass AST walk; splitting into sub-functions would obscure the traversal structure without adding clarity"
)]
fn scan_expr_for_private_refs(expr: &Expr, pf: Option<&HashSet<String>>, out: &mut Vec<String>) {
    match expr {
        Expr::Call { function, args, .. } => {
            if let Expr::Identifier(name) = &function.0 {
                // `pf == None` collects every bare call name; `Some(set)` records
                // only names present in `set` (the same-module private-fn filter).
                if pf.is_none_or(|set| set.contains(name)) {
                    out.push(name.clone());
                }
            }
            scan_expr_for_private_refs(&function.0, pf, out);
            for arg in args {
                scan_expr_for_private_refs(&arg.expr().0, pf, out);
            }
        }
        Expr::Binary { left, right, .. } => {
            scan_expr_for_private_refs(&left.0, pf, out);
            scan_expr_for_private_refs(&right.0, pf, out);
        }
        Expr::Unary { operand, .. } => scan_expr_for_private_refs(&operand.0, pf, out),
        Expr::Tuple(es) | Expr::Array(es) | Expr::Join(es) => {
            for e in es {
                scan_expr_for_private_refs(&e.0, pf, out);
            }
        }
        Expr::ArrayRepeat { value, count } => {
            scan_expr_for_private_refs(&value.0, pf, out);
            scan_expr_for_private_refs(&count.0, pf, out);
        }
        Expr::Block(b)
        | Expr::Scope { body: b }
        | Expr::ForkBlock { body: b }
        | Expr::GenBlock { body: b } => {
            scan_block_for_private_refs(b, pf, out);
        }
        Expr::If {
            condition,
            then_block,
            else_block,
            ..
        } => {
            scan_expr_for_private_refs(&condition.0, pf, out);
            scan_expr_for_private_refs(&then_block.0, pf, out);
            if let Some(e) = else_block {
                scan_expr_for_private_refs(&e.0, pf, out);
            }
        }
        Expr::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_private_refs(&expr.0, pf, out);
            scan_block_for_private_refs(body, pf, out);
            if let Some(b) = else_body {
                scan_block_for_private_refs(b, pf, out);
            }
        }
        Expr::Match { scrutinee, arms } => {
            scan_expr_for_private_refs(&scrutinee.0, pf, out);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_private_refs(&g.0, pf, out);
                }
                scan_expr_for_private_refs(&arm.body.0, pf, out);
            }
        }
        Expr::Lambda { body, .. } | Expr::SpawnLambdaActor { body, .. } => {
            scan_expr_for_private_refs(&body.0, pf, out);
        }
        Expr::Spawn { target, args, .. } => {
            scan_expr_for_private_refs(&target.0, pf, out);
            for (_, v) in args {
                scan_expr_for_private_refs(&v.0, pf, out);
            }
        }
        Expr::ScopeDeadline { duration, body } => {
            scan_expr_for_private_refs(&duration.0, pf, out);
            scan_block_for_private_refs(body, pf, out);
        }
        Expr::ForkChild { expr, .. } | Expr::Cast { expr, .. } => {
            scan_expr_for_private_refs(&expr.0, pf, out);
        }
        Expr::MethodCall { receiver, args, .. } => {
            scan_expr_for_private_refs(&receiver.0, pf, out);
            for arg in args {
                scan_expr_for_private_refs(&arg.expr().0, pf, out);
            }
        }
        Expr::StructInit { fields, base, .. } => {
            for (_, v) in fields {
                scan_expr_for_private_refs(&v.0, pf, out);
            }
            if let Some(b) = base {
                scan_expr_for_private_refs(&b.0, pf, out);
            }
        }
        Expr::MapLiteral { entries } => {
            for (k, v) in entries {
                scan_expr_for_private_refs(&k.0, pf, out);
                scan_expr_for_private_refs(&v.0, pf, out);
            }
        }
        Expr::InterpolatedString(parts) => {
            for part in parts {
                if let hew_parser::ast::StringPart::Expr(e) = part {
                    scan_expr_for_private_refs(&e.0, pf, out);
                }
            }
        }
        Expr::Select { arms, timeout } => {
            for arm in arms {
                scan_expr_for_private_refs(&arm.source.0, pf, out);
                scan_expr_for_private_refs(&arm.body.0, pf, out);
            }
            if let Some(t) = timeout {
                scan_expr_for_private_refs(&t.duration.0, pf, out);
                scan_expr_for_private_refs(&t.body.0, pf, out);
            }
        }
        Expr::Timeout { expr, duration } => {
            scan_expr_for_private_refs(&expr.0, pf, out);
            scan_expr_for_private_refs(&duration.0, pf, out);
        }
        Expr::UnsafeBlock(b) => scan_block_for_private_refs(b, pf, out),
        Expr::FieldAccess { object, .. } | Expr::PostfixTry(object) | Expr::Await(object) => {
            scan_expr_for_private_refs(&object.0, pf, out);
        }
        Expr::Index { object, index } => {
            scan_expr_for_private_refs(&object.0, pf, out);
            scan_expr_for_private_refs(&index.0, pf, out);
        }
        Expr::Is { lhs, rhs } => {
            scan_expr_for_private_refs(&lhs.0, pf, out);
            scan_expr_for_private_refs(&rhs.0, pf, out);
        }
        Expr::Range { start, end, .. } => {
            if let Some(s) = start {
                scan_expr_for_private_refs(&s.0, pf, out);
            }
            if let Some(e) = end {
                scan_expr_for_private_refs(&e.0, pf, out);
            }
        }
        Expr::Yield(Some(e)) => scan_expr_for_private_refs(&e.0, pf, out),
        Expr::MachineEmit { fields, .. } => {
            for (_, v) in fields {
                scan_expr_for_private_refs(&v.0, pf, out);
            }
        }
        _ => {}
    }
}

/// V0b-admissible shapes. Returns `None` when the impl is admissible (no
/// where-clause, or a where-clause whose predicates are all `where T: Bound(s)`
/// on the impl's own outer type parameters) and `Some(shape)` describing the
/// offending predicate otherwise. Multi-bound predicates (`where T: A + B`) are
/// admitted; only predicates on parameterised types and non-type-param names
/// remain fail-closed. The bound itself is consumed by the checker
/// (`enter_impl_scope` / `register_impl_method` already harvest
/// `decl.where_clause`); the HIR carries no extra metadata beyond the existing
/// `type_params` list because trait bounds have no runtime artefact.
fn classify_unsupported_where_clause(decl: &hew_parser::ast::ImplDecl) -> Option<String> {
    let where_clause = decl.where_clause.as_ref()?;
    let type_param_names: Vec<&str> = decl
        .type_params
        .as_ref()
        .map(|ps| ps.iter().map(|p| p.name.as_str()).collect())
        .unwrap_or_default();
    for predicate in &where_clause.predicates {
        let TypeExpr::Named {
            name: pred_ty_name,
            type_args,
        } = &predicate.ty.0
        else {
            return Some("where-clause predicate on non-named type".to_string());
        };
        if type_args.is_some() {
            return Some(format!(
                "where-clause predicate on parameterised type `{pred_ty_name}<...>`"
            ));
        }
        if !type_param_names.contains(&pred_ty_name.as_str()) {
            return Some(format!(
                "where-clause predicate on non-type-param `{pred_ty_name}`"
            ));
        }
    }
    None
}

impl LowerCtx {
    fn seed_stdlib_fn_registry(&mut self) {
        for (index, builtin) in stdlib_catalog::entries().iter().enumerate() {
            // W4.001 Stage C0b: `LayoutDescriptorSymbol` rows declare
            // `#[no_mangle] pub static` descriptors in `hew-runtime/src/
            // layout_intrinsics.rs`, not callable functions. Skip them
            // here so a user-written `hew_layout_key_i32()` is rejected at
            // HIR resolution (no fn_registry entry) rather than silently
            // resolving and disappearing at MIR (where the descriptor
            // symbol is correctly absent from `module_fn_names`). The
            // catalog rows themselves stay intact for ABI enumeration +
            // `stdlib_catalog_layout_descriptor_coverage`.
            if matches!(
                builtin.linkage,
                stdlib_catalog::BuiltinLinkage::LayoutDescriptorSymbol { .. }
            ) {
                continue;
            }
            // Keep catalog IDs out of the source-item sequence so existing HIR
            // item IDs remain stable while builtin callees still carry Item refs.
            let index = u32::try_from(index).expect("stdlib catalog fits in u32");
            let id = ItemId(u32::MAX - index);
            let param_tys = builtin.params.iter().map(|ty| ty.to_resolved()).collect();
            let return_ty = builtin.return_ty.to_resolved();
            let entry = FnEntry {
                id,
                return_ty,
                param_tys,
                linkage: Some(builtin.linkage),
                type_params: Vec::new(),
            };
            self.fn_registry
                .insert(builtin.name.to_string(), entry.clone());
            if let Some(symbol) = builtin.linkage.runtime_symbol() {
                self.fn_registry.insert(symbol.to_string(), entry);
            }
        }
        // Checker-registered runtime-builtin functions that have no stdlib_catalog
        // entry and no AST `fn` item.  The HIR verifier rejects `Unresolved`
        // callee refs, so these builtins need a synthetic `Item(id)` in
        // `fn_registry` for `lower_identifier` to resolve.  IDs live in the
        // `u32::MAX / 2` range — below the stdlib IDs (`u32::MAX - N`) and
        // above the source-item sequence (which starts from 0).
        //
        // MIR: the callee `BindingRef { name: "supervisor_stop", resolved: Item(_) }`
        // routes through `user_name_to_c_symbol("supervisor_stop")` →
        // `lower_runtime_call("hew_supervisor_stop", …)` before the Item-resolved
        // fail-closed arm at `lower.rs:2774` is reached.
        //
        // WHEN obsolete: when HIR gains `ResolvedRef::Builtin { c_symbol }` and the
        // verifier exempts it from the Unresolved check, at which point this seeding
        // and `user_name_to_c_symbol` become the bridge between the two.
        // WHAT: add `ResolvedRef::Builtin { c_symbol: String }` to `hew-hir`;
        // populate in `lower_identifier`; match in MIR.
        // `supervisor_stop(sup: LocalPid<S>) -> ()`.  The param type is a
        // `LocalPid<S>` (named "LocalPid" in resolved form), which is what
        // the checker registers.  The exact inner type does not matter here
        // because MIR lowering consults `user_name_to_c_symbol` on the
        // callee name and passes the sup place opaquely.
        self.fn_registry.insert(
            "supervisor_stop".to_string(),
            FnEntry {
                id: ItemId(u32::MAX / 2),
                return_ty: ResolvedTy::Unit,
                param_tys: vec![ResolvedTy::Named {
                    name: hew_types::BuiltinType::LocalPid
                        .canonical_name()
                        .to_string(),
                    args: vec![ResolvedTy::Unit],
                    builtin: Some(hew_types::BuiltinType::LocalPid),
                    is_opaque: false,
                }],
                linkage: None,
                type_params: Vec::new(),
            },
        );
        // Actor `link(target)` / `monitor(target)` builtins.  The checker
        // (`Checker::register_builtins`) registers both as **1-arg**
        // `LocalPid<T>` — the linking/monitoring subject is the implicit
        // calling actor (`self`), matching Erlang/OTP `link(Pid)` /
        // `monitor(process, Pid)`.  They have no AST `fn` item, so — like
        // `supervisor_stop` above — they need a synthetic `Item(id)` here for
        // `lower_identifier` to resolve (the HIR verifier rejects `Unresolved`
        // callees).  MIR routes `BindingRef { name: "link"|"monitor",
        // resolved: Item(_) }` through `user_name_to_c_symbol` →
        // `hew_actor_link` / `hew_actor_monitor`, synthesizing
        // `hew_actor_self()` as ABI arg0 and the user target as arg1.  The
        // exact inner `LocalPid` arg matters only for arity; MIR passes the
        // target place opaquely.
        for (name, id) in [
            ("link", SYNTHETIC_LINK_ITEM),
            ("monitor", SYNTHETIC_MONITOR_ITEM),
        ] {
            self.fn_registry.insert(
                name.to_string(),
                FnEntry {
                    id,
                    return_ty: ResolvedTy::Unit,
                    param_tys: vec![ResolvedTy::Named {
                        name: hew_types::BuiltinType::LocalPid
                            .canonical_name()
                            .to_string(),
                        args: vec![ResolvedTy::Unit],
                        builtin: Some(hew_types::BuiltinType::LocalPid),
                        is_opaque: false,
                    }],
                    linkage: None,
                    type_params: Vec::new(),
                },
            );
        }
        // `duplex_pair<S, R>(capacity: i64) -> (Duplex<S, R>, Duplex<R, S>)`.
        // The checker (`Checker::register_builtins`) registers it as a builtin
        // with no AST `fn` item, so — like `link`/`monitor`/`supervisor_stop`
        // — it needs a synthetic `Item(id)` here for `lower_identifier` to
        // resolve and for `verify_hir` to accept (the verifier rejects
        // `Unresolved` callee refs). The call-result type is read from the
        // checker's `expr_types` at the call site, so the entry's `return_ty`
        // is only a placeholder; the param carries the `i64` capacity arity.
        // MIR routes `BindingRef { name: "duplex_pair", resolved: Item(_) }`
        // through `user_name_to_c_symbol("duplex_pair")` → `hew_duplex_pair`.
        self.fn_registry.insert(
            "duplex_pair".to_string(),
            FnEntry {
                id: SYNTHETIC_DUPLEX_PAIR_ITEM,
                return_ty: ResolvedTy::Unit,
                param_tys: vec![ResolvedTy::I64],
                linkage: None,
                type_params: vec!["S".to_string(), "R".to_string()],
            },
        );
        // Duplex method-call rewrites: `check_duplex_method` records
        // `RewriteToFunction { c_symbol: "hew_duplex_*" }` for the Duplex
        // built-in methods.  The `RewriteToFunction` HIR path resolves the
        // c_symbol against `fn_registry`; a missing entry produces a
        // `ResolvedRef::Unresolved` callee which the HIR verifier rejects as
        // `UnresolvedSymbol`.  These synthetic entries exist solely to satisfy
        // the verifier — the actual call signature is constructed by the
        // `RewriteToFunction` arm and the return type is read from
        // `expr_types`.  IDs live just below `supervisor_stop`'s slot.
        for (idx, name) in [
            "hew_duplex_send",
            "hew_duplex_try_send",
            "hew_duplex_recv",
            "hew_duplex_try_recv",
            "hew_duplex_send_half",
            "hew_duplex_recv_half",
            "hew_duplex_close",
            "hew_duplex_close_half",
        ]
        .iter()
        .enumerate()
        {
            let id_offset = u32::try_from(idx).expect("duplex symbol index is small");
            self.fn_registry.insert(
                (*name).to_string(),
                FnEntry {
                    id: ItemId(u32::MAX / 2 - 1 - id_offset),
                    return_ty: ResolvedTy::Unit,
                    param_tys: Vec::new(),
                    linkage: None,
                    type_params: Vec::new(),
                },
            );
        }
        self.seed_channel_recv_fn_registry();
    }

    /// Seeds `fn_registry` entries for the four channel receive out-param-ABI
    /// symbols (`hew_channel_recv`, `hew_channel_recv_int`,
    /// `hew_channel_try_recv`, `hew_channel_try_recv_int`).
    ///
    /// These are registered by the checker (`registration.rs:5364`) but are
    /// not extern-declared in `channel.hew`. Return types are placeholders
    /// (MIR reads the actual `Option<T>` type from `expr_types` at the call
    /// site); param types carry only arity. See `SYNTHETIC_CHANNEL_RECV_*_ITEM`
    /// for the full rationale.
    fn seed_channel_recv_fn_registry(&mut self) {
        for (name, id) in [
            ("hew_channel_recv", SYNTHETIC_CHANNEL_RECV_STR_ITEM),
            ("hew_channel_recv_int", SYNTHETIC_CHANNEL_RECV_INT_ITEM),
            ("hew_channel_try_recv", SYNTHETIC_CHANNEL_TRY_RECV_STR_ITEM),
            (
                "hew_channel_try_recv_int",
                SYNTHETIC_CHANNEL_TRY_RECV_INT_ITEM,
            ),
        ] {
            self.fn_registry.insert(
                name.to_string(),
                FnEntry {
                    id,
                    return_ty: ResolvedTy::Unit,
                    param_tys: Vec::new(),
                    linkage: None,
                    type_params: Vec::new(),
                },
            );
        }
    }

    fn register_fn_entry(&mut self, name: &str, func: &FnDecl) {
        let id = self.ids.item();
        let return_ty = func
            .return_type
            .as_ref()
            .map_or(ResolvedTy::Unit, |ty| self.lower_type(ty));
        let param_tys = func.params.iter().map(|p| self.lower_type(&p.ty)).collect();
        let type_params = func
            .type_params
            .as_ref()
            .map(|params| params.iter().map(|p| p.name.clone()).collect())
            .unwrap_or_default();
        self.fn_registry.insert(
            name.to_string(),
            FnEntry {
                id,
                return_ty,
                param_tys,
                linkage: None,
                type_params,
            },
        );
    }

    fn register_impl_method_fn_entry(
        &mut self,
        self_type_name: &str,
        method: &FnDecl,
        impl_type_params: &[String],
    ) {
        let symbol = crate::node::HirImplBlock::method_symbol(self_type_name, &method.name);
        self.register_fn_entry(&symbol, method);
        if Self::is_var_self_method_for_type(method, self_type_name) {
            if let Some(entry) = self.fn_registry.get_mut(&symbol) {
                let Some(receiver_ty) = entry.param_tys.first().cloned() else {
                    unreachable!(
                        "var-self method `{symbol}` was registered without a receiver parameter"
                    );
                };
                entry.return_ty =
                    Self::var_self_dual_return_ty(entry.return_ty.clone(), receiver_ty);
            }
        }
        if impl_type_params.is_empty() {
            return;
        }
        if let Some(entry) = self.fn_registry.get_mut(&symbol) {
            let method_type_params = std::mem::take(&mut entry.type_params);
            entry
                .type_params
                .reserve(impl_type_params.len() + method_type_params.len());
            entry.type_params.extend(impl_type_params.iter().cloned());
            entry.type_params.extend(method_type_params);
        }
    }

    /// Register an `extern "..." { fn ...; }` declaration in `fn_registry`
    /// so call sites resolve the bare name to an item just like a regular
    /// `fn`. Extern fns are monomorphic (no type params) and have no body
    /// — codegen pre-declares the LLVM symbol with external linkage.
    fn register_extern_fn_entry(&mut self, decl: &hew_parser::ast::ExternFnDecl) {
        let id = self.ids.item();
        let return_ty = decl
            .return_type
            .as_ref()
            .map_or(ResolvedTy::Unit, |ty| self.lower_type(ty));
        let param_tys = decl.params.iter().map(|p| self.lower_type(&p.ty)).collect();
        self.fn_registry.insert(
            decl.name.clone(),
            FnEntry {
                id,
                return_ty,
                param_tys,
                linkage: None,
                type_params: Vec::new(),
            },
        );
    }

    fn is_var_self_method_for_type(method: &FnDecl, self_type_name: &str) -> bool {
        method.params.first().is_some_and(|param| {
            param.is_mutable && Self::is_receiver_param_for_type(param, self_type_name)
        })
    }

    fn is_var_self_method(method: &FnDecl) -> bool {
        method
            .params
            .first()
            .is_some_and(|param| param.is_mutable && Self::is_receiver_param(param))
    }

    fn is_receiver_param_for_type(param: &Param, self_type_name: &str) -> bool {
        match &param.ty.0 {
            TypeExpr::Named { name, .. } => name == "Self" || name == self_type_name,
            _ => false,
        }
    }

    fn is_receiver_param(param: &Param) -> bool {
        matches!(&param.ty.0, TypeExpr::Named { name, .. } if name == "Self")
    }

    fn var_self_dual_return_ty(result_ty: ResolvedTy, receiver_ty: ResolvedTy) -> ResolvedTy {
        ResolvedTy::Tuple(vec![result_ty, receiver_ty])
    }

    fn make_var_self_return_expr(
        &mut self,
        result_expr: HirExpr,
        receiver: &HirBinding,
        abi_return_ty: &ResolvedTy,
        span: Span,
    ) -> HirExpr {
        let self_ref = HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            ty: receiver.ty.clone(),
            value_class: ValueClass::of_ty(&receiver.ty, &self.type_classes),
            intent: IntentKind::Consume,
            kind: HirExprKind::BindingRef {
                name: receiver.name.clone(),
                resolved: ResolvedRef::Binding(receiver.id),
            },
            span: receiver.span.clone(),
        };
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            ty: abi_return_ty.clone(),
            value_class: ValueClass::of_ty(abi_return_ty, &self.type_classes),
            intent: IntentKind::Read,
            kind: HirExprKind::TupleLiteral {
                elements: vec![result_expr, self_ref],
            },
            span,
        }
    }

    fn signature_requires_mutable_receiver(&self, symbol: &str) -> bool {
        self.fn_sigs
            .get(symbol)
            .is_some_and(|sig| sig.requires_mutable_receiver)
    }

    fn make_unit_expr(&mut self, span: Span) -> HirExpr {
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            ty: ResolvedTy::Unit,
            value_class: ValueClass::of_ty(&ResolvedTy::Unit, &self.type_classes),
            intent: IntentKind::Read,
            kind: HirExprKind::Literal(HirLiteral::Unit),
            span,
        }
    }

    fn wrap_var_self_function_returns(
        &mut self,
        block: &mut HirBlock,
        receiver: &HirBinding,
        abi_return_ty: &ResolvedTy,
    ) {
        self.wrap_var_self_explicit_returns_in_block(block, receiver, abi_return_ty);
        let mut tail = block
            .tail
            .take()
            .map_or_else(|| self.make_unit_expr(block.span.clone()), |tail| *tail);
        self.wrap_var_self_explicit_expr_returns(&mut tail, receiver, abi_return_ty);
        let span = tail.span.clone();
        block.tail = Some(Box::new(self.make_var_self_return_expr(
            tail,
            receiver,
            abi_return_ty,
            span,
        )));
        block.ty = abi_return_ty.clone();
    }

    fn wrap_var_self_explicit_returns_in_block(
        &mut self,
        block: &mut HirBlock,
        receiver: &HirBinding,
        abi_return_ty: &ResolvedTy,
    ) {
        for stmt in &mut block.statements {
            self.wrap_var_self_stmt_returns(stmt, receiver, abi_return_ty);
        }
        if let Some(tail) = &mut block.tail {
            self.wrap_var_self_explicit_expr_returns(tail, receiver, abi_return_ty);
        }
    }

    fn wrap_var_self_stmt_returns(
        &mut self,
        stmt: &mut HirStmt,
        receiver: &HirBinding,
        abi_return_ty: &ResolvedTy,
    ) {
        match &mut stmt.kind {
            HirStmtKind::Return(Some(expr)) => {
                self.wrap_var_self_explicit_expr_returns(expr, receiver, abi_return_ty);
                let span = expr.span.clone();
                let old = std::mem::replace(expr, self.make_unit_expr(span.clone()));
                *expr = self.make_var_self_return_expr(old, receiver, abi_return_ty, span);
            }
            HirStmtKind::Return(None) => {
                let span = stmt.span.clone();
                let unit = self.make_unit_expr(span.clone());
                stmt.kind = HirStmtKind::Return(Some(self.make_var_self_return_expr(
                    unit,
                    receiver,
                    abi_return_ty,
                    span,
                )));
            }
            HirStmtKind::Let(_, Some(expr)) | HirStmtKind::Expr(expr) => {
                self.wrap_var_self_explicit_expr_returns(expr, receiver, abi_return_ty);
            }
            HirStmtKind::Assign { target, value } => {
                self.wrap_var_self_explicit_expr_returns(target, receiver, abi_return_ty);
                self.wrap_var_self_explicit_expr_returns(value, receiver, abi_return_ty);
            }
            HirStmtKind::Defer { body, .. } => {
                self.wrap_var_self_explicit_expr_returns(body, receiver, abi_return_ty);
            }
            HirStmtKind::Let(_, None) => {}
        }
    }

    #[allow(
        clippy::too_many_lines,
        reason = "visitor mirrors HIR shape while avoiding nested function-like bodies"
    )]
    fn wrap_var_self_explicit_expr_returns(
        &mut self,
        expr: &mut HirExpr,
        receiver: &HirBinding,
        abi_return_ty: &ResolvedTy,
    ) {
        match &mut expr.kind {
            HirExprKind::Block(block)
            | HirExprKind::Scope { body: block }
            | HirExprKind::ForkBlock { body: block, .. } => {
                self.wrap_var_self_explicit_returns_in_block(block, receiver, abi_return_ty);
            }
            HirExprKind::If {
                condition,
                then_expr,
                else_expr,
            } => {
                self.wrap_var_self_explicit_expr_returns(condition, receiver, abi_return_ty);
                self.wrap_var_self_explicit_expr_returns(then_expr, receiver, abi_return_ty);
                if let Some(else_expr) = else_expr {
                    self.wrap_var_self_explicit_expr_returns(else_expr, receiver, abi_return_ty);
                }
            }
            HirExprKind::While { condition, body } => {
                self.wrap_var_self_explicit_expr_returns(condition, receiver, abi_return_ty);
                self.wrap_var_self_explicit_returns_in_block(body, receiver, abi_return_ty);
            }
            HirExprKind::ForRange {
                start, end, body, ..
            } => {
                self.wrap_var_self_explicit_expr_returns(start, receiver, abi_return_ty);
                self.wrap_var_self_explicit_expr_returns(end, receiver, abi_return_ty);
                self.wrap_var_self_explicit_returns_in_block(body, receiver, abi_return_ty);
            }
            HirExprKind::WhileLet {
                scrutinee, body, ..
            } => {
                self.wrap_var_self_explicit_expr_returns(scrutinee, receiver, abi_return_ty);
                self.wrap_var_self_explicit_returns_in_block(body, receiver, abi_return_ty);
            }
            HirExprKind::IfLet {
                scrutinee,
                body,
                else_body,
                ..
            } => {
                self.wrap_var_self_explicit_expr_returns(scrutinee, receiver, abi_return_ty);
                self.wrap_var_self_explicit_returns_in_block(body, receiver, abi_return_ty);
                if let Some(eb) = else_body {
                    self.wrap_var_self_explicit_returns_in_block(eb, receiver, abi_return_ty);
                }
            }
            HirExprKind::Loop { body } => {
                self.wrap_var_self_explicit_returns_in_block(body, receiver, abi_return_ty);
            }
            HirExprKind::Match { scrutinee, arms } => {
                self.wrap_var_self_explicit_expr_returns(scrutinee, receiver, abi_return_ty);
                for arm in arms {
                    if let Some(guard) = &mut arm.guard {
                        self.wrap_var_self_explicit_expr_returns(guard, receiver, abi_return_ty);
                    }
                    self.wrap_var_self_explicit_expr_returns(
                        &mut arm.body,
                        receiver,
                        abi_return_ty,
                    );
                }
            }
            HirExprKind::Call { callee, args } | HirExprKind::SpawnedCall { callee, args, .. } => {
                self.wrap_var_self_explicit_expr_returns(callee, receiver, abi_return_ty);
                for arg in args {
                    self.wrap_var_self_explicit_expr_returns(arg, receiver, abi_return_ty);
                }
            }
            HirExprKind::ActorSend {
                receiver: target,
                args,
                ..
            }
            | HirExprKind::ActorAsk {
                receiver: target,
                args,
                ..
            }
            | HirExprKind::CallDynMethod {
                receiver: target,
                args,
                ..
            }
            | HirExprKind::ResolvedImplCall {
                receiver: target,
                args,
                ..
            }
            | HirExprKind::CallTraitMethodStatic {
                receiver: target,
                args,
                ..
            }
            | HirExprKind::VarSelfMethodCall {
                receiver: target,
                args,
                ..
            } => {
                self.wrap_var_self_explicit_expr_returns(target, receiver, abi_return_ty);
                for arg in args {
                    self.wrap_var_self_explicit_expr_returns(arg, receiver, abi_return_ty);
                }
            }
            HirExprKind::RemoteActorAsk {
                receiver: target,
                msg,
                timeout_ms,
                ..
            } => {
                self.wrap_var_self_explicit_expr_returns(target, receiver, abi_return_ty);
                self.wrap_var_self_explicit_expr_returns(msg, receiver, abi_return_ty);
                self.wrap_var_self_explicit_expr_returns(timeout_ms, receiver, abi_return_ty);
            }
            HirExprKind::Binary { left, right, .. }
            | HirExprKind::IdentityCompare { left, right } => {
                self.wrap_var_self_explicit_expr_returns(left, receiver, abi_return_ty);
                self.wrap_var_self_explicit_expr_returns(right, receiver, abi_return_ty);
            }
            HirExprKind::Unary { operand, .. } => {
                self.wrap_var_self_explicit_expr_returns(operand, receiver, abi_return_ty);
            }
            HirExprKind::NumericCast { value, .. }
            | HirExprKind::CoerceToDynTrait { value, .. } => {
                self.wrap_var_self_explicit_expr_returns(value, receiver, abi_return_ty);
            }
            HirExprKind::TupleLiteral { elements } => {
                for elem in elements {
                    self.wrap_var_self_explicit_expr_returns(elem, receiver, abi_return_ty);
                }
            }
            HirExprKind::StructInit { fields, base, .. } => {
                for (_, field_expr) in fields {
                    self.wrap_var_self_explicit_expr_returns(field_expr, receiver, abi_return_ty);
                }
                if let Some(base) = base {
                    self.wrap_var_self_explicit_expr_returns(base, receiver, abi_return_ty);
                }
            }
            HirExprKind::FieldAccess { object, .. }
            | HirExprKind::TupleIndex { tuple: object, .. }
            | HirExprKind::MachineStateName {
                receiver: object, ..
            }
            | HirExprKind::CancellationTokenIsCancelled { receiver: object }
            | HirExprKind::GeneratorNext {
                receiver: object, ..
            }
            | HirExprKind::ConnAwaitRead { conn: object, .. } => {
                self.wrap_var_self_explicit_expr_returns(object, receiver, abi_return_ty);
            }
            HirExprKind::ListenerAwaitAccept { listener } => {
                self.wrap_var_self_explicit_expr_returns(listener, receiver, abi_return_ty);
            }
            HirExprKind::Index { container, index } => {
                self.wrap_var_self_explicit_expr_returns(container, receiver, abi_return_ty);
                self.wrap_var_self_explicit_expr_returns(index, receiver, abi_return_ty);
            }
            HirExprKind::Slice {
                container,
                start,
                end,
                ..
            } => {
                self.wrap_var_self_explicit_expr_returns(container, receiver, abi_return_ty);
                if let Some(start) = start {
                    self.wrap_var_self_explicit_expr_returns(start, receiver, abi_return_ty);
                }
                if let Some(end) = end {
                    self.wrap_var_self_explicit_expr_returns(end, receiver, abi_return_ty);
                }
            }
            HirExprKind::MachineEmit { fields, .. }
            | HirExprKind::MachineVariantCtor {
                payload: Some(fields),
                ..
            } => {
                for (_, field_expr) in fields {
                    self.wrap_var_self_explicit_expr_returns(field_expr, receiver, abi_return_ty);
                }
            }
            HirExprKind::MachineStep {
                receiver: target,
                event,
                ..
            } => {
                self.wrap_var_self_explicit_expr_returns(target, receiver, abi_return_ty);
                self.wrap_var_self_explicit_expr_returns(event, receiver, abi_return_ty);
            }
            HirExprKind::ScopeDeadline { duration, body } => {
                self.wrap_var_self_explicit_expr_returns(duration, receiver, abi_return_ty);
                self.wrap_var_self_explicit_returns_in_block(body, receiver, abi_return_ty);
            }
            HirExprKind::Select(select) => {
                for arm in &mut select.arms {
                    match &mut arm.kind {
                        HirSelectArmKind::StreamNext { stream } => {
                            self.wrap_var_self_explicit_expr_returns(
                                stream,
                                receiver,
                                abi_return_ty,
                            );
                        }
                        HirSelectArmKind::ActorAsk { actor, args, .. } => {
                            self.wrap_var_self_explicit_expr_returns(
                                actor,
                                receiver,
                                abi_return_ty,
                            );
                            for arg in args {
                                self.wrap_var_self_explicit_expr_returns(
                                    arg,
                                    receiver,
                                    abi_return_ty,
                                );
                            }
                        }
                        HirSelectArmKind::TaskAwait { task } => {
                            self.wrap_var_self_explicit_expr_returns(task, receiver, abi_return_ty);
                        }
                        HirSelectArmKind::ChannelRecv { receiver: rx, .. } => {
                            self.wrap_var_self_explicit_expr_returns(rx, receiver, abi_return_ty);
                        }
                        HirSelectArmKind::AfterTimer { duration } => {
                            self.wrap_var_self_explicit_expr_returns(
                                duration,
                                receiver,
                                abi_return_ty,
                            );
                        }
                    }
                    self.wrap_var_self_explicit_expr_returns(
                        &mut arm.body,
                        receiver,
                        abi_return_ty,
                    );
                }
            }
            HirExprKind::Yield { value, .. } | HirExprKind::Break { value, .. } => {
                if let Some(value) = value {
                    self.wrap_var_self_explicit_expr_returns(value, receiver, abi_return_ty);
                }
            }
            HirExprKind::NumericMethod {
                receiver: target,
                arg,
                ..
            } => {
                self.wrap_var_self_explicit_expr_returns(target, receiver, abi_return_ty);
                self.wrap_var_self_explicit_expr_returns(arg, receiver, abi_return_ty);
            }
            HirExprKind::Spawn { args, .. } => {
                for (_, arg) in args {
                    self.wrap_var_self_explicit_expr_returns(arg, receiver, abi_return_ty);
                }
            }
            HirExprKind::SpawnLambdaActor { .. }
            | HirExprKind::Closure { .. }
            | HirExprKind::GenBlock { .. }
            | HirExprKind::Literal(_)
            | HirExprKind::RegexLiteralRef { .. }
            | HirExprKind::BindingRef { .. }
            | HirExprKind::AwaitTask { .. }
            | HirExprKind::ContextReader { .. }
            | HirExprKind::MachineFieldAccess { .. }
            | HirExprKind::MachineEventFieldAccess { .. }
            | HirExprKind::Continue { .. }
            | HirExprKind::MachineVariantCtor { payload: None, .. }
            | HirExprKind::Unsupported(_) => {}
        }
    }

    /// First-pass registration of a module-level `const`. Allocates a stable
    /// `ItemId` and records the declared (checker-resolved) type so const
    /// references resolve regardless of source order. The folded value is
    /// produced later, canonically, in [`Self::lower_const`].
    fn register_const_entry(&mut self, decl: &ConstDecl) {
        let id = self.ids.item();
        let ty = self.lower_type(&decl.ty);
        self.const_registry
            .insert(decl.name.clone(), ConstEntry { id, ty });
    }

    /// Emit-pass lowering of a module-level `const NAME: T = <expr>;`.
    ///
    /// Reuses the `ItemId` allocated in the first pass and constant-folds the
    /// initializer into a [`HirConstValue`]. Fail-closed: any initializer the
    /// fold cannot evaluate to a concrete integer/string emits a
    /// `HirDiagnosticKind::NotYetImplemented` and lowers to a placeholder value
    /// (never silently fabricated semantics).
    fn lower_const(
        &mut self,
        decl: &ConstDecl,
        span: std::ops::Range<usize>,
    ) -> crate::node::HirConst {
        // Reuse the stable ItemId + type pre-allocated during the first pass.
        let (id, ty) = match self.const_registry.get(&decl.name) {
            Some(entry) => (entry.id, entry.ty.clone()),
            None => (self.ids.item(), self.lower_type(&decl.ty)),
        };

        let value = self.fold_const_expr(&decl.value.0, &ty, span.clone());

        crate::node::HirConst {
            id,
            node: self.ids.node(),
            name: decl.name.clone(),
            ty,
            value,
            span,
        }
    }

    /// Fail-closed constant-fold for module-level `const` initializers.
    ///
    /// WHY this shape: integer const-evaluation is delegated wholesale to
    /// [`hew_types::check::const_eval::eval_const_expr`], the single sanctioned
    /// constexpr authority (A620 / Q329 — const-eval must reuse `const_eval.rs`,
    /// not fork a parallel evaluator). Only two things live here: the
    /// string-literal short-circuit (strings are non-arithmetic and `const_eval`
    /// is integer-only, so they legitimately stay HIR-local) and the
    /// `Result<u64, ConstEvalError>` → [`HirConstValue`] mapping with its
    /// fail-closed diagnostics. Const *references* in initializers resolve via
    /// the `ConstEnv`; they are deferred to a later slice, so an empty env is
    /// passed and `UnknownConst` is reported as a specific deferral diagnostic.
    fn fold_const_expr(
        &mut self,
        expr: &Expr,
        declared_ty: &ResolvedTy,
        span: std::ops::Range<usize>,
    ) -> crate::node::HirConstValue {
        // Dispatch on the initializer shape rather than the declared type:
        // the string primitive spells out as either `ResolvedTy::String` or
        // `ResolvedTy::Named { name: "String" }` depending on annotation form,
        // and the checker has already proven value/type agreement upstream.
        if let Expr::Literal(Literal::String(s)) = expr {
            return crate::node::HirConstValue::String(s.clone());
        }

        if let Expr::Unary {
            op: UnaryOp::Negate,
            operand,
        } = expr
        {
            if let Some(limit) = Self::signed_integer_negative_magnitude_limit(declared_ty) {
                let env = hew_types::check::const_eval::ConstEnv::new();
                match hew_types::check::const_eval::eval_const_expr(operand, &env) {
                    Ok(magnitude) if magnitude <= limit => {
                        let value = if magnitude == (1u64 << 63) {
                            i64::MIN
                        } else {
                            -i64::try_from(magnitude)
                                .expect("checked negative magnitude fits in i64")
                        };
                        return crate::node::HirConstValue::Integer(value);
                    }
                    Ok(_) => {
                        self.unsupported(
                            span,
                            "negative const initializer exceeds the declared signed integer range",
                            "const-fold",
                        );
                        return crate::node::HirConstValue::Integer(0);
                    }
                    Err(_) => {}
                }
            }
        }

        // Delegate integer/arithmetic evaluation to the sanctioned engine.
        // `decl.value` is a `Spanned<Expr>`, but `fold_const_expr` is handed the
        // bare `Expr`; reconstruct the `Spanned` shape the engine expects. The
        // env is empty because const references in initializers are deferred —
        // `UnknownConst` is mapped to a specific deferral diagnostic below.
        let spanned: hew_parser::ast::Spanned<Expr> = (expr.clone(), span.clone());
        let env = hew_types::check::const_eval::ConstEnv::new();
        match hew_types::check::const_eval::eval_const_expr(&spanned, &env) {
            Ok(u) => match i64::try_from(u) {
                Ok(value) => return crate::node::HirConstValue::Integer(value),
                Err(_) => {
                    self.unsupported(span, "const integer value exceeds i64 range", "const-fold");
                }
            },
            Err(hew_types::check::const_eval::ConstEvalError::UnknownConst(_)) => {
                self.unsupported(
                    span,
                    "const references in initializers are not yet supported",
                    "const-fold",
                );
            }
            Err(hew_types::check::const_eval::ConstEvalError::Overflow) => {
                self.unsupported(
                    span,
                    "constant arithmetic overflow, division by zero, or unsupported \
                     negative/out-of-range value (negative const initializers are not \
                     yet supported)",
                    "const-fold",
                );
            }
            Err(hew_types::check::const_eval::ConstEvalError::NotConstant) => {
                self.unsupported(
                    span,
                    "unsupported const initializer expression",
                    "const-fold",
                );
            }
        }

        // Fail-closed placeholder. A diagnostic was already emitted, so
        // compilation will not proceed; the placeholder only needs to match
        // the declared type's value shape so downstream structural invariants
        // hold.
        if Self::is_string_ty(declared_ty) {
            crate::node::HirConstValue::String(String::new())
        } else {
            crate::node::HirConstValue::Integer(0)
        }
    }

    /// True for the string primitive in either of its resolved spellings:
    /// the bare `ResolvedTy::String` or the `Named { name: "String" }` builtin
    /// form produced when the type is written as `String` in an annotation.
    fn is_string_ty(ty: &ResolvedTy) -> bool {
        matches!(ty, ResolvedTy::String)
            || matches!(ty, ResolvedTy::Named { name, .. } if name == "String")
    }

    fn signed_integer_negative_magnitude_limit(ty: &ResolvedTy) -> Option<u64> {
        match ty {
            ResolvedTy::I8 => Some(1u64 << 7),
            ResolvedTy::I16 => Some(1u64 << 15),
            ResolvedTy::I32 => Some(1u64 << 31),
            ResolvedTy::I64 => Some(1u64 << 63),
            #[cfg(target_pointer_width = "32")]
            ResolvedTy::Isize => Some(1u64 << 31),
            #[cfg(not(target_pointer_width = "32"))]
            ResolvedTy::Isize => Some(1u64 << 63),
            _ => None,
        }
    }

    fn lower_stdlib_callee(&mut self, entry: &BuiltinEntry, span: Span) -> HirExpr {
        let (id, param_tys, return_ty) = {
            let registry_entry = self
                .fn_registry
                .get(entry.name)
                .expect("catalog entries are seeded before expression lowering");
            (
                registry_entry.id,
                registry_entry.param_tys.clone(),
                registry_entry.return_ty.clone(),
            )
        };
        let fn_ty = ResolvedTy::Function {
            params: param_tys,
            ret: Box::new(return_ty),
        };
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::of_ty(&fn_ty, &self.type_classes),
            ty: fn_ty,
            intent: IntentKind::Read,
            kind: HirExprKind::BindingRef {
                name: entry.name.to_string(),
                resolved: ResolvedRef::Item(id),
            },
            span,
        }
    }

    fn unresolved_builtin_callee(&mut self, name: &str, span: Span) -> HirExpr {
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::BitCopy,
            ty: ResolvedTy::Unit,
            intent: IntentKind::Read,
            kind: HirExprKind::BindingRef {
                name: name.to_string(),
                resolved: ResolvedRef::Unresolved,
            },
            span,
        }
    }

    fn unresolved_module_object(&mut self, name: &str, span: Span) -> HirExpr {
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::BitCopy,
            ty: ResolvedTy::Unit,
            intent: IntentKind::Read,
            kind: HirExprKind::BindingRef {
                name: name.to_string(),
                resolved: ResolvedRef::Unresolved,
            },
            span,
        }
    }

    /// Build a HIR `String` literal expression for the given content.  Used by
    /// the f-string interpolation lowering to materialise the static segments
    /// between `{ … }` placeholders.
    fn build_string_literal_expr(&mut self, value: String, span: Span) -> HirExpr {
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::of_ty(&ResolvedTy::String, &self.type_classes),
            ty: ResolvedTy::String,
            intent: IntentKind::Read,
            kind: HirExprKind::Literal(HirLiteral::String(value)),
            span,
        }
    }

    /// Emit a call to a stdlib catalog entry resolved by name.  Returns a
    /// fully-typed HIR `Call` expression with the catalog entry's return
    /// type. Used by f-string lowering to invoke `string_concat` and the
    /// primitive `to_string_*` overloads that back the built-in `Display`
    /// impls in stdlib.
    fn build_catalog_call(
        &mut self,
        builtin_name: &str,
        args: Vec<HirExpr>,
        span: Span,
    ) -> HirExpr {
        let entry = crate::stdlib_catalog::CATALOG
            .iter()
            .find(|e| e.name == builtin_name)
            .expect("catalog entry exists for f-string lowering");
        let callee = self.lower_stdlib_callee(entry, span.clone());
        let return_ty = self
            .fn_registry
            .get(builtin_name)
            .map_or(ResolvedTy::String, |e| e.return_ty.clone());
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::of_ty(&return_ty, &self.type_classes),
            ty: return_ty,
            intent: IntentKind::Read,
            kind: HirExprKind::Call {
                callee: Box::new(callee),
                args,
            },
            span,
        }
    }

    /// Emit a call to a user-defined function or impl-method registered in
    /// `fn_registry` under the given symbol.  Used by f-string interpolation
    /// to invoke `<Type>::fmt` for user `impl Display for Type` blocks.
    fn build_user_fn_call(
        &mut self,
        fn_name: &str,
        args: Vec<HirExpr>,
        span: Span,
    ) -> Option<HirExpr> {
        let (id, param_tys, return_ty) = {
            let entry = self.fn_registry.get(fn_name)?;
            (entry.id, entry.param_tys.clone(), entry.return_ty.clone())
        };
        let fn_ty = ResolvedTy::Function {
            params: param_tys,
            ret: Box::new(return_ty.clone()),
        };
        let callee = HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::of_ty(&fn_ty, &self.type_classes),
            ty: fn_ty,
            intent: IntentKind::Read,
            kind: HirExprKind::BindingRef {
                name: fn_name.to_string(),
                resolved: ResolvedRef::Item(id),
            },
            span: span.clone(),
        };
        Some(HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::of_ty(&return_ty, &self.type_classes),
            ty: return_ty,
            intent: IntentKind::Read,
            kind: HirExprKind::Call {
                callee: Box::new(callee),
                args,
            },
            span,
        })
    }

    /// Lower a single interpolant of an f-string to a `string`-typed HIR
    /// expression by dispatching through `Display`.
    ///
    /// The display *method name* is resolved through
    /// [`hew_types::LangItemRegistry`] (`LANG_ITEM_DISPLAY_FMT` key)
    /// rather than hard-coded so renaming the stdlib `fmt` method only
    /// requires moving the `#[lang_item("display_fmt")]` attribute. With
    /// no registry entry, every interpolation is rejected fail-closed.
    ///
    /// Concretely:
    ///
    /// * `string` values prefer a user `impl Display for string` if one
    ///   exists (resolved through the per-type method symbol); otherwise
    ///   they pass through identity. The stdlib provides the identity
    ///   impl so a non-user-overridden `string` interpolation does call
    ///   it.
    /// * Primitives route through the per-type `to_string_*` catalog
    ///   entries that back the built-in `impl Display for <primitive>`
    ///   blocks in `std::builtins`.
    /// * Named user types route through the registry-derived method
    ///   symbol on the user type (`<Type>::<method_name>`).
    /// * Any path that would reach a fabricated fallback emits a
    ///   `CheckerBoundaryViolation` and returns an `Unsupported`
    ///   sentinel — the checker's `require_display_impl` gate is the
    ///   authoritative reject point. Reaching the sentinel means
    ///   compilation halts: never a silent empty-string substitute.
    fn lower_display_dispatch(&mut self, value: HirExpr, span: Span) -> HirExpr {
        // Resolve the Display method name through the lang-item registry.
        // Missing entry is fail-closed: f-string lowering cannot synthesise
        // dispatch without a method-name binding.
        let Some(method_name) = self.lang_items.display_method().map(str::to_owned) else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: "Display::fmt".to_string(),
                    reason: format!(
                        "no lang-item registered for key `{}`",
                        hew_types::LANG_ITEM_DISPLAY_FMT
                    ),
                },
                span.clone(),
                "f-string lowering requires a trait method tagged \
                 `#[lang_item(\"display_fmt\")]` in scope",
            ));
            return self.unsupported_expr(span, "f-string display dispatch: no display lang-item");
        };
        let ty = value.ty.clone();
        match &ty {
            // String: route through a user `impl Display for string` if one
            // is registered; otherwise pass through identity. The stdlib
            // identity impl ordinarily makes this a real (no-op) call so a
            // user impl can transparently replace it.
            ResolvedTy::String => {
                let symbol = crate::node::HirImplBlock::method_symbol("string", &method_name);
                if let Some(call) =
                    self.build_user_fn_call(&symbol, vec![value.clone()], span.clone())
                {
                    call
                } else {
                    // No registered impl (not even the stdlib identity) —
                    // fall through to identity. This keeps zero-stdlib unit
                    // tests working while preserving correctness in normal
                    // builds.
                    value
                }
            }
            ResolvedTy::I8
            | ResolvedTy::I16
            | ResolvedTy::I32
            | ResolvedTy::I64
            | ResolvedTy::U8
            | ResolvedTy::U16
            | ResolvedTy::U32
            | ResolvedTy::U64
            | ResolvedTy::Isize
            | ResolvedTy::Usize
            | ResolvedTy::F32
            | ResolvedTy::F64
            | ResolvedTy::Bool
            | ResolvedTy::Char => {
                let builtin = match ty {
                    ResolvedTy::I8 | ResolvedTy::I16 | ResolvedTy::I32 => "to_string_i32",
                    ResolvedTy::I64 | ResolvedTy::Isize => "to_string_i64",
                    ResolvedTy::U8 | ResolvedTy::U16 | ResolvedTy::U32 => "to_string_u32",
                    ResolvedTy::U64 | ResolvedTy::Usize => "to_string_u64",
                    ResolvedTy::F32 | ResolvedTy::F64 => "to_string_f64",
                    ResolvedTy::Bool => "to_string_bool",
                    ResolvedTy::Char => "to_string_char",
                    _ => unreachable!(),
                };
                self.build_catalog_call(builtin, vec![value], span)
            }
            ResolvedTy::Named { name, .. } => {
                let symbol = crate::node::HirImplBlock::method_symbol(name, &method_name);
                if let Some(call) = self.build_user_fn_call(&symbol, vec![value], span.clone()) {
                    call
                } else {
                    // Invariant: the checker's `require_display_impl` gate
                    // rejects interpolants whose type lacks an `impl Display`.
                    // Reaching here means the checker accepted the program
                    // but the impl symbol is absent from the HIR fn registry,
                    // which is a checker–HIR contract violation. Surface a
                    // fail-closed diagnostic and an `Unsupported` sentinel
                    // — never fabricate an empty string.
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: symbol.clone(),
                            reason: format!("no fn_registry entry for display impl `{symbol}`"),
                        },
                        span.clone(),
                        "checker accepted a Display interpolant but HIR has no \
                         corresponding impl symbol — checker–HIR contract violation",
                    ));
                    self.unsupported_expr(
                        span,
                        format!("f-string display dispatch: missing {symbol}"),
                    )
                }
            }
            _ => {
                // Same invariant as the named-type arm: the checker should
                // have rejected this interpolant via `require_display_impl`.
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: format!("Display::{method_name}"),
                        reason: format!("no Display dispatch shape for type `{ty:?}`"),
                    },
                    span.clone(),
                    "checker accepted a Display interpolant of an unsupported type \
                     shape — checker–HIR contract violation",
                ));
                self.unsupported_expr(span, "f-string display dispatch: unsupported type shape")
            }
        }
    }

    /// Lower an `Expr::InterpolatedString` to a chain of `string_concat` calls
    /// joining literal segments with `Display::fmt(…)` results.  Empty
    /// interpolations collapse to the empty-string literal.  The result type
    /// is always `ResolvedTy::String` so the surrounding lowering wraps it
    /// like any other string-typed expression.
    fn lower_interpolated_string(
        &mut self,
        parts: &[StringPart],
        span: Span,
    ) -> (HirExprKind, ResolvedTy) {
        let mut segments: Vec<HirExpr> = Vec::with_capacity(parts.len());
        for part in parts {
            match part {
                StringPart::Literal(text) => {
                    if !text.is_empty() {
                        segments.push(self.build_string_literal_expr(text.clone(), span.clone()));
                    }
                }
                StringPart::Expr((expr, expr_span)) => {
                    let value =
                        self.lower_expr(&(expr.clone(), expr_span.clone()), IntentKind::Read);
                    let rendered = self.lower_display_dispatch(value, expr_span.clone());
                    segments.push(rendered);
                }
            }
        }
        if segments.is_empty() {
            return (
                HirExprKind::Literal(HirLiteral::String(String::new())),
                ResolvedTy::String,
            );
        }
        let mut iter = segments.into_iter();
        let mut acc = iter.next().expect("non-empty segments by construction");
        for next in iter {
            acc = self.build_catalog_call("string_concat", vec![acc, next], span.clone());
        }
        // Unwrap the outer HirExpr into (kind, ty) so the caller can re-wrap
        // with its own site / value-class layer like other arms.
        (acc.kind, acc.ty)
    }

    fn lower_regular_call(
        &mut self,
        function: &Spanned<Expr>,
        args: Vec<HirExpr>,
        span: &Span,
        site: SiteId,
    ) -> (HirExprKind, ResolvedTy) {
        let callee = self.lower_expr(function, IntentKind::Read);
        // Record the per-instantiation monomorphisation if the callee is a
        // generic top-level user fn. Direct-name callees only;
        // `record_monomorphisation` filters out non-generic callees, non-
        // `fn_registry` callees (builtins, runtime symbols, local bindings),
        // and callsites the checker did not record. Fail-closed on poisoned
        // entries and on registry-cap exhaustion.
        self.record_monomorphisation(&function.0, span, site);
        // Checker authority takes precedence: consult expr_types at the full
        // call-expression span. The checker records the call result type here
        // for checker-registered builtins that have no AST `fn` item and
        // therefore no `fn_registry` hit. (LESSONS: checker-authority P0)
        let checker_key = SpanKey::from(span);
        let result_ty = if let Some(ty) = self.expr_types.get(&checker_key).cloned() {
            match ResolvedTy::from_ty(&ty) {
                Ok(resolved) => resolved,
                Err(err) => {
                    let callee_name = if let Expr::Identifier(name) = &function.0 {
                        name.clone()
                    } else {
                        "<expr>".to_string()
                    };
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: callee_name,
                            reason: err.to_string(),
                        },
                        span.clone(),
                        "checker-authoritative call result type failed boundary conversion",
                    ));
                    ResolvedTy::Unit
                }
            }
        } else if let ResolvedTy::Function { ret, .. } = &callee.ty {
            *ret.clone()
        } else {
            if matches!(
                callee.kind,
                HirExprKind::BindingRef {
                    resolved: ResolvedRef::Unresolved,
                    ..
                }
            ) {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::UnresolvedInferenceVar,
                    span.clone(),
                    "call result type cannot be determined: callee is unresolved",
                ));
            }
            ResolvedTy::Unit
        };
        (
            HirExprKind::Call {
                callee: Box::new(callee),
                args,
            },
            result_ty,
        )
    }

    fn lower_fn(&mut self, func: &FnDecl, span: std::ops::Range<usize>) -> HirFn {
        self.lower_fn_with_name(func, &func.name, span)
    }

    /// V0b: lower a top-level `impl [<TypeParams>] [Trait for] TargetType { ... }`
    /// block. Methods are flattened into per-impl `HirItem::Function` entries
    /// (named `<SelfType>::<method>`) so the existing MIR / codegen function
    /// pipeline can pick them up unchanged; a metadata-only [`HirItem::Impl`]
    /// is also pushed so checker-side reasoning has a single anchor for the
    /// trait/self pair and the associated-type bindings.
    ///
    /// Fail-closed: any shape outside the V0b sufficient surface
    /// (where-clauses, default-method bodies, non-nominal targets, blanket
    /// impls) emits a named [`HirDiagnosticKind::ImplBlockShapeNotLowered`]
    /// rather than falling through to the generic catch-all.
    #[allow(
        clippy::too_many_lines,
        reason = "single linear lowering path with a sequence of fail-closed \
                  shape guards (where-clause / non-nominal / blanket / builtin \
                  inherent) followed by the per-method emission loop; splitting \
                  would scatter the guards from the emission they protect"
    )]
    fn lower_impl_block(
        &mut self,
        decl: &hew_parser::ast::ImplDecl,
        span: std::ops::Range<usize>,
        items: &mut Vec<HirItem>,
        pub_only: bool,
        imported: Option<&ImportedImplLowering<'_>>,
    ) {
        // Pre-flight: classify the impl shape. Bail with a precise diagnostic
        // on any unsupported variant before lowering bodies.
        if let Some(shape) = classify_unsupported_where_clause(decl) {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::ImplBlockShapeNotLowered { shape },
                span,
                "impl-block shape not yet lowered: only where-clause predicates of the form \
                 `where T: Bound(s)` on the impl's own type parameters are admitted — \
                 predicates on parameterised types and non-type-param names require later slices",
            ));
            return;
        }
        let TypeExpr::Named {
            name: self_type_name,
            ..
        } = &decl.target_type.0
        else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::ImplBlockShapeNotLowered {
                    shape: "impl on non-nominal target".to_string(),
                },
                span,
                "impl-block shape not yet lowered: impl target must be a named \
                 nominal type (e.g. `impl Trait for VecIter<T>`); tuple, array, \
                 function, and trait-object targets are not yet supported",
            ));
            return;
        };
        // Outer type-parameter names (e.g. `T` in `impl<T> Iterator for VecIter<T>`).
        let type_params: Vec<String> = decl
            .type_params
            .as_ref()
            .map(|ps| ps.iter().map(|p| p.name.clone()).collect())
            .unwrap_or_default();
        // Blanket-impl guard: reject `impl<T> Trait for T` (target name is
        // itself one of the outer type parameters) — V0b does not handle the
        // monomorphisation of blanket impls.
        if type_params.iter().any(|p| p == self_type_name) {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::ImplBlockShapeNotLowered {
                    shape: format!(
                        "blanket impl `impl<{self_type_name}> ... for {self_type_name}`"
                    ),
                },
                span,
                "impl-block shape not yet lowered: blanket impls (target is a \
                 bare type parameter) require specialisation infrastructure \
                 that is not in V0b — restrict the target to a concrete \
                 nominal type",
            ));
            return;
        }
        // Inherent-impl on builtin nominal guard: reject `impl Vec<T> { ... }`
        // and similar bare inherent impls on builtin generic types (`Vec`,
        // `HashMap`, `Option`, `Result`, etc.). The stdlib ships its own
        // inherent impls on these types via `std/builtins.hew` (registered
        // through the checker's `register_builtins_hew_impls` path, not via
        // HIR lowering), so a user-source inherent impl on the same nominal
        // collides downstream with a confusing duplicate-definition error.
        // Fail-closing at the V0b boundary makes the rejection site the
        // failure site. Trait impls (`impl MyTrait for Vec<T>`) are not
        // covered here — orphan-rule policing is a separate concern.
        if decl.trait_bound.is_none() && hew_types::lookup_builtin_type(self_type_name).is_some() {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::ImplBlockShapeNotLowered {
                    shape: format!("inherent impl on builtin nominal `{self_type_name}`"),
                },
                span,
                "impl-block shape not yet lowered: inherent impls on builtin \
                 nominal types (`Vec`, `HashMap`, `Option`, `Result`, etc.) are \
                 reserved for the standard library — user code may add trait \
                 impls (`impl MyTrait for Vec<T>`) but not bare \
                 `impl Vec<T> { ... }`",
            ));
            return;
        }
        // V0b uses `FnDecl` for impl-block methods (per parser ast), which
        // always carries a `Block` body — there is no body-less / default-method
        // shape representable on the impl AST node itself.  Trait-decl default
        // methods are lowered below, after the explicitly-overridden methods,
        // by synthesising a `FnDecl` from the trait's `TraitMethod` body.  This
        // was previously skipped (out of scope for V0b) but is now required to
        // support `self.other_method()` dispatch inside a default body.

        // Lower methods through the standard `lower_fn_with_name` path. Each
        // method becomes a top-level `HirItem::Function` keyed by
        // `<SelfType>::<method>` — identical naming to the pre-V0b Index
        // special-case, so downstream consumers (MIR / codegen / monomorph)
        // see ordinary functions and need no new wiring per-method.
        // When `pub_only` is true (imported-module path) only pub-visibility
        // methods are lowered; private methods are not accessible to importers
        // and must not leak into the emitted HirItem list.
        let mut method_symbols: Vec<String> = Vec::with_capacity(decl.methods.len());
        let mut method_names: Vec<String> = Vec::with_capacity(decl.methods.len());
        // W3.042 S2-S1: stash the resolved impl-target type so that `Self`
        // appearing in any method's parameter/return annotation (notably the
        // parser-injected `self: Self` for bare `self` / `var self` receivers)
        // lowers to the concrete type. The lowering of `target_type` happens
        // outside the per-method loop so it pays the cost once. Restore the
        // previous value (almost always `None`) on exit so nested
        // impl-lowering reentry — should it ever arise — does not leak state.
        let prior_self_ty = self.current_impl_self_ty.take();
        self.current_impl_self_ty = Some(self.lower_type(&decl.target_type));
        // For imported impl blocks, apply the same-module fn-name rewrite map
        // (bare helper name → mangled qualified symbol) to method bodies, just
        // as `lower_imported_fn_with_name` does for free functions. Methods
        // whose bodies call a private same-module helper that is NOT in the
        // rewrite closure are listed in `skip_methods` and dropped here; the
        // caller has already emitted a fail-closed diagnostic for them.
        let prior_imported_rewrites =
            imported.map(|imp| self.imported_fn_rewrites.replace(imp.rewrites.clone()));
        for method in &decl.methods {
            if pub_only && !method.visibility.is_pub() {
                continue;
            }
            if let Some(imp) = imported {
                if imp.skip_methods.contains(method.name.as_str()) {
                    continue;
                }
            }
            let symbol = crate::node::HirImplBlock::method_symbol(self_type_name, &method.name);
            // Pass impl-level type params so that methods of e.g. `impl<U> Trait for Wrapper<U>`
            // carry `U` as a `HirFn::type_params` entry — required for monomorphization
            // of generic-over-generic impl methods (W3.022 Stage 3).
            items.push(HirItem::Function(self.lower_fn_with_name_and_impl_params(
                method,
                &symbol,
                span.clone(),
                &type_params,
            )));
            method_symbols.push(symbol);
            method_names.push(method.name.clone());
        }

        // Lower trait default methods that are NOT overridden in this impl.
        // Each default body becomes its own `HirItem::Function` keyed by
        // `<SelfType>::<method>`, exactly like an explicit impl method.
        // `current_impl_self_ty` is already set to the concrete self type above
        // so `Self` inside the default body lowers to the correct concrete type.
        if let Some(tb) = &decl.trait_bound {
            let overridden: HashSet<&str> = decl.methods.iter().map(|m| m.name.as_str()).collect();
            if let Some(defaults) = self.trait_default_methods.get(&tb.name).cloned() {
                for default_method in &defaults {
                    if overridden.contains(default_method.name.as_str()) {
                        continue;
                    }
                    let fn_decl = trait_method_to_fn_decl(default_method);
                    let symbol =
                        crate::node::HirImplBlock::method_symbol(self_type_name, &fn_decl.name);
                    items.push(HirItem::Function(self.lower_fn_with_name_and_impl_params(
                        &fn_decl,
                        &symbol,
                        span.clone(),
                        &type_params,
                    )));
                    method_symbols.push(symbol);
                    method_names.push(fn_decl.name.clone());
                }
            }
        }

        if let Some(prev) = prior_imported_rewrites {
            self.imported_fn_rewrites = prev;
        }
        self.current_impl_self_ty = prior_self_ty;

        // Lower associated-type bindings to `ResolvedTy`s. Recorded as
        // metadata only — no runtime artefact (the type-erasure model in
        // use treats `type Item = T;` as a checker-only projection).
        let type_aliases: Vec<(String, ResolvedTy)> = decl
            .type_aliases
            .iter()
            .map(|alias| (alias.name.clone(), self.lower_type(&alias.ty)))
            .collect();

        items.push(HirItem::Impl(crate::node::HirImplBlock {
            id: self.ids.item(),
            node: self.ids.node(),
            trait_name: decl.trait_bound.as_ref().map(|b| b.name.clone()),
            self_type_name: self_type_name.clone(),
            type_params,
            type_aliases,
            method_symbols,
            method_names,
            span,
        }));
    }

    fn lower_fn_with_name(
        &mut self,
        func: &FnDecl,
        name: &str,
        span: std::ops::Range<usize>,
    ) -> HirFn {
        self.lower_fn_with_name_and_impl_params(func, name, span, &[])
    }

    fn lower_imported_fn_with_name(
        &mut self,
        func: &FnDecl,
        name: &str,
        span: std::ops::Range<usize>,
        rewrites: &HashMap<String, String>,
    ) -> HirFn {
        let previous_rewrites = self.imported_fn_rewrites.replace(rewrites.clone());
        let lowered = self.lower_fn_with_name(func, name, span);
        self.imported_fn_rewrites = previous_rewrites;
        lowered
    }

    /// Lower an imported free function while applying the `#[intrinsic]` floor
    /// policy (W5.005 / F1b, D343).
    ///
    /// `source_module` is the dotted module path (e.g. `std.mem`) used to
    /// reconstruct the checker's qualified intrinsic key
    /// (`scoped_module_item_name`, e.g. `std.mem.alloc`). The bare-name
    /// root-item path (`Item::Function` third pass) cannot reach floor
    /// modules — they are always imported — so the keying happens only here.
    ///
    /// Returns:
    /// - `Some(HirFn)` for ordinary functions (unchanged behaviour);
    /// - `Some(HirFn)` tagged with `intrinsic_id` for a **callable** floor
    ///   intrinsic (`mem.*`, catalog linkage `CalleeNameDispatchOnly`): the
    ///   function is kept so its mangled symbol stays in MIR's
    ///   `module_fn_names` and calls dispatch to it, while codegen synthesizes
    ///   the trampoline body from the tagged id (the bodyless placeholder MIR
    ///   is discarded by `lower_fn`);
    /// - `None` for a numeric intrinsic (`math.*`, linkage `CompilerIntrinsic`)
    ///   or an unknown key: these must NOT be emitted as a `HirItem::Function`.
    ///   Numeric intrinsics route through builtin method-rewrites; emitting a
    ///   dead empty-body shell would waste a symbol and (post-Slice-3b) trip
    ///   the codegen fail-closed authority on an id it cannot synthesize.
    ///
    /// Fail-closed: an intrinsic key absent from the stdlib catalog emits
    /// `UnknownIntrinsic` and is dropped, never lowered to a silent no-op.
    fn lower_imported_fn_floor_aware(
        &mut self,
        func: &FnDecl,
        qualified: &str,
        source_module: &str,
        span: std::ops::Range<usize>,
        rewrites: &HashMap<String, String>,
    ) -> Option<HirFn> {
        let intrinsic_key = self
            .intrinsic_declarations
            .get(&format!("{source_module}.{}", func.name))
            .cloned();
        let mut lowered = self.lower_imported_fn_with_name(func, qualified, span.clone(), rewrites);
        let Some(intrinsic_key) = intrinsic_key else {
            return Some(lowered);
        };
        let Some(entry) = crate::stdlib_catalog::entries()
            .iter()
            .find(|e| e.name == intrinsic_key)
        else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::UnknownIntrinsic {
                    fn_name: func.name.clone(),
                    intrinsic_key,
                },
                span,
                "intrinsic key not found in stdlib catalog; \
                 check the #[intrinsic(\"..\")] argument matches a catalog entry name",
            ));
            return None;
        };
        match entry.linkage {
            crate::stdlib_catalog::BuiltinLinkage::CalleeNameDispatchOnly => {
                lowered.intrinsic_id = Some(intrinsic_key);
                Some(lowered)
            }
            _ => None,
        }
    }

    /// Variant of `lower_fn_with_name` that prepends impl-block-level type
    /// parameters into the lowered `HirFn::type_params`. Used by
    /// `lower_impl_block` so that methods of `impl<U> Trait for Wrapper<U>`
    /// carry `U` and can be monomorphized per concrete instantiation.
    ///
    /// The combined `type_params` is `impl_type_params ++ method.type_params`,
    /// matching how `Wrapper<U>::show` is logically `fn show<U>(w: Wrapper<U>) -> ...`
    /// once the impl-level binder is flattened into the method.
    fn lower_fn_with_name_and_impl_params(
        &mut self,
        func: &FnDecl,
        name: &str,
        span: std::ops::Range<usize>,
        impl_type_params: &[String],
    ) -> HirFn {
        // Use the stable ItemId pre-allocated during the first pass.
        let id = self
            .fn_registry
            .get(name)
            .map_or_else(|| self.ids.item(), |entry| entry.id);

        self.push_scope();
        let mut params = Vec::new();
        for param in &func.params {
            let ty = self.lower_type(&param.ty);
            let binding = self.bind(param.name.clone(), ty, param.is_mutable, param.ty.1.clone());
            params.push(binding);
        }

        let source_return_ty = func
            .return_type
            .as_ref()
            .map_or(ResolvedTy::Unit, |ty| self.lower_type(ty));
        // A `gen fn`'s declared `-> T` is the yield element type, NOT the body's
        // return type. The body falls off the end (Unit) and the function value
        // is `Generator<Yield = T, Return = Unit>` — matching the checker's
        // registered signature (`Ty::generator(declared, Unit)`,
        // registration.rs). The body lowers through the same gen-body path the
        // `gen { ... }` block expression uses (`lower_gen_block`), so MIR/codegen
        // construction (`Terminator::Yield`, state-record synthesis) is shared.
        if func.is_generator {
            let (body, generator_ty) = self.lower_generator_fn_body(func, source_return_ty, &span);
            self.pop_scope();
            return HirFn {
                id,
                node: self.ids.node(),
                name: name.to_string(),
                type_params: Self::concat_type_params(impl_type_params, func),
                params,
                return_ty: generator_ty,
                body,
                span,
                is_generator: true,
                intrinsic_id: None,
            };
        }
        let var_self_receiver = if Self::is_var_self_method(func) {
            params.first().cloned()
        } else {
            None
        };
        let mut body = self.with_current_return_type(source_return_ty.clone(), |ctx| {
            ctx.lower_block(&func.body, &source_return_ty)
        });
        let return_ty = if let Some(receiver) = &var_self_receiver {
            let abi_return_ty =
                Self::var_self_dual_return_ty(source_return_ty.clone(), receiver.ty.clone());
            self.wrap_var_self_function_returns(&mut body, receiver, &abi_return_ty);
            abi_return_ty
        } else {
            source_return_ty
        };
        self.pop_scope();

        HirFn {
            id,
            node: self.ids.node(),
            name: name.to_string(),
            type_params: Self::concat_type_params(impl_type_params, func),
            params,
            return_ty,
            body,
            span,
            is_generator: false,
            intrinsic_id: None,
        }
    }

    /// Concatenate impl-level and method-level type parameters for a lowered
    /// function. A method MAY shadow an impl-level type param name; that is a
    /// checker-level concern, so here we just concatenate.
    fn concat_type_params(impl_type_params: &[String], func: &FnDecl) -> Vec<String> {
        let method_type_params: Vec<String> = func
            .type_params
            .as_ref()
            .map(|params| params.iter().map(|param| param.name.clone()).collect())
            .unwrap_or_default();
        let mut type_params: Vec<String> =
            Vec::with_capacity(impl_type_params.len() + method_type_params.len());
        type_params.extend(impl_type_params.iter().cloned());
        type_params.extend(method_type_params);
        type_params
    }

    /// Lower a `gen fn` body into a `(HirBlock, Generator<Yield, Return>)` pair.
    ///
    /// The declared `-> T` is the Yield element type, NOT the body return type:
    /// the body falls off the end (Unit) and the function value is
    /// `Generator<Yield = T, Return = Unit>`, matching the checker's registered
    /// signature (`Ty::generator(declared, Unit)`, registration.rs). The body
    /// lowers through the same `GenBlock` path the `gen { ... }` block expression
    /// uses, so MIR/codegen construction (`Terminator::Yield`, state-record
    /// synthesis) is shared between both surfaces.
    ///
    /// Caller owns the surrounding `push_scope`/`pop_scope`; this only lowers the
    /// body and wraps it. The returned block is a thin tail-only block whose tail
    /// is the `GenBlock` expression.
    fn lower_generator_fn_body(
        &mut self,
        func: &FnDecl,
        source_return_ty: ResolvedTy,
        span: &std::ops::Range<usize>,
    ) -> (HirBlock, ResolvedTy) {
        let yield_ty = source_return_ty;
        let gen_return_ty = ResolvedTy::Unit;
        self.generator_yield_tys.push(yield_ty.clone());
        let gen_body = self.with_current_return_type(gen_return_ty.clone(), |ctx| {
            ctx.lower_block(&func.body, &gen_return_ty)
        });
        self.generator_yield_tys.pop();

        let generator_ty = ResolvedTy::Named {
            name: "Generator".to_string(),
            args: vec![yield_ty.clone(), gen_return_ty.clone()],
            builtin: Some(hew_types::BuiltinType::Generator),
            is_opaque: false,
        };
        let gen_block_expr = HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::of_ty(&generator_ty, &self.type_classes),
            ty: generator_ty.clone(),
            intent: IntentKind::Read,
            kind: HirExprKind::GenBlock {
                body: gen_body,
                yield_ty,
                return_ty: gen_return_ty,
            },
            span: span.clone(),
        };
        let body = HirBlock {
            node: self.ids.node(),
            scope: self.ids.scope(),
            statements: Vec::new(),
            tail: Some(Box::new(gen_block_expr)),
            ty: generator_ty.clone(),
            span: span.clone(),
        };
        (body, generator_ty)
    }

    /// W3.030 Stage 1 — three layered checks on `#[resource]` close:
    ///
    ///   1. Inline `TypeBodyItem::Method` named `close` is rejected
    ///      unconditionally (Q-α-B): the inline form is a silent
    ///      trap today (E8 — body not lowered, drop dispatcher
    ///      emits an unresolvable symbol). Emit
    ///      `ResourceCloseSourceUnsupported`. Short-circuit further
    ///      checks for this type — exactly one named diagnostic
    ///      per `close` slot (review R-4 determinism contract).
    ///
    ///   2. Otherwise look for an inherent-impl `<T>::close`
    ///      (collected in `impl_close_methods` during the
    ///      pre-pre-pass). Presence here satisfies the broadened
    ///      `ResourceMissingClose` check (Q-α-B); a non-unit return
    ///      type triggers `ResourceCloseMustReturnUnit` (Q-β-C).
    ///
    ///   3. Otherwise no `close` is reachable from any surface;
    ///      emit `ResourceMissingClose` as before.
    fn check_resource_close_discipline(&mut self, decl: &TypeDecl, span: &Span) {
        let inline_close = decl
            .body
            .iter()
            .any(|item| matches!(item, TypeBodyItem::Method(m) if m.name == "close"));
        if inline_close {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::ResourceCloseSourceUnsupported {
                    name: decl.name.clone(),
                },
                span.clone(),
                "`#[resource]` types must declare `close` in a sibling \
                 inherent-impl block (`impl T { fn close(self) { ... } }`); \
                 the inline `type T { fn close(consuming self) ... }` \
                 surface is not lowered in v0.5 and would silently fail \
                 link-time drop dispatch",
            ));
            return;
        }
        if let Some(sig) = self.impl_close_methods.get(&decl.name) {
            if !sig.return_ty_unit {
                let display = sig.return_ty_display.clone();
                let decl_span = sig.decl_span.clone();
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::ResourceCloseMustReturnUnit {
                        name: decl.name.clone(),
                        return_ty: display.clone(),
                    },
                    decl_span,
                    format!(
                        "`#[resource]` type `{}` declares `close` returning \
                         `{display}`; the implicit drop contract dispatches \
                         `close` on every scope-exit path and only unit return \
                         is admitted in v0.5 — compose fallible cleanup via \
                         `defer` instead",
                        decl.name
                    ),
                ));
            }
            return;
        }
        self.diagnostics.push(HirDiagnostic::new(
            HirDiagnosticKind::ResourceMissingClose {
                name: decl.name.clone(),
            },
            span.clone(),
            "`#[resource]` type must declare `fn close(self) { ... }` in a \
             sibling inherent-impl block (`impl T { fn close(self) { ... } }`); \
             the implicit drop contract dispatches to this method on every \
             scope-exit path",
        ));
    }

    fn lower_type_decl(&mut self, decl: &TypeDecl, span: std::ops::Range<usize>) -> HirTypeDecl {
        // Generic resource/linear types are rejected — the type→class map is
        // keyed by name, not by instantiation. This rule belongs at the
        // checker boundary (LESSONS `checker-output-boundary`); HIR is the
        // first place the marker is durable, so the check lands here.
        if decl.resource_marker != AstResourceMarker::None && decl.type_params.is_some() {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::ResourceGenericUnsupported {
                    name: decl.name.clone(),
                },
                span.clone(),
                "`#[resource]` / `#[linear]` types cannot have type parameters in v0.5",
            ));
        }

        match decl.resource_marker {
            AstResourceMarker::Resource => {
                self.check_resource_close_discipline(decl, &span);
            }
            AstResourceMarker::Linear => {
                // `#[linear]` must declare at least one consuming method.
                if decl.consuming_methods.is_empty() {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::LinearNoConsumingMethods {
                            name: decl.name.clone(),
                        },
                        span.clone(),
                        "`#[linear]` type must declare at least one `consuming self` method; \
                         without one no exit path could exhaust a binding of this type",
                    ));
                }
            }
            AstResourceMarker::None => {}
        }

        // Carry the field set so dump-hir and future analysis have something
        // to reason about; methods are out of scope for v0.5 MIR lowering
        // and stay on the parser-side `TypeBodyItem::Method`.
        let mut fields = Vec::new();
        for item in &decl.body {
            if let TypeBodyItem::Field {
                name,
                ty,
                span: field_span,
                ..
            } = item
            {
                fields.push(HirField {
                    name: name.clone(),
                    ty: self.lower_type(ty),
                    default: None,
                    span: field_span.clone(),
                });
            }
            // `TypeBodyItem::Method` is not lowered into HIR in v0.5 — the
            // method-call expression form has no HIR/MIR lowering yet, so
            // method bodies cannot be exercised. Their *declared names* are
            // captured upstream as `TypeDecl.consuming_methods` and travel
            // on `HirTypeDecl.consuming_methods`.
        }

        // For enum-kind type decls, lower every variant (unit, tuple, struct)
        // into `HirVariant` carrying fully resolved payload types. MIR
        // consumes the resulting `variants` vec to populate `EnumLayout`
        // including per-variant `field_tys`. The index assigned here matches
        // the order the ctor pre-pass walks `TypeBodyItem::Variant` entries,
        // so the HIR registry key and MIR layout index agree (see lane plan
        // D2 — variant-index ordering is HIR-pre-pass authoritative).
        let mut variants: Vec<HirVariant> = Vec::new();
        if decl.kind == TypeDeclKind::Enum {
            for body_item in &decl.body {
                if let TypeBodyItem::Variant(v) = body_item {
                    let kind = match &v.kind {
                        VariantKind::Unit => HirVariantKind::Unit,
                        VariantKind::Tuple(tys) => HirVariantKind::Tuple(
                            tys.iter().map(|ty| self.lower_type(ty)).collect(),
                        ),
                        VariantKind::Struct(fields) => HirVariantKind::Struct(
                            fields
                                .iter()
                                .map(|(name, ty)| (name.clone(), self.lower_type(ty)))
                                .collect(),
                        ),
                    };
                    variants.push(HirVariant {
                        name: v.name.clone(),
                        kind,
                    });
                }
            }
        }

        // Reuse the stable ItemId pre-allocated during the record/
        // type-decl pre-pass. Falling back to a fresh id keeps
        // the path safe if the pre-pass ever skips a decl.
        let id = self
            .record_registry
            .get(&decl.name)
            .map_or_else(|| self.ids.item(), |entry| entry.id);
        let type_params: Vec<String> = decl
            .type_params
            .as_ref()
            .map_or(vec![], |ps| ps.iter().map(|p| p.name.clone()).collect());
        // `#[opaque]`-only handles classify as `BitCopy`: pointer-width,
        // copied wholesale by memcpy, no implicit drop. `#[resource]`/`#[linear]`
        // ownership (if also declared) takes precedence — representation and
        // ownership are orthogonal axes.
        let marker = if decl.is_opaque && decl.resource_marker == AstResourceMarker::None {
            ResourceMarker::BitCopy
        } else {
            ResourceMarker::from(decl.resource_marker)
        };
        HirTypeDecl {
            id,
            node: self.ids.node(),
            name: decl.name.clone(),
            marker,
            is_opaque: decl.is_opaque,
            is_indirect: decl.is_indirect,
            consuming_methods: decl.consuming_methods.clone(),
            type_params,
            fields,
            variants,
            span,
        }
    }

    /// Lower a `record` declaration into `HirRecordDecl`.
    ///
    /// Only named-form records produce a field list; tuple-form records have an
    /// empty field list (`HirRecordDecl.fields` is empty) because their
    /// constructor is a `Call` (`R(a, b)`) rather than a `StructInit`
    /// (`R { x: a, y: b }`). Tuple records are never looked up in the
    /// `record_field_orders` table — the MIR producer only handles named-form.
    fn lower_record_decl(
        &mut self,
        decl: &RecordDecl,
        span: std::ops::Range<usize>,
    ) -> HirRecordDecl {
        let type_params: Vec<String> = decl.type_params.as_ref().map_or(vec![], |params| {
            params.iter().map(|p| p.name.clone()).collect()
        });

        let fields: Vec<HirField> = match &decl.kind {
            RecordKind::Named(record_fields) => record_fields
                .iter()
                .map(|rf| HirField {
                    name: rf.name.clone(),
                    ty: self.lower_type(&rf.ty),
                    default: None,
                    span: rf.span.clone(),
                })
                .collect(),
            // Tuple records have no named fields; their constructor fn handles
            // positional argument binding.
            RecordKind::Tuple(_) => vec![],
        };

        // Reuse the stable ItemId pre-allocated during the record/
        // type-decl pre-pass. Falling back to a fresh id keeps
        // the path safe if the pre-pass ever skips a decl.
        let id = self
            .record_registry
            .get(&decl.name)
            .map_or_else(|| self.ids.item(), |entry| entry.id);
        HirRecordDecl {
            id,
            node: self.ids.node(),
            name: decl.name.clone(),
            type_params,
            fields,
            span,
        }
    }

    /// Lower a `supervisor` declaration to `HirSupervisorDecl`.
    ///
    /// Bodies (MIR producer wiring, codegen) are deferred to slices S-C/S-D.
    /// This function mirrors `lower_record_decl` in structure: structural lift
    /// only, no HIR expression lowering.
    fn lower_supervisor(&mut self, decl: &SupervisorDecl, span: Span) -> HirSupervisorDecl {
        let strategy = decl.strategy.map(|s| match s {
            SupervisorStrategy::OneForOne => HirSupervisorStrategy::OneForOne,
            SupervisorStrategy::OneForAll => HirSupervisorStrategy::OneForAll,
            SupervisorStrategy::RestForOne => HirSupervisorStrategy::RestForOne,
            SupervisorStrategy::SimpleOneForOne => HirSupervisorStrategy::SimpleOneForOne,
        });

        // Assign slot indices by partitioning children into static and pool spaces.
        // Each partition uses its own 0-based counter so the indices are disjoint,
        // matching the runtime layout (children[] for static, pool_slots[] for pool).
        let mut static_slot = 0u32;
        let mut pool_slot = 0u32;
        let children = decl
            .children
            .iter()
            .map(|child| {
                let slot_index = if child.is_pool {
                    let idx = pool_slot;
                    pool_slot += 1;
                    idx
                } else {
                    let idx = static_slot;
                    static_slot += 1;
                    idx
                };
                HirSupervisorChild {
                    name: child.name.clone(),
                    ty: child.actor_type.clone(),
                    restart_policy: child.restart.map(|r| match r {
                        RestartPolicy::Permanent => HirRestartPolicy::Permanent,
                        RestartPolicy::Transient => HirRestartPolicy::Transient,
                        RestartPolicy::Temporary => HirRestartPolicy::Temporary,
                    }),
                    wired_to: child.wired_to.clone(),
                    is_pool: child.is_pool,
                    slot_index,
                    // Lower named init args from AST `(field, expr)` pairs.
                    // These were previously silently dropped at this boundary.
                    init_args: child
                        .args
                        .iter()
                        .map(|(field_name, spanned_expr)| {
                            let hir_expr = self.lower_expr(spanned_expr, IntentKind::Read);
                            (field_name.clone(), hir_expr)
                        })
                        .collect(),
                    shutdown: child.shutdown.as_ref().map(|s| match s {
                        ShutdownDirective::Timeout(d) => HirShutdownDirective::Timeout(d.clone()),
                        ShutdownDirective::BrutalKill => HirShutdownDirective::BrutalKill,
                        ShutdownDirective::Infinity => HirShutdownDirective::Infinity,
                    }),
                }
            })
            .collect();

        HirSupervisorDecl {
            id: self.ids.item(),
            node: self.ids.node(),
            name: decl.name.clone(),
            strategy,
            // Decompose the fused `intensity` AST field into the two HIR fields
            // (max_restarts + window) the MIR/codegen/runtime path already uses.
            // The window duration string flows through verbatim; codegen
            // interprets the unit so duration parsing stays centralised there.
            max_restarts: decl.intensity.as_ref().map(|i| i.restarts),
            window: decl.intensity.as_ref().map(|i| i.window.clone()),
            children,
            span,
        }
    }

    fn register_machine_ctor_variant_metadata(
        &mut self,
        module_short: Option<&str>,
        decl: &MachineDecl,
    ) {
        let state_variants: Vec<HirVariant> = decl
            .states
            .iter()
            .map(|state| {
                let kind = if state.fields.is_empty() {
                    HirVariantKind::Unit
                } else {
                    HirVariantKind::Struct(
                        state
                            .fields
                            .iter()
                            .map(|(name, ty)| (name.clone(), self.lower_type(ty)))
                            .collect(),
                    )
                };
                HirVariant {
                    name: state.name.clone(),
                    kind,
                }
            })
            .collect();
        self.enum_variants_by_name
            .insert(decl.name.clone(), state_variants.clone());
        if let Some(module_short) = module_short {
            self.enum_variants_by_name
                .insert(format!("{module_short}.{}", decl.name), state_variants);
        }

        let event_type_name = format!("{}Event", decl.name);
        let event_variants: Vec<HirVariant> = decl
            .events
            .iter()
            .map(|event| {
                let kind = if event.fields.is_empty() {
                    HirVariantKind::Unit
                } else {
                    HirVariantKind::Struct(
                        event
                            .fields
                            .iter()
                            .map(|(name, ty)| (name.clone(), self.lower_type(ty)))
                            .collect(),
                    )
                };
                HirVariant {
                    name: event.name.clone(),
                    kind,
                }
            })
            .collect();
        self.enum_variants_by_name
            .insert(event_type_name.clone(), event_variants.clone());
        if let Some(module_short) = module_short {
            self.enum_variants_by_name
                .insert(format!("{module_short}.{event_type_name}"), event_variants);
        }
    }

    #[expect(
        clippy::too_many_lines,
        reason = "machine lowering has three distinct phases (structure, checks, assembly) \
                  that read more clearly as a single function than as multiple helpers"
    )]
    fn lower_machine(
        &mut self,
        decl: &MachineDecl,
        span: std::ops::Range<usize>,
    ) -> Option<HirMachineDecl> {
        // Collect declared state names up front; the machine-body diagnostic
        // filter uses this to recognise the semicolon-shorthand transition
        // body (`Expr::Identifier(target_state)`) and avoid leaking its
        // expected `UnresolvedSymbol` diagnostic, while leaving every other
        // unresolved identifier visible.
        let state_names: HashSet<String> = decl.states.iter().map(|s| s.name.clone()).collect();

        // Collect event names in declaration order so `Expr::MachineEmit` can
        // resolve its event_idx by position lookup during body lowering.
        let event_names: Vec<String> = decl.events.iter().map(|ev| ev.name.clone()).collect();

        // Pre-lower state field types and build the `current_machine_states`
        // descriptor table. This is used during transition-body and entry/exit-block
        // lowering to resolve bare state-name identifiers (`MachineVariantCtor`)
        // and `self.field` accesses (`MachineFieldAccess`) without re-reading the
        // AST during expression lowering.
        //
        // WHY HIR-side authority: the type checker does not produce side-table
        // entries for machine state-name identifier references or self-field
        // accesses inside transition bodies. HIR derives these types from the
        // machine declaration itself, which is local to this pass.
        let machine_state_descriptors: Vec<(String, Vec<HirField>)> = decl
            .states
            .iter()
            .map(|s| {
                let fields: Vec<HirField> = s
                    .fields
                    .iter()
                    .map(|(name, ty)| HirField {
                        name: name.clone(),
                        ty: self.lower_type(ty),
                        default: None,
                        span: ty.1.clone(),
                    })
                    .collect();
                (s.name.clone(), fields)
            })
            .collect();

        // Install machine context so nested `lower_expr` calls can resolve
        // state-name references and self-field accesses. Restored at the end
        // of `lower_machine` via `mem::replace`.
        let prev_machine_name = self.current_machine_name.replace(decl.name.clone());
        let prev_machine_states = self
            .current_machine_states
            .replace(machine_state_descriptors.clone());

        // Lower states.
        let mut hir_states = Vec::new();
        for state in &decl.states {
            let fields: Vec<HirField> = machine_state_descriptors
                .iter()
                .find(|(name, _)| name == &state.name)
                .map(|(_, fields)| fields.clone())
                .unwrap_or_default();

            // Shallow-scan the entry and exit blocks for field-assignment targets.
            // Body-level effect-parity checking still uses the AST summary
            // walk; the lowered HIR block below is structural substrate.
            let entry_writes = state
                .entry
                .as_ref()
                .map(collect_assigned_field_names)
                .unwrap_or_default();
            let exit_writes = state
                .exit
                .as_ref()
                .map(collect_assigned_field_names)
                .unwrap_or_default();

            // Lower entry/exit blocks. The filter drops only the explicitly
            // expected diagnostics for the machine-body forms not yet wired
            // through HIR (state-name identifier refs, `this`); emit now
            // lowers to `HirExprKind::MachineEmit` so it no longer needs
            // filtering here.
            let entry = state.entry.as_ref().map(|block| {
                self.lower_machine_block_filtered(block, &state_names, event_names.clone())
            });
            let exit = state.exit.as_ref().map(|block| {
                self.lower_machine_block_filtered(block, &state_names, event_names.clone())
            });

            hir_states.push(HirMachineState {
                name: state.name.clone(),
                fields,
                has_entry: state.entry.is_some(),
                has_exit: state.exit.is_some(),
                entry_writes,
                exit_writes,
                entry,
                exit,
                span: span.clone(),
            });
        }

        // Lower events.
        let hir_events: Vec<HirMachineEvent> = decl
            .events
            .iter()
            .map(|ev| {
                let fields = ev
                    .fields
                    .iter()
                    .map(|(name, ty)| HirField {
                        name: name.clone(),
                        ty: self.lower_type(ty),
                        default: None,
                        span: ty.1.clone(),
                    })
                    .collect();
                HirMachineEvent {
                    name: ev.name.clone(),
                    fields,
                    span: span.clone(),
                }
            })
            .collect();

        // Lower transitions — record names, guard presence, body writes,
        // and emitted event names (for static checks). The body is also
        // lowered to `HirExpr`; see `lower_machine_expr_filtered` for the
        // narrow diagnostic-filter contract.
        let mut hir_transitions: Vec<HirMachineTransition> =
            Vec::with_capacity(decl.transitions.len());
        for tr in &decl.transitions {
            let is_self_transition = tr.source_state == tr.target_state && tr.source_state != "_";
            let body_writes = collect_assigned_field_names_expr(&tr.body.0);
            // Set the source-state index so `lower_expr` can resolve `self.field`
            // accesses to `MachineFieldAccess` nodes. Wildcard source `_` has no
            // concrete state index, so leave it as `None` — `self.field` access
            // inside a wildcard transition body cannot resolve to a specific
            // variant's fields and will be rejected by the `MachineFieldAccess`
            // producer with a diagnostic.
            let src_state_idx = decl.states.iter().position(|s| s.name == tr.source_state);
            let prev_source_state = self.current_machine_source_state;
            self.current_machine_source_state = src_state_idx;
            let prev_transition_event = self.current_machine_transition_event.take();
            self.current_machine_transition_event = hir_events
                .iter()
                .position(|ev| ev.name == tr.event_name)
                .map(|idx| (idx, hir_events[idx].fields.clone()));
            let body =
                self.lower_machine_expr_filtered(&tr.body, &state_names, event_names.clone());
            // Lower the guard expression (if any) through the same
            // machine-body filter so the guard sees the same implicit
            // bindings (`self`, source-state alias, event-field aliases) the
            // body sees, and so machine-body walkers can recurse into it.
            // Without this, FC-P1-B (call-shape gates), FC-P1-A2/D/A3/E
            // (blocking-recv gates), and every future machine-body walker
            // would silently treat guarded transitions as if the guard
            // position contained no expressions at all.
            let guard = tr
                .guard
                .as_ref()
                .map(|g| self.lower_machine_expr_filtered(g, &state_names, event_names.clone()));
            self.current_machine_source_state = prev_source_state;
            self.current_machine_transition_event = prev_transition_event;
            // body_emits is derived from the lowered HIR body by walking
            // `HirExprKind::MachineEmit { event_idx, .. }` rather than the
            // AST summary shape, so emit expressions nested inside
            // conditionals or match arms are correctly detected.
            let body_emits = collect_hir_emitted_events(&body, &event_names);
            hir_transitions.push(HirMachineTransition {
                event_name: tr.event_name.clone(),
                source_state: tr.source_state.clone(),
                target_state: tr.target_state.clone(),
                guard,
                is_self_transition,
                reenter: tr.reenter,
                body_writes,
                body_emits,
                body,
                span: tr.body.1.clone(),
            });
        }

        // ── Static checks ────────────────────────────────────────────────────

        // 1. Exhaustiveness: every concrete (state, event) pair must have a
        //    transition, or a `default` arm must exist, or a wildcard source `_`
        //    covers it.
        if !decl.has_default {
            let mut missing: Vec<(String, String)> = Vec::new();
            for state in &decl.states {
                for event in &decl.events {
                    let covered = decl.transitions.iter().any(|tr| {
                        tr.event_name == event.name
                            && (tr.source_state == state.name || tr.source_state == "_")
                    });
                    if !covered {
                        missing.push((state.name.clone(), event.name.clone()));
                    }
                }
            }
            if !missing.is_empty() {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::MachineExhaustivenessViolation {
                        machine_name: decl.name.clone(),
                        missing,
                    },
                    span.clone(),
                    format!(
                        "machine `{}` does not handle all (state, event) pairs; \
                         add the missing transitions or a `default` arm",
                        decl.name
                    ),
                ));
                // Restore machine context before early return so the next
                // top-level item lowers in a clean context.
                self.current_machine_name = prev_machine_name;
                self.current_machine_states = prev_machine_states;
                return None;
            }
        }

        // 2. Self-transition @reenter rule: a non-empty self-loop body without
        //    @reenter is a compile error. Empty body OR @reenter are both OK.
        //    "Empty" means the body resolves to `Expr::Identifier(target_state)`
        //    (the no-body semicolon shorthand) or an `Expr::Block` with no stmts
        //    and no trailing expression.
        for tr in decl.transitions.iter().zip(hir_transitions.iter()) {
            let (ast_tr, hir_tr) = tr;
            if !hir_tr.is_self_transition || hir_tr.reenter {
                continue;
            }
            let body_is_empty = is_empty_self_body(&ast_tr.body.0, &hir_tr.target_state);
            if !body_is_empty {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::MachineSelfTransitionNeedsReenter {
                        machine_name: decl.name.clone(),
                        state_name: hir_tr.source_state.clone(),
                        event_name: hir_tr.event_name.clone(),
                    },
                    hir_tr.span.clone(),
                    format!(
                        "self-transition `on {event}` in state `{state}` has a non-empty body \
                         but is not annotated `@reenter`; annotate with `@reenter` to opt in to \
                         Mealy re-entry semantics, or remove the body",
                        event = hir_tr.event_name,
                        state = hir_tr.source_state,
                    ),
                ));
            }
        }

        // 3. Effect-parity: a transition body that writes a field also written
        //    by the *target* state's `entry` block or the *source* state's `exit`
        //    block creates ambiguous initialization/teardown order.
        for tr in &hir_transitions {
            if tr.body_writes.is_empty() {
                continue;
            }
            // Check target entry conflict.
            if let Some(target) = hir_states.iter().find(|s| s.name == tr.target_state) {
                for field in &tr.body_writes {
                    if let Some((_, entry_assign_span)) =
                        target.entry_writes.iter().find(|(n, _)| n == field)
                    {
                        self.diagnostics.push(
                            HirDiagnostic::new(
                                HirDiagnosticKind::MachineEffectParityViolation {
                                    machine_name: decl.name.clone(),
                                    state_name: tr.target_state.clone(),
                                    field_name: field.clone(),
                                    transition_event: tr.event_name.clone(),
                                    is_entry_conflict: true,
                                },
                                tr.span.clone(),
                                format!(
                                    "transition `on {}` body and state `{}` entry block both \
                                     write field `{}`; remove the write from one site",
                                    tr.event_name, tr.target_state, field
                                ),
                            )
                            .with_secondary_spans(vec![(
                                entry_assign_span.clone(),
                                format!(
                                    "state `{}` entry block assigns `{}` here",
                                    tr.target_state, field
                                ),
                            )]),
                        );
                    }
                }
            }
            // Check source exit conflict.
            if let Some(source) = hir_states.iter().find(|s| s.name == tr.source_state) {
                for field in &tr.body_writes {
                    if let Some((_, exit_assign_span)) =
                        source.exit_writes.iter().find(|(n, _)| n == field)
                    {
                        self.diagnostics.push(
                            HirDiagnostic::new(
                                HirDiagnosticKind::MachineEffectParityViolation {
                                    machine_name: decl.name.clone(),
                                    state_name: tr.source_state.clone(),
                                    field_name: field.clone(),
                                    transition_event: tr.event_name.clone(),
                                    is_entry_conflict: false,
                                },
                                tr.span.clone(),
                                format!(
                                    "transition `on {}` body and state `{}` exit block both \
                                     write field `{}`; remove the write from one site",
                                    tr.event_name, tr.source_state, field
                                ),
                            )
                            .with_secondary_spans(vec![(
                                exit_assign_span.clone(),
                                format!(
                                    "state `{}` exit block assigns `{}` here",
                                    tr.source_state, field
                                ),
                            )]),
                        );
                    }
                }
            }
        }

        // 4. Emit-cycle: `on E` transition that directly emits `E` would
        //    immediately re-trigger its own handler.
        for tr in &hir_transitions {
            if tr.body_emits.contains(&tr.event_name) {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::MachineEmitCycle {
                        machine_name: decl.name.clone(),
                        event_name: tr.event_name.clone(),
                    },
                    tr.span.clone(),
                    format!(
                        "transition `on {}` emits `{}` which immediately re-triggers itself; \
                         rename the emitted event or remove the emit",
                        tr.event_name, tr.event_name
                    ),
                ));
            }
        }

        // 5. Emits-manifest cross-check: when the machine declares an
        //    `emits { … }` header, every event named by an `emit` statement in
        //    any transition body must appear in that manifest. The manifest is
        //    an auditable allowlist of permitted Mealy outputs.
        if !decl.emits.is_empty() {
            for tr in &hir_transitions {
                for emitted in &tr.body_emits {
                    if !decl.emits.contains(emitted) {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::MachineEmitNotInManifest {
                                machine_name: decl.name.clone(),
                                event_name: emitted.clone(),
                            },
                            tr.span.clone(),
                            format!(
                                "transition `on {}` emits `{}`, which is not declared in the \
                                 `emits {{ … }}` manifest of machine `{}`; add `{}` to `emits` \
                                 or remove the emit",
                                tr.event_name, emitted, decl.name, emitted
                            ),
                        ));
                    }
                }
            }
        }

        // Fail-closed: if any diagnostic was pushed for this machine, abort.
        // (Effect-parity, self-transition, and emit-cycle diagnostics are not
        // return-None by themselves but we abort to avoid a partially-valid
        // machine in HIR.)
        let has_machine_errors = self.diagnostics.iter().any(|d| {
            matches!(
                &d.kind,
                HirDiagnosticKind::MachineSelfTransitionNeedsReenter { machine_name, .. }
                | HirDiagnosticKind::MachineEffectParityViolation { machine_name, .. }
                | HirDiagnosticKind::MachineEmitCycle { machine_name, .. }
                | HirDiagnosticKind::MachineEmitNotInManifest { machine_name, .. }
                if machine_name == &decl.name
            )
        });
        if has_machine_errors {
            // Restore machine context before early return.
            self.current_machine_name = prev_machine_name;
            self.current_machine_states = prev_machine_states;
            return None;
        }

        // Restore machine context before returning.
        self.current_machine_name = prev_machine_name;
        self.current_machine_states = prev_machine_states;

        // Lower trait bounds declared on the machine's type parameters.
        // Both the inline `<T: Trait>` form and the trailing
        // `where T: Trait` clause are flattened into a single
        // `Vec<HirMachineBound>` in authored order: inline bounds
        // first (in the order their owning `TypeParam` appears, with
        // each param's `bounds` walked in their authored order), then
        // where-clause predicates. Per Q230-B the carrier is flat —
        // duplicate `(param, trait)` pairs from inline+where are
        // preserved at this layer with distinct `origin`s and dedup'd
        // downstream by the checker's per-machine bound table. The
        // span on `WhereOrigin::WhereClause` is the `WherePredicate.ty`
        // span (the LHS of the predicate), used by downstream
        // diagnostics that want to point at the predicate's source.
        let mut type_param_bounds: Vec<crate::node::HirMachineBound> = Vec::new();
        for tp in &decl.type_params {
            for tb in &tp.bounds {
                let trait_bound = self.lower_machine_trait_bound(tb);
                type_param_bounds.push(crate::node::HirMachineBound {
                    param: tp.name.clone(),
                    trait_bound,
                    origin: crate::node::WhereOrigin::Inline,
                });
            }
        }
        if let Some(where_clause) = &decl.where_clause {
            for predicate in &where_clause.predicates {
                // The LHS `ty` of a where predicate on a machine
                // type-param is parsed as a `TypeExpr::Named { name, .. }`
                // where `name` is the bare type-param symbol; this
                // matches the checker's `validate_machine_type_param_bounds`
                // contract that rejects anything else as `UndefinedType`.
                // Extract the param name; fall back to the displayed
                // form for resilience when the upstream parser admits
                // a non-Named LHS that has slipped past the checker
                // (defensive — should be unreachable in well-formed
                // programs).
                let param_name = match &predicate.ty.0 {
                    hew_parser::ast::TypeExpr::Named { name, .. } => name.clone(),
                    other => format!("{other:?}"),
                };
                let lhs_span = predicate.ty.1.clone();
                for tb in &predicate.bounds {
                    let trait_bound = self.lower_machine_trait_bound(tb);
                    type_param_bounds.push(crate::node::HirMachineBound {
                        param: param_name.clone(),
                        trait_bound,
                        origin: crate::node::WhereOrigin::WhereClause(lhs_span.clone()),
                    });
                }
            }
        }

        Some(HirMachineDecl {
            id: self.ids.item(),
            node: self.ids.node(),
            name: decl.name.clone(),
            type_params: decl.type_params.iter().map(|p| p.name.clone()).collect(),
            type_param_bounds,
            states: hir_states,
            events: hir_events,
            transitions: hir_transitions,
            has_default: decl.has_default,
            span,
        })
    }

    /// Lower a parser `TraitBound` (used in a machine's type-param
    /// bound list or where-clause predicate) into the cross-layer
    /// `ResolvedTraitBound` carrier. Trait `args` and
    /// `assoc_type_bindings` are recursively lowered via the existing
    /// `lower_type` seam — there is no separate HIR-side trait-arg
    /// resolver. Returning `ResolvedTraitBound` directly (rather than
    /// a forked HIR-local shape) reuses the carrier `dyn Trait`
    /// coercions and trait-object lowering already commit to.
    fn lower_machine_trait_bound(
        &mut self,
        tb: &hew_parser::ast::TraitBound,
    ) -> hew_types::ResolvedTraitBound {
        let args: Vec<ResolvedTy> = tb
            .type_args
            .as_ref()
            .map(|args| args.iter().map(|a| self.lower_type(a)).collect())
            .unwrap_or_default();
        let assoc_bindings: Vec<(String, ResolvedTy)> = tb
            .assoc_type_bindings
            .iter()
            .map(|b| (b.name.clone(), self.lower_type(&b.ty)))
            .collect();
        hew_types::ResolvedTraitBound {
            trait_name: tb.name.clone(),
            args,
            assoc_bindings,
        }
    }

    /// Lower a machine transition body expression to `HirExpr` so MIR /
    /// codegen has a typed-HIR tree to consume. The body's surface still
    /// uses constructs that aren't yet wired through HIR — direct
    /// state-name references (the semicolon-shorthand body
    /// `Expr::Identifier(target_state)`) and `Expr::This`. Those produce
    /// specific, expected diagnostics that the AST-summary walks
    /// (`body_writes` / `body_emits`) and the per-machine static checks
    /// (exhaustiveness, self-transition rules, effect-parity, emit-cycle)
    /// already cover; this helper filters out *only those exact* diagnostics
    /// whose span matches an allowlisted construct in the AST. Unrelated
    /// diagnostics — unresolved user symbols, type mismatches, malformed
    /// checker output, etc. — flow through unchanged so a buggy machine body
    /// still fails closed.
    ///
    /// `event_names` is the ordered list of event names for the enclosing
    /// machine (corresponding to `HirMachineDecl::events`). Set as
    /// `current_machine_events` during lowering so `Expr::MachineEmit` can
    /// resolve its `event_idx`.
    fn lower_machine_expr_filtered(
        &mut self,
        body: &Spanned<Expr>,
        state_names: &HashSet<String>,
        event_names: Vec<String>,
    ) -> HirExpr {
        let mut allowlist = MachineBodyAllowlist::default();
        walk_expr_for_machine_allowlist(body, state_names, &mut allowlist);
        let diag_snapshot = self.diagnostics.len();
        self.push_scope();
        self.bind_machine_transition_implicits(body.1.clone());
        let prev_events = self.current_machine_events.replace(event_names);
        let expr = self.lower_expr(body, IntentKind::Read);
        self.current_machine_events = prev_events;
        self.pop_scope();
        self.retain_or_drop_machine_body_diags(diag_snapshot, &allowlist);
        expr
    }

    /// Lower a machine state's `entry { ... }` / `exit { ... }` block,
    /// applying the same allowlist filter as `lower_machine_expr_filtered`.
    ///
    /// `event_names` is the ordered list of event names for the enclosing
    /// machine; see `lower_machine_expr_filtered` for details.
    fn lower_machine_block_filtered(
        &mut self,
        block: &Block,
        state_names: &HashSet<String>,
        event_names: Vec<String>,
    ) -> HirBlock {
        let mut allowlist = MachineBodyAllowlist::default();
        walk_block_for_machine_allowlist(block, state_names, &mut allowlist);
        let diag_snapshot = self.diagnostics.len();
        let prev_events = self.current_machine_events.replace(event_names);
        let lowered = self.lower_block(block, &ResolvedTy::Unit);
        self.current_machine_events = prev_events;
        self.retain_or_drop_machine_body_diags(diag_snapshot, &allowlist);
        lowered
    }

    /// Filter diagnostics produced since `snapshot_len`: drop only those
    /// whose `(kind, span)` matches an entry in `allowlist`. Anything else
    /// — including diagnostics with the same *kind* but a different span,
    /// or with the same span but a different kind — is preserved.
    fn retain_or_drop_machine_body_diags(
        &mut self,
        snapshot_len: usize,
        allowlist: &MachineBodyAllowlist,
    ) {
        if snapshot_len >= self.diagnostics.len() {
            return;
        }
        let tail: Vec<_> = self.diagnostics.drain(snapshot_len..).collect();
        for diag in tail {
            if !allowlist.permits(&diag) {
                self.diagnostics.push(diag);
            }
        }
    }

    /// Lower an `actor` declaration into `HirActorDecl`, including executable
    /// bodies for init blocks, receive handlers, methods, and lifecycle hooks.
    fn lower_actor(&mut self, decl: &ActorDecl, span: Span) -> HirActorDecl {
        let state_fields: Vec<HirField> = decl
            .fields
            .iter()
            .map(|f| HirField {
                name: f.name.clone(),
                ty: self.lower_type(&f.ty),
                default: f
                    .default
                    .as_ref()
                    .map(|default| self.lower_expr(default, IntentKind::Read)),
                span: f.ty.1.clone(),
            })
            .collect();

        let init = decl.init.as_ref().map(|init| {
            let (params, body) =
                self.lower_actor_body(&state_fields, &init.params, &init.body, &ResolvedTy::Unit);
            HirActorInit { params, body }
        });

        let receive_handlers: Vec<HirActorReceiveFn> = decl
            .receive_fns
            .iter()
            .map(|rf| self.lower_actor_receive_fn(rf, &state_fields))
            .collect();

        let (methods, lifecycle_hooks) = self.partition_actor_methods(&decl.methods, &state_fields);

        HirActorDecl {
            id: self.ids.item(),
            node: self.ids.node(),
            name: decl.name.clone(),
            state_fields,
            init,
            receive_handlers,
            methods,
            lifecycle_hooks,
            max_heap_bytes: decl.max_heap_bytes,
            is_isolated: decl.is_isolated,
            mailbox_capacity: decl.mailbox_capacity,
            overflow_policy: decl.overflow_policy.clone(),
            cycle_capable: self.cycle_capable_actors.contains(&decl.name),
            protocol_descriptor: self.actor_protocol_descriptors.get(&decl.name).cloned(),
            span,
        }
    }

    fn lower_actor_body(
        &mut self,
        state_fields: &[HirField],
        params: &[Param],
        body: &Block,
        expected_ty: &ResolvedTy,
    ) -> (Vec<HirBinding>, HirBlock) {
        let saved_scope_depth = self.scope_depth;
        self.scope_depth = 0;
        self.push_scope();
        for field in state_fields {
            self.bind(
                field.name.clone(),
                field.ty.clone(),
                true,
                field.span.clone(),
            );
        }
        let params = params
            .iter()
            .map(|p| {
                let ty = self.lower_type(&p.ty);
                self.bind(p.name.clone(), ty, p.is_mutable, p.ty.1.clone())
            })
            .collect();
        let body = self.with_current_return_type(expected_ty.clone(), |ctx| {
            ctx.lower_block(body, expected_ty)
        });
        self.pop_scope();
        self.scope_depth = saved_scope_depth;
        (params, body)
    }

    fn lower_actor_receive_fn(
        &mut self,
        rf: &ReceiveFnDecl,
        state_fields: &[HirField],
    ) -> HirActorReceiveFn {
        let return_ty = rf
            .return_type
            .as_ref()
            .map_or(ResolvedTy::Unit, |ty| self.lower_type(ty));
        let body_expected_ty = if rf.is_generator {
            ResolvedTy::Unit
        } else {
            return_ty.clone()
        };
        let (params, body) =
            self.lower_actor_body(state_fields, &rf.params, &rf.body, &body_expected_ty);
        let state_guard = match self
            .actor_handler_state_guards
            .get(&SpanKey::from(&rf.span))
            .copied()
        {
            Some(ActorStateGuard::Exclusive) => HirActorStateGuard::Exclusive,
            None => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::ActorStateGuardMissing {
                        handler: rf.name.clone(),
                    },
                    rf.span.clone(),
                    "missing checker-owned actor-state guard fact",
                ));
                HirActorStateGuard::Exclusive
            }
        };
        let every_ns = rf
            .attributes
            .iter()
            .find(|a| a.name == "every")
            .and_then(|a| a.args.first())
            .and_then(AttributeArg::as_duration_ns);
        HirActorReceiveFn {
            name: rf.name.clone(),
            is_generator: rf.is_generator,
            params,
            return_ty,
            body,
            state_guard,
            every_ns,
            span: rf.span.clone(),
        }
    }

    /// Partition an actor's `methods` vec into plain methods and lifecycle
    /// hooks (`#[on(start|stop|crash|upgrade)]`). The checker has already
    /// validated hook-kind spellings and uniqueness; HIR consumes the
    /// post-validation shape and silently ignores methods whose `#[on(...)]`
    /// attribute is malformed (the checker has emitted a diagnostic and the
    /// HIR consumer should not see the entry as a lifecycle hook).
    fn partition_actor_methods(
        &mut self,
        methods: &[FnDecl],
        state_fields: &[HirField],
    ) -> (Vec<HirActorMethod>, Vec<HirLifecycleHook>) {
        let mut plain = Vec::new();
        let mut hooks = Vec::new();
        for method in methods {
            let return_ty = method
                .return_type
                .as_ref()
                .map_or(ResolvedTy::Unit, |ty| self.lower_type(ty));
            let (params, body) =
                self.lower_actor_body(state_fields, &method.params, &method.body, &return_ty);
            let hook_attr = method.attributes.iter().find(|a| a.name == "on");
            let hook_kind = hook_attr
                .and_then(|a| a.args.first())
                .map(AttributeArg::as_str)
                .and_then(|k| match k {
                    "start" => Some(HirLifecycleHookKind::Start),
                    "stop" => Some(HirLifecycleHookKind::Stop),
                    "crash" => Some(HirLifecycleHookKind::Crash),
                    "upgrade" => Some(HirLifecycleHookKind::Upgrade),
                    _ => None,
                });
            match hook_kind {
                Some(kind) => hooks.push(HirLifecycleHook {
                    kind,
                    name: method.name.clone(),
                    params,
                    return_ty,
                    body,
                    span: method.fn_span.clone(),
                }),
                None => plain.push(HirActorMethod {
                    name: method.name.clone(),
                    params,
                    return_ty,
                    body,
                    span: method.fn_span.clone(),
                }),
            }
        }
        (plain, hooks)
    }

    fn lower_block(&mut self, block: &Block, expected_ty: &ResolvedTy) -> HirBlock {
        // Nested control-flow bodies (while, loop, if, match) must not
        // inherit the parent's `scope_depth`. The `scope_depth > 0` guard
        // in `lower_expression_stmt_kind` is intended to intercept only the
        // DIRECT statement-expressions of a `scope { }` body (handled by
        // `lower_scope_block`). Resetting to 0 here ensures that a call
        // inside `scope { while { call() } }` is NOT treated as a spawned
        // task — only the top-level scope statements are spawn candidates.
        let saved_scope_depth = self.scope_depth;
        self.scope_depth = 0;
        self.push_scope();
        let scope = self.ids.scope();
        let prev_scope_id = std::mem::replace(&mut self.current_scope_id, scope);
        let mut statements = Vec::new();
        for (stmt, span) in &block.stmts {
            statements.extend(self.lower_stmt_multi(stmt, span.clone(), expected_ty.clone()));
        }
        let tail = block
            .trailing_expr
            .as_ref()
            .map(|expr| Box::new(self.lower_expr(expr, IntentKind::Read)));
        let ty = tail
            .as_ref()
            .map_or(ResolvedTy::Unit, |expr| expr.ty.clone());
        self.current_scope_id = prev_scope_id;
        self.pop_scope();
        self.scope_depth = saved_scope_depth;

        HirBlock {
            node: self.ids.node(),
            scope,
            statements,
            tail,
            ty,
            span: 0..0,
        }
    }

    /// Lower a statement, returning zero or more `HirStmt`s.
    ///
    /// Most statements produce exactly one `HirStmt` (delegated to `lower_stmt`).
    /// `let (a, b) = expr;` (Q33 tuple-let) produces:
    ///   1. `let __tuple_N = expr;`    — binds the tuple value to a synthetic temp
    ///   2. `let a = __tuple_N.0;`     — per-element projection (as many as elements)
    ///   3. `let b = __tuple_N.1;`
    ///
    /// The element projections use a synthetic `HirExprKind::TupleIndex` node.
    /// Downstream MIR lowering handles tuple projections in the `Expr::Call` return
    /// path for `duplex_pair`.
    #[expect(
        clippy::too_many_lines,
        reason = "tuple-let expansion has three phases (validation, temp-bind, per-element loop) \
                  that read more clearly as a single function; splitting would obscure the \
                  invariant that temp-bind and per-element refs share the same temp_name"
    )]
    fn lower_stmt_multi(
        &mut self,
        stmt: &Stmt,
        span: std::ops::Range<usize>,
        return_ty: ResolvedTy,
    ) -> Vec<HirStmt> {
        // Tuple-let: `let (a, b, ...) = value_expr;`
        if let Stmt::Let {
            pattern,
            ty: annotation,
            value: Some(value_expr),
        } = stmt
        {
            if let Pattern::Tuple(element_patterns) = &pattern.0 {
                // Lower the tuple value once into a synthetic temp binding.
                let tuple_val = self.lower_expr(value_expr, IntentKind::Consume);
                let tuple_ty = tuple_val.ty.clone();

                // Validate the pattern element count against the inferred tuple type.
                let element_tys: Vec<ResolvedTy> = if let ResolvedTy::Tuple(elems) = &tuple_ty {
                    if elems.len() != element_patterns.len() {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::NotYetImplemented {
                                construct: format!(
                                    "tuple pattern with {} elements for tuple with {} elements",
                                    element_patterns.len(),
                                    elems.len()
                                ),
                                owning_pass: "type-checker".to_string(),
                            },
                            span.clone(),
                            "tuple pattern element count does not match tuple value arity",
                        ));
                        return vec![HirStmt {
                            node: self.ids.node(),
                            kind: HirStmtKind::Expr(
                                self.unsupported_expr(span, "tuple arity mismatch"),
                            ),
                            span: 0..0,
                        }];
                    }
                    elems.clone()
                } else if annotation.is_none() {
                    // Type not yet resolved — use Unit for each element (diagnostic
                    // already emitted by the checker; HIR does best-effort lowering).
                    vec![ResolvedTy::Unit; element_patterns.len()]
                } else {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::NotYetImplemented {
                            construct: "tuple pattern on non-tuple value".to_string(),
                            owning_pass: "type-checker".to_string(),
                        },
                        span.clone(),
                        "tuple-let pattern requires the right-hand side to have a tuple type",
                    ));
                    return vec![HirStmt {
                        node: self.ids.node(),
                        kind: HirStmtKind::Expr(
                            self.unsupported_expr(span, "tuple pattern on non-tuple"),
                        ),
                        span: 0..0,
                    }];
                };

                // Synthetic temp name — unlikely to collide with user identifiers.
                let temp_name = format!("__tuple_{}", self.ids.binding().0);
                let temp_binding =
                    self.bind(temp_name.clone(), tuple_ty.clone(), false, span.clone());
                // Capture the binding id before `temp_binding` is moved into
                // the `HirStmt` below.  MIR lowering's `TupleIndex` arm needs
                // `ResolvedRef::Binding(temp_id)` to look up the proxy Place in
                // `binding_locals`; `Unresolved` would return `None` and break
                // the `tuple_decomp` lookup for non-BitCopy element types.
                let temp_id = temp_binding.id;
                let temp_stmt = HirStmt {
                    node: self.ids.node(),
                    kind: HirStmtKind::Let(temp_binding, Some(tuple_val)),
                    span: span.clone(),
                };

                let mut stmts = vec![temp_stmt];

                // Per-element projection lets.
                for (idx, (elem_pat, elem_ty)) in
                    element_patterns.iter().zip(element_tys).enumerate()
                {
                    let elem_name = match &elem_pat.0 {
                        Pattern::Identifier(n) => n.clone(),
                        Pattern::Wildcard => format!("_{idx}"),
                        _ => {
                            // Nested tuple / constructor patterns are out of scope.
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::NotYetImplemented {
                                    construct: "nested pattern in tuple-let".to_string(),
                                    owning_pass: "pattern-matching".to_string(),
                                },
                                elem_pat.1.clone(),
                                "only identifier and wildcard patterns are supported \
                                 inside tuple-let in v0.5",
                            ));
                            format!("__unsupported_{idx}")
                        }
                    };

                    // Build a TupleIndex expression: `__tuple_N.<idx>`.
                    // Use `ResolvedRef::Binding(temp_id)` so MIR can resolve
                    // the proxy local from `binding_locals` and recover the
                    // per-element `Place` via `tuple_decomp`.
                    let temp_ref = HirExpr {
                        node: self.ids.node(),
                        site: self.ids.site(),
                        value_class: ValueClass::of_ty(&tuple_ty, &self.type_classes),
                        ty: tuple_ty.clone(),
                        intent: IntentKind::Read,
                        kind: HirExprKind::BindingRef {
                            name: temp_name.clone(),
                            resolved: ResolvedRef::Binding(temp_id),
                        },
                        span: span.clone(),
                    };
                    let projection = HirExpr {
                        node: self.ids.node(),
                        site: self.ids.site(),
                        value_class: ValueClass::of_ty(&elem_ty, &self.type_classes),
                        ty: elem_ty.clone(),
                        intent: IntentKind::Read,
                        kind: HirExprKind::TupleIndex {
                            tuple: Box::new(temp_ref),
                            index: idx,
                        },
                        span: elem_pat.1.clone(),
                    };

                    let elem_binding = self.bind(elem_name, elem_ty, false, elem_pat.1.clone());
                    stmts.push(HirStmt {
                        node: self.ids.node(),
                        kind: HirStmtKind::Let(elem_binding, Some(projection)),
                        span: elem_pat.1.clone(),
                    });
                }

                return stmts;
            }
        }

        // Non-tuple statements: delegate to the single-statement path.
        vec![self.lower_stmt(stmt, span, return_ty)]
    }

    fn lower_expression_stmt_kind(&mut self, expr: &Spanned<Expr>) -> HirStmtKind {
        // Inside a scope{} body, statement-expression calls are child-task
        // spawns (TI-1). Outside scope{} bodies all calls are synchronous
        // (TI-3). The TI-1 rewrite only applies when the expression is a
        // direct call — nested calls inside sub-expressions remain sync.
        //
        // Mark this as statement position before lowering so that
        // `lower_expr`'s `Expr::Await` arm can enforce TI-4 (await is
        // only legal in statement-expression position, not as a
        // sub-expression). The flag is consumed by `mem::replace` at the
        // top of `lower_expr`, so recursive calls see `false`.
        self.statement_position = true;
        if self.scope_depth > 0 {
            if let Expr::Call { .. } = &expr.0 {
                let spawned = self.lower_spawned_call(expr);
                HirStmtKind::Expr(spawned)
            } else {
                HirStmtKind::Expr(self.lower_expr(expr, IntentKind::Read))
            }
        } else {
            HirStmtKind::Expr(self.lower_expr(expr, IntentKind::Read))
        }
    }

    /// True when the `await`'s inner expression is a suspending typed-stream
    /// `recv()` over a `Stream<bytes>` — i.e. the checker wired the method call
    /// to the `hew_stream_next_bytes` runtime symbol. `await stream.recv()` is a
    /// bindable, value-producing await (NEW-7): it lowers to the inner recv call
    /// whose Option<bytes> result the MIR `SuspendingStreamNext` resume edge
    /// binds. (Only the canonical bytes surface suspends; `Stream<string>` recv
    /// keeps the blocking path and is not an awaitable here.)
    fn is_stream_recv_await(&self, inner_key: &SpanKey) -> bool {
        matches!(
            self.method_call_rewrites.get(inner_key),
            Some(MethodCallRewrite::RewriteToFunction { c_symbol, .. })
                if c_symbol == "hew_stream_next_bytes"
        )
    }

    /// True when the `await`'s inner expression is a suspending `std::channel`
    /// `recv()` over a `Receiver<T>` — i.e. the checker wired the method call to
    /// the `hew_channel_recv` (string) / `hew_channel_recv_int` (int) runtime
    /// symbol. `await rx.recv()` is a bindable, value-producing await (NEW-4):
    /// it lowers to the inner recv call whose `Option<T>` result the MIR
    /// `SuspendingChannelRecv` resume edge binds (or the blocking call for a
    /// context-free caller). `try_recv` never suspends and is not awaitable here.
    fn is_channel_recv_await(&self, inner_key: &SpanKey) -> bool {
        matches!(
            self.method_call_rewrites.get(inner_key),
            Some(MethodCallRewrite::RewriteToFunction { c_symbol, .. })
                if c_symbol == "hew_channel_recv" || c_symbol == "hew_channel_recv_int"
        )
    }

    /// `Some(true)` when the method call at `key` is a channel `recv` over an
    /// int element (`hew_channel_recv_int`), `Some(false)` for the string
    /// element (`hew_channel_recv`), `None` when it is not a channel recv.
    fn channel_recv_elem_is_int(&self, key: &SpanKey) -> Option<bool> {
        match self.method_call_rewrites.get(key) {
            Some(MethodCallRewrite::RewriteToFunction { c_symbol, .. })
                if c_symbol == "hew_channel_recv_int" =>
            {
                Some(true)
            }
            Some(MethodCallRewrite::RewriteToFunction { c_symbol, .. })
                if c_symbol == "hew_channel_recv" =>
            {
                Some(false)
            }
            _ => None,
        }
    }

    /// True when the `await`'s inner expression is a suspending typed-stream
    /// `send()` over a `Sink<bytes>` — i.e. the checker wired the method call to
    /// the `hew_sink_write_bytes` runtime symbol. `await sink.send(x)` is a
    /// unit-returning statement-position await (NEW-7): it lowers to the inner
    /// send call whose MIR `SuspendingStreamSend` suspends on a full ring.
    fn is_stream_send_await(&self, inner_key: &SpanKey) -> bool {
        matches!(
            self.method_call_rewrites.get(inner_key),
            Some(MethodCallRewrite::RewriteToFunction { c_symbol, .. })
                if c_symbol == "hew_sink_write_bytes"
        )
    }

    #[allow(
        clippy::too_many_lines,
        reason = "single large match on stmt variants; splitting would hurt readability"
    )]
    fn lower_stmt(
        &mut self,
        stmt: &Stmt,
        span: std::ops::Range<usize>,
        return_ty: ResolvedTy,
    ) -> HirStmt {
        let kind = match stmt {
            Stmt::Let { pattern, ty, value } => {
                // `await` on task handles is only legal as a statement-expression
                // inside a `scope{}` body. Actor asks are value-producing expressions
                // (the reply lands in MIR's `reply_dest`) and are handled by the
                // `Expr::Await` arm after typecheck's actor-dispatch classification.
                if let Some(val_expr) = value {
                    // A bindable `await` produces a value: an actor ask
                    // (`Result<R, AskError>`) or a non-blocking connection read
                    // (`bytes`/`string`, NEW-1). Both lower to a suspend carrier
                    // whose resume edge binds the value.
                    let is_bindable_await = match &val_expr.0 {
                        Expr::Await(inner) => {
                            let inner_key = SpanKey::from(&inner.1);
                            matches!(
                                self.actor_method_dispatch.get(&inner_key),
                                Some(ActorMethodKind::Ask(_, _))
                            ) || self.conn_await_reads.contains_key(&inner_key)
                                || self.listener_await_accepts.contains(&inner_key)
                                || self.is_stream_recv_await(&inner_key)
                                || self.is_channel_recv_await(&inner_key)
                        }
                        _ => false,
                    };
                    if matches!(&val_expr.0, Expr::Await(_)) && !is_bindable_await {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::AwaitOutOfPosition,
                            val_expr.1.clone(),
                            "`await` cannot be used as a let-value; \
                             only actor ask awaits and `await conn.read()` \
                             produce a bindable value",
                        ));
                        let name = self
                            .pattern_name(pattern)
                            .unwrap_or_else(|| "_".to_string());
                        let binding_ty = ty
                            .as_ref()
                            .map_or(ResolvedTy::Unit, |ty| self.lower_type(ty));
                        let binding = self.bind(name, binding_ty, false, pattern.1.clone());
                        let unsupported =
                            self.unsupported_expr(val_expr.1.clone(), "`await` in let-value");
                        return HirStmt {
                            node: self.ids.node(),
                            kind: HirStmtKind::Let(binding, Some(unsupported)),
                            span,
                        };
                    }
                }
                if let (Pattern::Wildcard, Some(value_expr)) = (&pattern.0, value.as_ref()) {
                    return HirStmt {
                        node: self.ids.node(),
                        kind: self.lower_expression_stmt_kind(value_expr),
                        span,
                    };
                }
                // Forward-bind for actor-lambda RHS. When the value is
                // `actor |params| { body }` and the let-pattern is a bare
                // identifier, the body may reference its own let-name for
                // recursive self-dispatch (HEW-SPEC §5.9 ratification 2).
                // Pre-bind the name BEFORE lowering the body so the body's
                // identifier reference resolves to a
                // `ResolvedRef::Binding(let_id)` rather than `Unresolved`.
                // The capture-strength classifier in `lower_expr`'s
                // `Expr::SpawnLambdaActor` arm checks the resolved id
                // against this let's id to discriminate Weak (self) from
                // Strong (every other free-variable capture).
                //
                // The pre-bind fires for both untyped and typed lets. The
                // binding type follows the annotation when present (the
                // type-checker layer reconciles the annotation against the
                // lambda's synthesised Duplex shape) and falls back to the
                // synthetic `Duplex<Msg, Reply>` derived from the lambda's
                // parameter / return annotations otherwise.
                if let (
                    Pattern::Identifier(name),
                    Some((
                        Expr::SpawnLambdaActor {
                            params: lambda_params,
                            return_type,
                            ..
                        },
                        _,
                    )),
                ) = (&pattern.0, value.as_ref())
                {
                    let binding_ty = match ty.as_ref() {
                        Some(annotation) => self.lower_type(annotation),
                        None => self.actor_lambda_duplex_ty(lambda_params, return_type.as_ref()),
                    };
                    // Pre-bind in the current scope; record the id so
                    // we can detect a self-reference inside the body
                    // walk via builder state.
                    let pre_binding = self.bind(name.clone(), binding_ty, false, pattern.1.clone());
                    let prior = self
                        .current_actor_self
                        .replace((pre_binding.id, name.clone()));
                    let lowered_value = self.lower_expr(
                        value.as_ref().expect("value Some checked above"),
                        IntentKind::Consume,
                    );
                    self.current_actor_self = prior;
                    return HirStmt {
                        node: self.ids.node(),
                        kind: HirStmtKind::Let(pre_binding, Some(lowered_value)),
                        span,
                    };
                }
                let value = value
                    .as_ref()
                    .map(|expr| self.lower_expr(expr, IntentKind::Consume));
                let binding_ty = ty.as_ref().map_or_else(
                    || {
                        value
                            .as_ref()
                            .map_or(ResolvedTy::Unit, |expr| expr.ty.clone())
                    },
                    |ty| self.lower_type(ty),
                );
                let name = self
                    .pattern_name(pattern)
                    .unwrap_or_else(|| "_".to_string());
                let binding = self.bind(name, binding_ty, false, pattern.1.clone());
                HirStmtKind::Let(binding, value)
            }
            Stmt::Var { name, ty, value } => {
                let value = value
                    .as_ref()
                    .map(|expr| self.lower_expr(expr, IntentKind::Consume));
                let binding_ty = ty.as_ref().map_or_else(
                    || {
                        value
                            .as_ref()
                            .map_or(ResolvedTy::Unit, |expr| expr.ty.clone())
                    },
                    |ty| self.lower_type(ty),
                );
                let binding = self.bind(name.clone(), binding_ty, true, span.clone());
                HirStmtKind::Let(binding, value)
            }
            Stmt::Assign { target, op, value } => {
                if let Some(op) = op {
                    self.lower_compound_assignment(target, *op, value, &span)
                } else {
                    let target = self.lower_expr(target, IntentKind::Modify);
                    let value = self.lower_expr(value, IntentKind::Consume);
                    HirStmtKind::Assign {
                        target,
                        value: Box::new(value),
                    }
                }
            }
            Stmt::Expression(expr) => self.lower_expression_stmt_kind(expr),
            Stmt::Return(value) => {
                if let Some(value) = value {
                    let expr = self.lower_expr(value, IntentKind::Consume);
                    // TI-5 escape check: a `Task<T>` value must not escape via
                    // return, whether the type was user-written or inferred. The
                    // `lower_type` wall blocks user-written `Task<T>` annotations;
                    // this check closes the inferred-escape path.
                    if matches!(expr.ty, ResolvedTy::Task(_)) {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::TaskCannotEscape,
                            value.1.clone(),
                            "a `Task<T>` handle cannot escape via `return`; \
                             await it inside the `scope{}` body with `await name`",
                        ));
                    } else if expr.ty != return_ty && return_ty != ResolvedTy::Unit {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::ReturnTypeMismatch {
                                expected: return_ty,
                                actual: expr.ty.clone(),
                            },
                            value.1.clone(),
                            "return expression type differs from function return annotation",
                        ));
                    }
                    HirStmtKind::Return(Some(expr))
                } else {
                    HirStmtKind::Return(None)
                }
            }
            Stmt::If {
                condition,
                then_block,
                else_block,
            } => {
                // Lower a statement-position `if` to `HirStmtKind::Expr` so
                // that sub-expression walkers (e.g. emit-cycle detection) can
                // descend into the branches.  `else if` chains are not yet
                // wired; they fall through to Unsupported to stay fail-closed.
                let lowered_condition = self.lower_expr(condition, IntentKind::Read);
                let then_hir_block = self.lower_block(then_block, &ResolvedTy::Unit);
                let then_ty = then_hir_block.ty.clone();
                let then_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    ty: then_ty.clone(),
                    value_class: ValueClass::of_ty(&then_ty, &self.type_classes),
                    intent: IntentKind::Read,
                    kind: HirExprKind::Block(then_hir_block),
                    span: span.clone(),
                };
                let else_expr = else_block.as_ref().and_then(|eb| {
                    if eb.is_if {
                        // `else if` chain: lower the nested Stmt::If recursively
                        // so the walker can descend into it. The inner stmt always
                        // lowers to HirStmtKind::Expr; any other outcome means the
                        // inner if hit an unsupported path and already emitted a
                        // diagnostic, so we fall back to an unsupported placeholder.
                        if let Some(inner) = &eb.if_stmt {
                            let inner_hir =
                                self.lower_stmt(&inner.0, inner.1.clone(), ResolvedTy::Unit);
                            match inner_hir.kind {
                                HirStmtKind::Expr(expr) => Some(Box::new(expr)),
                                _ => Some(Box::new(self.unsupported_expr(
                                    inner.1.clone(),
                                    "else-if chain produced non-expression HIR",
                                ))),
                            }
                        } else {
                            None
                        }
                    } else if let Some(block) = &eb.block {
                        let hir_block = self.lower_block(block, &ResolvedTy::Unit);
                        let else_ty = hir_block.ty.clone();
                        Some(Box::new(HirExpr {
                            node: self.ids.node(),
                            site: self.ids.site(),
                            ty: else_ty.clone(),
                            value_class: ValueClass::of_ty(&else_ty, &self.type_classes),
                            intent: IntentKind::Read,
                            kind: HirExprKind::Block(hir_block),
                            span: span.clone(),
                        }))
                    } else {
                        None
                    }
                });
                let if_ty = else_expr
                    .as_ref()
                    .map_or(ResolvedTy::Unit, |e| e.ty.clone());
                let if_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    ty: if_ty.clone(),
                    value_class: ValueClass::of_ty(&if_ty, &self.type_classes),
                    intent: IntentKind::Read,
                    kind: HirExprKind::If {
                        condition: Box::new(lowered_condition),
                        then_expr: Box::new(then_expr),
                        else_expr,
                    },
                    span: span.clone(),
                };
                HirStmtKind::Expr(if_expr)
            }
            Stmt::While {
                label: _,
                condition,
                body,
            } => {
                // `while cond { body }` — lowered to a HIR `While` expression
                // so that MIR can build the header/body/exit CFG shape.
                // Labels and `break`/`continue` are out of scope for this slice;
                // the label is dropped here because MIR does not yet wire
                // break/continue targets.
                let cond_hir = self.lower_expr(condition, IntentKind::Read);
                let body_block = self.lower_block(body, &ResolvedTy::Unit);
                let while_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    ty: ResolvedTy::Unit,
                    value_class: ValueClass::BitCopy,
                    intent: IntentKind::Read,
                    kind: HirExprKind::While {
                        condition: Box::new(cond_hir),
                        body: body_block,
                    },
                    span: span.clone(),
                };
                HirStmtKind::Expr(while_expr)
            }
            Stmt::WhileLet {
                label: _,
                pattern,
                expr,
                body,
            } => {
                // `while let <Ctor>(bindings) = scrutinee { body }` — lowered
                // to a HIR `WhileLet` expression so that MIR can build the
                // header/body/exit CFG shape (mirroring `While` + enum-tag
                // `Match`).
                //
                // Pattern scope: only a single payload-bearing enum
                // constructor pattern (`Some(x)`) is accepted here. Unit
                // variants (`None`), or-patterns, guards, literals, and
                // plain bindings fail closed with a typed diagnostic, the
                // same fail-closed shape used by `Match` lowering.
                //
                // The checker's `pattern_resolutions` side-table carries the
                // resolved variant identity + payload binding metadata;
                // missing entries (or-pattern / checker-rejected shapes)
                // surface a single `NotYetImplemented` diagnostic so callers
                // never see a half-built node.
                //
                // Labels are out of scope for this slice; the label is
                // dropped here because MIR does not yet wire break/continue
                // targets.
                let scrutinee_hir = self.lower_expr(expr, IntentKind::Read);
                // Register a generic-enum instantiation if the scrutinee's
                // type is a parameterised enum (`Option<i64>`). No-op for
                // monomorphic enums; required so MIR/codegen find the
                // `Option$$i64` layout — matches the Match path's
                // `try_register_enum_instantiation(scrutinee.1)` call.
                self.try_register_enum_instantiation(&expr.1);

                let pattern_span = &pattern.1;
                let key = SpanKey::from(pattern_span);
                let Some(resolution) = self.pattern_resolutions.get(&key).cloned() else {
                    self.unsupported(
                        pattern_span.clone(),
                        "while-let pattern has no resolution; \
                         only single payload-bearing enum-variant patterns are supported",
                        "while-let-substrate",
                    );
                    // Walk the body for checker-stream coverage.
                    self.push_scope();
                    let _ = self.lower_block(body, &ResolvedTy::Unit);
                    self.pop_scope();
                    let unsupported_expr = HirExpr {
                        node: self.ids.node(),
                        site: self.ids.site(),
                        ty: ResolvedTy::Unit,
                        value_class: ValueClass::BitCopy,
                        intent: IntentKind::Read,
                        kind: HirExprKind::Unsupported(
                            "while-let with unsupported pattern shape".into(),
                        ),
                        span: span.clone(),
                    };
                    return HirStmt {
                        node: self.ids.node(),
                        kind: HirStmtKind::Expr(unsupported_expr),
                        span: span.clone(),
                    };
                };

                // Only variant-constructor patterns with at least one
                // payload binding are lowered. Unit-variant patterns
                // (`None`), wildcards, literals, and plain bindings fail
                // closed — a `while let None = ...` would never terminate
                // (the condition is "tag matches None") and a plain
                // identifier pattern is semantically a `while true` with
                // a re-bind which is not what users mean.
                let (PatternKind::VariantCtor, Some(variant_match)) =
                    (resolution.pattern_kind, resolution.variant_match)
                else {
                    self.unsupported(
                        pattern_span.clone(),
                        "while-let supports only payload-bearing enum-variant patterns \
                         (e.g. `Some(x)`); unit variants, wildcards, literals, \
                         plain bindings, and or-patterns are reserved for a future lane",
                        "while-let-substrate",
                    );
                    self.push_scope();
                    let _ = self.lower_block(body, &ResolvedTy::Unit);
                    self.pop_scope();
                    let unsupported_expr = HirExpr {
                        node: self.ids.node(),
                        site: self.ids.site(),
                        ty: ResolvedTy::Unit,
                        value_class: ValueClass::BitCopy,
                        intent: IntentKind::Read,
                        kind: HirExprKind::Unsupported(
                            "while-let with unsupported pattern shape".into(),
                        ),
                        span: span.clone(),
                    };
                    return HirStmt {
                        node: self.ids.node(),
                        kind: HirStmtKind::Expr(unsupported_expr),
                        span: span.clone(),
                    };
                };

                // Resolve variant_idx via `machine_ctor_registry` (same
                // qualified-key lookup used by `lower_match_expr` so that
                // MIR/codegen consume identical indices).
                let qualified = format!(
                    "{}::{}",
                    variant_match.type_name, variant_match.variant_name
                );
                let Some((_, idx_usize)) = self.machine_ctor_registry.get(&qualified).cloned()
                else {
                    self.unsupported(
                        pattern_span.clone(),
                        "while-let variant not registered in machine/enum ctor registry",
                        "while-let-substrate",
                    );
                    self.push_scope();
                    let _ = self.lower_block(body, &ResolvedTy::Unit);
                    self.pop_scope();
                    let unsupported_expr = HirExpr {
                        node: self.ids.node(),
                        site: self.ids.site(),
                        ty: ResolvedTy::Unit,
                        value_class: ValueClass::BitCopy,
                        intent: IntentKind::Read,
                        kind: HirExprKind::Unsupported("while-let variant index unresolved".into()),
                        span: span.clone(),
                    };
                    return HirStmt {
                        node: self.ids.node(),
                        kind: HirStmtKind::Expr(unsupported_expr),
                        span: span.clone(),
                    };
                };
                let variant_idx = u32::try_from(idx_usize)
                    .expect("variant index exceeds u32::MAX — impossible in Hew");

                // Build per-arm bindings (same shape as `Match`).
                let mut binding_specs = Vec::with_capacity(resolution.payload_bindings.len());
                let mut binding_error = false;
                for payload in &resolution.payload_bindings {
                    let ty = match ResolvedTy::from_ty(&payload.ty) {
                        Ok(ty) => ty,
                        Err(err) => {
                            self.unsupported(
                                pattern_span.clone(),
                                format!("unresolved payload binding type in while-let ({err:?})"),
                                "while-let-substrate",
                            );
                            binding_error = true;
                            continue;
                        }
                    };
                    let Ok(field_idx) = u32::try_from(payload.field_idx) else {
                        self.unsupported(
                            pattern_span.clone(),
                            "while-let payload binding field index exceeds u32::MAX",
                            "while-let-substrate",
                        );
                        binding_error = true;
                        continue;
                    };
                    binding_specs.push((field_idx, payload.binding_name.clone(), ty));
                }

                self.push_scope();
                let bindings: Vec<HirMatchArmBinding> = if binding_error {
                    Vec::new()
                } else {
                    binding_specs
                        .into_iter()
                        .map(|(field_idx, name, ty)| {
                            let bound =
                                self.bind(name.clone(), ty.clone(), false, pattern_span.clone());
                            HirMatchArmBinding {
                                binding: bound.id,
                                field_idx,
                                name,
                                ty,
                            }
                        })
                        .collect()
                };
                let body_block = self.lower_block(body, &ResolvedTy::Unit);
                self.pop_scope();

                if binding_error {
                    let unsupported_expr = HirExpr {
                        node: self.ids.node(),
                        site: self.ids.site(),
                        ty: ResolvedTy::Unit,
                        value_class: ValueClass::BitCopy,
                        intent: IntentKind::Read,
                        kind: HirExprKind::Unsupported(
                            "while-let payload binding could not be resolved".into(),
                        ),
                        span: span.clone(),
                    };
                    return HirStmt {
                        node: self.ids.node(),
                        kind: HirStmtKind::Expr(unsupported_expr),
                        span: span.clone(),
                    };
                }

                let while_let_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    ty: ResolvedTy::Unit,
                    value_class: ValueClass::BitCopy,
                    intent: IntentKind::Read,
                    kind: HirExprKind::WhileLet {
                        scrutinee: Box::new(scrutinee_hir),
                        variant_match,
                        variant_idx,
                        bindings,
                        body: body_block,
                    },
                    span: span.clone(),
                };
                HirStmtKind::Expr(while_let_expr)
            }
            Stmt::For {
                label: _,
                pattern,
                iterable,
                body,
                is_await: _,
            } => {
                // Lower `for pat in iterable { body }`.
                // Only `Range`-typed iterables are supported in this slice:
                // `Expr::Range { start, end, inclusive }` where the iterable
                // expression is syntactically a range literal.  For all other
                // iterable shapes (Vec, Stream, HashMap, trait-Iterator, etc.)
                // a `NotYetImplemented` diagnostic is emitted and the statement
                // is replaced with an `Unsupported` placeholder so the pipeline
                // fails closed without fabricating a value.
                //
                // Only simple identifier patterns (`for i in …`) are supported;
                // tuple or struct patterns over a range are rejected the same
                // way.
                let kind = match (&iterable.0, &pattern.0) {
                    (
                        Expr::Binary {
                            op: op @ (BinaryOp::Range | BinaryOp::RangeInclusive),
                            left: range_start,
                            right: range_end,
                        },
                        Pattern::Identifier(var_name),
                    ) => {
                        // `for i in a..b` / `for i in a..=b` — the parser
                        // represents range literals as `Expr::Binary` with
                        // `BinaryOp::Range` or `BinaryOp::RangeInclusive`,
                        // NOT as `Expr::Range` (which is the slice-index form
                        // `xs[a..b]` inside bracket expressions only).
                        let inclusive = *op == BinaryOp::RangeInclusive;

                        // Lower start and end expressions first so their
                        // checker-resolved types are available for the loop
                        // variable binding below.
                        let start_hir = self.lower_expr(range_start, IntentKind::Read);
                        let end_hir = self.lower_expr(range_end, IntentKind::Read);

                        // Derive the loop-variable element type from the
                        // checker-authoritative Range<T> type recorded on the
                        // iterable expression.  This is the single source of
                        // truth: the checker already chose the common integer
                        // width (e.g. `i64` for a `i32..i64` range) and stored
                        // `Range<i64>` at the iterable span.  Reading it here
                        // avoids the "prefer-start-bound" heuristic that picked
                        // the wrong width when the two bounds had different
                        // signed widths.
                        //
                        // WHY: the old heuristic (start_hir.ty then end_hir.ty)
                        //   gave the wrong answer for mixed-width bounds such as
                        //   `a: i32 .. b: i64` — it chose `i32` but the checker
                        //   resolved `Range<i64>`.  The LLVM verifier then
                        //   rejected `call i64 @fn(i32 %arg)`.
                        // WHEN-OBSOLETE: this IS the real solution — no further
                        //   phase is needed unless Range semantics change.
                        // WHAT (real solution): read the checker-recorded
                        //   `Range<T>` at the iterable span and extract `T`.
                        let elem_ty = {
                            let range_key = SpanKey::from(&iterable.1);
                            self.expr_types
                                .get(&range_key)
                                .and_then(|ty| ty.as_range().cloned())
                                .and_then(|inner| ResolvedTy::from_ty(&inner).ok())
                                .filter(Self::resolved_is_integer)
                                // Fallback: derive from the lowered bound types.
                                // Covers cases where the iterable span is absent
                                // (e.g. an expression that produces a Range but
                                // is not a syntactic range literal).
                                .or_else(|| {
                                    if Self::resolved_is_integer(&start_hir.ty) {
                                        Some(start_hir.ty.clone())
                                    } else if Self::resolved_is_integer(&end_hir.ty) {
                                        Some(end_hir.ty.clone())
                                    } else {
                                        None
                                    }
                                })
                                .unwrap_or(ResolvedTy::I64)
                        };

                        // Bind the loop variable inside a fresh scope so it is
                        // scoped to the body but visible during body lowering.
                        self.push_scope();
                        let binding =
                            self.bind(var_name.clone(), elem_ty, false, pattern.1.clone());
                        let body_block = self.lower_block(body, &ResolvedTy::Unit);
                        self.pop_scope();

                        HirExprKind::ForRange {
                            binding,
                            start: Box::new(start_hir),
                            end: Box::new(end_hir),
                            inclusive,
                            body: body_block,
                        }
                    }
                    (_, Pattern::Identifier(_)) => {
                        self.lower_for_iter_desugar(pattern, iterable, body, span.clone())
                    }
                    _ => {
                        // Non-identifier pattern: not supported in this slice.
                        self.unsupported(
                            pattern.1.clone(),
                            "for-in with non-identifier binding pattern",
                            "for-while-lowering",
                        );
                        self.push_scope();
                        let _ = self.lower_block(body, &ResolvedTy::Unit);
                        self.pop_scope();
                        HirExprKind::Unsupported("for-in with non-identifier pattern".into())
                    }
                };

                let for_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    ty: ResolvedTy::Unit,
                    value_class: ValueClass::BitCopy,
                    intent: IntentKind::Read,
                    kind,
                    span: span.clone(),
                };
                HirStmtKind::Expr(for_expr)
            }
            Stmt::Match { scrutinee, arms } => {
                // `match scrut { ... }` in statement position. The parser
                // produces `Stmt::Match` distinct from `Stmt::Expression(Expr::Match)`,
                // so we route through the same `lower_match_expr` builder used by
                // expression-position match and wrap the result as a Unit-typed
                // statement-expression. The match's result type is discarded —
                // a statement-position match's value is unused.
                let (kind, ty) = self.lower_match_expr(scrutinee, arms, &span);
                let match_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    value_class: ValueClass::of_ty(&ty, &self.type_classes),
                    ty,
                    intent: IntentKind::Read,
                    kind,
                    span: span.clone(),
                };
                HirStmtKind::Expr(match_expr)
            }
            Stmt::Defer(body_expr) => {
                let body = self.lower_expr(body_expr, IntentKind::Read);
                HirStmtKind::Defer {
                    body: Box::new(body),
                    scope_id: self.current_scope_id,
                }
            }
            Stmt::Loop { label: _, body } => {
                // Bare `loop { body }` — lowered to a HIR `Loop` expression so
                // MIR can build the body/exit CFG shape with an unconditional
                // back-edge and a `break`-targeted exit block.
                //
                // Labels are out of scope for this slice (labeled break/continue
                // is deferred to a follow-up); the label is dropped here because
                // only the innermost-loop forms are wired through MIR.
                let body_block = self.lower_block(body, &ResolvedTy::Unit);
                let loop_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    ty: ResolvedTy::Unit,
                    value_class: ValueClass::BitCopy,
                    intent: IntentKind::Read,
                    kind: HirExprKind::Loop { body: body_block },
                    span: span.clone(),
                };
                HirStmtKind::Expr(loop_expr)
            }
            Stmt::Break { label, value } => {
                // `break;` / `break <value>;` — early exit from the innermost
                // enclosing loop. The type checker has already rejected
                // out-of-loop breaks, so a well-formed loop context is an
                // invariant here.
                //
                // Labeled `break @lbl` is deferred for v0.5: resolving a label
                // to a non-innermost loop changes the defer-flush window from
                // "innermost" to "all scopes up to the labeled loop", a
                // distinct jump-table concern. Fail closed with a structured
                // diagnostic rather than silently dropping the label
                // (LESSONS `boundary-fail-closed`).
                if label.is_some() {
                    self.unsupported(span.clone(), "labeled-break-continue", "slice-2");
                    return HirStmt {
                        node: self.ids.node(),
                        kind: HirStmtKind::Expr(
                            self.unsupported_expr(span.clone(), "labeled break"),
                        ),
                        span,
                    };
                }
                // Carry the operand of `break <value>` so MIR can lower it for
                // its side effects (and move-checker correctness) before the
                // jump. Loop-as-expression value return is out of scope; the
                // produced value is discarded downstream (LESSONS
                // `cleanup-all-exits`).
                let value_hir = value
                    .as_ref()
                    .map(|v| Box::new(self.lower_expr(v, IntentKind::Read)));
                let break_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    ty: ResolvedTy::Unit,
                    value_class: ValueClass::BitCopy,
                    intent: IntentKind::Read,
                    kind: HirExprKind::Break {
                        label: None,
                        value: value_hir,
                    },
                    span: span.clone(),
                };
                HirStmtKind::Expr(break_expr)
            }
            Stmt::Continue { label } => {
                // `continue;` — next iteration of the innermost enclosing loop.
                // Labeled `continue @lbl` is deferred for v0.5; fail closed with
                // a structured diagnostic rather than dropping the label
                // silently (LESSONS `boundary-fail-closed`).
                if label.is_some() {
                    self.unsupported(span.clone(), "labeled-break-continue", "slice-2");
                    return HirStmt {
                        node: self.ids.node(),
                        kind: HirStmtKind::Expr(
                            self.unsupported_expr(span.clone(), "labeled continue"),
                        ),
                        span,
                    };
                }
                let continue_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    ty: ResolvedTy::Unit,
                    value_class: ValueClass::BitCopy,
                    intent: IntentKind::Read,
                    kind: HirExprKind::Continue { label: None },
                    span: span.clone(),
                };
                HirStmtKind::Expr(continue_expr)
            }
            Stmt::IfLet {
                pattern,
                expr,
                body,
                else_body,
                ..
            } => {
                // `if let PAT = scrutinee { then } else { else }` in statement
                // position — result type is always Unit. Delegates to the shared
                // `lower_if_let_inner` helper (same one used by expression position).
                let kind = match self.lower_if_let_inner(
                    pattern,
                    expr,
                    body,
                    else_body.as_ref(),
                    &ResolvedTy::Unit,
                    &span,
                ) {
                    Some(k) => k,
                    None => HirExprKind::Unsupported("if-let lowering failed".into()),
                };
                let if_let_expr = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    ty: ResolvedTy::Unit,
                    value_class: ValueClass::BitCopy,
                    intent: IntentKind::Read,
                    kind,
                    span: span.clone(),
                };
                HirStmtKind::Expr(if_let_expr)
            }
        };
        HirStmt {
            node: self.ids.node(),
            kind,
            span,
        }
    }

    /// Shared core of `if let PAT = scrutinee { body } else { else_body }`.
    ///
    /// Used by both statement position (`Stmt::IfLet`, `result_ty` = Unit) and
    /// expression position (`Expr::IfLet`, `result_ty` = unified branch type).
    /// Returns `Some(HirExprKind::IfLet { ... })` on success, `None` on a
    /// fail-closed error (diagnostics already pushed). The `else_body` block
    /// is lowered with `result_ty` so that expression-position branches are
    /// type-consistent.
    ///
    /// Pattern scope (v0.5 substrate): only single payload-bearing enum-variant
    /// constructor patterns (e.g. `Some(x)`) are accepted — the same restriction
    /// as `WhileLet`.
    #[allow(
        clippy::too_many_lines,
        reason = "mirrors lower_while_let in structure; splitting would obscure the \
                  parallel error-handling paths"
    )]
    fn lower_if_let_inner(
        &mut self,
        pattern: &Spanned<Pattern>,
        scrutinee_expr: &Spanned<Expr>,
        body: &Block,
        else_body: Option<&Block>,
        result_ty: &ResolvedTy,
        _span: &Span,
    ) -> Option<HirExprKind> {
        let scrutinee_hir = self.lower_expr(scrutinee_expr, IntentKind::Read);
        // Register a generic-enum instantiation so MIR/codegen find the
        // mangled layout — matches the WhileLet/Match path.
        self.try_register_enum_instantiation(&scrutinee_expr.1);

        let pattern_span = &pattern.1;
        let key = SpanKey::from(pattern_span);
        let Some(resolution) = self.pattern_resolutions.get(&key).cloned() else {
            self.unsupported(
                pattern_span.clone(),
                "if-let pattern has no resolution; \
                 only single payload-bearing enum-variant patterns are supported",
                "if-let-substrate",
            );
            self.push_scope();
            let _ = self.lower_block(body, &ResolvedTy::Unit);
            self.pop_scope();
            if let Some(eb) = else_body {
                let _ = self.lower_block(eb, &ResolvedTy::Unit);
            }
            return None;
        };

        let (PatternKind::VariantCtor, Some(variant_match)) =
            (resolution.pattern_kind, resolution.variant_match)
        else {
            self.unsupported(
                pattern_span.clone(),
                "if-let supports only payload-bearing enum-variant patterns \
                 (e.g. `Some(x)`); unit variants, wildcards, literals, \
                 plain bindings, and or-patterns are reserved for a future lane",
                "if-let-substrate",
            );
            self.push_scope();
            let _ = self.lower_block(body, &ResolvedTy::Unit);
            self.pop_scope();
            if let Some(eb) = else_body {
                let _ = self.lower_block(eb, &ResolvedTy::Unit);
            }
            return None;
        };

        let qualified = format!(
            "{}::{}",
            variant_match.type_name, variant_match.variant_name
        );
        let Some((_, idx_usize)) = self.machine_ctor_registry.get(&qualified).cloned() else {
            self.unsupported(
                pattern_span.clone(),
                "if-let variant not registered in machine/enum ctor registry",
                "if-let-substrate",
            );
            self.push_scope();
            let _ = self.lower_block(body, &ResolvedTy::Unit);
            self.pop_scope();
            if let Some(eb) = else_body {
                let _ = self.lower_block(eb, &ResolvedTy::Unit);
            }
            return None;
        };
        let variant_idx =
            u32::try_from(idx_usize).expect("variant index exceeds u32::MAX — impossible in Hew");

        // Build per-arm bindings (same shape as Match / WhileLet).
        let mut binding_specs = Vec::with_capacity(resolution.payload_bindings.len());
        let mut binding_error = false;
        for payload in &resolution.payload_bindings {
            let ty = match ResolvedTy::from_ty(&payload.ty) {
                Ok(ty) => ty,
                Err(err) => {
                    self.unsupported(
                        pattern_span.clone(),
                        format!("unresolved payload binding type in if-let ({err:?})"),
                        "if-let-substrate",
                    );
                    binding_error = true;
                    continue;
                }
            };
            let Ok(field_idx) = u32::try_from(payload.field_idx) else {
                self.unsupported(
                    pattern_span.clone(),
                    "if-let payload binding field index exceeds u32::MAX",
                    "if-let-substrate",
                );
                binding_error = true;
                continue;
            };
            binding_specs.push((field_idx, payload.binding_name.clone(), ty));
        }

        self.push_scope();
        let bindings: Vec<HirMatchArmBinding> = if binding_error {
            Vec::new()
        } else {
            binding_specs
                .into_iter()
                .map(|(field_idx, name, ty)| {
                    let bound = self.bind(name.clone(), ty.clone(), false, pattern_span.clone());
                    HirMatchArmBinding {
                        binding: bound.id,
                        field_idx,
                        name,
                        ty,
                    }
                })
                .collect()
        };
        let body_block = self.lower_block(body, result_ty);
        self.pop_scope();

        let else_block = else_body.as_ref().map(|eb| self.lower_block(eb, result_ty));

        if binding_error {
            return None;
        }

        Some(HirExprKind::IfLet {
            scrutinee: Box::new(scrutinee_hir),
            variant_match,
            variant_idx,
            bindings,
            body: body_block,
            else_body: else_block,
            result_ty: result_ty.clone(),
        })
    }

    fn lower_compound_assignment(
        &mut self,
        target: &Spanned<Expr>,
        op: CompoundAssignOp,
        value: &Spanned<Expr>,
        span: &Span,
    ) -> HirStmtKind {
        let binary_op = Self::compound_assign_binary_op(op);
        let target_read = self.lower_expr(target, IntentKind::Read);
        let rhs = self.lower_expr(value, IntentKind::Read);
        let target_write = self.lower_expr(target, IntentKind::Modify);
        let value = HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            ty: target_read.ty.clone(),
            value_class: target_read.value_class,
            intent: IntentKind::Consume,
            kind: HirExprKind::Binary {
                op: binary_op,
                left: Box::new(target_read),
                right: Box::new(rhs),
            },
            span: span.clone(),
        };
        HirStmtKind::Assign {
            target: target_write,
            value: Box::new(value),
        }
    }

    fn compound_assign_binary_op(op: CompoundAssignOp) -> BinaryOp {
        match op {
            CompoundAssignOp::Add => BinaryOp::Add,
            CompoundAssignOp::Subtract => BinaryOp::Subtract,
            CompoundAssignOp::Multiply => BinaryOp::Multiply,
            CompoundAssignOp::Divide => BinaryOp::Divide,
            CompoundAssignOp::Modulo => BinaryOp::Modulo,
            CompoundAssignOp::BitAnd => BinaryOp::BitAnd,
            CompoundAssignOp::BitOr => BinaryOp::BitOr,
            CompoundAssignOp::BitXor => BinaryOp::BitXor,
            CompoundAssignOp::Shl => BinaryOp::Shl,
            CompoundAssignOp::Shr => BinaryOp::Shr,
        }
    }

    #[allow(
        clippy::too_many_lines,
        reason = "single large match on expr variants; splitting would hurt readability"
    )]
    fn lower_expr(&mut self, expr: &Spanned<Expr>, intent: IntentKind) -> HirExpr {
        // Consume the statement-position flag atomically. Every recursive call
        // to `lower_expr` (for arguments, operands, return values, block tails,
        // etc.) therefore sees `false`. Only the `Stmt::Expression` arm in
        // `lower_stmt` sets this to `true` immediately before calling us.
        let in_stmt_position = std::mem::replace(&mut self.statement_position, false);
        let span = expr.1.clone();
        // Pre-allocate the SiteId for this expression so call-site
        // side-tables (e.g. `call_site_type_args`) can be keyed
        // by the eventual HirExpr.site before the wrapping struct is
        // built. Allocation order: site before node so existing
        // SiteId counts in tests stay stable (lower_expr previously
        // allocated node before site at the same call).
        let site = self.ids.site();
        let (kind, ty) = match &expr.0 {
            Expr::Literal(lit) => {
                let (kind, default_ty) = Self::lower_literal(lit);
                // Apply checker authority for integer literals: the checker may have
                // recorded a concrete width (e.g. `I32`) via `check_against` when the
                // literal appears in a comparison with a fixed-width integer
                // (e.g. `register("w", pid) == 0`). Without this override the literal
                // always defaults to `I64`, causing `IntCmp` to see mismatched widths.
                // If checker recorded `IntLiteral` (unconstrained) or no entry exists,
                // `from_ty` returns Err and we fall back to the `lower_literal` default.
                let ty = {
                    let checker_key = SpanKey::from(&span);
                    if let Some(checker_ty) = self.expr_types.get(&checker_key) {
                        ResolvedTy::from_ty(checker_ty).unwrap_or(default_ty)
                    } else {
                        default_ty
                    }
                };
                // W4.047 P1.2: prove the typed handoff agrees with the live
                // path at this fail-open literal site (no behaviour change).
                self.assert_resolved_ty_totality(&span);
                (kind, ty)
            }
            Expr::RegexLiteral(pattern) => {
                // A standalone `re"..."` expression. Allocate (or reuse) the
                // module-level literal-table entry. The checker-assigned type is
                // `regex.Pattern`; read it from `expr_types` if present (it is
                // set by `synthesize_inner` for `Expr::RegexLiteral`), otherwise
                // fall back to the canonical `Named` form. Using the checker's
                // resolved type rather than hard-coding keeps capture / generic
                // resolution consistent with the rest of the pipeline.
                let checker_key = SpanKey::from(&span);
                let resolved_ty = if let Some(ty) = self.expr_types.get(&checker_key).cloned() {
                    ResolvedTy::from_ty(&ty).unwrap_or(ResolvedTy::Named {
                        name: "regex.Pattern".to_string(),
                        args: Vec::new(),
                        builtin: None,
                        is_opaque: false,
                    })
                } else {
                    ResolvedTy::Named {
                        name: "regex.Pattern".to_string(),
                        args: Vec::new(),
                        builtin: None,
                        is_opaque: false,
                    }
                };
                // W4.047 P1.2: prove the typed handoff agrees with the live
                // path at this fail-open regex-literal site (no behaviour change).
                self.assert_resolved_ty_totality(&span);
                // No named captures from a standalone literal — captures are
                // resolved per-arm in the match-arm context. Pass an empty
                // capture list; the table deduplicates by pattern only.
                let literal_id = self.alloc_regex_literal(pattern, &[]);
                (
                    HirExprKind::RegexLiteralRef {
                        literal_id,
                        pattern: pattern.clone(),
                        captures: Vec::new(),
                    },
                    resolved_ty,
                )
            }
            Expr::Identifier(name) => {
                // Inside a machine body, check if the identifier names one of the
                // enclosing machine's states (unit state ctor, e.g. `Green`).
                // If so, produce `MachineVariantCtor` rather than going through
                // `lower_identifier` (which would emit `UnresolvedSymbol` because
                // state names are not in the HIR scope).
                //
                // HIR-side authority: the type checker does not record a side-table
                // entry for this expression; the result type is derived from the
                // machine declaration context held in `current_machine_states`.
                if let Some((machine_name, state_idx)) = self.resolve_machine_state_name(name) {
                    let machine_ty = ResolvedTy::Named {
                        name: machine_name.clone(),
                        args: Vec::new(),
                        builtin: None,
                        is_opaque: false,
                    };
                    (
                        HirExprKind::MachineVariantCtor {
                            machine_name,
                            state_idx,
                            payload: None,
                        },
                        machine_ty,
                    )
                } else {
                    self.lower_identifier(name, span.clone())
                }
            }
            Expr::Binary { left, op, right } => {
                let left = self.lower_expr(left, IntentKind::Read);
                let right = self.lower_expr(right, IntentKind::Read);
                let ty = Self::binary_ty(*op, &left.ty, &right.ty);
                (
                    HirExprKind::Binary {
                        op: *op,
                        left: Box::new(left),
                        right: Box::new(right),
                    },
                    ty,
                )
            }
            Expr::Unary { op, operand } => self.lower_unary_expr(*op, operand, &span),
            Expr::Call { function, args, .. } => {
                let mut args = args
                    .iter()
                    .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                    .collect::<Vec<_>>();
                if let Expr::Identifier(name) = &function.0 {
                    // Intercept payload-bearing variant constructors written
                    // as calls (`Shape::Line(5)`, bare `Line(5)`). The bare
                    // identifier path produces `MachineVariantCtor { payload:
                    // None }`; the call form must capture the args into
                    // `payload: Some(...)`. Mismatched ctor shape (calling a
                    // unit variant with args, or calling a struct variant
                    // positionally) emits a structured diagnostic and falls
                    // through to the regular-call path so checker-stream
                    // coverage is preserved.
                    let variant_kind_for_call = self
                        .lookup_variant_ctor(name)
                        .map(|(_, _, kind)| kind.clone());
                    if let Some(HirVariantKind::Tuple(_)) = &variant_kind_for_call {
                        let taken = std::mem::take(&mut args);
                        self.lower_variant_ctor_tuple_call(name, taken, &span)
                    } else if let Some(kind) = &variant_kind_for_call {
                        self.report_variant_ctor_call_shape_mismatch(name, kind, &span);
                        // Fall through to regular-call to keep checker-stream
                        // coverage for the malformed source.
                        self.lower_regular_call(function, args, &span, site)
                    } else if stdlib_catalog::is_overloaded_builtin(name) {
                        let arg_tys = args.iter().map(|arg| arg.ty.clone()).collect::<Vec<_>>();
                        if let Some(entry) = stdlib_catalog::resolve_overload(name, &arg_tys) {
                            let result_ty = entry.return_ty.to_resolved();
                            let callee = self.lower_stdlib_callee(entry, function.1.clone());
                            (
                                HirExprKind::Call {
                                    callee: Box::new(callee),
                                    args,
                                },
                                result_ty,
                            )
                        } else {
                            let arg_ty = arg_tys.first().cloned().unwrap_or(ResolvedTy::Unit);
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::UnresolvedBuiltinOverload {
                                    name: name.clone(),
                                    arg_ty,
                                },
                                span.clone(),
                                "builtin call has no registered monomorphic overload for this argument type",
                            ));
                            let callee = self.unresolved_builtin_callee(name, function.1.clone());
                            (
                                HirExprKind::Call {
                                    callee: Box::new(callee),
                                    args,
                                },
                                ResolvedTy::Unit,
                            )
                        }
                    } else if name == "unlink" {
                        // `unlink` remains a checker-registered actor-lifecycle
                        // builtin without a MIR producer arm. `link` and `monitor`
                        // now pass through to MIR so statement-position calls can
                        // emit `CallRuntimeAbi` while value-needed composite returns
                        // fail closed at the producer boundary.
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::NotYetImplemented {
                                construct: format!("builtin call `{name}`"),
                                owning_pass: "cluster-runtime".to_string(),
                            },
                            span.clone(),
                            "unlink requires a MIR producer arm before it can reach \
                             the runtime substrate",
                        ));
                        let callee = self.unresolved_builtin_callee(name, function.1.clone());
                        (
                            HirExprKind::Call {
                                callee: Box::new(callee),
                                args,
                            },
                            ResolvedTy::Unit,
                        )
                    } else {
                        self.lower_regular_call(function, args, &span, site)
                    }
                } else {
                    self.lower_regular_call(function, args, &span, site)
                }
            }
            Expr::Block(block) => {
                let block = self.lower_block(block, &ResolvedTy::Unit);
                let ty = block.ty.clone();
                (HirExprKind::Block(block), ty)
            }
            Expr::If {
                condition,
                then_block,
                else_block,
            } => {
                let condition = self.lower_expr(condition, IntentKind::Read);
                let then_expr = self.lower_expr(then_block, IntentKind::Read);
                let else_expr = else_block
                    .as_ref()
                    .map(|expr| Box::new(self.lower_expr(expr, IntentKind::Read)));
                let ty = else_expr
                    .as_ref()
                    .map_or(ResolvedTy::Unit, |expr| expr.ty.clone());
                (
                    HirExprKind::If {
                        condition: Box::new(condition),
                        then_expr: Box::new(then_expr),
                        else_expr,
                    },
                    ty,
                )
            }
            Expr::StructInit {
                name,
                fields,
                // Surface-level explicit type arguments (`Box<i64> { ... }`).
                // The HIR-recorded `type_args` below comes from the checker's
                // `record_init_type_args` side-table (which already reconciled
                // inferred-vs-explicit and substituted enclosing-fn type-params
                // where applicable), so we ignore the raw surface args here.
                type_args: _,
                base,
            } => {
                // Inside a machine body, check if the struct-init name is a state
                // with payload fields (e.g. `SynReceived { remote_port: remote_port }`).
                // Resolve to `MachineVariantCtor` before the record-layout path.
                //
                // HIR-side authority: same deviation as `MachineVariantCtor` for bare
                // identifiers — the checker has no side-table for state-ctor sites.
                // Payload fields are validated structurally (field names matched against
                // the state's declared fields). The `base` functional-update form is not
                // supported for machine state ctors and is rejected below if present.
                // Enum struct-variant ctor (`Shape::Box { w: 3, h: 4 }`).
                // Looks like a struct literal but resolves to a registered
                // enum variant in `enum_variants_by_name`. Resolved before
                // the machine-state path so a qualified `Shape::Box` is
                // routed correctly even outside any machine body.
                let enum_struct_variant = if let Some((type_name, variant_idx, kind)) =
                    self.lookup_variant_ctor(name)
                {
                    match kind {
                        HirVariantKind::Struct(_) => Some((type_name, variant_idx, kind.clone())),
                        // Unit / tuple variants written with struct-literal
                        // syntax are a shape mismatch; report and let the
                        // regular-record path handle the fallthrough so
                        // downstream diagnostics still surface.
                        HirVariantKind::Unit | HirVariantKind::Tuple(_) => {
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::NotYetImplemented {
                                    construct: format!(
                                        "variant `{name}` initialised with struct-literal syntax"
                                    ),
                                    owning_pass: "variant ctor shape".to_string(),
                                },
                                span.clone(),
                                "this variant has no named fields; use the matching call or identifier form",
                            ));
                            None
                        }
                    }
                } else {
                    None
                };
                if let Some((type_name, variant_idx, HirVariantKind::Struct(field_decls))) =
                    enum_struct_variant
                {
                    if base.is_some() {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::NotYetImplemented {
                                construct: "functional-update syntax on enum variant constructors"
                                    .to_string(),
                                owning_pass: "variant ctor validation".to_string(),
                            },
                            span.clone(),
                            "enum variant constructors do not support `..base` syntax",
                        ));
                    }
                    // Validate source-declared field names against the
                    // variant's declared field set (mirrors the
                    // assignment-target-authority LESSONS row: HIR does not
                    // re-derive type identity from the AST, but it does
                    // validate field-name coverage against the lowered
                    // descriptor). MIR stores by `field_idx`, so we reorder
                    // source fields into declaration order.
                    let mut hir_payload: Vec<(String, HirExpr)> =
                        Vec::with_capacity(field_decls.len());
                    for (field_name, _field_ty) in &field_decls {
                        if let Some((_, src_expr)) = fields.iter().find(|(n, _)| n == field_name) {
                            hir_payload.push((
                                field_name.clone(),
                                self.lower_expr(src_expr, IntentKind::Read),
                            ));
                        } else {
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::NotYetImplemented {
                                    construct: format!(
                                        "variant `{name}` missing field `{field_name}`"
                                    ),
                                    owning_pass: "variant ctor field coverage".to_string(),
                                },
                                span.clone(),
                                "enum struct-variant constructor must initialise every declared field",
                            ));
                        }
                    }
                    // Flag unknown field names for checker-stream coverage;
                    // the canonical struct-init expr's checker entry covers
                    // most cases but the variant-ctor branch is HIR-side.
                    for (fname, src_expr) in fields {
                        if !field_decls.iter().any(|(n, _)| n == fname) {
                            // Lower the expression for coverage even though
                            // we discard it.
                            let _ = self.lower_expr(src_expr, IntentKind::Read);
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::NotYetImplemented {
                                    construct: format!("variant `{name}` has no field `{fname}`"),
                                    owning_pass: "variant ctor field coverage".to_string(),
                                },
                                span.clone(),
                                "extra field in enum struct-variant constructor",
                            ));
                        }
                    }
                    // Register the generic-enum instantiation before building
                    // result_ty so codegen's mangled-key lookup finds the entry.
                    self.try_register_enum_instantiation(&span);
                    // Checker-authoritative result type: the checker records the
                    // full `Named { name: "Maybe", args: [I64] }` at the
                    // struct-init expression span. Using it preserves type args
                    // so codegen computes the mangled registry key.
                    // Fall back to bare-name with a diagnostic if expr_types
                    // has no entry or boundary conversion fails.
                    let checker_key = SpanKey::from(&span);
                    let result_ty = if let Some(ty) = self.expr_types.get(&checker_key).cloned() {
                        match ResolvedTy::from_ty(&ty) {
                            Ok(resolved) => resolved,
                            Err(err) => {
                                self.diagnostics.push(HirDiagnostic::new(
                                    HirDiagnosticKind::CheckerBoundaryViolation {
                                        name: type_name.clone(),
                                        reason: err.to_string(),
                                    },
                                    span.clone(),
                                    "checker-authoritative struct-variant result type failed boundary conversion",
                                ));
                                ResolvedTy::Named {
                                    name: type_name.clone(),
                                    args: Vec::new(),
                                    builtin: None,
                                    is_opaque: false,
                                }
                            }
                        }
                    } else {
                        ResolvedTy::Named {
                            name: type_name.clone(),
                            args: Vec::new(),
                            builtin: None,
                            is_opaque: false,
                        }
                    };
                    (
                        HirExprKind::MachineVariantCtor {
                            machine_name: type_name,
                            state_idx: variant_idx,
                            payload: Some(hir_payload),
                        },
                        result_ty,
                    )
                } else if let Some((machine_name, state_idx)) =
                    self.resolve_machine_state_name(name)
                {
                    // Reject functional-update syntax (`SynReceived { ..base }`) on
                    // machine state constructors — the semantics differ from records.
                    if base.is_some() {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::NotYetImplemented {
                                construct: "functional-update syntax on machine state constructors"
                                    .to_string(),
                                owning_pass: "machine state constructor validation".to_string(),
                            },
                            span.clone(),
                            "machine state constructors do not support `..base` syntax",
                        ));
                    }
                    // Resolve payload field expressions against the state's declared fields.
                    // Field order follows source declaration; unknown field names are
                    // carried through (MIR validates against the state schema at Slice 4b).
                    let hir_payload: Vec<(String, HirExpr)> = fields
                        .iter()
                        .map(|(fname, expr)| {
                            (fname.clone(), self.lower_expr(expr, IntentKind::Read))
                        })
                        .collect();
                    let machine_ty = ResolvedTy::Named {
                        name: machine_name.clone(),
                        args: Vec::new(),
                        builtin: None,
                        is_opaque: false,
                    };
                    // Break out of the match to let the outer wrapper build the HirExpr.
                    // We use a nested block that evaluates to `(kind, ty)`.
                    (
                        HirExprKind::MachineVariantCtor {
                            machine_name,
                            state_idx,
                            payload: Some(hir_payload),
                        },
                        machine_ty,
                    )
                } else {
                    // Not a machine state — regular record init path.
                    // Record the per-instantiation `RecordLayout` for
                    // generic user records and capture the concrete type-args
                    // for propagation onto this expression's resolved type.
                    // `None` is legitimate for monomorphic/builtin records
                    // (args: [] is correct).  For generic records with a
                    // checker-accepted span but missing type-arg entry,
                    // `record_record_layout` emits `RecordLayoutMissing`
                    // before returning `None` — fail-closed, not pretend.
                    let resolved_type_args =
                        self.record_record_layout(name, &span).unwrap_or_default();
                    let hir_fields = fields
                        .iter()
                        .map(|(fname, expr)| {
                            (fname.clone(), self.lower_expr(expr, IntentKind::Read))
                        })
                        .collect();
                    // Lower the functional-update base if present. The checker has
                    // already validated type-compatibility and field coverage; HIR
                    // carries it verbatim so MIR lowering (A-7) can read the
                    // un-overridden fields from the base value.
                    let hir_base =
                        base.as_deref().map(|(base_expr, base_span)| {
                            Box::new(self.lower_expr(
                                &(base_expr.clone(), base_span.clone()),
                                IntentKind::Read,
                            ))
                        });
                    (
                        HirExprKind::StructInit {
                            name: name.clone(),
                            type_args: resolved_type_args.clone(),
                            fields: hir_fields,
                            base: hir_base,
                        },
                        ResolvedTy::Named {
                            name: name.clone(),
                            args: resolved_type_args,
                            builtin: None,
                            is_opaque: false,
                        },
                    )
                }
            }
            Expr::Scope { body } => {
                // A `scope{}` block lowers to `HirExprKind::Scope`. Inside the
                // body, statement-calls become spawned-call nodes (TI-1) and
                // `fork name = call(...)` statements introduce `Task<T>` bindings
                // (TI-2). The scope block's type is `Unit` — it is a lifetime
                // boundary, not a value-producing expression.
                self.scope_depth += 1;
                let hir_body = self.lower_scope_block(body);
                self.scope_depth -= 1;
                (HirExprKind::Scope { body: hir_body }, ResolvedTy::Unit)
            }
            Expr::ForkChild { binding, expr } => {
                // `fork name = expr` outside a `scope{}` body: no spawn context,
                // so this is malformed. Emit NotYetImplemented — the grammar
                // accepts this form but HIR-lowering requires scope context.
                // (Inside scope{} bodies this variant is handled by lower_scope_block,
                // not by lower_expr directly.)
                if self.scope_depth == 0 {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::AwaitOutOfPosition,
                        span.clone(),
                        "`fork name = expr` is only valid inside a `scope{}` body",
                    ));
                    (
                        HirExprKind::Unsupported(
                            "`fork name = expr` outside scope body".to_string(),
                        ),
                        ResolvedTy::Unit,
                    )
                } else {
                    // Inside a scope body, lower_scope_block handles this case;
                    // reaching here means the expression appeared in a non-statement
                    // position (e.g. tail expression). Reject: task handles cannot
                    // be used as values.
                    let _ = binding;
                    let _ = expr;
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::AwaitOutOfPosition,
                        span.clone(),
                        "`fork name = expr` must be a statement, not an expression value",
                    ));
                    (
                        HirExprKind::Unsupported("`fork name = expr` as expression".to_string()),
                        ResolvedTy::Unit,
                    )
                }
            }
            Expr::ForkBlock { body } => {
                if self.scope_depth == 0 || !in_stmt_position {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::AwaitOutOfPosition,
                        span.clone(),
                        "`fork { ... }` child-task blocks are only legal as statements inside a `scope{}` body",
                    ));
                    (
                        HirExprKind::Unsupported(
                            "`fork { ... }` outside scope statement".to_string(),
                        ),
                        ResolvedTy::Unit,
                    )
                } else {
                    let task_ty = ResolvedTy::Task(Box::new(ResolvedTy::Unit));
                    (
                        HirExprKind::ForkBlock {
                            body: self.lower_cancellation_clause_block(body),
                            task_ty: task_ty.clone(),
                        },
                        task_ty,
                    )
                }
            }
            Expr::ScopeDeadline { duration, body } => {
                if self.scope_depth == 0 || !in_stmt_position {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::AwaitOutOfPosition,
                        span.clone(),
                        "`after(duration) { ... }` deadline clauses are only legal as statements inside a `scope{}` body",
                    ));
                    (
                        HirExprKind::Unsupported(
                            "`after(duration) { ... }` outside scope statement".to_string(),
                        ),
                        ResolvedTy::Unit,
                    )
                } else {
                    let duration = self.lower_expr(duration, IntentKind::Read);
                    (
                        HirExprKind::ScopeDeadline {
                            duration: Box::new(duration),
                            body: self.lower_cancellation_clause_block(body),
                        },
                        ResolvedTy::Unit,
                    )
                }
            }
            Expr::Await(inner) => {
                // NEW-1: `await conn.read()` / `await conn.read_string()` — the
                // checker recorded the inner method-call span as a suspending
                // read. Lower to `ConnAwaitRead` (MIR emits `SuspendingRead` for
                // a suspendable caller, else the blocking read). The HIR type is
                // the method's return type (`bytes` for read, `string` for
                // read_string), already assigned to `expr` by the checker.
                if let Some(&to_string) = self.conn_await_reads.get(&SpanKey::from(&inner.1)) {
                    if let Expr::MethodCall { receiver, .. } = &inner.0 {
                        let conn = self.lower_expr(receiver, IntentKind::Read);
                        // The await's value type is the read's return type:
                        // `string` for `read_string`, `bytes` for raw `read`.
                        let result_ty = if to_string {
                            ResolvedTy::String
                        } else {
                            ResolvedTy::Bytes
                        };
                        let value_class = ValueClass::of_ty(&result_ty, &self.type_classes);
                        return HirExpr {
                            node: self.ids.node(),
                            site: self.ids.site(),
                            value_class,
                            ty: result_ty,
                            intent,
                            kind: HirExprKind::ConnAwaitRead {
                                conn: Box::new(conn),
                                to_string,
                            },
                            span: span.clone(),
                        };
                    }
                }
                // NEW-2: `await listener.accept()` — the checker recorded the
                // inner method-call span as a suspending accept. Lower to
                // `ListenerAwaitAccept` (MIR emits `SuspendingAccept` for a
                // suspendable caller, else the blocking accept). The value type is
                // the accept's return type (`Connection`), captured from the
                // checker's resolved type table (falling back to the qualified
                // opaque name, which the codegen handle map recognises).
                if self
                    .listener_await_accepts
                    .contains(&SpanKey::from(&inner.1))
                {
                    if let Expr::MethodCall { receiver, .. } = &inner.0 {
                        let listener = self.lower_expr(receiver, IntentKind::Read);
                        let result_ty = self
                            .resolved_expr_types
                            .get(&SpanKey::from(&inner.1))
                            .cloned()
                            .unwrap_or(ResolvedTy::Named {
                                name: "net.Connection".to_string(),
                                args: vec![],
                                builtin: None,
                                is_opaque: true,
                            });
                        let value_class = ValueClass::of_ty(&result_ty, &self.type_classes);
                        return HirExpr {
                            node: self.ids.node(),
                            site: self.ids.site(),
                            value_class,
                            ty: result_ty,
                            intent,
                            kind: HirExprKind::ListenerAwaitAccept {
                                listener: Box::new(listener),
                            },
                            span: span.clone(),
                        };
                    }
                }
                // NEW-7: `await stream.recv()` over a `Stream<bytes>` — the
                // checker wired the inner method call to `hew_stream_next_bytes`.
                // Strip the `await` and lower the inner recv directly; its
                // `Option<bytes>` result is bound on the resume edge of the MIR
                // `SuspendingStreamNext` (the suspendable-caller flip in
                // `lower_direct_call`), or the blocking call for a context-free
                // caller. Mirrors the actor-ask / conn-read bindable-await paths.
                if self.is_stream_recv_await(&SpanKey::from(&inner.1)) {
                    return self.lower_expr(inner, intent);
                }
                // NEW-4: `await rx.recv()` over a `std::channel` `Receiver<T>` —
                // the checker wired the inner method call to `hew_channel_recv`
                // (string) / `hew_channel_recv_int` (int). Strip the `await` and
                // lower the inner recv directly; its `Option<T>` result is bound
                // on the resume edge of the MIR `SuspendingChannelRecv` (the
                // suspendable-caller flip in `lower_direct_call`), or the blocking
                // call for a context-free caller. Mirrors the stream-recv /
                // conn-read bindable-await paths.
                if self.is_channel_recv_await(&SpanKey::from(&inner.1)) {
                    return self.lower_expr(inner, intent);
                }
                // NEW-7: `await sink.send(x)` over a `Sink<bytes>` — the checker
                // wired the inner method call to `hew_sink_write_bytes`. Strip the
                // `await` and lower the inner send directly (unit); the MIR
                // `SuspendingStreamSend` suspends on a full ring. Statement
                // position only (unit value), like `await actor.close()`.
                if self.is_stream_send_await(&SpanKey::from(&inner.1)) {
                    if !in_stmt_position {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::AwaitOutOfPosition,
                            span.clone(),
                            "`await sink.send(x)` is only legal as a statement-expression in v0.5",
                        ));
                        return HirExpr {
                            node: self.ids.node(),
                            site: self.ids.site(),
                            value_class: ValueClass::BitCopy,
                            ty: ResolvedTy::Unit,
                            intent,
                            kind: HirExprKind::Unsupported(
                                "`await sink.send(x)` out of position".to_string(),
                            ),
                            span,
                        };
                    }
                    return self.lower_expr(inner, intent);
                }
                if let Some(ActorMethodKind::Ask(_, reply_ty)) = self
                    .actor_method_dispatch
                    .get(&SpanKey::from(&inner.1))
                    .cloned()
                {
                    // Lower the inner ask expression (type = raw reply_ty) then
                    // upgrade its HIR type to `Result<reply_ty, AskError>` so
                    // that downstream HIR consumers (PostfixTry, MIR lowering)
                    // see the unified result type.  The MIR `lower_actor_ask`
                    // reads `expr.ty` to allocate the `result_dest` slot.
                    let ask_error_ty = ResolvedTy::Named {
                        name: "AskError".to_string(),
                        args: Vec::new(),
                        builtin: Some(BuiltinType::AskError),
                        is_opaque: false,
                    };
                    let result_ty = match ResolvedTy::from_ty(&reply_ty) {
                        Ok(r) => ResolvedTy::Named {
                            name: "Result".to_string(),
                            args: vec![r, ask_error_ty],
                            builtin: Some(BuiltinType::Result),
                            is_opaque: false,
                        },
                        Err(_) => {
                            // Fallback: return raw expr if reply_ty doesn't resolve;
                            // the checker already emitted an error in this case.
                            return self.lower_expr(inner, intent);
                        }
                    };
                    let mut ask_expr = self.lower_expr(inner, intent);
                    ask_expr.ty = result_ty;
                    return ask_expr;
                }
                // `await actor.close()` — lambda-actor (Duplex) close is awaitable
                // in statement position at any scope depth.  The checker records
                // `hew_duplex_close` as the method rewrite; the `await` is stripped
                // and the inner close call is lowered directly, matching the existing
                // `ActorMethodKind::Ask` path above.
                if matches!(
                    self.method_call_rewrites.get(&SpanKey::from(&inner.1)),
                    Some(MethodCallRewrite::RewriteToFunction { c_symbol, .. })
                        if c_symbol == "hew_duplex_close"
                ) {
                    if !in_stmt_position {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::AwaitOutOfPosition,
                            span.clone(),
                            "`await actor.close()` is only legal as a statement-expression in v0.5",
                        ));
                        return HirExpr {
                            node: self.ids.node(),
                            site: self.ids.site(),
                            value_class: ValueClass::BitCopy,
                            ty: ResolvedTy::Unit,
                            intent,
                            kind: HirExprKind::Unsupported(
                                "`await actor.close()` out of position".to_string(),
                            ),
                            span,
                        };
                    }
                    return self.lower_expr(inner, intent);
                }
                // `await expr` — only legal as the direct statement-expression
                // inside a `scope{}` body in v0.5 (TI-4). Sub-expression positions
                // (return value, function argument, binary operand, let value, block
                // tail, etc.) are rejected with `AwaitOutOfPosition`.
                // `in_stmt_position` is set by `Stmt::Expression` in `lower_stmt`
                // and consumed by `mem::replace` at the top of this function, so
                // recursive calls always see `false`.
                if self.scope_depth == 0 || !in_stmt_position {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::AwaitOutOfPosition,
                        span.clone(),
                        "`await` is only legal as a statement-expression inside a `scope{}` body \
                         in v0.5. It cannot be used as a return value, function argument, \
                         binary operand, or let-value. Move the await to its own statement.",
                    ));
                    return HirExpr {
                        node: self.ids.node(),
                        site: self.ids.site(),
                        value_class: ValueClass::BitCopy,
                        ty: ResolvedTy::Unit,
                        intent,
                        kind: HirExprKind::Unsupported("`await` out of position".to_string()),
                        span,
                    };
                }
                // Resolve the inner expression. It must be a binding-ref with a
                // `Task<T>` type to be awaitable.
                let inner_hir = self.lower_expr(inner, IntentKind::Consume);
                match &inner_hir.ty {
                    ResolvedTy::Task(output_ty) => {
                        let output_ty = *output_ty.clone();
                        // Extract the binding name and id for the AwaitTask node.
                        // The inner expression must be a direct binding-ref; await
                        // on a complex expression is not supported in v0.5.
                        if let HirExprKind::BindingRef {
                            name: binding_name,
                            resolved: ResolvedRef::Binding(binding_id),
                        } = &inner_hir.kind
                        {
                            let (binding_name, binding_id) = (binding_name.clone(), *binding_id);
                            let value_class = ValueClass::of_ty(&output_ty, &self.type_classes);
                            return HirExpr {
                                node: self.ids.node(),
                                site: self.ids.site(),
                                value_class,
                                ty: output_ty.clone(),
                                intent,
                                kind: HirExprKind::AwaitTask {
                                    binding_name,
                                    binding_id,
                                    output_ty,
                                },
                                span,
                            };
                        }
                        // Await on a non-binding-ref Task<T>: reject. The form
                        // `await (some_expr)` where the expr is not a name is not
                        // supported — only named bindings can be awaited.
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::AwaitOutOfPosition,
                            span.clone(),
                            "`await` requires a named task binding, not an expression",
                        ));
                        (
                            HirExprKind::Unsupported("`await` on non-binding-ref task".to_string()),
                            ResolvedTy::Unit,
                        )
                    }
                    found_ty => {
                        // The operand is not a Task<T> — reject with AwaitNonTask.
                        let found_ty = found_ty.clone();
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::AwaitNonTask {
                                found_ty: found_ty.clone(),
                            },
                            span.clone(),
                            "`await` requires a task handle (`Task<T>`). \
                             Hint: did you mean to bind a task with `fork name = call(...)` first?",
                        ));
                        (
                            HirExprKind::Unsupported("`await` on non-task".to_string()),
                            ResolvedTy::Unit,
                        )
                    }
                }
            }
            Expr::Select { arms, timeout } => {
                self.lower_select(arms, timeout.as_deref(), span.clone())
            }
            Expr::Spawn { target, args, .. } => self.lower_spawn(target, args, span.clone()),
            Expr::SpawnLambdaActor {
                params,
                return_type,
                body,
                ..
            } => self.lower_spawn_lambda_actor(params, return_type.as_ref(), body),
            Expr::Lambda {
                params,
                return_type,
                body,
                ..
            } => self.lower_closure(params, return_type.as_ref(), body, span.clone()),
            Expr::GenBlock { body } => self.lower_gen_block(body, span.clone()),
            Expr::Yield(value) => {
                let value = value
                    .as_deref()
                    .map(|value| Box::new(self.lower_expr(value, IntentKind::Read)));
                let yield_ty = if let Some(yield_ty) = self.generator_yield_tys.last() {
                    yield_ty.clone()
                } else {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: "yield".to_string(),
                            reason: "yield expression lowered outside an enclosing gen block"
                                .to_string(),
                        },
                        span.clone(),
                        "yield expression has no enclosing generator yield type",
                    ));
                    ResolvedTy::Unit
                };
                (HirExprKind::Yield { value, yield_ty }, ResolvedTy::Unit)
            }
            Expr::MethodCall {
                receiver,
                method,
                args,
            } => self.lower_method_call(receiver, method, args, span.clone(), site),
            Expr::UnsafeBlock(block) => {
                // Unsafe clearance is a checker-only concept; the HIR represents the
                // body as a plain block.  The `in_unsafe` flag pushed by the type
                // checker is not carried into HIR or MIR — pointer and FFI safety
                // obligations are enforced by the checker before lowering.
                let hir_block = self.lower_block(block, &ResolvedTy::Unit);
                let ty = hir_block.ty.clone();
                (HirExprKind::Block(hir_block), ty)
            }
            Expr::Index { object, index } => {
                // The checker records the element/result type at the whole
                // index expression's span. LESSONS: `checker-authority` P0 —
                // we never re-derive the element type from the container;
                // the checker is the sole owner.
                let checker_key = SpanKey::from(&span);
                let result_ty = if let Some(ty) = self.expr_types.get(&checker_key).cloned() {
                    match ResolvedTy::from_ty(&ty) {
                        Ok(resolved) => resolved,
                        Err(err) => {
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::CheckerBoundaryViolation {
                                    name: "xs[..]".to_string(),
                                    reason: err.to_string(),
                                },
                                span.clone(),
                                "checker-authoritative index/slice result type failed boundary conversion",
                            ));
                            ResolvedTy::Unit
                        }
                    }
                } else {
                    // Fall through: no checker entry. This can happen when the
                    // checker emitted an error for this expression (e.g.
                    // indexing into a non-Vec) and skipped recording the
                    // type. The diagnostic from the checker covers the
                    // user-facing error; emit Unit to stay well-formed.
                    ResolvedTy::Unit
                };

                // Distinguish range-slice (`xs[a..b]` and the four open-end
                // forms) from single-element indexing (`xs[i]`). The parser
                // emits `Expr::Range` only when the bracket contents are a
                // range; all other expressions remain as `Expr::Index`.
                let container = self.lower_expr(object, IntentKind::Read);
                if let Expr::Range {
                    start,
                    end,
                    inclusive,
                } = &index.0
                {
                    // C-3 range-slice: result type is Vec<T> (checker-authoritative).
                    let lowered_start = start
                        .as_ref()
                        .map(|s| Box::new(self.lower_expr(s, IntentKind::Read)));
                    let lowered_end = end
                        .as_ref()
                        .map(|e| Box::new(self.lower_expr(e, IntentKind::Read)));
                    (
                        HirExprKind::Slice {
                            container: Box::new(container),
                            start: lowered_start,
                            end: lowered_end,
                            inclusive: *inclusive,
                        },
                        result_ty,
                    )
                } else {
                    let index_expr = self.lower_expr(index, IntentKind::Read);
                    if let Some(dyn_call) = self
                        .dyn_trait_method_calls
                        .get(&SpanKey::from(&span))
                        .cloned()
                    {
                        return HirExpr {
                            node: self.ids.node(),
                            site,
                            value_class: ValueClass::of_ty(&result_ty, &self.type_classes),
                            ty: result_ty.clone(),
                            intent,
                            kind: HirExprKind::CallDynMethod {
                                receiver: Box::new(container),
                                trait_name: dyn_call.trait_name,
                                method_name: dyn_call.method_name,
                                slot: dyn_call.slot,
                                args: vec![index_expr],
                                ret_ty: result_ty,
                                signature: Box::new(dyn_call.signature),
                            },
                            span: span.clone(),
                        };
                    }

                    // `m[k]` over a `HashMap<K, V>` reuses the `.get(k)` runtime
                    // ABI in READ position. The checker recorded a `ResolvedCall`
                    // to `hew_hashmap_get_layout` at this span (result type
                    // `Option<V>`); emit the same `ResolvedImplCall` that
                    // `m.get(k)` produces so MIR/codegen consume the existing
                    // Option-projecting get path verbatim.
                    //
                    // An assignment target (`m[k] = v`, `IntentKind::Modify`)
                    // must NOT take the read path — it falls through to the plain
                    // `HirExprKind::Index` node below, which the MIR `assign`
                    // arm recognises and lowers to `hew_hashmap_insert_layout`.
                    if intent != IntentKind::Modify
                        && matches!(&container.ty, ResolvedTy::Named { name, .. } if name == "HashMap")
                    {
                        if let Some(resolved) =
                            self.resolved_calls.get(&SpanKey::from(&span)).cloned()
                        {
                            // Register the `Option<V>` instantiation so the
                            // module enum-layout table carries the matching key
                            // (mirrors the `HashMap::get` method-call path).
                            self.try_register_enum_instantiation(&span);
                            return HirExpr {
                                node: self.ids.node(),
                                site,
                                value_class: ValueClass::of_ty(&result_ty, &self.type_classes),
                                ty: result_ty.clone(),
                                intent,
                                kind: HirExprKind::ResolvedImplCall {
                                    receiver: Box::new(container),
                                    impl_id: resolved.impl_id,
                                    method_name: resolved.method_name,
                                    target_symbol: resolved.target.symbol_name,
                                    type_args: resolved.type_args,
                                    args: vec![index_expr],
                                    ret_ty: result_ty.clone(),
                                },
                                span: span.clone(),
                            };
                        }
                    }

                    if let ResolvedTy::Named { name, .. } = &container.ty {
                        let callee_name = format!("{name}::at");
                        if name != "Vec" && self.fn_registry.contains_key(&callee_name) {
                            let callee_ty = ResolvedTy::Function {
                                params: vec![container.ty.clone(), index_expr.ty.clone()],
                                ret: Box::new(result_ty.clone()),
                            };
                            let resolved = self
                                .fn_registry
                                .get(&callee_name)
                                .map_or(ResolvedRef::Unresolved, |entry| {
                                    ResolvedRef::Item(entry.id)
                                });
                            let callee = HirExpr {
                                node: self.ids.node(),
                                site: self.ids.site(),
                                value_class: ValueClass::PersistentShare,
                                ty: callee_ty,
                                intent: IntentKind::Read,
                                kind: HirExprKind::BindingRef {
                                    name: callee_name,
                                    resolved,
                                },
                                span: span.clone(),
                            };
                            return HirExpr {
                                node: self.ids.node(),
                                site,
                                value_class: ValueClass::of_ty(&result_ty, &self.type_classes),
                                ty: result_ty.clone(),
                                intent,
                                kind: HirExprKind::Call {
                                    callee: Box::new(callee),
                                    args: vec![container, index_expr],
                                },
                                span: span.clone(),
                            };
                        }
                    }

                    // C-2 single-element Vec indexing: result type is element type T.
                    (
                        HirExprKind::Index {
                            container: Box::new(container),
                            index: Box::new(index_expr),
                        },
                        result_ty,
                    )
                }
            }
            Expr::Is { lhs, rhs } => {
                if self.is_type_patterns.contains_key(&SpanKey::from(&rhs.1)) {
                    // The checker only records this side-table entry after
                    // proving the static lhs type matches the RHS type pattern.
                    // Do not lower the RHS identifier through the value namespace.
                    (
                        HirExprKind::Literal(HirLiteral::Bool(true)),
                        ResolvedTy::Bool,
                    )
                } else {
                    // Identity comparison: `lhs is rhs`. The checker (D-2) has already
                    // validated that both operands carry identity-bearing types and
                    // that neither is a scalar/String/record. The result is `bool`.
                    // LESSONS: `checker-authority` P0 — we do not re-validate the
                    // allowance set here; that is the checker's sole responsibility.
                    let left = self.lower_expr(lhs, IntentKind::Read);
                    let right = self.lower_expr(rhs, IntentKind::Read);
                    (
                        HirExprKind::IdentityCompare {
                            left: Box::new(left),
                            right: Box::new(right),
                        },
                        ResolvedTy::Bool,
                    )
                }
            }
            Expr::FieldAccess { object, field } => {
                // Inside a machine transition body, `self.field` accesses are
                // `Expr::FieldAccess { object: Expr::This, field }`. Resolve to
                // `MachineFieldAccess` using the source state's declared payload fields.
                //
                // HIR-side authority: the checker does not produce `expr_types` entries
                // for `self.field` inside machine bodies. The result type and field_idx
                // are derived from `current_machine_states[source_state_idx].fields`.
                // The parser emits `Expr::This` for the dedicated `this`
                // keyword and `Expr::Identifier("self")` for the bare `self`
                // identifier (the conventional machine-body receiver). Both
                // forms route to the same machine-self-field resolver inside
                // a machine transition body.
                let is_self_receiver = matches!(&object.0, Expr::This)
                    || matches!(&object.0, Expr::Identifier(name) if name == "self")
                        && self.current_machine_name.is_some();
                if is_self_receiver {
                    if let Some(hir_expr) =
                        self.try_lower_machine_self_field_access(field, &span, site, intent)
                    {
                        return hir_expr;
                    }
                    // If we're not in a machine body with a known source state, fall
                    // through to the catch-all below (which will emit `NotYetImplemented`
                    // because `Expr::This` is not otherwise handled).
                }
                if matches!(&object.0, Expr::Identifier(name) if name == "event")
                    && self.current_machine_name.is_some()
                {
                    if let Some(hir_expr) =
                        self.try_lower_machine_event_field_access(field, &span, site, intent)
                    {
                        return hir_expr;
                    }
                }
                // Pre-dispatch: module-qualified constant reference, e.g.
                // `module_short.CONST_NAME`.  The type checker accepted this as
                // a qualified const access and registered the result type in
                // `expr_types`; the HIR must produce a `BindingRef { Const(id) }`
                // rather than falling through to the generic struct-field path
                // (which would `lower_expr(object)` on a bare module name and
                // fail with `UnresolvedSymbol`).
                //
                // Guard: object is a bare `Expr::Identifier` and the qualified
                // key `"{module_short}.{field}"` is in `const_registry`.  The
                // `const_registry` pre-pass inserts pub consts from every
                // imported module under qualified keys, so any hit here is
                // authoritative.
                if let Expr::Identifier(module_name) = &object.0 {
                    let qualified_key = format!("{module_name}.{field}");
                    if let Some(entry) = self.const_registry.get(&qualified_key).cloned() {
                        let ty = entry.ty.clone();
                        let id = entry.id;
                        return HirExpr {
                            node: self.ids.node(),
                            site,
                            value_class: ValueClass::of_ty(&ty, &self.type_classes),
                            ty,
                            intent,
                            kind: HirExprKind::BindingRef {
                                name: qualified_key,
                                resolved: ResolvedRef::Const(id),
                            },
                            span,
                        };
                    }
                }

                let missing_import = if let Expr::Identifier(module_name) = &object.0 {
                    self.missing_stdlib_module_import(module_name)
                        .map(|module| (module_name, module))
                } else {
                    None
                };
                if let Some((module_name, module)) = missing_import {
                    let name = format!("{module_name}.{field}");
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::ImportMissing {
                            module: module.to_string(),
                            name,
                        },
                        span.clone(),
                        stdlib_catalog::missing_import_hint(module),
                    ));
                    (
                        HirExprKind::FieldAccess {
                            object: Box::new(
                                self.unresolved_module_object(module_name, object.1.clone()),
                            ),
                            field: field.clone(),
                        },
                        ResolvedTy::Unit,
                    )
                } else {
                    // Named-field read on a record or struct type, or numeric
                    // projection on a tuple type (`t.0`). The checker has already
                    // resolved the field and recorded the result type in
                    // `expr_types`. LESSONS: `checker-authority` P0 — the type of
                    // the field read comes exclusively from the checker side-table,
                    // never re-derived here.
                    let hir_object = self.lower_expr(object, IntentKind::Read);
                    let tuple_index = match &hir_object.ty {
                        ResolvedTy::Tuple(elements) => field
                            .parse::<usize>()
                            .ok()
                            .map(|index| (index, elements.get(index).cloned(), elements.len())),
                        _ => None,
                    };
                    if let Some((index, expected_ty, tuple_len)) = tuple_index {
                        if let Some(expected_ty) = expected_ty {
                            if let Some(field_ty) =
                                self.checker_expr_ty(&span, "tuple field access")
                            {
                                if field_ty == expected_ty {
                                    (
                                        HirExprKind::TupleIndex {
                                            tuple: Box::new(hir_object),
                                            index,
                                        },
                                        field_ty,
                                    )
                                } else {
                                    self.diagnostics.push(HirDiagnostic::new(
                                        HirDiagnosticKind::CheckerBoundaryViolation {
                                            name: format!("tuple index .{index}"),
                                            reason: format!(
                                                "checker result type {} does not match tuple element type {}",
                                                field_ty.user_facing(),
                                                expected_ty.user_facing()
                                            ),
                                        },
                                        span.clone(),
                                        "tuple field access result type must match the projected element",
                                    ));
                                    (
                                        HirExprKind::Unsupported(
                                            "tuple field access checker type mismatch".to_string(),
                                        ),
                                        ResolvedTy::Unit,
                                    )
                                }
                            } else {
                                (
                                    HirExprKind::Unsupported(
                                        "tuple field access missing checker result type"
                                            .to_string(),
                                    ),
                                    ResolvedTy::Unit,
                                )
                            }
                        } else {
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::CheckerBoundaryViolation {
                                    name: format!("tuple index .{index}"),
                                    reason: format!(
                                        "tuple index out of range: tuple has {tuple_len} elements"
                                    ),
                                },
                                span.clone(),
                                "tuple field access must be in bounds",
                            ));
                            (
                                HirExprKind::Unsupported(
                                    "tuple field access index out of bounds".to_string(),
                                ),
                                ResolvedTy::Unit,
                            )
                        }
                    } else {
                        let checker_key = SpanKey::from(&span);
                        let field_ty = if let Some(ty) = self.expr_types.get(&checker_key).cloned()
                        {
                            match ResolvedTy::from_ty(&ty) {
                                Ok(resolved) => resolved,
                                Err(err) => {
                                    let diagnostic = HirDiagnostic::new(
                                        HirDiagnosticKind::CheckerBoundaryViolation {
                                            name: field.clone(),
                                            reason: err.to_string(),
                                        },
                                        span.clone(),
                                        "field-access result type failed checker-boundary conversion",
                                    );
                                    self.diagnostics.push(diagnostic);
                                    ResolvedTy::Unit
                                }
                            }
                        } else {
                            // No checker entry: malformed checker output. Fail-closed.
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::CheckerBoundaryViolation {
                                    name: field.clone(),
                                    reason: "expr_types has no entry for field-access site".into(),
                                },
                                span.clone(),
                                "field-access result type missing from checker side-table",
                            ));
                            ResolvedTy::Unit
                        };
                        // Checker-authority: if the checker recorded a supervisor
                        // child-slot for this field-access span, propagate it into
                        // the accumulator keyed by the pre-allocated SiteId. MIR
                        // (S2) reads `HirModule.supervisor_child_slots` to intercept
                        // these sites before the `record_field_orders` path.
                        // Mirrors the `call_site_type_args` pattern (lower.rs line 1127).
                        if let Some(slot) = self.supervisor_child_slots_checker.get(&checker_key) {
                            self.supervisor_child_slots.insert(site, slot.clone());
                        }
                        (
                            HirExprKind::FieldAccess {
                                object: Box::new(hir_object),
                                field: field.clone(),
                            },
                            field_ty,
                        )
                    }
                }
            }
            Expr::MachineEmit { event_name, fields } => {
                // Lower `emit EventName { field: value, ... }` to
                // `HirExprKind::MachineEmit { event_idx, fields }`.
                //
                // Resolution: look up the event name in `current_machine_events`
                // (set by `lower_machine_expr_filtered` / `lower_machine_block_filtered`).
                // Outside a machine body (e.g. a bare `emit` in a function) the
                // context is absent and we produce `UnresolvedSymbol` to fail
                // closed — `emit` outside a machine body is already rejected by
                // the parser / static checks.
                let event_idx_opt = self
                    .current_machine_events
                    .as_ref()
                    .and_then(|names| names.iter().position(|n| n == event_name));
                if let Some(event_idx) = event_idx_opt {
                    let lowered_fields: Vec<(String, HirExpr)> = fields
                        .iter()
                        .map(|(fname, fval)| {
                            let hir_val = self.lower_expr(fval, IntentKind::Read);
                            (fname.clone(), hir_val)
                        })
                        .collect();
                    (
                        HirExprKind::MachineEmit {
                            event_idx,
                            fields: lowered_fields,
                        },
                        ResolvedTy::Unit,
                    )
                } else {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::UnresolvedSymbol {
                            name: event_name.clone(),
                        },
                        span.clone(),
                        format!("emitted event `{event_name}` is not declared in this machine"),
                    ));
                    (
                        HirExprKind::Unsupported(format!("unresolved emit event `{event_name}`")),
                        ResolvedTy::Unit,
                    )
                }
            }
            Expr::Match { scrutinee, arms } => self.lower_match_expr(scrutinee, arms, &span),
            Expr::PostfixTry(inner) => self.lower_postfix_try(inner, &span),
            Expr::InterpolatedString(parts) => self.lower_interpolated_string(parts, span.clone()),
            Expr::Tuple(elems) => self.lower_tuple_literal(elems, &span),
            Expr::Array(elems) => self.lower_array_literal(elems, &span),
            Expr::Cast { expr: value, ty } => self.lower_numeric_cast_expr(value, ty, &span),
            Expr::IfLet {
                pattern,
                expr: scrutinee_expr,
                body,
                else_body,
            } => {
                // Expression-position `if let` — delegates to the shared helper.
                // The result type is looked up from the checker's `resolved_expr_types`
                // side-table, mirroring `Expr::If` (same authority path).
                let result_ty = self
                    .resolved_expr_types
                    .get(&SpanKey::from(&span))
                    .cloned()
                    .unwrap_or(ResolvedTy::Unit);
                match self.lower_if_let_inner(
                    pattern,
                    scrutinee_expr,
                    body,
                    else_body.as_ref(),
                    &result_ty,
                    &span,
                ) {
                    Some(kind) => (kind, result_ty),
                    None => (
                        HirExprKind::Unsupported("if-let lowering failed".into()),
                        ResolvedTy::Unit,
                    ),
                }
            }
            Expr::Timeout {
                expr: timeout_inner,
                duration,
            } => {
                return self.lower_await_deadline(timeout_inner, duration, &span, intent);
            }
            _ => {
                self.unsupported(span.clone(), "expression", "slice-2");
                (
                    HirExprKind::Unsupported("unsupported expression".into()),
                    ResolvedTy::Unit,
                )
            }
        };
        let inner = HirExpr {
            node: self.ids.node(),
            site,
            value_class: if Self::is_vec_iter_ty(&ty) {
                ValueClass::CowValue
            } else {
                ValueClass::of_ty(&ty, &self.type_classes)
            },
            ty,
            intent,
            kind,
            span: span.clone(),
        };
        // Checker-authority coercion: if the just-lowered expression sits at
        // a `T → dyn Trait` coercion site (recorded by the type checker at
        // the *argument* expression span), wrap the result in
        // `HirExprKind::CoerceToDynTrait`. MIR lowers this 1:1 to
        // `Instr::CoerceToDynTrait`. The wrapping ResolvedTy is the
        // destination trait-object type, which the wrapping HirExpr
        // carries; the inner expression keeps its concrete type.
        let coercion_key = SpanKey::from(&span);
        if let Some(coercion) = self.dyn_trait_coercions.get(&coercion_key).cloned() {
            let mut resolved_bounds = Vec::new();
            for name in coercion.trait_name.split('+') {
                let mut assoc_bindings = Vec::new();
                for binding in coercion
                    .assoc_bindings
                    .iter()
                    .filter(|binding| binding.trait_name == name)
                {
                    let Ok(ty) = hew_types::ResolvedTy::from_ty(&binding.ty) else {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::CheckerBoundaryViolation {
                                name: "dyn-trait assoc binding".to_string(),
                                reason: format!(
                                    "`{}::{}` failed boundary conversion",
                                    binding.trait_name, binding.assoc_name
                                ),
                            },
                            span.clone(),
                            "associated type binding from dyn_trait_coercions failed boundary conversion",
                        ));
                        return inner;
                    };
                    assoc_bindings.push((binding.assoc_name.clone(), ty));
                }
                resolved_bounds.push(hew_types::ResolvedTraitBound {
                    trait_name: name.to_string(),
                    args: vec![],
                    assoc_bindings,
                });
            }
            let dyn_ty = ResolvedTy::TraitObject {
                traits: resolved_bounds,
            };
            let concrete_resolved = match ResolvedTy::from_ty(&coercion.concrete_type) {
                Ok(r) => r,
                Err(err) => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: "dyn-trait coercion".to_string(),
                            reason: err.to_string(),
                        },
                        span.clone(),
                        "concrete type from dyn_trait_coercions failed boundary conversion",
                    ));
                    return inner;
                }
            };
            return HirExpr {
                node: self.ids.node(),
                site: self.ids.site(),
                value_class: ValueClass::of_ty(&dyn_ty, &self.type_classes),
                ty: dyn_ty,
                intent,
                kind: HirExprKind::CoerceToDynTrait {
                    value: Box::new(inner),
                    trait_name: coercion.trait_name,
                    concrete_type: concrete_resolved,
                    method_table: coercion.method_table,
                    vtable_entries: coercion.vtable_entries,
                },
                span,
            };
        }
        inner
    }

    /// Derive the HIR binding type for a select arm's named pattern.
    ///
    /// For `ActorAsk` arms the reply type comes from the checker-authoritative
    /// `actor_method_dispatch` table keyed on the arm source expression's span.
    /// For `StreamNext` and `TaskAwait` arms `Unit` is returned as a placeholder
    /// — these arm kinds remain unsupported through MIR (slice 2+) and the real
    /// element type is recoverable from the lowered source expression's `.ty`
    /// field when those slices land. WHY placeholder: HIR has no type-inference
    /// machinery; keeping a real element type here would require either duplicating
    /// the checker's unification or adding a side table entry. WHEN obsolete: when
    /// `StreamNext` and `TaskAwait` arm lowering lands in slice 2+.
    fn select_arm_binding_ty(
        &self,
        kind: &HirSelectArmKind,
        source_span: &std::ops::Range<usize>,
    ) -> ResolvedTy {
        match kind {
            HirSelectArmKind::ActorAsk { .. } => {
                match self
                    .actor_method_dispatch
                    .get(&SpanKey::from(source_span))
                    .cloned()
                {
                    Some(ActorMethodKind::Ask(_, reply_ty)) => {
                        // W4.047 P1.2: the actor-ask reply type comes from the
                        // checker-authoritative `actor_method_dispatch` table
                        // (materialized at the checker boundary), not from
                        // `expr_types`. The fail-open `.unwrap_or(Unit)` below
                        // would silently install the *wrong* reply-channel ABI
                        // if `from_ty` ever failed. Prove it cannot for a
                        // concrete reply type: a conversion failure is only
                        // admissible for a covered generic var (resolved at
                        // monomorphization). No behaviour change.
                        debug_assert!(
                            ResolvedTy::from_ty(&reply_ty).is_ok() || reply_ty.has_inference_var(),
                            "W4.047 totality: actor-ask reply type {reply_ty:?} fails \
                             ResolvedTy::from_ty without being a covered generic var — \
                             the fail-open .unwrap_or(Unit) would install the wrong \
                             reply-channel ABI"
                        );
                        ResolvedTy::from_ty(&reply_ty).unwrap_or(ResolvedTy::Unit)
                    }
                    Some(ActorMethodKind::Fire(_)) | None => ResolvedTy::Unit,
                }
            }
            HirSelectArmKind::ChannelRecv { elem_is_int, .. } => {
                // The binding receives `Option<T>` — the same shape the awaited
                // `rx.recv()` produces. `None` is the channel-closed signal.
                let elem = if *elem_is_int {
                    ResolvedTy::I64
                } else {
                    ResolvedTy::String
                };
                Self::resolved_option_ty(elem)
            }
            HirSelectArmKind::StreamNext { .. }
            | HirSelectArmKind::TaskAwait { .. }
            | HirSelectArmKind::AfterTimer { .. } => ResolvedTy::Unit,
        }
    }

    /// Lower a parsed `select { ... }` expression to HIR.
    ///
    /// Per HEW-SPEC-2026 §4.11.1 the four arm forms are exhaustive:
    ///   1. `pat from next(<stream-expr>) => body`
    ///   2. `pat from <actor-expr>.<method>(<args>) => body`   (actor ask)
    ///   3. `pat from await <task-expr> => body`
    ///   4. `after <duration-expr> => body`                    (timer)
    ///
    /// Any other arm source shape is rejected with
    /// `SelectArmNotSealedForm`. Body-type disagreement is rejected
    /// with `SelectArmTypeMismatch`. Empty selects and multiple-after
    /// arms are rejected with `SelectNoArms` and
    /// `SelectMultipleAfterArms` respectively.
    fn lower_select(
        &mut self,
        arms: &[SelectArm],
        timeout: Option<&TimeoutClause>,
        span: std::ops::Range<usize>,
    ) -> (HirExprKind, ResolvedTy) {
        // Empty select — neither arms nor a timer — fires nothing.
        if arms.is_empty() && timeout.is_none() {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::SelectNoArms,
                span.clone(),
                "select expression contains no arms",
            ));
            return (
                HirExprKind::Unsupported("empty select".into()),
                ResolvedTy::Unit,
            );
        }

        // Multiple `after` arms have no meaningful join semantics and are
        // rejected. An `Expr::Timeout`-sourced arm in the `arms` vec is
        // treated as an `AfterTimer` arm; if that is combined with the
        // dedicated `timeout` field (or if two appear in `arms`) the
        // second one triggers `SelectMultipleAfterArms`.

        let mut hir_arms: Vec<HirSelectArm> = Vec::with_capacity(arms.len() + 1);
        let mut expected_ty: Option<ResolvedTy> = None;
        let mut first_after_span: Option<std::ops::Range<usize>> = None;

        for arm in arms {
            let binding_name = self.pattern_name(&arm.binding);
            let kind = self.recognize_sealed_arm_source(&arm.source);
            if matches!(kind, HirSelectArmKind::AfterTimer { .. }) {
                if first_after_span.is_some() {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::SelectMultipleAfterArms,
                        arm.source.1.clone(),
                        "select may have at most one `after` arm",
                    ));
                } else {
                    first_after_span = Some(arm.source.1.clone());
                }
            }
            // Each arm body lowers inside its own scope so `binding_name`
            // resolves to this arm's reply value within the body, and is
            // invisible to sibling arms and the surrounding scope.
            //
            // The `BindingId` returned by `bind()` is recorded on the
            // arm so MIR's `Terminator::Select` producer can register
            // `binding_locals[id] = <reply_dest_place>` before lowering
            // the arm body; without this id the body's `BindingRef`
            // resolves to an unbound `Place` and falls back to
            // `MirDiagnosticKind::UnresolvedPlace`.
            self.push_scope();
            let binding_id = if let Some(ref name) = binding_name {
                let binding_ty = self.select_arm_binding_ty(&kind, &arm.source.1);
                let bound = self.bind(name.clone(), binding_ty, false, arm.binding.1.clone());
                Some(bound.id)
            } else {
                None
            };
            let body = self.lower_expr(&arm.body, IntentKind::Read);
            self.pop_scope();
            if let Some(expected) = expected_ty.as_ref() {
                if &body.ty != expected {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::SelectArmTypeMismatch {
                            arm_index: hir_arms.len(),
                            expected: expected.clone(),
                            actual: body.ty.clone(),
                        },
                        arm.body.1.clone(),
                        "select arm body type differs from the first arm body type",
                    ));
                }
            } else {
                expected_ty = Some(body.ty.clone());
            }
            hir_arms.push(HirSelectArm {
                kind,
                binding_name,
                binding_id,
                body,
            });
        }

        if let Some(timeout) = timeout {
            if first_after_span.is_some() {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::SelectMultipleAfterArms,
                    timeout.duration.1.clone(),
                    "select may have at most one `after` arm",
                ));
            }
            let duration = self.lower_expr(&timeout.duration, IntentKind::Read);
            let body = self.lower_expr(&timeout.body, IntentKind::Read);
            if let Some(expected) = expected_ty.as_ref() {
                if &body.ty != expected {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::SelectArmTypeMismatch {
                            arm_index: hir_arms.len(),
                            expected: expected.clone(),
                            actual: body.ty.clone(),
                        },
                        timeout.body.1.clone(),
                        "select after-arm body type differs from earlier arm body types",
                    ));
                }
            } else {
                expected_ty = Some(body.ty.clone());
            }
            hir_arms.push(HirSelectArm {
                kind: HirSelectArmKind::AfterTimer {
                    duration: Box::new(duration),
                },
                binding_name: None,
                binding_id: None,
                body,
            });
        }

        let result_ty = expected_ty.unwrap_or(ResolvedTy::Unit);
        (HirExprKind::Select(HirSelect { arms: hir_arms }), result_ty)
    }

    /// Build the `Duplex<Msg, Reply>` `ResolvedTy` for an actor-lambda
    /// from its parameter list and optional return-type annotation.
    /// Mirrors the forward-bind logic in `hew-types::check::statements`:
    /// zero params → Unit message; one param → that param's type;
    /// multiple params → tuple of param types. The HIR layer only needs
    /// a placeholder shape so the forward-bind succeeds and capture
    /// resolution sees the let-name.
    ///
    /// SHIM — `ResolvedTy::Unit` for missing param / return annotations.
    ///
    /// - WHY: HIR has no type-inference machinery; the slice-2 type
    ///   checker uses `TypeVar::fresh()` to allocate inference variables
    ///   which HIR cannot represent. The forward-bind only needs a
    ///   syntactic placeholder so the body's recursive self-reference
    ///   resolves to a `BindingId`; the actual type identity is
    ///   reconstructed downstream.
    /// - WHEN OBSOLETE: either HIR gains a placeholder type variant
    ///   (an explicit `ResolvedTy::Hole` or equivalent) for forward-bind
    ///   sites, or the post-typecheck pipeline rewrites HIR binding
    ///   types from the slice-2 unifier's substitution table via a
    ///   side-table keyed on `BindingId`.
    /// - REAL SOLUTION: lift the slice-2 unifier's substitution into a
    ///   `BindingId → Ty` side-table emitted alongside HIR and consumed
    ///   by MIR lowering, so HIR never has to invent a stand-in.
    fn actor_lambda_duplex_ty(
        &mut self,
        params: &[LambdaParam],
        return_type: Option<&Spanned<TypeExpr>>,
    ) -> ResolvedTy {
        let param_tys: Vec<ResolvedTy> = params
            .iter()
            .map(|p| {
                p.ty.as_ref()
                    .map_or(ResolvedTy::Unit, |annotation| self.lower_type(annotation))
            })
            .collect();
        let msg_ty = match param_tys.len() {
            0 => ResolvedTy::Unit,
            1 => param_tys.into_iter().next().unwrap(),
            _ => ResolvedTy::Tuple(param_tys),
        };
        let reply_ty = return_type
            .as_ref()
            .map_or(ResolvedTy::Unit, |ann| self.lower_type(ann));
        ResolvedTy::Named {
            name: "Duplex".to_string(),
            args: vec![msg_ty, reply_ty],
            builtin: Some(hew_types::BuiltinType::Duplex),
            is_opaque: false,
        }
    }

    fn closure_signature_from_ty(ty: &ResolvedTy) -> Option<(Vec<ResolvedTy>, ResolvedTy)> {
        match ty {
            ResolvedTy::Function { params, ret } | ResolvedTy::Closure { params, ret, .. } => {
                Some((params.clone(), ret.as_ref().clone()))
            }
            _ => None,
        }
    }

    fn visible_outer_bindings(&self) -> HashMap<BindingId, OuterClosureBinding> {
        let mut visible_by_name: HashMap<String, ScopeBinding> = HashMap::new();
        for scope in self.scopes.iter().rev() {
            for (name, (id, ty, span)) in scope {
                visible_by_name
                    .entry(name.clone())
                    .or_insert_with(|| (*id, ty.clone(), span.clone()));
            }
        }
        visible_by_name
            .into_iter()
            .map(|(name, (id, ty, span))| (id, (name, ty, span)))
            .collect()
    }

    fn lower_gen_block(
        &mut self,
        body: &Block,
        span: std::ops::Range<usize>,
    ) -> (HirExprKind, ResolvedTy) {
        let checker_key = SpanKey::from(&span);
        let gen_ty = if let Some(ty) = self.expr_types.get(&checker_key).cloned() {
            match ResolvedTy::from_ty(&ty) {
                Ok(resolved) => resolved,
                Err(err) => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: "gen block".to_string(),
                            reason: err.to_string(),
                        },
                        span.clone(),
                        "gen block type failed checker-boundary conversion",
                    ));
                    ResolvedTy::Named {
                        name: "Generator".to_string(),
                        args: vec![ResolvedTy::Unit, ResolvedTy::Unit],
                        builtin: Some(hew_types::BuiltinType::Generator),
                        is_opaque: false,
                    }
                }
            }
        } else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: "gen block".to_string(),
                    reason: "expr_types has no entry for gen block site".to_string(),
                },
                span.clone(),
                "checker did not provide a Generator<Yield, Return> type for this gen block",
            ));
            ResolvedTy::Named {
                name: "Generator".to_string(),
                args: vec![ResolvedTy::Unit, ResolvedTy::Unit],
                builtin: Some(hew_types::BuiltinType::Generator),
                is_opaque: false,
            }
        };

        let (yield_ty, return_ty) = match &gen_ty {
            ResolvedTy::Named { name, args, .. } if name == "Generator" && args.len() == 2 => {
                (args[0].clone(), args[1].clone())
            }
            other => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: "gen block".to_string(),
                        reason: format!("expected Generator<Yield, Return>, got {other:?}"),
                    },
                    span.clone(),
                    "gen block checker type did not have Generator<Yield, Return> shape",
                ));
                (ResolvedTy::Unit, ResolvedTy::Unit)
            }
        };

        self.generator_yield_tys.push(yield_ty.clone());
        let lowered_body = self
            .with_current_return_type(return_ty.clone(), |ctx| ctx.lower_block(body, &return_ty));
        self.generator_yield_tys.pop();

        (
            HirExprKind::GenBlock {
                body: lowered_body,
                yield_ty,
                return_ty,
            },
            gen_ty,
        )
    }

    fn lower_closure(
        &mut self,
        params: &[LambdaParam],
        return_type: Option<&Spanned<TypeExpr>>,
        body: &Spanned<Expr>,
        span: std::ops::Range<usize>,
    ) -> (HirExprKind, ResolvedTy) {
        let checker_key = SpanKey::from(&span);
        let closure_ty = if let Some(ty) = self.expr_types.get(&checker_key).cloned() {
            match ResolvedTy::from_ty(&ty) {
                Ok(resolved) => resolved,
                Err(err) => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: "closure literal".to_string(),
                            reason: err.to_string(),
                        },
                        span.clone(),
                        "closure literal type failed checker-boundary conversion",
                    ));
                    ResolvedTy::Function {
                        params: vec![],
                        ret: Box::new(ResolvedTy::Unit),
                    }
                }
            }
        } else {
            let param_tys: Vec<ResolvedTy> = params
                .iter()
                .map(|p| {
                    p.ty.as_ref()
                        .map_or(ResolvedTy::Unit, |annotation| self.lower_type(annotation))
                })
                .collect();
            let ret_ty = return_type
                .as_ref()
                .map_or(ResolvedTy::Unit, |ann| self.lower_type(ann));
            ResolvedTy::Function {
                params: param_tys,
                ret: Box::new(ret_ty),
            }
        };

        let (signature_params, ret_ty) = Self::closure_signature_from_ty(&closure_ty)
            .unwrap_or_else(|| {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: "closure literal".to_string(),
                        reason: format!("expected Function/Closure type, got {closure_ty:?}"),
                    },
                    span.clone(),
                    "closure literal did not type as a callable value",
                ));
                (vec![], ResolvedTy::Unit)
            });

        let outer_bindings = self.visible_outer_bindings();
        self.push_scope();
        let mut hir_params: Vec<HirBinding> = Vec::with_capacity(params.len());
        for (idx, param) in params.iter().enumerate() {
            let ty = signature_params
                .get(idx)
                .cloned()
                .or_else(|| {
                    param
                        .ty
                        .as_ref()
                        .map(|annotation| self.lower_type(annotation))
                })
                .unwrap_or(ResolvedTy::Unit);
            let binding = self.bind(param.name.clone(), ty, false, 0..0);
            hir_params.push(binding);
        }
        let lowered_body = self
            .with_current_return_type(ret_ty.clone(), |ctx| ctx.lower_expr(body, IntentKind::Read));
        self.pop_scope();

        let checker_facts = if let Some(facts) = self.closure_capture_facts.get(&checker_key) {
            facts.clone()
        } else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: "closure literal".to_string(),
                    reason: "closure_capture_facts has no record for closure literal span"
                        .to_string(),
                },
                span.clone(),
                "closure literal reached HIR without checker capture metadata",
            ));
            Vec::new()
        };

        let captures =
            self.materialize_closure_captures(&lowered_body, &outer_bindings, checker_facts, span);

        // Conservative escape classification: when the checker did not emit
        // a `closure_escape_facts` entry for this literal (which would be a
        // boundary-fail-closed violation if it ever happened in steady
        // state), treat the closure as `Escapes` per R242=B. We do not
        // synthesize a `CheckerBoundaryViolation` here because the
        // boundary-pin runs in `into_result()` and the conservative
        // fall-through keeps the MIR path well-formed.
        let escape_kind = self
            .closure_escape_facts
            .get(&checker_key)
            .map_or(ClosureEscapeKind::Escapes, |fact| fact.kind);

        (
            HirExprKind::Closure {
                params: hir_params,
                ret_ty,
                body: Box::new(lowered_body),
                captures,
                escape_kind,
            },
            closure_ty,
        )
    }

    fn materialize_closure_captures(
        &mut self,
        body: &HirExpr,
        outer_bindings: &HashMap<BindingId, OuterClosureBinding>,
        facts: Vec<ClosureCaptureFact>,
        span: std::ops::Range<usize>,
    ) -> Vec<HirClosureCapture> {
        let mut seen: HashSet<BindingId> = HashSet::new();
        let mut ordered: Vec<ClosureCaptureCandidate> = Vec::new();
        collect_general_closure_captures_walk(body, outer_bindings, &mut seen, &mut ordered);

        let mut remaining_facts = facts;
        let mut captures = Vec::with_capacity(ordered.len());
        for (binding, name, def_span) in ordered {
            let fact_idx = remaining_facts.iter().position(|fact| {
                fact.name == name
                    && fact
                        .def_span
                        .as_ref()
                        .is_some_and(|fact_def_span| *fact_def_span == def_span)
            });
            let fact_idx = fact_idx.or_else(|| {
                let mut matches = remaining_facts
                    .iter()
                    .enumerate()
                    .filter(|(_, fact)| fact.name == name);
                let first = matches.next()?;
                if matches.next().is_none() {
                    Some(first.0)
                } else {
                    None
                }
            });
            let Some(fact_idx) = fact_idx else {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: name.clone(),
                        reason:
                            "closure_capture_facts has no unambiguous entry for captured HIR binding"
                                .to_string(),
                    },
                    span.clone(),
                    "closure capture reached HIR without checker materialization metadata",
                ));
                continue;
            };
            let fact = remaining_facts.remove(fact_idx);
            let ty = match ResolvedTy::from_ty(&fact.ty) {
                Ok(ty) => ty,
                Err(err) => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: fact.name.clone(),
                            reason: err.to_string(),
                        },
                        span.clone(),
                        "closure capture type failed checker-boundary conversion",
                    ));
                    continue;
                }
            };
            captures.push(HirClosureCapture {
                binding,
                name,
                ty,
                mode: fact.mode,
                is_send: fact.is_send,
                is_sync: fact.is_sync,
            });
        }

        for fact in remaining_facts {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: fact.name,
                    reason:
                        "checker reported a capture that HIR name resolution did not materialize"
                            .to_string(),
                },
                span.clone(),
                "closure capture metadata and lowered HIR body disagree",
            ));
        }

        captures
    }

    fn lower_spawn(
        &mut self,
        target: &Spanned<Expr>,
        args: &[(String, Spanned<Expr>)],
        span: Span,
    ) -> (HirExprKind, ResolvedTy) {
        let actor_name = match &target.0 {
            Expr::Identifier(name) => Some(name.clone()),
            Expr::FieldAccess { object, field } => {
                if let Expr::Identifier(module) = &object.0 {
                    Some(format!("{module}.{field}"))
                } else {
                    None
                }
            }
            _ => None,
        };
        let Some(actor_name) = actor_name else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::NotYetImplemented {
                    construct: "spawn target expression".to_string(),
                    owning_pass: "actor-body-lowering".to_string(),
                },
                span,
                "`spawn` currently requires a named actor target",
            ));
            return (
                HirExprKind::Unsupported("unsupported spawn target".to_string()),
                ResolvedTy::Unit,
            );
        };

        let lowered_args = args
            .iter()
            .map(|(name, expr)| (name.clone(), self.lower_expr(expr, IntentKind::Read)))
            .collect::<Vec<_>>();
        let ty = if let Some(ty) = self.expr_types.get(&SpanKey::from(&span)).cloned() {
            match ResolvedTy::from_ty(&ty) {
                Ok(resolved) => resolved,
                Err(err) => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: format!("spawn {actor_name}"),
                            reason: err.to_string(),
                        },
                        span.clone(),
                        "checker-authoritative spawn result type failed boundary conversion",
                    ));
                    ResolvedTy::Unit
                }
            }
        } else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: format!("spawn {actor_name}"),
                    reason: "missing expr_types entry".to_string(),
                },
                span.clone(),
                "checker did not provide a result type for this actor spawn expression",
            ));
            ResolvedTy::Unit
        };
        (
            HirExprKind::Spawn {
                actor_name,
                args: lowered_args,
            },
            ty,
        )
    }

    /// Lower an `Expr::SpawnLambdaActor` to an
    /// `HirExprKind::SpawnLambdaActor` with a resolved capture set.
    ///
    /// The lambda body lowers inside a fresh scope so the parameter
    /// bindings shadow outer names; after the body is built the
    /// `current_actor_self` field tells us whether the body lives
    /// under a `let <name> = actor |..| { .. }` forward-bind. The
    /// capture walker then collects every `BindingRef { resolved:
    /// Binding(id) }` whose `id` refers to a binding from an outer
    /// scope (not a parameter introduced by this lambda) and
    /// classifies the strength: `id == current_actor_self.0` → Weak
    /// (recursive self-dispatch, §5.9 ratification 2), else → Strong.
    ///
    /// The HIR `expr.ty` is the Duplex<Msg, Reply> handle type. The
    /// MIR producer wires this directly into a
    /// `Place::LambdaActorHandle` whose drop selects
    /// `DropKind::LambdaActorRelease`.
    fn lower_spawn_lambda_actor(
        &mut self,
        params: &[LambdaParam],
        return_type: Option<&Spanned<TypeExpr>>,
        body: &Spanned<Expr>,
    ) -> (HirExprKind, ResolvedTy) {
        let actor_ty = self.actor_lambda_duplex_ty(params, return_type);
        let reply_ty = match &actor_ty {
            ResolvedTy::Named { args, .. } if args.len() == 2 => args[1].clone(),
            _ => ResolvedTy::Unit,
        };
        // Lower params + body inside a new scope. Track the parameter
        // BindingIds so the capture walker can exclude them (params
        // are intra-lambda bindings, not captures from the enclosing
        // scope).
        self.push_scope();
        let mut hir_params: Vec<HirBinding> = Vec::with_capacity(params.len());
        let mut param_ids: std::collections::HashSet<BindingId> =
            std::collections::HashSet::with_capacity(params.len());
        for param in params {
            let ty = param
                .ty
                .as_ref()
                .map_or(ResolvedTy::Unit, |ann| self.lower_type(ann));
            let binding = self.bind(param.name.clone(), ty, false, 0..0);
            param_ids.insert(binding.id);
            hir_params.push(binding);
        }
        // Lexically scope `current_actor_self` to THIS lambda body. If the
        // caller (`lower_stmt`'s let-pre-bind path) set it before invoking
        // `lower_expr`, that value is this lambda's self-id; otherwise this
        // lambda is in expression position (anonymous) and has no self-id.
        // Take the value out for the duration of the body walk so any
        // nested actor-lambda lowered from within `body` does not inherit
        // it — nested anonymous lambdas would otherwise misclassify
        // captures of THIS lambda's enclosing-scope bindings as Weak.
        // Restored before `collect_lambda_captures` so the capture-strength
        // classifier sees the correct self-id, and restored to the caller's
        // prior value on exit.
        let my_self_id = self.current_actor_self.take();
        let lowered_body = self.with_current_return_type(reply_ty.clone(), |ctx| {
            ctx.lower_expr(body, IntentKind::Read)
        });
        self.current_actor_self = my_self_id;
        self.pop_scope();
        let captures = self.collect_lambda_captures(&lowered_body, &param_ids);
        (
            HirExprKind::SpawnLambdaActor {
                params: hir_params,
                reply_ty,
                body: Box::new(lowered_body),
                captures,
            },
            actor_ty,
        )
    }

    /// Walk a lowered lambda body collecting `BindingRef`s that resolve
    /// to bindings from the enclosing scope. A reference is a capture
    /// when its resolved binding id is not in `param_ids` (the lambda's
    /// own parameters). Each unique binding is classified Weak when
    /// its id matches `current_actor_self.0` (the let-name pre-bound
    /// before body lowering) and Strong otherwise.
    ///
    /// Duplicate references to the same binding produce a single
    /// capture entry — codegen needs the runtime to register the
    /// captured handle once per binding, not once per use site.
    fn collect_lambda_captures(
        &self,
        body: &HirExpr,
        param_ids: &std::collections::HashSet<BindingId>,
    ) -> Vec<HirLambdaCapture> {
        let mut seen: std::collections::HashSet<BindingId> = std::collections::HashSet::new();
        let mut captures: Vec<HirLambdaCapture> = Vec::new();
        let self_id = self.current_actor_self.as_ref().map(|(id, _)| *id);
        collect_captures_walk(body, param_ids, &mut seen, &mut captures, self_id);
        captures
    }

    /// Recognise the sealed-form discriminator for a `select` arm
    /// source expression. Emits a `SelectArmNotSealedForm` /
    /// `SelectStreamNextSurface` / `SelectStreamNextArity` diagnostic
    /// on miss and returns a placeholder `AfterTimer` arm kind (the
    /// callers tolerate the placeholder because the diagnostic has
    /// already been emitted; MIR lowering treats any select with HIR
    /// diagnostics as fail-closed downstream).
    fn recognize_sealed_arm_source(&mut self, source: &Spanned<Expr>) -> HirSelectArmKind {
        let span = source.1.clone();
        match &source.0 {
            // Form 1: `next(<stream-expr>)` — a call where the callee
            // is the bare identifier `next`. `next` is not a lexer
            // keyword; the sealed-form discriminator is the callee
            // name.
            Expr::Call { function, args, .. } => {
                if let Expr::Identifier(name) = &function.0 {
                    if name == "next" {
                        if args.len() != 1 {
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::SelectStreamNextArity {
                                    arg_count: args.len(),
                                },
                                span.clone(),
                                "next(<stream>) takes exactly one argument",
                            ));
                            return HirSelectArmKind::StreamNext {
                                stream: Box::new(
                                    self.unsupported_expr(span, "stream-next arity mismatch"),
                                ),
                            };
                        }
                        let stream = self.lower_expr(args[0].expr(), IntentKind::Read);
                        return HirSelectArmKind::StreamNext {
                            stream: Box::new(stream),
                        };
                    }
                }
                // Some other function call — not a sealed form.
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::SelectArmNotSealedForm {
                        source_shape: "function call".into(),
                    },
                    span.clone(),
                    "select arm source must be next(...), an actor method call, or `await <task>`",
                ));
                HirSelectArmKind::StreamNext {
                    stream: Box::new(self.unsupported_expr(span, "non-sealed arm source")),
                }
            }
            // Form 2: `<actor>.<method>(<args>)` — method call on an
            // actor expression. Per HEW-SPEC-2026 §4.11.1 this is the
            // actor-ask arm. `ask` is reserved as a future syntactic
            // marker (see HEW-FUTURE) but is not lexer-recognised in
            // edition 2026; the sealed-form discriminator is the
            // method-call surface.
            Expr::MethodCall {
                receiver,
                method,
                args,
            } => {
                // NEW-4: `pat from rx.recv()` — a std/channel receive arm. The
                // checker recorded the runtime rewrite (hew_channel_recv*) on
                // this method-call span; recognise it as a ChannelRecv arm
                // before the generic actor-ask interpretation.
                if method == "recv" {
                    if let Some(elem_is_int) = self.channel_recv_elem_is_int(&SpanKey::from(&span))
                    {
                        let recv = self.lower_expr(receiver, IntentKind::Read);
                        return HirSelectArmKind::ChannelRecv {
                            receiver: Box::new(recv),
                            elem_is_int,
                        };
                    }
                }
                let actor = self.lower_expr(receiver, IntentKind::Read);
                let lowered_args: Vec<HirExpr> = args
                    .iter()
                    .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                    .collect();
                HirSelectArmKind::ActorAsk {
                    actor: Box::new(actor),
                    method: method.clone(),
                    args: lowered_args,
                }
            }
            // Form 3: `await <task-expr>` — explicit await keyword.
            Expr::Await(task_expr) => {
                let task = self.lower_expr(task_expr, IntentKind::Read);
                HirSelectArmKind::TaskAwait {
                    task: Box::new(task),
                }
            }
            // Form 4 (arm-position): `after <duration>` written as an
            // arm source rather than the dedicated `timeout` field.
            // Recognised here so the `lower_select` multiple-after check
            // can fire; the duplicate check in `lower_select` emits the
            // diagnostic when this arm coexists with another after arm.
            Expr::Timeout { duration, .. } => {
                let dur = self.lower_expr(duration, IntentKind::Read);
                HirSelectArmKind::AfterTimer {
                    duration: Box::new(dur),
                }
            }
            // Method-call dressed up as `stream.next()` — sealed
            // surface is `next(stream)`. Diagnose specifically so the
            // user can fix the form.
            // (Already handled by the MethodCall arm above as a
            // generic actor-ask. The dedicated diagnostic for the
            // `.next()` shape would shadow the actor-ask recognition;
            // we keep the more general actor-ask interpretation and
            // rely on the SelectStreamNextSurface diagnostic only if
            // we later choose to special-case it. For now, `s.next()`
            // is recognised as an actor-ask of the `next` method on
            // `s`, which is the lower-noise default.)
            other => {
                let shape = describe_select_source_shape(other);
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::SelectArmNotSealedForm {
                        source_shape: shape,
                    },
                    span.clone(),
                    "select arm source must be next(...), an actor method call, or `await <task>`",
                ));
                HirSelectArmKind::StreamNext {
                    stream: Box::new(self.unsupported_expr(span, "non-sealed arm source")),
                }
            }
        }
    }

    fn lower_literal(lit: &Literal) -> (HirExprKind, ResolvedTy) {
        match lit {
            Literal::Integer { value, .. } => (
                HirExprKind::Literal(HirLiteral::Integer(*value)),
                ResolvedTy::I64,
            ),
            Literal::Float(value) => (
                HirExprKind::Literal(HirLiteral::Float(*value)),
                ResolvedTy::F64,
            ),
            Literal::String(value) => (
                HirExprKind::Literal(HirLiteral::String(value.clone())),
                ResolvedTy::String,
            ),
            Literal::Bool(value) => (
                HirExprKind::Literal(HirLiteral::Bool(*value)),
                ResolvedTy::Bool,
            ),
            Literal::Char(value) => (
                HirExprKind::Literal(HirLiteral::Char(*value)),
                ResolvedTy::Char,
            ),
            Literal::Duration(value) => (
                HirExprKind::Literal(HirLiteral::Duration(*value)),
                ResolvedTy::Duration,
            ),
        }
    }

    fn lower_unary_expr(
        &mut self,
        op: UnaryOp,
        operand: &Spanned<Expr>,
        span: &Span,
    ) -> (HirExprKind, ResolvedTy) {
        let operand_expr = self.lower_expr(operand, IntentKind::Read);

        if op == UnaryOp::RawDeref {
            self.unsupported(
                span.clone(),
                "raw pointer unary dereference",
                "m5-raw-pointers",
            );
            return (
                HirExprKind::Unsupported("unsupported raw pointer unary dereference".into()),
                ResolvedTy::Unit,
            );
        }

        let Some(result_ty) = self.checker_expr_ty(span, "unary expression") else {
            return (
                HirExprKind::Unsupported("unary expression missing checker result type".into()),
                ResolvedTy::Unit,
            );
        };
        let Some(operand_ty) = self.checker_unary_operand_ty(op, operand, &result_ty) else {
            return (
                HirExprKind::Unsupported("unary expression missing checker operand type".into()),
                ResolvedTy::Unit,
            );
        };

        if !Self::unary_shape_supported(op, &operand_ty, &result_ty) {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::UnaryOperatorUnsupportedInMir {
                    op: Self::unary_op_label(op).to_string(),
                    operand_ty: operand_ty.to_string(),
                    result_ty: result_ty.to_string(),
                },
                span.clone(),
                "checker-approved unary expression has no MIR/codegen lowering for this typed shape",
            ));
            return (
                HirExprKind::Unsupported(format!(
                    "unsupported unary `{}` for operand `{operand_ty}` -> `{result_ty}`",
                    Self::unary_op_label(op)
                )),
                result_ty,
            );
        }

        (
            HirExprKind::Unary {
                op,
                operand: Box::new(operand_expr),
                operand_ty,
            },
            result_ty,
        )
    }

    fn checker_expr_ty(&mut self, span: &Span, label: &str) -> Option<ResolvedTy> {
        let key = SpanKey::from(span);
        let Some(ty) = self.expr_types.get(&key).cloned() else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: label.to_string(),
                    reason: "missing expr_types entry".to_string(),
                },
                span.clone(),
                "checker-authoritative expression type is required for unary lowering",
            ));
            return None;
        };
        match ResolvedTy::from_ty(&ty) {
            Ok(resolved) => Some(resolved),
            Err(err) => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: label.to_string(),
                        reason: err.to_string(),
                    },
                    span.clone(),
                    "checker-authoritative unary type failed boundary conversion",
                ));
                None
            }
        }
    }

    fn checker_unary_operand_ty(
        &mut self,
        op: UnaryOp,
        operand: &Spanned<Expr>,
        result_ty: &ResolvedTy,
    ) -> Option<ResolvedTy> {
        let key = SpanKey::from(&operand.1);
        match self.expr_types.get(&key).cloned() {
            Some(ty) => match ResolvedTy::from_ty(&ty) {
                Ok(resolved) => {
                    // The operand span may have been recorded as `IntLiteral`
                    // during synthesis and then materialized to `I64` by
                    // `materialize_literal_defaults` at the checker boundary.
                    // If the outer result was narrowed to a different concrete
                    // integer (e.g. `I32`) by deferred range-bound resolution,
                    // the `I64` is a stale materialization artifact.  Use
                    // `result_ty` for the operand so `negate(5_literal) →
                    // i32` does not trip the `operand_ty == result_ty` shape
                    // guard in `unary_shape_supported`.
                    if Self::unary_literal_operand_uses_result_ty(op, &operand.0)
                        && Self::resolved_is_integer(&resolved)
                        && Self::resolved_is_integer(result_ty)
                        && resolved != *result_ty
                    {
                        Some(result_ty.clone())
                    } else {
                        Some(resolved)
                    }
                }
                Err(_) if Self::unary_literal_operand_uses_result_ty(op, &operand.0) => {
                    Some(result_ty.clone())
                }
                Err(err) => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: "unary operand".to_string(),
                            reason: err.to_string(),
                        },
                        operand.1.clone(),
                        "checker-authoritative unary operand type failed boundary conversion",
                    ));
                    None
                }
            },
            None if Self::unary_literal_operand_uses_result_ty(op, &operand.0) => {
                Some(result_ty.clone())
            }
            None => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: "unary operand".to_string(),
                        reason: "missing expr_types entry".to_string(),
                    },
                    operand.1.clone(),
                    "checker-authoritative expression type is required for unary lowering",
                ));
                None
            }
        }
    }

    fn unary_literal_operand_uses_result_ty(op: UnaryOp, operand: &Expr) -> bool {
        matches!(operand, Expr::Literal(_))
            && matches!(op, UnaryOp::Not | UnaryOp::Negate | UnaryOp::BitNot)
    }

    fn unary_shape_supported(op: UnaryOp, operand_ty: &ResolvedTy, result_ty: &ResolvedTy) -> bool {
        match op {
            UnaryOp::Not => operand_ty == &ResolvedTy::Bool && result_ty == &ResolvedTy::Bool,
            UnaryOp::Negate => {
                operand_ty == result_ty
                    && (Self::resolved_is_integer(operand_ty)
                        || Self::resolved_is_float(operand_ty))
            }
            UnaryOp::BitNot => operand_ty == result_ty && Self::resolved_is_integer(operand_ty),
            UnaryOp::RawDeref => false,
        }
    }

    fn resolved_is_integer(ty: &ResolvedTy) -> bool {
        matches!(
            ty,
            ResolvedTy::I8
                | ResolvedTy::I16
                | ResolvedTy::I32
                | ResolvedTy::I64
                | ResolvedTy::U8
                | ResolvedTy::U16
                | ResolvedTy::U32
                | ResolvedTy::U64
                | ResolvedTy::Isize
                | ResolvedTy::Usize
        )
    }

    fn resolved_is_float(ty: &ResolvedTy) -> bool {
        matches!(ty, ResolvedTy::F32 | ResolvedTy::F64)
    }

    fn lower_tuple_literal(
        &mut self,
        elems: &[Spanned<Expr>],
        span: &Span,
    ) -> (HirExprKind, ResolvedTy) {
        // Checker-authoritative: the type checker has already validated the
        // tuple arity and element types and stored the result type in
        // `expr_types`. HIR does not re-derive the tuple type from the
        // element list.
        let Some(result_ty) = self.checker_expr_ty(span, "tuple literal") else {
            return (
                HirExprKind::Unsupported("tuple literal missing checker result type".into()),
                ResolvedTy::Unit,
            );
        };

        // Lower each element expression. The checker has already validated
        // each element type matches the corresponding tuple slot.
        let hir_elements: Vec<HirExpr> = elems
            .iter()
            .map(|elem| self.lower_expr(elem, IntentKind::Read))
            .collect();

        (
            HirExprKind::TupleLiteral {
                elements: hir_elements,
            },
            result_ty,
        )
    }

    fn array_literal_vec_ty(&mut self, span: &Span) -> Option<(ResolvedTy, ResolvedTy)> {
        let key = SpanKey::from(span);
        let Some(ty) = self.expr_types.get(&key).cloned() else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: "array literal".to_string(),
                    reason: "missing expr_types entry".to_string(),
                },
                span.clone(),
                "array literal lowering requires the checker element type; HIR desugars to Vec<T>, never to a fixed-size Array<T, N>",
            ));
            return None;
        };
        let result_ty = match ResolvedTy::from_ty(&ty) {
            Ok(resolved) => resolved,
            Err(err) => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: "array literal".to_string(),
                        reason: err.to_string(),
                    },
                    span.clone(),
                    "checker-authoritative array literal type failed boundary conversion",
                ));
                return None;
            }
        };
        match result_ty {
            ResolvedTy::Named {
                name,
                args,
                builtin,
                ..
            } if name == "Vec" && builtin == Some(BuiltinType::Vec) && args.len() == 1 => {
                Some((Self::resolved_vec_ty(args[0].clone()), args[0].clone()))
            }
            ResolvedTy::Array(elem_ty, _) => {
                let elem_ty = *elem_ty;
                Some((Self::resolved_vec_ty(elem_ty.clone()), elem_ty))
            }
            other => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: "array literal".to_string(),
                        reason: format!("checker produced non-array type `{other}`"),
                    },
                    span.clone(),
                    "array literal lowering requires the checker element type; HIR desugars to Vec<T>, never to a fixed-size Array<T, N>",
                ));
                None
            }
        }
    }

    fn vec_push_symbol_for_elem(&self, elem_ty: &ResolvedTy) -> Option<&'static str> {
        match elem_ty {
            ResolvedTy::Bool => Some("hew_vec_push_bool"),
            ResolvedTy::Char | ResolvedTy::I32 | ResolvedTy::U32 => Some("hew_vec_push_i32"),
            ResolvedTy::I64 | ResolvedTy::U64 => Some("hew_vec_push_i64"),
            ResolvedTy::F64 => Some("hew_vec_push_f64"),
            ResolvedTy::String => Some("hew_vec_push_str"),
            ResolvedTy::Tuple(_) => Some("hew_vec_push_layout"),
            ResolvedTy::Named {
                builtin: Some(BuiltinType::Vec | BuiltinType::HashMap | BuiltinType::HashSet),
                ..
            } => Some("hew_vec_push_ptr"),
            ResolvedTy::Named { .. } => match ValueClass::of_ty(elem_ty, &self.type_classes) {
                ValueClass::CowValue
                | ValueClass::PersistentShare
                | ValueClass::AffineResource
                | ValueClass::Linear => Some("hew_vec_push_ptr"),
                ValueClass::BitCopy | ValueClass::Unknown => Some("hew_vec_push_layout"),
                ValueClass::View => None,
            },
            _ => None,
        }
    }

    fn make_vec_new_expr(&mut self, vec_ty: ResolvedTy, span: Span) -> HirExpr {
        let callee_ty = ResolvedTy::Function {
            params: Vec::new(),
            ret: Box::new(vec_ty.clone()),
        };
        let resolved_ref = self
            .fn_registry
            .get("Vec::new")
            .map_or(ResolvedRef::Unresolved, |entry| ResolvedRef::Item(entry.id));
        let callee = self.make_expr(
            HirExprKind::BindingRef {
                name: "Vec::new".to_string(),
                resolved: resolved_ref,
            },
            callee_ty,
            IntentKind::Read,
            span.clone(),
        );
        self.make_expr(
            HirExprKind::Call {
                callee: Box::new(callee),
                args: Vec::new(),
            },
            vec_ty,
            IntentKind::Read,
            span,
        )
    }

    fn make_vec_push_expr(
        &mut self,
        vec_ref: HirExpr,
        elem: HirExpr,
        elem_ty: &ResolvedTy,
        span: Span,
    ) -> Option<HirExpr> {
        let Some(target_symbol) = self.vec_push_symbol_for_elem(elem_ty) else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: "array literal".to_string(),
                    reason: format!("no Vec push runtime symbol for element type `{elem_ty}`"),
                },
                span,
                "array literal desugar reuses Vec::push infrastructure and cannot fabricate an element ABI",
            ));
            return None;
        };
        Some(self.make_expr(
            HirExprKind::ResolvedImplCall {
                receiver: Box::new(vec_ref),
                impl_id: ImplId(u32::MAX),
                method_name: "push".to_string(),
                target_symbol: target_symbol.to_string(),
                type_args: vec![Self::resolved_ty_pattern(elem_ty)],
                args: vec![elem],
                ret_ty: ResolvedTy::Unit,
            },
            ResolvedTy::Unit,
            IntentKind::Read,
            span,
        ))
    }

    fn lower_array_literal(
        &mut self,
        elems: &[Spanned<Expr>],
        span: &Span,
    ) -> (HirExprKind, ResolvedTy) {
        let Some((vec_ty, elem_ty)) = self.array_literal_vec_ty(span) else {
            return (
                HirExprKind::Unsupported("array literal missing checker element type".into()),
                ResolvedTy::Unit,
            );
        };

        let lowered_elems: Vec<HirExpr> = elems
            .iter()
            .map(|elem| self.lower_expr(elem, IntentKind::Read))
            .collect();
        let block_scope = self.ids.scope();
        self.push_scope();
        let temp_name = format!("__hew_array_{}", self.ids.binding().0);
        let temp_binding = self.bind(temp_name.clone(), vec_ty.clone(), false, span.clone());
        let temp_binding_id = temp_binding.id;
        let init_stmt = HirStmt {
            node: self.ids.node(),
            kind: HirStmtKind::Let(
                temp_binding,
                Some(self.make_vec_new_expr(vec_ty.clone(), span.clone())),
            ),
            span: span.clone(),
        };
        let mut statements = Vec::with_capacity(lowered_elems.len() + 1);
        statements.push(init_stmt);
        let mut push_failed = false;
        for elem in lowered_elems {
            let vec_ref = self.make_binding_ref(
                temp_name.clone(),
                temp_binding_id,
                vec_ty.clone(),
                IntentKind::Read,
                elem.span.clone(),
            );
            if let Some(push_expr) = self.make_vec_push_expr(vec_ref, elem, &elem_ty, span.clone())
            {
                statements.push(HirStmt {
                    node: self.ids.node(),
                    kind: HirStmtKind::Expr(push_expr),
                    span: span.clone(),
                });
            } else {
                push_failed = true;
            }
        }
        let tail = self.make_binding_ref(
            temp_name,
            temp_binding_id,
            vec_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );
        self.pop_scope();

        if push_failed {
            return (
                HirExprKind::Unsupported("array literal element type has no Vec push ABI".into()),
                ResolvedTy::Unit,
            );
        }

        (
            HirExprKind::Block(HirBlock {
                node: self.ids.node(),
                scope: block_scope,
                statements,
                tail: Some(Box::new(tail)),
                ty: vec_ty.clone(),
                span: span.clone(),
            }),
            vec_ty,
        )
    }

    fn unary_op_label(op: UnaryOp) -> &'static str {
        match op {
            UnaryOp::Not => "!",
            UnaryOp::Negate => "-",
            UnaryOp::BitNot => "~",
            UnaryOp::RawDeref => "*",
        }
    }

    #[allow(
        clippy::too_many_lines,
        reason = "multi-branch identifier resolution: context readers, bindings, fn_sigs, \
                  unit-variant ctors with generic-arg preservation, and fn-item references \
                  are each a short arm; extracting a helper gains nothing without a richer \
                  identifier-resolution abstraction"
    )]
    fn lower_identifier(
        &mut self,
        name: &str,
        span: std::ops::Range<usize>,
    ) -> (HirExprKind, ResolvedTy) {
        if let Some(reader) = ExecutionContextReader::from_surface_name(name) {
            let key = SpanKey::from(&span);
            if self
                .expr_types
                .get(&key)
                .is_some_and(|ty| *ty == reader.ty())
            {
                let ty = ResolvedTy::from_ty(&reader.ty()).expect("reader type resolves");
                return (HirExprKind::ContextReader { reader }, ty);
            }
        }
        if let Some((id, ty)) = self.lookup(name) {
            return (
                HirExprKind::BindingRef {
                    name: name.to_string(),
                    resolved: ResolvedRef::Binding(id),
                },
                ty,
            );
        }
        // Module-scope tagged-union unit constructor: machine states
        // (`TrafficLight::Red`, bare `Red`), machine events
        // (`TrafficLightEvent::Tick`, bare `Tick`), and user-defined enum
        // unit variants (`Colour::Red`, bare `Red`). The pre-pass over
        // `program.items` populated `machine_ctor_registry` with both
        // qualified and unambiguous-bare entries (see registry doc).
        // Consulted after lexical lookup so a user binding shadows a
        // same-named ctor (preserves the usual lexical-scope rule).
        //
        // Checker-authority cross-check: when the type checker has recorded
        // an `expr_types` entry for this span (which it does for any
        // accepted unit-ctor reference via `resolve_identifier_variant`),
        // the registered tagged-union name must match the type the checker
        // selected. This guarantees HIR follows checker authority across
        // bare-name collisions (e.g. an `enum Colour { Red }` plus a
        // `machine M { state Red }` where the checker's `type_defs` map
        // iteration order picked one of them). When the checker has no
        // entry — pure HIR-side resolution at a span the checker did not
        // type (rare; mostly synthesised code) — we accept the registry
        // hit unconditionally.
        // Checker-authoritative qualified-name fallback: when the bare-name
        // registry entry disagrees with the checker (e.g. a user `state Closed`
        // in scope alongside the synthetic `SendError::Closed` makes the bare
        // name ambiguous-or-missing, while the checker has already chosen
        // `TcpHandshake` for this identifier span), promote the checker's
        // chosen type into a qualified lookup. This keeps bare references to
        // unit ctors resolving correctly across builtin/user name collisions
        // without depending on registration-order races in the pre-pass.
        let key = SpanKey::from(&span);
        let checker_qualified = match self.expr_types.get(&key) {
            Some(Ty::Named { name: n, .. }) => Some(format!("{n}::{name}")),
            _ => None,
        };
        let registry_hit = self.machine_ctor_registry.get(name).cloned().or_else(|| {
            checker_qualified
                .as_deref()
                .and_then(|q| self.machine_ctor_registry.get(q).cloned())
        });
        if let Some((tagged_union_name, variant_idx)) = registry_hit {
            let checker_agrees = match self.expr_types.get(&key) {
                None => true,
                Some(Ty::Named { name: n, .. }) => Ty::names_match_qualified(n, &tagged_union_name),
                Some(_) => false,
            };
            if checker_agrees {
                // Register the generic-enum instantiation before building
                // result_ty so codegen's mangled-key lookup finds the entry.
                self.try_register_enum_instantiation(&span);
                // Checker-authoritative result type: the checker records the
                // full `Named { name: "Option", args: [I64] }` at this
                // identifier span. Using it preserves type args so codegen
                // can compute the mangled registry key (e.g. `"Option$$i64"`).
                // Fall back to bare-name with a diagnostic if expr_types has
                // no entry — absence is a real signal; the checker should
                // always populate accepted unit-ctor reference sites.
                let result_ty = if let Some(ty) = self.expr_types.get(&key).cloned() {
                    match ResolvedTy::from_ty(&ty) {
                        Ok(resolved) => resolved,
                        Err(err) => {
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::CheckerBoundaryViolation {
                                    name: tagged_union_name.clone(),
                                    reason: err.to_string(),
                                },
                                span.clone(),
                                "checker-authoritative unit-variant result type failed boundary conversion",
                            ));
                            ResolvedTy::Named {
                                name: tagged_union_name.clone(),
                                args: Vec::new(),
                                builtin: None,
                                is_opaque: false,
                            }
                        }
                    }
                } else {
                    // None means the checker had no entry at this span.
                    // Treat as bare-name rather than a hard diagnostic so
                    // synthesised/non-typed paths don't regress.
                    ResolvedTy::Named {
                        name: tagged_union_name.clone(),
                        args: Vec::new(),
                        builtin: None,
                        is_opaque: false,
                    }
                };
                // W4.047 P1.2: prove the typed handoff agrees at this fail-open
                // bare-name unit-ctor site (the B1 archetype; no behaviour
                // change). When the checker stamped the span (W4.042), the
                // typed map carries the concrete `Named` type and this assert
                // confirms it; when the span is genuinely absent, both miss.
                self.assert_resolved_ty_totality(&span);
                return (
                    HirExprKind::MachineVariantCtor {
                        machine_name: tagged_union_name,
                        state_idx: variant_idx,
                        payload: None,
                    },
                    result_ty,
                );
            }
        }
        if let Some(symbol) = self.imported_rewrite_symbol(name).map(str::to_string) {
            if let Some(entry) = self.fn_registry.get(&symbol) {
                let fn_ty = ResolvedTy::Function {
                    params: entry.param_tys.clone(),
                    ret: Box::new(entry.return_ty.clone()),
                };
                let id = entry.id;
                return (
                    HirExprKind::BindingRef {
                        name: symbol,
                        resolved: ResolvedRef::Item(id),
                    },
                    fn_ty,
                );
            }
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: name.to_string(),
                    reason: format!(
                        "imported same-module callee `{symbol}` missing from HIR fn registry"
                    ),
                },
                span.clone(),
                "imported free-function body rewrite target was not registered",
            ));
        }
        // Bare-name same-module const reference inside an imported module's
        // function body (e.g. `STATUS_OK` inside `tls.hew`).  The global
        // `const_registry` only carries the qualified key
        // `"tls.STATUS_OK"`; `imported_module_consts` holds the bare-name
        // entries that are in scope while this module's bodies are lowered.
        // Checked before `const_registry` so same-module bare names take
        // precedence over any qualified alias that happens to collide.
        if let Some(entry) = self
            .imported_module_consts
            .as_ref()
            .and_then(|m| m.get(name))
            .cloned()
        {
            let ty = entry.ty.clone();
            let id = entry.id;
            return (
                HirExprKind::BindingRef {
                    name: name.to_string(),
                    resolved: ResolvedRef::Const(id),
                },
                ty,
            );
        }
        if let Some(entry) = self.const_registry.get(name) {
            // Module-level `const` reference. Resolves to a `Const` ref carrying
            // the declaration's stable ItemId; MIR/codegen map it back to the
            // folded descriptor. Consulted after lexical lookup (a local binding
            // shadows a const) and after tagged-union ctor resolution, mirroring
            // the usual scope precedence.
            let ty = entry.ty.clone();
            let id = entry.id;
            return (
                HirExprKind::BindingRef {
                    name: name.to_string(),
                    resolved: ResolvedRef::Const(id),
                },
                ty,
            );
        }
        if let Some(entry) = self.fn_registry.get(name) {
            // Known function item — expose as a function-typed reference so
            // callers can extract the return type from the call expression.
            let fn_ty = ResolvedTy::Function {
                params: entry.param_tys.clone(),
                ret: Box::new(entry.return_ty.clone()),
            };
            let id = entry.id;
            (
                HirExprKind::BindingRef {
                    name: name.to_string(),
                    resolved: ResolvedRef::Item(id),
                },
                fn_ty,
            )
        } else {
            if let Some(module) = self.missing_stdlib_module_import(name) {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::ImportMissing {
                        module: module.to_string(),
                        name: name.to_string(),
                    },
                    span,
                    stdlib_catalog::missing_import_hint(module),
                ));
            } else {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::UnresolvedSymbol {
                        name: name.to_string(),
                    },
                    span,
                    "identifier has no binding in resolved HIR",
                ));
            }
            (
                HirExprKind::BindingRef {
                    name: name.to_string(),
                    resolved: ResolvedRef::Unresolved,
                },
                ResolvedTy::Unit,
            )
        }
    }

    fn lower_numeric_cast_expr(
        &mut self,
        value: &Spanned<Expr>,
        ty: &Spanned<TypeExpr>,
        span: &Span,
    ) -> (HirExprKind, ResolvedTy) {
        let value = self.lower_expr(value, IntentKind::Read);
        let from_ty = value.ty.clone();
        let to_ty = self.lower_type(ty);
        if !from_ty.can_explicitly_numeric_cast_to(&to_ty) {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: "numeric cast".to_string(),
                    reason: format!(
                        "cast from {} to {} is outside the checker-admitted numeric matrix",
                        from_ty.user_facing(),
                        to_ty.user_facing()
                    ),
                },
                span.clone(),
                "only numeric<->numeric, bool->integer, and integer->bool `as` casts lower to HIR",
            ));
            return (
                HirExprKind::Unsupported(format!(
                    "unsupported cast from {} to {}",
                    from_ty.user_facing(),
                    to_ty.user_facing()
                )),
                ResolvedTy::Unit,
            );
        }
        (
            HirExprKind::NumericCast {
                value: Box::new(value),
                from_ty: from_ty.clone(),
                to_ty: to_ty.clone(),
            },
            to_ty,
        )
    }

    #[allow(
        clippy::too_many_lines,
        reason = "single match over every TypeExpr variant; splitting would scatter the type-lowering authority"
    )]
    /// Resolve a non-keyword `TypeExpr::Named` reference to a `ResolvedTy`,
    /// classifying it as builtin / opaque-handle / user type. `name` is the
    /// annotation as written (possibly module-qualified); `args` are the
    /// already-lowered generic arguments. Split out of `lower_type` to keep
    /// that dispatcher under the line budget.
    fn resolve_named_type_ref(&self, name: &str, args: Vec<ResolvedTy>) -> ResolvedTy {
        let type_name = name
            .rsplit_once('.')
            .map_or(name, |(_, unqualified)| unqualified);
        if let Some(registration) = crate::builtin_type_classes::builtin_type_registration(name)
            .or_else(|| crate::builtin_type_classes::builtin_type_registration(type_name))
        {
            ResolvedTy::named_builtin(registration.name(), registration.builtin, args)
        } else if let Some(builtin) = hew_types::lookup_builtin_type(name) {
            ResolvedTy::named_builtin(name.to_string(), builtin, args)
        } else if let Some(builtin) = hew_types::lookup_builtin_type(type_name) {
            ResolvedTy::named_builtin(type_name.to_string(), builtin, args)
        } else if self.resolves_to_opaque_handle(name, type_name) {
            // `#[opaque]` runtime handle (e.g. `json.Value`). Stamp the
            // type-identity discriminator so the actor-state clone/drop
            // classifier fails closed on the handle even when its short name
            // collides with a user record/enum of the same name. See
            // `LowerCtx::resolves_to_opaque_handle`.
            ResolvedTy::named_opaque(type_name.to_string(), args)
        } else {
            ResolvedTy::named_user(type_name.to_string(), args)
        }
    }

    /// Decide whether a `Named` type reference resolves to a `#[opaque]`
    /// runtime handle, used to stamp `ResolvedTy::Named.is_opaque`.
    ///
    /// `full_name` is the annotation as written (qualified `json.Value` /
    /// `m.Value`, or bare `Value`); `short_name` is its module-prefix-stripped
    /// form. The decision is made from declared identity (the opaque sets
    /// harvested by `collect_opaque_type_short_names`), never from a
    /// name-collision heuristic:
    ///
    /// * A qualified reference (`json.Value`, `m.Value`) is opaque IFF its
    ///   EXACT qualified name is a registered opaque key. `json.Value` is
    ///   (it names the opaque handle); `m.Value` is NOT (it names a user
    ///   record in module `m` that merely shares the short name). A user type
    ///   cannot be declared `#[opaque]`, so the qualified key is unambiguous.
    /// * A bare reference (`Value`) is opaque ONLY when its short name is
    ///   opaque AND no non-opaque user type shares that short name. When both
    ///   exist, the local user declaration shadows the imported opaque handle
    ///   for an unqualified reference (matching name resolution), so the bare
    ///   reference resolves to the user type (`is_opaque: false`).
    fn resolves_to_opaque_handle(&self, full_name: &str, short_name: &str) -> bool {
        let is_qualified = full_name.contains('.');
        if is_qualified {
            // Exact qualified-key match only: distinguishes `json.Value`
            // (opaque) from `m.Value` (user record sharing the short name).
            return self.opaque_type_short_names.contains(full_name);
        }
        // Bare reference: opaque only if the short name is opaque and no user
        // type shadows it.
        self.opaque_type_short_names.contains(short_name)
            && !self.non_opaque_type_short_names.contains(short_name)
    }

    fn lower_type(&mut self, ty: &Spanned<TypeExpr>) -> ResolvedTy {
        match &ty.0 {
            TypeExpr::Named { name, type_args } => {
                let args: Vec<ResolvedTy> = type_args
                    .as_ref()
                    .map(|args| args.iter().map(|arg| self.lower_type(arg)).collect())
                    .unwrap_or_default();
                // W3.042 S2-S1: `Self` in an impl-method body annotation
                // resolves to the concrete impl-target type. Without this
                // interception, `self`'s parser-assigned `TypeExpr::Named
                // { name: "Self" }` leaks into MIR as `ResolvedTy::named_user
                // ("Self", _)` and field access fails with "unregistered
                // record type `Self`". When called outside an impl-method
                // context, `current_impl_self_ty` is `None` and Self falls
                // through to the generic unknown-type path below (preserving
                // the existing behaviour for trait declarations and any
                // not-yet-covered Self surface).
                if name == "Self" && args.is_empty() {
                    if let Some(self_ty) = self.current_impl_self_ty.clone() {
                        return self_ty;
                    }
                }
                match name.as_str() {
                    "i8" => ResolvedTy::I8,
                    "i16" => ResolvedTy::I16,
                    "i32" => ResolvedTy::I32,
                    "i64" => ResolvedTy::I64,
                    "u8" => ResolvedTy::U8,
                    "u16" => ResolvedTy::U16,
                    "u32" => ResolvedTy::U32,
                    "u64" => ResolvedTy::U64,
                    // Platform-sized integers: distinct from fixed-width
                    // i64/u64. Codegen branches on target: 32-bit for
                    // wasm32, 64-bit for native (B-D1 / Q42 ratification).
                    "isize" => ResolvedTy::Isize,
                    "usize" => ResolvedTy::Usize,
                    "f32" => ResolvedTy::F32,
                    "f64" => ResolvedTy::F64,
                    "bool" => ResolvedTy::Bool,
                    "char" => ResolvedTy::Char,
                    "string" => ResolvedTy::String,
                    "duration" => ResolvedTy::Duration,
                    "bytes" => ResolvedTy::Bytes,
                    "CancellationToken" if args.is_empty() => ResolvedTy::CancellationToken,
                    "Unit" | "()" => ResolvedTy::Unit,
                    // `Task` is a compiler-internal value class with no user-source
                    // syntax. Writing `Task<T>` in any annotation position is a
                    // compile error. Use `fork name = call(...)` to obtain a task
                    // handle. (TI-5 structural enforcement.)
                    "Task" => {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::TaskNotNameable,
                            ty.1.clone(),
                            "`Task<T>` is a compiler-internal type and cannot be written \
                             in source. Use `fork name = call(...)` to create a task handle.",
                        ));
                        ResolvedTy::Unit
                    }
                    _ => self.resolve_named_type_ref(name, args),
                }
            }
            TypeExpr::Infer => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::UnresolvedInferenceVar,
                    ty.1.clone(),
                    "inferred type reached resolved HIR boundary",
                ));
                ResolvedTy::Unit
            }
            TypeExpr::Tuple(elems) if elems.is_empty() => ResolvedTy::Unit,
            TypeExpr::Tuple(elems) => {
                ResolvedTy::Tuple(elems.iter().map(|elem| self.lower_type(elem)).collect())
            }
            TypeExpr::Array { element, size } => {
                ResolvedTy::Array(Box::new(self.lower_type(element)), *size)
            }
            TypeExpr::Slice(elem) => ResolvedTy::Slice(Box::new(self.lower_type(elem))),
            TypeExpr::Function {
                params,
                return_type,
            } => ResolvedTy::Function {
                params: params.iter().map(|param| self.lower_type(param)).collect(),
                ret: Box::new(self.lower_type(return_type)),
            },
            TypeExpr::Pointer {
                is_mutable,
                pointee,
            } => ResolvedTy::Pointer {
                is_mutable: *is_mutable,
                pointee: Box::new(self.lower_type(pointee)),
            },
            // `&T` immutable borrow — first-class no-retain shared reference.
            TypeExpr::Borrow(inner) => ResolvedTy::Borrow {
                pointee: Box::new(self.lower_type(inner)),
            },
            // `dyn Trait` / `dyn Trait<Arg>` / `dyn Trait<Assoc = T>` in any
            // type-annotation position. Each `TraitBound` maps to a
            // `ResolvedTraitBound` via the same three-field lowering
            // `lower_machine_trait_bound` uses; the result reaches the existing
            // downstream `ResolvedTy::TraitObject` paths in MIR and codegen
            // (fat-pointer / vtable machinery — W3.031 / W3.042).
            TypeExpr::TraitObject(bounds) => ResolvedTy::TraitObject {
                traits: bounds
                    .iter()
                    .map(|tb| self.lower_machine_trait_bound(tb))
                    .collect(),
            },
            _ => {
                self.unsupported(ty.1.clone(), "type-expression", "slice-2");
                ResolvedTy::Unit
            }
        }
    }

    fn binary_ty(op: BinaryOp, left: &ResolvedTy, right: &ResolvedTy) -> ResolvedTy {
        match op {
            BinaryOp::Equal
            | BinaryOp::NotEqual
            | BinaryOp::Less
            | BinaryOp::LessEqual
            | BinaryOp::Greater
            | BinaryOp::GreaterEqual
            | BinaryOp::And
            | BinaryOp::Or => ResolvedTy::Bool,
            BinaryOp::Add if left == &ResolvedTy::String || right == &ResolvedTy::String => {
                ResolvedTy::String
            }
            // Wrapping ops (WrappingAdd/WrappingSub/WrappingMul) fall through
            // to the wildcard: they return the left operand's integer type,
            // same as any other integer arithmetic op. The type checker has
            // already enforced integer-only operands.
            _ => left.clone(),
        }
    }

    fn resolve_numeric_method_ty(
        &mut self,
        ty: &Ty,
        span: &Span,
        label: &str,
    ) -> Option<ResolvedTy> {
        match ResolvedTy::from_ty(ty) {
            Ok(ty) => Some(ty),
            Err(err) => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: label.to_string(),
                        reason: err.to_string(),
                    },
                    span.clone(),
                    "checker-authoritative numeric method lowering type failed boundary conversion",
                ));
                None
            }
        }
    }

    fn register_option_layout(&mut self, operand_ty: &ResolvedTy, span: &Span, context: &str) {
        let key = EnumMonoKey {
            origin: SYNTHETIC_OPTION_ITEM,
            origin_name: "Option".to_string(),
            type_args: vec![operand_ty.clone()],
        };
        if self
            .enum_layout_registry
            .insert(
                key,
                vec![
                    EnumVariantLayout {
                        name: "Some".to_string(),
                        field_tys: vec![operand_ty.clone()],
                    },
                    EnumVariantLayout {
                        name: "None".to_string(),
                        field_tys: Vec::new(),
                    },
                ],
            )
            .is_err()
        {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::EnumLayoutCapExceeded {
                    cap: self.enum_layout_registry.cap(),
                },
                span.clone(),
                format!(
                    "enum monomorphisation cap exceeded while registering {context} Option layout"
                ),
            ));
        }
    }

    fn register_numeric_checked_option_layout(&mut self, operand_ty: &ResolvedTy, span: &Span) {
        self.register_option_layout(operand_ty, span, "checked numeric method");
    }

    fn register_vec_iter_layout(&mut self, elem_ty: &ResolvedTy, span: &Span) {
        let vec_ty = Self::resolved_vec_ty(elem_ty.clone());
        let key = RecordMonoKey {
            origin: SYNTHETIC_VEC_ITER_ITEM,
            origin_name: "VecIter".to_string(),
            type_args: vec![elem_ty.clone()],
        };
        let fields = vec![
            ("vec".to_string(), vec_ty),
            ("idx".to_string(), ResolvedTy::I64),
        ];
        if self
            .record_layout_registry
            .insert(key, fields, span.clone())
            .is_err()
            && !self.record_layout_cap_diag_emitted
        {
            self.record_layout_cap_diag_emitted = true;
            let cap = self.record_layout_registry.cap();
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::RecordLayoutCapExceeded { cap },
                span.clone(),
                "too many distinct VecIter<T> instantiations; the compiler refuses to \
                 monomorphise beyond the configured record-layout cap",
            ));
        }
    }

    fn resolved_vec_ty(elem_ty: ResolvedTy) -> ResolvedTy {
        ResolvedTy::Named {
            name: "Vec".to_string(),
            args: vec![elem_ty],
            builtin: Some(BuiltinType::Vec),
            is_opaque: false,
        }
    }

    fn resolved_vec_iter_ty(elem_ty: ResolvedTy) -> ResolvedTy {
        ResolvedTy::Named {
            name: "VecIter".to_string(),
            args: vec![elem_ty],
            builtin: None,
            is_opaque: false,
        }
    }

    fn resolved_option_ty(elem_ty: ResolvedTy) -> ResolvedTy {
        ResolvedTy::Named {
            name: "Option".to_string(),
            args: vec![elem_ty],
            builtin: None,
            is_opaque: false,
        }
    }

    fn make_expr(
        &mut self,
        kind: HirExprKind,
        ty: ResolvedTy,
        intent: IntentKind,
        span: Span,
    ) -> HirExpr {
        let value_class = if Self::is_vec_iter_ty(&ty) {
            ValueClass::CowValue
        } else {
            ValueClass::of_ty(&ty, &self.type_classes)
        };
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class,
            ty,
            intent,
            kind,
            span,
        }
    }

    fn is_vec_iter_ty(ty: &ResolvedTy) -> bool {
        matches!(
            ty,
            ResolvedTy::Named {
                name,
                args,
                builtin: None,
                ..
            } if name == "VecIter" && args.len() == 1
        )
    }

    fn make_binding_ref(
        &mut self,
        name: String,
        binding: BindingId,
        ty: ResolvedTy,
        intent: IntentKind,
        span: Span,
    ) -> HirExpr {
        self.make_expr(
            HirExprKind::BindingRef {
                name,
                resolved: ResolvedRef::Binding(binding),
            },
            ty,
            intent,
            span,
        )
    }

    fn make_i64_literal(&mut self, value: i64, span: Span) -> HirExpr {
        self.make_expr(
            HirExprKind::Literal(HirLiteral::Integer(value)),
            ResolvedTy::I64,
            IntentKind::Read,
            span,
        )
    }

    fn make_unit_block(
        &mut self,
        statements: Vec<HirStmt>,
        tail: Option<HirExpr>,
        ty: ResolvedTy,
        span: Span,
    ) -> HirBlock {
        HirBlock {
            node: self.ids.node(),
            scope: self.ids.scope(),
            statements,
            tail: tail.map(Box::new),
            ty,
            span,
        }
    }

    fn make_vec_len_call(
        &mut self,
        vec_expr: HirExpr,
        elem_ty: &ResolvedTy,
        span: Span,
    ) -> HirExpr {
        self.make_expr(
            HirExprKind::ResolvedImplCall {
                receiver: Box::new(vec_expr),
                impl_id: ImplId(u32::MAX),
                method_name: "len".to_string(),
                target_symbol: "hew_vec_len".to_string(),
                type_args: vec![Self::resolved_ty_pattern(elem_ty)],
                args: Vec::new(),
                ret_ty: ResolvedTy::I64,
            },
            ResolvedTy::I64,
            IntentKind::Read,
            span,
        )
    }

    fn resolved_option_elem_ty(ty: &ResolvedTy) -> Option<ResolvedTy> {
        let ResolvedTy::Named {
            name,
            args,
            builtin: Some(BuiltinType::Option),
            ..
        } = ty
        else {
            return None;
        };
        if name == "Option" && args.len() == 1 {
            Some(args[0].clone())
        } else {
            None
        }
    }

    fn direct_method_return_ty(
        &mut self,
        callee: &str,
        receiver_args: &[ResolvedTy],
        span: &Span,
        context: &str,
    ) -> Option<ResolvedTy> {
        let Some(sig) = self.fn_sigs.get(callee).cloned() else {
            self.unsupported(
                span.clone(),
                format!("{context} requires lowered method symbol `{callee}`"),
                "iterator-runtime-dispatch",
            );
            return None;
        };
        let type_params: HashSet<String> = sig.type_params.iter().cloned().collect();
        let Ok(mut ret_ty) = ResolvedTy::from_ty_with_type_params(&sig.return_type, &type_params)
        else {
            self.unsupported(
                span.clone(),
                format!("{context} method `{callee}` has a non-boundary return type"),
                "iterator-runtime-dispatch",
            );
            return None;
        };
        if receiver_args.len() != sig.type_params.len() {
            self.unsupported(
                span.clone(),
                format!(
                    "{context} method `{callee}` has {} type parameter(s), but the receiver supplies {} type argument(s)",
                    sig.type_params.len(),
                    receiver_args.len()
                ),
                "iterator-runtime-dispatch",
            );
            return None;
        }
        if !sig.type_params.is_empty() {
            ret_ty = substitute_type_params(&ret_ty, &sig.type_params, receiver_args);
        }
        Some(ret_ty)
    }

    fn generic_iterator_next_shape(
        &mut self,
        iter_ty: &ResolvedTy,
        span: &Span,
    ) -> Option<(ResolvedTy, HirVarSelfMethodTarget)> {
        let ResolvedTy::Named {
            name,
            args,
            builtin: None,
            ..
        } = iter_ty
        else {
            return None;
        };
        let callee = crate::node::HirImplBlock::method_symbol(name, "next");
        let sig = self.fn_sigs.get(&callee).cloned()?;
        if !sig.requires_mutable_receiver {
            self.unsupported(
                span.clone(),
                format!("generic for-in requires iterator method `{callee}` to take `var self`"),
                "iterator-runtime-dispatch",
            );
            return None;
        }
        let ret_ty = self.direct_method_return_ty(&callee, args, span, "generic for-in next")?;
        let Some(elem_ty) = Self::resolved_option_elem_ty(&ret_ty) else {
            self.unsupported(
                span.clone(),
                format!(
                    "generic for-in requires iterator method `{callee}` to return `Option<T>`, got `{ret_ty}`"
                ),
                "iterator-runtime-dispatch",
            );
            return None;
        };
        Some((elem_ty, HirVarSelfMethodTarget::Direct { callee }))
    }

    fn for_iter_next_call_for_ty(
        &mut self,
        iter_ty: &ResolvedTy,
        span: &Span,
    ) -> Option<(ResolvedTy, ForIterNextCall)> {
        if let ResolvedTy::Named {
            name,
            args,
            builtin: None,
            ..
        } = iter_ty
        {
            if name == "VecIter" && args.len() == 1 {
                return Some((args[0].clone(), ForIterNextCall::BuiltinVecIter));
            }
        }
        self.generic_iterator_next_shape(iter_ty, span)
            .map(|(elem_ty, target)| (elem_ty, ForIterNextCall::VarSelf(target)))
    }

    fn make_direct_method_call(
        &mut self,
        callee_name: String,
        receiver: HirExpr,
        ret_ty: &ResolvedTy,
        span: Span,
    ) -> HirExpr {
        let resolved_ref = self
            .fn_registry
            .get(&callee_name)
            .map_or(ResolvedRef::Unresolved, |entry| ResolvedRef::Item(entry.id));
        let callee_ty = ResolvedTy::Function {
            params: Vec::new(),
            ret: Box::new(ret_ty.clone()),
        };
        let callee = HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::PersistentShare,
            ty: callee_ty,
            intent: IntentKind::Read,
            kind: HirExprKind::BindingRef {
                name: callee_name,
                resolved: resolved_ref,
            },
            span: span.clone(),
        };
        let site = self.ids.site();
        HirExpr {
            node: self.ids.node(),
            site,
            ty: ret_ty.clone(),
            value_class: ValueClass::of_ty(ret_ty, &self.type_classes),
            intent: IntentKind::Read,
            kind: HirExprKind::Call {
                callee: Box::new(callee),
                args: vec![receiver],
            },
            span,
        }
    }

    fn generic_into_iter_init(
        &mut self,
        iterable: HirExpr,
        span: &Span,
    ) -> Option<(HirExpr, ResolvedTy, ResolvedTy, ForIterNextCall)> {
        let ResolvedTy::Named {
            name,
            args,
            builtin: None,
            ..
        } = &iterable.ty
        else {
            return None;
        };
        let callee = crate::node::HirImplBlock::method_symbol(name, "into_iter");
        if !self.fn_sigs.contains_key(&callee) {
            return None;
        }
        let receiver_ty = iterable.ty.clone();
        let ret_ty =
            self.direct_method_return_ty(&callee, args, span, "generic for-in into_iter")?;
        let (elem_ty, next_call) = self.for_iter_next_call_for_ty(&ret_ty, span)?;
        let call = self.make_direct_method_call(callee.clone(), iterable, &ret_ty, span.clone());
        self.record_var_self_direct_monomorphisation(&callee, &receiver_ty, span, call.site);
        Some((call, ret_ty, elem_ty, next_call))
    }

    fn resolved_ty_pattern(ty: &ResolvedTy) -> TyPattern {
        match ty {
            ResolvedTy::Tuple(items) => {
                TyPattern::Tuple(items.iter().map(Self::resolved_ty_pattern).collect())
            }
            ResolvedTy::Named { name, args, .. } if !args.is_empty() => TyPattern::App {
                ctor: name.clone(),
                args: args.iter().map(Self::resolved_ty_pattern).collect(),
            },
            _ => TyPattern::Primitive(ty.to_string()),
        }
    }

    fn make_option_ctor(
        &mut self,
        variant_name: &str,
        payload: Option<HirExpr>,
        elem_ty: &ResolvedTy,
        span: Span,
    ) -> HirExpr {
        let option_ty = Self::resolved_option_ty(elem_ty.clone());
        let variant_idx = match variant_name {
            "Some" => 0,
            "None" => 1,
            _ => unreachable!("only Option::Some/None are synthesized"),
        };
        let payload = payload.map(|expr| vec![("0".to_string(), expr)]);
        self.make_expr(
            HirExprKind::MachineVariantCtor {
                machine_name: "Option".to_string(),
                state_idx: variant_idx,
                payload,
            },
            option_ty,
            IntentKind::Read,
            span,
        )
    }

    fn lower_builtin_vec_into_iter(
        &mut self,
        receiver: &Spanned<Expr>,
        elem_ty: ResolvedTy,
        span: Span,
    ) -> (HirExprKind, ResolvedTy) {
        let receiver_hir = self.lower_expr(receiver, IntentKind::Consume);
        let iter_expr = self.make_vec_iter_init(receiver_hir, elem_ty, span);
        (iter_expr.kind, iter_expr.ty)
    }

    fn make_vec_iter_init(
        &mut self,
        receiver_hir: HirExpr,
        elem_ty: ResolvedTy,
        span: Span,
    ) -> HirExpr {
        self.register_vec_iter_layout(&elem_ty, &span);
        let idx = self.make_i64_literal(0, span.clone());
        let iter_ty = Self::resolved_vec_iter_ty(elem_ty.clone());
        self.make_expr(
            HirExprKind::StructInit {
                name: "VecIter".to_string(),
                type_args: vec![elem_ty],
                fields: vec![("vec".to_string(), receiver_hir), ("idx".to_string(), idx)],
                base: None,
            },
            iter_ty,
            IntentKind::Read,
            span,
        )
    }

    #[expect(
        clippy::too_many_lines,
        reason = "synthetic VecIter::next expansion must build the full caller-side state machine in HIR"
    )]
    fn lower_builtin_vec_iter_next(
        &mut self,
        receiver: &Spanned<Expr>,
        elem_ty: &ResolvedTy,
        span: Span,
    ) -> (HirExprKind, ResolvedTy) {
        self.register_option_layout(elem_ty, &span, "VecIter::next");
        self.register_vec_iter_layout(elem_ty, &span);
        let option_ty = Self::resolved_option_ty(elem_ty.clone());
        let iter_ty = Self::resolved_vec_iter_ty(elem_ty.clone());
        let lowered_receiver = self.lower_expr(receiver, IntentKind::Modify);
        let HirExprKind::BindingRef {
            name: receiver_name,
            resolved: ResolvedRef::Binding(receiver_binding),
        } = &lowered_receiver.kind
        else {
            self.unsupported(
                span.clone(),
                "VecIter::next requires a mutable binding receiver in the Rust MIR pipeline",
                "iterator-runtime-dispatch",
            );
            return (
                HirExprKind::Unsupported("VecIter::next receiver is not a binding".into()),
                option_ty,
            );
        };
        let receiver_name = receiver_name.clone();
        let receiver_binding = *receiver_binding;

        self.push_scope();
        let iter_obj = self.make_binding_ref(
            receiver_name.clone(),
            receiver_binding,
            iter_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );
        let idx_read = self.make_expr(
            HirExprKind::FieldAccess {
                object: Box::new(iter_obj),
                field: "idx".to_string(),
            },
            ResolvedTy::I64,
            IntentKind::Read,
            span.clone(),
        );
        let iter_obj = self.make_binding_ref(
            receiver_name.clone(),
            receiver_binding,
            iter_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );
        let vec_read_for_len = self.make_expr(
            HirExprKind::FieldAccess {
                object: Box::new(iter_obj),
                field: "vec".to_string(),
            },
            Self::resolved_vec_ty(elem_ty.clone()),
            IntentKind::Read,
            span.clone(),
        );
        let len_call = self.make_vec_len_call(vec_read_for_len, elem_ty, span.clone());
        let condition = self.make_expr(
            HirExprKind::Binary {
                op: BinaryOp::GreaterEqual,
                left: Box::new(idx_read),
                right: Box::new(len_call),
            },
            ResolvedTy::Bool,
            IntentKind::Read,
            span.clone(),
        );

        let none_expr = self.make_option_ctor("None", None, elem_ty, span.clone());
        let then_block =
            self.make_unit_block(Vec::new(), Some(none_expr), option_ty.clone(), span.clone());
        let then_expr = self.make_expr(
            HirExprKind::Block(then_block),
            option_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );

        let iter_obj = self.make_binding_ref(
            receiver_name.clone(),
            receiver_binding,
            iter_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );
        let vec_read_for_get = self.make_expr(
            HirExprKind::FieldAccess {
                object: Box::new(iter_obj),
                field: "vec".to_string(),
            },
            Self::resolved_vec_ty(elem_ty.clone()),
            IntentKind::Read,
            span.clone(),
        );
        let iter_obj = self.make_binding_ref(
            receiver_name.clone(),
            receiver_binding,
            iter_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );
        let idx_read_for_get = self.make_expr(
            HirExprKind::FieldAccess {
                object: Box::new(iter_obj),
                field: "idx".to_string(),
            },
            ResolvedTy::I64,
            IntentKind::Read,
            span.clone(),
        );
        let value_expr = self.make_expr(
            HirExprKind::Index {
                container: Box::new(vec_read_for_get),
                index: Box::new(idx_read_for_get),
            },
            elem_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );
        let value_binding_name = format!("__hew_iter_value_{}", self.ids.binding().0);
        let value_binding = self.bind(
            value_binding_name.clone(),
            elem_ty.clone(),
            false,
            span.clone(),
        );
        let value_binding_id = value_binding.id;
        let value_stmt = HirStmt {
            node: self.ids.node(),
            kind: HirStmtKind::Let(value_binding, Some(value_expr)),
            span: span.clone(),
        };

        let iter_obj = self.make_binding_ref(
            receiver_name.clone(),
            receiver_binding,
            iter_ty.clone(),
            IntentKind::Modify,
            span.clone(),
        );
        let idx_assign_target = self.make_expr(
            HirExprKind::FieldAccess {
                object: Box::new(iter_obj),
                field: "idx".to_string(),
            },
            ResolvedTy::I64,
            IntentKind::Modify,
            span.clone(),
        );
        let iter_obj = self.make_binding_ref(
            receiver_name,
            receiver_binding,
            iter_ty,
            IntentKind::Read,
            span.clone(),
        );
        let idx_read_for_add = self.make_expr(
            HirExprKind::FieldAccess {
                object: Box::new(iter_obj),
                field: "idx".to_string(),
            },
            ResolvedTy::I64,
            IntentKind::Read,
            span.clone(),
        );
        let one = self.make_i64_literal(1, span.clone());
        let idx_plus_one = self.make_expr(
            HirExprKind::Binary {
                op: BinaryOp::Add,
                left: Box::new(idx_read_for_add),
                right: Box::new(one),
            },
            ResolvedTy::I64,
            IntentKind::Read,
            span.clone(),
        );
        let assign_stmt = HirStmt {
            node: self.ids.node(),
            kind: HirStmtKind::Assign {
                target: idx_assign_target,
                value: Box::new(idx_plus_one),
            },
            span: span.clone(),
        };
        let value_ref = self.make_binding_ref(
            value_binding_name,
            value_binding_id,
            elem_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );
        let some_expr = self.make_option_ctor("Some", Some(value_ref), elem_ty, span.clone());
        let else_block = self.make_unit_block(
            vec![value_stmt, assign_stmt],
            Some(some_expr),
            option_ty.clone(),
            span.clone(),
        );
        let else_expr = self.make_expr(
            HirExprKind::Block(else_block),
            option_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );
        let if_expr = self.make_expr(
            HirExprKind::If {
                condition: Box::new(condition),
                then_expr: Box::new(then_expr),
                else_expr: Some(Box::new(else_expr)),
            },
            option_ty.clone(),
            IntentKind::Read,
            span.clone(),
        );
        let block = self.make_unit_block(Vec::new(), Some(if_expr), option_ty.clone(), span);
        self.pop_scope();
        (HirExprKind::Block(block), option_ty)
    }

    #[expect(
        clippy::too_many_lines,
        reason = "for-over-Vec desugars directly to existing Loop/Match HIR nodes"
    )]
    fn lower_for_iter_desugar(
        &mut self,
        pattern: &Spanned<Pattern>,
        iterable: &Spanned<Expr>,
        body: &Block,
        span: Span,
    ) -> HirExprKind {
        let Pattern::Identifier(var_name) = &pattern.0 else {
            unreachable!("lower_for_iter_desugar is only called for identifier patterns");
        };
        let lowered_iterable = self.lower_expr(iterable, IntentKind::Consume);
        let (iter_init, iter_ty, elem_ty, next_call) = match lowered_iterable.ty.clone() {
            ResolvedTy::Named {
                name,
                args,
                builtin: Some(BuiltinType::Vec),
                ..
            } if name == "Vec" && args.len() == 1 => {
                let elem_ty = args[0].clone();
                (
                    self.make_vec_iter_init(lowered_iterable, elem_ty.clone(), iterable.1.clone()),
                    Self::resolved_vec_iter_ty(elem_ty.clone()),
                    elem_ty,
                    ForIterNextCall::BuiltinVecIter,
                )
            }
            ResolvedTy::Named {
                name,
                args,
                builtin: None,
                ..
            } if name == "VecIter" && args.len() == 1 => (
                lowered_iterable,
                Self::resolved_vec_iter_ty(args[0].clone()),
                args[0].clone(),
                ForIterNextCall::BuiltinVecIter,
            ),
            // `for x in <generator>`: the generator value IS the iterator. The
            // loop binds it to `__hew_for_iter_*` (consuming it) and drives one
            // `.next()` per iteration; the binding's scope-exit drop frees it.
            ResolvedTy::Named {
                ref args,
                builtin: Some(BuiltinType::Generator | BuiltinType::AsyncGenerator),
                ..
            } if !args.is_empty() => {
                let elem_ty = args[0].clone();
                let gen_ty = lowered_iterable.ty.clone();
                (
                    lowered_iterable,
                    gen_ty,
                    elem_ty,
                    ForIterNextCall::Generator,
                )
            }
            other => {
                if let Some(shape) =
                    self.generic_into_iter_init(lowered_iterable.clone(), &iterable.1)
                {
                    shape
                } else if let Some((elem_ty, target)) =
                    self.generic_iterator_next_shape(&other, &iterable.1)
                {
                    (
                        lowered_iterable,
                        other,
                        elem_ty,
                        ForIterNextCall::VarSelf(target),
                    )
                } else {
                    self.unsupported(
                    iterable.1.clone(),
                    format!(
                        "for-in over non-Range iterable `{other}`; the Rust MIR pipeline currently supports Vec<T>, VecIter<T>, and concrete Iterator/IntoIterator impls"
                    ),
                    "iterator-runtime-dispatch",
                );
                    self.push_scope();
                    let _ = self.lower_block(body, &ResolvedTy::Unit);
                    self.pop_scope();
                    return HirExprKind::Unsupported(
                        "for-in over unsupported non-Range iterable type".into(),
                    );
                }
            }
        };

        self.push_scope();
        let block_scope = self.ids.scope();
        let iter_name = format!("__hew_for_iter_{}", self.ids.binding().0);
        let iter_binding = self.bind(iter_name.clone(), iter_ty, true, iterable.1.clone());
        let iter_stmt = HirStmt {
            node: self.ids.node(),
            kind: HirStmtKind::Let(iter_binding.clone(), Some(iter_init)),
            span: iterable.1.clone(),
        };

        let next_expr = match next_call {
            ForIterNextCall::BuiltinVecIter => {
                let next_receiver = (Expr::Identifier(iter_name), iterable.1.clone());
                let (next_kind, next_ty) =
                    self.lower_builtin_vec_iter_next(&next_receiver, &elem_ty, iterable.1.clone());
                self.make_expr(next_kind, next_ty, IntentKind::Read, iterable.1.clone())
            }
            ForIterNextCall::VarSelf(target) => {
                let receiver = self.make_binding_ref(
                    iter_binding.name.clone(),
                    iter_binding.id,
                    iter_binding.ty.clone(),
                    IntentKind::Consume,
                    iterable.1.clone(),
                );
                let option_ty = Self::resolved_option_ty(elem_ty.clone());
                self.register_option_layout(&elem_ty, &iterable.1, "generic Iterator::next");
                self.make_expr(
                    HirExprKind::VarSelfMethodCall {
                        receiver: Box::new(receiver),
                        target,
                        args: Vec::new(),
                        ret_ty: option_ty.clone(),
                        receiver_ty: iter_binding.ty.clone(),
                    },
                    option_ty,
                    IntentKind::Read,
                    iterable.1.clone(),
                )
            }
            ForIterNextCall::Generator => {
                // Borrow the generator binding (Read) and emit the dedicated
                // `GeneratorNext` consumption node — identical to a source-level
                // `g.next()`. The binding stays the sole owner so its scope-exit
                // drop frees the context once on loop exit.
                let receiver = self.make_binding_ref(
                    iter_binding.name.clone(),
                    iter_binding.id,
                    iter_binding.ty.clone(),
                    IntentKind::Read,
                    iterable.1.clone(),
                );
                let option_ty = Self::resolved_option_ty(elem_ty.clone());
                self.register_option_layout(&elem_ty, &iterable.1, "Generator::next");
                self.make_expr(
                    HirExprKind::GeneratorNext {
                        receiver: Box::new(receiver),
                        yield_ty: elem_ty.clone(),
                    },
                    option_ty,
                    IntentKind::Read,
                    iterable.1.clone(),
                )
            }
        };

        self.push_scope();
        let loop_binding = self.bind(var_name.clone(), elem_ty.clone(), false, pattern.1.clone());
        let some_binding = HirMatchArmBinding {
            binding: loop_binding.id,
            field_idx: 0,
            name: var_name.clone(),
            ty: elem_ty.clone(),
        };
        let body_block = self.lower_block(body, &ResolvedTy::Unit);
        self.pop_scope();
        let body_ty = body_block.ty.clone();
        let some_body = self.make_expr(
            HirExprKind::Block(body_block),
            body_ty,
            IntentKind::Read,
            span.clone(),
        );
        let none_body = self.make_expr(
            HirExprKind::Break {
                label: None,
                value: None,
            },
            ResolvedTy::Unit,
            IntentKind::Read,
            span.clone(),
        );
        let match_expr = self.make_expr(
            HirExprKind::Match {
                scrutinee: Box::new(next_expr),
                arms: vec![
                    HirMatchArm {
                        predicate: HirMatchArmPredicate::EnumVariant {
                            variant_match: hew_types::VariantMatch {
                                type_name: "Option".to_string(),
                                variant_name: "Some".to_string(),
                            },
                            variant_idx: 0,
                        },
                        bindings: vec![some_binding],
                        payload_predicates: Vec::new(),
                        guard: None,
                        body: some_body,
                        span: span.clone(),
                    },
                    HirMatchArm {
                        predicate: HirMatchArmPredicate::EnumVariant {
                            variant_match: hew_types::VariantMatch {
                                type_name: "Option".to_string(),
                                variant_name: "None".to_string(),
                            },
                            variant_idx: 1,
                        },
                        bindings: Vec::new(),
                        payload_predicates: Vec::new(),
                        guard: None,
                        body: none_body,
                        span: iterable.1.clone(),
                    },
                ],
            },
            ResolvedTy::Unit,
            IntentKind::Read,
            span.clone(),
        );
        let match_stmt = HirStmt {
            node: self.ids.node(),
            kind: HirStmtKind::Expr(match_expr),
            span: span.clone(),
        };
        let loop_body = self.make_unit_block(
            Vec::from([match_stmt]),
            None,
            ResolvedTy::Unit,
            span.clone(),
        );
        let loop_expr = self.make_expr(
            HirExprKind::Loop { body: loop_body },
            ResolvedTy::Unit,
            IntentKind::Read,
            span.clone(),
        );
        let loop_stmt = HirStmt {
            node: self.ids.node(),
            kind: HirStmtKind::Expr(loop_expr),
            span: span.clone(),
        };
        self.pop_scope();

        HirExprKind::Block(HirBlock {
            node: self.ids.node(),
            scope: block_scope,
            statements: vec![iter_stmt, loop_stmt],
            tail: None,
            ty: ResolvedTy::Unit,
            span,
        })
    }

    /// Lower `receiver.method(args)` using the checker's method-call side-tables.
    ///
    /// Fail-closed per `checker-output-boundary` (LESSONS P0): a missing entry for
    /// this call site's span is a hard diagnostic — HIR never re-infers the runtime
    /// symbol from the receiver type.  Only `RewriteToFunction` is recognised here;
    /// other rewrite variants are rejected as unsupported (they target the C++/MLIR
    /// pipeline, not the Rust MIR pipeline).
    #[allow(
        clippy::too_many_lines,
        reason = "single linear lowering path with three exclusive branches \
                  (dyn-method dispatch / dyn-receiver fail-closed / legacy \
                  rewrite); splitting would scatter related fail-closed \
                  diagnostics across helpers"
    )]
    fn lower_method_call(
        &mut self,
        receiver: &Spanned<Expr>,
        method: &str,
        args: &[hew_parser::ast::CallArg],
        span: Span,
        site: SiteId,
    ) -> (HirExprKind, ResolvedTy) {
        // Intercept `.clone()` before any side-table lookup — but only when the
        // type checker has NOT already resolved the call to a user-defined method
        // (e.g. a user-declared `trait Clone { fn clone(val: Self) -> Self; }`).
        //
        // Fail-closed per the no-silent-stub invariant (M-COW P0):
        // `.clone()` must never silently return the same handle.  The runtime
        // copy path (e.g. `hew_bytes_clone_ref` for `Bytes`) will be wired
        // into the HIR→MIR→codegen pipeline in P2.  Until then, every
        // unresolved `.clone()` call is a compile error with an explicit
        // diagnostic so the user is never left guessing why their code "works"
        // but produces aliased references instead of independent copies.
        let key = SpanKey::from(&span);
        if method == "clone"
            && args.is_empty()
            && !self.resolved_calls.contains_key(&key)
            && !self.method_call_rewrites.contains_key(&key)
            && !self.dyn_trait_method_calls.contains_key(&key)
            && !self.numeric_method_lowerings.contains_key(&key)
        {
            let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
            let receiver_ty = lowered_receiver.ty.to_string();
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CloneNotYetSupported {
                    receiver_ty: receiver_ty.clone(),
                },
                span.clone(),
                format!(
                    "`.clone()` on `{receiver_ty}` is not yet wired to a copy path \
                     in this phase (M-COW P0). The runtime deep-copy for heap types \
                     will be connected in P2. Restructure to avoid `.clone()` for now, \
                     or pass by value (which already retains under M-COW)."
                ),
            ));
            let ret_ty = lowered_receiver.ty.clone();
            return (
                HirExprKind::Unsupported(format!(
                    "`.clone()` on `{receiver_ty}` not yet supported"
                )),
                ret_ty,
            );
        }
        if let Some(lowering) = self.numeric_method_lowerings.get(&key).cloned() {
            if args.len() != 1 {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: format!("numeric method `.{method}`"),
                        reason: format!(
                            "checker side-table expected one argument, found {}",
                            args.len()
                        ),
                    },
                    span.clone(),
                    "numeric method lowering requires exactly one checked argument",
                ));
                return (
                    HirExprKind::Unsupported(format!(
                        "numeric method `.{method}` has invalid arity"
                    )),
                    ResolvedTy::Unit,
                );
            }
            let Some(result_ty) =
                self.resolve_numeric_method_ty(&lowering.result_ty, &span, "numeric method result")
            else {
                return (
                    HirExprKind::Unsupported(format!(
                        "numeric method `.{method}` has poisoned result type"
                    )),
                    ResolvedTy::Unit,
                );
            };
            let Some(operand_ty) = self.resolve_numeric_method_ty(
                &lowering.operand_ty,
                &span,
                "numeric method operand",
            ) else {
                return (
                    HirExprKind::Unsupported(format!(
                        "numeric method `.{method}` has poisoned operand type"
                    )),
                    ResolvedTy::Unit,
                );
            };
            if lowering.family == NumericMethodFamily::Checked {
                self.register_numeric_checked_option_layout(&operand_ty, &span);
            }
            let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
            let lowered_arg = self.lower_expr(args[0].expr(), IntentKind::Read);
            return (
                HirExprKind::NumericMethod {
                    receiver: Box::new(lowered_receiver),
                    arg: Box::new(lowered_arg),
                    family: lowering.family,
                    op: lowering.op,
                    result_ty: result_ty.clone(),
                    operand_ty,
                    signedness: lowering.signedness,
                    width: lowering.width,
                },
                result_ty,
            );
        }
        if let Some(dispatch) = self.actor_method_dispatch.get(&key).cloned() {
            let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
            let lowered_args: Vec<HirExpr> = args
                .iter()
                .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                .collect();
            return match dispatch {
                ActorMethodKind::Fire(method_id) => (
                    HirExprKind::ActorSend {
                        receiver: Box::new(lowered_receiver),
                        method_id,
                        args: lowered_args,
                    },
                    ResolvedTy::Unit,
                ),
                ActorMethodKind::Ask(method_id, reply_ty) => match ResolvedTy::from_ty(&reply_ty) {
                    Ok(reply_ty) => (
                        HirExprKind::ActorAsk {
                            receiver: Box::new(lowered_receiver),
                            method_id,
                            args: lowered_args,
                            reply_ty: reply_ty.clone(),
                            deadline_ns: None,
                        },
                        reply_ty,
                    ),
                    Err(err) => {
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::CheckerBoundaryViolation {
                                name: format!("actor method `.{method}`"),
                                reason: err.to_string(),
                            },
                            span.clone(),
                            "checker-authoritative actor_method_dispatch reply type failed boundary conversion",
                        ));
                        (
                            HirExprKind::Unsupported(format!(
                                "actor method `.{method}` has poisoned dispatch reply type"
                            )),
                            ResolvedTy::Unit,
                        )
                    }
                },
            };
        }
        if matches!(
            self.method_call_receiver_kinds.get(&key),
            Some(MethodCallReceiverKind::ActorInstance { .. })
        ) {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: format!("actor method `.{method}`"),
                    reason: "missing actor_method_dispatch entry".to_string(),
                },
                span.clone(),
                "checker classified this method-call receiver as actor-typed but omitted the actor dispatch discriminator",
            ));
            return (
                HirExprKind::Unsupported(format!(
                    "actor method `.{method}` has no dispatch discriminator"
                )),
                ResolvedTy::Unit,
            );
        }
        // Machine method dispatch: `.step()` / `.state_name()` recorded in the
        // checker's `machine_method_dispatch` side-table. Checked before
        // `method_call_rewrites` so these calls produce dedicated HIR nodes
        // (`MachineStep` / `MachineStateName`) rather than falling through to
        // `MethodCallNoRewrite`. MIR/codegen consumers wire this in slice 6.
        if let Some(dispatch) = self.machine_method_dispatch.get(&key).cloned() {
            let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
            let lowered_args: Vec<HirExpr> = args
                .iter()
                .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                .collect();
            return match dispatch {
                hew_types::MachineMethodKind::Step { machine_name } => {
                    let event = lowered_args.into_iter().next().unwrap_or_else(|| HirExpr {
                        node: self.ids.node(),
                        site: self.ids.site(),
                        value_class: ValueClass::PersistentShare,
                        ty: ResolvedTy::Unit,
                        intent: IntentKind::Read,
                        kind: HirExprKind::Unsupported(
                            "machine step: missing event argument".into(),
                        ),
                        span: span.clone(),
                    });
                    (
                        HirExprKind::MachineStep {
                            machine_name,
                            receiver: Box::new(lowered_receiver),
                            event: Box::new(event),
                        },
                        ResolvedTy::Unit,
                    )
                }
                hew_types::MachineMethodKind::StateName { machine_name } => (
                    HirExprKind::MachineStateName {
                        machine_name,
                        receiver: Box::new(lowered_receiver),
                    },
                    ResolvedTy::String,
                ),
            };
        }
        // `dyn Trait` receivers take precedence: the checker's
        // `dyn_trait_method_calls` side-table pins the trait/method/slot
        // resolution authoritatively, and these calls do NOT have a
        // `method_call_rewrites` entry (a direct-call rewrite would
        // collapse the dispatch indirection that the vtable provides).
        if let Some(dyn_call) = self.dyn_trait_method_calls.get(&key).cloned() {
            let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
            let lowered_args: Vec<HirExpr> = args
                .iter()
                .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                .collect();
            // Result type comes from the checker's expr_types side-table
            // (the call's full span). Fail-closed if absent or poisoned.
            let ret_ty = self
                .checked_ty(&span)
                .cloned()
                .or_else(|| {
                    self.expr_types
                        .get(&key)
                        .cloned()
                        .and_then(|ty| ResolvedTy::from_ty(&ty).ok())
                })
                .unwrap_or(ResolvedTy::Unit);
            // W4.047 P1.2: prove the typed handoff agrees at this fail-open
            // dyn-method-return site (no behaviour change).
            self.assert_resolved_ty_totality(&span);
            return (
                HirExprKind::CallDynMethod {
                    receiver: Box::new(lowered_receiver),
                    trait_name: dyn_call.trait_name,
                    method_name: dyn_call.method_name,
                    slot: dyn_call.slot,
                    args: lowered_args,
                    ret_ty: ret_ty.clone(),
                    signature: Box::new(dyn_call.signature),
                },
                ret_ty,
            );
        }
        // Receiver typed as `Ty::TraitObject` but no side-table entry:
        // fail-closed per `checker-output-boundary`. The checker MUST
        // populate `dyn_trait_method_calls` for every accepted call on
        // a trait-object receiver; missing entry is a hard diagnostic.
        if let Some(receiver_ty) = self.expr_types.get(&SpanKey::from(&receiver.1)) {
            if matches!(receiver_ty, hew_types::Ty::TraitObject { .. }) {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::TraitObjectMethodNoSideTableEntry {
                        method: method.to_string(),
                    },
                    span.clone(),
                    "method call on `dyn Trait` receiver has no \
                     dyn_trait_method_calls side-table entry; the \
                     checker must record one before HIR lowering",
                ));
                return (
                    HirExprKind::Unsupported(format!(
                        "method call `.{method}` on dyn-trait with no side-table entry"
                    )),
                    ResolvedTy::Unit,
                );
            }
        }
        // Look up the checker's `resolved_calls` verdict unconditionally so any
        // boundary-type conversion failure (TyPattern -> ResolvedTy mapping
        // bugs, `expr_types` side-table inconsistency, missing impl registration)
        // surfaces as a real `CheckerBoundaryViolation` diagnostic at the
        // boundary — not deferred until a runtime user hits the regression.
        // When a resolver verdict survives boundary conversion, we emit
        // `HirExprKind::ResolvedImplCall` carrying `MethodTarget.symbol_name`
        // verbatim; MIR/codegen consume that symbol via `Terminator::Call`.
        //
        // Precedence: when both `resolved_calls` and `method_call_rewrites`
        // have an entry for the same key (the current dual-emit overlap for
        // HashMap/HashSet during the C2→C3 transition), `resolved_calls`
        // wins — it carries the structured `(ImplId, MethodTarget)` verdict.
        // The legacy `method_call_rewrites` entries for that overlap are
        // removed in the C3 commit that retires the per-V allowlists, so the
        // precedence is exercised by construction once dual-emit retires.
        if let Some(resolved) = self.resolved_calls.get(&key).cloned() {
            // The checker's `expr_types` is the authoritative source for
            // the call-site result type (LESSONS `checker-authority`).
            // A missing or non-convertible entry is a checker boundary
            // violation — we record it eagerly so the gap is visible
            // long before the consumer is wired.
            let ret_ty = match self
                .expr_types
                .get(&key)
                .cloned()
                .map(|ty| ResolvedTy::from_ty(&ty))
            {
                Some(Ok(ty)) => Some(ty),
                Some(Err(err)) => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: format!("resolved-impl call `.{method}`"),
                            reason: err.to_string(),
                        },
                        span.clone(),
                        "checker-resolved method call has poisoned result type",
                    ));
                    None
                }
                None => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: format!("resolved-impl call `.{method}`"),
                            reason: "missing expr_types entry for call site".to_string(),
                        },
                        span.clone(),
                        "checker recorded a ResolvedCall for this site but no \
                         expr_types entry — the side-tables are inconsistent",
                    ));
                    None
                }
            };
            #[allow(
                clippy::items_after_statements,
                reason = "the activation gate lives next to the guard it controls; \
                          promoting to a module-level const would scatter the \
                          deferral rationale across the file"
            )]
            const RESOLVED_IMPL_CALL_ACTIVATED: bool = true;
            if RESOLVED_IMPL_CALL_ACTIVATED {
                // Only emit when the resolver verdict survived boundary
                // conversion; otherwise fall through to the legacy
                // `method_call_rewrites` arm below.
                if let Some(ret_ty) = ret_ty {
                    // Register any enum instantiation that surfaces as the
                    // return type (e.g. `HashMap::get -> Option<V>`,
                    // `HashMap::remove -> Option<V>`). Without this the
                    // module-level `enum_layouts` table lacks the matching
                    // key for `Named { name: "Option", .. }`, MIR records
                    // `ValueClass::Unknown → Strategy::UnknownBlocked` at
                    // the call site, and the totality gate fires
                    // (`DecisionMapTotal { offending_sites: [...] }`).
                    // This mirrors the legacy `RewriteToFunction` arm
                    // below — the new resolver-authority path inherits
                    // the same boundary obligation.
                    self.try_register_enum_instantiation(&span);
                    let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
                    let lowered_args: Vec<HirExpr> = args
                        .iter()
                        .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                        .collect();
                    return (
                        HirExprKind::ResolvedImplCall {
                            receiver: Box::new(lowered_receiver),
                            impl_id: resolved.impl_id,
                            method_name: resolved.method_name,
                            target_symbol: resolved.target.symbol_name,
                            type_args: resolved.type_args,
                            args: lowered_args,
                            ret_ty: ret_ty.clone(),
                        },
                        ret_ty,
                    );
                }
            }
            // Dormant path: the lookup ran (and diagnostics fired if the
            // boundary failed), but emission is deferred. Fall through to
            // the legacy `method_call_rewrites` branch below so live sites
            // keep their current dispatch behaviour.
            let _ = resolved;
        }
        let rewrite = self.method_call_rewrites.get(&key).cloned();
        match rewrite {
            Some(MethodCallRewrite::BuiltinVecIntoIter { elem_ty }) => {
                self.lower_builtin_vec_into_iter(receiver, elem_ty, span)
            }
            Some(MethodCallRewrite::BuiltinVecIterNext { elem_ty }) => {
                self.lower_builtin_vec_iter_next(receiver, &elem_ty, span)
            }
            Some(MethodCallRewrite::RemoteActorAsk) => {
                self.try_register_enum_instantiation(&span);
                if args.len() != 2 {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: "RemotePid.ask".to_string(),
                            reason: format!(
                                "checker side-table expected two arguments, found {}",
                                args.len()
                            ),
                        },
                        span.clone(),
                        "remote actor ask lowering requires message and timeout arguments",
                    ));
                    return (
                        HirExprKind::Unsupported("RemotePid.ask has invalid arity".into()),
                        ResolvedTy::Unit,
                    );
                }
                let ret_ty = self
                    .expr_types
                    .get(&key)
                    .cloned()
                    .and_then(|ty| ResolvedTy::from_ty(&ty).ok())
                    .unwrap_or(ResolvedTy::Unit);
                let reply_ty = match &ret_ty {
                    ResolvedTy::Named {
                        builtin: Some(BuiltinType::Result),
                        args,
                        ..
                    } => args.first().cloned(),
                    _ => None,
                };
                let Some(reply_ty) = reply_ty else {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: "RemotePid.ask".to_string(),
                            reason: format!(
                                "expected Result<Reply, AskError>, got {}",
                                ret_ty.user_facing()
                            ),
                        },
                        span.clone(),
                        "remote actor ask lowering requires a Result return type",
                    ));
                    return (
                        HirExprKind::Unsupported("RemotePid.ask has poisoned return type".into()),
                        ResolvedTy::Unit,
                    );
                };
                let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
                let lowered_msg = self.lower_expr(args[0].expr(), IntentKind::Read);
                let lowered_timeout = self.lower_expr(args[1].expr(), IntentKind::Read);
                (
                    HirExprKind::RemoteActorAsk {
                        receiver: Box::new(lowered_receiver),
                        msg: Box::new(lowered_msg),
                        timeout_ms: Box::new(lowered_timeout),
                        reply_ty,
                    },
                    ret_ty,
                )
            }
            Some(MethodCallRewrite::RewriteToFunction {
                c_symbol,
                consumes_receiver,
                ..
            }) => {
                // S5: a method-call rewrite that lands on a builtin-generic
                // enum result type (e.g. `Result<(), SendError>` for
                // `RemotePid<T>::tell`) needs the per-instantiation enum
                // layout registered here. Unlike struct-ctor/variant-ctor/
                // match-scrutinee paths — which already invoke
                // `try_register_enum_instantiation` — the rewrite arm builds
                // a synthetic `HirExprKind::Call` whose return type is the
                // checker-recorded `Result<...>`. Without explicit
                // registration MIR sees the `Named { name: "Result", .. }`
                // type but `module.enum_layouts` lacks the matching key,
                // and `machine_layout_names` therefore omits "Result" →
                // `UnknownType { name: "Result" }` plus
                // `ValueClass::Unknown → Strategy::UnknownBlocked` at the
                // MIR boundary.
                self.try_register_enum_instantiation(&span);
                // Read the actual return type from the checker's expr_types table.
                // Unit-returning methods (e.g. channel send/recv) record Unit there,
                // so the fallback is safe and this path remains correct for all callers.
                // `params` is empty — the call arg list carries the real args.
                let ret_ty = self
                    .expr_types
                    .get(&key)
                    .cloned()
                    .and_then(|ty| ResolvedTy::from_ty(&ty).ok())
                    .unwrap_or(ResolvedTy::Unit);
                // W4.047 P1.2: prove the typed handoff agrees at this fail-open
                // receiver-method-rewrite return site (no behaviour change).
                self.assert_resolved_ty_totality(&span);
                if self.signature_requires_mutable_receiver(&c_symbol) {
                    let lowered_receiver = self.lower_expr(receiver, IntentKind::Consume);
                    let receiver_ty = lowered_receiver.ty.clone();
                    self.record_var_self_direct_monomorphisation(
                        &c_symbol,
                        &receiver_ty,
                        &span,
                        site,
                    );
                    let lowered_args: Vec<HirExpr> = args
                        .iter()
                        .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                        .collect();
                    return (
                        HirExprKind::VarSelfMethodCall {
                            receiver: Box::new(lowered_receiver),
                            target: HirVarSelfMethodTarget::Direct { callee: c_symbol },
                            args: lowered_args,
                            ret_ty: ret_ty.clone(),
                            receiver_ty,
                        },
                        ret_ty,
                    );
                }
                // Lower receiver + args, then prepend receiver as first argument.
                // A consuming handle-release call (`.close()`-family: the
                // checker set `consumes_receiver` from the resolved runtime
                // symbol) takes ownership of the receiver, so lower it with
                // `IntentKind::Consume`. The MIR move-checker then marks the
                // handle moved-out and excludes it from the function-exit drop
                // set — a second close at scope exit would double-free the
                // underlying resource (LESSONS: raii-null-after-move,
                // cleanup-all-exits). Borrowing methods (`send`/`recv`) keep
                // `IntentKind::Read`.
                let receiver_intent = if consumes_receiver {
                    IntentKind::Consume
                } else {
                    IntentKind::Read
                };
                let lowered_receiver = self.lower_expr(receiver, receiver_intent);
                // Slice 2: a by-value direct-dot call to a generic impl method
                // on a concrete generic receiver (e.g. `p.first()` where
                // `impl<T> Pair<T> { fn first(self) -> T }` and `p: Pair<i64>`)
                // needs the impl-method monomorphisation registered so MIR has a
                // concrete body to dispatch to. The var-self (mutable-receiver)
                // branch above already does this via
                // `record_var_self_direct_monomorphisation`; the by-value branch
                // omitted it, so the call lowered to a `Call` whose mangled
                // callee (`Pair::first$$i64`) had no MIR body and failed closed
                // at the MIR boundary ("resolved callee has no MIR body").
                // `record_var_self_direct_monomorphisation` is a no-op for
                // non-generic / non-named-receiver / builtin callees, so this is
                // safe to call unconditionally for every RewriteToFunction by-value
                // method dispatch: it derives the concrete type-args from the
                // receiver type's args, registers the monomorphisation, and seeds
                // `call_site_type_args[site]` so MIR's `Call` arm mangles to the
                // same per-instantiation symbol.
                self.record_var_self_direct_monomorphisation(
                    &c_symbol,
                    &lowered_receiver.ty,
                    &span,
                    site,
                );
                let mut lowered_args = vec![lowered_receiver];
                for arg in args {
                    lowered_args.push(self.lower_expr(arg.expr(), IntentKind::Read));
                }
                let callee_ty = ResolvedTy::Function {
                    params: Vec::new(),
                    ret: Box::new(ret_ty.clone()),
                };
                // Resolve the rewrite-target c_symbol against the seeded
                // stdlib fn_registry (`seed_stdlib_fn_registry`), matching
                // the `RewriteModuleQualifiedToFunction` arm just below.
                // Without this, the BindingRef stays `Unresolved` and the
                // verifier emits `UnresolvedSymbol(<c_symbol>)`, even though
                // the catalog entry exists.
                let resolved_ref = self
                    .fn_registry
                    .get(&c_symbol)
                    .map_or(ResolvedRef::Unresolved, |entry| ResolvedRef::Item(entry.id));
                let callee = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    value_class: ValueClass::PersistentShare,
                    ty: callee_ty,
                    intent: IntentKind::Read,
                    kind: HirExprKind::BindingRef {
                        name: c_symbol,
                        resolved: resolved_ref,
                    },
                    span: span.clone(),
                };
                (
                    HirExprKind::Call {
                        callee: Box::new(callee),
                        args: lowered_args,
                    },
                    ret_ty,
                )
            }
            Some(MethodCallRewrite::GenericMathIntrinsic { op }) => {
                let lowered_args: Vec<HirExpr> = args
                    .iter()
                    .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                    .collect();
                let checked_ret_ty = self
                    .expr_types
                    .get(&key)
                    .map(Ty::materialize_literal_defaults)
                    .and_then(|ty| ResolvedTy::from_ty(&ty).ok());
                let dispatch_ty = checked_ret_ty
                    .as_ref()
                    .filter(|ty| stdlib_catalog::generic_math_intrinsic_callee(op, ty).is_some())
                    .cloned()
                    .or_else(|| lowered_args.first().map(|arg| arg.ty.clone()));
                let Some(dispatch_ty) = dispatch_ty else {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: format!("math.{method}"),
                            reason: "generic math intrinsic had no lowered arguments".to_string(),
                        },
                        span.clone(),
                        "generic math intrinsic dispatch requires at least one checked argument",
                    ));
                    return (
                        HirExprKind::Unsupported(format!(
                            "generic math intrinsic `math.{method}` has no dispatch type"
                        )),
                        ResolvedTy::Unit,
                    );
                };
                let Some((symbol, ret_ty)) =
                    stdlib_catalog::generic_math_intrinsic_callee(op, &dispatch_ty)
                else {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: format!("math.{method}"),
                            reason: format!(
                                "no generic math intrinsic for operand type `{dispatch_ty}`"
                            ),
                        },
                        span.clone(),
                        "current math intrinsic dispatch supports i64 and f64 operands",
                    ));
                    return (
                        HirExprKind::Unsupported(format!(
                            "generic math intrinsic `math.{method}` unsupported for `{dispatch_ty}`"
                        )),
                        ResolvedTy::Unit,
                    );
                };
                let resolved_ref = self
                    .fn_registry
                    .get(symbol)
                    .map_or(ResolvedRef::Unresolved, |entry| ResolvedRef::Item(entry.id));
                let callee_ty = ResolvedTy::Function {
                    params: Vec::new(),
                    ret: Box::new(ret_ty.clone()),
                };
                let callee = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    value_class: ValueClass::PersistentShare,
                    ty: callee_ty,
                    intent: IntentKind::Read,
                    kind: HirExprKind::BindingRef {
                        name: symbol.to_string(),
                        resolved: resolved_ref,
                    },
                    span: span.clone(),
                };
                (
                    HirExprKind::Call {
                        callee: Box::new(callee),
                        args: lowered_args,
                    },
                    ret_ty,
                )
            }
            Some(MethodCallRewrite::RewriteModuleQualifiedToFunction { c_symbol, .. }) => {
                // Module-qualified direct call: the receiver expression is the
                // module identifier, not a value.  Lower the args only — do
                // NOT prepend the receiver (LESSONS
                // `module-qualified-rewrite-authority`).
                //
                // The `c_symbol` from the checker uses dotted notation for
                // user-module calls (`module.fn`) and `hew_*` for stdlib calls.
                // User-module keys are stored in `fn_registry` under the mangled
                // form (`module$fn`) so they are safe as native object-file
                // symbols on all targets.  Apply `mangle_dotted_name` before
                // the registry lookup AND in the emitted `BindingRef.name` so
                // all three consumers (HIR verifier, MIR `module_fn_names`,
                // codegen `add_function`) see the same mangled key.  Stdlib
                // `hew_*` symbols contain no dots, so mangling is identity.
                let symbol = crate::mangle_dotted_name(&c_symbol);
                let lowered_args: Vec<HirExpr> = args
                    .iter()
                    .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                    .collect();
                let ret_ty = self
                    .expr_types
                    .get(&key)
                    .cloned()
                    .and_then(|ty| ResolvedTy::from_ty(&ty).ok())
                    .unwrap_or(ResolvedTy::Unit);
                // W4.047 P1.2: prove the typed handoff agrees at this fail-open
                // module-qualified-rewrite return site (no behaviour change).
                self.assert_resolved_ty_totality(&span);
                let resolved_ref = self
                    .fn_registry
                    .get(&symbol)
                    .map_or(ResolvedRef::Unresolved, |entry| ResolvedRef::Item(entry.id));
                let callee_ty = ResolvedTy::Function {
                    params: Vec::new(),
                    ret: Box::new(ret_ty.clone()),
                };
                let callee = HirExpr {
                    node: self.ids.node(),
                    site: self.ids.site(),
                    value_class: ValueClass::PersistentShare,
                    ty: callee_ty,
                    intent: IntentKind::Read,
                    kind: HirExprKind::BindingRef {
                        name: symbol,
                        resolved: resolved_ref,
                    },
                    span: span.clone(),
                };
                (
                    HirExprKind::Call {
                        callee: Box::new(callee),
                        args: lowered_args,
                    },
                    ret_ty,
                )
            }
            Some(MethodCallRewrite::DeferToLowering) => {
                // `DeferToLowering` targets the C++/MLIR pipeline and is not
                // consumed by the Rust MIR pipeline.  Fail-closed.
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::NotYetImplemented {
                        construct: format!("method-call rewrite variant for `.{method}`"),
                        owning_pass: "mir-pipeline".to_string(),
                    },
                    span,
                    "this method-call rewrite variant is not supported in the Rust MIR pipeline",
                ));
                (
                    HirExprKind::Unsupported(format!(
                        "unsupported rewrite variant for method `{method}`"
                    )),
                    ResolvedTy::Unit,
                )
            }
            Some(MethodCallRewrite::CancellationTokenIsCancelled) => {
                let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
                (
                    HirExprKind::CancellationTokenIsCancelled {
                        receiver: Box::new(lowered_receiver),
                    },
                    ResolvedTy::Bool,
                )
            }
            Some(MethodCallRewrite::GeneratorNext { yield_ty }) => {
                // The result is `Option<yield_ty>`; register its layout so MIR /
                // codegen can size the enum slot the unbox writes into.
                self.register_option_layout(&yield_ty, &span, "Generator::next");
                let option_ty = Self::resolved_option_ty(yield_ty.clone());
                // The receiver is borrowed (Read): `hew_gen_next` resumes the
                // generator but does not consume the handle — it stays live for
                // subsequent `.next()` calls and is freed by `hew_gen_free` on
                // its own scope-exit drop.
                let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
                (
                    HirExprKind::GeneratorNext {
                        receiver: Box::new(lowered_receiver),
                        yield_ty,
                    },
                    option_ty,
                )
            }
            Some(MethodCallRewrite::StaticTraitDispatch {
                receiver_type_param,
                bound_trait,
                declaring_trait,
                method_name,
                requires_mutable_receiver,
            }) => {
                let ret_ty = self
                    .expr_types
                    .get(&key)
                    .cloned()
                    .and_then(|ty| ResolvedTy::from_ty(&ty).ok())
                    .unwrap_or(ResolvedTy::Unit);
                // W4.047 P1.2: prove the typed handoff agrees at this fail-open
                // static-trait-dispatch return site (no behaviour change).
                self.assert_resolved_ty_totality(&span);

                // Trait default method body — concrete Self interception.
                //
                // When a trait default method body is lowered as a concrete
                // impl method (e.g. `Person::greet` instantiated from the
                // `Greeter::greet` default), the checker recorded
                // `StaticTraitDispatch { receiver_type_param: "Self" }` for
                // every `self.sibling_method()` call inside that body.  MIR
                // then tries to resolve "Self" through its monomorphization
                // substitution map — but there is no substitution for a
                // concrete function, causing `UnresolvedStaticDispatchSubstitution`.
                //
                // When `current_impl_self_ty` is set (we are inside
                // `lower_impl_block`) and `receiver_type_param == "Self"`,
                // the receiver is concretely known.  Derive the qualified
                // symbol `<ConcreteType>::<method>` and emit a direct `Call`
                // — the same shape a non-default trait-impl method would emit.
                // This bypasses `CallTraitMethodStatic` entirely for the
                // default-body context and lets MIR treat it as an ordinary
                // concrete call.
                if receiver_type_param == "Self" {
                    if let Some(self_ty) = self.current_impl_self_ty.clone() {
                        if let Some((self_type_name, _type_args)) =
                            crate::dispatch::receiver_self_type_for_impl_lookup(&self_ty)
                        {
                            let c_symbol = crate::node::HirImplBlock::method_symbol(
                                &self_type_name,
                                &method_name,
                            );
                            self.try_register_enum_instantiation(&span);
                            self.record_var_self_direct_monomorphisation(
                                &c_symbol,
                                // receiver type will be the concrete self type
                                &self_ty, &span, site,
                            );
                            let receiver_intent = if requires_mutable_receiver {
                                IntentKind::Consume
                            } else {
                                IntentKind::Read
                            };
                            let lowered_receiver = self.lower_expr(receiver, receiver_intent);
                            let mut lowered_args = vec![lowered_receiver];
                            for arg in args {
                                lowered_args.push(self.lower_expr(arg.expr(), IntentKind::Read));
                            }
                            let callee_ty = ResolvedTy::Function {
                                params: Vec::new(),
                                ret: Box::new(ret_ty.clone()),
                            };
                            let resolved_ref = self
                                .fn_registry
                                .get(&c_symbol)
                                .map_or(ResolvedRef::Unresolved, |entry| {
                                    ResolvedRef::Item(entry.id)
                                });
                            let callee = HirExpr {
                                node: self.ids.node(),
                                site: self.ids.site(),
                                value_class: ValueClass::PersistentShare,
                                ty: callee_ty,
                                intent: IntentKind::Read,
                                kind: HirExprKind::BindingRef {
                                    name: c_symbol,
                                    resolved: resolved_ref,
                                },
                                span: span.clone(),
                            };
                            return (
                                HirExprKind::Call {
                                    callee: Box::new(callee),
                                    args: lowered_args,
                                },
                                ret_ty,
                            );
                        }
                    }
                }

                if requires_mutable_receiver {
                    let lowered_receiver = self.lower_expr(receiver, IntentKind::Consume);
                    let receiver_ty = lowered_receiver.ty.clone();
                    let lowered_args: Vec<HirExpr> = args
                        .iter()
                        .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                        .collect();
                    return (
                        HirExprKind::VarSelfMethodCall {
                            receiver: Box::new(lowered_receiver),
                            target: HirVarSelfMethodTarget::StaticTrait {
                                receiver_type_param,
                                bound_trait,
                                declaring_trait,
                                method_name,
                            },
                            args: lowered_args,
                            ret_ty: ret_ty.clone(),
                            receiver_ty,
                        },
                        ret_ty,
                    );
                }
                // Static trait dispatch: emit `CallTraitMethodStatic` carrying
                // the structured metadata. MIR resolves the concrete callee from
                // the monomorphization substitution map.
                let lowered_receiver = self.lower_expr(receiver, IntentKind::Read);
                let lowered_args: Vec<HirExpr> = args
                    .iter()
                    .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                    .collect();
                (
                    HirExprKind::CallTraitMethodStatic {
                        receiver: Box::new(lowered_receiver),
                        receiver_type_param,
                        bound_trait,
                        declaring_trait,
                        method_name,
                        args: lowered_args,
                        ret_ty: ret_ty.clone(),
                    },
                    ret_ty,
                )
            }
            None => {
                if let Expr::Identifier(module_name) = &receiver.0 {
                    if let Some(module) = self.missing_stdlib_module_import(module_name) {
                        let lowered_args: Vec<HirExpr> = args
                            .iter()
                            .map(|arg| self.lower_expr(arg.expr(), IntentKind::Read))
                            .collect();
                        let name = format!("{module_name}.{method}");
                        self.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::ImportMissing {
                                module: module.to_string(),
                                name: name.clone(),
                            },
                            span.clone(),
                            stdlib_catalog::missing_import_hint(module),
                        ));
                        return (
                            HirExprKind::Call {
                                callee: Box::new(self.unresolved_module_object(&name, span)),
                                args: lowered_args,
                            },
                            ResolvedTy::Unit,
                        );
                    }
                }
                // No rewrite entry — fail closed.  Do not re-infer from the receiver type.
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::MethodCallNoRewrite {
                        method: method.to_string(),
                    },
                    span,
                    "no checker-produced rewrite entry for this method call; \
                     typecheck must record a rewrite before HIR lowering",
                ));
                (
                    HirExprKind::Unsupported(format!(
                        "method call `.{method}` has no rewrite entry"
                    )),
                    ResolvedTy::Unit,
                )
            }
        }
    }

    fn pattern_name(&mut self, pattern: &Spanned<Pattern>) -> Option<String> {
        if let Pattern::Identifier(name) = &pattern.0 {
            Some(name.clone())
        } else {
            self.unsupported(pattern.1.clone(), "pattern", "slice-2");
            None
        }
    }

    fn bind(
        &mut self,
        name: String,
        ty: ResolvedTy,
        mutable: bool,
        span: std::ops::Range<usize>,
    ) -> HirBinding {
        let id = self.ids.binding();
        if let Some(scope) = self.scopes.last_mut() {
            scope.insert(name.clone(), (id, ty.clone(), span.clone()));
        }
        HirBinding {
            id,
            name,
            ty,
            mutable,
            span,
        }
    }

    /// Register a pre-allocated `BindingId` in the current scope under `name`.
    ///
    /// Used when the caller needs the `BindingId` before the scope is pushed
    /// (e.g. `HirMatchArmPredicate::Binding` where the id is embedded in the
    /// predicate and must be available before the guard expression is lowered).
    fn bind_existing(
        &mut self,
        id: BindingId,
        name: String,
        ty: ResolvedTy,
        _mutable: bool,
        span: std::ops::Range<usize>,
    ) {
        if let Some(scope) = self.scopes.last_mut() {
            scope.insert(name, (id, ty, span));
        }
    }

    fn lookup(&self, name: &str) -> Option<(BindingId, ResolvedTy)> {
        self.scopes
            .iter()
            .rev()
            .find_map(|scope| scope.get(name).map(|(id, ty, _)| (*id, ty.clone())))
    }

    /// Look up an enum variant constructor by surface name (bare or
    /// qualified). Returns `(type_name, variant_idx, &HirVariantKind)` when
    /// `name` resolves to a registered enum variant. `None` for unknown
    /// names, machine-state names (whose layout lives in machine descriptors
    /// rather than `enum_variants_by_name`), and registry hits that point at
    /// an enum which somehow has no recorded variant at that index (should
    /// never happen — same-source ordering invariant).
    fn lookup_variant_ctor(&self, name: &str) -> Option<(String, usize, &HirVariantKind)> {
        let (type_name, idx) = self.machine_ctor_registry.get(name)?;
        let variants = self.enum_variants_by_name.get(type_name)?;
        let variant = variants.get(*idx)?;
        Some((type_name.clone(), *idx, &variant.kind))
    }

    fn resolved_option_inner(ty: &ResolvedTy) -> Option<&ResolvedTy> {
        match ty {
            ResolvedTy::Named {
                name,
                args,
                builtin,
                ..
            } if args.len() == 1
                && (name == "Option" || *builtin == Some(hew_types::BuiltinType::Option)) =>
            {
                Some(&args[0])
            }
            _ => None,
        }
    }

    fn resolved_result_parts(ty: &ResolvedTy) -> Option<(&ResolvedTy, &ResolvedTy)> {
        match ty {
            ResolvedTy::Named {
                name,
                args,
                builtin,
                ..
            } if args.len() == 2
                && (name == "Result" || *builtin == Some(hew_types::BuiltinType::Result)) =>
            {
                Some((&args[0], &args[1]))
            }
            _ => None,
        }
    }

    fn checker_expr_resolved_ty(
        &mut self,
        span: &std::ops::Range<usize>,
        name: &str,
    ) -> Option<ResolvedTy> {
        let checker_key = SpanKey::from(span);
        let checker_ty = self.expr_types.get(&checker_key).cloned()?;
        match ResolvedTy::from_ty(&checker_ty) {
            Ok(resolved) => Some(resolved),
            Err(err) => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::CheckerBoundaryViolation {
                        name: name.to_string(),
                        reason: err.to_string(),
                    },
                    span.clone(),
                    "checker-authoritative expression type failed boundary conversion",
                ));
                None
            }
        }
    }

    fn builtin_variant_predicate(
        &mut self,
        type_name: &str,
        variant_name: &str,
        span: &std::ops::Range<usize>,
    ) -> Option<(HirMatchArmPredicate, usize)> {
        let qualified = format!("{type_name}::{variant_name}");
        let Some((registered_type, variant_idx)) =
            self.machine_ctor_registry.get(&qualified).cloned()
        else {
            self.unsupported(
                span.clone(),
                format!("`?` builtin variant `{qualified}` missing from ctor registry"),
                "question-operator",
            );
            return None;
        };
        if registered_type != type_name {
            self.unsupported(
                span.clone(),
                format!(
                    "`?` builtin variant `{qualified}` resolved to unexpected type `{registered_type}`"
                ),
                "question-operator",
            );
            return None;
        }
        let Ok(variant_idx_u32) = u32::try_from(variant_idx) else {
            self.unsupported(
                span.clone(),
                format!("`?` builtin variant `{qualified}` index exceeds u32::MAX"),
                "question-operator",
            );
            return None;
        };
        Some((
            HirMatchArmPredicate::EnumVariant {
                variant_match: hew_types::VariantMatch {
                    type_name: type_name.to_string(),
                    variant_name: variant_name.to_string(),
                },
                variant_idx: variant_idx_u32,
            },
            variant_idx,
        ))
    }

    fn synthetic_binding_ref(
        &mut self,
        name: &str,
        binding: BindingId,
        ty: ResolvedTy,
        span: &std::ops::Range<usize>,
    ) -> HirExpr {
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::of_ty(&ty, &self.type_classes),
            ty,
            intent: IntentKind::Read,
            kind: HirExprKind::BindingRef {
                name: name.to_string(),
                resolved: ResolvedRef::Binding(binding),
            },
            span: span.clone(),
        }
    }

    fn synthetic_variant_ctor(
        &mut self,
        machine_name: &str,
        state_idx: usize,
        payload: Option<Vec<(String, HirExpr)>>,
        ty: ResolvedTy,
        span: &std::ops::Range<usize>,
    ) -> HirExpr {
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::of_ty(&ty, &self.type_classes),
            ty,
            intent: IntentKind::Consume,
            kind: HirExprKind::MachineVariantCtor {
                machine_name: machine_name.to_string(),
                state_idx,
                payload,
            },
            span: span.clone(),
        }
    }

    fn synthetic_return_block_expr(
        &mut self,
        value: HirExpr,
        span: &std::ops::Range<usize>,
    ) -> HirExpr {
        let return_stmt = HirStmt {
            node: self.ids.node(),
            kind: HirStmtKind::Return(Some(value)),
            span: span.clone(),
        };
        let block = HirBlock {
            node: self.ids.node(),
            scope: self.ids.scope(),
            statements: vec![return_stmt],
            tail: None,
            ty: ResolvedTy::Unit,
            span: span.clone(),
        };
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            value_class: ValueClass::BitCopy,
            ty: ResolvedTy::Unit,
            intent: IntentKind::Read,
            kind: HirExprKind::Block(block),
            span: span.clone(),
        }
    }

    fn unsupported_postfix_try(
        &mut self,
        span: &std::ops::Range<usize>,
        construct: impl Into<String>,
    ) -> (HirExprKind, ResolvedTy) {
        self.unsupported(span.clone(), construct, "question-operator");
        (
            HirExprKind::Unsupported("unsupported `?` expression".into()),
            ResolvedTy::Unit,
        )
    }

    fn lower_postfix_try(
        &mut self,
        inner: &Spanned<Expr>,
        span: &std::ops::Range<usize>,
    ) -> (HirExprKind, ResolvedTy) {
        let scrutinee = self.lower_expr(inner, IntentKind::Read);
        let scrutinee_ty = scrutinee.ty.clone();
        self.try_register_enum_instantiation_ty(&scrutinee_ty, &inner.1);

        let Some(return_ty) = self.current_return_type.clone() else {
            return self.unsupported_postfix_try(
                span,
                "`?` without an enclosing Result/Option return type",
            );
        };

        if let Some((ok_ty, err_ty)) = Self::resolved_result_parts(&scrutinee_ty) {
            if Self::resolved_result_parts(&return_ty).is_none() {
                return self.unsupported_postfix_try(
                    span,
                    "`?` in a body whose return type is not Result",
                );
            }
            self.try_register_enum_instantiation_ty(&return_ty, span);
            let result_ty = self
                .checker_expr_resolved_ty(span, "`?` expression")
                .unwrap_or_else(|| ok_ty.clone());
            self.lower_result_postfix_try(scrutinee, result_ty, err_ty.clone(), return_ty, span)
        } else if let Some(some_ty) = Self::resolved_option_inner(&scrutinee_ty) {
            if Self::resolved_option_inner(&return_ty).is_none() {
                return self.unsupported_postfix_try(
                    span,
                    "`?` in a body whose return type is not Option",
                );
            }
            self.try_register_enum_instantiation_ty(&return_ty, span);
            let result_ty = self
                .checker_expr_resolved_ty(span, "`?` expression")
                .unwrap_or_else(|| some_ty.clone());
            self.lower_option_postfix_try(scrutinee, result_ty, return_ty, span)
        } else {
            self.unsupported_postfix_try(span, "`?` scrutinee that is not Result or Option")
        }
    }

    fn lower_result_postfix_try(
        &mut self,
        scrutinee: HirExpr,
        ok_ty: ResolvedTy,
        err_ty: ResolvedTy,
        return_ty: ResolvedTy,
        span: &std::ops::Range<usize>,
    ) -> (HirExprKind, ResolvedTy) {
        let Some((ok_predicate, _)) = self.builtin_variant_predicate("Result", "Ok", span) else {
            return self.unsupported_postfix_try(span, "`?` Result::Ok predicate");
        };
        let Some((err_predicate, err_idx)) = self.builtin_variant_predicate("Result", "Err", span)
        else {
            return self.unsupported_postfix_try(span, "`?` Result::Err predicate");
        };

        let ok_binding = self.ids.binding();
        let err_binding = self.ids.binding();
        let ok_name = "__try_ok";
        let err_name = "__try_err";

        let ok_body = self.synthetic_binding_ref(ok_name, ok_binding, ok_ty.clone(), span);
        let err_payload = self.synthetic_binding_ref(err_name, err_binding, err_ty.clone(), span);
        let err_ctor = self.synthetic_variant_ctor(
            "Result",
            err_idx,
            Some(vec![("0".to_string(), err_payload)]),
            return_ty,
            span,
        );
        let err_body = self.synthetic_return_block_expr(err_ctor, span);

        let arms = vec![
            HirMatchArm {
                predicate: ok_predicate,
                bindings: vec![HirMatchArmBinding {
                    binding: ok_binding,
                    field_idx: 0,
                    name: ok_name.to_string(),
                    ty: ok_ty.clone(),
                }],
                payload_predicates: Vec::new(),
                guard: None,
                body: ok_body,
                span: span.clone(),
            },
            HirMatchArm {
                predicate: err_predicate,
                bindings: vec![HirMatchArmBinding {
                    binding: err_binding,
                    field_idx: 0,
                    name: err_name.to_string(),
                    ty: err_ty,
                }],
                payload_predicates: Vec::new(),
                guard: None,
                body: err_body,
                span: span.clone(),
            },
        ];

        (
            HirExprKind::Match {
                scrutinee: Box::new(scrutinee),
                arms,
            },
            ok_ty,
        )
    }

    fn lower_option_postfix_try(
        &mut self,
        scrutinee: HirExpr,
        some_ty: ResolvedTy,
        return_ty: ResolvedTy,
        span: &std::ops::Range<usize>,
    ) -> (HirExprKind, ResolvedTy) {
        let Some((some_predicate, _)) = self.builtin_variant_predicate("Option", "Some", span)
        else {
            return self.unsupported_postfix_try(span, "`?` Option::Some predicate");
        };
        let Some((none_predicate, none_idx)) =
            self.builtin_variant_predicate("Option", "None", span)
        else {
            return self.unsupported_postfix_try(span, "`?` Option::None predicate");
        };

        let some_binding = self.ids.binding();
        let some_name = "__try_some";
        let some_body = self.synthetic_binding_ref(some_name, some_binding, some_ty.clone(), span);
        let none_ctor = self.synthetic_variant_ctor("Option", none_idx, None, return_ty, span);
        let none_body = self.synthetic_return_block_expr(none_ctor, span);

        let arms = vec![
            HirMatchArm {
                predicate: some_predicate,
                bindings: vec![HirMatchArmBinding {
                    binding: some_binding,
                    field_idx: 0,
                    name: some_name.to_string(),
                    ty: some_ty.clone(),
                }],
                payload_predicates: Vec::new(),
                guard: None,
                body: some_body,
                span: span.clone(),
            },
            HirMatchArm {
                predicate: none_predicate,
                bindings: Vec::new(),
                payload_predicates: Vec::new(),
                guard: None,
                body: none_body,
                span: span.clone(),
            },
        ];

        (
            HirExprKind::Match {
                scrutinee: Box::new(scrutinee),
                arms,
            },
            some_ty,
        )
    }

    /// Register one concrete instantiation of a generic enum in the
    /// `enum_layout_registry`.
    ///
    /// Called from every lowering site that establishes a concrete enum type:
    /// tuple-variant ctor calls (`Option::Some(42)`) and match scrutinee
    /// lowering. The span is the source span of the expression whose checker-
    /// produced type carries the full `Named { name, args }` type.
    ///
    /// The method is a no-op when:
    /// - The span has no `expr_types` entry (checker never assigned a type).
    /// - The type is not `Named` — not an enum instantiation.
    /// - The enum has no type params (monomorphic enum — skip).
    /// - The registry already contains this `(origin, type_args)` key.
    /// - The cap is exceeded (emits `EnumLayoutCapExceeded` diagnostic
    ///   once per module lowering).
    ///
    /// Transitive expansion: after registering a key, this method recurses
    /// into each type arg that is itself a generic enum, running to a fixed
    /// point bounded by the registry cap.
    fn try_register_enum_instantiation(&mut self, span: &std::ops::Range<usize>) {
        // Collect concrete Named types reachable from the expression type at
        // this span. Uses a worklist to avoid recursion depth issues.
        let Some(checker_ty) = self.expr_types.get(&SpanKey::from(span)).cloned() else {
            return;
        };
        let Ok(resolved) = ResolvedTy::from_ty(&checker_ty) else {
            return;
        };
        self.try_register_enum_instantiation_ty(&resolved, span);
    }

    fn try_register_enum_instantiation_ty(
        &mut self,
        resolved: &ResolvedTy,
        span: &std::ops::Range<usize>,
    ) {
        // Flatten `resolved` into all Named types that could be generic-enum
        // instantiations, including nested ones inside the type args.
        let mut worklist: Vec<ResolvedTy> = vec![resolved.clone()];
        while let Some(ty) = worklist.pop() {
            let ResolvedTy::Named {
                ref name, ref args, ..
            } = ty
            else {
                continue;
            };
            // Only act if this enum has type params and this call provides args.
            let Some(type_params) = self.enum_type_params.get(name).cloned() else {
                continue;
            };
            if type_params.is_empty() || args.is_empty() {
                // Enqueue nested Named types even if this one is monomorphic,
                // in case a type arg contains a generic enum.
                for arg in args {
                    worklist.push(arg.clone());
                }
                continue;
            }
            // Enqueue type args for transitive expansion.
            for arg in args {
                worklist.push(arg.clone());
            }
            if args
                .iter()
                .any(|arg| self.contains_abstract_type_param(arg))
            {
                continue;
            }
            // Retrieve the origin ItemId for this enum.
            let Some(&origin) = self.enum_item_ids.get(name) else {
                continue;
            };
            let key = EnumMonoKey {
                origin,
                origin_name: name.clone(),
                type_args: args.clone(),
            };
            // Build the substituted variant list from the unsubstituted HIR
            // variant descriptors stored in `enum_variants_by_name`.
            let Some(variants_proto) = self.enum_variants_by_name.get(name).cloned() else {
                continue;
            };
            let variant_layouts: Vec<EnumVariantLayout> = variants_proto
                .iter()
                .map(|v| {
                    let raw_field_tys = v.field_tys();
                    let subst_field_tys = raw_field_tys
                        .iter()
                        .map(|ft| substitute_type_params(ft, &type_params, args))
                        .collect();
                    EnumVariantLayout {
                        name: v.name.clone(),
                        field_tys: subst_field_tys,
                    }
                })
                .collect();
            let insert_result = self.enum_layout_registry.insert(key, variant_layouts);
            if insert_result.is_err() {
                // Cap exceeded — emit diagnostic and abort further expansion.
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::EnumLayoutCapExceeded {
                        cap: self.enum_layout_registry.cap(),
                    },
                    span.clone(),
                    "enum monomorphisation cap exceeded; increase `mono_cap` or reduce generic enum instantiation count",
                ));
                return;
            }
        }
    }

    /// Build the `HirExprKind::MachineVariantCtor` node for a tuple-variant
    /// constructor call. Synthetic field names "0", "1", ... are used —
    /// MIR/codegen discard names and index payload slots by position (lane
    /// plan D1).
    fn lower_variant_ctor_tuple_call(
        &mut self,
        name: &str,
        args: Vec<HirExpr>,
        span: &std::ops::Range<usize>,
    ) -> (HirExprKind, ResolvedTy) {
        let Some((type_name, variant_idx, variant_kind)) = self.lookup_variant_ctor(name) else {
            unreachable!("lower_variant_ctor_tuple_call called without registry hit");
        };
        let HirVariantKind::Tuple(field_tys) = variant_kind else {
            unreachable!("lower_variant_ctor_tuple_call called with non-tuple variant");
        };
        let field_count = field_tys.len();
        let type_name_owned = type_name;
        let variant_idx_owned = variant_idx;
        if args.len() != field_count {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::NotYetImplemented {
                    construct: format!(
                        "variant ctor `{name}` arity mismatch: expected {field_count}, got {}",
                        args.len()
                    ),
                    owning_pass: "variant ctor arity".to_string(),
                },
                span.clone(),
                "tuple-variant constructor called with the wrong number of arguments",
            ));
        }
        let payload: Vec<(String, HirExpr)> = args
            .into_iter()
            .enumerate()
            .map(|(idx, expr)| (idx.to_string(), expr))
            .collect();
        // Register the generic-enum instantiation before building result_ty so
        // the registry is populated when codegen performs its mangled lookup.
        self.try_register_enum_instantiation(span);
        // Checker-authoritative result type: the checker records the full
        // `Named { name: "Option", args: [I64] }` at this call-expression span.
        // Using it directly preserves type args so codegen can compute the
        // mangled registry key (e.g. `"Option$$i64"`).  Fall back to bare-name
        // with a diagnostic if expr_types has no entry — absence is a real
        // signal (checker should always populate this site).
        let checker_key = SpanKey::from(span);
        let result_ty = if let Some(ty) = self.expr_types.get(&checker_key).cloned() {
            match ResolvedTy::from_ty(&ty) {
                Ok(resolved) => resolved,
                Err(err) => {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::CheckerBoundaryViolation {
                            name: type_name_owned.clone(),
                            reason: err.to_string(),
                        },
                        span.clone(),
                        "checker-authoritative variant-ctor result type failed boundary conversion",
                    ));
                    ResolvedTy::Named {
                        name: type_name_owned.clone(),
                        args: Vec::new(),
                        builtin: None,
                        is_opaque: false,
                    }
                }
            }
        } else {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::CheckerBoundaryViolation {
                    name: type_name_owned.clone(),
                    reason: "expr_types has no entry for variant-ctor site".into(),
                },
                span.clone(),
                "checker did not record a result type for this variant constructor call",
            ));
            ResolvedTy::Named {
                name: type_name_owned.clone(),
                args: Vec::new(),
                builtin: None,
                is_opaque: false,
            }
        };
        (
            HirExprKind::MachineVariantCtor {
                machine_name: type_name_owned,
                state_idx: variant_idx_owned,
                payload: Some(payload),
            },
            result_ty,
        )
    }

    /// Emit a structured diagnostic when a variant constructor is called in
    /// the wrong shape (unit variant invoked positionally, or struct variant
    /// invoked positionally). Caller falls through to the regular-call path
    /// to preserve checker-stream coverage.
    fn report_variant_ctor_call_shape_mismatch(
        &mut self,
        name: &str,
        kind: &HirVariantKind,
        span: &std::ops::Range<usize>,
    ) {
        match kind {
            HirVariantKind::Unit => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::NotYetImplemented {
                        construct: format!("unit variant `{name}` called as a function"),
                        owning_pass: "variant ctor arity".to_string(),
                    },
                    span.clone(),
                    "unit-variant constructors are referenced as identifiers, not called",
                ));
            }
            HirVariantKind::Struct(_) => {
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::NotYetImplemented {
                        construct: format!("struct variant `{name}` called positionally"),
                        owning_pass: "variant ctor arity".to_string(),
                    },
                    span.clone(),
                    "struct-variant constructors require named-field syntax (e.g. `Shape::Box { w: ..., h: ... }`)",
                ));
            }
            HirVariantKind::Tuple(_) => {
                // Tuple shape is the happy path handled by
                // `lower_variant_ctor_tuple_call`; this arm is unreachable in
                // production but kept exhaustive for the match.
            }
        }
    }

    /// Resolve an identifier to a machine state constructor if `name` is a
    /// declared state of the currently-enclosing machine.
    ///
    /// Returns `Some((machine_name, state_idx))` when both conditions hold:
    /// - `current_machine_name` / `current_machine_states` are set (inside a
    ///   machine lowering), AND
    /// - `name` matches one of the state names in declaration order.
    ///
    /// Returns `None` otherwise; the caller falls through to `lower_identifier`.
    fn resolve_machine_state_name(&self, name: &str) -> Option<(String, usize)> {
        let machine_name = self.current_machine_name.as_ref()?;
        let states = self.current_machine_states.as_ref()?;
        let idx = states.iter().position(|(n, _)| n == name)?;
        Some((machine_name.clone(), idx))
    }

    /// Attempt to lower a `self.<field>` access inside a machine transition body.
    ///
    /// Called when the `Expr::FieldAccess` arm detects `object == Expr::This`.
    ///
    /// Returns `Some(HirExpr)` on both the happy path (resolved to
    /// `HirExprKind::MachineFieldAccess`) and the error paths (diagnostic pushed,
    /// `HirExprKind::Unsupported` returned wrapped in `Some`). Returns `None` only
    /// when `self` is outside a machine body entirely, signalling the caller to
    /// fall through to the generic `Expr::This` handler (which will emit
    /// `NotYetImplemented`).
    fn try_lower_machine_self_field_access(
        &mut self,
        field: &str,
        span: &std::ops::Range<usize>,
        site: SiteId,
        intent: IntentKind,
    ) -> Option<HirExpr> {
        let machine_name = self.current_machine_name.as_ref()?.clone();

        // We are in a machine body.  Now check whether the source state is known.
        let Some(src_state_idx) = self.current_machine_source_state else {
            // Wildcard (`_`) transition body — no concrete source state.
            // `self.field` access has no unique variant to read from.
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::NotYetImplemented {
                    construct: format!("`self.{field}` inside a wildcard (`_`) transition body"),
                    owning_pass: "machine typed self-field access in wildcard transitions"
                        .to_string(),
                },
                span.clone(),
                "self-field reads inside wildcard transitions have no concrete source \
                 state; refactor to use a named source state or match on the state first",
            ));
            return Some(HirExpr {
                node: self.ids.node(),
                site,
                ty: ResolvedTy::Unit,
                value_class: ValueClass::BitCopy,
                intent,
                kind: HirExprKind::Unsupported(format!(
                    "self.{field} in wildcard transition (no source state)"
                )),
                span: span.clone(),
            });
        };

        // Look up the field by name in the source state's payload.
        let states = self.current_machine_states.as_ref()?;
        let state_fields = &states[src_state_idx].1;
        let state_name = states[src_state_idx].0.clone();
        if let Some((field_idx, hir_field)) = state_fields
            .iter()
            .enumerate()
            .find(|(_, f)| f.name == field)
        {
            let field_ty = hir_field.ty.clone();
            let vc = ValueClass::of_ty(&field_ty, &self.type_classes);
            Some(HirExpr {
                node: self.ids.node(),
                site,
                ty: field_ty,
                value_class: vc,
                intent,
                kind: HirExprKind::MachineFieldAccess {
                    machine_name,
                    state_idx: src_state_idx,
                    field_idx,
                    field_name: field.to_string(),
                },
                span: span.clone(),
            })
        } else {
            // Field name not declared on this state.
            let available: Vec<String> = state_fields.iter().map(|f| f.name.clone()).collect();
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::NotYetImplemented {
                    construct: format!(
                        "`self.{field}` — field not declared on state `{state_name}` \
                         of machine `{machine_name}`"
                    ),
                    owning_pass: "machine state payload field validation".to_string(),
                },
                span.clone(),
                format!(
                    "state `{state_name}` has fields: [{}]; `{field}` is not one of them",
                    available.join(", ")
                ),
            ));
            Some(HirExpr {
                node: self.ids.node(),
                site,
                ty: ResolvedTy::Unit,
                value_class: ValueClass::BitCopy,
                intent,
                kind: HirExprKind::Unsupported(format!(
                    "self.{field} not found on state {state_name}"
                )),
                span: span.clone(),
            })
        }
    }

    fn try_lower_machine_event_field_access(
        &mut self,
        field: &str,
        span: &std::ops::Range<usize>,
        site: SiteId,
        intent: IntentKind,
    ) -> Option<HirExpr> {
        let machine_name = self.current_machine_name.as_ref()?.clone();
        let (event_idx, event_fields) = self.current_machine_transition_event.clone()?;
        if let Some((field_idx, hir_field)) = event_fields
            .iter()
            .enumerate()
            .find(|(_, f)| f.name == field)
        {
            let field_ty = hir_field.ty.clone();
            let vc = ValueClass::of_ty(&field_ty, &self.type_classes);
            return Some(HirExpr {
                node: self.ids.node(),
                site,
                ty: field_ty,
                value_class: vc,
                intent,
                kind: HirExprKind::MachineEventFieldAccess {
                    machine_name,
                    event_idx,
                    field_idx,
                    field_name: field.to_string(),
                },
                span: span.clone(),
            });
        }

        self.diagnostics.push(HirDiagnostic::new(
            HirDiagnosticKind::NotYetImplemented {
                construct: format!("`event.{field}` — field not declared on current event"),
                owning_pass: "machine event payload field validation".to_string(),
            },
            span.clone(),
            "event payload field is not declared on this transition's event",
        ));
        Some(HirExpr {
            node: self.ids.node(),
            site,
            ty: ResolvedTy::Unit,
            value_class: ValueClass::BitCopy,
            intent,
            kind: HirExprKind::Unsupported(format!("event.{field} not found")),
            span: span.clone(),
        })
    }

    fn bind_machine_transition_implicits(&mut self, span: std::ops::Range<usize>) {
        let Some(machine_name) = self.current_machine_name.clone() else {
            return;
        };
        let machine_ty = ResolvedTy::Named {
            name: machine_name.clone(),
            args: Vec::new(),
            builtin: None,
            is_opaque: false,
        };
        let event_ty = ResolvedTy::Named {
            name: format!("{machine_name}Event"),
            args: Vec::new(),
            builtin: None,
            is_opaque: false,
        };
        let _state = self.bind("state".to_string(), machine_ty, false, span.clone());
        let _event = self.bind("event".to_string(), event_ty, false, span);
    }

    fn missing_stdlib_module_import(&self, name: &str) -> Option<&'static str> {
        if self.lookup(name).is_none() && !self.fn_registry.contains_key(name) {
            stdlib_catalog::missing_import_module(name)
        } else {
            None
        }
    }

    fn push_scope(&mut self) {
        self.scopes.push(HashMap::new());
    }

    fn pop_scope(&mut self) {
        self.scopes.pop();
    }

    fn lower_cancellation_clause_block(&mut self, block: &Block) -> HirBlock {
        let saved_scope_depth = self.scope_depth;
        self.scope_depth = 0;
        let lowered = self.lower_block(block, &ResolvedTy::Unit);
        self.scope_depth = saved_scope_depth;
        lowered
    }

    /// Lower the NEW-6b `await <op> | after <duration>` deadline combinator.
    ///
    /// Only `await <actor>.<askmethod>(...) | after <DurationLiteral>` is wired:
    /// it lowers to the same `HirExprKind::ActorAsk` (`Result<R, AskError>`) as a
    /// plain suspending ask, with `deadline_ns` attached so codegen schedules a
    /// fail-closed timeout against the suspend's cancel registration (deadline →
    /// `Err(AskError::Timeout)`). Every other form fails closed at CHECK time with
    /// a precise, deferred diagnostic — never a runtime `NotYetImplemented`, never
    /// a hang, never a fabricated value.
    fn lower_await_deadline(
        &mut self,
        inner: &Spanned<Expr>,
        duration: &Spanned<Expr>,
        span: &Span,
        intent: IntentKind,
    ) -> HirExpr {
        let Some(deadline_ns) = Self::duration_literal_ns(&duration.0) else {
            self.unsupported(
                span.clone(),
                "`await … | after <duration>` with a non-literal duration (deferred to v0.6)",
                "new6b-deadline-wiring",
            );
            return self.unsupported_expr(span.clone(), "non-literal deadline duration");
        };
        if deadline_ns <= 0 {
            self.unsupported(
                span.clone(),
                "`await … | after <duration>` with a non-positive duration (deferred to v0.6)",
                "new6b-deadline-wiring",
            );
            return self.unsupported_expr(span.clone(), "non-positive deadline duration");
        }
        let Expr::Await(await_inner) = &inner.0 else {
            self.unsupported(
                span.clone(),
                "`| after <duration>` on a non-await expression (deferred to v0.6)",
                "new6b-deadline-wiring",
            );
            return self.unsupported_expr(span.clone(), "non-await deadline combinator");
        };
        // The only suspendable await whose timeout `Result` is concretely specced
        // is the local actor ask (`Result<R, AskError>`, `AskError::Timeout`).
        let inner_key = SpanKey::from(&await_inner.1);
        let is_local_ask = matches!(
            self.actor_method_dispatch.get(&inner_key),
            Some(ActorMethodKind::Ask(_, _))
        );
        if is_local_ask {
            let mut ask_expr = self.lower_expr(inner, intent);
            if let HirExprKind::ActorAsk {
                deadline_ns: slot, ..
            } = &mut ask_expr.kind
            {
                *slot = Some(deadline_ns);
                return ask_expr;
            }
            // The await lowered to something other than a local `ActorAsk` (e.g. a
            // remote ask or a blocking-caller path). Out of scope — fail closed.
            self.unsupported(
                span.clone(),
                "`await <…>(...) | after d` is only supported for a local actor ask in a \
                 suspendable context (deferred to v0.6)",
                "new6b-deadline-wiring",
            );
            return self.unsupported_expr(span.clone(), "unsupported actor-ask deadline form");
        }
        // Out-of-scope await sources: task-await, conn.read/accept, channel recv,
        // stream next, suspending closure. Fail closed at CHECK time naming the form.
        self.unsupported(
            span.clone(),
            "`await <…> | after d` deadline is only supported for actor-ask awaits; \
             task-await, read/accept/recv/next, and suspending-closure deadlines are \
             deferred to v0.6",
            "new6b-deadline-wiring",
        );
        self.unsupported_expr(span.clone(), "unsupported await-deadline source")
    }

    /// Extract the nanosecond value of a literal `Duration` deadline. Non-literal
    /// durations (variables, arithmetic) are not constant-foldable here and fail
    /// closed at CHECK time (the codegen deadline is carried as a constant).
    fn duration_literal_ns(expr: &Expr) -> Option<i64> {
        match expr {
            Expr::Literal(Literal::Duration(ns)) => Some(*ns),
            _ => None,
        }
    }

    fn unsupported(
        &mut self,
        span: std::ops::Range<usize>,
        construct: impl Into<String>,
        owning_pass: impl Into<String>,
    ) {
        self.diagnostics.push(HirDiagnostic::new(
            HirDiagnosticKind::NotYetImplemented {
                construct: construct.into(),
                owning_pass: owning_pass.into(),
            },
            span,
            "",
        ));
    }

    fn unsupported_expr(
        &mut self,
        span: std::ops::Range<usize>,
        note: impl Into<String>,
    ) -> HirExpr {
        HirExpr {
            node: self.ids.node(),
            site: self.ids.site(),
            ty: ResolvedTy::Unit,
            value_class: ValueClass::BitCopy,
            intent: IntentKind::Unknown,
            kind: HirExprKind::Unsupported(note.into()),
            span,
        }
    }

    /// Lower a surface `match` expression to `HirExprKind::Match`.
    ///
    /// **Substrate scope (v0.5 match-expression slice)**: this lane lowers
    /// variant constructor arms (unit, tuple-payload, and struct-payload with
    /// plain binding / wildcard subpatterns), wildcard arms (`_`), plain
    /// binding arms (`x => ...`), literal arms (`0`, `"hello"`), or-pattern
    /// arms (`A | B => ...`), and arms with pattern guards (`x if cond => ...`).
    ///
    /// The type checker has already enforced exhaustiveness for enum
    /// scrutinees (`hew-types/src/check/diagnostics.rs::check_exhaustiveness`).
    /// MIR adds a runtime `Terminator::Trap { ExhaustivenessFallthrough }`
    /// as belt-and-braces; this HIR producer assumes the checker pre-gate
    /// holds.
    ///
    /// **Or-patterns**: the type-checker intentionally skips
    /// `record_arm_resolution` for `Pattern::Or` arms. HIR lowering handles
    /// them by flattening each or-tree into its leaf alternatives (each leaf
    /// becomes a separate `HirMatchArm` sharing the same body expression). The
    /// leaf patterns are classified directly rather than via the resolution
    /// side-table.
    ///
    /// **Guards**: a guard expression is lowered and attached to the `HirMatchArm`
    /// via the `guard` field. MIR lowering evaluates the guard after pattern
    /// matching succeeds and falls through to the next arm when the guard is
    /// false.
    ///
    /// Returns `(HirExprKind, ResolvedTy)`. The expression type is the
    /// first-arm body type (all arms must share a type — the type checker
    /// has already verified this; a mismatch would be a checker bug).
    #[allow(
        clippy::too_many_lines,
        reason = "one reject branch per unsupported pattern shape; splitting would scatter the fail-closed audit"
    )]
    fn lower_match_expr(
        &mut self,
        scrutinee: &Spanned<Expr>,
        arms: &[hew_parser::ast::MatchArm],
        span: &std::ops::Range<usize>,
    ) -> (HirExprKind, ResolvedTy) {
        let scrutinee_hir = self.lower_expr(scrutinee, IntentKind::Read);
        // Register a generic-enum instantiation if the scrutinee's type is
        // a parameterised enum. The checker-authoritative type at the scrutinee
        // span carries the full `Named { name, args }` including concrete type
        // args; `try_register_enum_instantiation` is a no-op for monomorphic enums.
        self.try_register_enum_instantiation(&scrutinee.1);

        // Or-pattern expansion: flatten `A | B | C => body` into three
        // synthetic arms sharing the same body and guard before the main loop.
        // The checker's `bind_pattern` already validated the or-pattern; we
        // just need to enumerate the leaf alternatives.
        let expanded_arms: Vec<hew_parser::ast::MatchArm> = arms
            .iter()
            .flat_map(|arm| {
                let leaves = flatten_or_pattern(&arm.pattern);
                if leaves.len() <= 1 {
                    // Not an or-pattern: pass through unchanged.
                    vec![arm.clone()]
                } else {
                    // Expand: one synthetic arm per leaf, all sharing the same
                    // body and guard. We clone the body for each alternative
                    // (HIR lowering of `Expr` is side-effect-free).
                    leaves
                        .into_iter()
                        .map(|leaf| hew_parser::ast::MatchArm {
                            pattern: leaf,
                            guard: arm.guard.clone(),
                            body: arm.body.clone(),
                        })
                        .collect()
                }
            })
            .collect();

        // Track whether any arm has been rejected; if so we still walk the
        // arm bodies (for checker-stream coverage) but produce
        // `HirExprKind::Unsupported` rather than a partial `Match` node.
        // A fail-closed shape keeps MIR lowering simple and prevents a
        // half-built Match from reaching codegen.
        let mut rejected = false;
        let mut hir_arms: Vec<HirMatchArm> = Vec::with_capacity(expanded_arms.len());
        let mut result_ty: Option<ResolvedTy> = None;

        for arm in &expanded_arms {
            let pattern_span = &arm.pattern.1;
            let key = SpanKey::from(pattern_span);

            // Resolve the pattern classification. For arms expanded from
            // or-patterns (or any arm whose resolution is not in the side table),
            // classify the leaf pattern directly from the AST. The checker has
            // already validated the pattern and arm type; HIR lowering only needs
            // the kind to emit the right predicate shape.
            let resolution_opt = self.pattern_resolutions.get(&key).cloned();

            // Classify: use the side-table entry when present, fall back to
            // direct pattern classification for or-pattern-derived leaves.
            let resolution = match resolution_opt {
                Some(r) => r,
                None => {
                    // Or-pattern leaf: classify the leaf pattern directly.
                    // Any other case (checker-rejected arm) is fail-closed below.
                    if let Some(r) =
                        self.classify_or_leaf_pattern(&arm.pattern.0, &scrutinee_hir.ty)
                    {
                        r
                    } else {
                        // Not a classifiable leaf (e.g. checker rejected or
                        // unknown shape). Fail closed.
                        let _ = self.lower_expr(&arm.body, IntentKind::Read);
                        self.unsupported(
                            pattern_span.clone(),
                            "or-pattern leaf / unsupported pattern in match arm",
                            "match-expression-substrate",
                        );
                        rejected = true;
                        continue;
                    }
                }
            };

            let predicate = match resolution.pattern_kind {
                PatternKind::Wildcard => HirMatchArmPredicate::Wildcard,
                PatternKind::Binding => {
                    // Plain lowercase-identifier pattern (`x => ...`).
                    // The scrutinee's full value is bound to `x` in the arm body.
                    let name = if let Pattern::Identifier(n) = &arm.pattern.0 {
                        n.clone()
                    } else {
                        // Checker contract: Binding resolution must come from
                        // an Identifier pattern.
                        let _ = self.lower_expr(&arm.body, IntentKind::Read);
                        self.unsupported(
                            pattern_span.clone(),
                            "binding resolution without an Identifier pattern — checker \
                             contract violation",
                            "match-expression-substrate",
                        );
                        rejected = true;
                        continue;
                    };
                    let ty = scrutinee_hir.ty.clone();
                    // Allocate the BindingId now so it can be registered in
                    // scope before the guard and body are lowered.
                    let binding_id = self.ids.binding();
                    HirMatchArmPredicate::Binding {
                        binding_id,
                        name,
                        ty,
                    }
                }
                PatternKind::VariantCtor => {
                    let Some(vm) = resolution.variant_match.clone() else {
                        let _ = self.lower_expr(&arm.body, IntentKind::Read);
                        self.unsupported(
                            pattern_span.clone(),
                            "variant pattern missing variant-match resolution",
                            "match-expression-substrate",
                        );
                        rejected = true;
                        continue;
                    };
                    // Resolve variant_idx via `machine_ctor_registry`
                    // (qualified key) — the HIR-side registry populated
                    // from `Item::TypeDecl` body order. The index matches
                    // `EnumLayout.variants` ordering so MIR/codegen don't
                    // re-derive it.
                    let qualified = format!("{}::{}", vm.type_name, vm.variant_name);
                    let Some((_, idx_usize)) = self.machine_ctor_registry.get(&qualified).cloned()
                    else {
                        let _ = self.lower_expr(&arm.body, IntentKind::Read);
                        self.unsupported(
                            pattern_span.clone(),
                            "match arm variant not registered in machine/enum ctor registry",
                            "match-expression-substrate",
                        );
                        rejected = true;
                        continue;
                    };
                    let idx = u32::try_from(idx_usize)
                        .expect("variant index exceeds u32::MAX — impossible in Hew");
                    HirMatchArmPredicate::EnumVariant {
                        variant_match: vm,
                        variant_idx: idx,
                    }
                }
                PatternKind::Literal => {
                    let Pattern::Literal(lit) = &arm.pattern.0 else {
                        let _ = self.lower_expr(&arm.body, IntentKind::Read);
                        self.unsupported(
                            pattern_span.clone(),
                            "literal arm resolution did not correspond to an AST literal pattern",
                            "match-expression-substrate",
                        );
                        rejected = true;
                        continue;
                    };
                    let (lit, literal_ty) = literal_to_hir(lit);
                    let ty = match (&lit, &scrutinee_hir.ty) {
                        (HirLiteral::Integer(_), scrutinee_ty)
                            if literal_match_integer_ty(scrutinee_ty) =>
                        {
                            scrutinee_ty.clone()
                        }
                        (HirLiteral::Bool(_), ResolvedTy::Bool) => ResolvedTy::Bool,
                        (HirLiteral::Char(_), ResolvedTy::Char) => ResolvedTy::Char,
                        (HirLiteral::String(_), ResolvedTy::String) => ResolvedTy::String,
                        (HirLiteral::Float(_), _) => {
                            let _ = self.lower_expr(&arm.body, IntentKind::Read);
                            self.unsupported(
                                pattern_span.clone(),
                                "float literal pattern in match arm",
                                "match-literal-stage2",
                            );
                            rejected = true;
                            continue;
                        }
                        (HirLiteral::Duration(_) | HirLiteral::Unit, _) => {
                            let _ = self.lower_expr(&arm.body, IntentKind::Read);
                            self.unsupported(
                                pattern_span.clone(),
                                format!("unsupported literal pattern in match arm ({lit:?})"),
                                "match-literal-stage2",
                            );
                            rejected = true;
                            continue;
                        }
                        _ => {
                            let _ = self.lower_expr(&arm.body, IntentKind::Read);
                            self.unsupported(
                                pattern_span.clone(),
                                format!(
                                    "literal pattern type mismatch in match arm: literal {:?} \
                                     has type {:?}, scrutinee has type {:?}",
                                    lit, literal_ty, scrutinee_hir.ty
                                ),
                                "match-expression-substrate",
                            );
                            rejected = true;
                            continue;
                        }
                    };
                    debug_assert!(literal_match_supported(&lit, &ty));
                    HirMatchArmPredicate::Literal { lit, ty }
                }
                PatternKind::StructPattern => {
                    let ResolvedTy::Named { .. } = &scrutinee_hir.ty else {
                        let _ = self.lower_expr(&arm.body, IntentKind::Read);
                        self.unsupported(
                            pattern_span.clone(),
                            format!(
                                "record project pattern on non-record scrutinee type {:?}",
                                scrutinee_hir.ty
                            ),
                            "match-expression-substrate",
                        );
                        rejected = true;
                        continue;
                    };
                    HirMatchArmPredicate::RecordProject {
                        ty: scrutinee_hir.ty.clone(),
                    }
                }
                PatternKind::TuplePattern => {
                    let ResolvedTy::Tuple(items) = &scrutinee_hir.ty else {
                        let _ = self.lower_expr(&arm.body, IntentKind::Read);
                        self.unsupported(
                            pattern_span.clone(),
                            format!(
                                "tuple project pattern on non-tuple scrutinee type {:?}",
                                scrutinee_hir.ty
                            ),
                            "match-expression-substrate",
                        );
                        rejected = true;
                        continue;
                    };
                    let Ok(arity) = u32::try_from(items.len()) else {
                        let _ = self.lower_expr(&arm.body, IntentKind::Read);
                        self.unsupported(
                            pattern_span.clone(),
                            "tuple project arity exceeds u32::MAX",
                            "match-expression-substrate",
                        );
                        rejected = true;
                        continue;
                    };
                    HirMatchArmPredicate::TupleProject { arity }
                }
                // Regex literal pattern in a string-scrutinee match arm.
                // Allocate (or reuse) the literal-table entry and build the
                // `HirMatchArmPredicate::Regex` predicate.
                PatternKind::Regex { captures } => {
                    // Extract the raw pattern string from the AST pattern node.
                    // The pattern must be `Pattern::Regex { pattern, .. }`; any
                    // other shape is a checker contract violation — fail closed.
                    let raw_pattern = match &arm.pattern.0 {
                        Pattern::Regex { pattern, .. } => pattern.clone(),
                        other => {
                            self.unsupported(
                                pattern_span.clone(),
                                format!(
                                    "regex arm pattern resolved to PatternKind::Regex but AST \
                                     pattern node is {:?} — checker contract violation",
                                    std::mem::discriminant(other)
                                ),
                                "regex-match-arm-substrate",
                            );
                            rejected = true;
                            continue;
                        }
                    };
                    let literal_id = self.alloc_regex_literal(&raw_pattern, &captures);
                    HirMatchArmPredicate::Regex {
                        literal_id,
                        pattern: raw_pattern,
                        captures,
                    }
                }
            };

            let mut binding_specs = Vec::with_capacity(resolution.payload_bindings.len());
            let mut binding_error = false;
            for payload in &resolution.payload_bindings {
                let ty = match ResolvedTy::from_ty(&payload.ty) {
                    Ok(ty) => ty,
                    Err(err) => {
                        self.unsupported(
                            pattern_span.clone(),
                            format!("unresolved payload binding type in match arm ({err:?})"),
                            "match-expression-substrate",
                        );
                        binding_error = true;
                        continue;
                    }
                };
                let Ok(field_idx) = u32::try_from(payload.field_idx) else {
                    self.unsupported(
                        pattern_span.clone(),
                        "payload binding field index exceeds u32::MAX",
                        "match-expression-substrate",
                    );
                    binding_error = true;
                    continue;
                };
                binding_specs.push((field_idx, payload.binding_name.clone(), ty));
            }
            if binding_error {
                let _ = self.lower_expr(&arm.body, IntentKind::Read);
                rejected = true;
                continue;
            }

            let payload_predicates = collect_match_payload_predicates(self, &arm.pattern.0);

            // Open scope for payload bindings + guard + body.
            // Binding patterns also need a scope (the scrutinee is bound there).
            let needs_scope = !binding_specs.is_empty()
                || matches!(predicate, HirMatchArmPredicate::Binding { .. });
            if needs_scope {
                self.push_scope();
            }

            // For Binding-predicate arms, register the binding in the HIR scope
            // so that references to the bound name in the guard and body resolve.
            // The BindingId was allocated during predicate classification above.
            if let HirMatchArmPredicate::Binding {
                binding_id,
                name: binding_name,
                ty: binding_ty,
            } = &predicate
            {
                self.bind_existing(
                    *binding_id,
                    binding_name.clone(),
                    binding_ty.clone(),
                    false,
                    pattern_span.clone(),
                );
            }

            // Materialise payload bindings (constructor payload fields).
            let mut bindings = Vec::with_capacity(binding_specs.len());
            for (field_idx, name, ty) in binding_specs {
                let bound = self.bind(name.clone(), ty.clone(), false, pattern_span.clone());
                bindings.push(HirMatchArmBinding {
                    binding: bound.id,
                    field_idx,
                    name,
                    ty,
                });
            }

            // Lower the guard expression (if any). The guard sees the same
            // bindings that the arm body sees, so it must be lowered after the
            // payload bindings are in scope.
            let guard_hir = arm
                .guard
                .as_ref()
                .map(|guard_spanned| self.lower_expr(guard_spanned, IntentKind::Read));

            let body_hir = self.lower_expr(&arm.body, IntentKind::Read);

            if needs_scope {
                self.pop_scope();
            }

            if result_ty.is_none() {
                result_ty = Some(body_hir.ty.clone());
            }

            hir_arms.push(HirMatchArm {
                predicate,
                bindings,
                payload_predicates,
                guard: guard_hir,
                body: body_hir,
                span: arm.pattern.1.start..arm.body.1.end,
            });
        }

        if rejected {
            return (
                HirExprKind::Unsupported(
                    "match expression contains an unsupported arm shape".into(),
                ),
                ResolvedTy::Unit,
            );
        }

        // Empty arms list is rejected by the parser/checker before reaching
        // here; treat the unexpected case as fail-closed.
        if hir_arms.is_empty() {
            self.unsupported(
                span.clone(),
                "match expression with no arms",
                "match-expression-substrate",
            );
            return (
                HirExprKind::Unsupported("match expression with no arms".into()),
                ResolvedTy::Unit,
            );
        }

        let ty = result_ty.unwrap_or(ResolvedTy::Unit);
        (
            HirExprKind::Match {
                scrutinee: Box::new(scrutinee_hir),
                arms: hir_arms,
            },
            ty,
        )
    }

    /// Classify a single leaf (non-`Or`) pattern for use when expanding
    /// or-patterns at HIR lowering time (the type-checker intentionally omits
    /// `record_arm_resolution` for `Pattern::Or` arms, so the resolution
    /// side-table has no entry for these).
    ///
    /// Returns `None` for patterns that cannot be classified (e.g. nested
    /// struct/tuple patterns that require deeper scrutinee type knowledge);
    /// the caller emits a fail-closed `Unsupported` diagnostic in that case.
    fn classify_or_leaf_pattern(
        &self,
        pattern: &Pattern,
        scrutinee_ty: &ResolvedTy,
    ) -> Option<hew_types::ArmResolution> {
        use hew_types::{ArmResolution, VariantMatch};
        match pattern {
            Pattern::Wildcard => Some(ArmResolution {
                pattern_kind: PatternKind::Wildcard,
                variant_match: None,
                payload_bindings: vec![],
            }),
            Pattern::Literal(_) => Some(ArmResolution {
                pattern_kind: PatternKind::Literal,
                variant_match: None,
                payload_bindings: vec![],
            }),
            Pattern::Identifier(name) => {
                let is_ctor =
                    name.contains("::") || name.chars().next().is_some_and(char::is_uppercase);
                if is_ctor {
                    // Unit variant reference: resolve against the scrutinee type.
                    // Use the same qualified-key lookup used by `lower_match_expr`
                    // for VariantCtor arms.
                    let short_name = name.rsplit("::").next().unwrap_or(name);
                    // Derive type_name from scrutinee type.
                    let type_name = match scrutinee_ty {
                        ResolvedTy::Named { name: n, .. } => n.clone(),
                        _ => return None,
                    };
                    let qualified = format!("{type_name}::{short_name}");
                    // Validate the variant is registered; return None if not.
                    self.machine_ctor_registry
                        .contains_key(&qualified)
                        .then(|| ArmResolution {
                            pattern_kind: PatternKind::VariantCtor,
                            variant_match: Some(VariantMatch {
                                type_name,
                                variant_name: short_name.to_owned(),
                            }),
                            payload_bindings: vec![],
                        })
                } else {
                    Some(ArmResolution {
                        pattern_kind: PatternKind::Binding,
                        variant_match: None,
                        payload_bindings: vec![],
                    })
                }
            }
            // Constructor (tuple-payload) patterns inside an or-pattern are
            // complex and rare in v0.5; fall back to fail-closed.
            Pattern::Constructor { .. }
            | Pattern::Struct { .. }
            | Pattern::Tuple(_)
            | Pattern::Or(_, _)
            | Pattern::Regex { .. } => None,
        }
    }

    /// Lower the body block of a `scope{}` expression. This is separate from
    /// `lower_block` because statements inside a scope body follow different
    /// rules:
    ///
    /// - `Stmt::Expression(Expr::Call{..})` → `SpawnedCall` (TI-1)
    /// - `Stmt::Expression(Expr::ForkChild { binding: Some(name), expr })` →
    ///   `HirStmtKind::Let` with a `Task<T>` typed binding (TI-2)
    /// - `Stmt::Expression(Expr::Await(..))` → `AwaitTask` (TI-4)
    /// - All other statements lower normally, including nested `scope{}` blocks.
    ///
    /// The caller is responsible for setting `scope_depth` before calling this
    /// function and restoring it after.
    #[allow(
        clippy::too_many_lines,
        reason = "single match on scope-body statement variants; splitting would hurt readability"
    )]
    fn lower_scope_block(&mut self, block: &Block) -> HirBlock {
        self.push_scope();
        let scope = self.ids.scope();
        let mut statements = Vec::new();

        for (stmt, span) in &block.stmts {
            let hir_stmt = match stmt {
                // `fork name = call(...)` and bare `fork = call(...)` inside a
                // scope body are the only `Stmt::Expression` shapes this
                // function intercepts. Destructure the `ForkChild` once and
                // branch on `binding` presence: the bound form (TI-2) builds
                // a typed `Task<T>` `Let`; the unbound form delegates to the
                // `lower_spawned_call` helper.
                Stmt::Expression(expr) => match &expr.0 {
                    Expr::ForkChild {
                        binding,
                        expr: child_expr,
                    } => {
                        if !matches!(&child_expr.0, Expr::Call { .. }) {
                            let message: &str = if binding.is_some() {
                                "`fork name = expr` requires a call expression as the \
                                 right-hand side; other expression forms cannot be spawned as tasks"
                            } else {
                                "`fork = expr` requires a call expression"
                            };
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::ForkChildNotACall,
                                child_expr.1.clone(),
                                message,
                            ));
                            self.unsupported(span.clone(), "fork-child-non-call", "slice-2");
                            HirStmt {
                                node: self.ids.node(),
                                kind: HirStmtKind::Expr(
                                    self.unsupported_expr(span.clone(), "fork child non-call"),
                                ),
                                span: span.clone(),
                            }
                        } else if let Some(binding_name) = binding {
                            // FC-P1-A1 Blocker 1+2: Validate fork child spawn shape before lowering
                            if let Expr::Call { function, args, .. } = &child_expr.0 {
                                self.validate_task_spawn_call(function, args, &child_expr.1);
                            }

                            // Lower the call synchronously first to get the return type,
                            // then wrap in SpawnedCall + Task<T>.
                            //
                            // FC-P1-A1 (revision pass 2): Non-unit callee return is
                            // VALID at spawn time. `fork t = compute() -> i64` binds
                            // `t: Task<i64>` cleanly here (canonical TI-2 invariant,
                            // see vertical.rs::task_handle_ti2_*). The
                            // `AwaitTaskResultUnsupported` gate at MIR :7871 fires
                            // when the non-unit result is awaited, not when spawned.
                            let call_hir = self.lower_expr(child_expr, IntentKind::Consume);
                            let call_site = call_hir.site;
                            let explicit_type_args = match &child_expr.0 {
                                Expr::Call {
                                    type_args: Some(type_args),
                                    ..
                                } => Some(type_args.clone()),
                                _ => None,
                            };
                            let call_ret_ty = call_hir.ty.clone();

                            let task_ty = ResolvedTy::Task(Box::new(call_ret_ty));

                            // Destructure call_hir.kind once to extract callee + args.
                            let HirExprKind::Call { callee, args } = call_hir.kind else {
                                unreachable!("just verified Call shape above")
                            };

                            // Re-wrap as a SpawnedCall node with Task<T> type.
                            let spawned_site = self.ids.site();
                            let type_args = self
                                .call_site_type_args
                                .get(&call_site)
                                .cloned()
                                .or_else(|| {
                                    explicit_type_args.map(|args| {
                                        args.iter().map(|arg| self.lower_type(arg)).collect()
                                    })
                                });
                            if let Some(type_args) = type_args {
                                self.call_site_type_args.insert(spawned_site, type_args);
                            }

                            let spawned = HirExpr {
                                node: self.ids.node(),
                                site: spawned_site,
                                value_class: ValueClass::Linear, // Task handles are linear (consume-once).
                                ty: task_ty.clone(),
                                intent: IntentKind::Consume,
                                kind: HirExprKind::SpawnedCall {
                                    callee,
                                    args,
                                    task_ty: task_ty.clone(),
                                },
                                span: child_expr.1.clone(),
                            };

                            // Bind the name with Task<T> type in the current scope.
                            let binding =
                                self.bind(binding_name.clone(), task_ty, false, span.clone());
                            HirStmt {
                                node: self.ids.node(),
                                kind: HirStmtKind::Let(binding, Some(spawned)),
                                span: span.clone(),
                            }
                        } else {
                            // Unbound `fork = call(...)`: lower as a plain SpawnedCall;
                            // the result is not bound.
                            let spawned = self.lower_spawned_call(child_expr);
                            HirStmt {
                                node: self.ids.node(),
                                kind: HirStmtKind::Expr(spawned),
                                span: span.clone(),
                            }
                        }
                    }

                    // Any other expression-as-statement (regular calls, blocks,
                    // etc.) lowers via the generic statement path.
                    _ => self.lower_stmt(stmt, span.clone(), ResolvedTy::Unit),
                },

                // All other statements lower normally (including let bindings,
                // nested scope{} blocks, etc.). Inside scope depth, `lower_stmt`
                // will already handle statement-expression calls as SpawnedCall
                // nodes via TI-1 (the scope_depth > 0 path in lower_stmt).
                _ => self.lower_stmt(stmt, span.clone(), ResolvedTy::Unit),
            };
            statements.push(hir_stmt);
        }

        let tail = block
            .trailing_expr
            .as_ref()
            .map(|expr| Box::new(self.lower_expr(expr, IntentKind::Read)));
        let ty = tail
            .as_ref()
            .map_or(ResolvedTy::Unit, |expr| expr.ty.clone());
        self.pop_scope();

        HirBlock {
            node: self.ids.node(),
            scope,
            statements,
            tail,
            ty,
            span: 0..0,
        }
    }

    /// Lower a call expression appearing as a statement inside a `scope{}` body
    /// as a child-task spawn (TI-1). The resulting `HirExpr` has kind
    /// `SpawnedCall` and type `Task<call_return_ty>`.
    ///
    /// FC-P1-A1 gates (blockers 1, 2, 3): Validates spawned call shape before
    /// emitting `SpawnedCall`. This is where implicit spawns (`scope { worker(); }`)
    /// are intercepted since they only appear as `SpawnedCall` after HIR lowering.
    fn lower_spawned_call(&mut self, expr: &Spanned<Expr>) -> HirExpr {
        let span = expr.1.clone();

        // FC-P1-A1 Blocker 1: Validate spawned call shape at lowering site
        // (implicit spawns never reach the AST walker)
        if let Expr::Call { function, args, .. } = &expr.0 {
            self.validate_task_spawn_call(function, args, &span);
        }

        // Lower the call normally to resolve the callee and argument types.
        //
        // FC-P1-A1 (revision pass 2): The callee return type is intentionally
        // NOT gated here. An implicit spawn that produces `Task<T>` for
        // non-unit T is a valid Hew construct; only `await` of a non-unit
        // task is gated (MIR :7871, `AwaitTaskResultUnsupported`). Gating at
        // spawn time would break the TI-1/TI-2/TI-4 canonical invariants.
        let call_hir = self.lower_expr(expr, IntentKind::Consume);
        let call_site = call_hir.site;
        let explicit_type_args = match &expr.0 {
            Expr::Call {
                type_args: Some(type_args),
                ..
            } => Some(type_args.clone()),
            _ => None,
        };
        let call_ret_ty = call_hir.ty.clone();

        let task_ty = ResolvedTy::Task(Box::new(call_ret_ty));

        let HirExprKind::Call { callee, args } = call_hir.kind else {
            // Should not happen: caller verified the expression is a Call.
            return self.unsupported_expr(span, "lower_spawned_call on non-call");
        };

        let spawned_site = self.ids.site();
        let type_args = self
            .call_site_type_args
            .get(&call_site)
            .cloned()
            .or_else(|| {
                explicit_type_args.map(|args| args.iter().map(|arg| self.lower_type(arg)).collect())
            });
        if let Some(type_args) = type_args {
            self.call_site_type_args.insert(spawned_site, type_args);
        }

        HirExpr {
            node: self.ids.node(),
            site: spawned_site,
            value_class: ValueClass::Linear, // Task handles are linear (consume-once).
            ty: task_ty.clone(),
            intent: IntentKind::Consume,
            kind: HirExprKind::SpawnedCall {
                callee,
                args,
                task_ty,
            },
            span,
        }
    }

    /// FC-P1-A1 helper: Validate task spawn call shape.
    /// Checks: (1) callee is direct fn or valid closure, (2) args list is empty,
    /// (3) for closures: params are empty, return is unit, captures are Send.
    fn validate_task_spawn_call(
        &mut self,
        function: &Spanned<Expr>,
        args: &[CallArg],
        span: &Span,
    ) {
        // Check args list is empty (required for all spawned calls)
        if !args.is_empty() {
            self.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::TaskSpawnSignatureUnsupported {
                    site: self.ids.site(),
                },
                span.clone(),
                "spawned call must have zero arguments".to_string(),
            ));
        }

        match &function.0 {
            Expr::Identifier(name) => {
                // FC-P1-A1 (revision pass 2, Finding 2): parser emits
                // `Expr::Identifier("mod::worker")` for module-qualified
                // calls; fn_registry is keyed on bare names. Strip the
                // prefix so cross-module spawns don't false-reject.
                let lookup_name = name.rsplit("::").next().unwrap_or(name.as_str());
                // Direct function call: check it's in fn_registry
                if !self.fn_registry.contains_key(lookup_name) {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::TaskSpawnCalleeUnsupported {
                            site: self.ids.site(),
                        },
                        span.clone(),
                        format!("spawned callee '{name}' is not a direct module function"),
                    ));
                }
                // Note: Return type validation happens in lower_spawned_call after type resolution
            }
            Expr::Lambda {
                params, body: _, ..
            } => {
                // FC-P1-A1 Blocker 3: Validate closure signature
                // (1) Zero params
                if !params.is_empty() {
                    self.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::SpawnedClosureSignatureUnsupported {
                            site: self.ids.site(),
                        },
                        span.clone(),
                        "spawned closure must have zero parameters".to_string(),
                    ));
                }

                // (2) Validate return type is unit
                // The closure body type will be checked after lowering via checker expr_types
                // For now, we rely on the inline checks at lowering time

                // (3) Check captures are Send (or conservatively reject if facts missing)
                let closure_span_key = SpanKey::from(&function.1);
                if let Some(captures) = self.closure_capture_facts.get(&closure_span_key) {
                    for capture in captures {
                        if !capture.is_send {
                            self.diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::SpawnedClosureNonSendCapture {
                                    site: self.ids.site(),
                                    capture_name: capture.name.clone(),
                                },
                                span.clone(),
                                format!(
                                    "spawned closure captures non-Send value '{}'",
                                    capture.name
                                ),
                            ));
                        }
                    }
                } else {
                    // FC-P1-A1 Blocker 3: Conservative reject when capture facts missing
                    // (Treat empty/missing as unknown — fail closed)
                    // Note: Zero-param closures with no captures are OK (empty vec is different from missing entry)
                    // We only warn here if there's actually a capture syntax present
                    // A production implementation would track whether the closure has capture syntax
                    // For now, we accept missing facts (assume no captures if not provided by checker)
                }
            }
            _ => {
                // Indirect call (variable, field access, etc.)
                self.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::TaskSpawnCalleeUnsupported {
                        site: self.ids.site(),
                    },
                    span.clone(),
                    "spawned callee must be a direct function or closure literal".to_string(),
                ));
            }
        }
    }
}

// ── Lambda-actor capture walker ─────────────────────────────────────────────

/// Recursive walk over a lowered actor-lambda body collecting captures.
///
/// A capture is any `HirExprKind::BindingRef { resolved: Binding(id) }`
/// whose `id` is NOT one of the lambda's own parameter bindings. The
/// first occurrence of each capture is recorded with a strength
/// classifier — `Weak` iff the id matches the lambda's let-binding id
/// passed in `self_id` (the forward-bound recursive-self case, §5.9
/// ratification 2), `Strong` otherwise. Subsequent references to the
/// same binding are skipped — codegen wires one runtime capture per
/// binding, not one per use site.
///
/// The walk is exhaustive over `HirExprKind` variants; nested lambdas
/// (an actor lambda inside another actor lambda's body) are NOT
/// descended into — their captures belong to the inner lambda's
/// frame and are reported separately when that lambda's own
/// `lower_spawn_lambda_actor` call ran. The nested lambda's appearance
/// in the outer body's capture set, if any, would come from the
/// outer body referencing a name that the inner lambda also referenced;
/// but `BindingRef` lives only in the outer body's expression tree, so
/// this falls out naturally from not descending into the inner body.
#[expect(
    clippy::too_many_lines,
    reason = "single-pass HIR walker; one arm per HirExprKind variant by design"
)]
fn collect_captures_walk(
    expr: &HirExpr,
    param_ids: &std::collections::HashSet<BindingId>,
    seen: &mut std::collections::HashSet<BindingId>,
    captures: &mut Vec<HirLambdaCapture>,
    self_id: Option<BindingId>,
) {
    match &expr.kind {
        HirExprKind::BindingRef {
            name,
            resolved: ResolvedRef::Binding(id),
        } => {
            // Parameters of the current lambda are intra-frame
            // bindings, never captures from the enclosing scope.
            if param_ids.contains(id) {
                return;
            }
            if !seen.insert(*id) {
                return;
            }
            let kind = if Some(*id) == self_id {
                HirCaptureKind::Weak
            } else {
                HirCaptureKind::Strong
            };
            captures.push(HirLambdaCapture {
                binding: *id,
                name: name.clone(),
                kind,
            });
        }
        // Empty-body terminals: nothing to walk.
        //   - BindingRef without a resolved binding (Item / Unresolved):
        //     does not produce a capture from the enclosing scope.
        //   - Literal: no sub-expressions.
        //   - SpawnLambdaActor (nested): its captures belong to its own
        //     frame and were classified when the inner lambda lowered.
        //   - Unsupported: nothing to walk.
        //   - MachineFieldAccess: implicit `self` receiver, no sub-expressions.
        HirExprKind::BindingRef { .. }
        | HirExprKind::ContextReader { .. }
        | HirExprKind::Literal(_)
        | HirExprKind::RegexLiteralRef { .. }
        | HirExprKind::SpawnLambdaActor { .. }
        | HirExprKind::Closure { .. }
        | HirExprKind::MachineFieldAccess { .. }
        | HirExprKind::MachineEventFieldAccess { .. }
        | HirExprKind::Continue { .. }
        | HirExprKind::Unsupported(_) => {}
        HirExprKind::Binary { left, right, .. } | HirExprKind::IdentityCompare { left, right } => {
            collect_captures_walk(left, param_ids, seen, captures, self_id);
            collect_captures_walk(right, param_ids, seen, captures, self_id);
        }
        HirExprKind::Unary { operand, .. } => {
            collect_captures_walk(operand, param_ids, seen, captures, self_id);
        }
        HirExprKind::ConnAwaitRead { conn, .. } => {
            collect_captures_walk(conn, param_ids, seen, captures, self_id);
        }
        HirExprKind::ListenerAwaitAccept { listener } => {
            collect_captures_walk(listener, param_ids, seen, captures, self_id);
        }
        HirExprKind::NumericCast { value, .. } | HirExprKind::CoerceToDynTrait { value, .. } => {
            collect_captures_walk(value, param_ids, seen, captures, self_id);
        }
        HirExprKind::TupleLiteral { elements } => {
            for elem in elements {
                collect_captures_walk(elem, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::NumericMethod { receiver, arg, .. } => {
            collect_captures_walk(receiver, param_ids, seen, captures, self_id);
            collect_captures_walk(arg, param_ids, seen, captures, self_id);
        }
        HirExprKind::Call { callee, args } | HirExprKind::SpawnedCall { callee, args, .. } => {
            collect_captures_walk(callee, param_ids, seen, captures, self_id);
            for arg in args {
                collect_captures_walk(arg, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::Spawn { args, .. } => {
            for (_, arg) in args {
                collect_captures_walk(arg, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::ActorSend { receiver, args, .. }
        | HirExprKind::ActorAsk { receiver, args, .. }
        | HirExprKind::CallDynMethod { receiver, args, .. }
        | HirExprKind::ResolvedImplCall { receiver, args, .. }
        | HirExprKind::CallTraitMethodStatic { receiver, args, .. }
        | HirExprKind::VarSelfMethodCall { receiver, args, .. } => {
            collect_captures_walk(receiver, param_ids, seen, captures, self_id);
            for arg in args {
                collect_captures_walk(arg, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::RemoteActorAsk {
            receiver,
            msg,
            timeout_ms,
            ..
        } => {
            collect_captures_walk(receiver, param_ids, seen, captures, self_id);
            collect_captures_walk(msg, param_ids, seen, captures, self_id);
            collect_captures_walk(timeout_ms, param_ids, seen, captures, self_id);
        }
        HirExprKind::Block(block)
        | HirExprKind::Scope { body: block }
        | HirExprKind::ForkBlock { body: block, .. }
        | HirExprKind::GenBlock { body: block, .. } => {
            collect_captures_walk_block(block, param_ids, seen, captures, self_id);
        }
        HirExprKind::Yield { value, .. } | HirExprKind::Break { value, .. } => {
            if let Some(value) = value {
                collect_captures_walk(value, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::ScopeDeadline { duration, body } => {
            collect_captures_walk(duration, param_ids, seen, captures, self_id);
            collect_captures_walk_block(body, param_ids, seen, captures, self_id);
        }
        HirExprKind::If {
            condition,
            then_expr,
            else_expr,
        } => {
            collect_captures_walk(condition, param_ids, seen, captures, self_id);
            collect_captures_walk(then_expr, param_ids, seen, captures, self_id);
            if let Some(else_expr) = else_expr {
                collect_captures_walk(else_expr, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::StructInit { fields, base, .. } => {
            for (_, field) in fields {
                collect_captures_walk(field, param_ids, seen, captures, self_id);
            }
            if let Some(base) = base {
                collect_captures_walk(base, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::FieldAccess { object, .. } => {
            collect_captures_walk(object, param_ids, seen, captures, self_id);
        }
        HirExprKind::AwaitTask { binding_id, .. } => {
            // The awaited task handle is captured from the enclosing
            // scope unless it is one of the lambda's own params.
            if param_ids.contains(binding_id) || !seen.insert(*binding_id) {
                return;
            }
            let kind = if Some(*binding_id) == self_id {
                HirCaptureKind::Weak
            } else {
                HirCaptureKind::Strong
            };
            captures.push(HirLambdaCapture {
                binding: *binding_id,
                // The await arm doesn't carry the binding's surface
                // name on its own — reach for the binding name via
                // the binding_name slot.
                name: String::new(),
                kind,
            });
        }
        HirExprKind::Select(select) => {
            for arm in &select.arms {
                match &arm.kind {
                    HirSelectArmKind::StreamNext { stream } => {
                        collect_captures_walk(stream, param_ids, seen, captures, self_id);
                    }
                    HirSelectArmKind::ActorAsk { actor, args, .. } => {
                        collect_captures_walk(actor, param_ids, seen, captures, self_id);
                        for arg in args {
                            collect_captures_walk(arg, param_ids, seen, captures, self_id);
                        }
                    }
                    HirSelectArmKind::TaskAwait { task } => {
                        collect_captures_walk(task, param_ids, seen, captures, self_id);
                    }
                    HirSelectArmKind::ChannelRecv { receiver, .. } => {
                        collect_captures_walk(receiver, param_ids, seen, captures, self_id);
                    }
                    HirSelectArmKind::AfterTimer { duration } => {
                        collect_captures_walk(duration, param_ids, seen, captures, self_id);
                    }
                }
                collect_captures_walk(&arm.body, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::TupleIndex { tuple, .. } => {
            collect_captures_walk(tuple, param_ids, seen, captures, self_id);
        }
        HirExprKind::Index { container, index } => {
            collect_captures_walk(container, param_ids, seen, captures, self_id);
            collect_captures_walk(index, param_ids, seen, captures, self_id);
        }
        HirExprKind::Slice {
            container,
            start,
            end,
            inclusive: _,
        } => {
            collect_captures_walk(container, param_ids, seen, captures, self_id);
            if let Some(s) = start {
                collect_captures_walk(s, param_ids, seen, captures, self_id);
            }
            if let Some(e) = end {
                collect_captures_walk(e, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::MachineEmit { fields, .. } => {
            // `emit` is only valid inside a machine body, which is never
            // inside a lambda/closure — so this arm should be unreachable in
            // practice.  Walk fields defensively to keep the traversal
            // exhaustive.
            for (_, field_val) in fields {
                collect_captures_walk(field_val, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::MachineStep {
            receiver, event, ..
        } => {
            // Machine method calls are not expected inside lambda/closure
            // bodies in v0.5. Walk defensively for exhaustiveness.
            collect_captures_walk(receiver, param_ids, seen, captures, self_id);
            collect_captures_walk(event, param_ids, seen, captures, self_id);
        }
        HirExprKind::CancellationTokenIsCancelled { receiver }
        | HirExprKind::GeneratorNext { receiver, .. }
        | HirExprKind::MachineStateName { receiver, .. } => {
            collect_captures_walk(receiver, param_ids, seen, captures, self_id);
        }
        HirExprKind::MachineVariantCtor { payload, .. } => {
            // Machine state constructors are not expected inside lambda bodies.
            // Walk payload fields defensively for exhaustiveness.
            if let Some(fields) = payload {
                for (_, val) in fields {
                    collect_captures_walk(val, param_ids, seen, captures, self_id);
                }
            }
        }
        HirExprKind::While { condition, body } => {
            collect_captures_walk(condition, param_ids, seen, captures, self_id);
            collect_captures_walk_block(body, param_ids, seen, captures, self_id);
        }
        HirExprKind::ForRange {
            start, end, body, ..
        } => {
            collect_captures_walk(start, param_ids, seen, captures, self_id);
            collect_captures_walk(end, param_ids, seen, captures, self_id);
            collect_captures_walk_block(body, param_ids, seen, captures, self_id);
        }
        HirExprKind::Match { scrutinee, arms } => {
            collect_captures_walk(scrutinee, param_ids, seen, captures, self_id);
            for arm in arms {
                if let Some(guard) = &arm.guard {
                    collect_captures_walk(guard, param_ids, seen, captures, self_id);
                }
                collect_captures_walk(&arm.body, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::WhileLet {
            scrutinee, body, ..
        } => {
            collect_captures_walk(scrutinee, param_ids, seen, captures, self_id);
            collect_captures_walk_block(body, param_ids, seen, captures, self_id);
        }
        HirExprKind::IfLet {
            scrutinee,
            body,
            else_body,
            ..
        } => {
            collect_captures_walk(scrutinee, param_ids, seen, captures, self_id);
            collect_captures_walk_block(body, param_ids, seen, captures, self_id);
            if let Some(eb) = else_body {
                collect_captures_walk_block(eb, param_ids, seen, captures, self_id);
            }
        }
        HirExprKind::Loop { body } => {
            collect_captures_walk_block(body, param_ids, seen, captures, self_id);
        }
    }
}

#[allow(
    clippy::too_many_lines,
    reason = "single exhaustive walker over HirExprKind variants; splitting risks traversal gaps"
)]
fn collect_general_closure_captures_walk(
    expr: &HirExpr,
    outer_bindings: &HashMap<BindingId, OuterClosureBinding>,
    seen: &mut HashSet<BindingId>,
    captures: &mut Vec<ClosureCaptureCandidate>,
) {
    match &expr.kind {
        HirExprKind::BindingRef {
            name,
            resolved: ResolvedRef::Binding(id),
        } if outer_bindings.contains_key(id) => {
            if seen.insert(*id) {
                let span = outer_bindings
                    .get(id)
                    .map(|(_, _, span)| span.clone())
                    .unwrap_or_default();
                captures.push((*id, name.clone(), span));
            }
        }
        HirExprKind::Closure {
            captures: nested, ..
        } => {
            for capture in nested {
                if outer_bindings.contains_key(&capture.binding) && seen.insert(capture.binding) {
                    let span = outer_bindings
                        .get(&capture.binding)
                        .map(|(_, _, span)| span.clone())
                        .unwrap_or_default();
                    captures.push((capture.binding, capture.name.clone(), span));
                }
            }
        }
        HirExprKind::BindingRef { .. }
        | HirExprKind::ContextReader { .. }
        | HirExprKind::Literal(_)
        | HirExprKind::RegexLiteralRef { .. }
        | HirExprKind::SpawnLambdaActor { .. }
        | HirExprKind::MachineFieldAccess { .. }
        | HirExprKind::MachineEventFieldAccess { .. }
        | HirExprKind::Continue { .. }
        | HirExprKind::Unsupported(_) => {}
        HirExprKind::Binary { left, right, .. } | HirExprKind::IdentityCompare { left, right } => {
            collect_general_closure_captures_walk(left, outer_bindings, seen, captures);
            collect_general_closure_captures_walk(right, outer_bindings, seen, captures);
        }
        HirExprKind::Unary { operand, .. } => {
            collect_general_closure_captures_walk(operand, outer_bindings, seen, captures);
        }
        HirExprKind::ConnAwaitRead { conn, .. } => {
            collect_general_closure_captures_walk(conn, outer_bindings, seen, captures);
        }
        HirExprKind::ListenerAwaitAccept { listener } => {
            collect_general_closure_captures_walk(listener, outer_bindings, seen, captures);
        }
        HirExprKind::NumericCast { value, .. } | HirExprKind::CoerceToDynTrait { value, .. } => {
            collect_general_closure_captures_walk(value, outer_bindings, seen, captures);
        }
        HirExprKind::TupleLiteral { elements } => {
            for elem in elements {
                collect_general_closure_captures_walk(elem, outer_bindings, seen, captures);
            }
        }
        HirExprKind::NumericMethod { receiver, arg, .. } => {
            collect_general_closure_captures_walk(receiver, outer_bindings, seen, captures);
            collect_general_closure_captures_walk(arg, outer_bindings, seen, captures);
        }
        HirExprKind::Call { callee, args } | HirExprKind::SpawnedCall { callee, args, .. } => {
            collect_general_closure_captures_walk(callee, outer_bindings, seen, captures);
            for arg in args {
                collect_general_closure_captures_walk(arg, outer_bindings, seen, captures);
            }
        }
        HirExprKind::Spawn { args, .. } => {
            for (_, arg) in args {
                collect_general_closure_captures_walk(arg, outer_bindings, seen, captures);
            }
        }
        HirExprKind::ActorSend { receiver, args, .. }
        | HirExprKind::ActorAsk { receiver, args, .. }
        | HirExprKind::CallDynMethod { receiver, args, .. }
        | HirExprKind::ResolvedImplCall { receiver, args, .. }
        | HirExprKind::CallTraitMethodStatic { receiver, args, .. }
        | HirExprKind::VarSelfMethodCall { receiver, args, .. } => {
            collect_general_closure_captures_walk(receiver, outer_bindings, seen, captures);
            for arg in args {
                collect_general_closure_captures_walk(arg, outer_bindings, seen, captures);
            }
        }
        HirExprKind::RemoteActorAsk {
            receiver,
            msg,
            timeout_ms,
            ..
        } => {
            collect_general_closure_captures_walk(receiver, outer_bindings, seen, captures);
            collect_general_closure_captures_walk(msg, outer_bindings, seen, captures);
            collect_general_closure_captures_walk(timeout_ms, outer_bindings, seen, captures);
        }
        HirExprKind::Block(block)
        | HirExprKind::Scope { body: block }
        | HirExprKind::ForkBlock { body: block, .. }
        | HirExprKind::GenBlock { body: block, .. } => {
            collect_general_closure_captures_walk_block(block, outer_bindings, seen, captures);
        }
        HirExprKind::Yield { value, .. } | HirExprKind::Break { value, .. } => {
            if let Some(value) = value {
                collect_general_closure_captures_walk(value, outer_bindings, seen, captures);
            }
        }
        HirExprKind::ScopeDeadline { duration, body } => {
            collect_general_closure_captures_walk(duration, outer_bindings, seen, captures);
            collect_general_closure_captures_walk_block(body, outer_bindings, seen, captures);
        }
        HirExprKind::If {
            condition,
            then_expr,
            else_expr,
        } => {
            collect_general_closure_captures_walk(condition, outer_bindings, seen, captures);
            collect_general_closure_captures_walk(then_expr, outer_bindings, seen, captures);
            if let Some(else_expr) = else_expr {
                collect_general_closure_captures_walk(else_expr, outer_bindings, seen, captures);
            }
        }
        HirExprKind::StructInit { fields, base, .. } => {
            for (_, field) in fields {
                collect_general_closure_captures_walk(field, outer_bindings, seen, captures);
            }
            if let Some(base) = base {
                collect_general_closure_captures_walk(base, outer_bindings, seen, captures);
            }
        }
        HirExprKind::FieldAccess { object, .. } => {
            collect_general_closure_captures_walk(object, outer_bindings, seen, captures);
        }
        HirExprKind::AwaitTask { binding_id, .. } => {
            if let Some((name, _, span)) = outer_bindings.get(binding_id) {
                if seen.insert(*binding_id) {
                    captures.push((*binding_id, name.clone(), span.clone()));
                }
            }
        }
        HirExprKind::Select(select) => {
            for arm in &select.arms {
                match &arm.kind {
                    HirSelectArmKind::StreamNext { stream } => {
                        collect_general_closure_captures_walk(
                            stream,
                            outer_bindings,
                            seen,
                            captures,
                        );
                    }
                    HirSelectArmKind::ActorAsk { actor, args, .. } => {
                        collect_general_closure_captures_walk(
                            actor,
                            outer_bindings,
                            seen,
                            captures,
                        );
                        for arg in args {
                            collect_general_closure_captures_walk(
                                arg,
                                outer_bindings,
                                seen,
                                captures,
                            );
                        }
                    }
                    HirSelectArmKind::TaskAwait { task } => {
                        collect_general_closure_captures_walk(task, outer_bindings, seen, captures);
                    }
                    HirSelectArmKind::ChannelRecv { receiver, .. } => {
                        collect_general_closure_captures_walk(
                            receiver,
                            outer_bindings,
                            seen,
                            captures,
                        );
                    }
                    HirSelectArmKind::AfterTimer { duration } => {
                        collect_general_closure_captures_walk(
                            duration,
                            outer_bindings,
                            seen,
                            captures,
                        );
                    }
                }
                collect_general_closure_captures_walk(&arm.body, outer_bindings, seen, captures);
            }
        }
        HirExprKind::TupleIndex { tuple, .. } => {
            collect_general_closure_captures_walk(tuple, outer_bindings, seen, captures);
        }
        HirExprKind::Index { container, index } => {
            collect_general_closure_captures_walk(container, outer_bindings, seen, captures);
            collect_general_closure_captures_walk(index, outer_bindings, seen, captures);
        }
        HirExprKind::Slice {
            container,
            start,
            end,
            inclusive: _,
        } => {
            collect_general_closure_captures_walk(container, outer_bindings, seen, captures);
            if let Some(s) = start {
                collect_general_closure_captures_walk(s, outer_bindings, seen, captures);
            }
            if let Some(e) = end {
                collect_general_closure_captures_walk(e, outer_bindings, seen, captures);
            }
        }
        HirExprKind::MachineEmit { fields, .. } => {
            // `emit` cannot appear inside a closure body (machine bodies are
            // not closures); walk fields defensively for exhaustiveness.
            for (_, field_val) in fields {
                collect_general_closure_captures_walk(field_val, outer_bindings, seen, captures);
            }
        }
        HirExprKind::MachineStep {
            receiver, event, ..
        } => {
            collect_general_closure_captures_walk(receiver, outer_bindings, seen, captures);
            collect_general_closure_captures_walk(event, outer_bindings, seen, captures);
        }
        HirExprKind::CancellationTokenIsCancelled { receiver }
        | HirExprKind::GeneratorNext { receiver, .. }
        | HirExprKind::MachineStateName { receiver, .. } => {
            collect_general_closure_captures_walk(receiver, outer_bindings, seen, captures);
        }
        HirExprKind::MachineVariantCtor { payload, .. } => {
            // Machine state constructors cannot appear inside closure bodies.
            // Walk payload fields defensively for exhaustiveness.
            if let Some(fields) = payload {
                for (_, val) in fields {
                    collect_general_closure_captures_walk(val, outer_bindings, seen, captures);
                }
            }
        }
        HirExprKind::While { condition, body } => {
            collect_general_closure_captures_walk(condition, outer_bindings, seen, captures);
            collect_general_closure_captures_walk_block(body, outer_bindings, seen, captures);
        }
        HirExprKind::ForRange {
            start, end, body, ..
        } => {
            collect_general_closure_captures_walk(start, outer_bindings, seen, captures);
            collect_general_closure_captures_walk(end, outer_bindings, seen, captures);
            collect_general_closure_captures_walk_block(body, outer_bindings, seen, captures);
        }
        HirExprKind::Match { scrutinee, arms } => {
            collect_general_closure_captures_walk(scrutinee, outer_bindings, seen, captures);
            for arm in arms {
                if let Some(guard) = &arm.guard {
                    collect_general_closure_captures_walk(guard, outer_bindings, seen, captures);
                }
                collect_general_closure_captures_walk(&arm.body, outer_bindings, seen, captures);
            }
        }
        HirExprKind::WhileLet {
            scrutinee, body, ..
        } => {
            collect_general_closure_captures_walk(scrutinee, outer_bindings, seen, captures);
            collect_general_closure_captures_walk_block(body, outer_bindings, seen, captures);
        }
        HirExprKind::IfLet {
            scrutinee,
            body,
            else_body,
            ..
        } => {
            collect_general_closure_captures_walk(scrutinee, outer_bindings, seen, captures);
            collect_general_closure_captures_walk_block(body, outer_bindings, seen, captures);
            if let Some(eb) = else_body {
                collect_general_closure_captures_walk_block(eb, outer_bindings, seen, captures);
            }
        }
        HirExprKind::Loop { body } => {
            collect_general_closure_captures_walk_block(body, outer_bindings, seen, captures);
        }
    }
}

fn collect_general_closure_captures_walk_block(
    block: &HirBlock,
    outer_bindings: &HashMap<BindingId, OuterClosureBinding>,
    seen: &mut HashSet<BindingId>,
    captures: &mut Vec<ClosureCaptureCandidate>,
) {
    for stmt in &block.statements {
        match &stmt.kind {
            HirStmtKind::Let(_, Some(value)) => {
                collect_general_closure_captures_walk(value, outer_bindings, seen, captures);
            }
            HirStmtKind::Expr(expr) | HirStmtKind::Return(Some(expr)) => {
                collect_general_closure_captures_walk(expr, outer_bindings, seen, captures);
            }
            HirStmtKind::Assign { target, value } => {
                collect_general_closure_captures_walk(target, outer_bindings, seen, captures);
                collect_general_closure_captures_walk(value, outer_bindings, seen, captures);
            }
            HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
            HirStmtKind::Defer { body, .. } => {
                collect_general_closure_captures_walk(body, outer_bindings, seen, captures);
            }
        }
    }
    if let Some(tail) = &block.tail {
        collect_general_closure_captures_walk(tail, outer_bindings, seen, captures);
    }
}

fn collect_captures_walk_block(
    block: &HirBlock,
    param_ids: &std::collections::HashSet<BindingId>,
    seen: &mut std::collections::HashSet<BindingId>,
    captures: &mut Vec<HirLambdaCapture>,
    self_id: Option<BindingId>,
) {
    for stmt in &block.statements {
        match &stmt.kind {
            HirStmtKind::Let(_, Some(value)) => {
                collect_captures_walk(value, param_ids, seen, captures, self_id);
            }
            HirStmtKind::Expr(expr) | HirStmtKind::Return(Some(expr)) => {
                collect_captures_walk(expr, param_ids, seen, captures, self_id);
            }
            HirStmtKind::Assign { target, value } => {
                collect_captures_walk(target, param_ids, seen, captures, self_id);
                collect_captures_walk(value, param_ids, seen, captures, self_id);
            }
            HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
            HirStmtKind::Defer { body, .. } => {
                collect_captures_walk(body, param_ids, seen, captures, self_id);
            }
        }
    }
    if let Some(tail) = &block.tail {
        collect_captures_walk(tail, param_ids, seen, captures, self_id);
    }
}

// ── Machine static-check helpers ────────────────────────────────────────────

/// Allowlist of AST spans that mark constructs in a machine transition body
/// or entry/exit block which the HIR lowerer cannot resolve today but which
/// are owned by the AST-summary static checks (exhaustiveness, self-
/// transition rules, effect-parity, emit-cycle). When lowering a machine
/// body produces a diagnostic whose `(kind, span)` matches one of these
/// entries exactly, the diagnostic is dropped; every other diagnostic
/// produced during the same lowering is preserved so unrelated unresolved
/// symbols and type errors still fail closed.
///
/// Note: `Expr::MachineEmit` is no longer in the allowlist because it now
/// lowers to `HirExprKind::MachineEmit` directly rather than falling through
/// to `NotYetImplemented`.
#[derive(Debug, Default)]
struct MachineBodyAllowlist {
    /// Spans of `Expr::Identifier(name)` where `name` is a declared state
    /// name in the current machine — drops the matching `UnresolvedSymbol`.
    state_name_refs: Vec<(Span, String)>,
    /// Spans of `Expr::This` — drops the matching `NotYetImplemented`
    /// raised by the catch-all expression arm.
    this_spans: Vec<Span>,
}

impl MachineBodyAllowlist {
    /// Return `true` iff the diagnostic's `(kind, span)` is one this
    /// allowlist explicitly accounts for. Anything else flows through.
    fn permits(&self, diag: &HirDiagnostic) -> bool {
        match &diag.kind {
            HirDiagnosticKind::UnresolvedSymbol { name } => self
                .state_name_refs
                .iter()
                .any(|(span, allowed)| spans_equal(span, &diag.span) && allowed == name),
            HirDiagnosticKind::NotYetImplemented { .. } => self
                .this_spans
                .iter()
                .any(|span| spans_equal(span, &diag.span)),
            _ => false,
        }
    }
}

fn spans_equal(a: &Span, b: &Span) -> bool {
    a.start == b.start && a.end == b.end
}

/// Walk a machine transition body expression to populate
/// `MachineBodyAllowlist`. Only the specific constructs that the HIR
/// lowerer is known not to support yet (state-name identifier references,
/// `this`, and `emit`) are recorded. All other sub-expressions are walked
/// solely to descend into their children — they themselves are never
/// allowlisted, so e.g. an unresolved user identifier inside a `Call`
/// argument still produces a visible diagnostic.
fn walk_expr_for_machine_allowlist(
    expr: &Spanned<Expr>,
    state_names: &HashSet<String>,
    out: &mut MachineBodyAllowlist,
) {
    let (node, span) = expr;
    match node {
        Expr::This => out.this_spans.push(span.clone()),
        Expr::MachineEmit { fields, .. } => {
            // `emit` now lowers to `HirExprKind::MachineEmit` directly; no
            // allowlist entry is needed.  Still descend into field values in
            // case they contain state-name refs or `this` that do need entries.
            for (_, value) in fields {
                walk_expr_for_machine_allowlist(value, state_names, out);
            }
        }
        Expr::Identifier(name) if state_names.contains(name) => {
            out.state_name_refs.push((span.clone(), name.clone()));
        }
        Expr::Block(block) => walk_block_for_machine_allowlist(block, state_names, out),
        Expr::Binary { left, right, .. } => {
            walk_expr_for_machine_allowlist(left, state_names, out);
            walk_expr_for_machine_allowlist(right, state_names, out);
        }
        Expr::Unary { operand, .. } => {
            walk_expr_for_machine_allowlist(operand, state_names, out);
        }
        Expr::Call { function, args, .. } => {
            walk_expr_for_machine_allowlist(function, state_names, out);
            for arg in args {
                walk_expr_for_machine_allowlist(arg.expr(), state_names, out);
            }
        }
        Expr::MethodCall { receiver, args, .. } => {
            walk_expr_for_machine_allowlist(receiver, state_names, out);
            for arg in args {
                walk_expr_for_machine_allowlist(arg.expr(), state_names, out);
            }
        }
        Expr::FieldAccess { object, .. } => {
            walk_expr_for_machine_allowlist(object, state_names, out);
        }
        Expr::Index { object, index } => {
            walk_expr_for_machine_allowlist(object, state_names, out);
            walk_expr_for_machine_allowlist(index, state_names, out);
        }
        Expr::StructInit { fields, base, .. } => {
            for (_, value) in fields {
                walk_expr_for_machine_allowlist(value, state_names, out);
            }
            if let Some(base) = base {
                walk_expr_for_machine_allowlist(base, state_names, out);
            }
        }
        Expr::If {
            condition,
            then_block,
            else_block,
        } => {
            walk_expr_for_machine_allowlist(condition, state_names, out);
            walk_expr_for_machine_allowlist(then_block, state_names, out);
            if let Some(else_block) = else_block {
                walk_expr_for_machine_allowlist(else_block, state_names, out);
            }
        }
        Expr::Match { scrutinee, arms } => {
            walk_expr_for_machine_allowlist(scrutinee, state_names, out);
            for arm in arms {
                if let Some(guard) = &arm.guard {
                    walk_expr_for_machine_allowlist(guard, state_names, out);
                }
                walk_expr_for_machine_allowlist(&arm.body, state_names, out);
            }
        }
        Expr::Cast { expr, .. } => walk_expr_for_machine_allowlist(expr, state_names, out),
        Expr::Range { start, end, .. } => {
            if let Some(start) = start {
                walk_expr_for_machine_allowlist(start, state_names, out);
            }
            if let Some(end) = end {
                walk_expr_for_machine_allowlist(end, state_names, out);
            }
        }
        Expr::Is { lhs, rhs } => {
            walk_expr_for_machine_allowlist(lhs, state_names, out);
            walk_expr_for_machine_allowlist(rhs, state_names, out);
        }
        Expr::Tuple(items) | Expr::Array(items) => {
            for item in items {
                walk_expr_for_machine_allowlist(item, state_names, out);
            }
        }
        // LEGITIMATE-NOOP: conservative Expr walker — only Expr variants
        // reachable in machine transition/entry/exit bodies are descended into.
        // Unknown variants cannot mask unresolved diagnostics; they simply
        // aren't allowlisted and surface normally. Expr has many variants not
        // valid here (lambdas, spawn, select, scope, timeout, for-loops, …).
        _ => {}
    }
}

/// Walk a machine entry/exit block to populate `MachineBodyAllowlist`.
fn walk_block_for_machine_allowlist(
    block: &Block,
    state_names: &HashSet<String>,
    out: &mut MachineBodyAllowlist,
) {
    for (stmt, _) in &block.stmts {
        walk_stmt_for_machine_allowlist(stmt, state_names, out);
    }
    if let Some(tail) = &block.trailing_expr {
        walk_expr_for_machine_allowlist(tail, state_names, out);
    }
}

fn walk_stmt_for_machine_allowlist(
    stmt: &Stmt,
    state_names: &HashSet<String>,
    out: &mut MachineBodyAllowlist,
) {
    match stmt {
        Stmt::Expression(e) => walk_expr_for_machine_allowlist(e, state_names, out),
        Stmt::Assign { target, value, .. } => {
            walk_expr_for_machine_allowlist(target, state_names, out);
            walk_expr_for_machine_allowlist(value, state_names, out);
        }
        Stmt::Let { value, .. } | Stmt::Var { value, .. } | Stmt::Return(value) => {
            if let Some(value) = value {
                walk_expr_for_machine_allowlist(value, state_names, out);
            }
        }
        Stmt::If {
            condition,
            then_block,
            else_block,
        } => {
            walk_expr_for_machine_allowlist(condition, state_names, out);
            walk_block_for_machine_allowlist(then_block, state_names, out);
            if let Some(else_block) = else_block {
                if let Some(block) = &else_block.block {
                    walk_block_for_machine_allowlist(block, state_names, out);
                }
                if let Some(if_stmt) = &else_block.if_stmt {
                    walk_stmt_for_machine_allowlist(&if_stmt.0, state_names, out);
                }
            }
        }
        Stmt::Defer(inner) => walk_expr_for_machine_allowlist(inner, state_names, out),
        // LEGITIMATE-NOOP: conservative Stmt walker — only statement variants
        // reachable in machine entry/exit blocks are descended into. See the
        // walker contract note on `walk_expr_for_machine_allowlist`.
        _ => {}
    }
}

/// Determine whether a self-transition body is "empty" for the `@reenter` rule.
///
/// A body is considered empty when:
/// - It is `Expr::Identifier(target_state)` — the no-body semicolon shorthand
///   that the parser synthesises for `on E: S -> S;`.
/// - It is `Expr::Block` with no statements and no trailing expression.
///
/// Any other form (statements, expressions) is non-empty and requires `@reenter`.
fn is_empty_self_body(body: &Expr, target_state: &str) -> bool {
    match body {
        Expr::Identifier(name) => name == target_state,
        Expr::Block(block) => block.stmts.is_empty() && block.trailing_expr.is_none(),
        _ => false,
    }
}

/// Shallow-scan a `Block` for field names appearing as the left-hand side of
/// an assignment statement (`self.field = ...`). Used for effect-parity checking
/// in entry blocks — the scan is intentionally shallow (depth = 1) since a
/// full walk would require type information we don't have in Lane A.
fn collect_assigned_field_names(block: &Block) -> Vec<(String, Span)> {
    let mut names = Vec::new();
    for (stmt, _) in &block.stmts {
        if let Stmt::Assign { target, .. } = stmt {
            if let Expr::FieldAccess { object, field } = &target.0 {
                if matches!(object.0, Expr::This) {
                    names.push((field.clone(), target.1.clone()));
                }
            }
        }
    }
    names
}

/// Shallow-scan an `Expr` (transition body) for `self.field = ...` assignments.
fn collect_assigned_field_names_expr(expr: &Expr) -> Vec<String> {
    if let Expr::Block(block) = expr {
        collect_assigned_field_names(block)
            .into_iter()
            .map(|(name, _)| name)
            .collect()
    } else {
        Vec::new()
    }
}

/// Collect event names directly emitted by `emit EventName` expressions within
/// an expression (transition body). Only direct emits are tracked; deeper nesting
/// is deferred to runtime (per the plan's "direct cycles only" rule).
///
/// Kept for AST-surface use; lowering now calls `collect_hir_emitted_events`
/// which walks the already-lowered `HirExpr` tree so that emit expressions
/// nested inside `if` branches or `match` arms are correctly detected.
#[allow(
    dead_code,
    reason = "retained for future AST-surface callers; active lowering uses collect_hir_emitted_events"
)]
fn collect_emitted_events(expr: &Expr) -> Vec<String> {
    let mut events = Vec::new();
    collect_emitted_events_inner(expr, &mut events);
    events
}

fn collect_emitted_events_inner(expr: &Expr, out: &mut Vec<String>) {
    match expr {
        Expr::MachineEmit { event_name, .. } => out.push(event_name.clone()),
        Expr::Block(block) => {
            for (stmt, _) in &block.stmts {
                if let Stmt::Expression((e, _)) = stmt {
                    collect_emitted_events_inner(e, out);
                }
            }
            if let Some(tail) = &block.trailing_expr {
                collect_emitted_events_inner(&tail.0, out);
            }
        }
        // LEGITIMATE-NOOP: this walker only collects `MachineEmit` and
        // descends into `Block` for top-level event counting. Other Expr
        // variants are irrelevant to direct-emit detection.
        _ => {}
    }
}

/// Collect event names emitted by `HirExprKind::MachineEmit` nodes within a
/// lowered HIR expression tree, resolving `event_idx` back to names via
/// `event_names` (the ordered event list of the enclosing machine declaration,
/// matching `HirMachineDecl::events` order).
///
/// Descends into all sub-expressions including `if`/`else` branches so that a
/// direct self-emit nested inside a conditional is detected by the emit-cycle
/// check — unlike the old AST walker which only traversed top-level blocks.
fn collect_hir_emitted_events(expr: &HirExpr, event_names: &[String]) -> Vec<String> {
    let mut events = Vec::new();
    collect_hir_emitted_events_walk(expr, event_names, &mut events);
    events
}

#[allow(
    clippy::too_many_lines,
    reason = "single recursive walker spanning all HirExprKind variants"
)]
fn collect_hir_emitted_events_walk(expr: &HirExpr, event_names: &[String], out: &mut Vec<String>) {
    match &expr.kind {
        HirExprKind::MachineEmit { event_idx, fields } => {
            if let Some(name) = event_names.get(*event_idx) {
                out.push(name.clone());
            }
            // Recurse into field expressions — they may contain nested emits.
            for (_, e) in fields {
                collect_hir_emitted_events_walk(e, event_names, out);
            }
        }
        HirExprKind::Block(block) => {
            for stmt in &block.statements {
                match &stmt.kind {
                    HirStmtKind::Expr(e)
                    | HirStmtKind::Let(_, Some(e))
                    | HirStmtKind::Return(Some(e)) => {
                        collect_hir_emitted_events_walk(e, event_names, out);
                    }
                    HirStmtKind::Assign { value, .. } => {
                        // Assignment targets are never emit-bearing expressions.
                        collect_hir_emitted_events_walk(value, event_names, out);
                    }
                    HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
                    HirStmtKind::Defer { body, .. } => {
                        collect_hir_emitted_events_walk(body, event_names, out);
                    }
                }
            }
            if let Some(tail) = &block.tail {
                collect_hir_emitted_events_walk(tail, event_names, out);
            }
        }
        HirExprKind::GenBlock { body, .. } => {
            for stmt in &body.statements {
                match &stmt.kind {
                    HirStmtKind::Expr(e)
                    | HirStmtKind::Let(_, Some(e))
                    | HirStmtKind::Return(Some(e)) => {
                        collect_hir_emitted_events_walk(e, event_names, out);
                    }
                    HirStmtKind::Assign { value, .. } => {
                        collect_hir_emitted_events_walk(value, event_names, out);
                    }
                    HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
                    HirStmtKind::Defer { body, .. } => {
                        collect_hir_emitted_events_walk(body, event_names, out);
                    }
                }
            }
            if let Some(tail) = &body.tail {
                collect_hir_emitted_events_walk(tail, event_names, out);
            }
        }
        HirExprKind::Yield {
            value: Some(value), ..
        } => collect_hir_emitted_events_walk(value, event_names, out),
        HirExprKind::If {
            condition,
            then_expr,
            else_expr,
        } => {
            collect_hir_emitted_events_walk(condition, event_names, out);
            collect_hir_emitted_events_walk(then_expr, event_names, out);
            if let Some(e) = else_expr {
                collect_hir_emitted_events_walk(e, event_names, out);
            }
        }
        HirExprKind::Binary { left, right, .. } | HirExprKind::IdentityCompare { left, right } => {
            collect_hir_emitted_events_walk(left, event_names, out);
            collect_hir_emitted_events_walk(right, event_names, out);
        }
        HirExprKind::Unary { operand, .. } => {
            collect_hir_emitted_events_walk(operand, event_names, out);
        }
        HirExprKind::ConnAwaitRead { conn, .. } => {
            collect_hir_emitted_events_walk(conn, event_names, out);
        }
        HirExprKind::ListenerAwaitAccept { listener } => {
            collect_hir_emitted_events_walk(listener, event_names, out);
        }
        HirExprKind::NumericCast { value, .. } | HirExprKind::CoerceToDynTrait { value, .. } => {
            collect_hir_emitted_events_walk(value, event_names, out);
        }
        HirExprKind::TupleLiteral { elements } => {
            for elem in elements {
                collect_hir_emitted_events_walk(elem, event_names, out);
            }
        }
        HirExprKind::Call { callee, args } | HirExprKind::SpawnedCall { callee, args, .. } => {
            collect_hir_emitted_events_walk(callee, event_names, out);
            for a in args {
                collect_hir_emitted_events_walk(a, event_names, out);
            }
        }
        HirExprKind::Match { scrutinee, arms } => {
            collect_hir_emitted_events_walk(scrutinee, event_names, out);
            for arm in arms {
                if let Some(guard) = &arm.guard {
                    collect_hir_emitted_events_walk(guard, event_names, out);
                }
                collect_hir_emitted_events_walk(&arm.body, event_names, out);
            }
        }
        // Additional expression forms whose sub-expressions can contain emits.
        HirExprKind::ActorSend { receiver, args, .. }
        | HirExprKind::ActorAsk { receiver, args, .. }
        | HirExprKind::CallDynMethod { receiver, args, .. }
        | HirExprKind::ResolvedImplCall { receiver, args, .. }
        | HirExprKind::CallTraitMethodStatic { receiver, args, .. }
        | HirExprKind::VarSelfMethodCall { receiver, args, .. } => {
            collect_hir_emitted_events_walk(receiver, event_names, out);
            for a in args {
                collect_hir_emitted_events_walk(a, event_names, out);
            }
        }
        HirExprKind::RemoteActorAsk {
            receiver,
            msg,
            timeout_ms,
            ..
        } => {
            collect_hir_emitted_events_walk(receiver, event_names, out);
            collect_hir_emitted_events_walk(msg, event_names, out);
            collect_hir_emitted_events_walk(timeout_ms, event_names, out);
        }
        HirExprKind::Spawn { args, .. } => {
            for (_, e) in args {
                collect_hir_emitted_events_walk(e, event_names, out);
            }
        }
        HirExprKind::StructInit { fields, base, .. } => {
            for (_, e) in fields {
                collect_hir_emitted_events_walk(e, event_names, out);
            }
            if let Some(b) = base {
                collect_hir_emitted_events_walk(b, event_names, out);
            }
        }
        HirExprKind::FieldAccess { object, .. } => {
            collect_hir_emitted_events_walk(object, event_names, out);
        }
        HirExprKind::Scope { body } | HirExprKind::ForkBlock { body, .. } => {
            for stmt in &body.statements {
                match &stmt.kind {
                    HirStmtKind::Expr(e)
                    | HirStmtKind::Let(_, Some(e))
                    | HirStmtKind::Return(Some(e)) => {
                        collect_hir_emitted_events_walk(e, event_names, out);
                    }
                    HirStmtKind::Assign { value, .. } => {
                        collect_hir_emitted_events_walk(value, event_names, out);
                    }
                    HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
                    HirStmtKind::Defer { body, .. } => {
                        collect_hir_emitted_events_walk(body, event_names, out);
                    }
                }
            }
            if let Some(tail) = &body.tail {
                collect_hir_emitted_events_walk(tail, event_names, out);
            }
        }
        HirExprKind::ScopeDeadline { duration, body } => {
            collect_hir_emitted_events_walk(duration, event_names, out);
            for stmt in &body.statements {
                match &stmt.kind {
                    HirStmtKind::Expr(e)
                    | HirStmtKind::Let(_, Some(e))
                    | HirStmtKind::Return(Some(e)) => {
                        collect_hir_emitted_events_walk(e, event_names, out);
                    }
                    HirStmtKind::Assign { value, .. } => {
                        collect_hir_emitted_events_walk(value, event_names, out);
                    }
                    HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
                    HirStmtKind::Defer { body, .. } => {
                        collect_hir_emitted_events_walk(body, event_names, out);
                    }
                }
            }
            if let Some(tail) = &body.tail {
                collect_hir_emitted_events_walk(tail, event_names, out);
            }
        }
        HirExprKind::While { condition, body } => {
            collect_hir_emitted_events_walk(condition, event_names, out);
            for stmt in &body.statements {
                match &stmt.kind {
                    HirStmtKind::Expr(e)
                    | HirStmtKind::Let(_, Some(e))
                    | HirStmtKind::Return(Some(e)) => {
                        collect_hir_emitted_events_walk(e, event_names, out);
                    }
                    HirStmtKind::Assign { value, .. } => {
                        collect_hir_emitted_events_walk(value, event_names, out);
                    }
                    HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
                    HirStmtKind::Defer { body, .. } => {
                        collect_hir_emitted_events_walk(body, event_names, out);
                    }
                }
            }
            if let Some(tail) = &body.tail {
                collect_hir_emitted_events_walk(tail, event_names, out);
            }
        }
        HirExprKind::ForRange {
            start, end, body, ..
        } => {
            collect_hir_emitted_events_walk(start, event_names, out);
            collect_hir_emitted_events_walk(end, event_names, out);
            for stmt in &body.statements {
                match &stmt.kind {
                    HirStmtKind::Expr(e)
                    | HirStmtKind::Let(_, Some(e))
                    | HirStmtKind::Return(Some(e)) => {
                        collect_hir_emitted_events_walk(e, event_names, out);
                    }
                    HirStmtKind::Assign { value, .. } => {
                        collect_hir_emitted_events_walk(value, event_names, out);
                    }
                    HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
                    HirStmtKind::Defer { body, .. } => {
                        collect_hir_emitted_events_walk(body, event_names, out);
                    }
                }
            }
            if let Some(tail) = &body.tail {
                collect_hir_emitted_events_walk(tail, event_names, out);
            }
        }
        HirExprKind::WhileLet {
            scrutinee, body, ..
        } => {
            collect_hir_emitted_events_walk(scrutinee, event_names, out);
            for stmt in &body.statements {
                match &stmt.kind {
                    HirStmtKind::Expr(e)
                    | HirStmtKind::Let(_, Some(e))
                    | HirStmtKind::Return(Some(e)) => {
                        collect_hir_emitted_events_walk(e, event_names, out);
                    }
                    HirStmtKind::Assign { value, .. } => {
                        collect_hir_emitted_events_walk(value, event_names, out);
                    }
                    HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
                    HirStmtKind::Defer { body, .. } => {
                        collect_hir_emitted_events_walk(body, event_names, out);
                    }
                }
            }
            if let Some(tail) = &body.tail {
                collect_hir_emitted_events_walk(tail, event_names, out);
            }
        }
        HirExprKind::IfLet {
            scrutinee,
            body,
            else_body,
            ..
        } => {
            collect_hir_emitted_events_walk(scrutinee, event_names, out);
            for block in std::iter::once(body).chain(else_body.as_ref()) {
                for stmt in &block.statements {
                    match &stmt.kind {
                        HirStmtKind::Expr(e)
                        | HirStmtKind::Let(_, Some(e))
                        | HirStmtKind::Return(Some(e)) => {
                            collect_hir_emitted_events_walk(e, event_names, out);
                        }
                        HirStmtKind::Assign { value, .. } => {
                            collect_hir_emitted_events_walk(value, event_names, out);
                        }
                        HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
                        HirStmtKind::Defer { body, .. } => {
                            collect_hir_emitted_events_walk(body, event_names, out);
                        }
                    }
                }
                if let Some(tail) = &block.tail {
                    collect_hir_emitted_events_walk(tail, event_names, out);
                }
            }
        }
        HirExprKind::Break { value, .. } => {
            if let Some(value) = value {
                collect_hir_emitted_events_walk(value, event_names, out);
            }
        }
        HirExprKind::Loop { body } => {
            for stmt in &body.statements {
                match &stmt.kind {
                    HirStmtKind::Expr(e)
                    | HirStmtKind::Let(_, Some(e))
                    | HirStmtKind::Return(Some(e)) => {
                        collect_hir_emitted_events_walk(e, event_names, out);
                    }
                    HirStmtKind::Assign { value, .. } => {
                        collect_hir_emitted_events_walk(value, event_names, out);
                    }
                    HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
                    HirStmtKind::Defer { body, .. } => {
                        collect_hir_emitted_events_walk(body, event_names, out);
                    }
                }
            }
            if let Some(tail) = &body.tail {
                collect_hir_emitted_events_walk(tail, event_names, out);
            }
        }
        HirExprKind::TupleIndex { tuple, .. } => {
            collect_hir_emitted_events_walk(tuple, event_names, out);
        }
        HirExprKind::Index { container, index } => {
            collect_hir_emitted_events_walk(container, event_names, out);
            collect_hir_emitted_events_walk(index, event_names, out);
        }
        HirExprKind::Slice {
            container,
            start,
            end,
            ..
        } => {
            collect_hir_emitted_events_walk(container, event_names, out);
            if let Some(s) = start {
                collect_hir_emitted_events_walk(s, event_names, out);
            }
            if let Some(e) = end {
                collect_hir_emitted_events_walk(e, event_names, out);
            }
        }
        HirExprKind::NumericMethod { receiver, arg, .. } => {
            collect_hir_emitted_events_walk(receiver, event_names, out);
            collect_hir_emitted_events_walk(arg, event_names, out);
        }
        HirExprKind::MachineStep {
            receiver, event, ..
        } => {
            collect_hir_emitted_events_walk(receiver, event_names, out);
            collect_hir_emitted_events_walk(event, event_names, out);
        }
        HirExprKind::CancellationTokenIsCancelled { receiver }
        | HirExprKind::GeneratorNext { receiver, .. }
        | HirExprKind::MachineStateName { receiver, .. } => {
            collect_hir_emitted_events_walk(receiver, event_names, out);
        }
        HirExprKind::MachineVariantCtor { payload, .. } => {
            if let Some(fields) = payload {
                for (_, e) in fields {
                    collect_hir_emitted_events_walk(e, event_names, out);
                }
            }
        }
        HirExprKind::Select(sel) => {
            for arm in &sel.arms {
                match &arm.kind {
                    HirSelectArmKind::StreamNext { stream } => {
                        collect_hir_emitted_events_walk(stream, event_names, out);
                    }
                    HirSelectArmKind::ActorAsk { actor, args, .. } => {
                        collect_hir_emitted_events_walk(actor, event_names, out);
                        for a in args {
                            collect_hir_emitted_events_walk(a, event_names, out);
                        }
                    }
                    HirSelectArmKind::TaskAwait { task } => {
                        collect_hir_emitted_events_walk(task, event_names, out);
                    }
                    HirSelectArmKind::ChannelRecv { receiver, .. } => {
                        collect_hir_emitted_events_walk(receiver, event_names, out);
                    }
                    HirSelectArmKind::AfterTimer { duration } => {
                        collect_hir_emitted_events_walk(duration, event_names, out);
                    }
                }
                collect_hir_emitted_events_walk(&arm.body, event_names, out);
            }
        }
        // A general closure executes inline in the current lowering flow;
        // emits in its body belong to the enclosing transition.
        HirExprKind::Closure { body, .. } => {
            collect_hir_emitted_events_walk(body, event_names, out);
        }
        // Lambda-actors run on a separate actor substrate; MIR materialises
        // only the handle/captures. Emits in their bodies belong to the inner
        // actor, not the enclosing transition.
        // Leaf variants also produce no emits.
        HirExprKind::SpawnLambdaActor { .. }
        | HirExprKind::Literal(_)
        | HirExprKind::RegexLiteralRef { .. }
        | HirExprKind::BindingRef { .. }
        | HirExprKind::ContextReader { .. }
        | HirExprKind::AwaitTask { .. }
        | HirExprKind::MachineFieldAccess { .. }
        | HirExprKind::MachineEventFieldAccess { .. }
        | HirExprKind::Yield { value: None, .. }
        | HirExprKind::Continue { .. }
        | HirExprKind::Unsupported(_) => {}
    }
}

/// One-token description of a parser `Expr` shape, used by
/// `SelectArmNotSealedForm` diagnostic notes. Intentionally coarse — the
/// goal is to tell the user "you wrote a literal where a sealed form
/// belongs", not to echo the expression back at them.
fn describe_select_source_shape(expr: &Expr) -> String {
    match expr {
        Expr::Literal(_) => "literal".into(),
        Expr::Identifier(_) => "identifier".into(),
        Expr::Binary { .. } => "binary expression".into(),
        Expr::Block(_) => "block".into(),
        Expr::If { .. } => "if expression".into(),
        Expr::Select { .. } => "nested select".into(),
        Expr::Join(_) => "join expression".into(),
        Expr::FieldAccess { .. } => "field access".into(),
        Expr::Index { .. } => "index expression".into(),
        Expr::Range { .. } => "range expression".into(),
        Expr::Cast { .. } => "cast expression".into(),
        Expr::Timeout { .. } => "timeout expression".into(),
        Expr::UnsafeBlock(_) => "unsafe block".into(),
        Expr::Yield(_) => "yield expression".into(),
        Expr::This => "this".into(),
        _ => "expression".into(),
    }
}

// ── Target architecture gates ────────────────────────────────────────────────

/// Pre-pass that rejects coroutine-dependent constructs (actors, tasks) on
/// unsupported targets and blocking channel recv on wasm32.
///
/// Fail-closed per slepp A222: emit fatal diagnostics at compile time instead
/// of allowing runtime panics at `hew-runtime/src/coro.rs:391/:492` (P0.1/P0.2)
/// or `hew-runtime/src/lib.rs:378/:391` (P0.3/P0.4).
fn check_target_gates(ctx: &mut LowerCtx, program: &Program) {
    // P0.1 + P0.2: Actor runtime ABI gate.
    // If target is NOT in {x86_64, aarch64}, reject actors/supervisors.
    // Suspension itself uses target-agnostic LLVM llvm.coro.*; the gap is the
    // actor runtime ABI (scheduler, mailbox, supervisor restart machinery).
    if !matches!(ctx.target_arch, TargetArch::X86_64 | TargetArch::Aarch64) {
        check_coroutine_gate(ctx, program);
    }

    // NB: P0.3 + P0.4 (wasm blocking channel recv) intentionally NOT dispatched
    // here. They are dispatched separately AFTER the type pre-pass's
    // diagnostics.clear() at line ~921 so the gate's diagnostics survive into
    // LowerOutput. See check_wasm_blocking_recv_gate at the post-clear call
    // site for the dispatch. The coroutine gate IS duplicated by inline
    // Item::Actor / Item::Supervisor checks in the source-order pass below; the
    // wasm gate has no such inline counterpart so the survival-ordering is
    // essential.
}

/// Check for actor/supervisor usage on targets without the actor runtime ABI.
fn check_coroutine_gate(ctx: &mut LowerCtx, program: &Program) {
    let target_name = match ctx.target_arch {
        TargetArch::Wasm32 => "wasm32",
        TargetArch::Other => "unsupported",
        // x86_64/aarch64 shouldn't reach here (guarded by caller)
        _ => "other",
    };

    for (item, span) in &program.items {
        match item {
            Item::Actor(actor_decl) => {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::TargetCoroutineUnsupported {
                        target_arch: target_name.to_string(),
                        construct: "actor decl".to_string(),
                    },
                    span.clone(),
                    format!(
                        "actor `{}` cannot be compiled for target `{}`: \
                         the actor runtime ABI (scheduler, mailbox) is only \
                         available on x86_64 and aarch64",
                        actor_decl.name, target_name
                    ),
                ));
            }
            Item::Supervisor(supervisor_decl) => {
                // Supervisors spawn actors, so they're also coroutine-dependent
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::TargetCoroutineUnsupported {
                        target_arch: target_name.to_string(),
                        construct: "supervisor decl".to_string(),
                    },
                    span.clone(),
                    format!(
                        "supervisor `{}` cannot be compiled for target `{}`: \
                         supervisors require the actor runtime ABI and supervisor \
                         restart machinery, only available on x86_64 and aarch64",
                        supervisor_decl.name, target_name
                    ),
                ));
            }
            // TODO: When `scope{}` and `fork` are surface syntax, add checks here
            _ => {}
        }
    }

    // TODO: Add checks for:
    // - `scope{}` blocks (when they exist in surface AST)
    // - `fork` statements (when they exist in surface AST)
    // - `await` expressions (when they appear outside of existing actor/scope)
    // For now, actors and supervisors are the only coroutine entry points.
}

/// Check for unsupported supervisor child accessor patterns (P1-C).
///
/// Reads the checker side-table `supervisor_child_slots` (keyed by the
/// `SpanKey` of the `sup.child_name` field-access expression) and emits
/// fail-closed diagnostics for two unsupported v0.5 forms:
///
/// 1. **Pool child accessor** — `slot.kind == ChildKind::Pool`. Routing pool
///    slots requires the `hew_supervisor_pool_route` ABI call (v0.6).
///    Currently fail-closed at `hew-mir/src/lower.rs:4413` as
///    `NotYetImplemented`.
///
/// 2. **Nested supervisor accessor** — `slot.kind == ChildKind::Static` AND
///    the declared child type is itself a supervisor (i.e. the result type
///    is `LocalPid<Supervisor>`). Multi-segment supervisor dotted access
///    requires the `hew_supervisor_nested_get` ABI call (v0.6). Currently
///    fail-closed at `hew-mir/src/lower.rs:4443` as `NotYetImplemented`.
///
/// The set of supervisor names is built by scanning `program.items` for
/// `Item::Supervisor` declarations — this is the cheapest source of truth
/// available at this dispatch point and matches the precedent set by other
/// HIR pre-passes that scan `program.items` directly rather than requiring
/// the checker to publish a new side-table.
///
/// LESSONS P0 `boundary-fail-closed` / slepp A222: surface the gap as a
/// compile-time diagnostic rather than letting the program reach a MIR
/// `NotYetImplemented` trap (or worse, a runtime panic).
fn check_supervisor_child_accessor_gates(
    ctx: &mut LowerCtx,
    program: &Program,
    tc_output: &TypeCheckOutput,
) {
    // Build the set of supervisor names from program items. Cheap one-pass
    // scan; no need to depend on a new TypeCheckOutput side-table.
    let supervisor_names: std::collections::HashSet<&str> = program
        .items
        .iter()
        .filter_map(|(item, _)| match item {
            Item::Supervisor(decl) => Some(decl.name.as_str()),
            _ => None,
        })
        .collect();

    // Iterate checker side-table. ChildSlot now carries authoritative
    // `supervisor` and `child_name` set by the checker at construction —
    // no reverse lookup, no string-identifier fragility (A39 invariant),
    // and two children of the same actor type are correctly disambiguated.
    for (span_key, slot) in &tc_output.supervisor_child_slots {
        let span = span_key.start..span_key.end;
        let sup_name = slot.supervisor.as_str();
        let child_name = slot.child_name.as_str();

        match slot.kind {
            ChildKind::Pool => {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::SupervisorPoolChildAccessorUnsupported {
                        supervisor: sup_name.to_string(),
                        child: child_name.to_string(),
                    },
                    span,
                    format!(
                        "pool child accessor `{sup_name}.{child_name}` is not yet \
                         implemented: pool slot routing requires the \
                         `hew_supervisor_pool_route` ABI call which lands in v0.6. \
                         Use a static child (`child {child_name}: {ty}`) if the \
                         pool semantics are not required.",
                        ty = slot.child_ty,
                    ),
                ));
            }
            ChildKind::Static => {
                // Nested supervisor: the declared child type is itself a
                // supervisor. The result of the field access is
                // `LocalPid<NestedSupervisor>`, which the MIR lowering
                // currently rejects as `NotYetImplemented` because the
                // multi-hop ABI call (`hew_supervisor_nested_get`) is not
                // yet implemented.
                if supervisor_names.contains(slot.child_ty.as_str()) {
                    ctx.diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::NestedSupervisorAccessorUnsupported {
                            supervisor: sup_name.to_string(),
                            child: child_name.to_string(),
                            nested_supervisor: slot.child_ty.clone(),
                        },
                        span,
                        format!(
                            "nested supervisor accessor `{sup_name}.{child_name}` \
                             (result type `LocalPid<{nested}>`) is not yet \
                             implemented: multi-segment supervisor dotted access \
                             requires the `hew_supervisor_nested_get` ABI call \
                             which lands in v0.6.",
                            nested = slot.child_ty,
                        ),
                    ));
                }
            }
        }
    }
}

/// Check for blocking channel recv usage on wasm32 (P0.3 + P0.4).
///
/// `hew_channel_recv` and `hew_channel_recv_int` in `hew-runtime/src/lib.rs:378`
/// and `:391` are `unreachable!()` stubs on wasm32 — the underlying coroutine
/// suspension primitives aren't available. Detect `.recv()` method calls at
/// HIR-lower time and emit `BlockingChannelRecvUnsupportedOnWasm` so the
/// program fails to compile instead of trapping at runtime.
///
/// `.try_recv()` is allowed because it never suspends.
fn check_wasm_blocking_recv_gate(ctx: &mut LowerCtx, program: &Program) {
    for (item, _span) in &program.items {
        match item {
            Item::Function(fn_decl) => {
                scan_block_for_blocking_recv(&fn_decl.body, &mut ctx.diagnostics);
            }
            Item::Actor(actor_decl) => {
                if let Some(init) = &actor_decl.init {
                    scan_block_for_blocking_recv(&init.body, &mut ctx.diagnostics);
                }
                for recv_fn in &actor_decl.receive_fns {
                    scan_block_for_blocking_recv(&recv_fn.body, &mut ctx.diagnostics);
                }
                for method in &actor_decl.methods {
                    scan_block_for_blocking_recv(&method.body, &mut ctx.diagnostics);
                }
            }
            Item::Impl(impl_decl) => {
                for method in &impl_decl.methods {
                    scan_block_for_blocking_recv(&method.body, &mut ctx.diagnostics);
                }
            }
            // A242 invariant: HIR pre-pass walkers that visit user expression
            // bodies in Item::Function/Item::Actor/Item::Impl MUST also visit ALL
            // FOUR Item::Machine positions:
            //   1. each state's `entry` block
            //   2. each state's `exit` block
            //   3. each transition's `guard` expression (if any)
            //   4. each transition's `body` expression (action)
            // Partial coverage (e.g. transitions but not states) is a BLOCK in
            // cross-eco review.
            Item::Machine(machine) => {
                for state in &machine.states {
                    if let Some(entry) = &state.entry {
                        scan_block_for_blocking_recv(entry, &mut ctx.diagnostics);
                    }
                    if let Some(exit) = &state.exit {
                        scan_block_for_blocking_recv(exit, &mut ctx.diagnostics);
                    }
                }
                for transition in &machine.transitions {
                    if let Some(guard) = &transition.guard {
                        scan_expr_for_blocking_recv(&guard.0, &mut ctx.diagnostics);
                    }
                    scan_expr_for_blocking_recv(&transition.body.0, &mut ctx.diagnostics);
                }
            }
            // Const, Trait, Supervisor, Struct, Enum, Use, Module, etc.
            // do not carry user expression bodies that can call `.recv()`.
            _ => {}
        }
    }
}

fn scan_block_for_blocking_recv(
    block: &hew_parser::ast::Block,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    for (stmt, _) in &block.stmts {
        scan_stmt_for_blocking_recv(stmt, diagnostics);
    }
    if let Some(trailing) = &block.trailing_expr {
        scan_expr_for_blocking_recv(&trailing.0, diagnostics);
    }
}

#[allow(
    clippy::match_same_arms,
    reason = "explicit per-Stmt-variant arms read more clearly than collapsed or-patterns for this walker"
)]
fn scan_stmt_for_blocking_recv(stmt: &hew_parser::ast::Stmt, diagnostics: &mut Vec<HirDiagnostic>) {
    match stmt {
        Stmt::Let { value: Some(v), .. } | Stmt::Var { value: Some(v), .. } => {
            scan_expr_for_blocking_recv(&v.0, diagnostics);
        }
        Stmt::Assign { target, value, .. } => {
            scan_expr_for_blocking_recv(&target.0, diagnostics);
            scan_expr_for_blocking_recv(&value.0, diagnostics);
        }
        Stmt::Expression(e) => {
            scan_expr_for_blocking_recv(&e.0, diagnostics);
        }
        Stmt::Return(Some(e)) => {
            scan_expr_for_blocking_recv(&e.0, diagnostics);
        }
        Stmt::Defer(e) => {
            scan_expr_for_blocking_recv(&e.0, diagnostics);
        }
        Stmt::Break { value: Some(v), .. } => {
            scan_expr_for_blocking_recv(&v.0, diagnostics);
        }
        Stmt::WhileLet { expr, body, .. } => {
            scan_expr_for_blocking_recv(&expr.0, diagnostics);
            scan_block_for_blocking_recv(body, diagnostics);
        }
        Stmt::If {
            condition,
            then_block,
            else_block,
        } => {
            scan_expr_for_blocking_recv(&condition.0, diagnostics);
            scan_block_for_blocking_recv(then_block, diagnostics);
            if let Some(eb) = else_block {
                scan_else_block_for_blocking_recv(eb, diagnostics);
            }
        }
        Stmt::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_blocking_recv(&expr.0, diagnostics);
            scan_block_for_blocking_recv(body, diagnostics);
            if let Some(eb) = else_body {
                scan_block_for_blocking_recv(eb, diagnostics);
            }
        }
        Stmt::Match { scrutinee, arms } => {
            scan_expr_for_blocking_recv(&scrutinee.0, diagnostics);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_blocking_recv(&g.0, diagnostics);
                }
                scan_expr_for_blocking_recv(&arm.body.0, diagnostics);
            }
        }
        Stmt::Loop { body, .. } => scan_block_for_blocking_recv(body, diagnostics),
        Stmt::For { iterable, body, .. } => {
            scan_expr_for_blocking_recv(&iterable.0, diagnostics);
            scan_block_for_blocking_recv(body, diagnostics);
        }
        Stmt::While {
            condition, body, ..
        } => {
            scan_expr_for_blocking_recv(&condition.0, diagnostics);
            scan_block_for_blocking_recv(body, diagnostics);
        }
        // Stmt::Break, Stmt::Continue, Stmt::Return(None), and any other leaf
        // statements carry no sub-expression to scan.
        _ => {}
    }
}

fn scan_else_block_for_blocking_recv(
    eb: &hew_parser::ast::ElseBlock,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    if let Some(stmt) = &eb.if_stmt {
        scan_stmt_for_blocking_recv(&stmt.0, diagnostics);
    }
    if let Some(b) = &eb.block {
        scan_block_for_blocking_recv(b, diagnostics);
    }
}

/// Recursively walk an expression tree looking for `.recv()` method calls.
/// Mirrors the shape of `scan_expr_for_private_refs`.
#[allow(
    clippy::too_many_lines,
    reason = "exhaustive Expr-variant walker mirrors scan_expr_for_private_refs above"
)]
fn scan_expr_for_blocking_recv(expr: &Expr, diagnostics: &mut Vec<HirDiagnostic>) {
    match expr {
        Expr::MethodCall {
            receiver,
            method,
            args,
        } => {
            scan_expr_for_blocking_recv(&receiver.0, diagnostics);
            for arg in args {
                scan_expr_for_blocking_recv(&arg.expr().0, diagnostics);
            }
            // `.recv()` is the blocking form; `.try_recv()` is allowed because
            // it does not suspend. Note: at HIR-lower time we don't yet know
            // the receiver's resolved type, so syntactic-match on the method
            // name is what we have. False positives would require a user
            // method literally named `recv` on a non-channel type — flagged as
            // a known limitation; resolved-type narrowing can be added in a
            // followup if it materially matters.
            if method == "recv" {
                diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::BlockingChannelRecvUnsupportedOnWasm {
                        construct: ".recv()".to_string(),
                    },
                    0..0,
                    "blocking channel `.recv()` is not supported on wasm32: \
                     coroutine suspension primitives are unavailable on this \
                     target. Use `.try_recv()` for the non-blocking variant."
                        .to_string(),
                ));
            }
        }
        Expr::Call { function, args, .. } => {
            scan_expr_for_blocking_recv(&function.0, diagnostics);
            for arg in args {
                scan_expr_for_blocking_recv(&arg.expr().0, diagnostics);
            }
        }
        Expr::Binary { left, right, .. } => {
            scan_expr_for_blocking_recv(&left.0, diagnostics);
            scan_expr_for_blocking_recv(&right.0, diagnostics);
        }
        Expr::Unary { operand, .. } => scan_expr_for_blocking_recv(&operand.0, diagnostics),
        Expr::Tuple(es) | Expr::Array(es) | Expr::Join(es) => {
            for e in es {
                scan_expr_for_blocking_recv(&e.0, diagnostics);
            }
        }
        Expr::ArrayRepeat { value, count } => {
            scan_expr_for_blocking_recv(&value.0, diagnostics);
            scan_expr_for_blocking_recv(&count.0, diagnostics);
        }
        Expr::Block(b)
        | Expr::Scope { body: b }
        | Expr::ForkBlock { body: b }
        | Expr::GenBlock { body: b } => {
            scan_block_for_blocking_recv(b, diagnostics);
        }
        Expr::If {
            condition,
            then_block,
            else_block,
            ..
        } => {
            scan_expr_for_blocking_recv(&condition.0, diagnostics);
            scan_expr_for_blocking_recv(&then_block.0, diagnostics);
            if let Some(e) = else_block {
                scan_expr_for_blocking_recv(&e.0, diagnostics);
            }
        }
        Expr::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_blocking_recv(&expr.0, diagnostics);
            scan_block_for_blocking_recv(body, diagnostics);
            if let Some(b) = else_body {
                scan_block_for_blocking_recv(b, diagnostics);
            }
        }
        Expr::Match { scrutinee, arms } => {
            scan_expr_for_blocking_recv(&scrutinee.0, diagnostics);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_blocking_recv(&g.0, diagnostics);
                }
                scan_expr_for_blocking_recv(&arm.body.0, diagnostics);
            }
        }
        Expr::Lambda { body, .. } | Expr::SpawnLambdaActor { body, .. } => {
            scan_expr_for_blocking_recv(&body.0, diagnostics);
        }
        Expr::Spawn { target, args, .. } => {
            scan_expr_for_blocking_recv(&target.0, diagnostics);
            for (_, v) in args {
                scan_expr_for_blocking_recv(&v.0, diagnostics);
            }
        }
        Expr::ScopeDeadline { duration, body } => {
            scan_expr_for_blocking_recv(&duration.0, diagnostics);
            scan_block_for_blocking_recv(body, diagnostics);
        }
        Expr::ForkChild { expr, .. } | Expr::Cast { expr, .. } => {
            scan_expr_for_blocking_recv(&expr.0, diagnostics);
        }
        Expr::StructInit { fields, base, .. } => {
            for (_, v) in fields {
                scan_expr_for_blocking_recv(&v.0, diagnostics);
            }
            if let Some(b) = base {
                scan_expr_for_blocking_recv(&b.0, diagnostics);
            }
        }
        Expr::MapLiteral { entries } => {
            for (k, v) in entries {
                scan_expr_for_blocking_recv(&k.0, diagnostics);
                scan_expr_for_blocking_recv(&v.0, diagnostics);
            }
        }
        Expr::InterpolatedString(parts) => {
            for part in parts {
                if let hew_parser::ast::StringPart::Expr(e) = part {
                    scan_expr_for_blocking_recv(&e.0, diagnostics);
                }
            }
        }
        Expr::Select { arms, timeout } => {
            for arm in arms {
                scan_expr_for_blocking_recv(&arm.source.0, diagnostics);
                scan_expr_for_blocking_recv(&arm.body.0, diagnostics);
            }
            if let Some(t) = timeout {
                scan_expr_for_blocking_recv(&t.duration.0, diagnostics);
                scan_expr_for_blocking_recv(&t.body.0, diagnostics);
            }
        }
        Expr::Timeout { expr, duration } => {
            scan_expr_for_blocking_recv(&expr.0, diagnostics);
            scan_expr_for_blocking_recv(&duration.0, diagnostics);
        }
        Expr::UnsafeBlock(b) => scan_block_for_blocking_recv(b, diagnostics),
        Expr::FieldAccess { object, .. } | Expr::PostfixTry(object) | Expr::Await(object) => {
            scan_expr_for_blocking_recv(&object.0, diagnostics);
        }
        Expr::Index { object, index } => {
            scan_expr_for_blocking_recv(&object.0, diagnostics);
            scan_expr_for_blocking_recv(&index.0, diagnostics);
        }
        Expr::Is { lhs, rhs } => {
            scan_expr_for_blocking_recv(&lhs.0, diagnostics);
            scan_expr_for_blocking_recv(&rhs.0, diagnostics);
        }
        Expr::Range { start, end, .. } => {
            if let Some(s) = start {
                scan_expr_for_blocking_recv(&s.0, diagnostics);
            }
            if let Some(e) = end {
                scan_expr_for_blocking_recv(&e.0, diagnostics);
            }
        }
        Expr::Yield(Some(e)) => scan_expr_for_blocking_recv(&e.0, diagnostics),
        Expr::MachineEmit { fields, .. } => {
            for (_, v) in fields {
                scan_expr_for_blocking_recv(&v.0, diagnostics);
            }
        }
        // Leaf nodes (Identifier, literals, etc.) and any other Expr variant
        // without sub-expressions: nothing to scan.
        _ => {}
    }
}

// ── FC-P1-A1: Task/fork/deadline gates ───────────────────────────────────────

/// FC-P1-A1 HIR pre-pass gate — task/fork/deadline construct validation.
/// Walks the entire program AST looking for `SpawnedCall`, `ForkChild`, `ForkBlock`,
/// `ScopeDeadline`, and `AwaitTask` expressions. Emits fail-closed diagnostics for
/// unsupported shapes before MIR lowering (moving the gates up from the 10 P1
/// sites at hew-mir/src/lower.rs:7623-7871).
fn check_task_gates(ctx: &mut LowerCtx, program: &Program) {
    for (item, _span) in &program.items {
        match item {
            Item::Function(fn_decl) => {
                scan_block_for_task_gates(&fn_decl.body, ctx, program);
            }
            Item::Actor(actor_decl) => {
                if let Some(init) = &actor_decl.init {
                    scan_block_for_task_gates(&init.body, ctx, program);
                }
                for recv_fn in &actor_decl.receive_fns {
                    scan_block_for_task_gates(&recv_fn.body, ctx, program);
                }
                for method in &actor_decl.methods {
                    scan_block_for_task_gates(&method.body, ctx, program);
                }
            }
            Item::Impl(impl_decl) => {
                for method in &impl_decl.methods {
                    scan_block_for_task_gates(&method.body, ctx, program);
                }
            }
            // A242 invariant: HIR pre-pass walkers that visit user expression
            // bodies in Item::Function/Item::Actor/Item::Impl MUST also visit ALL
            // FOUR Item::Machine positions:
            //   1. each state's `entry` block
            //   2. each state's `exit` block
            //   3. each transition's `guard` expression (if any)
            //   4. each transition's `body` expression (action)
            // Partial coverage (e.g. transitions but not states) is a BLOCK in
            // cross-eco review.
            Item::Machine(machine) => {
                for state in &machine.states {
                    if let Some(entry) = &state.entry {
                        scan_block_for_task_gates(entry, ctx, program);
                    }
                    if let Some(exit) = &state.exit {
                        scan_block_for_task_gates(exit, ctx, program);
                    }
                }
                for transition in &machine.transitions {
                    if let Some(guard) = &transition.guard {
                        scan_expr_for_task_gates(&guard.0, &guard.1, ctx, program);
                    }
                    scan_expr_for_task_gates(&transition.body.0, &transition.body.1, ctx, program);
                }
            }
            // Const, Trait, Supervisor, Struct, Enum, Use, Module, etc.
            // do not carry user expression bodies with task spawns.
            _ => {}
        }
    }
}

// ── FC-P1-A3: Supervisor spawn args gate ─────────────────────────────────────

/// Pre-pass that rejects `spawn AppSupervisor(...)` with non-empty init args.
///
/// Supervisors take their child specs declaratively (in the `supervisor`
/// declaration body); spawn-time init args have no defined semantics. The
/// checker already rejects supervisor *declarations* that take init params,
/// but this HIR gate is defense-in-depth: it catches any future surface that
/// could reach MIR (`hew-mir/src/lower.rs:8852`) before the checker guard does.
///
/// Per slepp A222 (fail-closed): surface a HIR fatal diagnostic at compile
/// time instead of a `NotYetImplemented` runtime-style diagnostic at MIR-
/// lowering time.
/// Structured supervisor registry consumed by the spawn-args gate.
///
/// Replaces the FC-P1-A3 v1 single-`HashSet<String>` approach (which lost
/// module context and produced both false negatives — `spawn other.Sup(args)`
/// on an imported supervisor slipped through — and false positives —
/// `spawn other.Root(args)` was rejected when the local `Root` was a
/// supervisor but `other.Root` was an actor). The structured form preserves
/// the spawn site's module qualifier so the lookup is module-scoped, matching
/// the checker's own resolution discipline.
///
/// Discharges the A237 string-fragility pattern (see LESSONS
/// `string-identifier-fragility-vs-structured-resolution`).
struct SupervisorRegistry {
    /// Supervisor names declared at the root program level. Consulted for
    /// bare-identifier spawn targets (`spawn Sup(args)`).
    root: std::collections::HashSet<String>,
    /// Supervisor names declared in each imported module, keyed by the
    /// module's short name (last path segment). Consulted for module-qualified
    /// spawn targets (`spawn module.Sup(args)`).
    by_module: std::collections::HashMap<String, std::collections::HashSet<String>>,
}

impl SupervisorRegistry {
    /// True iff the program declares no supervisors anywhere (root or any
    /// module). When true, the gate walk can short-circuit.
    fn is_empty(&self) -> bool {
        self.root.is_empty()
            && self
                .by_module
                .values()
                .all(std::collections::HashSet::is_empty)
    }
}

/// Collect supervisor declarations from the root program AND every module in
/// the program's `module_graph` (when present). Module-graph coverage is
/// required to reject `spawn other.MyServiceSup(args)` for supervisors
/// declared in imported modules.
fn collect_supervisor_registry(program: &Program) -> SupervisorRegistry {
    let mut root: std::collections::HashSet<String> = std::collections::HashSet::new();
    for (item, _) in &program.items {
        if let Item::Supervisor(decl) = item {
            root.insert(decl.name.clone());
        }
    }
    let mut by_module: std::collections::HashMap<String, std::collections::HashSet<String>> =
        std::collections::HashMap::new();
    if let Some(mg) = &program.module_graph {
        for (mod_id, module) in &mg.modules {
            if *mod_id == mg.root {
                continue;
            }
            let module_short = mod_id.path.last().map_or("", String::as_str);
            if module_short.is_empty() {
                continue;
            }
            let entry = by_module.entry(module_short.to_string()).or_default();
            for (item, _) in &module.items {
                if let Item::Supervisor(decl) = item {
                    entry.insert(decl.name.clone());
                }
            }
        }
    }
    SupervisorRegistry { root, by_module }
}

fn check_supervisor_spawn_gate(ctx: &mut LowerCtx, program: &Program) {
    let registry = collect_supervisor_registry(program);
    if registry.is_empty() {
        // No supervisors declared anywhere → no spawn site can target one;
        // skip the walk entirely.
        return;
    }

    // Walk root items. `current_module = None` selects the root supervisor
    // set for bare-name spawn targets.
    for (item, _span) in &program.items {
        scan_item_for_supervisor_spawn(item, None, &registry, &mut ctx.diagnostics);
    }
    // Walk every non-root module in the program's module graph. A supervisor
    // spawn with args inside a function/actor/impl/machine body in an imported
    // module must trigger the gate the same way the root does (A242: pre-pass
    // walkers must visit every body-bearing position in every module they're
    // logically scoped to, not just the root program).
    //
    // `current_module = Some(short_name)` scopes the bare-identifier lookup
    // to that module's own supervisor set. Bare identifiers in module bodies
    // resolve under the module's local scope (cf. checker's resolution
    // rules — root names are NOT auto-imported into modules; a module wanting
    // to spawn a root supervisor must reach it via a module-qualified path,
    // which dispatches through `Expr::FieldAccess` below). Without this
    // scoping we'd both (a) miss `spawn LocalSup(args)` inside an imported
    // module whose `LocalSup` isn't declared at root (false-negative) and
    // (b) reject `spawn Foo(args)` inside an imported module that happens
    // to share a name with a root-declared supervisor even though the
    // module's `Foo` is something else entirely (false-positive). Both
    // failure modes are documented in the rev2 cross-eco finding.
    if let Some(mg) = &program.module_graph {
        for (mod_id, module) in &mg.modules {
            if *mod_id == mg.root {
                continue;
            }
            let module_short = mod_id.path.last().map(String::as_str);
            for (item, _) in &module.items {
                scan_item_for_supervisor_spawn(item, module_short, &registry, &mut ctx.diagnostics);
            }
        }
    }
}

fn scan_block_for_task_gates(
    block: &hew_parser::ast::Block,
    ctx: &mut LowerCtx,
    program: &Program,
) {
    for (stmt, _) in &block.stmts {
        scan_stmt_for_task_gates(stmt, ctx, program);
    }
    if let Some(trailing) = &block.trailing_expr {
        scan_expr_for_task_gates(&trailing.0, &trailing.1, ctx, program);
    }
}

#[allow(
    clippy::match_same_arms,
    reason = "explicit per-Stmt-variant arms read more clearly than collapsed or-patterns for this walker"
)]
fn scan_stmt_for_task_gates(stmt: &hew_parser::ast::Stmt, ctx: &mut LowerCtx, program: &Program) {
    match stmt {
        Stmt::Let { value: Some(v), .. } | Stmt::Var { value: Some(v), .. } => {
            scan_expr_for_task_gates(&v.0, &v.1, ctx, program);
        }
        Stmt::Assign { target, value, .. } => {
            scan_expr_for_task_gates(&target.0, &target.1, ctx, program);
            scan_expr_for_task_gates(&value.0, &value.1, ctx, program);
        }
        Stmt::Expression(e) => {
            scan_expr_for_task_gates(&e.0, &e.1, ctx, program);
        }
        Stmt::Return(Some(e)) => {
            scan_expr_for_task_gates(&e.0, &e.1, ctx, program);
        }
        Stmt::Defer(e) => {
            scan_expr_for_task_gates(&e.0, &e.1, ctx, program);
        }
        Stmt::Break { value: Some(v), .. } => {
            scan_expr_for_task_gates(&v.0, &v.1, ctx, program);
        }
        Stmt::WhileLet { expr, body, .. } => {
            scan_expr_for_task_gates(&expr.0, &expr.1, ctx, program);
            scan_block_for_task_gates(body, ctx, program);
        }
        Stmt::If {
            condition,
            then_block,
            else_block,
        } => {
            scan_expr_for_task_gates(&condition.0, &condition.1, ctx, program);
            scan_block_for_task_gates(then_block, ctx, program);
            if let Some(eb) = else_block {
                scan_else_block_for_task_gates(eb, ctx, program);
            }
        }
        Stmt::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_task_gates(&expr.0, &expr.1, ctx, program);
            scan_block_for_task_gates(body, ctx, program);
            if let Some(eb) = else_body {
                scan_block_for_task_gates(eb, ctx, program);
            }
        }
        Stmt::Match { scrutinee, arms } => {
            scan_expr_for_task_gates(&scrutinee.0, &scrutinee.1, ctx, program);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_task_gates(&g.0, &g.1, ctx, program);
                }
                scan_expr_for_task_gates(&arm.body.0, &arm.body.1, ctx, program);
            }
        }
        Stmt::Loop { body, .. } => scan_block_for_task_gates(body, ctx, program),
        Stmt::For { iterable, body, .. } => {
            scan_expr_for_task_gates(&iterable.0, &iterable.1, ctx, program);
            scan_block_for_task_gates(body, ctx, program);
        }
        Stmt::While {
            condition, body, ..
        } => {
            scan_expr_for_task_gates(&condition.0, &condition.1, ctx, program);
            scan_block_for_task_gates(body, ctx, program);
        }
        // Stmt::Break, Stmt::Continue, Stmt::Return(None), and any other leaf
        // statements carry no sub-expression to scan.
        _ => {}
    }
}

fn scan_else_block_for_task_gates(
    eb: &hew_parser::ast::ElseBlock,
    ctx: &mut LowerCtx,
    program: &Program,
) {
    if let Some(stmt) = &eb.if_stmt {
        scan_stmt_for_task_gates(&stmt.0, ctx, program);
    }
    if let Some(b) = &eb.block {
        scan_block_for_task_gates(b, ctx, program);
    }
}

/// Recursively walk an expression tree looking for task/fork/deadline constructs.
/// Mirrors the shape of `scan_expr_for_blocking_recv`.
#[allow(
    clippy::too_many_lines,
    reason = "exhaustive Expr-variant walker mirrors scan_expr_for_blocking_recv above"
)]
fn scan_expr_for_task_gates(expr: &Expr, span: &Span, ctx: &mut LowerCtx, program: &Program) {
    match expr {
        // FC-P1-A1 sites: spawn/fork child and fork block
        Expr::ForkChild { expr: child, .. } => {
            check_fork_child_shape(child, span, ctx, program);
            scan_expr_for_task_gates(&child.0, &child.1, ctx, program);
        }
        Expr::ForkBlock { body } => {
            check_fork_block_shape(body, span, ctx, program);
            scan_block_for_task_gates(body, ctx, program);
        }
        Expr::ScopeDeadline { duration, body } => {
            check_scope_deadline_shape(body, span, ctx);
            scan_expr_for_task_gates(&duration.0, &duration.1, ctx, program);
            scan_block_for_task_gates(body, ctx, program);
        }
        Expr::Await(object) => {
            check_await_task_result(&object.0, &object.1, ctx, program);
            scan_expr_for_task_gates(&object.0, &object.1, ctx, program);
        }
        // Recursive scanning for all other expression variants
        Expr::MethodCall { receiver, args, .. } => {
            scan_expr_for_task_gates(&receiver.0, &receiver.1, ctx, program);
            for arg in args {
                scan_expr_for_task_gates(&arg.expr().0, &arg.expr().1, ctx, program);
            }
        }
        Expr::Call { function, args, .. } => {
            scan_expr_for_task_gates(&function.0, &function.1, ctx, program);
            for arg in args {
                scan_expr_for_task_gates(&arg.expr().0, &arg.expr().1, ctx, program);
            }
        }
        Expr::Binary { left, right, .. } => {
            scan_expr_for_task_gates(&left.0, &left.1, ctx, program);
            scan_expr_for_task_gates(&right.0, &right.1, ctx, program);
        }
        Expr::Unary { operand, .. } => {
            scan_expr_for_task_gates(&operand.0, &operand.1, ctx, program);
        }
        Expr::Tuple(es) | Expr::Array(es) | Expr::Join(es) => {
            for e in es {
                scan_expr_for_task_gates(&e.0, &e.1, ctx, program);
            }
        }
        Expr::ArrayRepeat { value, count } => {
            scan_expr_for_task_gates(&value.0, &value.1, ctx, program);
            scan_expr_for_task_gates(&count.0, &count.1, ctx, program);
        }
        Expr::Block(b) | Expr::Scope { body: b } | Expr::GenBlock { body: b } => {
            scan_block_for_task_gates(b, ctx, program);
        }
        Expr::If {
            condition,
            then_block,
            else_block,
            ..
        } => {
            scan_expr_for_task_gates(&condition.0, &condition.1, ctx, program);
            scan_expr_for_task_gates(&then_block.0, &then_block.1, ctx, program);
            if let Some(e) = else_block {
                scan_expr_for_task_gates(&e.0, &e.1, ctx, program);
            }
        }
        Expr::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_task_gates(&expr.0, &expr.1, ctx, program);
            scan_block_for_task_gates(body, ctx, program);
            if let Some(b) = else_body {
                scan_block_for_task_gates(b, ctx, program);
            }
        }
        Expr::Match { scrutinee, arms } => {
            scan_expr_for_task_gates(&scrutinee.0, &scrutinee.1, ctx, program);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_task_gates(&g.0, &g.1, ctx, program);
                }
                scan_expr_for_task_gates(&arm.body.0, &arm.body.1, ctx, program);
            }
        }
        Expr::Lambda { body, .. } => {
            // Check if this lambda is being spawned (will be checked at call site)
            // Recursively scan the body
            scan_expr_for_task_gates(&body.0, &body.1, ctx, program);
        }
        Expr::SpawnLambdaActor { body, .. } => {
            scan_expr_for_task_gates(&body.0, &body.1, ctx, program);
        }
        Expr::Spawn { target, args, .. } => {
            scan_expr_for_task_gates(&target.0, &target.1, ctx, program);
            for (_, v) in args {
                scan_expr_for_task_gates(&v.0, &v.1, ctx, program);
            }
        }
        Expr::Cast { expr, .. } => {
            scan_expr_for_task_gates(&expr.0, &expr.1, ctx, program);
        }
        Expr::StructInit { fields, base, .. } => {
            for (_, v) in fields {
                scan_expr_for_task_gates(&v.0, &v.1, ctx, program);
            }
            if let Some(b) = base {
                scan_expr_for_task_gates(&b.0, &b.1, ctx, program);
            }
        }
        Expr::MapLiteral { entries } => {
            for (k, v) in entries {
                scan_expr_for_task_gates(&k.0, &k.1, ctx, program);
                scan_expr_for_task_gates(&v.0, &v.1, ctx, program);
            }
        }
        Expr::InterpolatedString(parts) => {
            for part in parts {
                if let hew_parser::ast::StringPart::Expr(e) = part {
                    scan_expr_for_task_gates(&e.0, &e.1, ctx, program);
                }
            }
        }
        Expr::Select { arms, timeout } => {
            for arm in arms {
                scan_expr_for_task_gates(&arm.source.0, &arm.source.1, ctx, program);
                scan_expr_for_task_gates(&arm.body.0, &arm.body.1, ctx, program);
            }
            if let Some(t) = timeout {
                scan_expr_for_task_gates(&t.duration.0, &t.duration.1, ctx, program);
                scan_expr_for_task_gates(&t.body.0, &t.body.1, ctx, program);
            }
        }
        Expr::Timeout { expr, duration } => {
            scan_expr_for_task_gates(&expr.0, &expr.1, ctx, program);
            scan_expr_for_task_gates(&duration.0, &duration.1, ctx, program);
        }
        Expr::UnsafeBlock(b) => scan_block_for_task_gates(b, ctx, program),
        Expr::FieldAccess { object, .. } | Expr::PostfixTry(object) => {
            scan_expr_for_task_gates(&object.0, &object.1, ctx, program);
        }
        Expr::Index { object, index } => {
            scan_expr_for_task_gates(&object.0, &object.1, ctx, program);
            scan_expr_for_task_gates(&index.0, &index.1, ctx, program);
        }
        Expr::Is { lhs, rhs } => {
            scan_expr_for_task_gates(&lhs.0, &lhs.1, ctx, program);
            scan_expr_for_task_gates(&rhs.0, &rhs.1, ctx, program);
        }
        Expr::Range { start, end, .. } => {
            if let Some(s) = start {
                scan_expr_for_task_gates(&s.0, &s.1, ctx, program);
            }
            if let Some(e) = end {
                scan_expr_for_task_gates(&e.0, &e.1, ctx, program);
            }
        }
        Expr::Yield(Some(e)) => scan_expr_for_task_gates(&e.0, &e.1, ctx, program),
        Expr::MachineEmit { fields, .. } => {
            for (_, v) in fields {
                scan_expr_for_task_gates(&v.0, &v.1, ctx, program);
            }
        }
        // Leaf nodes (Identifier, literals, etc.) and any other Expr variant
        // without sub-expressions: nothing to scan.
        _ => {}
    }
}

/// Check fork child (spawned call / fork child) expression shape.
/// Sites: hew-mir/src/lower.rs:7623, 7641 (`TaskSpawn` signature/callee)
/// FC-P1-A1 Blocker 2: Also validates return type is unit.
fn check_fork_child_shape(
    child: &Spanned<Expr>,
    span: &Span,
    ctx: &mut LowerCtx,
    _program: &Program,
) {
    let Expr::Call { function, args, .. } = &child.0 else {
        // Fork child must be a call expression
        ctx.diagnostics.push(HirDiagnostic::new(
            HirDiagnosticKind::TaskSpawnCalleeUnsupported {
                site: ctx.ids.site(),
            },
            span.clone(),
            "fork child must be a direct function call".to_string(),
        ));
        return;
    };

    // Check if it's a direct function or a lambda
    match &function.0 {
        Expr::Identifier(name) => {
            // FC-P1-A1 (revision pass 2, Finding 2): parser emits
            // module-qualified calls as `Expr::Identifier("mod::worker")`
            // (see hew-parser/src/parser.rs:5334-5356), but `fn_registry`
            // is keyed on the bare function name. Use the last `::` segment
            // for the registry lookup so cross-module spawns are accepted.
            let lookup_name = name.rsplit("::").next().unwrap_or(name.as_str());
            // Check if it's a direct module function
            if !ctx.fn_registry.contains_key(lookup_name) {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::TaskSpawnCalleeUnsupported {
                        site: ctx.ids.site(),
                    },
                    span.clone(),
                    format!("fork child callee '{name}' is not a direct module function"),
                ));
                return;
            }
            // FC-P1-A1 (revision pass 2, Finding 1): Non-unit return is
            // VALID at spawn time — see `lower_spawned_call` comment. The
            // await-site gate (MIR :7871) handles non-unit results.
            // Check args are empty
            if !args.is_empty() {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::TaskSpawnSignatureUnsupported {
                        site: ctx.ids.site(),
                    },
                    span.clone(),
                    "spawned function must have zero arguments".to_string(),
                ));
            }
        }
        Expr::Lambda {
            params, body: _, ..
        } => {
            // FC-P1-A1 Blocker 3: Check call args are empty
            if !args.is_empty() {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::SpawnedClosureSignatureUnsupported {
                        site: ctx.ids.site(),
                    },
                    span.clone(),
                    "spawned closure call must have zero arguments".to_string(),
                ));
            }
            // Check lambda has zero params
            if !params.is_empty() {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::SpawnedClosureSignatureUnsupported {
                        site: ctx.ids.site(),
                    },
                    span.clone(),
                    "spawned closure must have zero parameters".to_string(),
                ));
            }
            // FC-P1-A1 Blocker 3: Check closure return type is unit
            // Note: Closure return type validation is deferred to inline lowering checks
            // since expr_types may not be populated in all contexts (e.g., default TypeCheckOutput).
            // The validate_task_spawn_call helper and inline lowering gates will catch this.

            // FC-P1-A1 Blocker 3: Check closure captures are Send
            let span_key = SpanKey::from(&function.1);
            if let Some(captures) = ctx.closure_capture_facts.get(&span_key) {
                for capture in captures {
                    if !capture.is_send {
                        ctx.diagnostics.push(HirDiagnostic::new(
                            HirDiagnosticKind::SpawnedClosureNonSendCapture {
                                site: ctx.ids.site(),
                                capture_name: capture.name.clone(),
                            },
                            span.clone(),
                            format!("spawned closure captures non-Send value '{}'", capture.name),
                        ));
                    }
                }
            }
            // Note: Missing closure_capture_facts is treated as "no captures" (acceptable)
            // since checker only populates this for closures with actual captures.
        }
        _ => {
            ctx.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::TaskSpawnCalleeUnsupported {
                    site: ctx.ids.site(),
                },
                span.clone(),
                "fork child callee must be a direct function or closure".to_string(),
            ));
        }
    }
}

/// Check fork block body shape.
/// Sites: hew-mir/src/lower.rs:7774, 7787, 7799, 7811 (`ForkBlock` body)
fn check_fork_block_shape(
    body: &hew_parser::ast::Block,
    span: &Span,
    ctx: &mut LowerCtx,
    _program: &Program,
) {
    // Check body has exactly one statement OR one trailing expression
    let stmt_count = body.stmts.len();
    let has_trailing = body.trailing_expr.is_some();

    if stmt_count == 0 && !has_trailing {
        ctx.diagnostics.push(HirDiagnostic::new(
            HirDiagnosticKind::ForkBlockBodyUnsupported {
                site: ctx.ids.site(),
                reason: "empty body".to_string(),
            },
            span.clone(),
            "fork block body must contain exactly one direct function call".to_string(),
        ));
        return;
    }

    if stmt_count > 1 || (stmt_count == 1 && has_trailing) {
        ctx.diagnostics.push(HirDiagnostic::new(
            HirDiagnosticKind::ForkBlockBodyUnsupported {
                site: ctx.ids.site(),
                reason: "multi-statement".to_string(),
            },
            span.clone(),
            "fork block body must contain exactly one statement or expression".to_string(),
        ));
        return;
    }

    // Check the single statement/expression is a direct function call
    let call_expr = if stmt_count == 1 {
        match &body.stmts[0].0 {
            Stmt::Expression(e) => Some(&e.0),
            _ => None,
        }
    } else {
        body.trailing_expr.as_ref().map(|e| &e.0)
    };

    if let Some(Expr::Call { function, args, .. }) = call_expr {
        // Must be a direct function identifier
        if let Expr::Identifier(name) = &function.0 {
            // FC-P1-A1 (revision pass 2, Finding 2): strip `mod::` prefix
            // for fn_registry lookup so module-qualified callees resolve.
            let lookup_name = name.rsplit("::").next().unwrap_or(name.as_str());
            if !ctx.fn_registry.contains_key(lookup_name) {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::ForkBlockBodyUnsupported {
                        site: ctx.ids.site(),
                        reason: "not a direct module function".to_string(),
                    },
                    span.clone(),
                    format!("fork block callee '{name}' is not a direct module function"),
                ));
            }
            // FC-P1-A1 (revision pass 2, Finding 1): Non-unit return is
            // VALID at spawn time — see `lower_spawned_call` comment.
            if !args.is_empty() {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::ForkBlockBodyUnsupported {
                        site: ctx.ids.site(),
                        reason: "function has arguments".to_string(),
                    },
                    span.clone(),
                    "fork block function must have zero arguments".to_string(),
                ));
            }
        } else {
            ctx.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::ForkBlockBodyUnsupported {
                    site: ctx.ids.site(),
                    reason: "callee is not a direct function identifier".to_string(),
                },
                span.clone(),
                "fork block body must be a direct function call".to_string(),
            ));
        }
    } else {
        ctx.diagnostics.push(HirDiagnostic::new(
            HirDiagnosticKind::ForkBlockBodyUnsupported {
                site: ctx.ids.site(),
                reason: "not a call expression".to_string(),
            },
            span.clone(),
            "fork block body must be a direct function call".to_string(),
        ));
    }
}

/// Check scope deadline body shape.
/// Site: hew-mir/src/lower.rs:7842 (Deadline body)
fn check_scope_deadline_shape(body: &hew_parser::ast::Block, span: &Span, ctx: &mut LowerCtx) {
    // Deadline body must be empty
    if !body.stmts.is_empty() || body.trailing_expr.is_some() {
        ctx.diagnostics.push(HirDiagnostic::new(
            HirDiagnosticKind::DeadlineBodyUnsupported {
                site: ctx.ids.site(),
            },
            span.clone(),
            "deadline body must be empty (syntax sugar for timeout-only scope)".to_string(),
        ));
    }
}

/// Check await task result type.
/// Site: hew-mir/src/lower.rs:7871 (`AwaitTask` result)
fn check_await_task_result(_expr: &Expr, span: &Span, ctx: &mut LowerCtx, _program: &Program) {
    // Look up the type of the awaited expression
    let span_key = SpanKey::from(span);
    if let Some(hew_types::Ty::Named { name, args, .. }) = ctx.expr_types.get(&span_key) {
        // Check if it's a Task<T> where T != unit
        if name == "Task" && !args.is_empty() && !matches!(args[0], hew_types::Ty::Unit) {
            ctx.diagnostics.push(HirDiagnostic::new(
                HirDiagnosticKind::AwaitTaskResultUnsupported {
                    site: ctx.ids.site(),
                },
                span.clone(),
                "awaiting task with non-unit result is not yet supported".to_string(),
            ));
        }
    }
}

// ── Actor send unit-handler gate (FC-P1-A2) ──────────────────────────────────

/// HIR pre-pass that rejects fire-and-forget actor sends to non-unit handlers.
///
/// The MIR layer carries a defense-in-depth check at `hew-mir/src/lower.rs:8477`
/// (`ActorSendRequiresUnitHandler`). Per slepp A222 the user-visible failure
/// belongs at compile-time; this gate surfaces the same constraint as a HIR
/// diagnostic, mirroring `check_wasm_blocking_recv_gate` (FC-P0).
///
/// Predicate: an `Expr::MethodCall` named `send` whose receiver type is
/// `LocalPid<Actor>` or `ActorRef<Actor>` and whose argument shape matches a
/// receive handler in `actor_protocol_descriptors[Actor]` with `return_ty`
/// other than `ResolvedTy::Unit`. Unmatched handler names fall through silently
/// (defense-in-depth — the type-check pass owns the "unknown method" error,
/// not this gate).
fn check_actor_send_gates(ctx: &mut LowerCtx, program: &Program) {
    let LowerCtx {
        ref mut diagnostics,
        ref expr_types,
        ref actor_protocol_descriptors,
        ..
    } = *ctx;
    let mut gate_ctx = ActorSendGateCtx {
        expr_types,
        actor_protocol_descriptors,
        diagnostics,
    };
    for (item, _span) in &program.items {
        match item {
            Item::Function(fn_decl) => {
                scan_block_for_actor_send(&fn_decl.body, &mut gate_ctx);
            }
            Item::Actor(actor_decl) => {
                if let Some(init) = &actor_decl.init {
                    scan_block_for_actor_send(&init.body, &mut gate_ctx);
                }
                for recv_fn in &actor_decl.receive_fns {
                    scan_block_for_actor_send(&recv_fn.body, &mut gate_ctx);
                }
                for method in &actor_decl.methods {
                    scan_block_for_actor_send(&method.body, &mut gate_ctx);
                }
            }
            Item::Impl(impl_decl) => {
                for method in &impl_decl.methods {
                    scan_block_for_actor_send(&method.body, &mut gate_ctx);
                }
            }
            Item::Machine(machine_decl) => {
                // Machines carry user expression bodies in three places that
                // HIR lowers: per-state `entry` / `exit` blocks, transition
                // guards, and transition bodies (`hew-hir/src/lower.rs`
                // ~L4129 entry/exit; ~L4194 transition body). A `.send(msg)`
                // hidden in any of these would bypass the HIR pre-pass — the
                // walker must visit them. See LESSONS row
                // `machine-body-walker-coverage`.
                for state in &machine_decl.states {
                    if let Some(entry) = &state.entry {
                        scan_block_for_actor_send(entry, &mut gate_ctx);
                    }
                    if let Some(exit) = &state.exit {
                        scan_block_for_actor_send(exit, &mut gate_ctx);
                    }
                }
                for tr in &machine_decl.transitions {
                    if let Some(guard) = &tr.guard {
                        scan_spanned_expr_for_actor_send(&guard.0, &guard.1, &mut gate_ctx);
                    }
                    scan_spanned_expr_for_actor_send(&tr.body.0, &tr.body.1, &mut gate_ctx);
                }
            }
            // Const, Trait, Supervisor, Struct, Enum, Use, Module, etc.
            // do not carry user expression bodies that can call `.send()`.
            _ => {}
        }
    }
}

/// Disjoint-borrow bundle for the actor-send walker. The walker mutates
/// `diagnostics` while reading `expr_types` and `actor_protocol_descriptors`;
/// bundling avoids re-borrowing `LowerCtx` per call site.
struct ActorSendGateCtx<'a> {
    expr_types: &'a HashMap<SpanKey, Ty>,
    actor_protocol_descriptors: &'a HashMap<String, hew_types::ActorProtocolDescriptor>,
    diagnostics: &'a mut Vec<HirDiagnostic>,
}

fn scan_block_for_actor_send(block: &hew_parser::ast::Block, gate: &mut ActorSendGateCtx<'_>) {
    for (stmt, _) in &block.stmts {
        scan_stmt_for_actor_send(stmt, gate);
    }
    if let Some(trailing) = &block.trailing_expr {
        scan_spanned_expr_for_actor_send(&trailing.0, &trailing.1, gate);
    }
}

#[allow(
    clippy::match_same_arms,
    reason = "explicit per-Stmt-variant arms read more clearly than collapsed or-patterns for this walker"
)]
fn scan_stmt_for_actor_send(stmt: &hew_parser::ast::Stmt, gate: &mut ActorSendGateCtx<'_>) {
    match stmt {
        Stmt::Let { value: Some(v), .. } | Stmt::Var { value: Some(v), .. } => {
            scan_spanned_expr_for_actor_send(&v.0, &v.1, gate);
        }
        Stmt::Assign { target, value, .. } => {
            scan_spanned_expr_for_actor_send(&target.0, &target.1, gate);
            scan_spanned_expr_for_actor_send(&value.0, &value.1, gate);
        }
        Stmt::Expression(e) => {
            scan_spanned_expr_for_actor_send(&e.0, &e.1, gate);
        }
        Stmt::Return(Some(e)) => {
            scan_spanned_expr_for_actor_send(&e.0, &e.1, gate);
        }
        Stmt::Defer(e) => {
            scan_spanned_expr_for_actor_send(&e.0, &e.1, gate);
        }
        Stmt::Break { value: Some(v), .. } => {
            scan_spanned_expr_for_actor_send(&v.0, &v.1, gate);
        }
        Stmt::WhileLet { expr, body, .. } => {
            scan_spanned_expr_for_actor_send(&expr.0, &expr.1, gate);
            scan_block_for_actor_send(body, gate);
        }
        Stmt::If {
            condition,
            then_block,
            else_block,
        } => {
            scan_spanned_expr_for_actor_send(&condition.0, &condition.1, gate);
            scan_block_for_actor_send(then_block, gate);
            if let Some(eb) = else_block {
                scan_else_block_for_actor_send(eb, gate);
            }
        }
        Stmt::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_spanned_expr_for_actor_send(&expr.0, &expr.1, gate);
            scan_block_for_actor_send(body, gate);
            if let Some(eb) = else_body {
                scan_block_for_actor_send(eb, gate);
            }
        }
        Stmt::Match { scrutinee, arms } => {
            scan_spanned_expr_for_actor_send(&scrutinee.0, &scrutinee.1, gate);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_spanned_expr_for_actor_send(&g.0, &g.1, gate);
                }
                scan_spanned_expr_for_actor_send(&arm.body.0, &arm.body.1, gate);
            }
        }
        Stmt::Loop { body, .. } => scan_block_for_actor_send(body, gate),
        Stmt::For { iterable, body, .. } => {
            scan_spanned_expr_for_actor_send(&iterable.0, &iterable.1, gate);
            scan_block_for_actor_send(body, gate);
        }
        Stmt::While {
            condition, body, ..
        } => {
            scan_spanned_expr_for_actor_send(&condition.0, &condition.1, gate);
            scan_block_for_actor_send(body, gate);
        }
        // Stmt::Break, Stmt::Continue, Stmt::Return(None), and any other leaf
        // statements carry no sub-expression to scan.
        _ => {}
    }
}

fn scan_else_block_for_actor_send(
    eb: &hew_parser::ast::ElseBlock,
    gate: &mut ActorSendGateCtx<'_>,
) {
    if let Some(stmt) = &eb.if_stmt {
        scan_stmt_for_actor_send(&stmt.0, gate);
    }
    if let Some(b) = &eb.block {
        scan_block_for_actor_send(b, gate);
    }
}

/// Recursively walk an expression tree carrying its enclosing span. The
/// leaf check (`Expr::MethodCall` with `method == "send"`) needs the outer
/// call-site span for the diagnostic; downstream span lookups consult
/// `expr_types` via the receiver / arg spans directly.
#[allow(
    clippy::too_many_lines,
    reason = "exhaustive Expr-variant walker mirrors scan_expr_for_blocking_recv above"
)]
fn scan_spanned_expr_for_actor_send(expr: &Expr, span: &Span, gate: &mut ActorSendGateCtx<'_>) {
    match expr {
        Expr::MethodCall {
            receiver,
            method,
            args,
        } => {
            scan_spanned_expr_for_actor_send(&receiver.0, &receiver.1, gate);
            for arg in args {
                let (e, sp) = arg.expr();
                scan_spanned_expr_for_actor_send(e, sp, gate);
            }
            if method == "send" {
                check_actor_send_method_call(receiver, args, span, gate);
            }
        }
        Expr::Call { function, args, .. } => {
            scan_spanned_expr_for_actor_send(&function.0, &function.1, gate);
            for arg in args {
                let (e, sp) = arg.expr();
                scan_spanned_expr_for_actor_send(e, sp, gate);
            }
        }
        Expr::Binary { left, right, .. } => {
            scan_spanned_expr_for_actor_send(&left.0, &left.1, gate);
            scan_spanned_expr_for_actor_send(&right.0, &right.1, gate);
        }
        Expr::Unary { operand, .. } => {
            scan_spanned_expr_for_actor_send(&operand.0, &operand.1, gate);
        }
        Expr::Tuple(es) | Expr::Array(es) | Expr::Join(es) => {
            for e in es {
                scan_spanned_expr_for_actor_send(&e.0, &e.1, gate);
            }
        }
        Expr::ArrayRepeat { value, count } => {
            scan_spanned_expr_for_actor_send(&value.0, &value.1, gate);
            scan_spanned_expr_for_actor_send(&count.0, &count.1, gate);
        }
        Expr::Block(b)
        | Expr::Scope { body: b }
        | Expr::ForkBlock { body: b }
        | Expr::GenBlock { body: b } => {
            scan_block_for_actor_send(b, gate);
        }
        Expr::If {
            condition,
            then_block,
            else_block,
            ..
        } => {
            scan_spanned_expr_for_actor_send(&condition.0, &condition.1, gate);
            scan_spanned_expr_for_actor_send(&then_block.0, &then_block.1, gate);
            if let Some(e) = else_block {
                scan_spanned_expr_for_actor_send(&e.0, &e.1, gate);
            }
        }
        Expr::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_spanned_expr_for_actor_send(&expr.0, &expr.1, gate);
            scan_block_for_actor_send(body, gate);
            if let Some(b) = else_body {
                scan_block_for_actor_send(b, gate);
            }
        }
        Expr::Match { scrutinee, arms } => {
            scan_spanned_expr_for_actor_send(&scrutinee.0, &scrutinee.1, gate);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_spanned_expr_for_actor_send(&g.0, &g.1, gate);
                }
                scan_spanned_expr_for_actor_send(&arm.body.0, &arm.body.1, gate);
            }
        }
        Expr::Lambda { body, .. } | Expr::SpawnLambdaActor { body, .. } => {
            scan_spanned_expr_for_actor_send(&body.0, &body.1, gate);
        }
        Expr::Spawn { target, args, .. } => {
            scan_spanned_expr_for_actor_send(&target.0, &target.1, gate);
            for (_, v) in args {
                scan_spanned_expr_for_actor_send(&v.0, &v.1, gate);
            }
        }
        Expr::ScopeDeadline { duration, body } => {
            scan_spanned_expr_for_actor_send(&duration.0, &duration.1, gate);
            scan_block_for_actor_send(body, gate);
        }
        Expr::ForkChild { expr, .. } | Expr::Cast { expr, .. } => {
            scan_spanned_expr_for_actor_send(&expr.0, &expr.1, gate);
        }
        Expr::StructInit { fields, base, .. } => {
            for (_, v) in fields {
                scan_spanned_expr_for_actor_send(&v.0, &v.1, gate);
            }
            if let Some(b) = base {
                scan_spanned_expr_for_actor_send(&b.0, &b.1, gate);
            }
        }
        Expr::MapLiteral { entries } => {
            for (k, v) in entries {
                scan_spanned_expr_for_actor_send(&k.0, &k.1, gate);
                scan_spanned_expr_for_actor_send(&v.0, &v.1, gate);
            }
        }
        Expr::InterpolatedString(parts) => {
            for part in parts {
                if let hew_parser::ast::StringPart::Expr(e) = part {
                    scan_spanned_expr_for_actor_send(&e.0, &e.1, gate);
                }
            }
        }
        Expr::Select { arms, timeout } => {
            for arm in arms {
                scan_spanned_expr_for_actor_send(&arm.source.0, &arm.source.1, gate);
                scan_spanned_expr_for_actor_send(&arm.body.0, &arm.body.1, gate);
            }
            if let Some(t) = timeout {
                scan_spanned_expr_for_actor_send(&t.duration.0, &t.duration.1, gate);
                scan_spanned_expr_for_actor_send(&t.body.0, &t.body.1, gate);
            }
        }
        Expr::Timeout { expr, duration } => {
            scan_spanned_expr_for_actor_send(&expr.0, &expr.1, gate);
            scan_spanned_expr_for_actor_send(&duration.0, &duration.1, gate);
        }
        Expr::UnsafeBlock(b) => scan_block_for_actor_send(b, gate),
        Expr::FieldAccess { object, .. } | Expr::PostfixTry(object) | Expr::Await(object) => {
            scan_spanned_expr_for_actor_send(&object.0, &object.1, gate);
        }
        Expr::Index { object, index } => {
            scan_spanned_expr_for_actor_send(&object.0, &object.1, gate);
            scan_spanned_expr_for_actor_send(&index.0, &index.1, gate);
        }
        Expr::Is { lhs, rhs } => {
            scan_spanned_expr_for_actor_send(&lhs.0, &lhs.1, gate);
            scan_spanned_expr_for_actor_send(&rhs.0, &rhs.1, gate);
        }
        Expr::Range { start, end, .. } => {
            if let Some(s) = start {
                scan_spanned_expr_for_actor_send(&s.0, &s.1, gate);
            }
            if let Some(e) = end {
                scan_spanned_expr_for_actor_send(&e.0, &e.1, gate);
            }
        }
        Expr::Yield(Some(e)) => scan_spanned_expr_for_actor_send(&e.0, &e.1, gate),
        Expr::MachineEmit { fields, .. } => {
            for (_, v) in fields {
                scan_spanned_expr_for_actor_send(&v.0, &v.1, gate);
            }
        }
        // Leaf nodes (Identifier, literals, etc.) and any other Expr variant
        // without sub-expressions: nothing to scan.
        _ => {}
    }
    // Silence unused-span warning when no leaf path consumes `span`.
    let _ = span;
}

/// Leaf predicate for the actor-send gate.
///
/// Conditions for emitting `ActorSendRequiresUnitHandler`:
/// 1. The receiver's checker-recorded type is `LocalPid<Actor>` or
///    `ActorRef<Actor>` where `Actor` is a `Named` type with a known
///    `ActorProtocolDescriptor` entry. Other receiver shapes (lambda-actor
///    `Duplex<Msg, Reply>`, unresolved types, error types) are skipped —
///    those surfaces are owned by other gates or by the type-checker.
/// 2. There is exactly one receive handler in the actor's protocol
///    descriptor whose `param_tys` match the call's argument types (after
///    `ResolvedTy::from_ty` conversion). The match is by sequence
///    equality; arity-mismatch or type-mismatch falls through silently
///    (defense-in-depth — the checker owns unknown-handler errors).
/// 3. That handler's `return_ty` is not `ResolvedTy::Unit`.
fn check_actor_send_method_call(
    receiver: &hew_parser::ast::Spanned<Expr>,
    args: &[hew_parser::ast::CallArg],
    call_span: &Span,
    gate: &mut ActorSendGateCtx<'_>,
) {
    let Some(receiver_ty) = gate.expr_types.get(&SpanKey::from(&receiver.1)) else {
        return;
    };
    let inner = receiver_ty
        .as_local_pid()
        .or_else(|| receiver_ty.as_actor_ref());
    let Some(Ty::Named {
        name: actor_name, ..
    }) = inner
    else {
        return;
    };
    let Some(descriptor) = gate.actor_protocol_descriptors.get(actor_name) else {
        return;
    };

    let mut arg_tys: Vec<ResolvedTy> = Vec::with_capacity(args.len());
    for arg in args {
        let (_, sp) = arg.expr();
        let Some(ty) = gate.expr_types.get(&SpanKey::from(sp)) else {
            return;
        };
        let Ok(resolved) = ResolvedTy::from_ty(ty) else {
            return;
        };
        arg_tys.push(resolved);
    }

    let mut matched: Option<&hew_types::ActorHandlerDescriptor> = None;
    for handler in &descriptor.handlers {
        if handler.param_tys == arg_tys {
            if matched.is_some() {
                return;
            }
            matched = Some(handler);
        }
    }
    let Some(handler) = matched else {
        return;
    };

    if handler.return_ty == ResolvedTy::Unit {
        return;
    }

    gate.diagnostics.push(HirDiagnostic::new(
        HirDiagnosticKind::ActorSendRequiresUnitHandler {
            actor_name: actor_name.clone(),
            method_name: handler.name.clone(),
            return_ty: handler.return_ty.to_string(),
        },
        call_span.clone(),
        format!(
            "fire-and-forget `.send(...)` on actor `{}` targets receive \
             handler `{}` which returns `{}`. Bare `.send()` discards the \
             reply; use `await actor.ask(...)` (or call-syntax with `await`) \
             for non-unit handlers.",
            actor_name, handler.name, handler.return_ty,
        ),
    ));
}

// ── FC-P1-D: binary-operator HIR pre-pass gates ──────────────────────────────

/// Context carried by the binary-operator gate walker. Bundles the
/// diagnostic sink with the checker's `expr_types` side-table so the
/// `isize`/`usize` predicates can resolve operand types.
struct BinopGateCtx<'a> {
    diagnostics: &'a mut Vec<HirDiagnostic>,
    expr_types: &'a HashMap<SpanKey, Ty>,
}

/// FC-P1-D entry point. Scans every user expression body in `program` for
/// binary operators that the MIR backend cannot lower today and emits the
/// corresponding fatal HIR diagnostic. Three closed gates:
///
/// 1. `..` / `..=` in value position (MIR site `:5336`).
/// 2. `/` / `%` on `isize` (MIR site `:5564`).
/// 3. `<<` / `>>` on `isize`/`usize` (MIR site `:5696`).
///
/// Walker shape mirrors `check_wasm_blocking_recv_gate` / `scan_*_for_
/// blocking_recv`. Range gate is exempted when the binary expression is the
/// direct iterable of a `for` loop (the `ForRange` lowering owns those).
fn check_binary_operator_gates(ctx: &mut LowerCtx, program: &Program) {
    let mut gate_ctx = BinopGateCtx {
        diagnostics: &mut ctx.diagnostics,
        expr_types: &ctx.expr_types,
    };
    for (item, _span) in &program.items {
        match item {
            Item::Function(fn_decl) => {
                scan_block_for_binop_gates(&fn_decl.body, &mut gate_ctx);
            }
            Item::Actor(actor_decl) => {
                if let Some(init) = &actor_decl.init {
                    scan_block_for_binop_gates(&init.body, &mut gate_ctx);
                }
                for recv_fn in &actor_decl.receive_fns {
                    scan_block_for_binop_gates(&recv_fn.body, &mut gate_ctx);
                }
                for method in &actor_decl.methods {
                    scan_block_for_binop_gates(&method.body, &mut gate_ctx);
                }
            }
            Item::Impl(impl_decl) => {
                for method in &impl_decl.methods {
                    scan_block_for_binop_gates(&method.body, &mut gate_ctx);
                }
            }
            Item::Machine(machine_decl) => {
                // State entry/exit blocks and transition guards/bodies are
                // lowered to HIR (see `lower_machine` at lower.rs:4057+ —
                // `lower_machine_block_filtered` walks entry/exit, and
                // `lower_machine_expr_filtered` walks the transition body
                // around lower.rs:4201). A gated binop in any of these
                // positions would otherwise escape FC-P1-D and surface at
                // the MIR producer. Reference: hew-parser/src/ast.rs
                // MachineDecl / MachineState (entry, exit) / MachineTransition
                // (guard, body).
                for state in &machine_decl.states {
                    if let Some(entry) = &state.entry {
                        scan_block_for_binop_gates(entry, &mut gate_ctx);
                    }
                    if let Some(exit) = &state.exit {
                        scan_block_for_binop_gates(exit, &mut gate_ctx);
                    }
                }
                for tr in &machine_decl.transitions {
                    if let Some(guard) = &tr.guard {
                        scan_expr_for_binop_gates(&guard.0, &guard.1, false, &mut gate_ctx);
                    }
                    scan_expr_for_binop_gates(&tr.body.0, &tr.body.1, false, &mut gate_ctx);
                }
            }
            // Variants below carry no user expression bodies that reach MIR
            // in v0.5; each is explicit (no `_` catch-all) so a future
            // `Item` variant trips compilation and forces an audit instead of
            // silently slipping past the gate (cf. A228 walker-scope rule).
            //
            // - Const: value expr is parsed but `Item::Const` is currently
            //   emitted as `unsupported top-level-item slice-2` in `lower.rs`
            //   (~line 1338); no MIR reachable, so no binop site to gate.
            // - Trait: default-method bodies live on `TraitMethod` but are
            //   not lowered in V0b (`lower.rs` ~line 3666: "out of scope for
            //   V0b"). Impl methods are scanned via the `Item::Impl` arm.
            // - Supervisor: `ChildSpec.args` are not lowered by
            //   `lower_supervisor` (`lower.rs` ~line 3936), so any binop in a
            //   child-arg position never reaches MIR.
            // - TypeDecl: struct/enum field types carry no expressions;
            //   `TypeBodyItem::Method` is "not lowered into HIR in v0.5"
            //   (`lower.rs` ~line 3822).
            // - TypeAlias / Wire / Record / ExternBlock / Import: no
            //   value-position user expressions.
            Item::Const(_)
            | Item::TypeDecl(_)
            | Item::TypeAlias(_)
            | Item::Trait(_)
            | Item::Wire(_)
            | Item::ExternBlock(_)
            | Item::Supervisor(_)
            | Item::Record(_)
            | Item::Import(_) => {}
        }
    }
}

fn scan_block_for_binop_gates(block: &hew_parser::ast::Block, ctx: &mut BinopGateCtx) {
    for (stmt, _) in &block.stmts {
        scan_stmt_for_binop_gates(stmt, ctx);
    }
    if let Some(trailing) = &block.trailing_expr {
        scan_expr_for_binop_gates(&trailing.0, &trailing.1, false, ctx);
    }
}

#[allow(
    clippy::match_same_arms,
    reason = "explicit per-Stmt-variant arms read more clearly than collapsed or-patterns for this walker"
)]
fn scan_stmt_for_binop_gates(stmt: &hew_parser::ast::Stmt, ctx: &mut BinopGateCtx) {
    match stmt {
        Stmt::Let { value: Some(v), .. } | Stmt::Var { value: Some(v), .. } => {
            scan_expr_for_binop_gates(&v.0, &v.1, false, ctx);
        }
        Stmt::Assign { target, value, .. } => {
            scan_expr_for_binop_gates(&target.0, &target.1, false, ctx);
            scan_expr_for_binop_gates(&value.0, &value.1, false, ctx);
        }
        Stmt::Expression(e) => {
            scan_expr_for_binop_gates(&e.0, &e.1, false, ctx);
        }
        Stmt::Return(Some(e)) => {
            scan_expr_for_binop_gates(&e.0, &e.1, false, ctx);
        }
        Stmt::Defer(e) => {
            scan_expr_for_binop_gates(&e.0, &e.1, false, ctx);
        }
        Stmt::Break { value: Some(v), .. } => {
            scan_expr_for_binop_gates(&v.0, &v.1, false, ctx);
        }
        Stmt::WhileLet { expr, body, .. } => {
            scan_expr_for_binop_gates(&expr.0, &expr.1, false, ctx);
            scan_block_for_binop_gates(body, ctx);
        }
        Stmt::If {
            condition,
            then_block,
            else_block,
        } => {
            scan_expr_for_binop_gates(&condition.0, &condition.1, false, ctx);
            scan_block_for_binop_gates(then_block, ctx);
            if let Some(eb) = else_block {
                scan_else_block_for_binop_gates(eb, ctx);
            }
        }
        Stmt::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_binop_gates(&expr.0, &expr.1, false, ctx);
            scan_block_for_binop_gates(body, ctx);
            if let Some(eb) = else_body {
                scan_block_for_binop_gates(eb, ctx);
            }
        }
        Stmt::Match { scrutinee, arms } => {
            scan_expr_for_binop_gates(&scrutinee.0, &scrutinee.1, false, ctx);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_binop_gates(&g.0, &g.1, false, ctx);
                }
                scan_expr_for_binop_gates(&arm.body.0, &arm.body.1, false, ctx);
            }
        }
        Stmt::Loop { body, .. } => scan_block_for_binop_gates(body, ctx),
        Stmt::For { iterable, body, .. } => {
            // Range/RangeInclusive directly in the iterable position is
            // lowered via `ForRange`, so exempt the OUTER binop only.
            // Operand sub-expressions are still scanned without the
            // exemption (a nested range in `for i in (1..foo(2..3))` is
            // still value-position).
            scan_expr_for_binop_gates(&iterable.0, &iterable.1, true, ctx);
            scan_block_for_binop_gates(body, ctx);
        }
        Stmt::While {
            condition, body, ..
        } => {
            scan_expr_for_binop_gates(&condition.0, &condition.1, false, ctx);
            scan_block_for_binop_gates(body, ctx);
        }
        // Stmt::Break (no value), Stmt::Continue, Stmt::Return(None), etc.
        // carry no sub-expression to scan.
        _ => {}
    }
}

fn scan_else_block_for_binop_gates(eb: &hew_parser::ast::ElseBlock, ctx: &mut BinopGateCtx) {
    if let Some(stmt) = &eb.if_stmt {
        scan_stmt_for_binop_gates(&stmt.0, ctx);
    }
    if let Some(b) = &eb.block {
        scan_block_for_binop_gates(b, ctx);
    }
}

/// Recursively walk an expression looking for binop-gate violations.
///
/// `in_for_iterable` is set when this expression is the direct iterable
/// child of `Stmt::For`. A top-level `Range`/`RangeInclusive` in that
/// position is exempted (the for-loop lowering handles it). The flag does
/// NOT propagate into sub-expressions.
#[allow(
    clippy::too_many_lines,
    reason = "exhaustive Expr-variant walker mirrors scan_expr_for_blocking_recv"
)]
fn scan_expr_for_binop_gates(
    expr: &Expr,
    span: &Span,
    in_for_iterable: bool,
    ctx: &mut BinopGateCtx,
) {
    if let Expr::Binary { left, op, right } = expr {
        // Apply gates to THIS binop. Sub-expressions are recursed below
        // (always with in_for_iterable=false; the exemption is one-deep).
        apply_binop_gates(*op, left, right, span, in_for_iterable, ctx);
        scan_expr_for_binop_gates(&left.0, &left.1, false, ctx);
        scan_expr_for_binop_gates(&right.0, &right.1, false, ctx);
        return;
    }

    match expr {
        Expr::Binary { .. } => unreachable!("handled above"),
        Expr::Unary { operand, .. } => {
            scan_expr_for_binop_gates(&operand.0, &operand.1, false, ctx);
        }
        Expr::MethodCall { receiver, args, .. } => {
            scan_expr_for_binop_gates(&receiver.0, &receiver.1, false, ctx);
            for arg in args {
                let a = arg.expr();
                scan_expr_for_binop_gates(&a.0, &a.1, false, ctx);
            }
        }
        Expr::Call { function, args, .. } => {
            scan_expr_for_binop_gates(&function.0, &function.1, false, ctx);
            for arg in args {
                let a = arg.expr();
                scan_expr_for_binop_gates(&a.0, &a.1, false, ctx);
            }
        }
        Expr::Tuple(es) | Expr::Array(es) | Expr::Join(es) => {
            for e in es {
                scan_expr_for_binop_gates(&e.0, &e.1, false, ctx);
            }
        }
        Expr::ArrayRepeat { value, count } => {
            scan_expr_for_binop_gates(&value.0, &value.1, false, ctx);
            scan_expr_for_binop_gates(&count.0, &count.1, false, ctx);
        }
        Expr::Block(b)
        | Expr::Scope { body: b }
        | Expr::ForkBlock { body: b }
        | Expr::GenBlock { body: b } => {
            scan_block_for_binop_gates(b, ctx);
        }
        Expr::If {
            condition,
            then_block,
            else_block,
            ..
        } => {
            scan_expr_for_binop_gates(&condition.0, &condition.1, false, ctx);
            scan_expr_for_binop_gates(&then_block.0, &then_block.1, false, ctx);
            if let Some(e) = else_block {
                scan_expr_for_binop_gates(&e.0, &e.1, false, ctx);
            }
        }
        Expr::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_binop_gates(&expr.0, &expr.1, false, ctx);
            scan_block_for_binop_gates(body, ctx);
            if let Some(b) = else_body {
                scan_block_for_binop_gates(b, ctx);
            }
        }
        Expr::Match { scrutinee, arms } => {
            scan_expr_for_binop_gates(&scrutinee.0, &scrutinee.1, false, ctx);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_binop_gates(&g.0, &g.1, false, ctx);
                }
                scan_expr_for_binop_gates(&arm.body.0, &arm.body.1, false, ctx);
            }
        }
        Expr::Lambda { body, .. } | Expr::SpawnLambdaActor { body, .. } => {
            scan_expr_for_binop_gates(&body.0, &body.1, false, ctx);
        }
        Expr::Spawn { target, args, .. } => {
            scan_expr_for_binop_gates(&target.0, &target.1, false, ctx);
            for (_, v) in args {
                scan_expr_for_binop_gates(&v.0, &v.1, false, ctx);
            }
        }
        Expr::ScopeDeadline { duration, body } => {
            scan_expr_for_binop_gates(&duration.0, &duration.1, false, ctx);
            scan_block_for_binop_gates(body, ctx);
        }
        Expr::ForkChild { expr, .. } | Expr::Cast { expr, .. } => {
            scan_expr_for_binop_gates(&expr.0, &expr.1, false, ctx);
        }
        Expr::StructInit { fields, base, .. } => {
            for (_, v) in fields {
                scan_expr_for_binop_gates(&v.0, &v.1, false, ctx);
            }
            if let Some(b) = base {
                scan_expr_for_binop_gates(&b.0, &b.1, false, ctx);
            }
        }
        Expr::MapLiteral { entries } => {
            for (k, v) in entries {
                scan_expr_for_binop_gates(&k.0, &k.1, false, ctx);
                scan_expr_for_binop_gates(&v.0, &v.1, false, ctx);
            }
        }
        Expr::InterpolatedString(parts) => {
            for part in parts {
                if let hew_parser::ast::StringPart::Expr(e) = part {
                    scan_expr_for_binop_gates(&e.0, &e.1, false, ctx);
                }
            }
        }
        Expr::Select { arms, timeout } => {
            for arm in arms {
                scan_expr_for_binop_gates(&arm.source.0, &arm.source.1, false, ctx);
                scan_expr_for_binop_gates(&arm.body.0, &arm.body.1, false, ctx);
            }
            if let Some(t) = timeout {
                scan_expr_for_binop_gates(&t.duration.0, &t.duration.1, false, ctx);
                scan_expr_for_binop_gates(&t.body.0, &t.body.1, false, ctx);
            }
        }
        Expr::Timeout { expr, duration } => {
            scan_expr_for_binop_gates(&expr.0, &expr.1, false, ctx);
            scan_expr_for_binop_gates(&duration.0, &duration.1, false, ctx);
        }
        Expr::UnsafeBlock(b) => scan_block_for_binop_gates(b, ctx),
        Expr::FieldAccess { object, .. } | Expr::PostfixTry(object) | Expr::Await(object) => {
            scan_expr_for_binop_gates(&object.0, &object.1, false, ctx);
        }
        Expr::Index { object, index } => {
            scan_expr_for_binop_gates(&object.0, &object.1, false, ctx);
            scan_expr_for_binop_gates(&index.0, &index.1, false, ctx);
        }
        Expr::Is { lhs, rhs } => {
            scan_expr_for_binop_gates(&lhs.0, &lhs.1, false, ctx);
            scan_expr_for_binop_gates(&rhs.0, &rhs.1, false, ctx);
        }
        Expr::Range { start, end, .. } => {
            // `Expr::Range` is the AST node for slice-index ranges
            // (`xs[a..b]`); separate from `Expr::Binary { op: Range }`.
            // No gate, but recurse into operands.
            if let Some(s) = start {
                scan_expr_for_binop_gates(&s.0, &s.1, false, ctx);
            }
            if let Some(e) = end {
                scan_expr_for_binop_gates(&e.0, &e.1, false, ctx);
            }
        }
        Expr::Yield(Some(e)) => scan_expr_for_binop_gates(&e.0, &e.1, false, ctx),
        Expr::MachineEmit { fields, .. } => {
            for (_, v) in fields {
                scan_expr_for_binop_gates(&v.0, &v.1, false, ctx);
            }
        }
        // Leaf nodes (Identifier, literals, Yield(None), etc.).
        _ => {}
    }
}

/// Apply the three FC-P1-D gates to a single `Expr::Binary` node.
///
/// Exhaustive over `BinaryOp` so future operator additions surface as
/// compile errors here. WHEN-ADDING-BINOP: extend this match to gate or
/// explicitly admit the new operator.
fn apply_binop_gates(
    op: BinaryOp,
    left: &Spanned<Expr>,
    _right: &Spanned<Expr>,
    binop_span: &Span,
    in_for_iterable: bool,
    ctx: &mut BinopGateCtx,
) {
    match op {
        // Gate 1: Range / RangeInclusive in value position.
        BinaryOp::Range | BinaryOp::RangeInclusive => {
            if !in_for_iterable {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::BinaryOperatorUnsupportedInMir {
                        op: format!("{op}"),
                    },
                    binop_span.clone(),
                    format!(
                        "binary operator `{op}` is not lowered to MIR in value \
                         position. Range operators are accepted only as the \
                         iterable of a `for` loop. LESSONS `boundary-fail-closed`."
                    ),
                ));
            }
        }
        // Gate 2: div/mod on isize.
        BinaryOp::Divide | BinaryOp::Modulo => {
            if operand_is_isize(left, ctx.expr_types) {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::PlatformSizedDivRemUnsupported {
                        op: format!("{op}"),
                    },
                    binop_span.clone(),
                    format!(
                        "binary operator `{op}` on `isize` requires the target's \
                         pointer-width MIN constant, which the MIR pipeline does \
                         not yet thread. Use `i32` or `i64` for explicit-width \
                         division. LESSONS `boundary-fail-closed`."
                    ),
                ));
            }
        }
        // Gate 3: shift on isize/usize.
        BinaryOp::Shl | BinaryOp::Shr => {
            if operand_is_platform_sized_int(left, ctx.expr_types) {
                ctx.diagnostics.push(HirDiagnostic::new(
                    HirDiagnosticKind::PlatformSizedShiftUnsupported {
                        op: format!("{op}"),
                    },
                    binop_span.clone(),
                    format!(
                        "binary operator `{op}` on `isize`/`usize` requires the \
                         target's pointer-width bit-count constant, which the MIR \
                         pipeline does not yet thread. Use `i32`/`i64`/`u32`/`u64` \
                         for explicit-width shifts. LESSONS `boundary-fail-closed`."
                    ),
                ));
            }
        }
        // MIR-supported operators (admitted). Listed explicitly so adding a
        // new BinaryOp variant elsewhere triggers a non-exhaustive-match
        // compile error here.
        BinaryOp::Add
        | BinaryOp::Subtract
        | BinaryOp::Multiply
        | BinaryOp::Equal
        | BinaryOp::NotEqual
        | BinaryOp::Less
        | BinaryOp::LessEqual
        | BinaryOp::Greater
        | BinaryOp::GreaterEqual
        | BinaryOp::And
        | BinaryOp::Or
        | BinaryOp::BitAnd
        | BinaryOp::BitOr
        | BinaryOp::BitXor
        | BinaryOp::WrappingAdd
        | BinaryOp::WrappingSub
        | BinaryOp::WrappingMul => {}
    }
}

/// True iff the operand's checker-resolved type is `Ty::Isize`. Returns
/// false when the type is missing from `expr_types` (defense-in-depth:
/// MIR's own gate at `:5564` remains as a backstop, so under-rejection
/// here does not lose safety).
fn operand_is_isize(operand: &Spanned<Expr>, expr_types: &HashMap<SpanKey, Ty>) -> bool {
    matches!(expr_types.get(&SpanKey::from(&operand.1)), Some(Ty::Isize))
}

/// True iff the operand's checker-resolved type is `Ty::Isize` or
/// `Ty::Usize`. Same defense-in-depth note as `operand_is_isize`.
fn operand_is_platform_sized_int(
    operand: &Spanned<Expr>,
    expr_types: &HashMap<SpanKey, Ty>,
) -> bool {
    matches!(
        expr_types.get(&SpanKey::from(&operand.1)),
        Some(Ty::Isize | Ty::Usize)
    )
}

// ── FC-P1-B: Call-shape gates (HIR-level) ───────────────────────────────────
//
// Hoists MIR's two call-shape fail-closed diagnostics into HIR:
//   - `CallableUnsupportedInMir` (lifted from `hew-mir/src/lower.rs:4194`):
//     `BindingRef { Item(_) }` callees whose name is not in the module's
//     callable set.
//   - `IndirectCallUnsupported` (lifted from `hew-mir/src/lower.rs:4236`):
//     `BindingRef { Unresolved }` callees with callable static type
//     (`Function` / `Closure`) — narrowed deliberately so closure-binding
//     calls (`let f = |x| x + 1; f(2)` → `Binding(_)`) and direct module-fn
//     calls are not false-positively rejected.
//
// Walks the LOWERED HIR (not the parser AST) because the predicates depend
// on `ResolvedRef` and `ResolvedTy`, which only exist post-lowering. The
// walker shape mirrors `scan_*_for_blocking_recv`: per-item bucket, then a
// per-`HirBlock` / `HirStmt` / `HirExpr` recursion exhaustive over the HIR
// expression tree.
//
// Runtime ABI bridges (`is_known_runtime_symbol` and `user_name_to_c_symbol`)
// live in `hew-mir`; `hew-hir` cannot depend on `hew-mir`. Instead the gate
// recomputes the same callable set from sources that already exist in
// `hew-hir`: `stdlib_catalog::entries()` for the runtime allowlist, plus the
// hard-coded user-name → C-symbol bridges (`supervisor_stop`, `hew_duplex_*`)
// that `LowerCtx::seed_stdlib_fn_registry` already mirrors when seeding the
// fn registry.

/// Test-only entrypoint that runs the FC-P1-B call-shape gates against a
/// synthetic HIR module slice. Exposed so integration tests in
/// `hew-hir/tests/call_shape_gates.rs` can exercise the negative-test cases
/// directly without having to drive a real surface program through every
/// path that produces a `BindingRef { Item(_) }` to a name absent from the
/// callable set (which is hard to reach from current v0.5 surface syntax
/// because `lower_identifier` only emits `Item(_)` after a successful
/// `fn_registry` lookup).
#[doc(hidden)]
#[must_use]
#[cfg(any(test, feature = "internal-test-hooks"))]
pub fn run_call_shape_gates_for_test(
    items: &[HirItem],
    monomorphisations: &[crate::monomorph::MonomorphizedFn],
) -> Vec<HirDiagnostic> {
    let mut diagnostics = Vec::new();
    check_call_shape_gates(items, monomorphisations, &mut diagnostics);
    diagnostics
}

fn check_call_shape_gates(
    items: &[HirItem],
    monomorphisations: &[crate::monomorph::MonomorphizedFn],
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    let callable = build_callable_set(items, monomorphisations);
    for item in items {
        scan_item_for_call_shape(item, &callable, diagnostics);
    }
}

/// Build the set of names the MIR `Expr::Call` dispatch chain accepts.
///
/// Mirrors MIR's `module_fn_names` (`hew-mir/src/lower.rs:759-783`) plus the
/// runtime-symbol bridges consulted ahead of it in `runtime_symbol_for_call_expr`
/// (`hew-mir/src/lower.rs:3574-3588`). Includes:
///
/// 1. Every `stdlib_catalog::entries()` name (intrinsic linkage included —
///    intrinsics route through `runtime_symbol_for_call_expr` before the
///    fail-closed arm).
/// 2. Every user `HirItem::Function` name — monomorphic AND generic origin.
///    The generic-origin name is admissible because MIR's
///    `call_site_type_args` + mangled-name dispatch resolves the call at the
///    site; if the mangled lookup fails MIR's defense-in-depth still catches
///    it. Excluding generic origins here would false-positively reject every
///    direct call to a generic user function.
/// 3. Every `HirItem::ExternFn` name.
/// 4. Every monomorphisation's mangled name.
/// 5. The hard-coded runtime-ABI bridges `supervisor_stop` and the
///    `hew_duplex_*` family that `seed_stdlib_fn_registry` adds to
///    `fn_registry` for the same reason.
fn build_callable_set(
    items: &[HirItem],
    monomorphisations: &[crate::monomorph::MonomorphizedFn],
) -> std::collections::HashSet<String> {
    let mut set: std::collections::HashSet<String> = std::collections::HashSet::new();
    for entry in stdlib_catalog::entries() {
        // W4.001 Stage C0b: LayoutDescriptorSymbol rows declare runtime
        // statics, not callables. Excluding them here keeps the HIR
        // verifier's callable-set in sync with MIR's `module_fn_names`
        // (which already skips this linkage) and with `fn_registry`
        // (which now also skips it). A user-written call to a descriptor
        // symbol fails closed at HIR resolution with no callable found.
        if matches!(
            entry.linkage,
            stdlib_catalog::BuiltinLinkage::LayoutDescriptorSymbol { .. }
        ) {
            continue;
        }
        set.insert(entry.name.to_string());
        if let Some(symbol) = entry.linkage.runtime_symbol() {
            set.insert(symbol.to_string());
        }
    }
    for item in items {
        match item {
            HirItem::Function(f) => {
                set.insert(f.name.clone());
            }
            HirItem::ExternFn(ef) => {
                set.insert(ef.name.clone());
            }
            _ => {}
        }
    }
    for mono in monomorphisations {
        set.insert(mono.mangled_name.clone());
    }
    // Runtime-ABI bridges seeded into `fn_registry` by
    // `seed_stdlib_fn_registry` (lines ~3055-3104) — kept in sync here
    // because MIR's `runtime_symbol_for_call_expr` accepts them via
    // `user_name_to_c_symbol`.
    set.insert("supervisor_stop".to_string());
    // Actor link/monitor builtins — seeded into `fn_registry` by
    // `seed_stdlib_fn_registry` and bridged in MIR via
    // `user_name_to_c_symbol` (`hew_actor_link` / `hew_actor_monitor`).
    set.insert("link".to_string());
    set.insert("monitor".to_string());
    // User-facing `duplex_pair` constructor — seeded into `fn_registry` by
    // `seed_stdlib_fn_registry` and bridged in MIR via
    // `user_name_to_c_symbol("duplex_pair")` → `hew_duplex_pair`.
    set.insert("duplex_pair".to_string());
    for name in [
        "hew_duplex_send",
        "hew_duplex_try_send",
        "hew_duplex_recv",
        "hew_duplex_try_recv",
        "hew_duplex_send_half",
        "hew_duplex_recv_half",
        "hew_duplex_close",
        "hew_duplex_close_half",
    ] {
        set.insert(name.to_string());
    }
    // Channel recv out-param-ABI symbols — seeded into `fn_registry` by
    // `seed_stdlib_fn_registry` and lowered as `Terminator::Call` by MIR
    // (not `CallRuntimeAbi`; they are not in the runtime-symbol allowlist).
    // Codegen intercepts the `Terminator::Call` by name and emits the
    // null-ptr → `Option<T>` materialisation.
    for name in [
        "hew_channel_recv",
        "hew_channel_recv_int",
        "hew_channel_try_recv",
        "hew_channel_try_recv_int",
    ] {
        set.insert(name.to_string());
    }
    set
}

fn scan_item_for_call_shape(
    item: &HirItem,
    callable: &std::collections::HashSet<String>,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    match item {
        HirItem::Function(f) => scan_block_for_call_shape(&f.body, callable, diagnostics),
        HirItem::Actor(actor) => {
            if let Some(init) = &actor.init {
                scan_block_for_call_shape(&init.body, callable, diagnostics);
            }
            for handler in &actor.receive_handlers {
                scan_block_for_call_shape(&handler.body, callable, diagnostics);
            }
            for method in &actor.methods {
                scan_block_for_call_shape(&method.body, callable, diagnostics);
            }
            for hook in &actor.lifecycle_hooks {
                scan_block_for_call_shape(&hook.body, callable, diagnostics);
            }
        }
        HirItem::Machine(machine) => {
            for state in &machine.states {
                if let Some(entry) = &state.entry {
                    scan_block_for_call_shape(entry, callable, diagnostics);
                }
                if let Some(exit) = &state.exit {
                    scan_block_for_call_shape(exit, callable, diagnostics);
                }
            }
            for trans in &machine.transitions {
                // FC-P1-B revision pass 1: walk the guard expression as
                // well as the body. Prior to lowering `tr.guard` into HIR
                // (resolved in this same pass), `HirMachineTransition`
                // carried only `has_guard: bool`, so this walker — and
                // every other machine-body walker — was a no-op for guard
                // positions. With `guard: Option<HirExpr>` the gate now
                // sees call shapes inside `when <expr>` predicates.
                if let Some(g) = &trans.guard {
                    scan_expr_for_call_shape(g, callable, diagnostics);
                }
                scan_expr_for_call_shape(&trans.body, callable, diagnostics);
            }
        }
        // TypeDecl, Record, Supervisor, Impl, ExternFn carry no user
        // expression bodies that contain `HirExprKind::Call` nodes at this
        // stage (impl methods are also re-emitted as `HirItem::Function`
        // entries, so their bodies are covered by that arm).
        HirItem::TypeDecl(_)
        | HirItem::Record(_)
        | HirItem::Supervisor(_)
        | HirItem::Impl(_)
        | HirItem::ExternFn(_)
        | HirItem::Const(_) => {}
    }
}

fn scan_block_for_call_shape(
    block: &HirBlock,
    callable: &std::collections::HashSet<String>,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    for stmt in &block.statements {
        match &stmt.kind {
            HirStmtKind::Let(_, Some(init)) => {
                scan_expr_for_call_shape(init, callable, diagnostics);
            }
            HirStmtKind::Assign { target, value } => {
                scan_expr_for_call_shape(target, callable, diagnostics);
                scan_expr_for_call_shape(value, callable, diagnostics);
            }
            HirStmtKind::Expr(e) | HirStmtKind::Return(Some(e)) => {
                scan_expr_for_call_shape(e, callable, diagnostics);
            }
            HirStmtKind::Let(_, None) | HirStmtKind::Return(None) => {}
            HirStmtKind::Defer { body, .. } => {
                scan_expr_for_call_shape(body, callable, diagnostics);
            }
        }
    }
    if let Some(tail) = &block.tail {
        scan_expr_for_call_shape(tail, callable, diagnostics);
    }
}

/// Dispatch one `Item` to its body-bearing positions. Centralised so the
/// root-items loop and the module-graph loop emit identical coverage, and so
/// `Item::Machine`'s four positions (per A242) are handled in one place.
fn scan_item_for_supervisor_spawn(
    item: &Item,
    current_module: Option<&str>,
    registry: &SupervisorRegistry,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    match item {
        Item::Function(fn_decl) => {
            scan_block_for_supervisor_spawn(&fn_decl.body, current_module, registry, diagnostics);
        }
        Item::Actor(actor_decl) => {
            if let Some(init) = &actor_decl.init {
                scan_block_for_supervisor_spawn(&init.body, current_module, registry, diagnostics);
            }
            for recv_fn in &actor_decl.receive_fns {
                scan_block_for_supervisor_spawn(
                    &recv_fn.body,
                    current_module,
                    registry,
                    diagnostics,
                );
            }
            for method in &actor_decl.methods {
                scan_block_for_supervisor_spawn(
                    &method.body,
                    current_module,
                    registry,
                    diagnostics,
                );
            }
        }
        Item::Impl(impl_decl) => {
            for method in &impl_decl.methods {
                scan_block_for_supervisor_spawn(
                    &method.body,
                    current_module,
                    registry,
                    diagnostics,
                );
            }
        }
        // A242 invariant: HIR pre-pass walkers that visit user expression
        // bodies in Item::Function/Item::Actor/Item::Impl MUST also visit ALL
        // FOUR Item::Machine positions:
        //   1. each state's `entry` block
        //   2. each state's `exit` block
        //   3. each transition's `guard` expression (if any)
        //   4. each transition's `body` expression (action)
        // Partial coverage (e.g. transitions but not states) is a BLOCK in
        // cross-eco review (6th instance documented this session).
        Item::Machine(machine) => {
            for state in &machine.states {
                if let Some(entry) = &state.entry {
                    scan_block_for_supervisor_spawn(entry, current_module, registry, diagnostics);
                }
                if let Some(exit) = &state.exit {
                    scan_block_for_supervisor_spawn(exit, current_module, registry, diagnostics);
                }
            }
            for transition in &machine.transitions {
                if let Some(guard) = &transition.guard {
                    scan_expr_for_supervisor_spawn(&guard.0, current_module, registry, diagnostics);
                }
                scan_expr_for_supervisor_spawn(
                    &transition.body.0,
                    current_module,
                    registry,
                    diagnostics,
                );
            }
        }
        // Const, Trait, Supervisor, Record, TypeDecl, TypeAlias, Wire,
        // Import, ExternBlock: no user expression bodies that can call
        // `spawn`.
        _ => {}
    }
}

fn scan_block_for_supervisor_spawn(
    block: &hew_parser::ast::Block,
    current_module: Option<&str>,
    registry: &SupervisorRegistry,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    for (stmt, _) in &block.stmts {
        scan_stmt_for_supervisor_spawn(stmt, current_module, registry, diagnostics);
    }
    if let Some(trailing) = &block.trailing_expr {
        scan_expr_for_supervisor_spawn(&trailing.0, current_module, registry, diagnostics);
    }
}

#[allow(
    clippy::too_many_lines,
    reason = "exhaustive HirExprKind match — every recursing variant is named \
              so adding a new variant forces a conscious decision"
)]
#[allow(
    clippy::match_same_arms,
    reason = "structurally identical recursion bodies on distinct HirExprKind \
              variants (e.g. ActorSend/ActorAsk, MachineEmit/StructInit-field \
              walks) are kept separate so adding a new variant forces an \
              explicit per-variant decision rather than silently joining a \
              merged arm"
)]
fn scan_expr_for_call_shape(
    expr: &HirExpr,
    callable: &std::collections::HashSet<String>,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    match &expr.kind {
        HirExprKind::Call { callee, args } => {
            // Site 4194 + 4236 predicates fire on the callee's resolution.
            // Recurse first so any nested invalid call inside `callee` or
            // `args` still surfaces, then apply the gate to this site.
            scan_expr_for_call_shape(callee, callable, diagnostics);
            for arg in args {
                scan_expr_for_call_shape(arg, callable, diagnostics);
            }
            if let HirExprKind::BindingRef { name, resolved } = &callee.kind {
                match resolved {
                    ResolvedRef::Item(_) => {
                        if !callable.contains(name) {
                            diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::CallableUnsupportedInMir { name: name.clone() },
                                callee.span.clone(),
                                format!(
                                    "call to `{name}` has no MIR body or runtime-ABI lowering; \
                                     only module functions, extern fns, monomorphisation \
                                     instantiations, and recognised runtime symbols are \
                                     callable here"
                                ),
                            ));
                        }
                    }
                    ResolvedRef::Unresolved => {
                        // Narrow predicate: only fire when the unresolved
                        // callee has a callable static type. A `Binding(_)`
                        // resolved callee (closure binding, fn parameter,
                        // let-bound function value) is admitted and lowered
                        // by MIR's `CallClosure` arm; rejecting it here
                        // would block valid programs such as
                        // `let f = |x| x + 1; f(2)`.
                        let callable_ty = matches!(
                            callee.ty,
                            ResolvedTy::Function { .. } | ResolvedTy::Closure { .. }
                        );
                        if callable_ty {
                            diagnostics.push(HirDiagnostic::new(
                                HirDiagnosticKind::IndirectCallUnsupported {
                                    callee: format!("unresolved binding `{name}`"),
                                    callee_ty: format!("{:?}", callee.ty),
                                },
                                callee.span.clone(),
                                "indirect call through an unresolved callable binding has no \
                                 MIR dispatch path; only direct calls to module-declared \
                                 functions, extern fns, and recognised runtime symbols are \
                                 supported"
                                    .to_string(),
                            ));
                        }
                    }
                    ResolvedRef::Binding(_) => {
                        // Closure / fn-value bindings: MIR's `CallClosure`
                        // arm dispatches these. Intentionally NOT rejected.
                    }
                    ResolvedRef::Const(_) => {
                        // A `const` is never a callee. If a const name appears
                        // in callee position the checker has already rejected
                        // it as a non-callable type; nothing to gate here.
                    }
                }
            }
        }
        HirExprKind::Binary { left, right, .. } | HirExprKind::IdentityCompare { left, right } => {
            scan_expr_for_call_shape(left, callable, diagnostics);
            scan_expr_for_call_shape(right, callable, diagnostics);
        }
        HirExprKind::Unary { operand, .. } => {
            scan_expr_for_call_shape(operand, callable, diagnostics);
        }
        HirExprKind::ConnAwaitRead { conn, .. } => {
            scan_expr_for_call_shape(conn, callable, diagnostics);
        }
        HirExprKind::ListenerAwaitAccept { listener } => {
            scan_expr_for_call_shape(listener, callable, diagnostics);
        }
        HirExprKind::NumericCast { value, .. } => {
            scan_expr_for_call_shape(value, callable, diagnostics);
        }
        HirExprKind::TupleLiteral { elements } => {
            for elem in elements {
                scan_expr_for_call_shape(elem, callable, diagnostics);
            }
        }
        HirExprKind::Spawn { args, .. } => {
            for (_, v) in args {
                scan_expr_for_call_shape(v, callable, diagnostics);
            }
        }
        HirExprKind::ActorSend { receiver, args, .. }
        | HirExprKind::ActorAsk { receiver, args, .. } => {
            scan_expr_for_call_shape(receiver, callable, diagnostics);
            for a in args {
                scan_expr_for_call_shape(a, callable, diagnostics);
            }
        }
        HirExprKind::RemoteActorAsk {
            receiver,
            msg,
            timeout_ms,
            ..
        } => {
            scan_expr_for_call_shape(receiver, callable, diagnostics);
            scan_expr_for_call_shape(msg, callable, diagnostics);
            scan_expr_for_call_shape(timeout_ms, callable, diagnostics);
        }
        HirExprKind::Block(b) => scan_block_for_call_shape(b, callable, diagnostics),
        HirExprKind::If {
            condition,
            then_expr,
            else_expr,
        } => {
            scan_expr_for_call_shape(condition, callable, diagnostics);
            scan_expr_for_call_shape(then_expr, callable, diagnostics);
            if let Some(e) = else_expr {
                scan_expr_for_call_shape(e, callable, diagnostics);
            }
        }
        HirExprKind::StructInit { fields, base, .. } => {
            for (_, v) in fields {
                scan_expr_for_call_shape(v, callable, diagnostics);
            }
            if let Some(b) = base {
                scan_expr_for_call_shape(b, callable, diagnostics);
            }
        }
        HirExprKind::FieldAccess { object, .. } => {
            scan_expr_for_call_shape(object, callable, diagnostics);
        }
        HirExprKind::Scope { body }
        | HirExprKind::ForkBlock { body, .. }
        | HirExprKind::GenBlock { body, .. } => {
            scan_block_for_call_shape(body, callable, diagnostics);
        }
        HirExprKind::SpawnedCall { callee, args, .. } => {
            scan_expr_for_call_shape(callee, callable, diagnostics);
            for a in args {
                scan_expr_for_call_shape(a, callable, diagnostics);
            }
        }
        HirExprKind::ScopeDeadline { duration, body } => {
            scan_expr_for_call_shape(duration, callable, diagnostics);
            scan_block_for_call_shape(body, callable, diagnostics);
        }
        HirExprKind::Select(select) => {
            for arm in &select.arms {
                match &arm.kind {
                    HirSelectArmKind::StreamNext { stream } => {
                        scan_expr_for_call_shape(stream, callable, diagnostics);
                    }
                    HirSelectArmKind::ActorAsk { actor, args, .. } => {
                        scan_expr_for_call_shape(actor, callable, diagnostics);
                        for a in args {
                            scan_expr_for_call_shape(a, callable, diagnostics);
                        }
                    }
                    HirSelectArmKind::TaskAwait { task } => {
                        scan_expr_for_call_shape(task, callable, diagnostics);
                    }
                    HirSelectArmKind::ChannelRecv { receiver, .. } => {
                        scan_expr_for_call_shape(receiver, callable, diagnostics);
                    }
                    HirSelectArmKind::AfterTimer { duration } => {
                        scan_expr_for_call_shape(duration, callable, diagnostics);
                    }
                }
                scan_expr_for_call_shape(&arm.body, callable, diagnostics);
            }
        }
        HirExprKind::SpawnLambdaActor { body, .. } | HirExprKind::Closure { body, .. } => {
            scan_expr_for_call_shape(body, callable, diagnostics);
        }
        HirExprKind::Yield { value: Some(v), .. } => {
            scan_expr_for_call_shape(v, callable, diagnostics);
        }
        HirExprKind::TupleIndex { tuple, .. } => {
            scan_expr_for_call_shape(tuple, callable, diagnostics);
        }
        HirExprKind::Index { container, index } => {
            scan_expr_for_call_shape(container, callable, diagnostics);
            scan_expr_for_call_shape(index, callable, diagnostics);
        }
        HirExprKind::Slice {
            container,
            start,
            end,
            ..
        } => {
            scan_expr_for_call_shape(container, callable, diagnostics);
            if let Some(s) = start {
                scan_expr_for_call_shape(s, callable, diagnostics);
            }
            if let Some(e) = end {
                scan_expr_for_call_shape(e, callable, diagnostics);
            }
        }
        HirExprKind::CoerceToDynTrait { value, .. } => {
            scan_expr_for_call_shape(value, callable, diagnostics);
        }
        HirExprKind::CallDynMethod { receiver, args, .. }
        | HirExprKind::ResolvedImplCall { receiver, args, .. }
        | HirExprKind::CallTraitMethodStatic { receiver, args, .. }
        | HirExprKind::VarSelfMethodCall { receiver, args, .. } => {
            scan_expr_for_call_shape(receiver, callable, diagnostics);
            for a in args {
                scan_expr_for_call_shape(a, callable, diagnostics);
            }
        }
        HirExprKind::NumericMethod { receiver, arg, .. } => {
            scan_expr_for_call_shape(receiver, callable, diagnostics);
            scan_expr_for_call_shape(arg, callable, diagnostics);
        }
        HirExprKind::CancellationTokenIsCancelled { receiver }
        | HirExprKind::GeneratorNext { receiver, .. } => {
            scan_expr_for_call_shape(receiver, callable, diagnostics);
        }
        HirExprKind::MachineEmit { fields, .. } => {
            for (_, v) in fields {
                scan_expr_for_call_shape(v, callable, diagnostics);
            }
        }
        HirExprKind::MachineStep {
            receiver, event, ..
        } => {
            scan_expr_for_call_shape(receiver, callable, diagnostics);
            scan_expr_for_call_shape(event, callable, diagnostics);
        }
        HirExprKind::MachineStateName { receiver, .. } => {
            scan_expr_for_call_shape(receiver, callable, diagnostics);
        }
        HirExprKind::MachineVariantCtor {
            payload: Some(fields),
            ..
        } => {
            for (_, v) in fields {
                scan_expr_for_call_shape(v, callable, diagnostics);
            }
        }
        HirExprKind::While { condition, body } => {
            scan_expr_for_call_shape(condition, callable, diagnostics);
            scan_block_for_call_shape(body, callable, diagnostics);
        }
        HirExprKind::ForRange {
            start, end, body, ..
        } => {
            scan_expr_for_call_shape(start, callable, diagnostics);
            scan_expr_for_call_shape(end, callable, diagnostics);
            scan_block_for_call_shape(body, callable, diagnostics);
        }
        HirExprKind::Match { scrutinee, arms } => {
            scan_expr_for_call_shape(scrutinee, callable, diagnostics);
            for arm in arms {
                if let Some(guard) = &arm.guard {
                    scan_expr_for_call_shape(guard, callable, diagnostics);
                }
                scan_expr_for_call_shape(&arm.body, callable, diagnostics);
            }
        }
        HirExprKind::WhileLet {
            scrutinee, body, ..
        } => {
            scan_expr_for_call_shape(scrutinee, callable, diagnostics);
            scan_block_for_call_shape(body, callable, diagnostics);
        }
        HirExprKind::IfLet {
            scrutinee,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_call_shape(scrutinee, callable, diagnostics);
            scan_block_for_call_shape(body, callable, diagnostics);
            if let Some(eb) = else_body {
                scan_block_for_call_shape(eb, callable, diagnostics);
            }
        }
        HirExprKind::Break { value, .. } => {
            if let Some(value) = value {
                scan_expr_for_call_shape(value, callable, diagnostics);
            }
        }
        HirExprKind::Loop { body } => {
            scan_block_for_call_shape(body, callable, diagnostics);
        }
        // Leaf / no-sub-expression variants: Literal, RegexLiteralRef,
        // BindingRef, ContextReader, AwaitTask, Yield { value: None },
        // MachineVariantCtor { payload: None }, MachineFieldAccess,
        // MachineEventFieldAccess, Continue, Unsupported. Nothing to recurse into.
        HirExprKind::Literal(_)
        | HirExprKind::RegexLiteralRef { .. }
        | HirExprKind::BindingRef { .. }
        | HirExprKind::ContextReader { .. }
        | HirExprKind::AwaitTask { .. }
        | HirExprKind::Yield { value: None, .. }
        | HirExprKind::MachineVariantCtor { payload: None, .. }
        | HirExprKind::MachineFieldAccess { .. }
        | HirExprKind::MachineEventFieldAccess { .. }
        | HirExprKind::Continue { .. }
        | HirExprKind::Unsupported(_) => {}
    }
}

#[allow(
    clippy::match_same_arms,
    reason = "explicit per-Stmt-variant arms read more clearly than collapsed or-patterns for this walker"
)]
fn scan_stmt_for_supervisor_spawn(
    stmt: &hew_parser::ast::Stmt,
    current_module: Option<&str>,
    registry: &SupervisorRegistry,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    match stmt {
        Stmt::Let { value: Some(v), .. } | Stmt::Var { value: Some(v), .. } => {
            scan_expr_for_supervisor_spawn(&v.0, current_module, registry, diagnostics);
        }
        Stmt::Assign { target, value, .. } => {
            scan_expr_for_supervisor_spawn(&target.0, current_module, registry, diagnostics);
            scan_expr_for_supervisor_spawn(&value.0, current_module, registry, diagnostics);
        }
        Stmt::Expression(e) => {
            scan_expr_for_supervisor_spawn(&e.0, current_module, registry, diagnostics);
        }
        Stmt::Return(Some(e)) => {
            scan_expr_for_supervisor_spawn(&e.0, current_module, registry, diagnostics);
        }
        Stmt::Defer(e) => {
            scan_expr_for_supervisor_spawn(&e.0, current_module, registry, diagnostics);
        }
        Stmt::Break { value: Some(v), .. } => {
            scan_expr_for_supervisor_spawn(&v.0, current_module, registry, diagnostics);
        }
        Stmt::WhileLet { expr, body, .. } => {
            scan_expr_for_supervisor_spawn(&expr.0, current_module, registry, diagnostics);
            scan_block_for_supervisor_spawn(body, current_module, registry, diagnostics);
        }
        Stmt::If {
            condition,
            then_block,
            else_block,
        } => {
            scan_expr_for_supervisor_spawn(&condition.0, current_module, registry, diagnostics);
            scan_block_for_supervisor_spawn(then_block, current_module, registry, diagnostics);
            if let Some(eb) = else_block {
                scan_else_block_for_supervisor_spawn(eb, current_module, registry, diagnostics);
            }
        }
        Stmt::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_supervisor_spawn(&expr.0, current_module, registry, diagnostics);
            scan_block_for_supervisor_spawn(body, current_module, registry, diagnostics);
            if let Some(eb) = else_body {
                scan_block_for_supervisor_spawn(eb, current_module, registry, diagnostics);
            }
        }
        Stmt::Match { scrutinee, arms } => {
            scan_expr_for_supervisor_spawn(&scrutinee.0, current_module, registry, diagnostics);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_supervisor_spawn(&g.0, current_module, registry, diagnostics);
                }
                scan_expr_for_supervisor_spawn(&arm.body.0, current_module, registry, diagnostics);
            }
        }
        Stmt::Loop { body, .. } => {
            scan_block_for_supervisor_spawn(body, current_module, registry, diagnostics);
        }
        Stmt::For { iterable, body, .. } => {
            scan_expr_for_supervisor_spawn(&iterable.0, current_module, registry, diagnostics);
            scan_block_for_supervisor_spawn(body, current_module, registry, diagnostics);
        }
        Stmt::While {
            condition, body, ..
        } => {
            scan_expr_for_supervisor_spawn(&condition.0, current_module, registry, diagnostics);
            scan_block_for_supervisor_spawn(body, current_module, registry, diagnostics);
        }
        // Stmt::Break, Stmt::Continue, Stmt::Return(None), and other leaf
        // statements carry no sub-expression to scan.
        _ => {}
    }
}

fn scan_else_block_for_supervisor_spawn(
    eb: &hew_parser::ast::ElseBlock,
    current_module: Option<&str>,
    registry: &SupervisorRegistry,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    if let Some(stmt) = &eb.if_stmt {
        scan_stmt_for_supervisor_spawn(&stmt.0, current_module, registry, diagnostics);
    }
    if let Some(b) = &eb.block {
        scan_block_for_supervisor_spawn(b, current_module, registry, diagnostics);
    }
}

/// Recursively walk an expression tree looking for `Expr::Spawn` whose target
/// names a known supervisor and whose args list is non-empty.
///
/// `current_module` scopes bare-identifier resolution: `None` for root-program
/// bodies, `Some(short_name)` for non-root module bodies. The supervisor set
/// consulted for a bare `spawn Name(args)` is the set the checker would use
/// when resolving that bare identifier — root's set at root, the module's own
/// set in a module body. Module-qualified `spawn mod.Name(args)` always
/// consults `mod`'s set regardless of `current_module`.
#[allow(
    clippy::too_many_lines,
    reason = "exhaustive Expr-variant walker mirrors scan_expr_for_blocking_recv above"
)]
fn scan_expr_for_supervisor_spawn(
    expr: &Expr,
    current_module: Option<&str>,
    registry: &SupervisorRegistry,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    match expr {
        Expr::Spawn { target, args, .. } => {
            // Module-scoped supervisor lookup.
            //
            // Two recognised spawn-target surface forms carry different
            // module qualifiers; the gate must consult the *correct*
            // module's supervisor set — not a flat union — to avoid both
            // false negatives (a module-local supervisor slipping through
            // because the root has no same-named supervisor) and false
            // positives (a root supervisor name rejecting an unrelated
            // module-local actor that happens to share the name).
            //
            //   bare `spawn Sup(args)` at root            → root supervisors
            //   bare `spawn Sup(args)` in module `M`      → M's supervisors
            //   `spawn mod.Sup(args)` (anywhere)          → mod's supervisors
            //
            // Bare identifiers in module bodies resolve against the module's
            // own scope; root names are not auto-imported, so falling back
            // to root's set would generate false positives. A module that
            // intends to spawn a root supervisor must reach it via a
            // module-qualified path, which dispatches through the
            // `Expr::FieldAccess` arm below. Discharges A237 / LESSONS
            // `string-identifier-fragility-vs-structured-resolution` and
            // the rev2 cross-eco finding on module-context threading.
            let resolved: Option<&str> = match &target.0 {
                Expr::Identifier(name) => {
                    let set = match current_module {
                        Some(m) => registry.by_module.get(m),
                        None => Some(&registry.root),
                    };
                    set.and_then(|s| s.get(name).map(String::as_str))
                }
                Expr::FieldAccess { object, field } => {
                    if let Expr::Identifier(module) = &object.0 {
                        registry
                            .by_module
                            .get(module)
                            .and_then(|set| set.get(field).map(String::as_str))
                    } else {
                        // Non-`Identifier` object (e.g. `foo().Sup`) is not a
                        // module-qualified spawn; the checker would already
                        // reject this shape upstream, so the gate stays
                        // silent here.
                        None
                    }
                }
                _ => None,
            };
            if let Some(name) = resolved {
                if !args.is_empty() {
                    diagnostics.push(HirDiagnostic::new(
                        HirDiagnosticKind::SupervisorSpawnArgsUnsupported {
                            supervisor_name: name.to_string(),
                        },
                        target.1.clone(),
                        format!(
                            "supervisor `{name}` cannot be spawned with init args: \
                             supervisors take their child specs declaratively in the \
                             `supervisor` body; spawn-time init args have no defined \
                             semantics. Use `spawn {name}` with no arguments."
                        ),
                    ));
                }
            }
            // Recurse into target + args so a nested supervisor spawn inside
            // an arg expression is also caught.
            scan_expr_for_supervisor_spawn(&target.0, current_module, registry, diagnostics);
            for (_, v) in args {
                scan_expr_for_supervisor_spawn(&v.0, current_module, registry, diagnostics);
            }
        }
        Expr::MethodCall { receiver, args, .. } => {
            scan_expr_for_supervisor_spawn(&receiver.0, current_module, registry, diagnostics);
            for arg in args {
                scan_expr_for_supervisor_spawn(
                    &arg.expr().0,
                    current_module,
                    registry,
                    diagnostics,
                );
            }
        }
        Expr::Call { function, args, .. } => {
            scan_expr_for_supervisor_spawn(&function.0, current_module, registry, diagnostics);
            for arg in args {
                scan_expr_for_supervisor_spawn(
                    &arg.expr().0,
                    current_module,
                    registry,
                    diagnostics,
                );
            }
        }
        Expr::Binary { left, right, .. } => {
            scan_expr_for_supervisor_spawn(&left.0, current_module, registry, diagnostics);
            scan_expr_for_supervisor_spawn(&right.0, current_module, registry, diagnostics);
        }
        Expr::Unary { operand, .. } => {
            scan_expr_for_supervisor_spawn(&operand.0, current_module, registry, diagnostics);
        }
        Expr::Tuple(es) | Expr::Array(es) | Expr::Join(es) => {
            for e in es {
                scan_expr_for_supervisor_spawn(&e.0, current_module, registry, diagnostics);
            }
        }
        Expr::ArrayRepeat { value, count } => {
            scan_expr_for_supervisor_spawn(&value.0, current_module, registry, diagnostics);
            scan_expr_for_supervisor_spawn(&count.0, current_module, registry, diagnostics);
        }
        Expr::Block(b)
        | Expr::Scope { body: b }
        | Expr::ForkBlock { body: b }
        | Expr::GenBlock { body: b } => {
            scan_block_for_supervisor_spawn(b, current_module, registry, diagnostics);
        }
        Expr::If {
            condition,
            then_block,
            else_block,
            ..
        } => {
            scan_expr_for_supervisor_spawn(&condition.0, current_module, registry, diagnostics);
            scan_expr_for_supervisor_spawn(&then_block.0, current_module, registry, diagnostics);
            if let Some(e) = else_block {
                scan_expr_for_supervisor_spawn(&e.0, current_module, registry, diagnostics);
            }
        }
        Expr::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_supervisor_spawn(&expr.0, current_module, registry, diagnostics);
            scan_block_for_supervisor_spawn(body, current_module, registry, diagnostics);
            if let Some(b) = else_body {
                scan_block_for_supervisor_spawn(b, current_module, registry, diagnostics);
            }
        }
        Expr::Match { scrutinee, arms } => {
            scan_expr_for_supervisor_spawn(&scrutinee.0, current_module, registry, diagnostics);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_supervisor_spawn(&g.0, current_module, registry, diagnostics);
                }
                scan_expr_for_supervisor_spawn(&arm.body.0, current_module, registry, diagnostics);
            }
        }
        Expr::Lambda { body, .. } | Expr::SpawnLambdaActor { body, .. } => {
            scan_expr_for_supervisor_spawn(&body.0, current_module, registry, diagnostics);
        }
        Expr::ScopeDeadline { duration, body } => {
            scan_expr_for_supervisor_spawn(&duration.0, current_module, registry, diagnostics);
            scan_block_for_supervisor_spawn(body, current_module, registry, diagnostics);
        }
        Expr::ForkChild { expr, .. } | Expr::Cast { expr, .. } => {
            scan_expr_for_supervisor_spawn(&expr.0, current_module, registry, diagnostics);
        }
        Expr::StructInit { fields, base, .. } => {
            for (_, v) in fields {
                scan_expr_for_supervisor_spawn(&v.0, current_module, registry, diagnostics);
            }
            if let Some(b) = base {
                scan_expr_for_supervisor_spawn(&b.0, current_module, registry, diagnostics);
            }
        }
        Expr::MapLiteral { entries } => {
            for (k, v) in entries {
                scan_expr_for_supervisor_spawn(&k.0, current_module, registry, diagnostics);
                scan_expr_for_supervisor_spawn(&v.0, current_module, registry, diagnostics);
            }
        }
        Expr::InterpolatedString(parts) => {
            for part in parts {
                if let hew_parser::ast::StringPart::Expr(e) = part {
                    scan_expr_for_supervisor_spawn(&e.0, current_module, registry, diagnostics);
                }
            }
        }
        Expr::Select { arms, timeout } => {
            for arm in arms {
                scan_expr_for_supervisor_spawn(
                    &arm.source.0,
                    current_module,
                    registry,
                    diagnostics,
                );
                scan_expr_for_supervisor_spawn(&arm.body.0, current_module, registry, diagnostics);
            }
            if let Some(t) = timeout {
                scan_expr_for_supervisor_spawn(
                    &t.duration.0,
                    current_module,
                    registry,
                    diagnostics,
                );
                scan_expr_for_supervisor_spawn(&t.body.0, current_module, registry, diagnostics);
            }
        }
        Expr::Timeout { expr, duration } => {
            scan_expr_for_supervisor_spawn(&expr.0, current_module, registry, diagnostics);
            scan_expr_for_supervisor_spawn(&duration.0, current_module, registry, diagnostics);
        }
        Expr::UnsafeBlock(b) => {
            scan_block_for_supervisor_spawn(b, current_module, registry, diagnostics);
        }
        Expr::FieldAccess { object, .. } | Expr::PostfixTry(object) | Expr::Await(object) => {
            scan_expr_for_supervisor_spawn(&object.0, current_module, registry, diagnostics);
        }
        Expr::Index { object, index } => {
            scan_expr_for_supervisor_spawn(&object.0, current_module, registry, diagnostics);
            scan_expr_for_supervisor_spawn(&index.0, current_module, registry, diagnostics);
        }
        Expr::Is { lhs, rhs } => {
            scan_expr_for_supervisor_spawn(&lhs.0, current_module, registry, diagnostics);
            scan_expr_for_supervisor_spawn(&rhs.0, current_module, registry, diagnostics);
        }
        Expr::Range { start, end, .. } => {
            if let Some(s) = start {
                scan_expr_for_supervisor_spawn(&s.0, current_module, registry, diagnostics);
            }
            if let Some(e) = end {
                scan_expr_for_supervisor_spawn(&e.0, current_module, registry, diagnostics);
            }
        }
        Expr::Yield(Some(e)) => {
            scan_expr_for_supervisor_spawn(&e.0, current_module, registry, diagnostics);
        }
        Expr::MachineEmit { fields, .. } => {
            for (_, v) in fields {
                scan_expr_for_supervisor_spawn(&v.0, current_module, registry, diagnostics);
            }
        }
        // Leaf nodes (Identifier, literals, etc.) and any other Expr variant
        // without sub-expressions: nothing to scan.
        _ => {}
    }
}

// ── FC-P1-E: Vec<T> index/slice element-type gates ──────────────────────────
//
// MIR `lower_vec_index` (sites :7265) and `lower_vec_slice` (site :7384)
// already reject unsupported element types via `MirDiagnosticKind::NotYetImplemented`,
// but the diagnostic surfaces deep in MIR and codegen has historically been
// liable to drop downstream expressions when a sub-expression fails to lower.
// Fail-closed per slepp A222 ("compile-time diagnostic, not runtime surprise")
// and A228 ("no silent no-op stubs"): catch the unsupported case at the HIR
// boundary so the user sees a clean diagnostic before any lowering work runs.
//
// Walker shape mirrors `check_wasm_blocking_recv_gate` (above), with the
// difference that we walk `Spanned<Expr>` instead of bare `Expr` because the
// gate needs the object's span (to query the checker's `expr_types`
// side-table) and the surrounding `Expr::Index` span (for the diagnostic
// location).
//
// The gate is target-independent: the runtime ABI lacks
// `hew_vec_get_T` / `hew_vec_slice_range_T` for the rejected element types
// on every target.

fn check_vec_index_element_type_gates(ctx: &mut LowerCtx, program: &Program) {
    // Field-split borrow: `expr_types` is read-only; `diagnostics` is appended.
    let expr_types = &ctx.expr_types;
    let diagnostics = &mut ctx.diagnostics;
    for (item, _span) in &program.items {
        scan_item_for_vec_index_gate(item, expr_types, diagnostics);
    }
}

fn scan_item_for_vec_index_gate(
    item: &Item,
    expr_types: &HashMap<SpanKey, Ty>,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    match item {
        Item::Function(fn_decl) => {
            scan_block_for_vec_index_gate(&fn_decl.body, expr_types, diagnostics);
        }
        Item::Actor(actor_decl) => {
            if let Some(init) = &actor_decl.init {
                scan_block_for_vec_index_gate(&init.body, expr_types, diagnostics);
            }
            for recv_fn in &actor_decl.receive_fns {
                scan_block_for_vec_index_gate(&recv_fn.body, expr_types, diagnostics);
            }
            for method in &actor_decl.methods {
                scan_block_for_vec_index_gate(&method.body, expr_types, diagnostics);
            }
        }
        Item::Impl(impl_decl) => {
            for method in &impl_decl.methods {
                scan_block_for_vec_index_gate(&method.body, expr_types, diagnostics);
            }
        }
        Item::Machine(machine_decl) => {
            // Machine walkers must cover all four user-expression positions:
            // state entry, state exit, transition guard, transition body.
            // Skipping any of state.entry / state.exit lets unsupported
            // `Vec<T>` index/slice expressions slip past this gate (see
            // `.tmp/orchestration/dispatch-invariants.md` →
            // `machine-body-walker-coverage`).
            for state in &machine_decl.states {
                if let Some(entry) = &state.entry {
                    scan_block_for_vec_index_gate(entry, expr_types, diagnostics);
                }
                if let Some(exit) = &state.exit {
                    scan_block_for_vec_index_gate(exit, expr_types, diagnostics);
                }
            }
            for transition in &machine_decl.transitions {
                if let Some(guard) = &transition.guard {
                    scan_expr_for_vec_index_gate(guard, expr_types, diagnostics);
                }
                scan_expr_for_vec_index_gate(&transition.body, expr_types, diagnostics);
            }
        }
        // Const, Trait, Supervisor, Struct, Enum, Use, Module, etc. do not
        // carry user expression bodies that can contain `Expr::Index`.
        _ => {}
    }
}

fn scan_block_for_vec_index_gate(
    block: &Block,
    expr_types: &HashMap<SpanKey, Ty>,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    for (stmt, _) in &block.stmts {
        scan_stmt_for_vec_index_gate(stmt, expr_types, diagnostics);
    }
    if let Some(trailing) = &block.trailing_expr {
        scan_expr_for_vec_index_gate(trailing, expr_types, diagnostics);
    }
}

#[allow(
    clippy::match_same_arms,
    reason = "explicit per-Stmt-variant arms mirror scan_stmt_for_blocking_recv for review symmetry"
)]
fn scan_stmt_for_vec_index_gate(
    stmt: &Stmt,
    expr_types: &HashMap<SpanKey, Ty>,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    match stmt {
        Stmt::Let { value: Some(v), .. } | Stmt::Var { value: Some(v), .. } => {
            scan_expr_for_vec_index_gate(v, expr_types, diagnostics);
        }
        Stmt::Assign { target, value, .. } => {
            scan_expr_for_vec_index_gate(target, expr_types, diagnostics);
            scan_expr_for_vec_index_gate(value, expr_types, diagnostics);
        }
        Stmt::Expression(e) => {
            scan_expr_for_vec_index_gate(e, expr_types, diagnostics);
        }
        Stmt::Return(Some(e)) => {
            scan_expr_for_vec_index_gate(e, expr_types, diagnostics);
        }
        Stmt::Defer(e) => {
            scan_expr_for_vec_index_gate(e, expr_types, diagnostics);
        }
        Stmt::Break { value: Some(v), .. } => {
            scan_expr_for_vec_index_gate(v, expr_types, diagnostics);
        }
        Stmt::WhileLet { expr, body, .. } => {
            scan_expr_for_vec_index_gate(expr, expr_types, diagnostics);
            scan_block_for_vec_index_gate(body, expr_types, diagnostics);
        }
        Stmt::If {
            condition,
            then_block,
            else_block,
        } => {
            scan_expr_for_vec_index_gate(condition, expr_types, diagnostics);
            scan_block_for_vec_index_gate(then_block, expr_types, diagnostics);
            if let Some(eb) = else_block {
                scan_else_block_for_vec_index_gate(eb, expr_types, diagnostics);
            }
        }
        Stmt::IfLet {
            expr,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_vec_index_gate(expr, expr_types, diagnostics);
            scan_block_for_vec_index_gate(body, expr_types, diagnostics);
            if let Some(eb) = else_body {
                scan_block_for_vec_index_gate(eb, expr_types, diagnostics);
            }
        }
        Stmt::Match { scrutinee, arms } => {
            scan_expr_for_vec_index_gate(scrutinee, expr_types, diagnostics);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_vec_index_gate(g, expr_types, diagnostics);
                }
                scan_expr_for_vec_index_gate(&arm.body, expr_types, diagnostics);
            }
        }
        Stmt::Loop { body, .. } => {
            scan_block_for_vec_index_gate(body, expr_types, diagnostics);
        }
        Stmt::For { iterable, body, .. } => {
            scan_expr_for_vec_index_gate(iterable, expr_types, diagnostics);
            scan_block_for_vec_index_gate(body, expr_types, diagnostics);
        }
        Stmt::While {
            condition, body, ..
        } => {
            scan_expr_for_vec_index_gate(condition, expr_types, diagnostics);
            scan_block_for_vec_index_gate(body, expr_types, diagnostics);
        }
        // Stmt::Break (no value), Stmt::Continue, Stmt::Return(None), and
        // any other leaf statements carry no sub-expression to scan.
        _ => {}
    }
}

fn scan_else_block_for_vec_index_gate(
    eb: &hew_parser::ast::ElseBlock,
    expr_types: &HashMap<SpanKey, Ty>,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    if let Some(stmt) = &eb.if_stmt {
        scan_stmt_for_vec_index_gate(&stmt.0, expr_types, diagnostics);
    }
    if let Some(b) = &eb.block {
        scan_block_for_vec_index_gate(b, expr_types, diagnostics);
    }
}

/// Recursively walk a `Spanned<Expr>` tree, gating `Vec<T>` `Expr::Index`
/// nodes whose element type `T` is not in the runtime ABI's supported set.
#[allow(
    clippy::too_many_lines,
    reason = "exhaustive Expr-variant walker mirrors scan_expr_for_blocking_recv above"
)]
fn scan_expr_for_vec_index_gate(
    expr: &Spanned<Expr>,
    expr_types: &HashMap<SpanKey, Ty>,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    let (kind, span) = expr;
    match kind {
        Expr::Index { object, index } => {
            check_vec_index_element_type(object, index, span, expr_types, diagnostics);
            // Recurse into sub-expressions: an `xs[ys[i]]` form must gate
            // `ys[i]` even if `xs[..]` is supported, and vice versa.
            scan_expr_for_vec_index_gate(object, expr_types, diagnostics);
            scan_expr_for_vec_index_gate(index, expr_types, diagnostics);
        }
        Expr::MethodCall { receiver, args, .. } => {
            scan_expr_for_vec_index_gate(receiver, expr_types, diagnostics);
            for arg in args {
                scan_expr_for_vec_index_gate(arg.expr(), expr_types, diagnostics);
            }
        }
        Expr::Call { function, args, .. } => {
            scan_expr_for_vec_index_gate(function, expr_types, diagnostics);
            for arg in args {
                scan_expr_for_vec_index_gate(arg.expr(), expr_types, diagnostics);
            }
        }
        Expr::Binary { left, right, .. } => {
            scan_expr_for_vec_index_gate(left, expr_types, diagnostics);
            scan_expr_for_vec_index_gate(right, expr_types, diagnostics);
        }
        Expr::Unary { operand, .. } => {
            scan_expr_for_vec_index_gate(operand, expr_types, diagnostics);
        }
        Expr::Tuple(es) | Expr::Array(es) | Expr::Join(es) => {
            for e in es {
                scan_expr_for_vec_index_gate(e, expr_types, diagnostics);
            }
        }
        Expr::ArrayRepeat { value, count } => {
            scan_expr_for_vec_index_gate(value, expr_types, diagnostics);
            scan_expr_for_vec_index_gate(count, expr_types, diagnostics);
        }
        Expr::Block(b)
        | Expr::Scope { body: b }
        | Expr::ForkBlock { body: b }
        | Expr::GenBlock { body: b } => {
            scan_block_for_vec_index_gate(b, expr_types, diagnostics);
        }
        Expr::If {
            condition,
            then_block,
            else_block,
            ..
        } => {
            scan_expr_for_vec_index_gate(condition, expr_types, diagnostics);
            scan_expr_for_vec_index_gate(then_block, expr_types, diagnostics);
            if let Some(e) = else_block {
                scan_expr_for_vec_index_gate(e, expr_types, diagnostics);
            }
        }
        Expr::IfLet {
            expr: cond,
            body,
            else_body,
            ..
        } => {
            scan_expr_for_vec_index_gate(cond, expr_types, diagnostics);
            scan_block_for_vec_index_gate(body, expr_types, diagnostics);
            if let Some(b) = else_body {
                scan_block_for_vec_index_gate(b, expr_types, diagnostics);
            }
        }
        Expr::Match { scrutinee, arms } => {
            scan_expr_for_vec_index_gate(scrutinee, expr_types, diagnostics);
            for arm in arms {
                if let Some(g) = &arm.guard {
                    scan_expr_for_vec_index_gate(g, expr_types, diagnostics);
                }
                scan_expr_for_vec_index_gate(&arm.body, expr_types, diagnostics);
            }
        }
        Expr::Lambda { body, .. } | Expr::SpawnLambdaActor { body, .. } => {
            scan_expr_for_vec_index_gate(body, expr_types, diagnostics);
        }
        Expr::Spawn { target, args, .. } => {
            scan_expr_for_vec_index_gate(target, expr_types, diagnostics);
            for (_, v) in args {
                scan_expr_for_vec_index_gate(v, expr_types, diagnostics);
            }
        }
        Expr::ScopeDeadline { duration, body } => {
            scan_expr_for_vec_index_gate(duration, expr_types, diagnostics);
            scan_block_for_vec_index_gate(body, expr_types, diagnostics);
        }
        Expr::ForkChild { expr: inner, .. } | Expr::Cast { expr: inner, .. } => {
            scan_expr_for_vec_index_gate(inner, expr_types, diagnostics);
        }
        Expr::StructInit { fields, base, .. } => {
            for (_, v) in fields {
                scan_expr_for_vec_index_gate(v, expr_types, diagnostics);
            }
            if let Some(b) = base {
                scan_expr_for_vec_index_gate(b, expr_types, diagnostics);
            }
        }
        Expr::MapLiteral { entries } => {
            for (k, v) in entries {
                scan_expr_for_vec_index_gate(k, expr_types, diagnostics);
                scan_expr_for_vec_index_gate(v, expr_types, diagnostics);
            }
        }
        Expr::InterpolatedString(parts) => {
            for part in parts {
                if let hew_parser::ast::StringPart::Expr(e) = part {
                    scan_expr_for_vec_index_gate(e, expr_types, diagnostics);
                }
            }
        }
        Expr::Select { arms, timeout } => {
            for arm in arms {
                scan_expr_for_vec_index_gate(&arm.source, expr_types, diagnostics);
                scan_expr_for_vec_index_gate(&arm.body, expr_types, diagnostics);
            }
            if let Some(t) = timeout {
                scan_expr_for_vec_index_gate(&t.duration, expr_types, diagnostics);
                scan_expr_for_vec_index_gate(&t.body, expr_types, diagnostics);
            }
        }
        Expr::Timeout {
            expr: inner,
            duration,
        } => {
            scan_expr_for_vec_index_gate(inner, expr_types, diagnostics);
            scan_expr_for_vec_index_gate(duration, expr_types, diagnostics);
        }
        Expr::UnsafeBlock(b) => scan_block_for_vec_index_gate(b, expr_types, diagnostics),
        Expr::FieldAccess { object, .. } | Expr::PostfixTry(object) | Expr::Await(object) => {
            scan_expr_for_vec_index_gate(object, expr_types, diagnostics);
        }
        Expr::Is { lhs, rhs } => {
            scan_expr_for_vec_index_gate(lhs, expr_types, diagnostics);
            scan_expr_for_vec_index_gate(rhs, expr_types, diagnostics);
        }
        Expr::Range { start, end, .. } => {
            if let Some(s) = start {
                scan_expr_for_vec_index_gate(s, expr_types, diagnostics);
            }
            if let Some(e) = end {
                scan_expr_for_vec_index_gate(e, expr_types, diagnostics);
            }
        }
        Expr::Yield(Some(e)) => scan_expr_for_vec_index_gate(e, expr_types, diagnostics),
        Expr::MachineEmit { fields, .. } => {
            for (_, v) in fields {
                scan_expr_for_vec_index_gate(v, expr_types, diagnostics);
            }
        }
        // Leaf nodes (Identifier, literals, etc.) and any other Expr variant
        // without sub-expressions: nothing to scan.
        _ => {}
    }
}

/// Render a `ResolvedTy` for the user-facing diagnostic. Keep the textual
/// form compact (`bool`, `char`, `Vec<i32>`, `Foo`) so the diagnostic reads
/// naturally; do not use `{:?}` because that leaks variant punctuation
/// (`I32`, `Named { name: "Foo", args: [] }`, etc.).
fn render_elem_ty(ty: &ResolvedTy) -> String {
    match ty {
        ResolvedTy::Bool => "bool".to_string(),
        ResolvedTy::Char => "char".to_string(),
        ResolvedTy::I8 => "i8".to_string(),
        ResolvedTy::U8 => "u8".to_string(),
        ResolvedTy::I16 => "i16".to_string(),
        ResolvedTy::U16 => "u16".to_string(),
        ResolvedTy::I32 => "i32".to_string(),
        ResolvedTy::U32 => "u32".to_string(),
        ResolvedTy::I64 => "i64".to_string(),
        ResolvedTy::U64 => "u64".to_string(),
        ResolvedTy::Isize => "isize".to_string(),
        ResolvedTy::Usize => "usize".to_string(),
        ResolvedTy::F32 => "f32".to_string(),
        ResolvedTy::F64 => "f64".to_string(),
        ResolvedTy::String => "String".to_string(),
        ResolvedTy::Unit => "()".to_string(),
        ResolvedTy::Named { name, args, .. } if args.is_empty() => name.clone(),
        ResolvedTy::Named { name, args, .. } => {
            let arg_list = args
                .iter()
                .map(render_elem_ty)
                .collect::<Vec<_>>()
                .join(", ");
            format!("{name}<{arg_list}>")
        }
        other => format!("{other:?}"),
    }
}

fn check_vec_index_element_type(
    object: &Spanned<Expr>,
    index: &Spanned<Expr>,
    index_expr_span: &Span,
    expr_types: &HashMap<SpanKey, Ty>,
    diagnostics: &mut Vec<HirDiagnostic>,
) {
    // Look up the container type at the object's span. If absent, the
    // checker already emitted an error for this expression (e.g. indexing
    // into a non-Vec) — defer to that diagnostic and skip the gate.
    let Some(container_ty) = expr_types.get(&SpanKey::from(&object.1)) else {
        return;
    };
    let Ok(resolved) = ResolvedTy::from_ty(container_ty) else {
        // Boundary violation upstream; do not double-report.
        return;
    };
    let elem_ty = match &resolved {
        ResolvedTy::Named { name, args, .. } if name == "Vec" && !args.is_empty() => {
            args[0].clone()
        }
        // Not a Vec<T>: this might be a user-defined type with an `at` method
        // (the HIR lower handles that path) or an array literal (separate
        // lowering). The gate only governs Vec<T> runtime ABI dispatch.
        _ => return,
    };

    let is_range_slice = matches!(&index.0, Expr::Range { .. });

    // Allowlists track the runtime ABI dispatch arms in
    // `hew-mir/src/lower.rs::lower_vec_index` (scalar) and
    // `lower_vec_slice` (range). Keep these in sync with any new
    // `hew_vec_get_T` / `hew_vec_slice_range_T` symbol added to the
    // runtime.
    let is_supported = if is_range_slice {
        matches!(
            elem_ty,
            ResolvedTy::I32
                | ResolvedTy::U32
                | ResolvedTy::I64
                | ResolvedTy::U64
                | ResolvedTy::F64
                | ResolvedTy::String
                | ResolvedTy::Named { .. }
        )
    } else {
        matches!(
            elem_ty,
            ResolvedTy::Bool
                | ResolvedTy::Char
                | ResolvedTy::I32
                | ResolvedTy::U32
                | ResolvedTy::I64
                | ResolvedTy::U64
                | ResolvedTy::F64
                | ResolvedTy::Named { .. }
                | ResolvedTy::Tuple(_)
        )
    };

    if is_supported {
        return;
    }

    let rendered = render_elem_ty(&elem_ty);
    let (kind, note) = if is_range_slice {
        (
            HirDiagnosticKind::VecSliceElementTypeUnsupported {
                element_ty: rendered.clone(),
            },
            format!(
                "Vec<{rendered}> range-slice (xs[a..b]) is not yet supported. \
                 Supported element types for Vec range-slicing are: \
                 i32, u32, i64, u64, f64, String, and user-defined types \
                 (records, enums, Duplex, etc.). \
                 Vec<bool> and Vec<char> will be added in a future \
                 width-normalisation slice."
            ),
        )
    } else {
        (
            HirDiagnosticKind::VecIndexElementTypeUnsupported {
                element_ty: rendered.clone(),
            },
            if matches!(elem_ty, ResolvedTy::String) {
                format!(
                    "Vec<{rendered}> scalar index (xs[i]) is not yet supported. \
                     Supported element types for Vec scalar indexing are: \
                     bool, char, i32, u32, i64, u64, f64, tuples, and user-defined types \
                     (records, enums, Duplex, etc.). \
                     Vec<String> requires the retained/header-aware getter's \
                     owner to be balanced with hew_string_drop; as a workaround, use a \
                     range-slice to extract a single-element Vec: \
                     `let single = strings[i..i+1];`"
                )
            } else {
                format!(
                    "Vec<{rendered}> scalar index (xs[i]) is not yet supported. \
                     Supported element types for Vec scalar indexing are: \
                     bool, char, i32, u32, i64, u64, f64, tuples, and user-defined types \
                     (records, enums, Duplex, etc.)."
                )
            },
        )
    };
    diagnostics.push(HirDiagnostic::new(kind, index_expr_span.clone(), note));
}

// ── Tests ────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;
    use hew_types::module_registry::ModuleRegistry;
    use hew_types::Checker;

    fn parse_typecheck_and_lower(
        source: &str,
    ) -> (hew_parser::ast::Program, TypeCheckOutput, LowerOutput) {
        let parsed = hew_parser::parse(source);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:#?}",
            parsed.errors
        );

        let mut checker = Checker::new(ModuleRegistry::new(vec![]));
        let tco = checker.check_program(&parsed.program);
        assert!(tco.errors.is_empty(), "type errors: {:#?}", tco.errors);

        let lowered = lower_program(&parsed.program, &tco, &ResolutionCtx, TargetArch::host());
        (parsed.program, tco, lowered)
    }

    fn main_function_body(output: &LowerOutput) -> &HirBlock {
        let Some(HirItem::Function(function)) =
            output.module.items.iter().find(
                |item| matches!(item, HirItem::Function(function) if function.name == "main"),
            )
        else {
            panic!("expected lowered main function: {:#?}", output.module.items);
        };
        &function.body
    }

    fn checker_fact_named<'a>(
        facts: impl Iterator<Item = &'a ClosureCaptureFact>,
        name: &str,
    ) -> &'a ClosureCaptureFact {
        let mut matches = facts.filter(|fact| fact.name == name);
        let first = matches
            .next()
            .unwrap_or_else(|| panic!("expected checker fact named {name}"));
        assert!(
            matches.next().is_none(),
            "expected exactly one checker fact named {name}"
        );
        first
    }

    #[test]
    fn closure_capture_uses_checker_mode_and_send_fact() {
        let (_program, tco, lowered) = parse_typecheck_and_lower(
            r"
            fn main() {
                let k: i32 = 2;
                let f = |n: i32| n + k;
            }
            ",
        );
        assert!(
            lowered.diagnostics.is_empty(),
            "lower diagnostics: {:#?}",
            lowered.diagnostics
        );

        let checker_fact = checker_fact_named(
            tco.closure_capture_facts
                .values()
                .flat_map(|facts| facts.iter()),
            "k",
        );

        let body = main_function_body(&lowered);
        let HirStmtKind::Let(k_binding, _) = &body.statements[0].kind else {
            panic!("expected first statement to bind k");
        };
        let HirStmtKind::Let(_, Some(closure_expr)) = &body.statements[1].kind else {
            panic!("expected second statement to bind closure");
        };
        let HirExprKind::Closure { captures, .. } = &closure_expr.kind else {
            panic!("expected closure initializer, got {:#?}", closure_expr.kind);
        };
        let hir_capture = captures
            .iter()
            .find(|capture| capture.name == "k")
            .unwrap_or_else(|| panic!("expected HIR capture named k: {captures:#?}"));

        assert_eq!(hir_capture.binding, k_binding.id);
        assert_eq!(hir_capture.mode, checker_fact.mode);
        assert_eq!(hir_capture.is_send, checker_fact.is_send);
    }

    #[test]
    fn synthesized_actor_handle_lowering_uses_builtin_type_marker() {
        let (_program, _tco, lowered) = parse_typecheck_and_lower(
            r"
            actor Worker {
                receive fn ping() {}
            }

            fn main() {
                let worker = spawn Worker;
            }
            ",
        );

        assert!(
            lowered.diagnostics.is_empty(),
            "lower diagnostics: {:#?}",
            lowered.diagnostics
        );
        let body = main_function_body(&lowered);
        let HirStmtKind::Let(binding, Some(init)) = &body.statements[0].kind else {
            panic!("expected first statement to bind worker");
        };
        assert_eq!(binding.name, "worker");
        assert_eq!(
            init.value_class,
            ValueClass::AffineResource,
            "LocalPid<Worker> must resolve through the builtin type marker registry"
        );
    }

    #[test]
    fn missing_closure_capture_facts_emit_boundary_diagnostic() {
        let (program, mut tco, _) = parse_typecheck_and_lower(
            r"
            fn main() {
                let k: i32 = 2;
                let f = |n: i32| n + k;
            }
            ",
        );
        assert!(
            !tco.closure_capture_facts.is_empty(),
            "test setup requires checker-produced closure capture facts"
        );
        tco.closure_capture_facts.clear();

        let lowered = lower_program(&program, &tco, &ResolutionCtx, TargetArch::host());

        assert!(
            lowered.diagnostics.iter().any(|diagnostic| matches!(
                &diagnostic.kind,
                HirDiagnosticKind::CheckerBoundaryViolation { name, reason }
                    if name == "closure literal"
                        && reason == "closure_capture_facts has no record for closure literal span"
            )),
            "missing closure_capture_facts entry must emit root-cause boundary diagnostic; got {:#?}",
            lowered.diagnostics
        );
    }

    /// When `closure_capture_facts` are missing, `into_result()` must return
    /// `Err` — not `Ok` with empty captures.  This pins the fail-closed
    /// contract at the public API boundary.
    #[test]
    fn missing_closure_capture_facts_into_result_is_err() {
        let (program, mut tco, _) = parse_typecheck_and_lower(
            r"
            fn main() {
                let k: i32 = 2;
                let f = |n: i32| n + k;
            }
            ",
        );
        assert!(
            !tco.closure_capture_facts.is_empty(),
            "test setup requires checker-produced closure capture facts"
        );
        tco.closure_capture_facts.clear();

        let lowered = lower_program(&program, &tco, &ResolutionCtx, TargetArch::host());
        assert!(
            lowered.into_result().is_err(),
            "into_result() must return Err when closure capture facts are missing"
        );
    }

    #[test]
    fn stdlib_println_resolves_to_i64_overload() {
        let (_program, _tco, lowered) = parse_typecheck_and_lower(
            r"
            fn main() {
                println(42);
            }
            ",
        );
        assert!(
            !lowered.diagnostics.iter().any(|diagnostic| matches!(
                &diagnostic.kind,
                HirDiagnosticKind::UnresolvedSymbol { name } if name == "println"
            )),
            "println must not fall through to unresolved symbol: {:#?}",
            lowered.diagnostics
        );
        assert!(
            lowered.diagnostics.is_empty(),
            "lower diagnostics: {:#?}",
            lowered.diagnostics
        );

        let body = main_function_body(&lowered);
        let HirStmtKind::Expr(expr) = &body.statements[0].kind else {
            panic!("expected println statement expression");
        };
        let HirExprKind::Call { callee, .. } = &expr.kind else {
            panic!("expected println call, got {:#?}", expr.kind);
        };
        let HirExprKind::BindingRef { name, resolved } = &callee.kind else {
            panic!("expected callee binding ref, got {:#?}", callee.kind);
        };
        assert_eq!(name, "println_i64");
        assert!(
            matches!(resolved, ResolvedRef::Item(_)),
            "expected println_i64 item ref, got {resolved:?}"
        );
    }

    #[test]
    fn stdlib_println_unsupported_type_emits_overload_diagnostic() {
        let parsed = hew_parser::parse(
            r"
            fn main() {
                let w: Widget;
                println(w);
            }
            ",
        );
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:#?}",
            parsed.errors
        );

        let lowered =
            lower_program_host_target(&parsed.program, &TypeCheckOutput::default(), &ResolutionCtx);
        assert!(
            lowered.diagnostics.iter().any(|diagnostic| matches!(
                &diagnostic.kind,
                HirDiagnosticKind::UnresolvedBuiltinOverload { name, arg_ty }
                    if name == "println"
                        && matches!(arg_ty, ResolvedTy::Named { name, .. } if name == "Widget")
            )),
            "expected unsupported println overload diagnostic, got {:#?}",
            lowered.diagnostics
        );
        assert!(
            !lowered.diagnostics.iter().any(|diagnostic| matches!(
                &diagnostic.kind,
                HirDiagnosticKind::UnresolvedSymbol { name } if name == "println"
            )),
            "unsupported println overload must not fall through to UnresolvedSymbol: {:#?}",
            lowered.diagnostics
        );
    }

    #[test]
    fn missing_stdlib_module_field_emits_import_missing() {
        let parsed = hew_parser::parse(
            r"
            fn main() {
                let _ = fs.read;
            }
            ",
        );
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:#?}",
            parsed.errors
        );

        let lowered =
            lower_program_host_target(&parsed.program, &TypeCheckOutput::default(), &ResolutionCtx);
        assert!(
            lowered.diagnostics.iter().any(|diagnostic| matches!(
                &diagnostic.kind,
                HirDiagnosticKind::ImportMissing { module, name }
                    if module == "std::fs"
                        && name == "fs.read"
                        && diagnostic.note == "add 'import std::fs;' at the top of the file"
            )),
            "expected missing import diagnostic for fs.read, got {:#?}",
            lowered.diagnostics
        );
        assert!(
            !lowered.diagnostics.iter().any(|diagnostic| matches!(
                &diagnostic.kind,
                HirDiagnosticKind::UnresolvedSymbol { name } if name == "fs"
            )),
            "fs.read must not fall through to UnresolvedSymbol: {:#?}",
            lowered.diagnostics
        );
    }

    #[test]
    fn missing_stdlib_module_call_emits_import_missing() {
        let parsed = hew_parser::parse(
            r#"
            fn main() {
                let _ = fs.read("test.txt");
            }
            "#,
        );
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:#?}",
            parsed.errors
        );

        let lowered =
            lower_program_host_target(&parsed.program, &TypeCheckOutput::default(), &ResolutionCtx);
        assert!(
            lowered.diagnostics.iter().any(|diagnostic| matches!(
                &diagnostic.kind,
                HirDiagnosticKind::ImportMissing { module, name }
                    if module == "std::fs"
                        && name == "fs.read"
                        && diagnostic.note == "add 'import std::fs;' at the top of the file"
            )),
            "expected missing import diagnostic for fs.read call, got {:#?}",
            lowered.diagnostics
        );
        assert!(
            !lowered.diagnostics.iter().any(|diagnostic| matches!(
                &diagnostic.kind,
                HirDiagnosticKind::MethodCallNoRewrite { method } if method == "read"
            )),
            "fs.read call must not fall through to MethodCallNoRewrite: {:#?}",
            lowered.diagnostics
        );
    }

    // ── Select arm-binding scoping ──────────────────────────────────────────
    //
    // Source shared by several tests below: two actors both returning `i64`.
    // Both arm bodies return the bound name so the arm body types agree (the
    // type checker requires all arm bodies to have the same type).  Distinct
    // binding names (`reply` vs `verdict`) let us prove each arm has its own
    // BindingId.

    const SELECT_SCOPE_SOURCE: &str = r"
        actor Pinger {
            receive fn ping() -> i64 { 1 }
        }
        actor Counter {
            receive fn count() -> i64 { 2 }
        }
        fn main() {
            let p = spawn Pinger;
            let c = spawn Counter;
            let result = select {
                reply from p.ping() => reply,
                verdict from c.count() => verdict,
            };
        }
    ";

    /// Helper: walk a lowered HIR expression looking for the first
    /// `BindingRef` whose `name` matches `target`. Returns `Some(resolved)`.
    fn find_binding_ref_named<'a>(expr: &'a HirExpr, target: &str) -> Option<&'a ResolvedRef> {
        if let HirExprKind::BindingRef { name, resolved } = &expr.kind {
            if name == target {
                return Some(resolved);
            }
        }
        // Recurse into children where an arm body might live.
        if let HirExprKind::Select(sel) = &expr.kind {
            for arm in &sel.arms {
                if let Some(r) = find_binding_ref_named(&arm.body, target) {
                    return Some(r);
                }
            }
        }
        None
    }

    /// Walk each arm's body separately and return the resolved ref for
    /// `target` found only within `arm_index`.
    fn find_binding_ref_in_arm<'a>(
        select_expr: &'a HirExpr,
        arm_index: usize,
        target: &str,
    ) -> Option<&'a ResolvedRef> {
        let HirExprKind::Select(sel) = &select_expr.kind else {
            return None;
        };
        let arm = sel.arms.get(arm_index)?;
        find_binding_ref_named(&arm.body, target)
    }

    /// Return the select expression from `main`'s first statement's let
    /// initialiser.
    fn main_select_expr(output: &LowerOutput) -> &HirExpr {
        let body = main_function_body(output);
        // The select is the initialiser of the third let (`let _ = select{..}`).
        // Statements: 0=let p, 1=let c, 2=let _ = select.
        let HirStmtKind::Let(_, Some(init)) = &body.statements[2].kind else {
            panic!(
                "expected third statement to be `let _ = select{{..}}`, got {:#?}",
                body.statements
            );
        };
        init
    }

    #[test]
    fn select_actor_ask_arm_body_resolves_own_binding() {
        // Arm body reference to `reply` must resolve to a Binding, not
        // Unresolved — confirming the arm's scope registration works.
        let (_, _, lowered) = parse_typecheck_and_lower(SELECT_SCOPE_SOURCE);
        assert!(
            lowered.diagnostics.is_empty(),
            "unexpected lower diagnostics: {:#?}",
            lowered.diagnostics
        );

        let select_expr = main_select_expr(&lowered);
        let resolved = find_binding_ref_in_arm(select_expr, 0, "reply")
            .unwrap_or_else(|| panic!("expected BindingRef 'reply' in arm 0"));

        assert!(
            matches!(resolved, ResolvedRef::Binding(_)),
            "arm 0 body 'reply' must resolve to Binding, got {resolved:?}"
        );
    }

    #[test]
    fn select_sibling_arm_binding_is_not_visible() {
        // Arm 1's body references `reply` (arm 0's binding name). Since
        // there is no outer `reply` binding, it must produce UnresolvedSymbol.
        let source = r"
            actor Pinger {
                receive fn ping() -> i64 { 1 }
            }
            actor Checker {
                receive fn check() -> i64 { 2 }
            }
            fn main() {
                let p = spawn Pinger;
                let c = spawn Checker;
                let result = select {
                    reply from p.ping() => reply,
                    _verdict from c.check() => reply,
                };
            }
        ";
        let parsed = hew_parser::parse(source);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:#?}",
            parsed.errors
        );

        let mut checker = Checker::new(ModuleRegistry::new(vec![]));
        // Type errors are expected (reply is unresolved in arm 1 context);
        // we proceed to HIR lowering regardless.
        let tco = checker.check_program(&parsed.program);
        let lowered = lower_program(&parsed.program, &tco, &ResolutionCtx, TargetArch::host());

        assert!(
            lowered.diagnostics.iter().any(|d| matches!(
                &d.kind,
                HirDiagnosticKind::UnresolvedSymbol { name } if name == "reply"
            )),
            "arm 1 body referencing arm 0's 'reply' must emit UnresolvedSymbol; got {:#?}",
            lowered.diagnostics
        );
    }

    #[test]
    fn select_arm_binding_not_visible_after_select() {
        // A reference to `reply` after the select (outside the select body)
        // must produce UnresolvedSymbol — the scope is popped on arm exit.
        let source = r"
            actor Pinger {
                receive fn ping() -> i64 { 1 }
            }
            fn main() {
                let p = spawn Pinger;
                let result = select {
                    reply from p.ping() => reply,
                };
                let late = reply;
            }
        ";
        let parsed = hew_parser::parse(source);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:#?}",
            parsed.errors
        );

        let mut checker = Checker::new(ModuleRegistry::new(vec![]));
        let tco = checker.check_program(&parsed.program);
        let lowered = lower_program(&parsed.program, &tco, &ResolutionCtx, TargetArch::host());

        assert!(
            lowered.diagnostics.iter().any(|d| matches!(
                &d.kind,
                HirDiagnosticKind::UnresolvedSymbol { name } if name == "reply"
            )),
            "reference to arm binding outside select must emit UnresolvedSymbol; got {:#?}",
            lowered.diagnostics
        );
    }

    #[test]
    fn select_multiple_arms_have_independent_binding_ids() {
        // Two arms with distinct binding names must each resolve to their own
        // BindingId in their respective bodies.
        let (_, _, lowered) = parse_typecheck_and_lower(SELECT_SCOPE_SOURCE);
        assert!(
            lowered.diagnostics.is_empty(),
            "unexpected lower diagnostics: {:#?}",
            lowered.diagnostics
        );

        let select_expr = main_select_expr(&lowered);
        let reply_ref = find_binding_ref_in_arm(select_expr, 0, "reply")
            .unwrap_or_else(|| panic!("expected BindingRef 'reply' in arm 0"));
        let verdict_ref = find_binding_ref_in_arm(select_expr, 1, "verdict")
            .unwrap_or_else(|| panic!("expected BindingRef 'verdict' in arm 1"));

        let ResolvedRef::Binding(reply_id) = reply_ref else {
            panic!("arm 0 'reply' must be Binding, got {reply_ref:?}");
        };
        let ResolvedRef::Binding(verdict_id) = verdict_ref else {
            panic!("arm 1 'verdict' must be Binding, got {verdict_ref:?}");
        };

        assert_ne!(
            reply_id, verdict_id,
            "distinct arm bindings must have distinct BindingIds"
        );
    }

    fn function_named<'a>(output: &'a LowerOutput, name: &str) -> &'a HirFn {
        output
            .module
            .items
            .iter()
            .find_map(|item| match item {
                HirItem::Function(function) if function.name == name => Some(function),
                _ => None,
            })
            .unwrap_or_else(|| panic!("expected lowered function `{name}`"))
    }

    fn first_let_value(function: &HirFn) -> &HirExpr {
        let Some(stmt) = function.body.statements.first() else {
            panic!("expected at least one statement in `{}`", function.name);
        };
        match &stmt.kind {
            HirStmtKind::Let(_, Some(value)) => value,
            other => panic!("expected first statement to be let-with-value, got {other:#?}"),
        }
    }

    fn enum_variant_name(arm: &HirMatchArm) -> (&str, u32) {
        match &arm.predicate {
            HirMatchArmPredicate::EnumVariant {
                variant_match,
                variant_idx,
            } => (&variant_match.variant_name, *variant_idx),
            other => panic!("expected enum-variant predicate, got {other:#?}"),
        }
    }

    fn assert_result_try_match(expr: &HirExpr) {
        let HirExprKind::Match { arms, .. } = &expr.kind else {
            panic!("expected `?` to lower to Match, got {:#?}", expr.kind);
        };
        assert_eq!(arms.len(), 2, "Result? match must have Ok and Err arms");
        let (ok_name, _) = enum_variant_name(&arms[0]);
        let (err_name, err_idx) = enum_variant_name(&arms[1]);
        assert_eq!(ok_name, "Ok");
        assert_eq!(err_name, "Err");
        assert_eq!(arms[0].bindings.len(), 1, "Ok arm must bind payload");
        assert_eq!(arms[1].bindings.len(), 1, "Err arm must bind payload");
        match &arms[0].body.kind {
            HirExprKind::BindingRef {
                resolved: ResolvedRef::Binding(id),
                ..
            } => assert_eq!(*id, arms[0].bindings[0].binding),
            other => panic!("Ok arm must return its payload binding, got {other:#?}"),
        }
        let HirExprKind::Block(block) = &arms[1].body.kind else {
            panic!(
                "Err arm must be a return block, got {:#?}",
                arms[1].body.kind
            );
        };
        assert!(block.tail.is_none(), "Err return block must have no tail");
        let [return_stmt] = block.statements.as_slice() else {
            panic!("Err return block must contain exactly one statement: {block:#?}");
        };
        let HirStmtKind::Return(Some(return_expr)) = &return_stmt.kind else {
            panic!("Err block statement must be Return(Some), got {return_stmt:#?}");
        };
        match &return_expr.kind {
            HirExprKind::MachineVariantCtor {
                machine_name,
                state_idx,
                payload: Some(payload),
            } => {
                assert_eq!(machine_name, "Result");
                assert_eq!(
                    u32::try_from(*state_idx).expect("variant index must fit in u32"),
                    err_idx
                );
                assert_eq!(payload.len(), 1, "Err ctor must carry one payload");
            }
            other => panic!("Err return must construct Result::Err, got {other:#?}"),
        }
    }

    fn assert_option_try_match(expr: &HirExpr) {
        let HirExprKind::Match { arms, .. } = &expr.kind else {
            panic!("expected `?` to lower to Match, got {:#?}", expr.kind);
        };
        assert_eq!(arms.len(), 2, "Option? match must have Some and None arms");
        let (some_name, _) = enum_variant_name(&arms[0]);
        let (none_name, none_idx) = enum_variant_name(&arms[1]);
        assert_eq!(some_name, "Some");
        assert_eq!(none_name, "None");
        assert_eq!(arms[0].bindings.len(), 1, "Some arm must bind payload");
        assert!(
            arms[1].bindings.is_empty(),
            "None arm has no payload binding"
        );
        match &arms[0].body.kind {
            HirExprKind::BindingRef {
                resolved: ResolvedRef::Binding(id),
                ..
            } => assert_eq!(*id, arms[0].bindings[0].binding),
            other => panic!("Some arm must return its payload binding, got {other:#?}"),
        }
        let HirExprKind::Block(block) = &arms[1].body.kind else {
            panic!(
                "None arm must be a return block, got {:#?}",
                arms[1].body.kind
            );
        };
        let [return_stmt] = block.statements.as_slice() else {
            panic!("None return block must contain exactly one statement: {block:#?}");
        };
        let HirStmtKind::Return(Some(return_expr)) = &return_stmt.kind else {
            panic!("None block statement must be Return(Some), got {return_stmt:#?}");
        };
        match &return_expr.kind {
            HirExprKind::MachineVariantCtor {
                machine_name,
                state_idx,
                payload: None,
            } => {
                assert_eq!(machine_name, "Option");
                assert_eq!(
                    u32::try_from(*state_idx).expect("variant index must fit in u32"),
                    none_idx
                );
            }
            other => panic!("None return must construct Option::None, got {other:#?}"),
        }
    }

    #[test]
    fn postfix_try_result_lowers_to_enum_match_returning_err() {
        let (_, _, lowered) = parse_typecheck_and_lower(
            r"
            fn pass(r: Result<i64, i64>) -> Result<i64, i64> {
                let x: i64 = r?;
                Ok(x)
            }
            ",
        );
        assert!(
            lowered.diagnostics.is_empty(),
            "unexpected HIR diagnostics: {:#?}",
            lowered.diagnostics
        );
        let pass = function_named(&lowered, "pass");
        assert_result_try_match(first_let_value(pass));
    }

    #[test]
    fn postfix_try_option_lowers_to_enum_match_returning_none() {
        let (_, _, lowered) = parse_typecheck_and_lower(
            r"
            fn pass(o: Option<i64>) -> Option<i64> {
                let x: i64 = o?;
                Some(x)
            }
            ",
        );
        assert!(
            lowered.diagnostics.is_empty(),
            "unexpected HIR diagnostics: {:#?}",
            lowered.diagnostics
        );
        let pass = function_named(&lowered, "pass");
        assert_option_try_match(first_let_value(pass));
    }

    #[test]
    fn postfix_try_in_non_result_returning_fn_stays_fail_closed() {
        let source = r"
            fn bad(r: Result<i64, i64>) -> i64 {
                let x: i64 = r?;
                x
            }
        ";
        let parsed = hew_parser::parse(source);
        assert!(
            parsed.errors.is_empty(),
            "parse errors: {:#?}",
            parsed.errors
        );

        let mut checker = Checker::new(ModuleRegistry::new(vec![]));
        let tco = checker.check_program(&parsed.program);
        assert!(
            !tco.errors.is_empty(),
            "checker must reject `?` in i64-returning fn"
        );
        let lowered = lower_program(&parsed.program, &tco, &ResolutionCtx, TargetArch::host());
        assert!(
            lowered.diagnostics.iter().any(|d| matches!(
                &d.kind,
                HirDiagnosticKind::NotYetImplemented { owning_pass, .. }
                    if owning_pass == "question-operator"
            )),
            "HIR must fail closed for rejected `?`; got {:#?}",
            lowered.diagnostics
        );
    }

    // ── Enum-layout discovery tests ──────────────────────────────────────────

    /// Lower the §0 probe (`Option<i64>` instantiated at a call site and
    /// matched) and assert that the HIR enum-layout registry contains exactly
    /// the expected entry. The `Some` variant's payload field must be
    /// `ResolvedTy::I64` (not `ResolvedTy::Named { name: "T", args: [] }` —
    /// the raw type-param symbol). This pins the substitution contract.
    ///
    /// LESSONS: `type-info-survival` (P0) — read type from `expr_types`,
    /// not the un-substituted HIR node type. `checker-authority` (P0).
    #[test]
    fn generic_enum_option_i64_registered_in_enum_layouts() {
        let (_, _, lowered) = parse_typecheck_and_lower(
            r"
            enum Option<T> { Some(T); None }
            fn main() -> i64 {
                let x: Option<i64> = Option::Some(42);
                match x {
                    Option::Some(v) => v,
                    Option::None => 0,
                }
            }
            ",
        );

        let layouts = &lowered.module.enum_layouts;
        assert_eq!(
            layouts.len(),
            1,
            "exactly one enum-layout entry expected for Option<i64>; got {layouts:#?}"
        );

        let layout = &layouts[0];
        assert_eq!(
            layout.key.origin_name, "Option",
            "enum origin name must be 'Option'"
        );
        assert_eq!(
            layout.key.type_args,
            vec![ResolvedTy::I64],
            "type_args must be [I64]"
        );
        assert_eq!(
            layout.mangled_name, "Option$$i64",
            "mangled name must follow shared scheme"
        );

        // Two variants: Some(T→i64) and None.
        assert_eq!(layout.variants.len(), 2, "Option has two variants");
        let some_variant = layout
            .variants
            .iter()
            .find(|v| v.name == "Some")
            .expect("Some variant must be present");
        assert_eq!(
            some_variant.field_tys,
            vec![ResolvedTy::I64],
            "Some variant payload must be substituted to I64, not a type-param symbol"
        );
        let none_variant = layout
            .variants
            .iter()
            .find(|v| v.name == "None")
            .expect("None variant must be present");
        assert!(
            none_variant.field_tys.is_empty(),
            "None variant must have no payload fields"
        );
    }

    /// A STDLIB bare `None` — with NO user `enum Option<T>` in source — must
    /// lower to a unit ctor whose stamped result type carries the concrete
    /// `Option<i64>` args, so codegen's mangled key resolves to `Option$$i64`.
    ///
    /// Note: `enum_layouts` alone does NOT discriminate — the match scrutinee
    /// (`f()` typed `Option<i64>`) registers `Option$$i64` regardless. The
    /// load-bearing assertion is the `None` ctor node's stamped `ty`.
    #[test]
    fn stdlib_option_none_registers_in_enum_layouts() {
        let (_, _, lowered) = parse_typecheck_and_lower(
            r"
            fn f() -> Option<i64> { None }
            fn main() -> i64 { match f() { Some(x) => x, None => 7 } }
            ",
        );

        // The match scrutinee registers Option$$i64 even on tip; assert it is
        // present (the layout the None ctor must resolve against).
        assert!(
            lowered
                .module
                .enum_layouts
                .iter()
                .any(|l| l.mangled_name == "Option$$i64"),
            "Option$$i64 must be in enum_layouts; got {:#?}",
            lowered.module.enum_layouts
        );

        // Discriminating assertion: the bare `None` ctor in `f`'s body must
        // stamp the concrete Option<i64> type args, not a bare Option.
        let f_func = lowered
            .module
            .items
            .iter()
            .find_map(|item| match item {
                HirItem::Function(func) if func.name == "f" => Some(func),
                _ => None,
            })
            .expect("lowered module must contain fn f");
        let tail = f_func
            .body
            .tail
            .as_ref()
            .expect("fn f body must have a trailing `None` expression");
        let HirExprKind::MachineVariantCtor { machine_name, .. } = &tail.kind else {
            panic!(
                "expected `None` to lower to a unit MachineVariantCtor, got {:#?}",
                tail.kind
            );
        };
        assert_eq!(machine_name, "Option", "ctor must target Option");
        match &tail.ty {
            ResolvedTy::Named { name, args, .. } => {
                assert_eq!(name, "Option");
                assert_eq!(
                    args.as_slice(),
                    &[ResolvedTy::I64],
                    "bare `None` ctor must stamp concrete Option<i64> args (not bare \
                     Option), so codegen's mangled key resolves to Option$$i64; got {:#?}",
                    tail.ty
                );
            }
            other => panic!("expected Named Option<i64>, got {other:#?}"),
        }
    }

    /// A plain monomorphic enum must NOT appear in `enum_layouts` — the
    /// registry is only for generic-enum instantiations.
    #[test]
    fn monomorphic_enum_does_not_appear_in_enum_layouts() {
        let (_, _, lowered) = parse_typecheck_and_lower(
            r"
            enum Colour { Red; Green; Blue }
            fn main() -> i64 {
                let c: Colour = Colour::Red;
                match c {
                    Colour::Red => 1,
                    Colour::Green => 2,
                    Colour::Blue => 3,
                }
            }
            ",
        );

        assert!(
            lowered.module.enum_layouts.is_empty(),
            "monomorphic enums must not appear in enum_layouts; got {:#?}",
            lowered.module.enum_layouts
        );
    }

    /// Nested generic instantiation: `Option<Option<i64>>` must produce two
    /// registry entries — one for `Option<Option<i64>>` and one for
    /// `Option<i64>`. The worklist transitively expands type args so that the
    /// inner instantiation is discovered even though only the outer type
    /// appears at the call site.
    ///
    /// This exercises the fixpoint path in `try_register_enum_instantiation`.
    #[test]
    fn nested_generic_enum_option_option_i64_registers_both_instantiations() {
        let (_, _, lowered) = parse_typecheck_and_lower(
            r"
            enum Option<T> { Some(T); None }
            fn main() -> i64 {
                let inner: Option<i64> = Option::Some(5);
                let outer: Option<Option<i64>> = Option::Some(inner);
                match outer {
                    Option::Some(v) => match v {
                        Option::Some(n) => n,
                        Option::None => 0,
                    },
                    Option::None => -1,
                }
            }
            ",
        );

        let layouts = &lowered.module.enum_layouts;
        // Both Option<i64> and Option<Option<i64>> must be registered.
        assert!(
            layouts.len() >= 2,
            "expected at least two enum-layout entries for Option<i64> and \
             Option<Option<i64>>; got {layouts:#?}"
        );

        let has_option_i64 = layouts
            .iter()
            .any(|l| l.key.origin_name == "Option" && l.key.type_args == vec![ResolvedTy::I64]);
        let has_option_option_i64 = layouts.iter().any(|l| {
            l.key.origin_name == "Option"
                && l.key.type_args == vec![ResolvedTy::named_user("Option", vec![ResolvedTy::I64])]
        });

        assert!(
            has_option_i64,
            "registry must contain Option<i64>; got {layouts:#?}"
        );
        assert!(
            has_option_option_i64,
            "registry must contain Option<Option<i64>>; got {layouts:#?}"
        );
    }

    // ── Walker recursion regression tests ────────────────────────────────────
    //
    // These tests construct HIR nodes directly and call the private walker
    // functions.  They guard against a future variant arm accidentally dropping
    // recursion — exhaustivity catches a *missing* arm, but not an arm that
    // exists yet skips sub-expressions.

    /// Build a minimal `HirExpr` wrapping a given `kind`.  All identity fields
    /// are set to zero/default; they have no effect on the walker functions.
    fn dummy_expr(kind: HirExprKind) -> HirExpr {
        use crate::ids::HirNodeId;
        HirExpr {
            node: HirNodeId(0),
            site: SiteId(0),
            ty: ResolvedTy::Unit,
            value_class: ValueClass::BitCopy,
            intent: IntentKind::Read,
            kind,
            span: 0..0,
        }
    }

    /// `collect_call_sites_in_expr` must recurse into the field expressions of
    /// a `MachineEmit` node.  Without the arm added in the exhaustivity fix, a
    /// `Call` nested in an emit field was silently ignored, so the call site
    /// would never surface in the monomorphisation registry.
    #[test]
    fn collect_call_sites_in_expr_recurses_through_machine_emit_fields() {
        let call_expr = dummy_expr(HirExprKind::Call {
            callee: Box::new(dummy_expr(HirExprKind::BindingRef {
                name: "call_some_fn".to_string(),
                resolved: ResolvedRef::Unresolved,
            })),
            args: vec![],
        });
        let emit_expr = dummy_expr(HirExprKind::MachineEmit {
            event_idx: 0,
            fields: vec![("x".to_string(), call_expr)],
        });

        let mut sites: Vec<(String, SiteId)> = Vec::new();
        let mut trait_sites: Vec<TraitMethodStaticSite> = Vec::new();
        collect_call_sites_in_expr(&emit_expr, &mut sites, &mut trait_sites);

        assert!(
            sites.iter().any(|(name, _)| name == "call_some_fn"),
            "collect_call_sites_in_expr must recurse into MachineEmit fields; \
             got sites: {sites:?}"
        );
    }

    /// `collect_hir_emitted_events_walk` must recurse into the field
    /// expressions of a `MachineEmit` node so that a nested emit is reported.
    /// Before the exhaustivity fix the field loop was absent; `Inner` would be
    /// silently dropped from `body_emits`.
    #[test]
    fn collect_hir_emitted_events_walk_recurses_through_machine_emit_fields() {
        let inner_emit = dummy_expr(HirExprKind::MachineEmit {
            event_idx: 1,
            fields: vec![],
        });
        let outer_emit = dummy_expr(HirExprKind::MachineEmit {
            event_idx: 0,
            fields: vec![("x".to_string(), inner_emit)],
        });
        let event_names = vec!["Outer".to_string(), "Inner".to_string()];

        let mut out: Vec<String> = Vec::new();
        collect_hir_emitted_events_walk(&outer_emit, &event_names, &mut out);

        assert!(
            out.contains(&"Outer".to_string()),
            "Outer emit must be reported; got: {out:?}"
        );
        assert!(
            out.contains(&"Inner".to_string()),
            "Inner emit nested in Outer field must be reported; got: {out:?}"
        );
    }

    /// A general `Closure` body executes inline — its emits belong to the
    /// enclosing transition and must bubble out.  Before revision 1 of the
    /// exhaustivity fix, `Closure { .. }` was grouped with `SpawnLambdaActor`
    /// as a scope boundary, so `emit Beep` inside a closure was silently
    /// dropped from `body_emits`.
    #[test]
    fn collect_hir_emitted_events_walk_recurses_into_closure_body() {
        let emit_expr = dummy_expr(HirExprKind::MachineEmit {
            event_idx: 0,
            fields: vec![],
        });
        let closure_expr = dummy_expr(HirExprKind::Closure {
            params: vec![],
            ret_ty: ResolvedTy::Unit,
            body: Box::new(emit_expr),
            captures: vec![],
            escape_kind: ClosureEscapeKind::Local,
        });
        let event_names = vec!["Beep".to_string()];

        let mut out: Vec<String> = Vec::new();
        collect_hir_emitted_events_walk(&closure_expr, &event_names, &mut out);

        assert!(
            out.contains(&"Beep".to_string()),
            "emit inside a Closure body must bubble to the enclosing transition; \
             got: {out:?}"
        );
    }

    /// A `SpawnLambdaActor` body runs on a separate actor substrate; its emits
    /// must NOT bubble out to the parent transition.  This is the inverse of
    /// the `Closure` test above and guards that the `SpawnLambdaActor` leaf
    /// boundary is preserved by the revision-1 fix.
    #[test]
    fn collect_hir_emitted_events_walk_does_not_recurse_into_spawn_lambda_actor_body() {
        let emit_expr = dummy_expr(HirExprKind::MachineEmit {
            event_idx: 0,
            fields: vec![],
        });
        let spawn_expr = dummy_expr(HirExprKind::SpawnLambdaActor {
            params: vec![],
            reply_ty: ResolvedTy::Unit,
            body: Box::new(emit_expr),
            captures: vec![],
        });
        let event_names = vec!["Inner".to_string()];

        let mut out: Vec<String> = Vec::new();
        collect_hir_emitted_events_walk(&spawn_expr, &event_names, &mut out);

        assert!(
            out.is_empty(),
            "emit inside a SpawnLambdaActor body must NOT bubble to the parent \
             transition; got: {out:?}"
        );
    }

    /// Regression test: `await actor.close()` at the top level of a function
    /// (`scope_depth` == 0) must NOT produce `AwaitOutOfPosition`.
    ///
    /// Before the fix, the HIR `Expr::Await` handler required `scope_depth > 0`
    /// for all `await` expressions except `ActorMethodKind::Ask` dispatches.
    /// Lambda-actor `close()` goes through `method_call_rewrites` (not
    /// `actor_method_dispatch`), so it hit the `scope_depth` guard and emitted
    /// `AwaitOutOfPosition` even when the `await` was a valid statement.
    #[test]
    fn await_actor_close_outside_scope_block_is_accepted() {
        let (_, _, lowered) = parse_typecheck_and_lower(
            r"
            fn main() {
                let a = actor |x: i64| { };
                await a.close();
            }
            ",
        );
        let await_out_of_position: Vec<_> = lowered
            .diagnostics
            .iter()
            .filter(|d| matches!(d.kind, HirDiagnosticKind::AwaitOutOfPosition))
            .collect();
        assert!(
            await_out_of_position.is_empty(),
            "`await actor.close()` at function level must not produce AwaitOutOfPosition; \
             got: {await_out_of_position:#?}"
        );
    }

    /// `await actor.close()` must still be rejected in non-statement position
    /// (e.g., as a let-value).
    #[test]
    fn await_actor_close_as_let_value_is_rejected() {
        let (_, _, lowered) = parse_typecheck_and_lower(
            r"
            fn main() {
                let a = actor |x: i64| { };
                let _result = await a.close();
            }
            ",
        );
        assert!(
            lowered
                .diagnostics
                .iter()
                .any(|d| matches!(d.kind, HirDiagnosticKind::AwaitOutOfPosition)),
            "`await actor.close()` as a let-value must produce AwaitOutOfPosition; \
             diagnostics: {:#?}",
            lowered.diagnostics
        );
    }
}

/// Parity tests: assert that the three catalogs holding builtin enum variant
/// names agree with each other in name and declaration order.
///
/// The catalogs being compared:
///   1. `hew_types::builtin_enums::monomorphic_builtin_enums()` — the Rust-side
///      out-of-band layout catalog consumed by MIR and codegen.
///   2. `builtin_enum_specs()` — the HIR lowering table that seeds the checker's
///      `machine_ctor_registry`, `enum_variants_by_name`, and the discriminant
///      assignments that drive match-arm lowering and codegen tag emission.
///   3. `BUILTIN_ENUM_VARIANT_BARE_NAMES` — the flat de-duplication guard that
///      prevents bare variant names from silently overwriting user machine-state
///      constructor entries.
///
/// These three catalogs are hand-mirrored. A past regression (the original
/// `Full`/`Closed`/`NodeRoutingNotWired`/`NotFound` silent-overwrite) occurred
/// because one catalog was updated without the others. This module converts that
/// reviewer-vigilance requirement into a compile-time-enforced test invariant.
#[cfg(test)]
mod builtin_enum_parity_tests {
    use super::{builtin_enum_specs, BUILTIN_ENUM_VARIANT_BARE_NAMES};

    /// For each monomorphic builtin enum in the `hew-types` out-of-band catalog,
    /// assert that `builtin_enum_specs()` declares the same variants in the same
    /// order.
    ///
    /// A mismatch here means the HIR discriminant assignments (index in
    /// `variant_names`) diverge from the MIR layout (index in
    /// `BuiltinMonomorphicEnum::variants`), which breaks codegen tag emission.
    #[test]
    fn monomorphic_enum_variants_agree_between_hir_and_types_catalog() {
        let hir_specs = builtin_enum_specs();
        let types_catalog = hew_types::builtin_enums::monomorphic_builtin_enums();

        for types_entry in types_catalog {
            let hir_entry = hir_specs
                .iter()
                .find(|s| s.type_name == types_entry.name)
                .unwrap_or_else(|| {
                    panic!(
                        "builtin_enum_specs() is missing an entry for `{}`, \
                         which is present in hew_types::builtin_enums::monomorphic_builtin_enums(). \
                         Add a matching BuiltinEnumSpec for it.",
                        types_entry.name
                    )
                });

            let hir_variants: Vec<&str> = hir_entry.variant_names.to_vec();
            let types_variants: Vec<&str> = types_entry.variants.iter().map(|v| v.name).collect();

            assert_eq!(
                hir_variants, types_variants,
                "Variant list for `{}` differs between builtin_enum_specs() \
                 (hew-hir) and monomorphic_builtin_enums() (hew-types).\n\
                 hew-hir:   {:?}\n\
                 hew-types: {:?}\n\
                 These must be identical: the index of each variant is its \
                 discriminant tag, and both catalogs must agree.",
                types_entry.name, hir_variants, types_variants
            );
        }

        // Reverse direction: every monomorphic HIR spec (no type params) must
        // appear in the hew-types catalog too.
        for hir_spec in hir_specs.iter().filter(|s| s.type_params.is_empty()) {
            let found = types_catalog.iter().any(|e| e.name == hir_spec.type_name);
            assert!(
                found,
                "builtin_enum_specs() contains monomorphic entry `{}` that \
                 is absent from hew_types::builtin_enums::monomorphic_builtin_enums(). \
                 Add it to the hew-types catalog so MIR/codegen can register its layout.",
                hir_spec.type_name
            );
        }
    }

    /// `BUILTIN_ENUM_VARIANT_BARE_NAMES` must be the exact set of all variant
    /// names across all `builtin_enum_specs()` entries — no more, no fewer.
    ///
    /// This list prevents bare names (e.g. `Full`, `NotFound`) from
    /// silently overwriting user machine-state constructor entries in
    /// `machine_ctor_registry`.  A variant added to `builtin_enum_specs()`
    /// but missing here causes the silent-overwrite regression; a name
    /// listed here but absent from every spec is dead weight that erodes
    /// trust in the guard.
    #[test]
    fn bare_names_guard_is_exhaustive_union_of_all_spec_variants() {
        use std::collections::BTreeSet;

        let specs = builtin_enum_specs();

        // Collect every variant name from every spec (any arity, generic or not).
        let mut expected: BTreeSet<&str> = BTreeSet::new();
        for spec in specs {
            for name in spec.variant_names {
                expected.insert(name);
            }
        }

        let actual: BTreeSet<&str> = BUILTIN_ENUM_VARIANT_BARE_NAMES.iter().copied().collect();

        let missing_from_guard: Vec<&&str> =
            expected.iter().filter(|n| !actual.contains(*n)).collect();
        assert!(
            missing_from_guard.is_empty(),
            "BUILTIN_ENUM_VARIANT_BARE_NAMES is missing variant names that appear \
             in builtin_enum_specs(). Omitting them re-opens the silent-overwrite \
             regression. Add each of these to BUILTIN_ENUM_VARIANT_BARE_NAMES:\n  {missing_from_guard:?}"
        );

        let extra_in_guard: Vec<&&str> = actual.iter().filter(|n| !expected.contains(*n)).collect();
        assert!(
            extra_in_guard.is_empty(),
            "BUILTIN_ENUM_VARIANT_BARE_NAMES contains names that do not appear \
             in any builtin_enum_specs() entry. Remove dead entries to keep the \
             guard trustworthy:\n  {extra_in_guard:?}"
        );
    }
}
